const T02B = [{"id":3870,"author":"张秋芳","title":"利簋制作年代补考","abstract":"关于利簋的制作年代,学术界一直存在着两种不同的观点,即周武王时期说和周成王时期说。本文从&quot;珷&quot;字的性质、用字习惯以及&quot;征&quot;字的文化内涵等角度进行了重新考释,证明利簋的制作年代当为成王统治时期。","categories":["02_字词句考释"],"year":2015,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2015.05.002","pages":"46245","volume":""},{"id":3872,"author":"刘正印","title":"“公”字本义考","abstract":"一、诸家说&quot;公&quot;前人对&quot;公&quot;字的本义已进行了多种考释,但每种说法都有其局限性。如许慎认为,&quot;,平分也。从八,从厶。八犹背也。韩非曰:‘背厶为公。古红切’&quot;。其局限性在于,许慎当时只看到&quot;公&quot;小篆形体,并未见到甲骨文形体。郭沫若(1965:404)认为,&quot;字作,下二片亦同。《说文》云‘,山间陷泥地,读若沇州之沇’&quot;。舍义以就形,说非。朱芳圃(1962:93-94)认为,&quot;(应公鼎),象侈口深腹圆底之器,","categories":["02_字词句考释"],"year":2015,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2015.05.017","pages":"59-61","volume":""},{"id":3876,"author":"李光锐","title":"重识汉字——以金文青字为字根解读相关汉字","abstract":"中国古人以金文青字为字根进行文字创造,体现了中国古人&quot;远取诸物,近取诸身&quot;的造字理念,使得这样文字人人皆懂,便于记忆,达到共识,得到最广泛的传播,从而具有无限的生命力。传统的汉字教育方式不能深入解读青的基本含义和深刻的引申意,而简化字的学习舍本逐末,止于表象,没有起到传承文化精髓的作用。致使国人只认字,不识字,造成了当今中国社会出现了一系列问题。没有认识到青和以青字根的相关汉字的内在逻辑,今天学青,明年学情,后年学静,把原本的内在联系完全打乱,十分不利于汉字的学习和传播。致使上世纪五十年代简化完成的汉字,只能在大陆使用。海外华人宁可使用繁体字也不认可简化字,两种文字的使用无","categories":["02_字词句考释"],"year":2015,"publication":"艺术品鉴","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLWEQ9P5VIcLpDsIrqQVbcz127ZA_KmUxaVr1S2HTnd0A9im2FJzkiODsDtpsPT436PeuHNF4zgzigOXBDmCGa72RW7aVuhOWJ7aDbpUprDTMu1Ygd_yfQ5EmPiCdO1y-iKToAyZaUInUDcWw0gMgyxTYtNAg7Xu1ntvEfDgG9itad2bz1S2UiF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"177-178","volume":""},{"id":3877,"author":"刘政学","title":"先秦时期冠以国名或地名的“某尹”当为“某君”","abstract":"我们通过对于&quot;尹&quot;这一类官职名称的研究发现:在先秦时期作为官职名称的&quot;尹&quot;之前所冠的字从来不作地名,而前面冠以国名或地名的&quot;某尹&quot;当作&quot;某君&quot;。这种现象是在尹、君作为同源字分化过程中产生的。而被理解为楚国县尹的&quot;某尹&quot;一般都是具有某种具体职能的职官。","categories":["02_字词句考释"],"year":2015,"publication":"学术界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkuvepnvTeVDsJfFa_sxYaCMp5CsZK1ZSKswgVN1XONyNdzEjr3z1UfZQPKRycIJ4r318x09sy7MaK7sYc64ZnvYE0E2OTTvTq217ISqBBD2LRfCXvwwrrmoC9X-mwvtVByhutstG2pIfHKy_pVEnS_AJkm_-lWf9zn9JAyixeam08lXf5eAUo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"209-216","volume":""},{"id":3882,"author":"钟红丹; 邓飞","title":"“■”字补释","abstract":"甲骨文有字作&quot;■&quot;&quot;■&quot;,学界多认为其为一字,从贝;又&quot;■&quot;字在金文中作&quot;■&quot;,或释为&quot;贮&quot;,或释为&quot;贾&quot;,意见不一。&quot;■&quot;并非从贝,而是从心,应与&quot;■&quot;分释两字,可能为&quot;■&quot;,而金文中的&quot;■&quot;字,可能在后来分化为&quot;贮&quot;和&quot;贾&quot;字,分别承担它在铭文中的不同义项。","categories":["02_字词句考释"],"year":2015,"publication":"乐山师范学院学报","link":"https://link.cnki.net/doi/10.16069/j.cnki.51-1610/g4.2015.10.010","pages":"52-55","volume":"30"},{"id":3883,"author":"李佼佼","title":"探析汉字字形演变与民俗文化的关系——以汉字中的“贞”字为例","abstract":"中国民俗文化作为传统文化的一部分,在汉字构字的内涵意义中也有深刻的体现。本文选取汉字中的&quot;贞&quot;字来进行解析,通过对其在不同时期的字形发展演变及其字义的探究,来探讨蕴含与其内部的各个阶段的民俗文化。","categories":["02_字词句考释"],"year":2015,"publication":"柳州职业技术学院学报","link":"https://link.cnki.net/doi/10.16221/j.cnki.issn1671-1084.2015.05.022","pages":"107-110","volume":"15"},{"id":3887,"author":"李春桃","title":"夒膚瑚铭文新释","abstract":"夔膚簠一器应定名为夒膚瑚,铭文中被误释为&quot;夔&quot;的字,实为&quot;夒&quot;字,&quot;夒&quot;读为&quot;鄾&quot;,指被楚所灭的鄾国。此器为鄾国后裔所作,是难得的鄾国史料。此外,铭文干支记日及瑚字写法也很重要。","categories":["02_字词句考释"],"year":2015,"publication":"古代文明","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2015.04.010","pages":"56-58, 111","volume":"9"},{"id":3890,"author":"王恩田","title":"高青陈庄重大考古发现补证与答疑——高青新出申簋释读商榷","abstract":"古今中外都有天有九层的观念。陈庄遗址有九层堆积,结构复杂、并埋有祭祀牺牲的夯土台基应是祭天的天坛。文献记载说:&quot;水所营绕,故曰营丘。&quot;&quot;营,围守也。&quot;台基周围有封闭式的围墙和壕沟相环绕围守的陈庄夯土台基只能是齐太公始建的营丘。礼制规定:&quot;诸侯不能祖天子,大夫不能祖诸侯。&quot;丰器称齐国始祖&quot;齐公&quot;为&quot;祖&quot;,只能是齐太公之孙名得字丰的乙公得。墓道是国君身份的标志。有一条墓道的甲字形35号大墓出土的申簋,器主申即献公山,申是本字,山是借字。幽公是献公山之父庮公慈母。庮是借字。&quot;同追&quot;","categories":["02_字词句考释"],"year":2015,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2015.03.020","pages":"93-98, 108","volume":""},{"id":3891,"author":"徐义华","title":"琱生三器铭文补释","abstract":"琱生尊是近年新出土的重要器物,与原琱生簋形成三器联读,内容十分重要,深受学界关注。但对于其内容的具体理解,学者却多有分歧。本文通过对琱生三器中关键字&quot;狱&quot;、&quot;刺&quot;的考释,尤其是对《琱生六年簋》中琱生和伯氏行为的对比,认为两者皆是对土地、财产和相关法律文书进行清理,为分家的具体执行作准备。申述琱生三器无关诉讼,而是西周晚期的分家记录。琱生尊发现前,只有王玉哲等少数学者认为是族内事务而非诉讼,绝大部分学者认为是诉讼记录。琱生尊发现后,认同琱生三器是分家记录的学者增多,但大部分学者依然坚持与诉讼有关,主要原因在于对&quot;狱&quot;、&quot;刺&q","categories":["02_字词句考释"],"year":2015,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKG0YNWz4X1CLYaHRHfz_1_-1NP3OG8DT3-gBi7DtsR4qrOUkEyLqzQ6DW5lfMVmRL-qCyf_wVNTGcSP8P7i88NID9ed22_ebbB8kKeDoF3RuGy-qudxgCBq-vvdLaloK6w-d8EPspvsAN5pspWW4AJy0ugWyTmD02YAggcEnlOrNhkmjivmV5_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-106, 82","volume":""},{"id":3892,"author":"王兰","title":"金文虎字的变迁及相关问题","abstract":"&quot;虎&quot;在金文中是一个常见的形符。通过分析金文虎字从殷至战国时期的形体变化,认为虎字形体的变迁主要表现在虎头、虎身等方面,归纳了虎字形体的时代特征,并以此为依据,进行了有关器物的断代、辨伪以及相关文字的释读讨论。","categories":["02_字词句考释"],"year":2015,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2015.03.016","pages":"134-136","volume":""},{"id":3897,"author":"孫建偉","title":"慧琳《一切經音義》所釋文字考辨六則","abstract":"文章通過提取、歸納慧琳《一切經音義》所收釋的文字信息,結合《慧琳音義》之外的相關文獻,考辨了六組文字關係。一方面疏通、辨析了慧琳書中的一些疑難文字,同時也爲相關字詞關係的考察提供了更多證據。","categories":["02_字词句考释"],"year":2015,"publication":"国学学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeqCEOdq47rLirzzEYwS81NFKrDcSsjWUUAuTl97uYJVp9r9l-SlBSZYQ2_B-SzM21nDIMAy0ePdFfbcdr4u0N07u0T-Xuki8p2SoqapfJQWYxGo0buSJWlToEJefnj4Frvm0H_AmmbqGejsybAmtA0dkgK6SDW0EQb9Ac3gh0vpI0vXLAlMda&amp;uniplatform=NZKPT&amp;language=CHS","pages":"10-14, 141","volume":""},{"id":3898,"author":"陶曲勇","title":"談談古文字編編纂中的幾個問題","abstract":"文字編是一種具有一定獨立性的字形工具書,它反映了同一個字在一定時間、空間範圍內的字形演變系統。而現有的許多文字編對形義關係、字際關係未作具體分析,在同形字、假借字、同源字、同義换讀字等方面處理不當。産生這些問題的原因,既在於編纂者没有一套準確的判斷原則,也在於對文字編的性質還存在認識上的偏頗。","categories":["02_字词句考释"],"year":2015,"publication":"国学学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeqCEOdq47rLirzzEYwS81NFKrDcSsjWUUAuTl97uYJVp9r9l-SlBSC4hW3NFN47PZjrBUmo5uXqaFar0__44fOZM_VrBqA7zq7gZiFX1YFdjd0os0rE_uNqGMeTl-zDYeBkZLnG7nezWA3Ug6MbxAdDq1jd-LDoe_9S8Vnie3PPL3iQPUL9ak&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-27, 141","volume":""},{"id":3899,"author":"腾兴建","title":"令鼎铭文补释——以驭、御、仆三字用法的区别为中心","abstract":"根据对卜辞和金文的研究,&quot;驭&quot;并非&quot;御&quot;字的古文,而历代学者都囿于许慎之说,认为&quot;驭&quot;、&quot;御&quot;二字通用,导致对令鼎铭文的解释有误。&quot;驭&quot;指一般意义上的执鞭驱马,&quot;御&quot;专指兵车上的驾车者,而&quot;仆&quot;专指普通马车上的驾车者。令鼎铭文&quot;王驭,溓仲仆&quot;一句中,&quot;驭&quot;、&quot;仆&quot;二字都是动词,而且二字对举,&quot;仆&quot;指驾御马车,&quot;驭&quot;字在此处只能作&quot;骑马&quot;解","categories":["02_字词句考释"],"year":2015,"publication":"邢台学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIgpIVW9JDKcoItVVrch3zs4QPXclafUVwRisknq6N_zJJeDigJa0lR-fQRWBtHQ8_oV7jE-ZwsxM5r3pjvE6orO7M-DULD4snnAmRQCXB0kMQ_8nBFhpvH2bzO_hNf2nl2bsFupPSkTthqf3PFUT_6CMUPKJA-ACPH1RZB4TiZtk2d9K31ZYDF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-105","volume":"30"},{"id":3900,"author":"刘志基","title":"基于语料特点判断的上古出土文献某字存否研究——以“信”字为例","abstract":"针对某些文字上古存否无解的问题,本文立足语料特点判断理论,以甲骨文、西周金文&quot;信&quot;字探究为例,提出新的研究思路:在能够全面反映断代用字存在实际,并要求相关字必须露脸的语境内,通过地毯式搜索来给出答案。具体判断逻辑是:其一,虽某字依据语境要求当见而未见,但却有同义它字填补缺位,则表明某字因其前身尚在而没有存在的理由;其二,依据后世观念某字在相关文献语境中当见而未见,又没有与之同义之字替代其履行记语之职,则意味着某字的缺位源自相关文化观念的缺失或被关注程度不够。","categories":["02_字词句考释"],"year":2015,"publication":"华东师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16382/j.cnki.1000-5579.2015.05.021","pages":"208-215, 225","volume":"47"},{"id":3902,"author":"钱宗武","title":"《周书》特殊的被动语法标记刍议","abstract":"汉语被动句一直是语法学家讨论的热点问题。今文《尚书》的《周书》出现了一个特殊的被动语法标记&quot;在&quot;,不见于任何传世文献。研究今文《尚书》被动句的类型特征、形式被动句介词宾语的语义类型、&quot;在&quot;的形成理据及其机制,对于汉语被动句的发展演变研究具有重要的理论价值。","categories":["02_字词句考释"],"year":2015,"publication":"西北师大学报（社会科学版）","link":"https://link.cnki.net/doi/10.16783/j.cnki.nwnus.2015.05.005","pages":"23-30","volume":"52"},{"id":3907,"author":"刘志基","title":"也说“噩”字兼论“禸”式饰笔之来由","abstract":"定量偏旁分析表明:西周金文&quot;噩&quot;字是表示鳄鱼的会意字,认为&quot;噩&quot;字所从同&quot;禹&quot;、&quot;萬&quot;等所从之&quot;内式饰笔&quot;相同的新释不可取。&quot;禸式饰笔&quot;与&quot;某种动物的足爪形符号&quot;无关,而源自古文字&quot;又&quot;形的泛化。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL3XIapIMopuNLDkbgilBbj6Zbf6L8hGFrj_cPjD9klvCcAnOLsty3yblMgQIQmQyLP0J4TcMwkCDFlEjzC_MuQWp5DMATkpRPjptuWHZlMhhbuhouzVBLFhp2A5UJaJxXImVh3q4sJLPD2Y-rMjopJqQeYz9P04dynf9MDk6250Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46035","volume":""},{"id":3908,"author":"陶曲勇","title":"“■工”试解","abstract":"论文分析了关于明公簋&quot;■工&quot;的已有说法,如优功说、人名说、地名说、大功说等,均有可以商榷之处。论文认为&quot;田工&quot;应与《诗经》及金文中常见的&quot;戎工&quot;结构类似,表示卜兆之功。与此类似,鸣士卿尊的&quot;■工&quot;、京师畯尊的&quot;■工&quot;分别表示裸祭时的营酒之功和获大兕之功。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgk8OdxOFT_k3GlJme3qA945mpQxdN1as7kIEmID4SLoYponxRpVbqnAkiIp7gMRPlrOoG9Z73e3Hy9ZPdbQfYNY8WLz2dIyNts-2Itd-_4TWwZttAqn5YVugCfko5eNDTv8ZWTzQ0qiJzufp7ARkFaSU_X-wKiei-xtxBxjpvrQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-30","volume":""},{"id":3909,"author":"苏影","title":"释齐太宰归父盘铭中的“己之”和“祈易”","abstract":"齐太宰归父盘,曾是陈介祺旧藏珍品。盘底有铭二十六字,其中第四行第二个形体作■、第五行第二个形体作■,因这两个形体书写怪异,百年来一直不能定释。本文利用金文字形研究的最新成果,运用偏旁分析法,结合文例、书写风格,论证这两个形体当是&quot;己之&quot;、&quot;祈易&quot;的合文,从而纠正了释忌、■,释蕲、■的错误。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIOIwktrQvalHRRITtv7cCkZ_iJlCpwPEkoUS_v98DUVxuWKLpF932NrjhAU93MBQdvj0tRIBKwE1KgFPgB_cG0Ox64GdUV_l4OrJSH6684Ql7RGjlgbfRy16nY2CNmwx56JfMYk5su6fE80hox0puGJZ8Yy7b_EHp3xg3In-CD9g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-38","volume":""},{"id":3910,"author":"章水根","title":"亢鼎中的“郁”","abstract":"亢鼎中&quot;郁&quot;,学者或释成它字,或不明其构形。本文对&quot;郁&quot;的构形提出新解,认为此字应分析为从&quot;髦&quot;从&quot;苞&quot;,&quot;苞&quot;亦声。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUhC2JMYDqa1pNOorXFqQh1Qpa6gFaOM2L2PSpbju8Y_lsFRR1It6CLfz7RslSdzWxE9XYOsWU-V4KI_APnW4ZEQR72ma-6F1w1zUNjNVqSt06_arK-XdMxI4sfcIYm1B9NfB5JSA-dryRg9TdxWzbsobVAekSkOuEv6RwOQG_UA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-46","volume":""},{"id":3911,"author":"董莲池; 徐善飞","title":"中■王鼎铭文研究","abstract":"本文考证了1978年出土的中■王鼎铭中的&quot;■&quot;,认为从贝从帚,应隶释作■,从&quot;歸&quot;省声,铭中可能读作馈,&quot;中馈&quot;犹言家中饮食事宜,鼎以中馈铭,可能是载鼎系为王家饮食所用。不过&quot;中■&quot;也有可能是封邑名,如同湖南所出&quot;审阳王鼎&quot;中的&quot;审阳&quot;,如此则该铭便是言中■王之鼎。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8cjKGlV_ypzDKNYpvocRHBorOS-cyk96Zu3jd25u-_49QKLrLn_u5H-wbcxFRKT6pjh76RPTus_RniVs9HI6UTyskEpEZfpFG1C3Ctc3Zt_BtQwZbyNAi0-G3-SenWgCJM1O9YyEkWdD_MWnDolFr3O4dpAiU757OQzcsDVsovA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-17","volume":""},{"id":3913,"author":"禤健聪","title":"铜器铭文识小录","abstract":"通过文义推勘、集例比较或形义分析,辨析两周铜器铭文字形七例,并就其中部分字词的释读提出意见。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIG0FeTsJtsOR5S5XUcylG2pLgyzEgKt5LUcwZPILCeVAbksE_B0pSHDxnyDMamCOuMkAnUTnZzCqT9nvDJxG8p5p7tztQ48lccuDGCipCUVQfGcJxZhV9ECBzTA9eig6pE5X3lQyWzj_umCwQRFmuKfDCPliYLJY0_1tu4xndTNw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-26","volume":""},{"id":3914,"author":"唐洪志","title":"金文“谋猷不飤”新诂","abstract":"本文在仔细梳理前人成说的基础上,结合楚简中的通假字资料,认为金文&quot;谋猷不飤&quot;的&quot;飤&quot;应读为&quot;忒&quot;,训过差、过失。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIG0FeTsJtsOR5S5XUcylG2pLgyzEgKt5LUcwZPILCeVAbksE_B0pSHwU8sQA4pf0hvhTlT2c2OwMNuFSeF2aaDTYKf-svxZEXJqd7YTJZmwIppRvfYt9iyidFsE_GP3rhkWd0cpEKaXBXGs9ktgw-QzS7KZHGo8DZpAPIi5WacqQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-42","volume":""},{"id":3915,"author":"樊俊利","title":"十四年下邑令疡铍铭文补释及其他相关问题探讨","abstract":"十四年下邑令疡铍是一件有铭铜铍,《商周金文资料通鉴》首次著录。铭文共17字,倒数第二字作■,未释,我们认为即《说文》&quot;■&quot;字,在铭文中用为姓氏,读作&quot;原&quot;。&quot;左库工帀&quot;后的&quot;洮所■者&quot;应为两位工师的姓名,&quot;每库工师好像只有一个&quot;的结论或不可信。铜铍制造地下邑的地望在今天河南夏邑县境内,战国晚期属于魏国领土。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2PS0OEAQxwszdkcjDpmpAgj64AsC97dWPR_xpn5jfVU5u9jwzr-eLa6EdQwI3pKNk7dZFnZVy_DNv1tGVGL-1WtRcWfk4N83t-YDM8LT8mglYHOXDmsnSyyiZG9utm0hyKr1nMA4zZZoNr426hzCKnQOvEE9U7qxXhnERPPCLeQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-50","volume":""},{"id":3916,"author":"杨蒙生","title":"枣庄徐楼出土鄝子戈铭文补说","abstract":"新近发表的《山东枣庄徐楼东周墓发掘简报》中披露了一件鄝子戈,戈铭与1979年淅川下寺春秋楚墓所出铜戈相同。但是,两件戈铭中的人名&quot;■&quot;字形体略有差异:枣庄徐楼戈铭此字作■,淅川下寺戈铭此字作■。分析可知,与后者相比,前者所从安旁之中包含了两个指事符号。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkpnFmLPHQ51TuWJse201rIOWgbcw2y6uwTVw2WVEWsEmlAtrwyhHtfKlvqO-yPXWxzU0kNvLNm7fmmRUVgIivWTE086Xx47-EOjFxFDJWlOh8rhBR6lanlj744bcsxFPPV1tbyKqfurehzz0Xjd2uEBFSTu4Rkkc6il5NK99xBA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-57","volume":""},{"id":3918,"author":"鄔可晶","title":"西周金文所見有關“九旗”的資料","abstract":"《周禮·春官·司常》所記“九旗”之制，在西周金文裏可以找到不少相應的資料。本文吸收古文字學界現有的研究成果並參以己見，認爲“九旗”中的常、旂、旜、旟、旐作爲賞賜物已見於西周金文，“(物)”則發現了可能與之有關的字形;金文資料還能在一定程度上印證孫詒讓“五正旗四通制”之説。","categories":["02_字词句考释"],"year":2015,"publication":"中国经学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoOFfdrwziMHbryHaPp6FICmQ6FuMqJKcJsCi3OAaUqXzachN3RcXe1K1wX6w9yozJgOB9333RCy9qI4Yszn5G-S-EXFlDDhOp27Yiki1G78oOtI45oQr61KetMVasZOsgUjO36EZwgj_E6Ggle0JoBTR_HkfTSwtcMbsw-5WgJQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"135-144","volume":""},{"id":3919,"author":"谢明文","title":"释西周金文中的“垣”字","abstract":"西周金文中有些从“■”的字,过去没有得到正确的释读。根据已有的研究成果,西周金文中从“■”、从“■”得声的字应当释作“垣”。“■(垣)伯丰鼎”之“■(垣)”当读作“韩”,“垣(韩)伯”可能即周武王之后。此外■伯盘之“■”,应改释作“■”字,“■伯”亦可能即“韩伯”。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ1S-cJVrqdgw1RxWgxjNu1DucyUaNkuJP0xkKhXUrsIDuQ2Ov-aR5BLz9Y4rqx9GRmi_8rlQYCNQ6i0CAqmKAfApXdsCsimA_VprP6_BSdjKPTyFbdqn6j3ayts385-6zG7YE7cuTyZUioPPpkIHa5SH1CB0eWlyR3lH6BEJ4StQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":""},{"id":3920,"author":"程燕","title":"秦公簋“徵各”解","abstract":"本文对秦公簋中“徵”字字形做了补充说明:“■”省去了下部所从,具有秦文字的地域特色;“尤”是加注的声符。簋铭“徵各”,读作“登遐”,乃上古成词,表示先祖的默佑。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI21VPVXRta5OGZFSUgxYXy5O1I-UZYYAo7IOTstBKkkTug09oUwshiiDr2OVy0MxKccYmSgHiD5jixSpARprw2mkonKl2KlnrKBMaEByZPgScUy_eOkoK3W_pDuzRCd4XFLwHvMZ8eHdRbeHWYBRhaw-IezZ0xGktvLw0hpCDDYQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-77","volume":""},{"id":3922,"author":"胡文嘉","title":"金文“世”字源流初探","abstract":"金文“世”字构形多样,各家对其形义关系说法不一。本文收集了六十个在金文中用作“世”字的字形加以分析,并在此基础上结合甲骨文材料,对“世”字的字形源流和形义关系进行初步探讨。本文认为金文“世”字多用于嘏辞,其形体来源于枝叶之形。在使用过程中“世”字形体衍生出多种构形,体现了汉字在发展过程中,意义趋于分化和明确,形体趋于固定的总体演变规律。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvwwebP3Wf_woMOFmIQqgnKpGvMHmY4DVJS6x9HBGre8_tqQ2al8R7HgKpXsBH7o6YtlE7baUql59XHwax8ukC6FPr_PMHnBcmhGHYcoT-pOS31c48vWX8QeVDWtgPbLj5fzK5n2G6PAs7yj395VHFJ6S32UZzR7Z-_HG39kqP7g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-91","volume":""},{"id":3923,"author":"张振谦","title":"燕玺文字考释七则","abstract":"燕国玺印文字因其字量繁多、字形具有典型区域特征,故其为重要的燕系文字材料。本文对燕国玺印中的“■”、“败”、“弢”、“■”、“■”、“道”、“■”、“■”等字作了初步的考释。","categories":["02_字词句考释"],"year":2015,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ1ZZLscP0sBzK1LIAD-Q8BXoEqnV-jLolTVrX96Sps6C3-8_C-wpfexCLkBFIHrgCKRWkmgx-JVYVmHi0W5Uajmh52r1JU_ctOjFLHystWx-6ZKvqcFPl-ClRxA02YfmIXU9eiXrDmLE9x2V74FOLoFYT5fSg0SPi5EEBATSUQbw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-109","volume":""},{"id":3925,"author":"冯玉涛","title":"类说记号对古文字结构的繁化作用及其规律","abstract":"记号是语言学中一个被广泛运用的术语,语言学下属的语法学中同样有记号——语法记号(notation)——的说法,本文所说的记号指文字学中的记号。在汉字学界,对记号有不同的称呼,除通常叫作记号外,还有彣饰、文饰、羡符、定符、羡余等等不同说法。所谓记号,简单说即标记符号,指在字形结构中既不说明意义,又不表示读音,也不区别词性,而只起代替、指点、区分或美化结构作用的部件。在汉字系统中,记号和汉字所","categories":["02_字词句考释"],"year":2015,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2015.04.003","pages":"22-26","volume":""},{"id":3926,"author":"张程昊","title":"东周青铜兵器四考","abstract":"本文对见于著录的四件东周青铜兵器进行了考释:间右库戈应为春秋晚期晋国&quot;涧&quot;地所铸兵器;廿二年左矛铭文中的&quot;■&quot;字应隶作&quot;■&quot;,释为&quot;县&quot;,该矛当为周赧王二十二年(前293)&quot;左县&quot;所铸兵器;右库工师戈铭文中阙释的地名为&quot;少曲&quot;,该戈为韩地少曲所造兵器;河南郸城出土的廿二年戈原为魏国兵器,后为韩国所获,铭文中的&quot;廿二年&quot;应为韩昭侯纪年。","categories":["02_字词句考释"],"year":2015,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2015.04.002","pages":"46372","volume":""},{"id":3927,"author":"刘益明; 李青","title":"“青”字的本义考——兼与潘峰先生商榷","abstract":"论文针对潘峰在《释&quot;青&quot;》一文中提出的&quot;‘青’是个文化词,并非开始就用来作颜色词&quot;这一观点,提出了相反意见,认为卜辞中尚未发现&quot;青&quot;字,潘文所述卜辞中的&quot;青&quot;字实为&quot;南&quot;字。&quot;青&quot;字是个从生从丹的会意字,&quot;青&quot;字的本义为绿草的颜色,后来又用作深蓝、黑色等。&quot;青&quot;字出现之初就用作颜色词。","categories":["02_字词句考释"],"year":2015,"publication":"成都大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdIS-wfxmWzbm_mDPorvmEwW26zPSa0pRwNOiq1fAJkpURscACXxp57KElkxFYwWWtZX8miwlXoRvZnJHKhCLhO2S7POL9PsB82t46mo7IZl6EWxb2HQw08KYef553Yi25uyMGTR63106QDJpM8zVM6c8uixUh447nNkOkVg_aKr4J2pHbhZRF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-91","volume":""},{"id":3931,"author":"何家兴","title":"《燕侯载簋》考释二则","abstract":"燕侯载簋是十分重要的燕系文字资料。本文考释了其中的&quot;卬&quot;和&quot;无争&quot;两个疑难字词,讨论了它们的含义,对于探讨燕国世系以及燕文化与中原文化之间的关系具有重要的价值。","categories":["02_字词句考释"],"year":2015,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ8uGWhNhB8vLh4wr1XuD6e3retyEAa81hxP0pWye-wcQzhlikWah5H-wvu46uuWWr36DQe57BHYXk08jQzKjMWHfxpFgqPmKVzju85CM14kw4oAAVa88ZPXHnvE4_Uhss2idgyeUia5BV0eIFTpHymykHT4RgSk0DMYmTVZBaYL5c2l87Xhjn8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-102","volume":""},{"id":3935,"author":"冯玉涛; 彭霞","title":"古文字讹变问题研究回顾与再探","abstract":"汉字形体讹变现象在甲骨文即已出现,在整个古文字阶段普遍存在并伴随着汉字发展的各个阶段。唐兰先生在20世纪30年代比较系统地分析了古文字的讹变现象,但此后一段时期内几乎无人在汉字结构演变过程的视野下讨论讹变,直至近40年这一问题才受到重视,李孝定、张桂光等十多位学者对其概念、类型、原因、结果等有比较热烈的讨论。在回顾以往研究的基础上,分析了古文字讹变现象,发现几乎所有的古文字都出现过或多或少、或轻或重的讹变字形,讹变和简化、繁化处于三足鼎立的状态。其类型有意符讹变、声符讹变和整字讹变三种。形成讹变的原因有六:因结构相近、因误解记号、因误解字形、因以字形附会字义、因字形断裂、因字形粘连。讹变有消极","categories":["02_字词句考释"],"year":2015,"publication":"华侨大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16067/j.cnki.35-1049/c.2015.04.013","pages":"123-140","volume":""},{"id":3936,"author":"严志斌","title":"小臣■玉柄形器诠释","abstract":"小臣玉柄形器自名为瓒。祼礼中将瓒实于彝器以鬯酒灌之以祀神(或享人),瓒是通名,有圭、璋、璜、及璧、琅、珥诸瓒。瓒是祼玉,而不是象伯公父勺一类的勺形器。伯公父勺自名为爵,也不宜据之改变原来爵与勺的习惯称名。","categories":["02_字词句考释"],"year":2015,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIM-VKa2oQHYpOR9xZSJF1_M8v0FkWp6k9hsjqGLb7pIxK4UyfSwxO8DuDCym48hJtRtkwMbR48biDiOglX8wdeA80mEfzuSXQCp8FJ5joyonJwJE8tjyOPW74Ex9ilF7ElQLjuhwMpYhUBHw4K8g9e2329m3846D2qLWHvDxX0EvY4jYStwQSt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"93-104","volume":""},{"id":3937,"author":"吴红松","title":"西周金文考释三则","abstract":"本文结合传世文献记载及考古出土实物资料考释西周金文所见赏赐名物三种。第一则指出毛公鼎赏赐之物中位于&quot;错衡、金踵、金柅&quot;之下的&quot;■&quot;二字当释&quot;约辖&quot;,是与軎配套使用的用以约束轴的装置。第二则释大保铭文中&quot;易休土&quot;为&quot;易休杂土&quot;,杂土指优劣并存的土地。第三则释番生蓋铭&quot;朱旂金■二铃&quot;,其中&quot;金&quot;下一字从冘得声,读为&quot;首&quot;。&quot;金首&quot;就是铜质的旗杆顶部。","categories":["02_字词句考释"],"year":2015,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISSid70Q6yVX5Ysbg-LgMOtLq1zKmnrRipA9Jv5qPe9sMW53POyDka4YLNQUo7Sq0P5lT2HyiQxJRZ40sbQmA8gg5QLhym3pjEBmuKh1irpakXfjJG-QjHR6waF9ysTdW14wqoFtEiDNSKEvax5pqpgGJRV44utIzPuAL-7QVhEsn04WgopVpe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"115-118","volume":""},{"id":3939,"author":"田小娟","title":"说“芾”","abstract":"出土商周人像上腹前多有一片斧形的装饰,即&quot;芾&quot;。西周时期,&quot;芾&quot;已是礼服中重要的组成部分,成为&quot;别尊卑,明贵贱&quot;的重要标志。&quot;芾&quot;从最初的人人均可穿用服装,经漫长演变,成为贵族彰显地位的礼服,至汉代成为只有君王才能佩戴的冕服之一,一直沿用至明末。直至满清入关建立新的服饰制度,&quot;芾&quot;才退出了历史舞台。","categories":["02_字词句考释"],"year":2015,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLwqAGVm3FOPaKyvNoxyiE-pnsiofINl1YBTU1vvqlT8zCqk4ikZrDcsLOHHi89cVURhPDzSpB3XI-InBqJyo-P2N-IZ-0YKQYQCUqTOxGUUiaAlo-giRRKtR2PYPtqE7aIsv90f0z8GP0bZrqW4Ug-kvaiTMhDOG23vSDVMD_ZeL6oAYCSX1PG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-90","volume":""},{"id":3943,"author":"李奕声","title":"西周吉金“三年师兑簋”考释——兼与李亦洲、张志亮先生商榷","abstract":"近日购得《书法·东方艺术》（由河南省艺术研究院主办，东方艺术杂志社，今日美术馆出版发行）2012.4下半月刊，总第252期。书中刊登李亦洲、张志亮署名文章《雪庐藏〈吉金集拓册〉琐语》，对有关青铜器之断代考证，诠释颇有讹漏（下称《琐语》），现以文中“三年师兑簋”为例考述之。","categories":["02_字词句考释"],"year":2015,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLeZGKt8zfkL2KVCc3nloMTvEjFbQEsl9SOs5Sxv3eLjrLIAOM0KDqhFijduaS3ize977OumfWJtOE3Jv28dPBcS7oqa_kHlFiraDyiPE4WQUZmU6tvGU6oiO20IyoC3yXYc_wS3I85a-_IQio9NNWaY4LYdlodbCc2MDA9uFQEShC9qt2xsOPn&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-53","volume":""},{"id":3945,"author":"张鹏飞","title":"释“昜”和“易”","abstract":"汉字的形体总是携带着可供分析的意义信息,通过对&quot;昜&quot;和&quot;易&quot;的甲骨文、金文构形构意分析,得出:&quot;昜&quot;的造意是&quot;云开日现光线下射&quot;,&quot;易&quot;的造意是&quot;日月半现光辉交互&quot;。一个汉字作为词使用时的众多义项,总是在该汉字的造意基础上引申衍生的,汉字的造意是该字作为词孳衍的各种意义的语源。","categories":["02_字词句考释"],"year":2015,"publication":"湖北师范学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJkNzearKm9WVMe-CM_yTex9g6kCg0EuHgIaeWcneLBTEzhSdrTalULYBAohffaOTwUPz3UBlky1lVU0qNmAQm2BPMAAJNM7Oy2-bpfLyX4ECUFjZfjWHITRqdO4OiO-8bQ_WOvwJJ_m0-zRgFp9HS_G0NPuT8MQonK0LjV17QIdrkgpTce4olT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-45","volume":"35"},{"id":3949,"author":"谢明文","title":"郑义伯铭文补释","abstract":"郑义伯铭文中的一些字,旧没有得到很好的释读。如&quot;余以行以&quot;后面一字,旧或释作&quot;川&quot;、或释作&quot;顺&quot;、或释作&quot;征&quot;,本文赞同最后一种意见。&quot;即&quot;前一字,旧或释作&quot;酉&quot;,或释作&quot;(郑)&quot;,本文赞同前一种意见,认为应读作&quot;酒&quot;。&quot;我酒即&quot;后面一字,旧或误释作&quot;浩&quot;,或误释作&quot;造&quot;、或误释作&quot;沽&quot;、或误释作&quot;&quot;,本文根据相关金文资料指出它应释作&q","categories":["02_字词句考释"],"year":2015,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ7-vF6EYivWWvF8hmiFEg7Wp3BpI0Epd4zmvz_TMu3QAY0iMGaIzSIyCI_cdwjUX_dfO_gzOFbfDwMNy5O-3HJFuymtIKwgowK11LG-CubOfxYERcqvvIqG6mZMd25hJTopCwChYDlVK1agEzIEGUJp8KENj20Ue93fm4JFXuRTRzdlhQz-C4h&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-70","volume":""},{"id":3954,"author":"张素凤","title":"从古文字透视古代最高统治者名称的内涵与嬗变","abstract":"从古文字透视古代最高统治者名称的内涵与嬗变古文献中,用来表示社会地位最高、权力最大的统治者的名词有很多种,其中使用频率较高的先后有:&quot;后&quot;&quot;王&quot;&quot;天子&quot;&quot;皇帝&quot;&quot;圣上&quot;等。这些不同的名称背后隐藏着丰富的历史文化信息。本文旨在通过分析记录这些名词的古文字形所包含的文化信息,揭示每一个名称的意义内涵及其嬗变轨迹。一、后1.母权时代族中最高主宰者——女性&quot;后&quot;的甲骨文像妇女产子之形,表示女权社会的主宰者。2.父权时代族中最高主宰者——男性父系社会,&quot;后&quot;的意义变","categories":["02_字词句考释"],"year":2015,"publication":"第六届汉字与汉字教育国际研讨会论文摘要集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLw-QK_QoaRQrcaBorpuRo6OqPiFmD6Xx1XXtKEsVriENPmT-mKH0dYk6SuHZ6ob9cioEQ-n_EIPmj0FD7usMcsVOuDRObJCsSfFW4Tw-cJaCtyqpKpZiNsa5rvuQV64C-LuzHYdbY08q9cnT67pj5_k-iRFIcq7-c3pYSXrXtxV8Kg0u37imh4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119","volume":""},{"id":3955,"author":"李守奎","title":"系统释字法与古文字考释——以“厂”、“石”构形功能的分析为例","abstract":"系统释字法是以汉字构形的系统性为基础,将具有某种关系的若干组文字放置在静态的构形系统和动态的演变过程中系统考察、全面释字的方法。汉字中70多个与&quot;厂&quot;、&quot;石&quot;相关的字形可以通过系统释字法得以全面考释和系统的阐释。商代与西周&quot;石&quot;字写法不同。自西周开始,&quot;石&quot;在上下结构的构形中就简化为&quot;厂&quot;,经秦文字沿袭一直留存至今,致使古、今文字中从&quot;石&quot;构形的文字经常与从&quot;厂&quot;构形的文字混讹,隶定与阐释意见纷纭。楚文字&quot;石&quot;的写法大部分不是直接继承西","categories":["02_字词句考释"],"year":2015,"publication":"吉林大学社会科学学报","link":"https://link.cnki.net/doi/10.15939/j.jujsse.2015.04.021","pages":"225-241, 256","volume":"55"},{"id":3956,"author":"曾文决","title":"癸字探源","abstract":"对于&quot;癸&quot;字,古人有几种不同的解释,想要真正理解&quot;癸&quot;字的意思,就必须从本源上探析&quot;癸&quot;字的演变过程。从甲骨文到金文再到小篆,&quot;癸&quot;字呈现出不同的字形结构,许多文字学家根据这些不同的字形结构对其作出了不同意义的阐释。","categories":["02_字词句考释"],"year":2015,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJYFiy1E6_gyyx2mmzNe__N8nK8ucreIhoWq_FFmIFdwz4trYNuW8qpVWjZvlEZcZ0gHgXasgjA-Ww4bUWTnnWg9nofpBHzjhLPSKm4rLY7tr9uupeQXoyEbLppN2hBPw7rq8yoa1UCeFm_YHzvbpfm_v-zv53r4Ar9q1wkQ5Mr84JxaviH1-nd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-103","volume":""},{"id":3961,"author":"寇占民","title":"金文句讀疑義釋例","abstract":"殷周金文內容豐富,長篇較多,由於銘文本身没有句讀標識,學界在一些金文句讀的理解上仁智互見,從而導致對同一篇金文的釋讀出現了較大的差異,這些分歧使成了研究和使用這些寶貴材料的障礙。令就二祀邲其卣、史密簋、師■簋銘中具有分歧的句讀加以疏證。","categories":["02_字词句考释"],"year":2015,"publication":"汉语史研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDNPddRw4nfjOoPOP2wBS6qslu_moCyF8IJRPYiF7Tj1ZWbAAEFZ83HS2-vxl6SB2wXcRmTr644M5e0fVbVLpZHKXOGpn03W3Wr26KbuOdypbnw7_TjgHLUXwZdQWacgZnUBV7lJpVo451cOEWnHUxn3ieu2bi_GmskKHa3Frp7Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"354-366","volume":""},{"id":3964,"author":"程义; 陈伟","title":"“兵与礼——吴王余眜剑学术研讨会”综述","abstract":"2015年5月18日,苏州博物馆举办&quot;兵与礼——吴王余眜剑学术研讨会&quot;,与会专家对苏州博物馆征集展出的吴王余眜剑从铭文隶定、名词考释、史实考订与形制特征等方面进行了热烈的讨论,基本解决了文字的字形问题,但对&quot;伐麻&quot;之战的年代,&quot;姑发&quot;、&quot;姑雠&quot;、&quot;姑癹&quot;的关系及剑的制作年代尚有较大分歧。与会专家还对吴越文化特别是吴文化研究作了回顾与思考。","categories":["02_字词句考释"],"year":2015,"publication":"东南文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJcGPq7Nu6km_qpPmHJISSBlEw_L8CRNo4Ec9-94UB-ZM61EO7xrMrlFSeI989JYWIPgnDndxdZzpYOiPzdWS2LJqSsOouG2LFzmNknhVDkBUqeh-hDxFomRwxbAfW9ngukKSmdRkbQDcX_sl2kycEYpZ7GvfkIHI9qqxMhNCHSIwZhgsXOFt1G&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-126","volume":""},{"id":3969,"author":"金惠敏","title":"“民”字的文化解析","abstract":"民的意义来源一直是一个有争议的问题,大多数人都认同郭沫若的观点,即民是用针刺瞎一目的奴隶的标志。本文认为民早期应该是表示纹身,由于纹身可以使人的肌肤受伤,因此民又可以用来表示刑罚。刑罚主要是针对下层阶级,因此民又可以引申表示庶民、民间、人等意义。","categories":["02_字词句考释"],"year":2015,"publication":"吕梁教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLcRjlSRAX2j9p1o-kCuvuzk4QQSYufs97qaEV4PHQWwW1i3GIRfxD0k8N90gZhMhAX5grm0Ja-h_PUYpZE69HJ6JTq4d2u_1H-SnOscKQ0ik5hl9Bo81CPFchO_P3NEkZ3rG34P2SioHE34RqALhf95i-iWLyyPY_ZMN-uPaF_gKeUmZc0G5Ji&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-96","volume":"32"},{"id":3970,"author":"王娟","title":"《静簋》铭文释读","abstract":"静簋是西周中期穆王时代的青铜器,其铭文记载对研究当时历法、官制、书法发展等都具有较大研究价值。本文仅从断句、训诂以及其现存意义几个方面对《静簋》铭文做释读。","categories":["02_字词句考释"],"year":2015,"publication":"才智","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLcRjlSRAX2j9p1o-kCuvuzk4QQSYufs94Et9wBHe8u6KMKfIeYI1wdp2hSqq96lx4-drubUHiG1OwavyQfwutM5qMl-J3DvPVyudjBUaa2Mjq0wx-p82o093S425jw3_qEwUDLseZGlcqPGu-EXK6lLIGJkfzGyhnI3WpqqO5-fqfqTXEQjGly&amp;uniplatform=NZKPT&amp;language=CHS","pages":"286, 288","volume":""},{"id":3976,"author":"李元芝","title":"沈尹钲铭与叶公沈诸梁","abstract":"江西省高安县西清泉市出土的沈尹钲,铸有铭文42字。本文对铭文中个别字词试作新释,认为该器是楚国令尹兼司马叶公沈诸梁所铸,铭文中&quot;沈尹&quot;的含义是&quot;沈&quot;姓。","categories":["02_字词句考释"],"year":2015,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzBUjMoFEvhZ4xgJjAxptI1e5alYniiu7LcJzuCQiRC6TafImXtvgvAShw6gy4mViTEDrE_bzPr0GK2Jt0CkH1yym6b0yw5NjQbtD9Tc_5870UrIyCMjl7TR7_FtbGi4CjXZWo5_sVMgtdzGl2hJPFlRYMU8lSZANHLmJFh9avnJbfFqjuU6B8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-41, 44","volume":""},{"id":3977,"author":"牛清波","title":"(疒木)儿鼎铭文补释","abstract":"(疒木)儿鼎中的&quot;(塦攴)&quot;字糅合了两种写法,具有重要价值。&quot;■&quot;应释为&quot;(疒木)&quot;。鼎铭中的&quot;陈侯&quot;是陈国的首位国君&quot;胡公满&quot;。","categories":["02_字词句考释"],"year":2015,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIK6FSP-ask6eMEP5vue5ie-E2-8zzMcHYpyA9FHmtc0YAsDigxXDIiOpzbqUjQ-cXZ0Dx9ikswMV3V4fm3KdWop_zxj8NfUCREa0MabvBLuhc9L3OU6xmbTkonF4vtli_E9uYCufq4yrYTnv11KG9gXfBXFOHIHH2d3boCw-eQUe75akoWAjGe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-44","volume":""},{"id":3978,"author":"郭倩","title":"西周青铜铭文中的自述型铭文初探","abstract":"西周时期青铜铭文的铸造、铭刻日趋成熟,涌现出一批以&quot;某某(作器者)曰&quot;开头的自述型铭文。这类铭文,具有明确的记言意识,以追孝为主要目的,以颂扬祖先功业、表达黾勉从事的决心为主要内容,以明德为重要宗旨。这种自述型铭文的出现,显示出西周时期贵族对言论价值的重视,这类铭文与后世之&quot;立言&quot;思想有密切关系。","categories":["02_字词句考释"],"year":2015,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2015.02.005","pages":"30-33","volume":"36"},{"id":3979,"author":"苏影","title":"陈逆簠铭文补释","abstract":"陈逆簠是战国早期齐国之重器,对研究田陈的历史有重要参考价值。由于铭文刻写草率,对于个别特殊形体,学界无定说。其中簠上字,或释为&quot;宝&quot;,或读为&quot;容&quot;,或作为未识字。查考战国古文形体,它与&quot;容&quot;字的古文写法同;从辞例看,读为&quot;容&quot;亦通。","categories":["02_字词句考释"],"year":2015,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2015.02.020","pages":"104-106","volume":"36"},{"id":3980,"author":"吴祺","title":"读叶正渤教授《金文四要素铭文考释与研究》","abstract":"叶正渤教授的《金文四要素铭文考释与研究》2015年3月由台湾花木兰文化出版社正式出版。该书是叶教授运用古文字知识和对西周历法研究的成果对金文四要素铭文进行考释和历史断代所取得的成果,同时也是叶教授2010年度所承担的国家社科基金项目&quot;金文历朔研究&quot;的部分前期研究成果(项目编号:10BYY051)。金文历法研究一直是叶教授学术研究的重点,如叶教授的《金文月相纪时法研究》《金文标准器","categories":["02_字词句考释"],"year":2015,"publication":"辽东学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkOx9qkNzFpjvR71dAEZeHCi4b40I7SCpBgrpjPCItZcdMhB_5fQfsNPXbyUkg6whIMRpDplKGnJCtuo2xpTuDWykgE9IhraXjG6NlEQu7sJu_1PJRXF6CAgtcygbAoxaEx3V6_Rl7MFD874YW92pUJ18dihF9xG7PLy8_hCothnyGwtCKqUFP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"141","volume":"17"},{"id":3982,"author":"冯时","title":"巴蜀印章文字考释——巴蜀文字释读方法探索","abstract":"通过比较冬笋坝墓葬所出巴蜀文字印与汉文印,分析两类形制、款式、字数相同的印章,可知巴蜀文字印实系模仿汉文印而制作。巴蜀文字体系中相当一部分文字的作用应重在表音,而并不在表意,这与巴蜀文字数量尚少的事实互为因果。而巴蜀文字的来源之一则是对汉字的借用,其发生时代当在东周以前。","categories":["02_字词句考释"],"year":2015,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmbtUG1oG0Tz_zh2a-fsfpDQ38uwa-EVL881ixlBBLwbTbUKi7qwbmqLpbN5tmiTIdWHoD7q0P7UBkZcQUHvg_hlBfRDAi6hbls3XlZT1Bon8tPeP9pkUtKVVBy-bhUlhifTm2eT2WO4DcRqKmce4oPiwgTeYpNEVaoeLikgJdiTJ-at8SYbR_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-36","volume":""},{"id":3984,"author":"雍际春; 周晓聪","title":"论秦人早期青铜器与秦系文字的形成","abstract":"近年来在天水地区新出土的秦人早期青铜器及其铭文,为准确认识秦系文字的形成提供了重要资料。将新出秦人早期青铜器与传世青铜器相结合,根据其制作年代考察其铭文的演变,则秦人早期青铜器目前所见最早的是秦庄公时的不其簋,其次是秦襄公受封建国时所造秦公簋与盄和钟,再次是大堡子山秦公诸器。与之对应,不其簋铭文表明秦人已经熟练模仿和使用周文字,而秦襄公时的秦公簋与盄和钟铭文标志着秦系文字已肇其端,中经大堡子山秦公诸器铭文的进一步发展,至春秋早期秦景公钟、镈铭文,秦系文字已完全形成。","categories":["02_字词句考释"],"year":2015,"publication":"西安财经学院学报","link":"https://link.cnki.net/doi/10.19331/j.cnki.jxufe.2015.03.017","pages":"92-95","volume":"28"},{"id":3986,"author":"周素焕; 陈鸿; 林志强","title":"东周燕系文字疏证","abstract":"春秋戰國之交，社會的劇烈變化，使得文字因國別和地域的不同呈現出不同的特色。近幾十年來，戰國文字研究取得了諸多成果，分域研究也取得了很大的進展。相較之下，東周燕系文字的研究成果不少，但仍比較緩慢。目前尚未有對整個東周燕系文字從文字學的角度，結合前人的研究成果，進行全面整理、釋讀、疏證的文章。本篇論文題目為《東周燕系文字疏證》，共分三個部分：第一部分是緒論，第二部分是論文的主體一單字、合文疏證，第三部分是附錄。所收的文字材料大體分為銅器、兵器、璽印、陶文及貨幣文。“緒論”部分對目前東周燕系文字的研究概況進行詳細的整理和概括。介紹論文的選題意義、研究内容和研究方法。正文包括“單字”疏證和“合文”疏證","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_ARTkUvVqgDNNzGBs2UZo4Dhv5D91iczLSiQjIwdotxzDR1Ld5_vdGYIXsocd6l5mzHz1Uufl5IRqdPGlre9Y6BGAZMahuFpXXcHmL0KFJCJ8So9LuRWt0oHE8YEvXIwEDxp3HaaJoApEOB6MRxA3sgfYaGX-l_Yz8VXQwq5hwsWh8Q3BR-Sm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3987,"author":"吴雅静; 林志强","title":"近二十年汉字溯源研究综论","abstract":"汉字溯源,即追溯汉字的源头流变,关于这方面的研究早在春秋战国时期就已经有所萌芽了,历史悠久,且涉及的方面多,因此本文将研究范围限定在近二十年所出现的新的研究成果上,主要对其进行整理归纳和探讨。首先,阐述了学界对汉字溯源的理解,并介绍了汉字溯源在每个时期的历史概况,以及所要研究的近二十年的概况,使人们对汉字溯源研究所包含的内容有初步的了解。其次,通过三个部分总结并分析探讨近二十年关于汉字溯源的研究：第一,汉字起源的理论研究,从考古学、语言学等几个新的角度谈汉字的起源问题；第二,汉字结构的溯源研究,主要是列举例子来分析汉字结构变化中形义关系的改变,并阐释由归纳汉字结构变化规律而成的构形理论；第三,","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLohu3UxfHdGgkKouC-3ky5kl7a-6SgKWfPcMNO70xrFc6FQATBnrSP6XNhZtOFrLOoUvUzUr5D09AvjeQLKCy1jMwYI0SUe8B3ge09kMfdKnTLDjueg5vorSFxpMksUCtrVFzeCf17zBjLpI-YTv9RZIzzqZJ599G8SdzaRB6pjDzexQ19SUgt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3992,"author":"邵阳; 李守奎","title":"古文字疊體構形研究","abstract":"疊體字是漢字系統中不可或缺的一部分，無論是在古文字，還是在我們現在使用的現代漢字中，都可以見到疊體字的身影，疊體單複無別現象更是古文字疊體字中一種比較特殊的現象，本文將系統研究古文字階段的疊體單複無別字，梳理其在古文字中的字形以及在語言中所承擔的意義。本文共分為三個大章節，第一章為緒論，主要介紹了本文的選題背景、研究目的、相關研究綜述、研究內容、研究材料簡稱表以及列舉字形的格式等幾個方面的內容；第二章為疊體字單複無別情況研究，這也是本文的主體部分與側重點，這一章共分為四個小節，前三節以部件數量為標準，採用逐字分析法，從部件數量角度一一列舉了古文字中的疊體單複無別字，系統梳理每一個疊體單複無別字","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUHdOheWPZxl9t_gtJJslCAmPnT8t8kPT4iTNFtS3zpCSciIjXRK0ExoE5NGr9Qt76JNtOhu28BW10AU2aNvBCF9xBTbJoBbXfacvZDbjco2sfgsuuJvtpzs3wpv04kXa09CkceyvE5HzazKJluKSSVvTXcCn5iU-ImIltOwiB80SEqcQA8em9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3993,"author":"武敏; 陈双新","title":"从殷商到战国文字义近意符通用研究","abstract":"義近意符通用現象雖早被發現並研究,但對於通用意符的歷時性整理研究還不夠完善。本文分為義近通用意符的通用條件、分類及歷時演變三大模塊。義近意符的通用並不適用于所有的漢字,本文首先探討義近意符通用的條件,分為義近意符的地位及示意功能的分佈、換用意符之後不能影響原來的字義以及意符通用的時段性三個條件。然後搜集殷商甲骨文、兩周金文、戰國文字三個時期通用的義近意符,對其進行歷時的分類。通過對通用意符的分類,總結意符通用的歷時演變規律,進而探討演變的原因。在歷時演變中,某些義近意符的通用相對穩定,在不同時期均可通用,但有些義近意符的通用則是在短時期內進行的,究其原因是由通用意符自身的類型所決定的。意義本身","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4dMI2JNq7lmulF2Kd6gefmSOxPqFPaZnmnmnDBu-XieHUts5mbheV5g8vzfsMsVetmZHPznVIsPXBI6jeAQFJKHOv8_iuEmCmCn1shWFrSWc1ares87b2DZB-T1a4cq0CFT7s1YEqpaQx0N8-j_xbMdi0iUGD7K03khkQY2fUJC_2GENlDphX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3994,"author":"李娇; 张振谦","title":"朝向别义的古文字构件研究","abstract":"古人造字,往往用變化一個字的形體的方式來表示與之相關的另一個概念,改變構件朝向是其中的重要方式。構件朝向別義的古文字一直不為學術界所關注,已有研究只是將“古文字反正或倒正無別”作為辨析古文字字形時經常被利用的一條規律,但這條規律並不適用於所有古文字。有些古文字通過構件朝向來構成新字或區別意義。為了保證不致濫用正反、正倒無別的規律,就務必知道哪一類字對正反或正倒無別規律是適用的,哪一類字是不適用的。以這個規律作為大前提,才能正確運用古文字正反或正倒無別的規律,從而有利於古文字字形的特點及字形演變規律的研究探索。本文以《新甲骨文編》、《新金文編》和《戰國文字編》為材料來源,根據構件朝向別義的原則,","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqaeHaGcvx_M677MhtheA-2eUFFpn-5SpEcqhDuukyBFSobz_EIstlQIdRAbbH3KDbK-xSLdJN5vHbkI_WcRO2_XcDVORp2S97Oa8dMjgZtbyZmVurlv30jRvL64BMdFkAl5CzbdL2zAPOg9kaK1BGg4l3JHz2BRwKSEbumL9_bC-70wE9hh6b&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3996,"author":"王保成","title":"頍方彝新解","abstract":"頍方彝重新著录于《殷周金文集成》,考释者们对该铭文的意见还存在着一定的分歧,或因文例和字形难解而怀疑本器为伪品。本文在通读铭文和对一些特殊字探讨之后,认为此器不伪,同时认为该器器主应是高。","categories":["02_字词句考释"],"year":2015,"publication":"励耘语言学刊","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2015.01.020","pages":"267-273","volume":""},{"id":3997,"author":"宋華强","title":"西周金文札記二則","abstract":"一、釋我方鼎銘文的&quot;■&quot;西周早期的我方鼎銘文云:&quot;隹十月又一月丁亥,我乍■A祖乙、妣乙、祖己、妣癸,延礿■二母。咸。&quot;(《集成》2763-1)其中A作■,連劭名、趙平安等先生釋爲&quot;■&quot;。1我懷疑&quot;示&quot;旁上部可能是&quot;衁&quot;字的省寫。殷墟甲骨卜辭中&quot;衁&quot;字或作■,2上部的如果把中間小圈填實,就和A的上部相同了(由於刻寫與鑄造的不同,甲骨文空廓形的寫法在金文常作填實形)。&quot;衁&quot;作爲偏旁時或作上下結構,如,3而上","categories":["02_字词句考释"],"year":2015,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLRbFtIjYcWzl8RHX0y7HIRyf-DSL9v548WXHutzUKKwju4K-VaTFbZeCJZomEF9xcsF-5Ze8xNE1CGfbERqqs95YjKUAzphOv8cQD4JKf9__tFmD31OW1cQMnb7NWYm4fi2E3aDV3Vu2WzpQHhsIi2NPrztMgiB_pjegtw6Lvreg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"1-4, 294","volume":""},{"id":4001,"author":"陈娜娜; 黄亚平","title":"形体相似与符号化的研究","abstract":"按照区域划分,战国文字可分为齐系文字、晋系文字、燕系文字、楚系文字和秦系文字。石鼓文是现存的秦系文字的代表。战国时期社会生活的巨大变化对文字形体发展产生了重大的影响,这一时期的文字的异形现象非常的严重,文字的形体变化多端。许多字体的变化没有什么规律。这一时期的文字内部形体变化差异比较大,我们不仅要看到其内部的差异,还要看到这一时期文字在形体上的相似之处。文字形体是异中有同,不能忽视其相同的方面。此外,这一时期的文字属于整个文字发展时期的某一部分,它同时也具有文字发展的共性,其内部的文字发展机制与人类思维发展由具体形象向抽象过渡的一致性。观察发现,这一时期的文字内部存在文字形体上的相似。特别是石","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLNtVRCpb4Gfk9cjeduhrhQuQ8oE7dP-jT5yIpzO_44fDvcejW3O2BVH2pjnVhyHkXwgFA_56Ho3_unnhKqslRTCv5l4_zNDCu16vkEiGKgMVoWI05rV6uddOb5XeSRH9bfrmSb4ilD9r1EFaQKl2xKqr8zPsCawvyebkRpKG1Ljoz8nWtLT3wM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4002,"author":"秦晓华","title":"战国三晋兵器铭辞格式特点研究","abstract":"战国时期三晋兵器铭辞格式有其共性,即&quot;令+工帀+冶&quot;的铭文格式为三晋共有。赵、魏两国虽然都有两级监造的款式,但赵国未署冶名,而魏国的督造者未出现。三晋&quot;库&quot;的设置各不相同,&quot;库&quot;为韩国所特有,赵国以相邦督造的兵器仅见左、右库,而且库名之前一般要冠以&quot;邦&quot;字。","categories":["02_字词句考释"],"year":2015,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2015.03.009","pages":"67-73","volume":"55"},{"id":4003,"author":"孙伟龙; 曲冰","title":"绍兴塔山甬钟器主考辨","abstract":"绍兴塔山甬钟又被称为&quot;自钟&quot;、&quot;自铎&quot;、&quot;之乘晨钟&quot;。由于其铭文无论在文字释读方面,还是在标点断句方面,都还存在着多种不同看法,所以有关该钟器主名字的认定也是众说纷纭:有的学者认为器主是&quot;自&quot;,有的学者认为器主是&quot;之乘晨&quot;,有的学者认为器主是&quot;之乘辰&quot;。在之前学者们研究的基础之上,本文主要做了以下两方面工作:第一,对铭文中在判定器主方面具有关键作用的文字,重新进行了详细地考订释读;第二,对徐国铜器铭文中器主自述身世的方式进行了总结,归纳出两种习惯模式,即&quot;徐王/君(","categories":["02_字词句考释"],"year":2015,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKw9M-22j_jn7qssX8BQ-SoHZpSB5GDZxGcoi3vk4N7Di0VROOGghmYalqEqf9VrG2O6nI2PsLwClIjQC5dnjDKAFIqrtsF77bSvBaUOFmcMZUIG5Jcg0jzaK7QtUChdLr9n_0F_6SZD7ZCyQtJXPss0JacuRKqLNf5icY5Fj1fzhL8OnGJ_TNj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-69","volume":""},{"id":4006,"author":"贾雅婷","title":"“穆”之本义考","abstract":"《说文解字·禾部》&quot;穆&quot;之本义,历来众说纷纭,其中以&quot;华美&quot;与&quot;幽微&quot;二说为多。通过字形与文献考察,认为&quot;华美&quot;当为&quot;穆&quot;之本义,而&quot;幽微&quot;当是&quot;穆&quot;之假借义。","categories":["02_字词句考释"],"year":2015,"publication":"乐山师范学院学报","link":"https://link.cnki.net/doi/10.16069/j.cnki.51-1610/g4.2015.05.012","pages":"58-60","volume":"30"},{"id":4008,"author":"申红义","title":"从简帛文献看《经典释文》异文成因及来源","abstract":"唐代陆德明所撰《经典释文》收录了大量的异文资料,前人多以&quot;错讹&quot;等名目对这些异文进行概括。参照新材料如简帛文献,可以看出《经典释文》中的异文是秦汉时期&quot;文字异形&quot;的产物。这些异文具有明显的秦汉文字特征,是这一时期的通行字。这种因书写习惯和时代风尚与后世不同而形成的异文,应充分考虑其时代性,不能一律概之以&quot;错讹&quot;。","categories":["02_字词句考释"],"year":2015,"publication":"青海师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16229/j.cnki.issn1000-5102.2015.03.024","pages":"132-137","volume":"37"},{"id":4009,"author":"雷缙碚; 喻遂生","title":"甲金文“阜”字及字符“阜”的两个来源","abstract":"甲骨文以往被释作&quot;阜&quot;的字,主要有■等四种形体。关于&quot;阜&quot;字的解说,或以为象土山,如《说文解字·阜部》:&quot;■,大陆,山无石者。象形。凡阜之属皆从阜。■,古文。&quot;段注:&quot;象形者,象土山高大而上平,可层絫而上,首象其高,下象其三成也。&quot;现代学者或以为象阶级类建筑,如徐中舒(1989:1507-1508):&quot;古代穴居,于竖穴侧壁挖有■形之脚窝以便出入登降。甲骨文自字作■等形,正象脚窝之形,作■者乃其省体。&quot;此外李孝定(1965:4129):&quot;■■象山之阪级峻峭崚嶒。&quot;此显然糅合二者","categories":["02_字词句考释"],"year":2015,"publication":"中国语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPeb-gg5zsLF3FHQ6cRaob1AknFbLzwWbeWZFo96ZVVsTNro3Mp8RTIQ9080HkPpCv7MrW5U4FjI1BD86lpOwKiyvGDzZfluFwumOVwEQkKVufqi5cyX8E0EdLN_3g4MyLrLiJaZvYZCyQmjjBt2JGPro42PhIYZqawWU7mXOVGpRkl4lDMJYo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"274-277","volume":""},{"id":4011,"author":"孙银琼","title":"金文复音词的词典学价值例析","abstract":"金文复音词具有四个方面的词典学价值:可据以增收词目;可据以增补词的义项;可据以提前书证;可据以修正释义。","categories":["02_字词句考释"],"year":2015,"publication":"湖北社会科学","link":"https://link.cnki.net/doi/10.13660/j.cnki.42-1112/c.013198","pages":"132-135","volume":""},{"id":4013,"author":"蔣紅; 喻遂生","title":"兩周金文時間範疇研究","abstract":"時間是萬事萬物存在和發展的前提。它是客觀存在的，任何人不能加以改變，我們可以能動地感知它，并通過語言表達它。時間的記錄方式不僅反映了當時的文化，也具有豐富的語言文化内涵。金文作為漢字發展史上的一個重要階段，其歷史跨度較之甲骨文要大得多。經過學界眾多專家、學者的不懈努力，在文字考釋、詞彙、語法、字形分析等研究上都取得了顯著的成就。然而，從語言方面來研究金文的時間問題，還未見前人作過全面系統的論述。本文對金文的時間範疇進行分析和歸納，探討金文時間表達的方式。本文正文共有五章：第一章為緒論。主要論述時間範疇的界定，研究現狀，選題意義以及研究方法等問題。第二章為兩周金文時間名詞研究。兩周金文時間名詞分","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICBKBlEZ5om3TgQPUshF7tkhx7rc6ciXxx39ttz0myRcwqi583lF6CT_FS8b4U7gHcUqC92IEGhMEvJF3jNEihLBMEoP8MkIgfebQBc0I0T5JQG9SmRq7R-ea3d7gXl2Ie8SZaGweW23d165PdmEGOgfQC4yHKduFn_z8JULEJyitdDI37Vshy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4019,"author":"熊欢; 张鹏飞","title":"中国古代农业文化在汉字中的折射研究","abstract":"语言是社会成员联系的纽带,同时也是民族文化赖以建构与传播的工具。汉字作为标记汉民族语言的书写符号系统,它以视觉符号的形式折射和传承悠久灿烂的中华文化,弥补了汉语言声音信息不易保存的局限。由于汉字具有文化镜像功能和文化传承功能,因此透过汉字可以探究汉字棱镜中的文化信息。农业是我国古代最重要的生产部门,古代农业文化信息在汉字棱镜中存在一定的折射。在引言部分,概述选题缘起、汉字与农业文化研究现状、研究意义、研究方法等。在汉字与农业物质文化部分,透过汉字讨论古代农作物、农业生产工具、农田水利、谷物储存场所等方面。在汉字与农业制度文化部分,透过汉字探讨古代农田制度、赋税制度、农官制度、耕作制度、祭祀礼仪","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFsp70zwscWsi7OPapCkxvLN_DP9NUMgqk6uSDC-BGloasZhSmbZxitPQL0PAu7SVwN2nYbIzOFSPMlasG9m7wnRbsSUjeXkw4OAMacMlcLMwRso04fL_2nF2ebNiSCZ7dSzJm9sT7WMDMHXJsNjJw3ulUUieVDQ7aOuNahePre-JFVcmMcXaA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4023,"author":"朱穎星; 董蓮池","title":"秦系金文整理與研究","abstract":"秦文字上承西周金文,下啟後世用字,是汉字发展史上的一座橘棵。秦系金文是秦文字的重要组成部份。然而,在各类秦文字的研究整理成果中,关於秦系金文的系统而全面的专门研究不多。因此,有必要封秦系金文進行系统而全面的整理与研究。本文在全面整理春秋至始皇统一期间秦系金文资料的基础上,封秦系金文在不同时期构形发展情况進行研究,兼舆《说文》小篆、古文、籀文字形進行比较研究,勾勒出秦系金文的特点；并编制秦系金文字形全编,为相关研究提供字檬。本文分为上下雨编。上编为秦系金文的研究部分,分为四章。第一章为绪论,封本文研究目的和意羲、秦系金文相关研究现状进行了概述。第二章研究秦系金文的构形,封秦系金文构件形体的增省、","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK44hk0U2fOq2M-eshoMsR8sH-wziPDZoHoG6jX001l92zfbe7xcy8lv9dbF-aMVEUe4qoGYmrC4BQL3YbHRN2lJ5QAE_WyhB32voXpSp_2QpRGTSmdhxMJ6xQPjFJEJSzYWlK-ynv9uDXPydVcNqRbZ8XHBXrEU5t-7ezbdLW0uePUnBSg5l4m&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4025,"author":"陈栋; 郝士宏","title":"丁山古文字研究初探","abstract":"本文是以丁山古文字成就为研究对象,通过文献的收集整理,梳理丁山关于古文字研究的成果,同时与现当代其它学者的学术观点进行纵向的分析比较,在此基础上对丁山古文字的成就做简要的综述与评价。全文共包括三个部分。第一章,绪论,包括丁山生平及其学术述略,国内外学者对丁山的学术研究情况以及本文的研究内容、方法、目的、意义等方面。第二章是本文的主要章节,第一节甲骨文研究,总结丁山首释的字,误释的字以及释字的方法；第二节金文研究,主要是对丁山文章中器物研究的集释；第三节是对丁山利用古文字对古史的研究成果进行阐述；第四节再从整体上概括丁山在古文字研究领域的价值与地位。第三章为结语。","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjWch5whh6gePTo7auo8oN2IwsXn5NpsK_-WNngLhMBoAV1pBuJpHdFvcCCV-f1a7ZBA96HQeR27XKYVH2VeJ6BKDfV8MZwCJ-kLh4SHdTfst-xjQLBsvlWZKk9o6OrxdVKkvuCbXKQKBR795ox4WTQUIv6X_zI5VVCk-V_LXubKCNPqFaAvpf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4029,"author":"武霞; 张世超","title":"霸伯孟銘文集釋及相關問題研究","abstract":"2009年,山西省翼城大河口地區的西周墓地出土了一件內有較長銘文的青銅器——霸伯盂。銘文內容是關於西周時期賓禮的記載,可以與《周禮》、《儀禮》、《左傳》等傳世文獻進行相互印證,並且補充了傳世文獻的不足,因此具有十分珍貴的史料價值,引起了學界廣泛的關注。本文以霸伯盂銘文為研究對象,在已有的研究成果的基礎上,重在疏通文意及探討相關賓禮問題,主要分為三個部分:首先,是對霸伯盂研究概況的綜述,包括文字的隸定與訓釋、篇章的斷句、禮儀問題的討論等;其次,是對銘文的集釋,這也是本文的重點所在。力求窮盡式地搜集和吸納學者們的研究成果,分析各家之說並擇優而從之,努力做到既尊重別人的學術成果,也能表達自己的看法,","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ7wrcL5R3mUwzev0X_S6XkNZRu5_Ak6geQgghD1k6u1pwA5j3-hRcwHn38Ag6GhbTMGP0XnNRuTB0XdOTjyE9vwNmZKnNQ-V_r3QvoGSZqtEs6Nwyxxb3XcTarlD7AwFAS4_Gp8VipN5tEjAAbFDfX9Nkxh-i9VNPrK3KOWLVt0HUSOCnB58Ie&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4031,"author":"謝明文","title":"釋束周金文中的幾例“■”字","abstract":"1933年安徽壽縣朱家集李三孤堆楚王墓出土了一批青銅器,其中在鼎、盉、爐上有下列字形:A1■鑄客鼎（蓋）《銘文選》[1]676《集成》[2]2300 A2■鑄客盉（蓋）《集成》09420 A3■鑄客爐,[3]《銘文選》677、《集成》10388B1■鑄客鼎（器）,《銘文選》676、《集成》02300 B2■鑄客盉（器）,《集成》09420以上A、B兩组字形,所在辭例爲&quot;鑄客爲集A/B爲之&quot;。許多研究者認爲它們是一字","categories":["02_字词句考释"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPjEPYB-8tRQESQ7wzy60G4k148PROaE-cLipngpBq49sCeh9G-TWPz7porNzl_DKt5vcGP_XuJUp5hdMglQeNktd2o8zWCRlv_6cC4fqg69piTMzXRfiJEdHkNzFMA5ReI0Hqf0jMbtymhIpdP-pg6hqe9k-rxwzdv1RT9QBl5A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-90","volume":""},{"id":4032,"author":"李守奎","title":"“屎”與“徙之古文”考","abstract":"清華簡《繫年》&quot;屎&quot;與&quot;层&quot;並出,用法有别。追根溯源,這兩個字典甲骨文中的&quot;尿&quot;、西周金文中的&quot;■&quot;有關。古文字中的&quot;■&quot;&quot;■&quot;二字胡厚宣、郭沫若、李家浩、裘錫圭等學者先後做過不同程度的研究,裘錫圭先生曾作了全面的總結。[1]綜理諸說,大致有如下幾點:胡厚宣認爲甲骨文中的&quot;■&quot;後來變作《說文》&quot;徙&quot;字古文&quot;■&quot;,又變爲&quot;屎&quot;。屎田就是在田地里施糞肥。","categories":["02_字词句考释"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISLDqHIoSAnso_Mb4yNFVcJJ4stgmel3WqJHaa43Mv3aSCJJbL5m-_pyY2U9e5bEUElaGaaYkFjPQHyIbcL_CX5HnIaywlzSseODPRhPDrmIJMWgPRJLKptV-Pu4lEYHYl5WUQZ3lvqUR08GN9Ksm3oOi4ewI1HHOIJ8qakPlo8A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"154-162","volume":""},{"id":4034,"author":"李家浩","title":"郳公■父鎛銘文補釋","abstract":"郳公■父鎛是近年流散的重要有銘銅器之一,周亞、董珊已有專文研究,提出了許多好的見解。[1]我擬在他們研究的基礎上,補充一點不成熟的意見,不妥之處,敬請周、董兩位先生和讀者指教。據周亞、董珊所說的有關情况,郳公■父鑄大概共有六件:北京三件,山東一件,香港一件,上海博物館一件,銘文相同。周亞對上海博物館收藏的那一件郳公■父鑄的大小、形制作了詳細介紹,並且公佈了器形照片、銘文拓片和摹本,所以我以上博郳","categories":["02_字词句考释"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJzgif37dONLHYuFFEpcmK2E7wuCjoG4TOc6ddocyTHZE08sH4EaIJaOY0ouPPql3kphem8A__o-NuVfZMRwzhsNGfzlULHQP0ZLMG4jSB18Ac9Wu4nq-mmHAJ3PAJx9FFBUPokXu1ywC8IBneXaBzx2GiCIuTyao06sHskeVgbWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46027","volume":""},{"id":4035,"author":"何景成","title":"釋曾侯與編鐘銘文中的“堂”","abstract":"湖北隨州文峰塔墓地發掘出土的曾侯與編鐘（1號鐘）銘文記載了曾國的重要歷史,以及曾與楚、吴等國的關係,具有重要的學術價值。[1]甫一發表,即引發學者的熱烈討論。[2]銘文中涉及曾國與楚國、吴國關係的内容是:周室之既卑,吾用燮A楚,吴恃有衆庶,行亂西征南伐,乃加于楚。荆邦既爝（削）[3],而天命將虞。有嚴曾侯,業業厥聲,親敷武功,楚命是争,復奠楚王。","categories":["02_字词句考释"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJzgif37dONLHYuFFEpcmK2E7wuCjoG4TOc6ddocyTHZE08sH4EaIJakortUO5abP0JccwdZT5L7z65ZZZ8iln6lGubsKxDGKWGglJsIiRyMQJj9--OYt2_uP8wuRcKTH-ouuzPdqpwmAVc7lxGeqgOO5K0CUP8lUg_RQyf97nWbg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46345","volume":""},{"id":4036,"author":"袁金平; 王麗","title":"新出曾國金文考釋二題","abstract":"2012—2013年,湖北省考古研究所等單位在隨州市東城區義地崗墓地的東南部文峰塔發掘出東周墓葬54座,出土大量銅禮器,多有銘文,具有非常重要的學術價值與意義。[1]今就其中兩件銘文中的有關問題進行討論。（一）曾侯丙缶[2]M18北坑中出土一對銅方缶,直口鼓腹,方形圈足,肩上附有兩個對稱的龍耳銜環,蓋上飾四個環鈕;通體菱形紋,並鑲嵌有经松石,器、蓋皆有銘文。其中M18:2蓋","categories":["02_字词句考释"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJGmVk7hdHI2SY44h8yhH8szY6ytwyXQHWxMPg6bW88dMvqM9I6x7710qU9-VaAMlTLf71Gl52jPQZFplepYRU_p6Ob-Knzn9uu4CMgiuhvyTAD6eTIQbn8lsM-gH8bN9dbQTZ27axB5imcVR1uY1zDsG7tUKoE4-9ZucgzPkGbTA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-24","volume":""},{"id":4037,"author":"許可","title":"試説隨州文峰塔曾侯與墓編鐘銘文中从“匕”之字","abstract":"近來,隨州文峰塔曾侯與墓地出土的編鐘引起熱烈討論。其中,M1:1鐘正面左鼓銘文說&quot;王■（逝）命南公■（營）宅汭土,君△淮尸（夷）,■（臨）有江■（夏）&quot;。[1]句中△字,原照、拓片、摹本分别作:發掘簡報釋&quot;此&quot;,[2]方輝[3]、徐少華[4]、董珊[5]等先生均從之。凡國棟先生說:&quot;戰國楚簡‘此'字形體多變化,銘文該字與郭店緇衣14號簡■字寫法相近。君此淮夷,意思是說南宫受命統治淮夷地區。&quot;[36]李學勤先生則認爲:&quot;暫隸寫爲‘■’,是从","categories":["02_字词句考释"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHbaMrM6sxdqDKdg85DmTRGSk1Pxb55QHZXkDT87I_v8rNSksEsmEVqt7Cs49CiiuZzrKt7Fyt8ELURFQHdZe-raWriPJ1sUwLnT1k5KscLT-zKzbqwKp0se5PoqqjFpleoMjj5Vc_VIo6FiK-3X9Ww2k-fVNaIjgwcc4L7qQSSA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-30","volume":""},{"id":4042,"author":"刘影; 冯亚坤","title":"“县”字词义考释","abstract":"&quot;县&quot;字当今的词义通常指最基本的&quot;行政区划单位&quot;。古汉语中的&quot;县&quot;假借为&quot;寰&quot;,通&quot;悬&quot;,通常用作名词、动词和形容词。随着时间的推移,&quot;县&quot;字逐渐被引申并确定为一种&quot;行政区划单位&quot;,这一含义的确定历经了三个阶段。对&quot;县&quot;进行考释不仅可以了解&quot;县&quot;字的语义演变,而且可以揭示其背后隐含的国家体制、国家行政区划的变化趋势。","categories":["02_字词句考释"],"year":2015,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPL9neOHJaNWn2-B0jJ2JsXG44ihszRIx_5PcNfHol_7MTAgA13VSgwo2h02xFtCw6-pApRUiosFVBYk1txalkNnazPOaIZ8nH4wN4ptEtaF6XoaDb2-vyvWc5VvD6X0w8hRJqQYjiUFuJKggyFm8VqWJfMp9EOKEAZRgEjRm317HqxPCxGFcU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-55","volume":""},{"id":4044,"author":"黄益飞","title":"平顶山应国墓地出土“旡”鼎铭文研究","abstract":"■鼎出土于应国墓地M242,年代属于西周早期晚段[1]。&quot;■&quot;为作器者名,字亦见于殷卜辞,与&quot;无&quot;字作&quot;■&quot;不类,该字目前尚未识出。发掘报告称作&quot;无&quot;鼎,或系权宜之计,为不引起混乱,本文亦暂称作&quot;无&quot;鼎。鼎铭共5行24字:&quot;旡■■（稽）首,皇兄考（孝）于公,宣厥事。弟不敢不择衣,夙夜用占■（将）公&quot;[2]（图一）。铭文所记关乎西周宗法及丧服制度,具有重要学术价值,本文略为疏证,以就正于方家。（一）皇兄孝于公,宣厥事&quot;公&quot;乃亲称,与后文&quot;夙夜用占将","categories":["02_字词句考释"],"year":2015,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1FOFXQfCpjhASGzQZWBXZHjhS7phNfec12v7N2RZkYVXZ75-bQB1lyiFaNX4jskd67pZFT8_e6FOjkcc5DGvybjVVZHMmwuEPT108xZ3uS4ptxltr9TQf8n14sLYOFV5rO3fJYvuRWwvgRTOx4d0mSvPm8vhGBt4mjwzAJC9-tcCJ1yZ8MPq_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96-101","volume":""},{"id":4047,"author":"景红艳","title":"金文所见周代王室赏赐物中的“黄”及其等级","abstract":"&quot;黄&quot;是金文所见周代王室赏赐活动中频见的物品。根据金文中&quot;黄&quot;的颜色、纹饰、质地以及它与相关服饰的固定搭配等综合因素可以推断:&quot;黄&quot;为周代贵族男子束腰的带子而非佩玉之属。金文中的&quot;黄&quot;颜色丰富,形制复杂,等级森严,这不仅弥补了传世文献对周代服饰制度记载的不足,同时也印证了周代服饰制度繁密的内容和严格的等级。","categories":["02_字词句考释"],"year":2015,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2015.02.005","pages":"24-27","volume":"35"},{"id":4051,"author":"刘孝霞","title":"释荣仲方鼎“■”字","abstract":"本文通过对&quot;序&quot;和&quot;宫&quot;的时代考察和字形分析,认为《荣仲方鼎》中的&quot;■&quot;不应释为&quot;序&quot;,而应释为&quot;宫&quot;,是居住之所,非宗庙。&quot;王作荣仲宫&quot;中的&quot;宫&quot;应是王对荣仲的赏赐。","categories":["02_字词句考释"],"year":2015,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL7JXu-YHjusbWi-j99TKiDfxP3IcvMBG7_sH5GpVuahD9yxkj0A1Xp0P1k2EYA0eW9PulFxRHW5Zy2vivQFq7MjXSK_GaRKnqEo3ohOUibVbRZ3ABfF9U6QwNkIzYkxA74DhPWYE0N1iFUkmZsmAuAKR1WDh_-cPK7u1AlS6aI61ZWejsZCBjj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-99, 118","volume":""},{"id":4052,"author":"吴镇烽","title":"“鱼鼎匕”新释","abstract":"新发现一件&quot;鱼鼎匕&quot;,与20世纪20年代山西浑源出土的鱼鼎匕形制相同,也断成两截,但茬口相合,文字不缺,铭文没有错金,匕体锈色斑驳,确属真品。此铭填补了传世鱼鼎匕缺字的遗憾。今据新见匕重新解读铭文,并得出结论,匕铭的内容系一则有感而发的告诫性箴言。这2件匕与所谓的鱼鼎无关,匕名不应称为&quot;鱼鼎匕&quot;而应改名&quot;箴铭匕&quot;。","categories":["02_字词句考释"],"year":2015,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKdPIE3teEEh58YV_tUY5_iwzdjLEHLwHD2bwnxzKAqnQwb4Tm59k3NyRIS02PwWlt4h_CJikaR3m_t1JKE2IUyfr8rxehRbfAU3dnZIvCR0dt2mxdDfNzOS_zCO_UWi6YXiKeqbRU4OFFSRp3lrQKmlC36xdIC7bSawxkJ916geQS15k4MjWBO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-57","volume":""},{"id":4054,"author":"趙晉鋒; 陳光田","title":"中山國出土器物銘文詞彙研究","abstract":"1977年,河北省平山縣三汲地區發掘了中山國墓葬群,出土文物一萬九千餘件。中山王墓出土了大量有銘器物,包括銅器、兵器、貨幣、石器、陶器、木器、漆器等文字,其中中山王鼎、中山王壺、胤嗣壺、兆域圖等器物上的長篇銘文,為研究中山國歷史提供了重要資料,是建國以來戰國文字資料的重大發現之一。中山國器物出土以來,有關文字、歷史、文化等方面的研究已有不少成果,但一直以來,有關詞彙方面的研究卻較為薄弱。詞彙研究是語言學研究不可或缺的一部分,它可以更真實地展示當時的語言狀況,對漢語史研究具有極為重要的意義。本文在前人考釋與研究的基礎上,運用詞彙學的基本理論,借助定量研究的方法,對中山國出土器物銘文詞彙做一個系統","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqbMvYN6-EGYkzsULkzr02ppzk74hfdZr4xmPmMlAixK6qgiPl6WWcII5PNVXef9Xn-LL59fs8naelEqiWZOegZDlQqajq64k0PfyZVPAZnrc7hX31_2qlbovxL-smPfWIgS2qo6N8PyR8D4GRuEsjn1KZrto_yoh2ukGRj5BznxGud0OYdeGo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4058,"author":"楊坤; 吳良寶","title":"戰國晉系銅器銘文校釋及相關問題初探","abstract":"戰國晉系銅器銘文內容豐富，具有極高的歷史學和文字學價值，相關研究成果眾多。但到目前為止，在晉系銅器銘文逐篇校釋及重點語詞的文義辨析方面，仍然存在作進一步工作的餘地。同時，在基於銅器銘文的鑄造、校量、收藏置用制度研究方面，部分概念亟需釐清，研究深度也可進一步拓展。是為本文寫作初衷和意義所在。本文主要對晉系青銅器銘文進行校釋，同時對銘文所涉及的鑄造、校量、置用等制度進行梳理和探討。所謂的晉系國家，指韓、趙、魏、兩周。銅器則專指兵器、貨幣、銅鏡之外的有銘青銅製品。本文採用古文字學和歷史學相結合的研究方法。以文字考釋為基礎，在廣泛參考學者已有研究成果的基礎上，力求銘文文義、國別及時代的正確解讀，同時也","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5UDCPzaLL8h-ZoLvQBj8L1Koqs_Kk9ZO-ZACstrox9WlgzPDv_PR5IdsaxESpvwDrPyHn5oiP5ySkBQiOMLmrugeuyq0jhdH1a-AieuYPj8DTJ36WX5pbTu2c71ZtepBtYk9SPGgYhVppctT9cqUM_O-q5Q6V-dIQK2SCiaEHjAFGPjKbSn2_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4061,"author":"陈运舟","title":"说“夷”","abstract":"殷商时代,商人把生活在山东、江苏一带的人称为夷。《说文》:&quot;夷,东方人也。&quot;与中原地区的人两膝着地的跪坐方式不同,夷人坐姿是&quot;踞&quot;。这&quot;踞&quot;,据资料看来有两义,一是蹲,一是如同当今世人的普遍坐法。前者,如甲骨文、金文中的夷字,就是一个蹲踞的人形。甲骨文","categories":["02_字词句考释"],"year":2015,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6MP6T7BCBPHiU7eexBWDjQ3jqWdkPPbhHIcZS57iTXZ7TF_pckvbktfy_5ETFjSyE8Jgg7DV1TH8DQcnpSBxvZcWZaz_sIwFLXXtf_02FBCVdBBHLbBQ0I5TjSGqWlyl5Zv2qTgKdBGNXR4bjReQqZfJPjxmSGg6SlcwmLpWwKIuMmZ-Z5IkJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-48","volume":""},{"id":4064,"author":"高兴全","title":"“书于竹帛,镂于金石”——春秋战国文字载体及用字现象","abstract":"一般情况下,将春秋文字与西周文字放在一起研究,现根据历史阶段将春秋与战国合二为一。墨子&quot;书于竹帛,镂于金石,琢于盘盂&quot;正反映了当时的文字存在形态。从目前考古所发现的实物成果来看,殷商、西周时期的字体不论载体还是形体都比较统一。殷商文字以甲骨文为主,金文为辅,还包括少量的玉刻、陶器、石器文字等;西周以铜器铭文为主,还包括甲骨、玉刻、陶器、石器文字等。到了春秋战国,文字的载体名目繁多,有铜器、铁器、金器、银","categories":["02_字词句考释"],"year":2015,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDCbSbKpPeFqFEQn-QXU2z0S9tz698IQpMvbRs28TFAVFFAFtysEZAQTelz6FD0Z_Z4ww2rAycWSBp3NsrwADNDH7Nza0CKcrW6hGhEASK0wDJpaj2xtZZhV-hELUOWG3KMGUraQ-Ry3g55FOC7Itidk6m0NsRpJNmkXWv5XnT7XyV1phVU6h7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-129","volume":""},{"id":4065,"author":"武树臣","title":"古文字中的“仁”","abstract":"甲骨文中是否存在从人从二的&quot;仁&quot;字,学术界尚无最后定论。但金文中的&quot;仁&quot;字始见于西周晚期的《夷伯夷簋器铭》,又见于春秋早期的《鲁伯俞父簋铭》,以及战国中山王墓铜器铭文和睡虎地秦墓竹简,可谓一脉相传。甲骨文中有&quot;仁&quot;的八个原形字:仌、夾、化、乘、尼、儿(兒)、身、申。它们反映了东夷民族&quot;相人耦&quot;的古老风俗,也是&quot;仁&quot;字问世的文化土壤。这些原形字的共同特点是双人结构。重文符号&quot;二&quot;的使用是&quot;仁&quot;字产生的技术条件。孔子关于&quot;仁&quot;的学说正是以殷","categories":["02_字词句考释"],"year":2015,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2015.01.013","pages":"70-74","volume":"36"},{"id":4070,"author":"黄锦前","title":"妟鼎铭文试释","abstract":"本文对新公布的河南平顶山应国墓地M242出土的一件妟鼎进行了讨论。认为从形制等方面来看,其时代可定为康王时,而不会晚至昭穆时期。对铭文中整理者误释的字如&quot;妟&quot;字进行了重新释读;将所谓&quot;择衣&quot;改读作&quot;怿瘁&quot;,训&quot;尽瘁&quot;,认为与所谓的&quot;丧服礼&quot;无关。又将其与传世两件西周早期的应公鼎铭文进行对读,认为从时代来看,妟鼎铭的&quot;公&quot;,可能即应公鼎铭的&quot;应公&quot;,亦即第一代应公;疑应公鼎铭的&quot;&quot;可能即妟鼎铭的&quot;皇兄&quot;,从铭文来看,很","categories":["02_字词句考释"],"year":2015,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZr4djzespAZlkguI6TL6mtBrY7VSKchggarweelTBQh_RA9LVyBeXIAe6_Lc6wdbtxbE_fY1Btul206wCgVxVRkM3A5q7FCu4N4IE9TBXKNlbm1KDlJh8ItEU4AvBUD9sW9Dl_MV9_1VcL1NsT_cb_2G4NGeW_I0TJ1uRDZd7hD2tz1AC7ObW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-59","volume":""},{"id":4073,"author":"張晗; 董蓮池","title":"楚銅器銘文整理與研究","abstract":"本文從楚铜器铭文的搜集整理出发,全面搜集截至2014年底为止已公之于世的楚铜器铭文1012件,在前人研究的基础上,充分利用新材料,吸收新的研究成果,從文字学角度对楚铜器铭文造行系统的整理和研究。具体说有以下几个方面：绪论部分,主要介绍本文的选取材料的标准,选题的缘由及其研究意义,评介了前人的研究成果,提出了本文的研究内容。第一章“楚铜器铭文的释文校定”。在充分吸收学术界新的考释成果的基础上,对所收的1012件楚铜器铭文逐一做了新的释文,并附简要校记,以供参考。第二章“楚铜器铭文的特徵探索”。從鸟蟲书、文字使用的复古化、偏旁的换用及与《说文》重文四个方面总结了楚铜器铭文的特徵。第三章“楚铜器铭文","categories":["02_字词句考释"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPDKEB74S0Pr_1FxuJDMmOhYzH7_FcOsV0trwKN-6onmSTijsZARG-o85vAG38mLit20mLQ0RQNC-4UKwlUiLULR1M7rtSR_87DDxhPRIHCrKQlRT1wOFrvRO6S_Xaxjzmt1LQIRdYbDOFWTPK2ML8zdotY8NiZ46bloZpnhomU3FYaybE-ZlZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4077,"author":"松丸道雄; 廣瀨薰雄","title":"關於地支“巳”的疑問","abstract":"明年的干支是&quot;癸巳&quot;1。所以一定會有很多人在寫賀年卡時用各種各樣的方式提這個干支。就本刊而言,按慣例,每年的正月號編&quot;干支印&quot;的專題,因爲本刊是關於篆刻的雜誌,大多數的印章使用古文的字體。不過這個&quot;巳&quot;的古文有一個有點麻煩的問題,所以出於老婆心,我跟編1先生商量,決定寫一篇文章,盡量簡潔","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_h3OYJYsyJvW2pgRmHaSPSa7LiKCj9ksYbLPK2NIDdwQgepUUwDrkkt2nUnAwn4exiDpf1HzQmRN9BEe3fiUqKVEt7eZUcZGrzao9t0wdyGah-HvHFirKx8FhynLIlO5Jr7F-SpxOFoa4R8kY_gV-qh5XMrWjtruwH_LD_p0HJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46028","volume":""},{"id":4078,"author":"朱鳳瀚","title":"新見商金文考釋(二篇)","abstract":"本文是對近年來新發現的兩件商末銅器,即尊與陶觥銘文所作考釋。其中尊,係香港收藏家的藏品,2013年秋在中國文物諮詢中心獲觀其實物1。陶觥,則是2012年8月在中國文物諮詢中心得見其資料2。兩件器物銘文均較長,其内容亦相當重要。現僅將對兩器銘文不成熟的膚淺認識寫出來與大家討論,誠冀","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIrgQ7hatGQ94qyxBfblvHY9eRU1mEz5IjJpPmJIZl7iYdbOpzCGoy4fatKKGv1Y-glg4SC_ROWqK3mCl3ThjVhjcMonFPGJGm3jTWJrIfwYcuj68JLtIi71ccIimDBDF9joMiqXi5HAQ4ZJUTgrIg3fmx9jCbgWnNUi62PM5lGOw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"123-142","volume":""},{"id":4081,"author":"董珊","title":"它簋蓋銘文新釋——西周凡國銅器的重新發現","abstract":"西周銅器它簋僅存簋蓋(圖一),據傳1931年出於洛陽,舊藏劉體智,原器今在比利時皇家藝術與歷史博物館1。簋蓋銘文長達149字(圖二),内容是一篇祭禱辭,在西周金文中是少見的文體。此銘既長,又缺乏對比材料,因此向來比較難讀2。過去我曾在一些小文中順帶討論過這篇銘文的片段3,最近重研此銘,在這裏寫出我的一些意見,希望能有助於通讀全銘。需要先説明的是,這件簋蓋過去被稱爲&quot;沈子它","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL1XjCHI-rG338N7ys7qewpFWzo5kXkAPhxRUxea_Yf0LuFOd-HFUXDFmxpJLdDoPe_AE5i1Qzqs6B7rxEqccqEKyO-i61kF2DL963L069pldThDMrq39wYQhbZ-6AS8MyhYHw25Fts3fGxYF-fToGmmFZb-QiT7mrdN1IzYb62WQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"163-178","volume":""},{"id":4082,"author":"郭永秉","title":"從戰國文字所見的類“倉”形“寒”字論古文獻中表“寒”義的“滄/凔”是轉寫誤釋的産物","abstract":"戰國文字尤其是楚文字資料近年的大量發表及深入研究,不但讓出土文字資料中諸多疑難字的釋讀得以確定,而且也使得先秦文獻在漢代由古文字抄本整理轉寫爲隸書文本的過程中發生的誤釋誤讀等問題不斷地暴露出來。這些問題從發生的角度看,有的屬於文字層面(屬於&quot;誤釋&quot;、&quot;誤抄&quot;),有的則屬於語言層面(屬於&quot;誤","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL1XjCHI-rG338N7ys7qewpFWzo5kXkAPhxRUxea_Yf0LuFOd-HFUXDVsqSvkefJ0otVUQ9TaVkXbwM5i6hvL7xkRDh5TDemrpzHDUEs1WjsbpMszdkEAOr4nSM5-wpAK7Abug7h43Ek53gNlpB9wK9upfnev817sS_mPnlNHaT6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"379-397","volume":""},{"id":4083,"author":"許學仁","title":"漢字形體研究斷鏈管窺","abstract":"壹、前言:董彦堂先生與廣字譜漢字形體發展軌迹之研究,藉由分層、分期、分類、分域等相關條件之繫聯,在文字構形、語音綫索及字義孳乳的基礎上,勾稽演變的字際關係,交錯比對文字形體字樣,以建構文字的發展譜系。基本字樣的采擷,傳統純依字書、韻書、辭書,今日則多","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSDpgzdKRyF05PySbFdh2ygbfsoZZ-WXATeJ8fOSP7ZWrEMMIjH02WTsyetqmklPPtNAarcmrF7MZC_GCLD1GdnrfE9lKfjKNms26GQ1AWw3sNPncK8zfkDVtwOcfJY84cp018wqC2qpd4HiIv7US6s5dAEAZbfVgkO21OKa4x-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"717-728","volume":""},{"id":4085,"author":"田煒","title":"西周金文與傳世文獻字詞關係之對比研究","abstract":"一、引言王國維先生在《古史新證》中説了一段很有名的話:吾(5生於今日,幸於紙上之材料外更得地下之新材料。由此種材料,我(5固得據以補正紙上之材料,亦得證明古書之某部分全爲實録,即百家不雅馴之言亦不無表示一面之事實。此二重證據法惟在今日始得爲之。","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKyK3MiEODY6vLbkF3G40xFa9MgbPt9oDgZv8eE5LWCh1_-_v9aDjic2n1zmcR5THJFq71rLYnveq5vstKwl-LqH3YSOKgqjJaW5W8YL3oA8jyyWQBIOeNylFB9m7ZVbpURv16rVr3tiaUohbJrS9-o0j8lKA66JgFa_KBgyEqteA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"191-217","volume":""},{"id":4086,"author":"陳劍","title":"《容成氏》補釋三則","abstract":"一《上海博物館藏戰國楚竹書(二)·容成氏》講&quot;堯&quot;的部分,謂其時&quot;不懽(勸)而民力,不型(刑)殺而無(盜)惻(賊),甚緩而民備(服)&quot;之後,續云:於是■(乎)方【6】百里之■(中)■(■―率),天下之人(就),■(奉)而立之,■(以)爲天子。於是","categories":["02_字词句考释"],"year":2015,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYGf2Lg_4hw_Sk4mXos9_0XJ_yD_NAOo8leK7GnPInlOafpZCSP-llCtafclKrvO4Q0IQsQaiWNe1u1qYAaM7-Y9bpkhOMuxQw24crdVyBgKHhWajRehdmtyi2osj0RlKeCFzVkEJeFW3GAEm0FDn1On1d3F1WX30gTceciYfytg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"365-378","volume":""},{"id":4089,"author":"杨明明","title":"颂器铭文与西周册命礼新探——“受令册佩以出”再释","abstract":"西周晚期颂鼎铭文是西周册命礼最完善的篇章之一,对其铭文内容的深入研究有利于更详细地了解当时的册命制度。铭文&quot;受令册佩以出&quot;一句虽无疑难字词,但其句读历来存在争议,利用新出金文用例结合文献判断,该句当断为&quot;受令册、佩以出&quot;,&quot;令册&quot;与&quot;佩&quot;同为&quot;受&quot;之宾语,&quot;佩&quot;当指赏赐的命服。册命时当面赐予命书及命服,而命书及命服之外的赏赐物品则在门外,并非当面授予,故云&quot;受令册、佩以出&quot;,这一记载正与《仪礼·觐礼》所载相关礼制相吻合。","categories":["02_字词句考释"],"year":2015,"publication":"中华文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2kmxZfbBDX2rr7XWL0rdcHyfa_YkJyV3L4lAPeNpBu1fJ7Ay37wkNPX5mDEZYkt9IxXizTAZOzJ1b6JFBdk2z2C4q1EuS9Qfq2qPLRkGU6fgUWHaxn9o1xORtG1pFBnau-nyBIuB7DSW6LVC1zSMQm_y22OAWuqi3bIKZBGg4fwKt6fKHXmB_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-89","volume":""},{"id":4091,"author":"谭飞","title":"天文地理字溯源","abstract":"天文地理字大多有浓郁的图画色彩,然因同类物象较多,象形、会意、指事的手段无法将它们明显区别开来,故而有的字采用形声的办法。一些字在甲骨文、金文中就已有添加音符、义符的异体,说明很早就开始出现见字知音、因形见义的心理需求。有的字通过引申出现了多个常用义,区别不同意义的需要促使其形体发生分化,常见手段是添加不同的义符。少数字演变中,笔画、部件发生粘连离析,形体被重新建构。","categories":["02_字词句考释"],"year":2015,"publication":"重庆师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLi1X0QVZxVBJ_ezhJVQNU6tublFpjJPIelBUqtblQYqOoTxRxAWTRHQCKpWKuB5RyshZV7WdY3rHOKujMZFXK15Dk6Dyva64LwzZ7AcB_4RXQt5-yygwKzeqbVN0OhoyLTBAmF-3uek5YhAMK2ZvwRT7XUpl8M_NmuaesUogtGUxG2N7RGKlNG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-78","volume":""},{"id":4099,"author":"李零","title":"文峰塔M1出土钟铭补释","abstract":"本文针对文峰塔M1出土曾侯(月與)编钟铭文进行补充论证,供学界参考。","categories":["02_字词句考释"],"year":2015,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ8brqVqqwVkLT_EN3J3ojQH8KEirUpSm5Oj7BHqJg-sFuUCbhuO_-IdasWlIW2uobHQRWkvpAMS4c6djAYfSct1wtWY6_6AuoO1Dt5Is7IZE-SXz-hzAB1L8qDEvuq3KBCnRCLmGHibz64eBhzp7YgSSniOeL8haXY_NK15P1S5OFTZgDu9r-T&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-120","volume":""},{"id":4102,"author":"金东雪","title":"“琱生三器”研究述评","abstract":"琱生三器是研究西周的仆庸土田关系、宗法关系等内容的第一手资料,自出土以来,得到了学术界的普遍关注。一系列的研究论文出现,这些论文的讨论不仅集中于对古文字字词释读,而且包括各器铭文之间的关系、事件中的人物关系等内容。其中,很多成果得到了学术界的一致认可,而部分内容还存在争议。从琱生三器的名称及年代、琱生三器之间的关系、琱生三器的人物关系、琱生三器的铭文释读等角度,梳理、概述以往的研究成果,是深化研究的必要基础。","categories":["02_字词句考释"],"year":2015,"publication":"珠江论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-fqU4HAGTcWzcBcLXZsTHQoGcHL_5ktIT_I2CFSLuErrHMN6AY9phsRLpMlX0luDMyWGN60JJFIlBC0Ir6zj-NBuN8eIHJr9p-SziAmyLi3F5L6nOlVV1aZzQvBoKf4qs8MtwBsZ77grZmkUE-OTbRoNI2ggRcbTjE3fD4n0y_g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-117","volume":""},{"id":4103,"author":"卢敏","title":"西周晚期铭文整理与研究之字形简化现象初探","abstract":"目前所見西周時期的文字主要是金文,即鑄刻在各種金屬器皿上的文字。文字的形體,即字形是古文字研究的主要對象。本文就西周晚期铭文字形的简化现象作了一个简要的勾勒,以期對金文的字形結構、演變規律的研究提供一個比較重要的參考資料。","categories":["02_字词句考释"],"year":2015,"publication":"兰州教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI24xPoixK4wLrRo_QLnSReNxQyfW8fIey5Y6nlnEuh5fbw5pCbS-AwrS7JWKj_3xWo7LYGgWFObfIki-U9qKCwXYOgrm5UElccPvp5vD3SiCZKyFszUkjjxDWGAYYKqjjPCTqsTgm5wELDA9w8oiiAOJc4dBohzsPLJWFBWngsZprG--kmy0r1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-23","volume":"31"},{"id":4104,"author":"谭飞","title":"罗振玉古文字研究的特点与得失","abstract":"罗振玉古文字研究著录与考释并重,以形体分析为重点,参验文献典籍,考虑文例句式,力图建立起清晰的字形字义发展演变的链条,多有创发,成果丰硕。他对古文字的特点和文字发展过程中结构方式的调整及繁化、简化、分化、省变、讹变等现象时有涉及,虽不成体系,但见解深刻、其失误主要在于有些字形的分析不够细致、有些字义的追溯不够准确。","categories":["02_字词句考释"],"year":2015,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL58CEUUaVv5k5bWlIAE9LGgY3I4ipXCeaa9UMy11dFX0vjOZudpTmbO6X5oGldfNm8Ih7JxH82Ko74nQEAis8Lkhvv1uhNwD6MZhiVT4bferadJtokOpbMdJlB74UHS-vinM2taQN__7FsEhEHp2YZb3x_5RdF_fja144-0lgRu8GknhVOERgH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46247","volume":"37"},{"id":4106,"author":"李刚","title":"释“■”兼论东阳合韵","abstract":"战国铜器铭文中有一个从庚从肉的■字,此字后面往往是记录容量的词,从语法位置判断这是一个与&quot;容&quot;字相当的动词。郭沫若等学者指出■应读为容,但各家对字形的分析却莫衷一是,我们根据垣上官鼎中此字写作庚,判断此字是庚字的异体。庚又是镛的本字,与康、空为同源字,三字皆有容义。","categories":["02_字词句考释"],"year":2015,"publication":"赤峰学院学报（汉文哲学社会科学版）","link":"https://link.cnki.net/doi/10.13398/j.cnki.issn1673-2596.2015.01.049","pages":"140-142","volume":"36"},{"id":4107,"author":"孙董霞","title":"先秦“德”义新解","abstract":"&quot;德&quot;是先秦时期一个极其重要的概念范畴。关于&quot;德&quot;的含义历来解释甚多。本文在梳理了对先秦之&quot;德&quot;的研究资料的基础上,对&quot;德&quot;的造字本义提出了一种新的解释:&quot;德&quot;观念源于上古人们的&quot;能力&quot;崇拜,&quot;德&quot;字的产生源于人类社会对于一种特殊&quot;能力&quot;:&quot;政治控驭能力&quot;的需要。&quot;德&quot;之初义就是&quot;政治控驭能力&quot;和&quot;权威影响力&quot;。从德的字形结构、音韵训诂和文献用例等方面可以证","categories":["02_字词句考释"],"year":2015,"publication":"甘肃社会科学","link":"https://link.cnki.net/doi/10.15891/j.cnki.cn62-1093/c.2015.01.024","pages":"95-99","volume":""},{"id":4110,"author":"祝中熹","title":"民国初出土秦公簋的文化魅力——兼评丁楠先生《秦公簋》铭文考释","abstract":"民国初年出土于甘肃礼县红河一带的秦公簋因其多样价值,面世以来不断引发学界对它的绍介、阐述、考论、评说和引证,在器物学和文献学紧密结合的基础上,体现出了鲜明的构史、证史趋向。关于此簋认知的各个环节,经过将近一个世纪的持续探讨,学界已经形成了较为一致的判断和认知。丁楠先生《秦公簋铭文考释》一书的编著,不仅显见了他对于地方文化别样用心的学者情怀,而且也通过对于簋铭详尽清晰的解读,从一个特殊的渠道对于秦公簋研究成果并及秦历史文化进行了一次有效的普及宣传。","categories":["02_字词句考释"],"year":2015,"publication":"天水师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbxwO9HYwI1bZ9fw0E7tiFXZo5sf39iNP525Li15GCSGnE0G7W0-ffiUR6mbN3GjtIgIOMyg6DdAxk7JXo6ZvAar9Y_DZfRUaMk7xy1OhH_N_L_ttXMc8He9oxZtIeUB_vckQICyAs_6heI5sJp_kXdli23g0rJ3YRgqPfjQ9cWfqkdvao-Gew&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-80","volume":"35"},{"id":4111,"author":"苏文英","title":"再论甲金文中的“典”“册”及简牍出现的时代","abstract":"学界对甲骨文中的&quot;典&quot;&quot;册&quot;二字像简册还是龟册尚有争议,这关系到对我国文献的起源和简牍文献出现时代的认定,近年来不断有学者撰文讨论。本文以出土实物和出土文献材料为据,对前贤的主要意见进行了述评,认为甲骨文&quot;册&quot;字的竖笔是竹简或龟版侧影的象形,因此典册可指竹简,也可指龟版。殷商时期甲骨、金石、竹木等都是文献的载体,甲骨文中的&quot;典册&quot;主要指祭祀文书和册命文书,而金文中的&quot;典册&quot;已经成为各种文书的通称。","categories":["02_字词句考释"],"year":2015,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKewmUCWL3aJTFKFAfuTssDzeG9l_rXlY1d5lnbiAnMar0yIzAuCAYQ9pvaAUwqV-d_4M2rND59iPs1WXsikFniacxaXoUXaw_i1v7UmvSvHpKCAMzOp3o_jTPGpcQO1a89UYlY0mdlQ0IeV0urolf42arYPuzl8yBkt3qoIsv0gDFl_1iR4Fu_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-89","volume":""},{"id":4112,"author":"林志强","title":"《文源》取材三题","abstract":"本文论及《文源》采用古文字资料的范围、《文源》不用甲骨文之谜和《文源》引用传统&quot;说文学&quot;资料等三个问题。从取材的角度看,《文源》是一部继承传统文字学特别是清代段、朱&quot;说文学&quot;的成就,同时又结合古文字资料尤其是商周秦汉金石文字资料来探讨汉字本形本义的承前启后的著作,它虽然还没来得及用上甲骨文的资料,但已经充分展示出古文字资料和传统文字学相结合给汉字学研究所带来的新气象。","categories":["02_字词句考释"],"year":2015,"publication":"福建师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/urlid/35.1016.c.20150122.1338.015","pages":"92-96","volume":""},{"id":4113,"author":"陈桐生","title":"商周铭文语言的发展演变","abstract":"商周青铜器铭文语言的发展经历了四个阶段:从殷商武丁晚期到文丁为滥觞期,此时铭文只有一些标记性的单词或词组,谈不上有什么文学性;从殷末帝乙到西周为兴盛期,这是商周铭文大发展大繁荣的阶段,其表现是遣词造句日趋丰富,逐步凝炼成博约温润的语言风格,形成某些程式化套语,铭文多从《诗》《书》中吸取语言营养,西周中后期铭文出现一些四言句,少数铭文具有韵律,铭文语言内涵丰富;春秋为铭文语言蜕变期,铭文大势由繁趋简,四言韵文情形增多,而铭文语言内涵减少;战国为铭文语言衰落期,除少数铭文为精心制作之外,绝大多数铭文语言简单粗糙,缺少文采和内涵。","categories":["02_字词句考释"],"year":2015,"publication":"东南大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13916/j.cnki.issn1671-511x.2015.01.019","pages":"124-129","volume":"17"},{"id":4114,"author":"安丰存; 程工","title":"汉语数量结构演变及量词产生的语言认知机制","abstract":"量词是汉语名词数量结构中的必需成分。以往的研究过于关注量词的属性和功能以及语法化等问题,对于量词的产生及数量结构变化关注不够。量词的产生与发展需要有内在的语言基础以及外在的认知条件。研究表明量词是在受不可数名词表量结构的类推作用下产生与发展的。可数名词数量结构首先受到不可数名词表量结构&quot;名词-数词-单位词&quot;序列的类推作用产生了&quot;名词-数词-名词&quot;的序列构造,进而右侧名词逐渐由左侧名词同范畴的名词取代。由于不可数名词表量结构&quot;名词-数词-单位词&quot;序列变为&quot;数词-单位词-名词&quot;,在类推作用下,可数名词数量结构也演变为&","categories":["02_字词句考释"],"year":2015,"publication":"延边大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16154/j.cnki.cn22-1025/c.2015.01.014","pages":"103-110","volume":"48"},{"id":4115,"author":"李芳","title":"从汉字看女子一生角色的转变","abstract":"古汉字是我们研究文化和生活的活化石。从奼、女、妻等一系列文字简析女子一生从少女到妻子再到母亲的角色转变。","categories":["02_字词句考释"],"year":2015,"publication":"黑龙江生态工程职业学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIanATd7cjMjXYHx1baRL_6qIqNc2EqtpD48kB46gw1FOMxWBjcnDC6WC4fabpnzwLCjSUW-ZiSRyopX88AtZWz6TotfyeTs3En9D3XuClCdUC2_kjJmKe3YDu918qcwQvmJn7-7rGki7YaE4WCJvddcTySPcqCftSWhn5XdxXgZnoxvN0umrL5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-144","volume":"28"},{"id":4116,"author":"张玉金","title":"出土先秦文献语气词的发展","abstract":"文章利用出土先秦文献,探讨了先秦汉语语气词的历时发展以及地域性等问题,揭示了先秦汉语语气词发展演变的原因和规律,还比较了出土先秦文献中语气词和传世先秦文献中语气词的异同。","categories":["02_字词句考释"],"year":2015,"publication":"语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIYEXBPmCN0RvesSGcwPX7XojkXm7X24vIryrnFOqs4jma8NUxRwwZGntY5RcYBKQCQQfIYG0b2zA00SCB7yWUn92oUpnNDsmWODHNevEznoqnqJK2Vj4E0984oN85eoN-ojwDl27avvi00Pz3JHuqQ6WnLOFoK07r756FY9lolwp1BqO2LzMsR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-44","volume":"35"},{"id":4117,"author":"郭静云","title":"重新思考“寿”字来源与字形结构","abstract":"在目前所见的青铜铭文上,&quot;寿&quot;字的出现率甚高,共见六百余次,其字形的异体均有五种。从这五种的字形年代不同,或许可以表达&quot;寿&quot;的形成脉络。本文从两周金文和战国简文搜集一切&quot;寿&quot;字的字形,重新探讨该字的结构与形成的历史。本文认为,&quot;寿&quot;字是殷周之际从&quot;神&quot;字衍生的字体,以表达天神所能赐予的寿命。商文明的信仰传统,乃是通过神兽吞吐神杀的方式,以期获得天上的神性之新生,即通过神杀手段避开自然生物必经的死亡过程,进而得到由神所产生的永生。早期社会观念中,老死病死者将变得永远脆弱无力,身强力壮时期被杀者,反","categories":["02_字词句考释"],"year":2015,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJGos-aFKzAc04YwDvWDcrtMNg_9iQjinkxWRyO035zRQIgWXbiBWyxB3t-ZAF9beyOnT_LNZbYdXyUsdtlCkI0BVTr3ViuIX8k2u5_kaJnnqZfl-qdIlxW3bBYNKphKcaqAXLDvqmdRkWpI1Ej3TNJtSQ4rmoY2DCLnTu_RckeBFpZWVDuSee4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-64","volume":""},{"id":4121,"author":"杨淑茜","title":"论古文字演变中的类化与美化","abstract":"类化和美化是古文字形体演变中的两种重要现象,二者交叉出现。美化是产生类化现象的一个原因,类化也促进了美化现象的出现。它们相辅相成,使得古文字构形系统更为完善、严密。","categories":["02_字词句考释"],"year":2015,"publication":"丽水学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKJbYm2NMrhGJxUjpPKuMFJccxPDn-AVwiomWLo0HRJgIk65JIHGSbbs0Rajzcc5hWOdsthFeg3Gh1l1Abb-t-bB_UyR8rtdkY9HPmLa1w2wUHvSaMXkVHxfEwpt09BUlhdueedEIAfC7tCNYVPMSwil09snhpIazKHNE0oiWKiHC_eq3YpTOrz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-54","volume":"37"},{"id":4133,"author":"李力","title":"“■”、“殹”、“历”三字的疑难与困惑:枣阳曾伯陭钺铭文之再研读","abstract":"在出土于湖北枣阳郭家庙曾国墓地21号墓的曾伯陭钺铭文中,可见有&quot;■&quot;、&quot;井&quot;两个&quot;刑&quot;字。有学者据&quot;■&quot;字推定西周时期早已有&quot;铸刑鼎&quot;事件,因而判定该器在中国法律史上具有重要意义。这是对该钺铭文之误读与过度解释&quot;■&quot;字、&quot;则&quot;字的结果。曾伯陭钺属于西周晚期至春秋早期之器,是曾国国君权力的象征物。其铭文所见&quot;■&quot;、&quot;井&quot;这两个&quot;刑&quot;字,当为古文字常见的所谓&quot;同字同辞异构&quot;现象。&","categories":["02_字词句考释"],"year":2015,"publication":"中国古代法律文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCWQz-o5_Rix_I8ctbkq2v3Vr_dVKuIZ-98lh-K9WpZF4VMetf9HMrOARZsrV7rDj2Rb_5oz_AMvT34cocKlMZwEOjjUQwGVa7FpxM2GiRl_8nBkpvV0iOH7Iimba2-_ATyTpeCusw7mR_nGRfHXFSQ29moxrX7vSeiiGigeVk4A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46043","volume":""},{"id":4030,"author":"石小力","title":"吴王寿梦之子剑铭文补释","abstract":"1997年,浙江省绍兴市在鲁迅路改造工程中,出土了一件春秋时期的青铜剑,剑身铸有铭文2行40字,是目前所知出土青铜剑中铭文字数最多的一件。此剑铭对于研究春秋吴国历史、吴王名号,十分重要。文章先对铭文中仍存争议的&quot;(?)&quot;和&quot;弟&quot;加以考释,在此基础上补证器主即吴王余昧,并考证剑铭&quot;攻吴王姑义(?)寿梦&quot;中之&quot;姑义&quot;为寿梦之字、&quot;(?)寿梦&quot;乃寿梦之名,进而将诸樊及其子所作兵器中的&quot;姑发&quot;释为诸樊之字。","categories":["02_字词句考释"],"year":2014,"publication":"珞珈史苑","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJXLeEhftua5AZQz0bFqRFolOtNwLFZwMd8qYtJrPCncIiNpqGm5OrgoppLR9H33rhGSzqSSCMzH-GRonDgASazYXzuejEYAot_mwwzChQ-AsLg2MCX32EGdtaSe1jVmmGhf8VHB84Oe6agQ5cCCX61yFvuJT1fh6b4kJ_NGG6wtw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-54","volume":""},{"id":4127,"author":"王蕴智","title":"商代文字可释字形解析(二)","abstract":"随着以甲骨文为主体的商代文字研究的不断深化,殷商文字的结体特征及其构形规律尚有待全面总结。据笔者的统计,迄今所见商代文字与后世字书中相对应的可释字形计1250余个,加上正在同源分化的字形和主要的通假用字,隶释字目可达1490多个。本文试对一部分笔者所整理出来的商代可释文字的结体特征加以解说,解说字目为:小、少、八、尔*、曾、公、番*、牛、物、告、口、吾、君、召、唯、咸、周、唐、各、否*噪*、凵(坎)、嚴、單、走*、止、趾*、歸、登、步、歲、正、征、進、逆、迎*、遘、徙、返*、遣、邐○、逮*、遲、达、遺、追、逐、邍、迄*、徝(德)、彶、微、得、律、御、建、延*、行、齒、足*、疋、品、喿△、龠、册","categories":["02_字词句考释"],"year":2014,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIgDwyjgytsWvPXGlzAExfjtA0qd1z2niZ9Y8BfdBv--ZeBTf8KYUMpto4HLDZWAG7zYSAPE2vkj6J7L3CmzFxv35WTGZ0t7yIQgjpTJuUpdPNIUW757gcKhgsrLHJXRdxETwxG0jPRGj5lSi-OrRbokeo_2YCXfBI2AT3nFrKJSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-97","volume":""},{"id":4128,"author":"齐晓燕","title":"从《经典释文》看“盡”字的变声构词","abstract":"本文考察《十三经注疏》中&quot;盏&quot;字在《经典释文》中的注音情况,认为精母是&quot;盍&quot;的原始词,义为全部使出或用出,表动作;从母是&quot;盍&quot;的滋生词,义为完了、没有了,表示状态或者结果。这是汉语史上曾客观存在的语言事实。","categories":["02_字词句考释"],"year":2014,"publication":"南开语言学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHmBrgW49mz6sgP-GZtMFgOTc7-kExcWBYUlxTXT5wsKGZbXd_5bxPBBQNgG54ew8I12wo4PXqX44b8GhQSRPPF9-_7iWv9sCS3UVEQT43gXyzqKKmjmQRsu4J3vxMTiL3LPy2JuRMeAmVoabG2LWN80o0NH8ooAk6UZ2mylEAhw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48-55","volume":""},{"id":4129,"author":"郭洪义","title":"《大唐愿力寺故瞻法师影塔之铭》释文校补","abstract":"《唐代墓志汇编续集》公布的《大唐愿力寺故瞻法师影塔之铭》释文错讹甚多,严重影响了对该通塔铭的有效利用。本文通过校补释文中多处可商榷之处,分析误因,避免以讹传讹,以便使这份宝贵的材料得到更科学地利用。","categories":["02_字词句考释"],"year":2014,"publication":"学行堂语言文字论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEaGxrzl9JdV10DffPQhY3DJbv6ujA4hxn9ryBnNU3zhJwJkMSyk_A5-OPHv4RJvM3bj4nPYyGGdQsHn8dd___X60ScJ5x3ps4ycGVAoEhtLkCpaBc8Q-6Zefa0jA1VGAbU3zLBrOEmH6_WZjqxdWYzgVDsDDYGac2H6leWgweOQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"213-223","volume":""},{"id":4130,"author":"马良民","title":"古文字考释两则","abstract":"一、释&quot;与&quot;、&quot;舆&quot;、&quot;牙&quot;&quot;与&quot;和&quot;舆&quot;在《说文解字》中是两个字。&quot;与&quot;隶勺部,篆作（?）,曰:&quot;赐予也,一勺为予,会意,此与舆同。&quot;&quot;舆&quot;归舁部,篆作（?）,曰:&quot;党舆也,从舁从与。&quot;朱骏声《说文通训定声》&quot;舆&quot;字下按曰:&quot;与声&quot;,意为会意兼形声。单独的&quot;与&quot;字除见于文籍外,又见于战国楚简,作（?）、（?）形①,在金文和其他出土古文字资料中,都作为偏旁出","categories":["02_字词句考释"],"year":2014,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2h1X7HckpTa9cfkvESB5Gmc0tDfSXwC372wN5Gs8AyBlizHLpVe0Wed9xpf1nC_fnMG4gSwnP_ZtnSX53q0nBDJINKkFj6rTftWCXIogoqsiYeFN2WF8y-Y7bgfb-LLxrWjmH5_sn1qrHmNJi9ifZ_I44VVCv269B4PkNX-h3Nw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"167-172","volume":""},{"id":4134,"author":"罗卫东","title":"金文所见“邾”、“鼄”等字及相关问题探讨","abstract":"本文依据《商周青铜器铭文暨图像集成》〔1〕,分析金文中&quot;邾&quot;、&quot;鼄&quot;等形体。&quot;邾&quot;、&quot;鼄&quot;等不同字形,记录了中国历史上的多个国族名称。笔者同时联系《左传》、《史记》等文献典籍,梳理前人研究成果,探讨&quot;邾分三国&quot;、&quot;邾分为五&quot;等说法的源流。本文试图结合古文字与古文献,寻绎不同地域邾国族的文字特点。","categories":["02_字词句考释"],"year":2014,"publication":"民俗典籍文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK_uTsbR2GQ-zg-xvcHZdLuieAgjRMezdCseVhfJ8IjpJDBOXNQl2vtLkIK9IaoZwg7SVp68S3-NS1QxXjdyFnGqIeYVQNACurG24ewo1AZ77D7NBA3sO-9_4SkegdT4EnAI5r7-OUWE8yG1IJFCVU07LfwBhs09LKhKUs9fWCmWg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-131, 237","volume":""},{"id":4135,"author":"王伟","title":"秦文字“徒淫”的释读及其相关问题","abstract":"在对秦兵器铭文&quot;徒淫&quot;旧释存在问题做补充说明的基础上,结合战国至秦汉时期的简牍、玺印封泥和陶文等出土文献,对?、巠二字的形体和读音变化做了梳理,厘清了相关诸字在形体和读音上的关系以及讹混的原因,并以此为基础,解释了出土文献与传世典籍用字差异的原因。","categories":["02_字词句考释"],"year":2014,"publication":"民俗典籍文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaEkPZt118mn0BgBejtp1kYUI5BCP0C7Ae5nai3O7-k1YgpNFEz6EqN6hFihLnkxyXC2cwtC2wPM_aJ6dw-Khc2wNsEtCmqa3kUY3Jz8I90vzUXjubGTuH1lotLZywuev4psf8NGuSwYuUCqXXJLETLCFY3G9_17RjDZ42vYo6yw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"132-138, 237","volume":""},{"id":4137,"author":"杨坤","title":"三晋铜器铭文札记两则","abstract":"一合阳鼎器、盖非原配合阳鼎现藏于上海博物馆,鼎铭最先著录于《殷周金文集成》（以下简称为《集成》）,定名&quot;二十三年槀朝鼎&quot;,编号2693。黄盛璋①、李朝远②、吴良宝③等先生先后撰文对该鼎的铭文及相关问题进行过考证。这里主要谈谈对该鼎器、盖是否原配问题的一点意见。为了便于讨论,根据去锈后的新拓本,④先将铭文重新释写如下:十九年,邛干为合阳,（?）(容)半（?）,□（五?）。（器盖刻铭）","categories":["02_字词句考释"],"year":2014,"publication":"陕西历史博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ1khXvPBoyBz6rolsQrLB0RgboCY5TI9JRo_07DJF290pogCoe2AHhxYLr2MkJ0FIV6oRj4lYjwZRo4nmP_gphZoz1LMj4aNARZ9d9gj7cSTnyrOJpyy1s3hvXmsn8H96Bw2YN2Bo1bSWj2uZC8EBDcx6LNL8NpxTgJlHhazZypg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-26","volume":""},{"id":4138,"author":"李春桃","title":"“臺”字補釋","abstract":"金文中有如下形體:■（《集成》423）①關於該形目前有以下幾種釋讀意見,一是直接釋爲&quot;喬&quot;,這一觀點爲學界廣泛接受,因形體在銘文中用爲作器者的姓氏,所以該器一直被定名爲&quot;喬君鉦鋮&quot;。二是將該形分析成從止、從高,認爲是&quot;蹺&quot;字的異體。②三是近年來董珊先生所持觀點,他認爲該形從之得聲,可釋爲&quot;臺&quot;。③按,上述第二説顯然有誤,可以不論,其餘兩説中,我們認爲董珊先生的觀點是","categories":["02_字词句考释"],"year":2014,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI1SSCP3bORLllZdJExtxGdyJ8fB9fktAQXeuRIAh3yQeOhG24Mcbr6vy5hXGc7OWq1q8N_iwNyzBUO05CN1RX1jUkREn-gnNtBiZhWhgfbezw-62AfXt_hF3ujdvO3hk2-ZPoRBGHbqrm1PGDf0FK96sp0GYv95zLdrIfrd9eRMw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"318-324","volume":""},{"id":4139,"author":"王泽文","title":"吴王光鉴“既字白期”诸说辨析","abstract":"吴王光鉴,于1955年出土于安徽省寿县西门内发现的春秋晚期蔡侯墓1,是吴王光(阖闾)为叔姬出嫁所作,有两件。为便于讨论,先暂依《殷周金文集成(修订增补本)》释文抄录如下2:唯王五月,既字白期,吉日初庚。吳王光擇其吉金,玄銧白銧,台(以)作叔姬寺吁宗薦鑑。用享用孝,眉壽無疆。往已,叔姬,虔敬乃后,子孫勿忘。&quot;既字白期&quot;之&quot;字&quot;,一件明确作&quot;字&quot;,另一件拓本不甚清晰。郭沫若、陈梦家认为作&quot;子&quot;,相关讨论或据此进行。唐","categories":["02_字词句考释"],"year":2014,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKs60FSrwDAo2KESBGWOTBb4w44BTtngETOVoi70R5m-cT-QOb6r44qcn9HehW4hFtzdjYhr4wrstjs1aPT_sx7oyJPwAfWxjtNc6SFaYoJp-U3Lz5EEwUYwX_I1y-BQPqq1rhX7gp8aiKbMbILsSBnuHdVlyp3H5JxqKNiFY2he2wiAW7qdTQx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-116","volume":""},{"id":4140,"author":"方有国","title":"“考”“老”解诂与转注再认识","abstract":"一、问题的提出六书转注一直是个悬而未决的问题,特别是转注是造字法还是用字法,聚讼纷纭,莫衷一是。笔者曾撰有《六书&quot;转注&quot;补说》[1]一文(以下简称《补说》),赞同转注是造字法,并认为转注是造字者为分化和区别处于使用中的多义字的一个意义,回转头去在已使用的原体字上加注该意义的类首,从而形成新的文字即转注字。文中对转注是否只针对假借多义字,《说文》转注&quot;建类一首,同意相受&quot;的含义,转","categories":["02_字词句考释"],"year":2014,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2014.06.002","pages":"25-29","volume":""},{"id":4144,"author":"杨怀源; 孙银琼","title":"爯簋、酓章钟、酓章镈、公鼎“乍”新释","abstract":"爯簋、遣伯盨的&quot;乍&quot;字应读为&quot;胙&quot;,其义为赏赐,与另一件爯簋的&quot;赐&quot;为同义词,酓章钟、酓章镈、公鼎的&quot;乍&quot;字也应如此解释。","categories":["02_字词句考释"],"year":2014,"publication":"重庆理工大学学报（社会科学）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI9sSXlU_XTReQAf4Ofaa3naUfhV7L-1dSujfIXyLttLZqqoalz4o-zJZRVfKtRI9L2tXDNQiWs1bElSVgEXDgquy4GKe_auw0HuZL1Yn6mEILoYqpko0rA9VU9rQOgh_4VCPVgzBxWDeC7AZ3CN2Us2TdOuZxXsgV5V7vobXtnXWeG3O8Mp9-2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-35, 79","volume":"28"},{"id":4146,"author":"徐山","title":"释“屯”","abstract":"&quot;屯&quot;字的甲骨文和金文形体,《说文》认为&quot;屯&quot;字&quot;象草木之初生&quot;的形义分析当从,&quot;屯&quot;的本义即草木初生的萌芽状态。从&quot;屯&quot;的本义出发,可知&quot;屯&quot;一词在卜辞、金文以及早期典籍的各种引申义用法。《说文》&quot;屯,难也&quot;的释义已非本义所在。","categories":["02_字词句考释"],"year":2014,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2014.04.002","pages":"46024","volume":"35"},{"id":4147,"author":"侯乃峰","title":"由鲁国厚氏诸器谈金文“厚柲”之义","abstract":"在对春秋时期鲁国厚氏诸器进行研究的过程中,前人已经提出&quot;鞏&quot;与&quot;厚&quot;声音相近的说法,为深入探讨&quot;厚&quot;字的本义提供了线索。在前人研究的基础上,可以推知&quot;厚&quot;之声符当是&quot;缿&quot;之初文。由上述文字之间的通假关系,可见&quot;厚(后)&quot;声字与&quot;工&quot;声字可以相互通假。如此,西周中晚期青铜器铭文中常见的&quot;厚柲&quot;一词或可以读为&quot;鞏柲&quot;,根据《说文》解释为用韦缠束的戈柲。","categories":["02_字词句考释"],"year":2014,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2014.04.006","pages":"21-25","volume":"35"},{"id":4149,"author":"肖峰","title":"杨树达形符“泛”“切”研究述论","abstract":"杨树达指出,表器物的形声字,其重文的形符在表义功能上,不同时期有不同的特点,甲骨文字形的形符相对剀切,而后起的小篆字形的形符则相对空泛。本文通过剖析,认为他所举的例证不一定恰当,但其观点基本上还是正确的。当然,完全坐实这一观点,还有待更丰富的出土材料发掘和更进一步的古文字研究。","categories":["02_字词句考释"],"year":2014,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoKCbY1VqVtaIj9uyyZAfmzmypLTp7yzrR99Qwl1b6ZErtsxvilFYmC5hy0TiU62TPyvH16qMBpFut2RUKLDj3umKObdXgJrxUciONZ-KLE8Acgju5rDqnf1ZrWR5H8k7_DabtyMEboekQ4hIaTJMdV8hzdSwaMuaAeiDH9NxSoIOT-y0uuvfg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-90","volume":""},{"id":4151,"author":"吴慧","title":"商承祚的古文字考释与义近形符通用","abstract":"义近形符通用通作是古文字形体的一个普遍现象,也是古文字学家考释古文字时常常凭借的重要方法,商承祚利用这一规律考释辨认了不少古文字。论文整理了商承祚著作中&quot;义近形符通用&quot;的例子并加以说明。","categories":["02_字词句考释"],"year":2014,"publication":"江西省语言学会2014年度学术年会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLvf7ni1P5s60xy3er56NbmGYpMrd7skh1wL9GENScEm73a_ZKrPBKG8o1SRjylr2o6n5bFa0noFySYxL5fWgGJIoc70HhIXJgbeSRkomm4G4X8r96e3cP5EnuJ4W-vxMCldEgDuz8cECVDvaUfUiEtpn6fEi46WFPbi0lhMS4APqf8q9sqyIq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-28","volume":""},{"id":4152,"author":"王蕴智","title":"商代文字可释字形解析(二)","abstract":"随着以甲骨文为主体的商代文字研究的不断深化,殷商文字的结体特征及其构形规律尚有待全面总结。据笔者的统计,迄今所见商代文字与后世字书中相对应的可释字形计1250余个,加上正在同源分化的字形和主要的通假用字,隶释字目可达1490多个。本文试对一部分笔者所整理出来的商代可释文字的结体特征加以解说,解说字目为:小、少、八、尔*、曾、公、番*、牛、物、告、口、吾、君、召、唯、成、周、唐、各、否*噪*、凵(坎)、嚴、單、走*、止、趾*、歸、登、步、歲、正、征、進、逆、迎*、遘、徙、返*、遣、邐○、逮*、遲、达、遗、追、逐、邍、迄*、徝(德)、彶、微、得、律、御、建、延*、行、齿、足*、疋、品、喿△、龠、册","categories":["02_字词句考释"],"year":2014,"publication":"黄河文明与可持续发展（第十辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8cF0fLOpRLKXDCJdOOLduc4vZfwfTNM5JmO0TzbQ58XmG797ep0Rhy_DxOI_iiNqSvv8teDl35dJ_LCbExpM3vzp1fEFKtoP4S4dKjcUf930FntrbzWe5kyq7HNjaoqZs_mZH4Rd5DND245_Bj60TjpZ5Crf-TUkdeCzDjYbNPu485e8EuA3R&amp;uniplatform=NZKPT&amp;language=CHS","pages":"90-102","volume":""},{"id":4157,"author":"朱彩云","title":"说“见事”","abstract":"匽侯旨鼎铭文中有&quot;见事&quot;一词,对于其意,众家说法不一。综合来说,约有四种:述职、勤劳政事、一种礼节、朝见。笔者以为&quot;见事&quot;当释作&quot;述职&quot;,铭文中表示&quot;申述职守&quot;之义。玥方鼎所见、也当释作&quot;见■■事&quot;,而非&quot;视事&quot;。《尚书·康诰》有&quot;见士&quot;一词,士、事相通,&quot;见士&quot;即&quot;见事&quot;。作册卣&quot;见服&quot;一词亦当与&quot;见事&quot;同义。现代汉语中常见的&quot;见事&quot;已经与铭文中的&quo","categories":["02_字词句考释"],"year":2014,"publication":"励耘语言学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoZUGw3VZwn7OUISJr8NRLY3JF8fQvlZ629PvczJZ96X_8NJlPnRs4WSKBB_LIkNISBnRKLwkrPu75l_Nk77dhjdRayTwnGorstlx_WZOIbA8JO9hMlf0tP43TNnxNOdIYLRAx4KRJxAcz2cwlOZHuxDD_IoWHAXflnZjLlHmAJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"203-213","volume":""},{"id":4159,"author":"武振玉","title":"兩周金文“取予”類動詞研究","abstract":"兩周金文因特定内容的關係,其中的取予類動詞數量眾多,構成了一個豐富的詞義系統。依詞義相關度,這些動詞可首先歸爲給予和獲取兩大語義場,前者又可進一步劃分爲賜予、獻納、付與三個子語義場。其中賜予語義場有23個成員,獻納語義場有11個成員,付與語義場有11個成員,獲取語義場有8個成員。四個語義場共有成員53個,總出現頻率罵739次。從各詞的情況看,出現頻率在10次以下的有31詞,在10到20次之間的有11詞,在20次以上的有7詞,即除個別詞外,出現頻率普遍較低。從句法功能看,除獻納類不帶賓語的略多於帶賓語的外,其餘各類帶賓語的均遠高於不帶賓語的,且總體上雙賓語多於單賓語。從賓語的情況看,除少數幾詞所","categories":["02_字词句考释"],"year":2014,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI48-ihiYn4i2dTVj4DrGULkmTV5ntDzSELZQKMBPgZIg_gEFYWImFKzN8Z9RTyvIZbZbbPerxx3hhQVugkn-pzpUWZGnYN9qvmxTphpjomSWGCbvlP_Qyu_y2G4EZE06Bo5oC-kQ-HI7mOW6vDmLW6Q-MFsmQPHi4MgwcDLLiZow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-83","volume":""},{"id":4160,"author":"王蘊智","title":"商代文字可釋字形解析(二)","abstract":"隨著以甲金文為主體的商代文字研究的不斷深化,殷商文字的結體特徵及其構形規律尚有待全面總結。據筆者的統計,迄今所見商代文字與後世字書中相對應的可釋字形計125。餘個,加上正在同源分化的字形和主要的通假用字,隸釋字目可達1490多個。本文試對一部分筆者所整理出來的商代可釋文字的結體特徵及其形義關係加以解說,解說字目爲:小、少、八、尔（爾）*、曾、公、番*、牛、物、告、口、吾、君、召、唯、咸、周、唐、各、否*、凵（坎）、嚴、單、走*、止、趾*、歸、登、步、歲、正、征、進、逆、迎*、遘、徙、返*、遣、邐○、逮*、遲、達、遺、追、逐、■、迄*、徝（德）彶、微、得、律、禦、建、延*、行、齒、足*、疋、品、","categories":["02_字词句考释"],"year":2014,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInBeTI6zwm9OfLr7aC54G6vem6-6Fq-34JQ_-W7LJdfJr2ZkJdpG6EVVee1PxtHe8mbvVHdpWhHWM4KKDAlT4aXHTNOQDtIA-ywcfuUFSN33c-ygNNw8ECfFGPTvxv38EOuSPSC34EQ1OZvmcl_Ee9zqfWip-gZ8pQ8eeLc-xy5Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-133","volume":""},{"id":4161,"author":"趙誠","title":"《利簋》銘文補釋","abstract":"西周早期銅器利簋銘文中&quot;歲鼎克聪夙又商&quot;七個字,前人有不同的解釋。本文根據傳世文獻《尚書。大誥》中周公協助成王用文王傳下來的大寶龜進行占卜的史實作為旁證,結合今人的相關研究,推斷銘文記載了武王伐商前曾用大寶龜進行占卜的事實,因而認為這七個字應該斷罵&quot;歲鼎(貞):克。聞。夙又(有)商&quot;。其大意爲:舉行歲祭並用大寶龜進行占卜貞問,得到吉卜,於是聞於四方,最終在一個早上就得到了商朝的天下。","categories":["02_字词句考释"],"year":2014,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKw2-HHL7f11YcmYxhJqZ4kAxhu1jHIcm3iNjt1lPijyObMIsheZkGdUNVWUHiJYKoi8i-PpiT6yYS71C2pmQkQ9-xkk4X6ZkdN5agdQkG4XR9dhg_3jsp9rLB6kUgidrGp-z7u7TxAo60r_cMBiaw2R9bVss4vZKKwvdz4V7r_qw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"134-139","volume":""},{"id":4162,"author":"李家浩","title":"“越王者旨於睗”新考","abstract":"越王者旨於暘的銅器約有二十多件,經學者研究,者旨於暘即《史記。越王句踐世家》所說的句踐之子鼫與。鼫與的名字在傳世古書中有不同寫法,者旨於暘與鼫與名字不同寫法之間的關係,諸家說法不一。本文運用吳越人名多附加語的觀點,對者旨於暘與古書中鼫與名字不同寫法之間的關係進行了新的解釋。從解釋的情況看,再次證明吳越人名多附加語的觀點是可信的,運用這一觀點研究某些吳越人名是可行的。","categories":["02_字词句考释"],"year":2014,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCazl9ppEYj-HwMRkN_-I-8_rhNJ9aBvJx4-_1-hzXwaHqojL0JHEma_0Vyxdg-K25OlFgir4tm4Jj4ZH5fAv6OQvH4OeL6n4thnw1Fx8_zWC3AYV4NU34N-cfmpnxZUnhNYSvu4DUXmqYLR6wKTJjcQVbleext90mEN_iM4vIoQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"140-148","volume":""},{"id":4163,"author":"董蓮池","title":"“臾”字考釋的反思兼說某些甲骨金文形體釋臾的錯誤","abstract":"本文列舉相關古文字形体,論證了小篆&quot;臾&quot;字不从申,但也絕不从人,否定了林義光的臾字从人之說。由此出發,纠正以往據&quot;臾&quot;字从&quot;人&quot;之說將某些古文字形體釋臾的錯誤。","categories":["02_字词句考释"],"year":2014,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIqXW35jz_bQRcZYisLM0cx6wxanJQ0q5X4eqrtZMZ-SbgCQbRLbeCA9rbGJBvI1K7xB9w_JwScbF0rJ-L5oW7nQXEDFgmSEpksPU6VA-qeoqD5mEh3lHNFeVCAQVy0c1h9edFikY_eSG_Zy9fEzHXHtcCfmTJdz2Ln-MLlhI1Q2A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-152","volume":""},{"id":4165,"author":"沈培","title":"試論西周金文否定詞“某”的性質","abstract":"新出銅器气盉銘文對確認西周時代&quot;某&quot;有否定詞的用法具有積極作用。本文同意多數學者將&quot;某&quot;看作否定詞的觀點,但不同意將之讀罵&quot;無&quot;,認為應當讀罵&quot;毋&quot;。通過討論,不僅可以幫助我們對气盉銘文有更準確的理解,同時,也可以加深我們對否定詞&quot;毋&quot;的了解。","categories":["02_字词句考释"],"year":2014,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqn4qVptI8OBanFk_uOglDyesqhjN1UT8j8Vdpg6xvyWTdQEGHYN-0g-CUY4fSSAoOouxnL5toJpVG0vgQzzsGG6cqjbTpcUzFdzVDtrmLzkO8ayUkVx4bR0A_n437u6dNfTRsARbIvGukivOpTONiMnX-9opbXQzIX8DY7cySvA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-58","volume":""},{"id":4168,"author":"苏影","title":"山东所出宋左大师鼎铭补释","abstract":"宋左大师鼎,1986年出自山东淄博,盖内有10铭,内容关涉宋国的官制,学术价值颇大。铭中第三和第四个形体,学界或释作&quot;大师&quot;,或释作&quot;天师&quot;。通过材料分析和字形比对,考论这两个形体当为&quot;帀&quot;&quot;巿&quot;,又通过文献佐证,认为器主当为&quot;左师&quot;,而非&quot;左大师&quot;,并推测&quot;巿&quot;为器主之名,因此鼎名应改为&quot;宋左师巿鼎&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQIdA6Ei0RCH3Yqs6wxTJ9Tc0ulgA8G3jEKpsrT1A9RPIuQauLs3dP5Wn_fg7WADVmdnm_H0uPIvckwDmN1MAGhNB7x1z_Kg9BfMX_PDyKdXGv9sm8XYXQqk8yiJ6CZq8-7iRnjbqHUi-h4kwXGBqbNDZwDq7Mows5Q6EkFsJBheqq6eE4tzYL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-74","volume":""},{"id":4170,"author":"胡红梅; 段斌","title":"中国文化关键词“气”的字源学考释","abstract":"&quot;气&quot;作为中国文化(文论)的关键词无疑同其他概念范畴一样具有普遍的意义,但其普遍意义必然是从气字的具体的原始意义中升华发展出来的。只是由于年代的久远,历史的长河已经把&quot;气&quot;概念生成演化的过程冲刷得踪迹难寻。因此,想要探明&quot;气&quot;文化底蕴和文论内涵,首先必须从字源学的角度进行一番审慎的考释。","categories":["02_字词句考释"],"year":2014,"publication":"内江师范学院学报","link":"https://link.cnki.net/doi/10.13603/j.cnki.51-1621/z.2014.11.018","pages":"94-98","volume":"29"},{"id":4171,"author":"彭裕商","title":"“王若曰”新考","abstract":"&quot;王若曰&quot;是先秦典籍和金文材料中比较常见的词语。对该词语的释义,目前仍未取得一致意见。通过对金文、简牍和传世典籍中的相关资料进行考察和梳理,可知&quot;王若曰&quot;不是王一般的谈话,而主要是指王命,语感在强调其庄严性。此外,学者以往举出的殷墟甲骨文中&quot;王若曰&quot;的例证并不可靠,从现有材料来看,&quot;王若曰&quot;可能是周人的说法。","categories":["02_字词句考释"],"year":2014,"publication":"四川大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIwvB7-zehOzZNbtD-7LmKKnPNSQuROOPDCXobS634dexfBc8-OoJVxjNvXEuAYieExinQXAsmNBedS2u_JTvNNhLqPHnyTMTvLVCu34KDeKDHELi0OqM0NrbQdeD4HnypiZkLjy75Ne3dmZlgh1xTMOq_OBJWzDRyk63VbuXOFqw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46152","volume":""},{"id":4172,"author":"马楠","title":"《尚书》、金文互证三则","abstract":"&quot;衋&quot;字先秦传世文献仅见《酒诰》一处,《说文》据《酒诰》上下文释作&quot;伤痛&quot;,根据多友鼎、作册嗌卣等铜器铭文,可以推知&quot;衋&quot;即&quot;盡&quot;字,训为悉、皆。《酒诰》有&quot;劼毖&quot;一语,《说文》同样据上下文训作&quot;慎&quot;,而比对戎生编钟与晋姜鼎,可知&quot;劼&quot;实即&quot;嘉&quot;字,训为&quot;善&quot;。根据《立政》相关文句,可以推知毛公鼎谓王赐命毛公,言内外小大诸事,总听于毛公,我不与闻;小大诸事不委于有司而总于王,是国所以丧。","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLFd1x17Ch8KUzsMe5MH9eqi3wfWnzocoI_fkSslP_QPo8SzetuIkdyAkPOOoJ2hWREe0XIcJGCh7ircJPJVqSBdBBVJxSNEbwGHRDbfA18Nk9825dXrnVdqScRDLAqfIfZCkz7ZmkHOLas_BSpwVrKblNiSPvi8FjA7MlMtqjXh7TZWL2PvCbL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-46","volume":""},{"id":4173,"author":"魏宜辉","title":"古文字中用作“伊”之字考释","abstract":"叔夷镈、钟及清华简中释读作&quot;伊&quot;之字的右旁,是从卜辞中有斜笔或横笔的&quot;几&quot;字演变来的,由于&quot;伊&quot;、&quot;几&quot;古音读音相近,因此这些从&quot;几&quot;得声之字在铭文及简文中读作&quot;伊&quot;。另外,中山王■铜器铭文中用作&quot;也&quot;的&quot;■&quot;字,其所从&quot;■&quot;旁很可能也是从卜辞中有斜笔的&quot;几&quot;字演变来的。","categories":["02_字词句考释"],"year":2014,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2014.06.007","pages":"55-59","volume":"54"},{"id":4174,"author":"刘书芬","title":"西周金文中“休”的词义和句法","abstract":"西周金文中&quot;赐休&quot;、&quot;休赐&quot;的&quot;休&quot;,学者们多解释为赐予义,而解释为休美、嘉美、嘉奖义更合适;句法方面,特别是当&quot;休&quot;作动词时,学者们对其词性、意义、断句等方面存在分歧,尚须结合西周金文&quot;休&quot;出现的整体语境、铭文的意义以及语法,作出合理的判断。","categories":["02_字词句考释"],"year":2014,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2014.06.008","pages":"60-64","volume":"54"},{"id":4175,"author":"田成浩","title":"“轩辕”名号研究概述","abstract":"目前学界围绕&quot;轩辕&quot;名号来源取得的研究成果,大致从四个方面进行介绍:第一,认为黄帝&quot;轩辕&quot;的由来与黄帝的制作发明有关;第二,&quot;人因地名&quot;与&quot;地因人名&quot;两种对立的观点;第三,认为金文中的&quot;天鼋&quot;即是&quot;轩辕&quot;的观点;第四,从音韵角度出发得出的其他观点。就目前学界的整体研究来看,因观察视角广、涉及领域多,多数观点之间存在着较大的分歧。","categories":["02_字词句考释"],"year":2014,"publication":"重庆文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.19493/j.cnki.issn1673-8004.2014.06.007","pages":"44-48, 120","volume":"33"},{"id":4176,"author":"鞠焕文; 张世超","title":"《金文形义通解》订补（上编）","abstract":"在已發現的古文字材料中，金文佔有特別重要的地位。它的延續時間長，能夠反映不同時代文字形體結構特征；銘文不乏長篇可讀者，又能夠為我們提供不同時代的歷史語言、文化信息。一直以來備受學者關注。而且它每個時代都有一定數量的出土和發現，其研究可以持續地、恆溫地進行下去。《金文形義通解》是繼《金文編》、《金文詁林》後一部重要的綜合性工具書，是金文研究階段性總結的成果。它體例新穎，創獲頗豐，一經問世便受到了學界的歡迎。但是，隨著時代的發展，新的資料不斷被發現，學界研究水平不斷在提高，《金文形義通解》到了需要進行修訂的時候了。基於此，本文擬對它進行一次初步的訂補工作。論文全文共分上下兩編：上編包括：第一章：緒","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8BSEGZx-cyu7Z7sr6m4K0bmd66oSpjOgg4G_W7U8CrS01Mbe7VS7B-7NilCdACF0uDzzFu9T5t9V9nHixdZtPMFCkyuNTqVdRa5U9xxk7PF8ndJ_QF-6l4MQLmnEzX2dSL3le1_pJXtuqGHDJ-IANnpP6SL6-W6ukcvBoYn2b4ZOdsOWsrdtI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4177,"author":"董莲池; 郭秋媛","title":"释孔鼎中的季","abstract":"《篮斋吉金录》鼎九著录一西周中期鼎,其铭第一个形体一向被释为&quot;孔&quot;字,本文研究认为这个所谓&quot;孔&quot;字与通常所见诸多&quot;孔&quot;字写法皆有别,辞例亦不能证明是&quot;孔&quot;,它应该是&quot;季&quot;字省体,当释为&quot;季&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLyb1AVsvtt2b5cqpwtyRbU5CHOt6nl6R8hpjgOiP3mOoPjy5RM5wLS7ShnJBlsR2smKkV28pBfQF3l4Dr0mbKjQ0i7iTbYIRLMq6VYbcxURfMvSgP1dpRwBCL7FSIBNheM_hmxmvA7lt249wUmgp5TVG1ybSzPHoMM-6rLGJtYeA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46339","volume":""},{"id":4178,"author":"周宝宏","title":"畯簋铭文考释","abstract":"畯簋铭文为新发表的铭文,只见著录于吴镇烽《商周金文通鉴》(2013年光盘)。本文对畯簋铭文中几个疑难字词进行了考释。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdWZOUcOFmDY6gl3IEw2bYjdncNHGVcJCtz-ZbpuAem-9PN8CbTrOJXE-IDBzTF7hqTH5D1jE5yMHONZRVKd4PP5BVBWSrjpLVoKYpAGWXBqpajImCrYBoLNKrmeuBPGYFFvyrQNb-6928G4buYMF6wy0eCZ5bYK1Yce-pIPExlw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-18","volume":""},{"id":4179,"author":"宋華强","title":"上博九《成王爲城濮之行》考釋(九則)","abstract":"一子■(文)△1帀(師)於■[甲1]子[甲1]玉△2帀(師),出之■[甲2]君王命余△3帀(師)於■[乙1]簡文中&quot;帀(師)&quot;前之字,字形分别作:△1■、△2■、△3■。整理者把△2釋爲&quot;叟&quot;,△1、△3釋爲&quot;遚&quot;,皆讀爲&quot;受&quot;。1陳偉先生疑&quot;叟&quot;、&quot;遚&quot;讀爲&quot;蒐&quot;,&quot;叟師&quot;即《左傳》僖公二十七年的&quot;治兵&quot;。2&quot;不求甚解&quot;先生贊同陳説。3蘇建洲先生認爲△本是&quot;受&quot;字。4賴怡璿先","categories":["02_字词句考释"],"year":2014,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKAgvE5FEFI12i0DeG4FP1HTu_RXtT2QO-YMYBvDeXc4I3B_qmgxwFzkqKtDa_PdkYTNjQp8R0gYLxRpPpLoZYHEfFrNI73TC7DB4sNwOWFhKzqDlpDgGdmFnCSru8Os8FNbBU4kCgjyvuTZgtx8nczsDsmp0DzD4is8yshcWPdIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-101, 531","volume":""},{"id":4180,"author":"李守奎","title":"據清華簡《繫年》“克反邑商”釋讀小臣單觶中的“反”與包山簡中的“鈑”","abstract":"小臣單觶原文作&quot;王後克商才成周公易小臣單貝十朋用作寶尊彝&quot;,雖然很短,只有二十一字,但研究的學者很多,異説紛紜。分歧的焦點是&quot;□&quot;字的釋讀,其字形作□:字形很清楚,由表示山崖的&quot;厂&quot;、&quot;土&quot;和帶有指甲的右手&quot;又&quot;三個部件構成,但學者們對三個部件之間的層次關係和功能理解不同,綜理諸説,大致可以概括爲如下幾類:一、隸作&quot;□&quot;,釋爲&quot;阪&quot;,讀爲反叛之&quot;反&quot;,&quot;王後阪(反)克商&quot;指武王在文王十一年渡孟津克商。1周人自作器","categories":["02_字词句考释"],"year":2014,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0YFFBX-YV8vAFqCW0Cd9DuOYDjDEL50yWCkx4uJg1kep7gOKCFYz92FhefXQMuDOgmjy9HrFFhDDbGfjAQrf24Fl5tJHauMq4EvxHqUfpfMl67Zqy58ZtqF0zzDfSw2Pu4erc-NJFVbI-yasGKsgaKy61a9o9TGNzYVM3auLQvw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-136, 531","volume":""},{"id":4182,"author":"宋華强","title":"淅川和尚嶺“鎮墓獸座”銘文小考","abstract":"時代在春秋晚期到戰國早期的淅川和尚嶺2號楚墓出有一件青銅“鎮墓獸座”,其方座頂部有銘文八字,發掘報告釋讀爲:[1]曾中（仲）■（薳）君■之且（祖）埶銘文雖短,釋讀却頗爲分歧。關於前五個字,李零先生讀“■”爲“君”,認爲:“器主‘曾仲化君'疑是曾氏女嫁於化氏,猶魯隱公母稱‘君氏'（見《左傳》隱公三年）。”[2]賈連","categories":["02_字词句考释"],"year":2014,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeBjwrMVgv74wknFtSVDTzTZ4UkCjUlVmC-tr2s7y9Tp43EBZu1TskdLJg633wuaBm7vw0xGJR-3sIfNRWw2ze3cPnJI5MyoUwop0ct_yswnzilhTlc5IEhJSBaWTgf-tKcYfDjL5NXeOM9bNkMrcYWBnV_4tUVI5NUCFzPw4-H0pnvbMWId1Q&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-32","volume":""},{"id":4183,"author":"謝明文","title":"金文叢考(一)","abstract":"1.釋復封壺“廢”復封壺甲(《銘圖》[1]12447)、復封壺乙（《銘圖》12448）兩器銘文相同,其中有一句作“公命■（復）封（邦）■（■）于魯,不敢△公命”。△宇分别作■、■（下文如對它們加以區分時,則用△_甲來表示前者,用△_乙來表示後者）,《銘圖》皆釋作“■（貸、怠）”,我們認爲這是不對的。","categories":["02_字词句考释"],"year":2014,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdXlLY6E_7jS_to3hzg4grVXAQWkVPs8B4B7lbQxKiOV6bJIWpW1mlCQF9LjlQNZ_aHGfYo3KxWz7hoK_2GTd8YHsS6QrdoSBuE-GD_KlF4l_dUZg-Mzk1bl_FCRxN23p0AYWjThj3AQ7Nc3wFkdjOACaK-0t0IpygEgYzzHo5yiY-6-v07XTG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-51","volume":""},{"id":4186,"author":"章晶晶","title":"释“止”","abstract":"汉字&quot;止&quot;,按汉字源流学的考察当属于&quot;初文&quot;,其源可追溯至商周时期,并因其较强的孳乳繁衍能力,产生了以其作为构字部件的诸多新字。古时造字大抵多由近及远,&quot;近取诸身,远取诸物&quot;。&quot;止&quot;作为人体下肢重要器官,察其形音义之演变,对于考究含部件&quot;止&quot;之诸字有必要性。一、&quot;止&quot;形止,按《说文》:&quot;下基也,象艸木出有阯。","categories":["02_字词句考释"],"year":2014,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2014.05.009","pages":"50-52","volume":""},{"id":4187,"author":"赵庆淼","title":"西周金文“■”地识小","abstract":"自王国维开始,学者多将金文中的&quot;■&quot;字释为&quot;坏&quot;,认为其地即大伾山。事实上,该字应该隶释为&quot;■&quot;,当分析为从不、乇声。究其地望而言,&quot;■&quot;地很可能正是传世文献中的偃师&quot;西亳&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJWA6LiAC72fRqIo_u2rVFA1iWJ-YMdi7WUcV_mCg0ygAexSj5NtsWTE7RI3AzJQaFsswE_cgWxHG8rvfFA8tuns5qnRxXc0xqUIK7ImL8wS4VR8pcjHDp0hYljjIQayGuRzIAIeh22lyapwQvwgnZ4C6bT10IagnPwBqWwFhWm6g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-43, 59","volume":""},{"id":4189,"author":"董越","title":"廿二年邞戈考","abstract":"1982年郸城宁平出土一件青铜兵器邞戈,本文首次从铭文的字形特点、格式、辞例内容等方面对其进行考释,并在此基础上认为邞戈为三晋中的韩国兵器。","categories":["02_字词句考释"],"year":2014,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLwpvQdMHfQnPNAzIGZzicqyyROUXgQqvCz_xWOUrvJpX1KLS4QT0dcqMCS7bdkITqoKWOHK-XM4O02A5iA504ovwHkYQ_v_LrRnLg2YCJmHWfiZ8Bz7cU8SjCmtges6FCFrWqrk-VesLy-JXDZHmomv0eUF4acGZIFSNa93GHu2g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-74","volume":""},{"id":4193,"author":"郭洪义","title":"《曲阳白石造像研究》释文校补","abstract":"《曲阳白石造像研究》释文错讹、缺文较多,实因不辨形近字形、未识合文、误释异体、文字泐蚀、不明文化词语等疏漏所致。通过结合历史文献及石刻拓片,纠正其讹误,分析误因,避免以讹传讹,以使这些宝贵资料得到更科学的利用。","categories":["02_字词句考释"],"year":2014,"publication":"绵阳师范学院学报","link":"https://link.cnki.net/doi/10.16276/j.cnki.cn51-1670/g.2014.10.018","pages":"88-93","volume":"33"},{"id":4194,"author":"单育辰","title":"近出金文词语考释两则","abstract":"本文对《史惠鼎》、《(?)钟》中的两处字词进行了考释:把《史惠鼎》中的&quot;褐化(?)&quot;读为&quot;遏过去怒&quot;,是遏止过错,除去怨怒之意;把《(?)钟》中的&quot;埶&quot;读为&quot;杰&quot;,是杰出人材之意。","categories":["02_字词句考释"],"year":2014,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIRxVaIuvLQnhIEvnC32GzfrZjSBxbLaOT2AAkndhLqQmkdD4zHADgEAvqw06O4f5ufmb4gj6Iiuu_cNm8nH5iVPKGBe4QVnp9d2piU6PRMTiks5u_TpdXhxpWf0o0InDgxx_X4Kw4k5APNRmLSucnYjsRbVXFuncAfSLi_Q8NGDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-115","volume":""},{"id":4200,"author":"孫合肥; 徐在國","title":"戰國文字形體研究","abstract":"在漢字發展的歷史進程中,戰國文字上承春秋文字,下啟秦漢篆隸,是非常重要的中間環節。我們以出土戰國文字材料爲基礎,在全面搜集字形資料的基礎上,對戰國文字形體的若干現象進行細緻地梳理。同時將戰國文字置於古漢字發展的歷史背景中,採用共時研究與歷時比较相结合的方法,全面考察戰国文字的形體風貌。我們選取簡化、繁化、替換、移位、旋轉、訛變、類化及區系特徵八個方面爲切入點,考察分析戰國文字形體的具體现象。簡化是漢字發展的主要趨勢,戰國文字的簡化方式與前期文字大致相同,主要有輪廓性簡化、特徵性簡化和並畫性簡化。但是戰國文字簡化過程中卻使用了以往未曾未見且重要的方法,如輪廓性簡化中的形體濃縮、形體留空、筆畫收缩","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL9enzExJqWyZP0JgArvlGBZpIk75sKHtqeJouiDajUi3iHHsdBV5AodHpqXsgn3xL1TITeNiKdJr6xeDTbdM1W9WRysekCLe9h2gtWIlaSM7fN0kpd9bwUSzwRSTqVT1fyC_7jvdYk8TBXZAdnGoejAAOloYTnTs03dN6rxpo_h6yZoPDuTxD-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4201,"author":"田率","title":"夔膚簠铭文读笺","abstract":"2009年中国国家博物馆新入藏了一件夔膚簠,时代定为春秋中晚期之际,是南方夔国被楚灭后,其公室遗胄为嫁女所作的媵器,器形、纹饰带有明显的楚式风格。夔膚、兒等称谓比较特殊。","categories":["02_字词句考释"],"year":2014,"publication":"古代文明","link":"https://link.cnki.net/doi/10.16758/j.cnki.1004-9371.2014.04.014","pages":"70-74, 111-112","volume":"8"},{"id":4203,"author":"李春桃","title":"自钟铭文补释——兼说掳器","abstract":"2003年浙江省绍兴市出土一件青铜甬钟,钟上有鸟虫书铭文50字,是研究吴越地区史实的重要材料。曹锦炎首先对钟铭进行了介绍与考释,创获甚多①。其后一些学者又围绕钟铭进行了热烈讨论,据笔者所见蒋明明、马冀、紫陌、董珊、杨坤、赵平安、李家浩、郭永秉等先后对钟铭提出了见解②。相关讨论使铭文研究得以不断推进。本文试对钟铭提出一点补充意见,不当之处,祈方家指正。","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzccui10FOEF6zf8Ru0a6K7bUMEALthuCL_qp2NcwyyP2p1GPg4q4gEflmemiXEnF9sAZj79dFg4d10lF-m3bVF2PkaJRAr8drCNtgNzvF9_WhFJftqHd1uD38XUZhyUPkUfcSEMTfDNpVdrFVNnD323zwQh7-F3mJibaL5bUfRw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"223-229","volume":""},{"id":4204,"author":"程鹏万","title":"番中(仲)戈铭“白皇”研究","abstract":"番中（仲）戈系1978年湖北当阳赵家湖43号墓出土的青铜戈①。它的援与胡上有错金铭文。铭文是优美的鸟虫书,共三行八字,即戈援上有两行,每行三字,胡部有一行,二字。戈铭可以看下面的拓本（《商周青铜器铭文选[二]》②622号）及摹本（《殷周金文集成[修订增补本]》6051页1126eB）③:","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKBc6D1ad8DCqpemuGvqpWFV2nG5x_WkP-jCtKNbUpv3WO0nPze-Mp7v7S6SacsGUosWlu_maX0sYnriIVQXzwEqNBnL-oh-bEoN5hwkhMDgFzOpSOSModhXPw0V7XLgpN9UCsUkCbNHmhyw8NoXem750csHj9lre4O--6PH4vMwA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"230-234","volume":""},{"id":4205,"author":"秦晓华","title":"梁十九年亡智鼎补释","abstract":"梁十九年亡智鼎(《集成》2746)是一件战国时期魏惠王时期的标准器,自公布以来,引起了众多学者的关注。该器铭文前半记录器物的制作时间、制作者与容量,开物勒工名之先河;后半记述了作器者参与的一件有纪念意义的事情,具有书史的性质。本文就其中的几个问题稍作阐述,就教于大方之家。一、“求”字的释读","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIqS6cQcMmNqDVkM8E51wub4X9h6IKX7OnsKKuqLpnD3QPvkcnKOPRzIcXr69lyLaUWhZe7TvqwfCgUQBLuoUjHP7MhevCpL_rCd0DK1nFXDgZZeyak94vvtIDNZ10ZUG2CGmcCM2ZAb0cTT8uZAYeV5-9CX-xsQCDy_l7d16RYaw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"241-243","volume":""},{"id":4206,"author":"魏宜辉","title":"金文新释(四题)","abstract":"一、禹鼎西周铜器禹鼎著录于《殷周金文集成》2833(以下简称《集成》),铭文记述了器主禹佐助其君武公讨伐鄂侯驭方的事迹,其中有这样一段内容(除了讨论涉及之字外,本文尽量使用宽式隶定):肆武公乃遣禹率公戎车百乘、厮驭二百、徒千,日于■(将)肤肃慕(谟),■西六师、殷八师,伐鄂侯驭方,勿遗寿幼。","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKStQC08y2vHDgj62ZrZWBwbC8MRO4h_LreCnxjSzEsG5HTA1ZlNz1Dyi-1va8vkbHmMuHYO9E9ZEXyjzWSrmPUPRR_7oyLru_E4P6mxSxcWYX12F21Rjfd6n62JNYzj01HWzqvKf0MR4FTvv4U496DqoeVlWK06xFHZkomiscCOQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"244-250","volume":""},{"id":4208,"author":"汤志彪","title":"先秦兵器铭文考释四则","abstract":"近年来,先秦兵器大量出土,其中有铭兵器数量众多,铭文内容备受关注。下面我们就几件先秦兵器中的铭文释读问题,提出自己的见解,以期抛砖引玉,就正于方家。一、释“拲”《江陵九店墓东周墓》第234页著录一件三晋铜戈,其中工师的名字作:“▲■”形。▲字原作:","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIupB1tYTSdpLmCfv-jx4KfS5ITG8E_E6T964dqPInCdzlzdn44nmwy3UClKNnlRfCxdAL7qnXpYXdpyfmw5PYt7LNfgCRsl9XB6DODWvJD2zSJDZN8ZzwEn3gfLrziHB4T5wXV3DDEbc0AV1QYrEDtk3lw5gYhh5Yu78sKoBTaig==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"258-261","volume":""},{"id":4211,"author":"赵诚","title":"两周金文中的“弘”和“引”","abstract":"拙著《甲骨文的“弘”和“引”》①简述了殷墟甲骨文的弘字和引字构形有别,所表示的词的用义也不同。弘字写作■,引字写作■;弘的用义为“大”,“弘吉”即“大吉”;引的用义为“继续”,释义见后。两周金文在很长一段时期里所出现的构形,基本上写作■,摹本参容庚《金文编》第三版663页②,被看成是同一类型,没有分辨出其中存在的差别,王国维、容庚、郭沫若、徐中舒、高鸿缙、周法高等均释为“弘”③。其实,宋代学者早己将秦公钟、叔夷镈中这一构形的字释为","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoy5ITCxLqhgP4sfE7K7OVElBHLA_3MCZliEOeUeLQQuhUPXL8Sfdzvue7AMj7_LtdWyHQVr7EzD1zRj7wCLVBQoyLC-2fVtZrdPyWsrsyWa7zB1kKk6JYL-Z9DE6rOgxQnmoNVs1Kc-s3dOu_eFeFFvL_Vn1pQiewn2VdQW2qkA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-118","volume":""},{"id":4212,"author":"唐钰明","title":"铜器铭文释读八则","abstract":"一、金笔者在《铜器铭文释读二题》①中已将效父簋“休王赐效父吕（铝）三”的“吕三”释作“金三”。查《殷周金文集成》②,執卣、執尊依然释作:“乙亥尹格（各）于宫,商（赏）執,易（赐）吕（铝）二、聿（筆）二,孰用作父丁尊彝。”释“吕三、吕二”,典籍缺乏文例支持,铭文也难","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsaWoStaVynCxvRTQnNiOAwY7bRnRJI2LIKuNmwUlTvQCLx2p5CVPB4WDp5nvtfAvBquUio7rly9tEiisa_iMIUIdT0aKDdweeU86WkCnJoeM-ZCT4vB44qSGoilyxTp_2QzGrjliheB2m188cK9BSpOK32NfZ6O09F4NjbKfaOQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-122","volume":""},{"id":4213,"author":"李家浩","title":"说“命汝更■克司直鄙”","abstract":"1974年,陕西省扶风县强家村出土一批西周铜器中,有两件恒簋盖,其上有相同铭文,开■部分说①:王曰:恒,令（命）女（汝）更（赓）■克酮（司）直■（鄙）,易（赐）女（汝）■（銮）旗,用事。二十多年前,我在一篇小文注中说,“更”下之字从“京”从“又”,即“就”字的异体②。现","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsaWoStaVynCxvRTQnNiOAwY7bRnRJI2LIKuNmwUlTvQCLx2p5CVPBqiAP__5xMO6OJwrzu9ASCOsg7W89stUFhKpYyvFTu4CAT8h4EU9qim15Wob1QH_tg738hS3Q7-eZCnRlAKDbepRYnC2857qjZcYrIpJrjT3IipzVHPM-JA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"123-124","volume":""},{"id":4215,"author":"单育辰","title":"焂卣补释","abstract":"焂卣或称叔■父卣,1978年出土于河北元氏县西张村①,共二卣,每卣盖、器皆有铭,拓本著录于《集成》5428、5429,铭文内容相同,文字如下:叔■父曰:“余考（老）,不克御事,唯汝焂■（其）敬乂乃身,毋尚为小子。余■（兄）为汝兹小郁彝,汝■（其）用飨乃辟軝侯,逆■（复）出纳事人。呜呼!焂,敬哉!兹小彝妹（未）吹见,余唯用諆（其）■（延）汝。”","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIK9uRsRSm9OECAt3Y1rNTZB5xKV6jjp38wN6VoAchvsYe-KyPkpTjQC0e3MVXW3Auqzs2GgqomGXI1sjvWERHZreqS4Wx-OhsLCiz535MoxJBS5iFirTOnZPr58t2SD1p983HMxcxPMufQEde0j7-4KVk7R7gOhQX0OVXznxfQ4g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"131-133","volume":""},{"id":4216,"author":"田炜","title":"西周金文字词关系零札(两则)","abstract":"汉语字词关系是指文字及其所表示的词(音义)之间的对应关系。不同时代有不同的用字规范和习惯,因此不同时代的文献资料所反映出来的字词关系是不尽相同的。总结和研究出土文献的字词关系,对文献的释读工作以及汉语史的研究都是很有必要的。我们在阅读西周金文资料时随手记录了一些与字词关系有关的札记,兹选录两则,就教于方家。","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuCbi9jWQragih6F5ANurMTWA8iYg0tY_333U-8PSRANuz_UaM_xMRo2XVYv8cQoPe-Q0s-pKDy52COsi1Wt12N2M3IDLYbNcEfixfA-bSw9UhpLOfDwoiI23UNWATyX2bMWSHMienGoLlQJuUm_HmQ2kmwW074T9jIAsQFkao8w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"134-136","volume":""},{"id":4217,"author":"罗卫东","title":"金文“匽”“郾”字际关系再考","abstract":"金文有■等字形,这两字之间是什么关系呢?前贤时彦有不同的表述。容希白《金文编》（第三版批校本）“匽”字头下注明:“匽,经典通作燕。”旁边朱批:“孳乳为郾。”在该页的天头,容先生朱批①:国名,姬姓,伯爵。武王封召公奭于蓟为北燕。董莲池在《新金文编》中这样分析②:郾,假匽字为之。典籍用燕。","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0wCCA8b_ZfySK-bS4uhGHbdx-t0id0vqu7u3jqXuywtHW2bzFeueftALY87Ern-QIsdVTsz2ErOR1urJaOqbROEwmLHgRvctgzPeKxa17xbiigd5Tmi3gfYe3Nsw0G6zRmkMw5KwK1KwPm5KSBsGjLaIxMdBbjFUtdw_7mYXnmg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"137-140","volume":""},{"id":4219,"author":"商艳涛","title":"“王若曰”所领起的铭文性质补说——兼说先秦时期的誓师活动","abstract":"西周金文中常见一类由“王若曰”引领的一类铭辞,很多学者对此进行过探讨①。据学界最新研究,“王若曰”可以省作“王曰”;金文中由“王若曰”引领的文字多为命官之辞,即周王册命大臣时的现场讲话,少量为王就国家大政方针等所展开的论述,即布政之辞,后者即多见于《尚书》的诘辞,典型者如西周晚期的毛公鼎（《集成》5.2841）;此外,王以外的贵族也可以用“某某若曰”的形式来表示讲话的开始,如西周晚期的逆钟铭（《集成》1.60—63）“叔氏若","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJikpqN0WziqPOjTKEAlSu-lQr_qAGbtR1tPVld8BvqgZl3BUVUNyy--gio6Q5gYEzipVxuYFfhy_1lmT3CpR8Mf8HdjtRAAszEzv5tohyRKcq7Cbb7fPHIy0L-k79uIVqNc3pOB6mit7MN_0BkY7f9quZH-HqO8w-af_ntKo_VMg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"146-151","volume":""},{"id":4223,"author":"袁国华","title":"子犯编钟■字考释","abstract":"一、前言本文参考六位学者的研究成果,重新考证子犯编钟■一字的形音义,尚期对相关研究有所裨益。惟疏漏难免,尚盼大雅君子有以教之。二、子犯编钟■字考释回顾子犯编钟,1994年11月中旬由台北故宫博物院购藏①。原为十六件,八件成组,共两套。台北故宫博物院购得当中十二件,除了第一套的八件外,还有四件小钟,是第二套钟的后半。至","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-e9SBot_pwb_VnHvVaHvPMXtni7Vi8KBjbJvljhXtoRGFu_R-uiFov0ACDs_0OLKPgdO3o_9de_FlZ2tfZkOMWse7uCe_KatmR4IIQ2-jsW3J7d2m6NcnJNmg1VvNcPOS3xJvy8uVypv_HVNW3AEnbimz19hooA2H3EMtjqMAnw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"178-183","volume":""},{"id":4225,"author":"邓佩玲","title":"铜器自名前修饰语“■”字试释——兼谈“延钟、反钟”等辞","abstract":"“■”于金文中颇为习见,除叔尸钟用作地名外,其余皆置于铜器自名前作修饰语,主要见于西周晚期至春秋晚期的食器,当中有鼎、簋、簠及鬲,如:曾者子铸用乍(作)■鼎。(春秋早期,曾者子鼎)■乍(作)其■鼎贞(鼎)。(春秋早期,■鼎)倗之■。(春秋晚期,王子午鼎)隈凡白(伯)怡父自乍(作)■鼎。(春秋晚期,隈凡伯怡父鼎)蔡侯■(申)之■。(春秋晚期,蔡侯申簋)束中(仲)豆父乍(作)■。(西周晚期。束仲豆父簋盖)","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLFDX0Rd4QjTtmw4zUO2To9m3cbty_GCJ_YH_ZTLQNWl8AqUr_yWu-ncTBjMJF5RjL69gGxpe5EHsYEb1fMd3CR05ARgJALx0fafRZoFXppPSKwg8TUzLmRbWzuhhXQlUPOGrNzGMHyskNLzX-crFGS8YHK8KIwJ6mnBBI1fYZCAQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"200-205","volume":""},{"id":4226,"author":"孙刚; 李瑶","title":"读金文札记三则","abstract":"一、释“■”《殷周金文集成》(以下简称《集成》)2162、2163号著录两件西周早期大丐鼎铭文,原器本为罗振玉旧藏。现将铭文释写如下:丐△乍(作)大丐《集成》2162、2163释文中△所代表的形体原作:","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLIv2AB3j_ArWkxGqgCXPxRebtBfVuXDTWP0UG2DCJgoRfu-cuhjkLInkfVnocreD0VC13Bc6iEaDSHtIXPOf0oSAnnTa5foCwZKuGNJDF-lZv8mGM8WrvHY5puhEPceOavXs3gnvHO1sPYhy0YL-YLcir58zorZE01vmJsyNavHA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"262-266","volume":""},{"id":4227,"author":"石小力","title":"利用楚简考释金文字词两则","abstract":"建国以来,战国竹简文字陆续出土,上世纪90年代以来,随着包山简、郭店简、上博简、清华简的陆续公布,楚简成为战国文字研究的核心,也成为破解其他文字材料的一把钥匙。学者们利用新出楚简考释其他文字材料中的疑难字,取得了很大成绩,本文利用新出楚简考释了金文中的两个疑难字。","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLIv2AB3j_ArWkxGqgCXPxRebtBfVuXDTWP0UG2DCJgoRfu-cuhjkLIdkp35_mIK-Hb-dEHntwfe7tayfWjdi-7XTEjPdcYtbyASd11r9butvgzjg3xZP8Huu3rvXiRO1RDtj5QjUztJO6YQBUInJOxFfQB3SO9LBLGXdTUJxLdmw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"273-278","volume":""},{"id":4229,"author":"刘洪涛","title":"谈古文字中用作“察、浅、窃”之字的考释","abstract":"战国竹简文字中有一个经常用作偏旁的字,它在偏旁中主要有以下几种写法:a■郭店《语丛一》68 ■包山183b■郭店《五行》13 ■郭店《五行》8c■包山128 ■郭店《穷达以时》1d■郭店《五行》46 ■同前e■郭店《尊德义》17 ■上博《用曰》15","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyDVZvTMmasRljjHcCeCsgpiQp-lhvHhepoAlUUHEzGOVKZtCgqmFK9NcwGreLzw_8k2Hb6SejAhhXtHna7R5ng5cI600mrORe6zIVT77k9-ptnRXDlT3KfB_9pm1KjrcpwkPrh1vEp8lPpaIPMCy3PLiLWR7L5ayR_b-AcT_g-A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"315-319","volume":""},{"id":4230,"author":"郭永秉","title":"关于“兆、涉”疑问的解释","abstract":"容庚的三版《金文编》附录,收有下列四个字形（四版《金文编》附录下507号同）:■容先生按语指出“旧释姚”,因第二个字形是器主之名,容先生不采纳旧释,但仍把器名称作“■（即容先生所定姚字简体）鼎”①,大概是权宜示意的办法（四版《金文编》则改摹器主之名原形而未作隶定）。这个字去除女旁部分所从因为与“涉”之初文相似,该字能否用作女姓“姚”,学者看法有异;主张此字是“姚”的,对其声旁的分析也有不同看法。容先生阙疑的态","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIENl8EjTp13qrJ2omlyYKeQbjgFYBXJA4FXgYVxNrPbFzziTKkG3PgTFcwNKB8FiY-ZALwzoJg_vTtqZ8twvU4bu_WTyqQ_FxEGd_S-xfslFL6QtZMOVMv8Q9-HtRiIEcaZl3e1gX3NT9EGuH-IulCA_4iDLhjng-NbI_19aLGQQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"485-492","volume":""},{"id":4231,"author":"陈致","title":"“赤纻市”與“彼交匪纾”","abstract":"金文中有■字,或称“赤■市”,或称“■市”,每与“玄衣、朱黄、銮旂、黹屯”等相并举,显然为赏赐之物。又有“朱市、赤市、叔（■）市、■（■）市”等①。传统学者多释为“环”,如薛尚功《钟鼎彝器款识》十四,唐兰由此说申论之;又或释为“鹥”,如郭沫若初谓此字是“鹥”之初形,而“鹥”亦市属,是蔽膝之一种;郭氏后又谓此字为《说文》中■字之初文,亦即■字,是茅蒐所染之绛色;李旦丘释其字为“纾”,谓为纾缓之义,并认为金文中叔市之叔字亦与","categories":["02_字词句考释"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIENl8EjTp13qrJ2omlyYKeQbjgFYBXJA4FXgYVxNrPbFzziTKkG3PgDiACFc0acm3-Ry821mWGVutlB5KintwkHAIxG0-rKunQHABFBpJ7RAzcXwxYVUOV9cq3PwQ9Sot3V7siePx9EtvvPgmNE9P6KnLmA-q8nY72jHX6MCYGVg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"514-521","volume":""},{"id":4232,"author":"朱崇才","title":"论“婉”:词学核心概念的字源学谱系分析样例","abstract":"&quot;婉约&quot;为词学的核心概念,&quot;婉&quot;的含义,可从&quot;夗-宛-婉&quot;的谱系中寻绎。&quot;夗&quot;训&quot;卧&quot;,在甲骨文及金文中,系由两个或一个弯曲的人体所构成的象形字。&quot;夗&quot;含有&quot;屈、曲、圆、转&quot;等义;&quot;宛&quot;从宀从夗,由宀(馆室)这一部件,增加并引申有&quot;深、幽、凄、清&quot;等义;&quot;婉&quot;从女从宛,增加了&quot;顺、丽、娈、媚&quot;等义。&quot;宛、婉、惋、怨&quot;等夗族字,可与意义相近或相关的字组成诸多双","categories":["02_字词句考释"],"year":2014,"publication":"南京师大学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJuJKIqCzyXY1xIPuJWz15rTUA1bDFxLG6ugWdrJSMdxzzf7aG59YeKzC0-PGStrlKFZVqglZCcWyB_gtWZlI-hwu0xa9-5Br24Cpta8iMibiG7Panwkr3ZPNtvCH0eJWVS_A2AyxANjPtvxagTMO1YQgcaPFA9jz-J6XabOBbt0w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"155-160","volume":""},{"id":4234,"author":"张国安","title":"“言”与商周礼仪及其歌咏——汉文化歌唱传统探源","abstract":"本文以卜辞、周代铭文材料的训释解读为依据,对商代、周初礼仪及其歌咏情况作了梳理,得出如下观点或推断:甲文&quot;言&quot;之初义取象于&quot;口簧说话&quot;,口簧用以表情达意,说话交流的功能是后世&quot;言&quot;字派生出&quot;言语&quot;之义的根据;口簧乐器演奏所具有的&quot;以乐传语&quot;、&quot;以语定乐&quot;之特点,正是后世&quot;歌永言&quot;传统&quot;以乐传辞&quot;、&quot;以文化乐&quot;的原初范型。以口簧说话为造字背景的同源异构字言、舌、告,在卜辞时代其语言学意义和人文内涵已渐分化,其字指义始有","categories":["02_字词句考释"],"year":2014,"publication":"文艺理论研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJSIYBuJ_83gdBuOIlBVHZpbrhIi2jBOqc_6WmFuOehurmU4D1NPE7zdQjWW-_ywfKgveFIvgp3QiZ65CiKZ_GTurKHLd0VD9nwWSoYrnWsdIYyF28Y-LyeMixI1jTzj3cPVbg0WM2fitT77brXxbE-Y57h9mDML6l4WnFdkTmnqA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-67","volume":"34"},{"id":4235,"author":"袁俊杰","title":"令鼎铭文通释补证","abstract":"令鼎是西周早期重要的有铭青铜器,因铭文记录了周王在藉田礼末了举行的燕射礼和竞走比赛而受到学界的重视,但各家看法不一。本文在已有研究的基础上,着重从礼学的角度,对铭文作了通释补证意译,并对一些关键字句及其相关问题作了新的考释与论证,提出了自己的看法。","categories":["02_字词句考释"],"year":2014,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2014.03.031","pages":"113-122","volume":""},{"id":4236,"author":"赵卿","title":"秦戈铭文里的“物勒工名”","abstract":"涪陵小田溪铜戈铭文1972年,由当时的四川省博物馆、重庆市博物馆、涪陵县文化馆三家机构联合,在重庆涪陵小田溪清理发掘了3座战国时期巴族墓葬。其中三号墓(M3)为长方形竖穴土坑墓,墓底长4.4、宽2.1米,墓坑四壁有夯打痕迹,棺椁木质部分已腐朽殆尽,人骨架已朽,葬式不明。在M3中出土了一件铜戈,为四穿长胡内刃戈,戈前援长14、栏长16.2、内长10厘米。内上一面刻有铭文,与&quot;秦昭王四年相邦冉戈&quot;篆法体例一致,所以推断&quot;廿六年&quot;为秦昭襄王二十六年(公元前281年)。","categories":["02_字词句考释"],"year":2014,"publication":"大众考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJE0pHmA4guBAEz3QnM635OJno42L_5DI1SJHlCYlczTgfiAig4gqVqRrlTpLGBC1-9IXYQaBgmqLpmGVno-ecjXoT9o7vd5MgvUnOM8bMbI1qpbZ1isQzzpLgP6BzU-94lRlvej9oY0yk946caRMshwMtpj_wa9vxzT4x0flIp5A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-73","volume":""},{"id":4240,"author":"刘传宾","title":"说“金”字的一种特殊形体","abstract":"&quot;■&quot;字形体特殊,在铜器铭文中多次出现。从铭文内容来看,&quot;■&quot;字或作为赏赐的物品,或与&quot;尊&quot;、&quot;彝&quot;等词语连用。对于&quot;■&quot;字的研究,以往学者有释&quot;贝&quot;、&quot;吕(铝)&quot;、&quot;鉼&quot;、&quot;铜&quot;等多种意见,但放入铭文中于文意皆有未安。本文在前辈学者研究的基础上,结合金文、简帛等多种出土文献材料,对&quot;■&quot;字进行全面考察研究。本文认为&quot;■&quot;字当为&quot;金&quot;字的一种特殊形体。原因如","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5LbL74-no9jiE2PcvhT6XpyOee2dLNL37Q6QREMloOrrrGzc7aVtpjf0as7MBozz7DTJAEGDwteqFH50mOtB4w4Cyz0Qyx6MsapfYQW9bk8BGP4t37Wvt3QKDz6z5N2plDQDYuf2PN7PhF4LiCTHwPDQ6rUOxAe8bD_3mmFmJiw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-69","volume":""},{"id":4242,"author":"寇占民","title":"西周金文动词语法化初探","abstract":"西周金文是最早的成系统的汉民族语书面语之一,它保持着当时的语言原貌,是探索上古汉语词汇和语法的最真实、最宝贵的语料。汉语虚词的广泛应用,是促使语法变化的重要条件。通过对商周出土文献中&quot;来&quot;、&quot;于&quot;、&quot;即&quot;、&quot;以&quot;、&quot;及&quot;、&quot;眔&quot;的意义与功能的梳理,确认西周金文动词语法化过程导源于连动结构,证明上古汉语动词虚化始于商周之际。","categories":["02_字词句考释"],"year":2014,"publication":"天津大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3rHMslFfxLYsrXS8SmxWmWb6S0DkWQNVVMMEfH72VD6dDQOFVIzYVnoVelijwQcaEiQAtUpWYKB1PpCg3MKEfc0Li924OHYwRy_3A_jPJmWjfBuHvkKhclUV-Ao1UIT9EC0Mona8nLeA7HHNf3vWBx2BEadEwF5izLpqCbnzuWA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"468-472","volume":"16"},{"id":4244,"author":"王锦城","title":"岳麓简文和秦金石铭文字体比较研究","abstract":"秦系文字名目繁多的字体实际上主要包含两种字体,即篆书和隶书。篆书以金石铭文为代表;隶书主要是简牍上的古隶。除官方颁布政令、记功刻石等郑重场合使用规整的篆书外,普遍情形则使用笔墨书写于简牍上的古隶文字。秦隶源于篆书,是一种不成熟的字体,从以金石铭文为代表的篆体发展而来。秦金石铭文本身存在着圆转规整和方折简率的区别,主要是由书写方式、书写时的态度等造成的。","categories":["02_字词句考释"],"year":2014,"publication":"牡丹江师范学院学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13815/j.cnki.jmtc(pss).2014.04.029","pages":"84-86","volume":""},{"id":4245,"author":"康盛楠","title":"兮甲盘“畮”字意义再证","abstract":"兮甲盘是西周晚期著名青铜器,宋代出土。铭文记述了兮甲随从周宣王征伐玁狁,对夷征收赋贡之事。自清代以来,经过多家考释,铭文内容已基本可读,但各家对部分字的理解仍存分歧,如对&quot;畮&quot;就有通&quot;贿&quot;、通&quot;贸&quot;、依字读三种理解。文章进一步证明通&quot;贿&quot;才是准确的解释。","categories":["02_字词句考释"],"year":2014,"publication":"遵义师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKlCmPkthL2mUf0WnmaV3ryyolpIzeGAlzuRNm5aUGtWl4E_pHz6WI_ORCnhdzRDZjZ0bvaZPK_943aXFDXlS27kNyyKNm8kj708XH2eHjNG7stxRub8dq33syiHKjDfxhDPmHWG2SOpPqx0mtBOJVf8ZmHstMtYCrdLyI8DsowDA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-24, 31","volume":"16"},{"id":4246,"author":"马芳","title":"释“甫”——兼说“甫”声字","abstract":"《说文·用部》云:&quot;甫,男子美称也。&quot;但从&quot;甫&quot;字的甲骨文和金文字形分析及相关文献例证来看,&quot;男子美称&quot;并非&quot;甫&quot;的本义,而是借&quot;夫&quot;之引申义。&quot;甫&quot;是&quot;圃&quot;的初文,&quot;圃&quot;则是&quot;甫&quot;后起本字,即&quot;甫&quot;的本义就是种菜果的园子。同时,依据&quot;形声字声中有义&quot;说与&quot;形声字借声&quot;说的理论,对&quot;甫&quot;声(含&quot;尃&quot;声)字义作了进行分析","categories":["02_字词句考释"],"year":2014,"publication":"开封教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIn36XDZxi7jeZoIDJNjoah4-hIoxp09Zh-z5mg68OHsB6_xhpow400ftCX_CoU0opupkLAvin4bhJTILyBQmqtUnqwwPyPAH9y3RdT9WFNpfekRnkSbTOzm6Y-gFrc91VYgOk1Kkdrgk4Soeo5ovNR_VSKx9priXFqayEzOiR4YYOOnnOqownj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-19","volume":"34"},{"id":4247,"author":"寇占民","title":"西周金文动词研究综述","abstract":"西周金文是最早的成系统的汉民族书面语之一,保持着当时语言的原貌,是该时期语言的真实记录,因此它是研究上古汉语词汇和语法的重要语料。通过对西周金文动词的判定标准、词义系统、语法功能和复音词进行全面的梳理,为西周金文的释读和应用以及上古汉语动词的研究奠定基础。","categories":["02_字词句考释"],"year":2014,"publication":"理论观察","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIn36XDZxi7jeZoIDJNjoah4-hIoxp09ZioVzQUVX5ntk_xaJpHyZ_yz0NSYkaBMn7vip4bvRG8E1cVaZSjx2RMQ0jWQJecv1qdeNdh6AVACfqI4BBGiMfFaJ5EEY8edtBPtvFsn_GKOaNsBA802CuPyhh8wA3UqCOqM5oc6P0GqLmD5LB9DCxN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-121","volume":""},{"id":4250,"author":"林桂榛; 王虹霞","title":"“樂”字形、字义综考——《释“樂”》系列考论之二","abstract":"甲骨文里无&quot;樂&quot;字,罗振玉将植物形状的&quot;■&quot;隶定为&quot;樂&quot;并认为&quot;樂&quot;字源于木、丝构成的弦乐器是错误的。金文里&quot;樂&quot;字多见,《说文》谓&quot;■(樂),五声八音总名,象鼓鞞木虡也&quot;亦大体不谬。&quot;樂&quot;造字来源于铃鼓,是悬铃之建鼓的实际摹写,别体&quot;■&quot;(楽)象有鼓无铃且木虡所支之鼓正在鸣声状。小篆&quot;■&quot;上两侧之&quot;■&quot;即悬铃,&quot;8&quot;字形的&quot;幺&quot;源自小铃。&quot;幺、■","categories":["02_字词句考释"],"year":2014,"publication":"南京艺术学院学报（音乐与表演版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIE1bdhXtZHfkz611vQWM8SzFQeidLbD81bEjI3kpSjdOGnw-jenolI8Ui8hgXk-nITuYDg_D78ybwBjbIceprOrWlJ9Q7wlblVwlYRGxEGT8RUCbpuSovXRHLy9q7SyeCh2-HQgrlcfYK4eZreR0JuPV_uB8zcWuFnUX3DZsQ0JgWSzsPVCUBW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-78","volume":""},{"id":4255,"author":"凡国栋","title":"曾侯舆与编钟铭文柬释","abstract":"本文在简报释文的基础上,对随州文峰塔M1所出曾侯(月舆文)(與)编钟1、3、5等号钟铭文作简要注释,初步揭示其重要学术价值。","categories":["02_字词句考释"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-T4gAmp8IxhVf23P-dUw4_kb93rXUJZEFohCSXpRDDAvarnmIKiy4NCk1Koo2K2sXNgI3MVzLY0zkHSukXWhOjvvUWNfVuw5zHUnZ4X6VKxEIKk1W4k50cIvXNxUTXM4WvzZzUttibiwCJl6RKXPwDEPHPg8_E55OpzRBkE_J1w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-67","volume":""},{"id":4257,"author":"曹锦炎","title":"曾侯残钟铭文考释","abstract":"曹锦炎先生对北京收藏家梁氏庋藏青铜残钟铭文的考释可与随州文峰塔M1(曾侯與墓)所出编钟铭文合观。本文在残钟照片基础上作出摹本、录出钟铭释文,考释详细,颇便利用,现征得曹先生首肯与随州文峰塔M1(曾侯與墓)简报同期发表,供学界参考。","categories":["02_字词句考释"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIz26gjihCZHj4BMUhkvPsM6wnLdnFlM51BCx8McSAwfi385Gh7yH7Hlk5kogBB7d5gI2R6WUbeyYzh3AkefbMGIKrO-EU6PbQM2upbNFgQm34cFjZI94UD6axgX6yO1rKIfYwzP7vN5fJi4R370hXxEwXD2_duLzBWCjsY9xbDGA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-73","volume":""},{"id":4258,"author":"李天虹","title":"曾侯(月與文)(與)编钟铭文补说","abstract":"随州文峰塔一号墓出土的编钟主人曾侯(月與文)(與),也就是曾侯乙墓出土铜器铭文中的曾侯(尸月與)(■),是曾侯乙的祖父。一号钟背面右鼓铭文&quot;燮&quot;字之后的第一个字,应释为&quot;(言就)&quot;,可能读为&quot;就&quot;,&quot;就&quot;有归依、俯就之义。铭文&quot;周室之既卑,吾用燮就楚&quot;,意思大概是说:周王室已经衰微了,我因此和顺楚国。这说明,曾侯之时,曾国已经与楚国交好。","categories":["02_字词句考释"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJRA6OtbNq80R4bo04ehRoLgnSXm_SvZe9dIjGhBmTYilUvUMct9nB3sE1AStIFoZX6Pa_NRuQ-GurRtb9agdZmOH2zWJIwoviCX3N0Z3AtYMqdttupQDu1msWcvAiwSqQeKkcDxJ6MJv-qPnXSBEhqiT6LrRIhYme1rwwig97hA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-75, 129","volume":""},{"id":4261,"author":"谢刚","title":"“王”、“臣”本义发微——兼论辞书释义的阶级性","abstract":"本文对&quot;王&quot;、&quot;臣&quot;二字的甲骨文、金文、篆文的字形演变、字义训释进行考释,探究二字的本义,证明此二字的本义并非许慎在《说文解字》中的解释,而许慎的解释则在一定程度上反映了辞书释义的阶级性。","categories":["02_字词句考释"],"year":2014,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0FzMUVRM7Kn-NJ7akr-0qaBgQzueNT003_tw7cFGVb1-PgQAojNZTwJIn3WvwQflzlXUm6pjqdzTObaEYtAPcJog5k2aTWIa9UWh1_wJhmvhEV3KSqTqkMXPRGfItbT4d3YkAwx-QJ17hCsuOb7q7Bh0EggES8xggTqmd90Mbm5sDNjsUKrki&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-28","volume":""},{"id":4262,"author":"馬楠","title":"東周姓氏名字考釋二則","abstract":"（一）者■鐘&quot;者■鐘&quot;存世十三件,《殷周金文集成》著録號爲120-132。器主名舊釋&quot;者■&quot;,或釋&quot;者■&quot;&quot;者■&quot;①,所謂&quot;■&quot;&quot;■&quot;&quot;■&quot;字字形如下:■（《集成》122）右半似刀形,而刀形兩筆末端各有一頓點,可知右半是&quot;刅&quot;而非&quot;刀&quot;,字當隸定爲&quot;■&quot;,即西周晚期和春秋戰國文字常見的省去木旁的&quot;梁&quot;字②。&quot;者■&quot;當釋爲&quot;諸梁&quot;,楚國有葉","categories":["02_字词句考释"],"year":2014,"publication":"文史","link":"https://link.cnki.net/doi/10.19325/j.cnki.11-1678/k.2014.03.012","pages":"267-268","volume":""},{"id":4263,"author":"董文强","title":"西周青铜铭文书体风格探析","abstract":"西周青铜器铭文按书体风格特征分为早、中、晚三期,早期风格是对殷商晚期青铜铭文和甲骨风格的继承和发展;中期阶段西周青铜铭文艺术达到成熟,并体现出了明显特征;晚期青铜铭文书体走向了规范化和唯美化。三个阶段铭文风格特征的演变与西周的&quot;礼乐之制&quot;密不可分,开创了中国历史上金文书法的黄金时代。","categories":["02_字词句考释"],"year":2014,"publication":"名作欣赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIK6RGix59s70PkktdFxbjRMwak5Jks2TO99SqcuFomKtJOlL0E34EyFNhNyT0c67nocB4pqCCCZMQSpAlXBUbvb4QyfAeHJK_hVv7C6JRbhF7WUvaH-De4IipCxZXAgHY_3snP_IWdj2BR1xhqtE131a0OEn4NkW5pNHGFlMpqag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"168-170","volume":""},{"id":4265,"author":"郭永秉","title":"《春秋事语》(一至四章)新释文与注释","abstract":"本文根据《春秋事语》重新拼合整理的结果,在马王堆帛书整理小组和裘锡圭先生对该篇整理释读的基础上,写出新的释文和注释,以供研究《春秋事语》的学者参考。因篇幅所限,此次先发表的为第一至第四章内容。","categories":["02_字词句考释"],"year":2014,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_ipO3Nn1jzg82PZY1fqbDN3Ck0VekBBmeXV1thFifIcNALJxaaZTWxGOPZ00Clsc9k2i63XySPa8xNGzrAHMzwaeZPQrG0wZVsYNngCpO8101ocgUYt4R0F_YWyVAnLjDw8VeFbXxuyxXNGj7dKO87sFK8s3Hk0eUZ6x778yK2A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46036","volume":""},{"id":4267,"author":"刘彬徽","title":"“武王”戈及其铭文综考","abstract":"传世与出土的青铜兵器&quot;武王&quot;戈现已发现多件,关于对其国别有楚、秦两说。本文论其为战国时期楚国兵器,并对其铭文第五字提出新释。","categories":["02_字词句考释"],"year":2014,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_CBUNsgHh0RmEVJGkCWWwx4y25rr-HGCNxY_KuCFp86iiIyGvOipjeRfPbdhXVcI4H8leqxxjRKCmJIRycdDCRmxFQSu7_TYP3UdfW6t1IDUHbXR69GwStCUWPcqPVNBUvkaVQGVyQE4D48hLoMH4KcMzkAKHuLAtFop1CCIoXQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"154-157","volume":""},{"id":4268,"author":"时兵","title":"关于《合补》9264的文字与语言学分析","abstract":"《甲骨文合集补编》9264片包含有丰富的文字学及语言学信息,也一直为学术界所关注。本文着重探讨其中两个问题。一是&quot;其坩不■&quot;读作&quot;其不颾&quot;,其大意是指马之争强角逐而不能依次序奔驰。这充分反映了殷人在选择驾车所用马匹时特别重视它们之间的协调性。二是&quot;丿&quot;读作&quot;匹&quot;,用来称量&quot;配对马匹中的一个&quot;,这种用法来源于表&quot;匹配&quot;和&quot;同伴&quot;义的实词&quot;匹&quot;,其语义演变模式可以得到跨语言调查的支持。另外,&quot;匹&quot;字初文实乃从&quot","categories":["02_字词句考释"],"year":2014,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxAdypIsfbGFlV0cuVtSulHlIvD6qrAMOpGT_DTmi8rY7kmai7xqejJbAYM3KNxDUPEhTYekl1uYbIx7rrLWkwXlDyhYkznWSLYSs7iwCjWInEbdIgfVEQBdytvWQhrBdA25P3F03uXbvignzfDtWaJISPPb50DNwDcZg8HWMu5w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-69","volume":""},{"id":4270,"author":"郭永秉","title":"作册封鬲铭文拾遗","abstract":"作册封鬲有一对,现藏于中国国家博物馆。其铭文拓本最早由王冠英先生发表于《中国历史文物》2002年第2期,1后著录于《新收殷周青铜器铭文暨器影汇编》2和《商周金文资料通鉴》3(参看文末附图)。这两件鬲的铭文行款不同,文字内容上唯一的不同,是王冠英先生所定甲器铭文&quot;多易休&quot;一句,乙器作&quot;多休&quot;。王先生据乙器将本文所要讨论的相关铭文释读为&quot;王弗叚(暇)■(忘),享厥孙子,多休&quot;,并解释说:","categories":["02_字词句考释"],"year":2014,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfZdOy9Cxovk4wkUBneLCxTc0RqBY8TA0RgL8MtvSErK_5f9ua1qnGk_vvvqHmdS8LmOtlaSl1-CCwjaxUgqdAkWl6fwrU1oDZZjrhJjyk5y7QaGW3SBOTfWLAOxpdg75bu7TeTNqtlAbxoi8e1Fy8iSRdUq4cpO33rb5JZPMIuw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-79","volume":""},{"id":4271,"author":"牛新房","title":"金文“履”字补释","abstract":"应侯视工簋中有一从酉从履的字,学者释为&quot;醴&quot;,在大盂鼎中有一字与此同形,也应释为&quot;醴&quot;;此外还考释了金文中另一个被误释的&quot;履&quot;字。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUTp2YLkmnoSIN6ltjMBPyWMimBM-fNqxJLRdkmqPr1MzZFjPSf4LW92-WTWhbxym-3-NZqXksAYPEX7HTEo6SiD0WJVt3nN5NOb7TPnTbTFrDhwLxdeS1Y0peogLFkZcLqpSkoXMeNz-nME79VgQUpl66Dy8SPSES2pQcbm3AFg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-87","volume":""},{"id":4272,"author":"牛清波; 王保成; 陈世庆","title":"晋侯苏钟铭文集释","abstract":"本文汇集了晋侯苏钟的已有研究成果,并在此基础上对钟铭相关问题进行了探讨。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKltqlGa69MPpH1t-MzTShvvud3awlAcbPSj8ypE4qt6OzI28k_f8Rg6o4G55qcmyqhq8ffknVjZGudckbjqnNY8KTytBh1pztbPtPhuejpSOIScPgwq7jLQXS8FKml3fxem4x_Vy6b4zzNzbO8SHiXRhFVAc_MKJQI-pvg7WE2mw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-98","volume":""},{"id":4273,"author":"夏大兆","title":"“公”字补释及安陵地望","abstract":"黄德宽师认为纯釜铭文中的■是&quot;公&quot;字,本文重点从字形和语法的角度证实了这一观点的正确,并探讨了安陵的地望。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKI6C8VsoGSX8G_7-egucNiOpho2SiGOVzw1y9oJdh8wts9MzE1STFmVgCLnB7hTOu72PUU-8koH0hLGkh_rYMr1osDornF9iDZz7_id84AJ22g3GU2Ikxk0XJrxAMExXOyu5OcB_iPZO_HE07HHUZqIFCtkYyh0AOWJSFkdUyrOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108-113","volume":""},{"id":4274,"author":"张青松","title":"《正字通》疑难字考释八则","abstract":"文对《正字通》沟通有误或未予沟通而至今阙如的八个疑难字——?、■、伄、■、?、怴、■、懩——进行了考释,并纠正了古代辞书中的一些错误。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJSS8aYiublMSBFYuFmfT-sI_DzkU-sp4Z_dU-XFguTy3BZoif3DFCsiKw9jAnJKazuVah3_BR5zVwZ-wO2A7TaE1MPm8JnLnF_2tkZAet4TKEx_oqfQXofks2_PVhdNSj04GjHKWpLN96OMsusKKfLYJ3Z5QXc9vgYjkQfZV3CFg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"235-242","volume":""},{"id":4276,"author":"程江霞","title":"“青天”考释","abstract":"结合古代诗词和文献语料并参考辞书,对&quot;青天&quot;之&quot;青&quot;的意义提出新的看法:&quot;青天&quot;之&quot;青&quot;不表示蓝颜色,而是描述天空呈现出的状态。反映了古代人对天的视觉和心理意象,包括:高远辽阔、神秘静穆的神性特质,也包括清明透彻的世俗观念。","categories":["02_字词句考释"],"year":2014,"publication":"集美大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8MDAxrqHmPJWpcr2oXClGysOSkd8sc7ONqdbTF6EyA4KEyfvxyzdhf30sKV5xqDrIgN8qyGZ_cLn_hh6yfvj4xhXUidNFc-cdPx6DizI6W-_pTljac4PjiRxm5GAg4AKv_XZ2RrVQpCXCXqbgrrLBGGJayhsivZYZ_J1gHykstjFsefiJkIjY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-128","volume":"17"},{"id":4278,"author":"郭洪义","title":"《大唐愿力寺故瞻法师影塔之铭》释文校补","abstract":"《唐代墓志汇编续集》公布的《大唐愿力寺故瞻法师影塔之铭》释文错讹甚多,严重影响了对该通石刻的有效利用。释文中多处错讹之处通过校补,分析误因,可避免以讹传讹,使这份宝贵的材料得到更科学的利用。","categories":["02_字词句考释"],"year":2014,"publication":"宜宾学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJnXfHRm80Dgonj_JXJgTQ2Hm40tC-igaf24heIMzJhU7NSiOpymige-M77yqHLX2j6vI1HVDbgftTvIzg5zT9oS2votCPbTcHAEIMz54YwD_4K5hS0Wm3N016HYBQHPJwHKiWmY3vyGKAGeQ1PWDW6uSK6VQchjjOA8i4zclvK9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-98","volume":"14"},{"id":4280,"author":"魏文超; 李民","title":"“典”的两则史料辨正","abstract":"西周格伯簋铭文中记载的&quot;典&quot;与《后汉书·刘虞传》中记载的&quot;典当&quot;,分别是迄今发现的文献中最早出现的&quot;典&quot;与&quot;典当&quot;用语。一些学者认为,两则文献中的&quot;典&quot;与&quot;典当&quot;分别具有典卖与典当之义,也有一些学者持不同观点。至今尚无学者对此问题作充分的论证,所提出的观点缺乏令人信服的理据作支撑。通过考察典制的发生学意义,并结合两则文献的时代背景与其它史料作综合分析,不难看出,这两则文献记载的内容,均与典制无关,不能视为典制的早期运用。","categories":["02_字词句考释"],"year":2014,"publication":"阜阳师范学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.14096/j.cnki.cn34-1044/c.2014.04.027","pages":"94-97","volume":""},{"id":4285,"author":"贾作林","title":"“貯”、“賈”源流考","abstract":"&quot;貯&quot;、&quot;賈&quot;释读是当今训诂的一大难点。通过对战国、秦汉玺印和封泥的综合研究,认为前人在甲骨、金文中所厘定的&quot;貯&quot;、&quot;賈&quot;二字,实即&quot;&quot;字(音古,表储藏、交换)的两种不同写法,后者则是对原始社会的&quot;家&quot;之音义在商品、货币条件下的继承与发展。战国时期,商业发展终于把两种写法催生成了两个异体,以便分别承担储藏、交换之义,节约社会交往成本,而&quot;&quot;、&quot;貯&quot;、&quot;賈&quot;遂得以各各定型。援此为例,围绕&quot;&quot;之其他异","categories":["02_字词句考释"],"year":2014,"publication":"甘肃高师学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlzNJhXUQqX1BvKmcW-xrGSOa5M6iDKR3xJbATJHaPCGXHCgmsx9CJBbxhnhJGwUvikoi6k4n1BbdifRalkqT8t7SlKY8sO4wXQxQMWuELagJeytoBsDKOTN-aSg7R1WrxNXfe-us4FE4KiSEEMBpS5lfkrfz7V4b8dF5lmOJNgw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-41","volume":"19"},{"id":4286,"author":"闫华; 徐今","title":"唐子仲濒儿盘、匜“咸”字新解及铭文补释","abstract":"2001年湖北肖家河出土3件有铭铜器,器主是&quot;唐子仲濒儿&quot;,引起了学界对&quot;&quot;字的讨论,此字关涉到金文历日这个重要问题,比如&quot;月相四分说&quot;和&quot;月相定点说&quot;。现有成果对铭文中&quot;御&quot;字的解释亦有可商榷之处。文章研究表明:第一,从字形、文献、考古等多个角度论证,认为唐子仲濒儿盘、匜铭文中的&quot;&quot;是&quot;咸&quot;字,释为&quot;咸池&quot;。&quot;咸池&quot;是岁星纪年,岁在戊午,即为咸池,并考证做器年代可能为公元前602年。第二,铭文&quot;御盘&qu","categories":["02_字词句考释"],"year":2014,"publication":"大连理工大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19525/j.issn1008-407x.2014.03.024","pages":"133-136","volume":"35"},{"id":4294,"author":"齐冲","title":"附着形式“者”的逆形态化","abstract":"本文讨论的问题主要有两个:&quot;者&quot;的形态句法属性和&quot;者&quot;的历时演变机制。我们从形态句法、语义及韵律的角度,并尝试运用一些新的方法证明了&quot;者&quot;在现代汉语里的形态句法特征介于词缀和词根之间,为附着形式。通过对从西周金文到现代汉语的&quot;者&quot;字结构的实例分析,我们证明了&quot;者&quot;的形态句法发展路径。该研究结果显示:&quot;者&quot;的历时演变机制为&quot;逆形态化&quot;,也就是一个从词缀演变到附着形式的过程。","categories":["02_字词句考释"],"year":2014,"publication":"语言学论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKakXN5o6YuzBGCt-rj9VJRmepL-OpU_i23CB7E-O1hgwWbEnNb8JIaMwakAqZ32LoDbgiV_jjxpKQKD9ge-FIRaUpJLYcASZTHd5bi0qRsR9pBDAcVfu9RbXb2D6palcfKj_lInqq4Rjg-mnaSUI3madY7bfntJgrf3pON7D_Q1Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"186-208, 355","volume":""},{"id":4295,"author":"杨晓霞","title":"■羌鐘铭文考释","abstract":"■羌鐘是战国前期的一件重要彝器,其铭文记述了晋、齐之间的一次战役。文章旨在从字句方面入手解读这段铭文,以期为了解战国前期诸侯争霸中原提供一点史料,也为我们研究战国时期的语言、文字提供一些语料。","categories":["02_字词句考释"],"year":2014,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJprQ3EdG_wk__dDHn-vtGH1nNyxFwRBB4_Apugk_rLjL1cywjt9bX5oG-2fSoWEsXmF4trcG4WmdsybO9GEE5EaVucQFJihr9MW1L0zyVEzviWHXSKdCnnbMWDYJWIVcRQumky1jaqGCoHY1PeJhjEEqnnpT4NAFtAb50bWlCqstUM6EkJU2I2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-35","volume":""},{"id":4297,"author":"孙振兴","title":"西周金文中的司土司徒辨","abstract":"在西周金文中,&quot;司土&quot;&quot;司徒&quot;二词多次出现。&quot;司土&quot;在早、中、晚期均有出现,晚期之后不见。从金文内容看,司土可以作为中央政府的官员,也可作为某地主管,地方封国或采邑也有设置。&quot;司徒&quot;在中期才出现,晚期以后渐多。司土与司徒所管理事务有许多重合,但二者也有明显区别。从司土到司徒的转化,折射出西周统治方式的转变,其在文献中的体现,即宣王&quot;料民于太原&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2014.03.002","pages":"46277","volume":""},{"id":4298,"author":"石风","title":"《汉字发展史纲要》形声字发展说指瑕","abstract":"《汉字发展史纲要》在论证汉代形声字发展之时,对《说文解字》中部分汉字史料的时代缺乏考辨;对出土文献所用汉字与《说文解字》收录汉字的类型差别,未作区分;对出土文献中的汉字史料利用也不够充分,故而导致其书对形声字发展轨迹的描述不尽准确。《汉字发展史纲要》认为汉代是形声字大量产生的时期,根据近人的最新统计资料,形声字数量在战国时期就超过当时汉字总量的80%,形声字大量产生的时间,应该提前至战国时期。","categories":["02_字词句考释"],"year":2014,"publication":"商洛学院学报","link":"https://link.cnki.net/doi/10.13440/j.slxy.1674-0033.2014.03.017","pages":"78-81","volume":"28"},{"id":4302,"author":"张俊成","title":"公典盘铭补释","abstract":"文章通过对公典盘铭重新梳理认为该盘当为齐器,是齐国公典为嫁到邿国之女所作媵器。&quot;子姜首&quot;称谓,&quot;子&quot;当系美称,&quot;姜&quot;是姓,&quot;首&quot;是名,&quot;邿&quot;当为夫国国名。&quot;&quot;为动词,非连词,当训为&quot;往嫁&quot;。&quot;于终有卒&quot;表示在终老的时候能有所依靠。","categories":["02_字词句考释"],"year":2014,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3J8jlSHV08-Cwv5mgFhlOzePjBiFKRZZNA1fZv1P7WLpSRTP1KslX1xPHYcwPnFZIVYGZj3s50fFJ4XZeRzvV6iz5H20Qa5wFD-aiIDMFTs8usM0_XHhcWKOhzcMV0COCOOUPBXW7njfw1rWSoGwy2KWLVj-YYRJE3kP5I1rYMg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-108","volume":""},{"id":4305,"author":"譚生力; 李守奎","title":"楚文字形近、同形現象源流考","abstract":"在楚文字的研究過程當中，由於各種原因的存在，經常會發生一定的誤釋現象。其中，由於形近、同形所導致的誤釋現象較為嚴重。因此，在楚文字的研究過程當中必須對這些形近、同形現象加以關注。在以往的研究過程當中，有部分學者對楚文字中的形近、同形現象進行了一定的關注。但是，學者們僅僅是對個別現象加以關注，並未進行系統的研究與整理。近些年來，隨著相關材料的不斷公佈和研究力度的不斷加深，楚文字的考釋已經取得了較大的成就。在此種背景之下，有關楚文字形近、同形現象的系統整理與研究的條件逐漸成熟起來。鑒於此，我們將研究視角放在了楚文字中的形近、同形現象的系統整理與研究上。本論文主要分兩部分：上編為通論。首先對出土材料","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIEwDbODQBm8mXlMUbTG7RbEanEwtuZy08djtL4noM7zCOj_SHqhSGgggWmQabmBf7-0UejixmzxPElID3VzI1ii6xZIY45_U46GMM4IdmHP2zguWt8Hw70hXs7Y8-SBkF4hpUWZJOz5wC7JDiQ6vYh7x45k7VXwd9sK_PD2qvZwWkt5WOsqTop&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4308,"author":"马丽丽; 程鹏万","title":"先秦汉语介词“于”、“於”研究","abstract":"介词“于”、“於”是上古汉语中出现较早、使用频率较高、语法功能丰富的介词，但是二者的关系十分复杂，既可以并用，又有独特个性，因此很早就引起学术界的注意，但是研究角度不够全面，而且至今仍没有统一的认识，鉴于此，本文从内外因两个角度、结合传世文献和出土文献讨论影响介词“于”、“於”使用的因素，进而探究它们的本质关系。我们首先以时代为主线运用穷尽性统计的方法探究介词“于”、“於”在西周、春秋、战国时期的不同使用情况，发现西周时期是介词“于”的全盛时期、介词“於”的萌芽期，以使用介词“于”为主；春秋时期是介词“于”由盛转衰、介词“於”由弱转强的发展时期，仍以使用介词“于”为主；战国初期介词“于”、“於","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJXzdyMy_sSc-hBZBZrDhQHTK1qvJiq-CddekfrxBq7xvRVYwrwKQXf0p9SQhOme8F7EPlUFj1X-pqTk_UxJMNSQ5c7c9YvHzAnMv_qf5N_Yy-yqKt0xJQl514wspkMj_9SodDp-n5M_uIREm8rj47jS_VrYZWBglyuTHqD6dGx_Nja-E2qXBW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4311,"author":"郑彩凤; 柳建钰","title":"《玉篇校释》引用古文字材料之研究","abstract":"《玉篇校释》是著名文字学家胡吉宣先生毕生精力的结晶，它是第一部《玉篇》校勘注释著作，具有很高的学术价值。论文通过对《玉篇校释》运用古文字材料具体情况的研究，探讨了胡吉宣先生在利用古文字材料校释《玉篇》的体例、目的、贡献和不足。论文首先对《玉篇》进行了简单介绍，同时介绍胡吉宣先生和他的《玉篇校释》，对相关研究进行了汇总，并阐述了古文字定义，明确了论文所要研究的具体对象和研究方法。论文对《玉篇校释》中引用甲骨文、金文、古匋文、古钵文、石鼓文等材料的体例进行了详细数据统计，对引用古文字材料进行分析与归类，将引用古文字材料的目的归纳为六类，即言斯篆误、证许说误、疏解故训、保留意见、另立新说，以及单纯列","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjtFPAHVZIgnz6nTf9ue3ESpW67xtOntL40ZHOCW_oT8yreJBEzO-N7KdmvHEOAr18xx7cQ8kI0VLLHjqUKdrkCF0H5FXQfuUWrvw5lql86PwIIFSiYt8KKf0i9DNx13fBQxhN583tlKshYDO-hF_o4-G5KsFC3-xaHE3XTYfVOw8wqfNUY_VL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4312,"author":"陈亭亭; 李守奎","title":"古文字手形字構形與演變及相關闡釋","abstract":"“手”以其與生俱來的重要性在漢字的發展演變中留下了不可磨滅的印記。對各個時期，不同地域古文字中與“手”有關的字形（我們以下稱其爲“手形字”）進行貫通性地梳理，有助于我们瞭解古文字形體的發展演變。本文對“又”及由“又”構成的漢字在各個時期的構形與演變情況詳加探尋，並對“史”、“事”、“吏”和“使”之間關係以及分化情況進行詳盡研究。本文共有三部份，第一部份為緒論，主要介紹了本文的選題目的、研究現狀并簡要闡述了論文寫作中所使用的相關概念；第二部份為“又”及由“又”所構字的構形與演變，這一部份又分為四小節，主要是分析了相關手形字的構形與演變情況，並對“又”在漢字發展演變過程中的功能以及出現的訛變和與其","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJTaa7VeV-8jP5uUV3HkEeQa5L18TK_POA5nfbpfey2lECESMQssUU2Yh8_UtKiMmxx1ECLQygr5MAXt91-jOzfVMojMEnRicM3ajBXqRM11v5r-AW6sgp5eJInVnHbFso0p1WOO1ICbXTDWsbtybjD7eNg4h5Oc3N2IS4zk8UltB7-wyezSlzJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4314,"author":"王永昌; 李守奎","title":"古文字中从“酉”之字的构形与流变","abstract":"古文字構形理論的研究應當建立在對古文字字形資料進行充分地、精確地構形分析的基礎上，不僅要對同一歷史時期的字形資料進行分析，還要從歷時的角度，對同一個字的字形演變進行分析，這樣得出的構形理論才是全面的、準確的。构形理论不僅能夠真實反映漢字發展的歷史規律，而且還有利於漢字理論研究的進一步深入。本文本著“大處著眼、小處著手”的思想，選取古文字中的從“酉”之字為研究對象，廣泛搜集從商代甲骨文到漢代銅器銘文、簡牘文字中的諸多從“酉”之字，對其構形及字形流變逐一進行分析。此外，文字是記錄語言的符號，本文對諸多從“酉”之字在具體辭例中所記錄的詞義也進行了分析和整理。","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKyRirOxheom1aA5oPJ6rhpCp5G6921abx8UxrEYExlZXUvJOaPj4Ax3X1MmV3nQ4J7aotsgisiMvYPHg4UWKGiM-HuF1mYEZZHFuSb8dnVzAPvGZ-y5mgT0TATi2ts5leLBPrTKGkAtmIey9CAmTjhRjRMH3LXDsXuG02RJX40cNrpqzY7K5vR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4316,"author":"陶曲勇","title":"《金文编》中字头与字形关系探析——兼论文字编的相关问题","abstract":"《金文编》中字头与字形的关系,可以分为两类,一是字头与字形一致,一是字头与字形不一致。第一类包括三种情况:一是字头与其下的字形形音义皆同,二是字形与见于《说文》的重文同形,这其中又包括异体字、假借字和同义换读字,三是字头与其下的字形为同形字关系。第二类则分为三种类型,即异构字、分别字和假借字。《金文编》对上述各种关系的处理方式有些较为合理,有些则有待商榷,反映出来的问题在其他文字编上也时常可见。","categories":["02_字词句考释"],"year":2014,"publication":"励耘语言学刊","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2014.01.017","pages":"260-269","volume":""},{"id":4318,"author":"李蘇和; 劉釗","title":"秦文字構形研究","abstract":"本論文所研究的“秦文字”,包括西周晚期至戰國時代的秦國,以及秦代的各種載體上的文字资料。上世紀七十年代以來,大批秦文字資料相繼出土,為我們對秦文字進行深入研究提供了便利的條件。本論文主要内容如下：首先,在緒論中介紹了研究目的、意義、範圍和方法,然後對相關研究進行了回顧和綜述。第一章是“秦文字的源流與演變相關問题探討”。在這一章中探討了“秦文字的源流”、“秦文字發展中的隸變、草化”、“書同文字”、“秦文字和《說文》的問題”、“傳世文獻保存的秦異體字”等問題。通過全面地梳理迄今發表的秦文字材料,來綜觀秦文字發展史。在第二、第三章中,分別討論“與音義無關的秦文字異化現象”、“與音義有關的秦文字異化現","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJYMqVSlsHZpWcOs06N2x94_Du374Lsux6-EwNtJQhRwK3sxhEBRc6RJJelvQPWYJLTtqtnpXJd3Vvb6PFc5onCWtbZhV3xpZJjCyKgLIC0_nmCnL3vYdU0NSjn_ehvIi4_CjB5hyO3ZukZExKR7TW0_6jMOji5WfCg3erQBCQXMoXdsrZdo5SR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4319,"author":"郭理遠; 郭永秉","title":"《張政烺批注&lt;兩周金文辭大系考釋&gt;》的重新整理與初步研究","abstract":"《張政烺批注<兩周金文辭大系考釋>》是張政烺先生在長達半個世紀的時間里,對郭沫若《兩周金文辭大系考釋》一書所作的批注。朱鳳瀚等學者通過兩年的整理,將批注的整理本和原書影印圖版共同呈現給了學術界。這些作為私人讀書筆記與心得的批注具有十分重要的學術價值,但是原整理本在文本錄入、分條歸類、標點斷句、闡釋說解等方面存在一些錯誤之處。因此本文對批注作了重新整理,並進行了初步研究。本文内容分為兩部分。“上編”分類概述了整理本的失誤並簡要介紹了批注的學術價值。整理本的失誤之處大體分為以下幾類:第一,對原稿内容移錄的錯誤;第二,對同一條目下批注排序的錯誤:第三,對個別批注分條歸類的不當;第四,標點、斷句的失誤","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4s7fvCSQz9xM3xl87gHuaWcIoyzQqR6L5059IXvzCp18syYGC79XGtL0kwP3nU9Bda-JaFon3To1oJ4yf2Yj8EtGXYeccq_HZhrumblhTaMkMsGMfR-afuxDLu52ll0NC2WnQq3mN8woeM5wi88JvgxUOyvFUS0HakoAtqLREMjY1bDBQH4nI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4320,"author":"蘇影; 董蓮池","title":"山東出土金文整理與研究（上）","abstract":"宋代以來,山東省出土了大量商周至戰國的金文,形體十分豐富。我们利用新材料,吸收新成果,封山東出土的金文做了全面系统的整理和研究,以填補從文字學角度研究山東出土金文的空白,徙而改變山東金文字形全编無、偏旁分域研究無、释文鳌正燕、一些疑鞋字的考释没有的局面。本文主要包括四方面内容：第一,首次撤底地清理了宋代以來山東出土商周至戟國末期的铜器铭文,計六百餘件。全面地著缘這些銅器的器影、時代、出土、铭文拓片等方面的信息,釐正以往错误的释文,同畴封疑難形體作了必要的註释。第二,首次祥盡地考論了山東出土金文中的85個重要偏旁。统計出這些偏旁出现的频率,描寫出這些偏旁出现的畴代、地域的分怖和演變的规律,揭示出","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQt5jL7w9BJcxUGsS_avbueF0gOeH7_F7GULIWgk0DMLgKPo0Ps_lnfopX_gFqdX5Snir_AP-0PUbzcaXf0iYJKumis_4kXx5C2iS6_mj8LR9hJdbx9viRkUsDvIBSdqQzwFPa59oA7pT8NcWsM9rmNFtypbUzi9jeXv0eRWPNsJZygqreCufO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4324,"author":"苏少敏; 李冬鸽","title":"汉代铜器铭文构形系统研究","abstract":"本论文研究课题为汉代铜器铭文构形系统，全文以王宁的汉字构形学理论以及相关的汉字基础理论研究成果为指导，以徐正考《汉代铜器铭文文字编》为取材对象，借助计算机技术，合理运用综合分析比较、计算机量化处理等科学方法，对该字编所收录的汉代铭文从构形、理据等方面进行系统性总结。本论文尝试对汉代铭文从构件、理据度、构形模式、组合方式等方面进行全面分析，微观上具体分析到每一个单字主形，宏观上总结汉代铜器铭文的构形特征，并与不同文字进行比较，为研究汉字从古文字到今文字转变演化的进程提供材料。论文分为六部分：第一部分绪论，主要对选题的意义与可行性进行论证，综合描述汉字构形系统以及汉代铭文的研究现状，并说明本论文的","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9VOO7wKX6n9xubFZQh-E5R00ESJvhrgvOCTyc9BOAUZFaaafCq8M6xHqgxK4kc_xlqcn5OmF9FmdVCUtaU2SEyJnrHlua-hkGnvYLx9c_Ty7Zw8eEZU2G4W3FYF2r_YwCF6vTCPqtgX_UndVawCyqkQyIWHtgzHOPxJREkbC84wPtc0ubviEu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4327,"author":"苏影; 王征","title":"释渔阳铍铭中的“(齊阝)”","abstract":"战国早期燕国兵器渔阳铍&quot;马&quot;下一字,一直被误释为&quot;命&quot;。文章从字形上运用偏旁分析的方法论证了这个形体是从齐从邑的&quot;(齊阝)&quot;,当&quot;齐&quot;之异体字。","categories":["02_字词句考释"],"year":2014,"publication":"哈尔滨学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJwH_Cja_QRbUgIWEWN6R7p11X_l-5quWiT5Gx7Rf-JsOtshJWrFB84UKsc0GUxbZq5dUveOutD97PpyBtDRP2QvlyiFDKoMPNVEcyGfP7k6B3Kj5gCKvozhzd3r33VT05HxTlDssTDs6uPu_M9kE1h1OuuinsjuAkDWFOyHsp7hA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-80","volume":"35"},{"id":4328,"author":"黄国辉","title":"商周亲属称谓的演变及其比较研究","abstract":"商周亲属称谓的演变及其比较研究是商周家族制度研究中的重要内容。本文对甲骨、金文所见祖、妣、父、母、子等亲属称谓作了详细考证。在此基础上,大致勾勒出这些亲属称谓在商周之际的演变历程,并对这些亲属称谓在商周社会中的含义进行了比较研究,考察异同,分析原因。还进一步就商周亲属称谓制的类型、意义,及其与商周社会结构、文化的关系等诸多问题作了探讨,由此亦可窥见商周文明之间的传","categories":["02_字词句考释"],"year":2014,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLLVjl4Z6j7h1oEmiq3QTMSv2rLBkPlvKs5lfHO7K0MHUO1T3eWVBEGTyP82XcsHQMpgkPOstnSOdFPvaZoaS_1CISLwTEHPMbF5aDcL84RZTz9OW1tCXV-AmnnQcatzL9sJchzTh7K3uxId0FqRb293eA7GL7sLWow6YB0vUIC1Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-62","volume":""},{"id":4329,"author":"武振玉","title":"西周金文中的抽象名词","abstract":"西周金文中凡有56个抽象名词,据词义相关性可归纳概括为福禄类、生命类、天命天神类、休咎类、社会礼制类五大类别。从出现频率看,西周金文中抽象名词的个体数量已颇为可观,但除个别词外,出现频率普遍不高。时间分布则以西周晚期居多,大体可知此类名词出现偏晚。组合方面,此类名词普遍前有修饰语,或为形容性成分,或为指代性成分,或为两者的叠加形式。句法功能方面,此类名词基本都出现于宾语部分,其前动词或为祈求义类,或为赐予义类,或为称颂义类,或为遵循义类,或为治理义类,均与各类名词的词义密切相关。从语言反映文化的角度,西周金文抽象名词的梳理亦有助于从一个侧面窥探西周时期的社会价值观。","categories":["02_字词句考释"],"year":2014,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2014.03.005","pages":"41-46","volume":"54"},{"id":4330,"author":"黄锦前","title":"有儿簋释读及相关问题","abstract":"本文主要讨论河南上蔡郭庄王金鼎1号春秋楚墓出土有儿簋铭文中&quot;洹&quot;字读法及相关问题。簋之时代,从其铭文字体和有关辞例,同出铜器、陶器等看,似以定在春秋晚期前段为宜,而非春秋早期。从文字学的角度来看,目前所见两周金文中&quot;桓&quot;字,或写作&quot;■&quot;、&quot;■&quot;,而未见有写作&quot;洹&quot;者。相反,金文和楚简中却有&quot;宣&quot;写作&quot;洹&quot;的例证。因此,将&quot;洹&quot;读作&quot;桓&quot;,谓&quot;陈洹公&quot;即&quot;陈桓公&quot;,不当,应读为&","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvSHAhWr2DQ0JbB4Qb6qx7Zttb5tUhpftoIP47R1mlP2IVyVof5xjlazmUCSRiAorRpFkoTtT_um7XXNx4uz-EF7AjYRXnFgh2xY3-e3J6CqTLLWTvCP64eYNBz1C0rnfmPliHTZtU_9pKVDNdJ0XFS_ynX6wHE6t3e3Zlb7mfUA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-63","volume":""},{"id":4331,"author":"乐游","title":"配儿钩鑃铭文新考","abstract":"20世纪70年代绍兴出土了两件有铭东周青铜乐器&quot;配儿钩鑃&quot;,其铭文残损较严重,铭中第二行中有旧释&quot;冢&quot;或&quot;犬&quot;之残字,实际应为&quot;元&quot;字残划。此字与下文连读为&quot;元子&quot;,这里应是一种美称,而并非嫡长子之意。第二行残存的&quot;余&quot;形笔划,本应属某左右结构文字的右半或右上部分,从各方面迹象分析,原字左半当是&quot;邑&quot;旁,是徐国的国名用字。东周时期南方青铜器中&quot;元子&quot;的称谓和人名加&quot;儿&quot;现象等用语用字特征,是有一定分布规律的。&quo","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHoL1F-p2i_LEIUhUm8pCx2XXs-uiFU2yrR6YPZ6rHmwfitL-eesK2s9-RDU9V_Y8VBrFfUByPyh4r47NY_E5TubXPjouDHYYbuzzBoy74amPvyVI_gtqfxogzDzCahtsVWMk9ft8wuVdalkgMVG36pp0e2FsczKcfU2rHUP2h2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-70","volume":""},{"id":4332,"author":"龚军","title":"翼城大河口墓地出土鸟形盉铭文与西周法律","abstract":"本文在前人研究基础上,通过对鸟形盉铭文的重新考释,尤其是铭文中出现的西周时期相关法律用语&quot;誓&quot;、&quot;鞭&quot;、&quot;笰传出&quot;、&quot;出弃&quot;等词,与已出土的金文进行比对研究,有助于对西周时期法律制度中的&quot;鞭刑&quot;、&quot;流放刑&quot;作进一步的探讨。此外,铭文中两次出现&quot;誓&quot;字,将铭文中的&quot;誓&quot;和已出土金文资料进行比较、归纳、研究,&quot;誓&quot;在西周时期的诉讼、审判等领域曾被广泛使用,表明&quot;誓&quot;在此一时期具有较强的法律意义和法律约","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLyPwze663qJtSqMO-nWooxUhQSMLx6-JBu_YKEWmnD49eGfXTG-iZ6fAQMzygEipOMGchO7ZN7VMRuQMPKVb5EzKFWaK5GzFk5GEepowhY7ciqZfYFc2BHz-PGRXeHKBPKm-OQO5ftRoZ7zT7eA130wfQpo_8_vb1_LIq698AwEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-77","volume":""},{"id":4333,"author":"黄杰","title":"疑尊、疑卣及“栗成左”戈铭文补释","abstract":"疑尊、疑卣铭文开头人的名号应释为&quot;中義子父&quot;,金文中偶尔有这种&quot;伯&quot;、&quot;仲&quot;、&quot;叔&quot;、&quot;季&quot;与&quot;父&quot;之间有二字的名号。疑尊器底铭文第一行&quot;于&quot;下的字应依李学勤先生释为&quot;卜&quot;,其写法与甲骨文中部分&quot;卜&quot;字相同,这可能与器主是西周早期商遗民有关。&quot;卜鄂侯于盩城&quot;,即通过占卜的方式让鄂侯到盩城建都。铭文第二行的■字,释读尚需进一步探讨。《记一件新见铭文铜戈》公布的齐国铜戈,铭文第一字当释为&quot;栗","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZI9up1R4TewAOy0DvlBusf6pX-EDORA7NXNWRUjQh9lIkoPLoY_sVZLtgSDD6dJXFCuUkWeDLQCKEYSq89BD9PEN_xoMwOD0m3MsVX59Nd4TQuIgkLfEnYWpt53HykwPZzGW-NI0D8jJt5y58iplDo_haw5CVKzb1By7Zqwvk-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-82","volume":""},{"id":4335,"author":"张巧玲","title":"古文字形体与上古刑罚","abstract":"中国古代严刑苛法,在古文字中得到真实反映。本文对现有甲骨文、金文等古文字材料中出现的反映上古时期残酷刑罚的字形作归总和梳理,并从中窥见古人某些思维方式。","categories":["02_字词句考释"],"year":2014,"publication":"企业导报","link":"https://link.cnki.net/doi/10.19354/j.cnki.42-1616/f.2014.10.127","pages":"188, 185","volume":""},{"id":4336,"author":"余群","title":"“樂”本义辨正","abstract":"对于&quot;樂&quot;字的解释,自罗振玉否定许慎之说以后,各种观点层出不穷。许氏与罗氏的根本区别在于,许慎用金文,从鼓悬于簴的象形来解释&quot;■&quot;字,而罗振玉则用甲骨文,从琴瑟附于木来解释&quot;■&quot;字。两相比较可知,许氏的解说不仅符合&quot;乐悬&quot;实际,也与乐器发展历程、重要程度及文字发展阶段相吻合。罗氏的解释不仅不符合甲骨文含义,也与乐器发展时代不相对应。罗氏以后的学者也都存在各自的误区。","categories":["02_字词句考释"],"year":2014,"publication":"宁波大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLsPvff9BU0mJILOUaJ1ViCVgNKhDdgDx_BJfAYxU2ZY96cihSsKNXWYuHgegkErnadEAhguKoJwAZOw1qTml5Yvkjj7ZYRvvnD0_b7axH2YAXFtB3YWJ4Gp47B-YqgylegqxTzXQFrjyGNeZzJcEW9VZQeMCuLeNvDobqgnzp3EA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46278","volume":"27"},{"id":4337,"author":"冯胜利","title":"语体俗、正、典三分的历史见证:风、雅、颂","abstract":"在近年的语体研究中,通俗、正式、庄典三个范畴被看做是用语言来确定和调节人类直接交际关系的最基本的手段。文章认为,当把这种语体理论用于历史语言的研究时,可以发现先秦《诗经》中的风、雅、颂,恰好可以作为共时语体俗、正、典三分体系的历史见证。","categories":["02_字词句考释"],"year":2014,"publication":"语文研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPHP3ThV_3dOyMNNCxXsufNe8Rtu6m4ZO6BQsjlH7NZWMoWy3wsXutIxXs9C90EY8HNZU-e91JOwoTjwSuWg7xbimEQm6VRCRZOg9EUncjujECgN0r_vzAksM1yhQGG3yB2ezzbbqAysknt1ehVCZrABKuIjcKNFn-lSgdESjGzg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46032","volume":""},{"id":4340,"author":"谭飞","title":"罗振玉“由金文以窥书契”的考释方法","abstract":"罗振玉的《增订殷虚书契考释》是甲骨文研究史上里程碑式的杰作。该书立有560个字头,利用金文的字头有187个,一共引述金文293条次,其中仅言古金文或器物未摹字形者就有69条次,涉及到760个甲骨文形体的考释。罗振玉利用金文考释甲骨文的方法主要有:以金文偏旁或单字证甲骨文、利用金文通律证甲骨文、金文篆文比较以证甲骨文等。罗振玉在考释的同时,还通过甲金文的相互比照,探讨了文字发展演变中的分化、简化、繁化、讹变等现象,追溯了文字的初形初义,纠正了前人的一些错误。","categories":["02_字词句考释"],"year":2014,"publication":"西华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19642/j.issn.1672-8505.2014.03.004","pages":"17-24","volume":"33"},{"id":4341,"author":"徐豔利; 喻遂生","title":"《殷墟小屯村中村南甲骨》整理及文字研究","abstract":"甲骨文自發现至今已經有115年的歷史了,其研究已经形成了一門獨立成熟的學科即甲骨學。2012年4月《殷墟小屯村中村南甲骨》一害出版,為語言文字及甲骨學的研究提供了新的研究材料。這批甲骨是1986年與1989年在小屯村中以及2002年與2004年在小屯村南發掘所得,害中著錄甲骨(連同附錄)共531號,包括自组、賓组、歷组、出组、無名组、午组、黄组等卜辭。時間上從武丁時期跨至帝乙、帝辛時期,约250多年；内容上出現了新的祭祀封象、人名、地名,新的有關卜辭文例、經濟、戰爭、農業等方面的内容。對這批新公怖的材料進行整理與研究是必要而且有實隙意義的。本文封這批新材料作初步整理舆文字研究,输文共分四章。第","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZvH-K3FtJvaglLuN8VyxJ70LzrGHqBMGUpdOraT2T8YiYLXD2A7IfTCs5Of0C0_qMt41a1nXcqirue_mhvXlTgHGJi7Vg4OZP34yfxK2ZcfHnqXVp9hFijA2UJiDbWxi3PKP5mqrjB0Y5UPibcRCH6quS50ZqXnX8jg2tjlr0TirbzcDInn-G&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4347,"author":"彭瑾; 周言","title":"周代媵器试论","abstract":"媵器是古人为嫁女而作的青铜礼器。“媵”在文献典籍中的意义是“相送”。它在青铜器铭文中有多种异体字写法,其中以“朕”“媵”“塍”的出现频率最高,这可能说明当时嫁女时流行陪嫁宝物或土地。“媵”字在铭文中可用作表示目的的动词,也可用作表示用途的形容词。媵器的发展与衰落伴随着媵婚制的兴盛和衰落。媵婚制盛行的主要原因一是为了巩固嫡妻地位,增强血缘集团的后备力量；二是为了扩大政治联盟范围；三是为了维护家庭团结与稳定。春秋末年战国初期,由于宗法制的崩溃以及国际形势的制约,媵婚制逐渐消亡,媵器也随之减少直至消失。媵器根据铭文中有无“媵”字可分为狭义的媵器和广义的媵器。判断广义的媵器的性质可根据作器者与被媵者关","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjUo_fGRbLqLAmMgRBTYGDPgwJ36VdI2ZxCK3xe8qR0QWjbz-rDO4umx7razfMo6nvXPUCANYWnVBMv5q5UvtAwkcwBFl9F0dgYE7BRqPJxeVopDV__g6Kr9VJL9ydUY0DbplpQYa2BXtytyeOfwB6kD8tCl8SZyV0RJyDuP4SeUfWsyZtbM0s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4348,"author":"谢祎明; 王功龙","title":"王筠“分别文”与“累增字”研究","abstract":"清代的汉字学思想极度繁荣，也因此造就了成就斐然的“说文四大家”，即段玉裁、桂馥、朱骏声、王筠。其中，王筠著述宏富，并在其著作中系统阐述自己独特的文字学观点，促进了《说文》学的发展。本文以王筠提出的“分别文”与“累增字”为研究对象，从基本概念出发，结合具体例子，探讨二者的实质，运用比较分析法，把“分别文”、“累增字”与古今字区别开来，开拓学术视野。在行文中，不仅研究了字与字之间的关系，更做到了由点及面、由浅入深，由对字的研究上升到对文字学思想的认识，在逐步分析中，系统地总结了王筠的文字学思想，并灵活运用他的文字学理论去解决一些学术问题。本文绪论部分介绍了王筠及其对于《说文》学的主要贡献；第一章则","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIRFAgFrHdZihW2EsPHuamClvyPBUUGFclEHJGwSLrHYMb9WJcUR7oaqNCnXwdErsGkcBB31u-1C5trXP9cnaHuwDKBQlDjjSrXvGIYOD0crHQYccFvyL05tLag6P-NZL6hhQbyUeD6zRCc0RRaE4WgWe0vO__FgHS_ry5x4gnSg3k7duwOqe2s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4350,"author":"陈超; 程鹏万","title":"先秦汉语第一人称代词研究综述","abstract":"先秦时期，人称代词繁复，常见的有“我”“吾”“余（予）”“朕”“卬”“台”六个，这些人称代词是语法研究中的热门，越来越受到学者的重视。学者们从多个角度对先秦时期的人称代词进行了专门的研究，并取得了一些成果。本文力图在这些研究的基础上，通过对出土文献与传世文献中人称代词使用情况的对比、分析，讨论先秦第一人称代词的使用情况、句法功能、称数问题、感情色彩、使用时间等问题，以期对先秦汉语第一人称代词有较全面的认识。本文共分为六个部分。第一部分是引言，主要介绍了现阶段学者们对第一人称代词研究的成果，说明本论题研究的意义，并对本文的研究方法也进行了说明。文章的主体部分为第一章至第四章，第一章探讨了先秦汉语","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJR54biO5ZaJKCpNdKEpdL9J2WgBKow9L0V6AK74Xc4KmQOqZqsOytV89lnzyJ92TRvXgkMGSOxAg0ZQFBre6ZkOeCFSaBVKh0RYDIbTyUmOwFydjA8qlvB2pppCq7RLy1HAuXaYbqCtJS4L_HsP1SGpmGbBiNEiknc1SAAD6wo7wm0Xn6FHmUm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4353,"author":"盧瑩; 雷黎明","title":"考古學視野下的《儀禮》飲食器匯考","abstract":"《仪礼》一书是三礼中成书最早的著作,其内容广泛反映了先秦时期的祭祀礼制及社会生活,且该书对我们了解先秦时期的服饰、日常生活用具、饮食食材、饮食器具等都有很大帮助。本文选取《仪礼》中的饮食器具名物词作为研究对象,共四十九个,将这些名物词分为炊器、食器、承器、酒器四大类,并在考古学视野下结合考古出土材料对这些器皿的功用、形制及器形沿革进行详细的介绍,对若干尚末得到考证又无出土材料可查的器皿,则总结国内外学者的研究成果,当试提出自己的观点。文章的最後一章按这些器皿在现代的流变状况进行重新分类,共计五类,并在此基础上分析《仪礼》饮食器在现代社会的存现状况及一些器具在历史长河中被赋予的文化意义。","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBlq7d4oW4thtPE8lResxoHldjbjOt322c1mdB-v0EiALHUfB-lNDh7-H-dH1eCabWL0JlShK5x-a7aIBrZuKGgzb_cFiKYWeMxdCz8hxFxIkBzzaD1D5BMeLt4I_p8Hp8_mXKDDfOneDf5kHpiCIjU3Wdlqva-yVulWe83R1z2rvLHiaXIGL-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4354,"author":"王杨军; 雷黎明","title":"《詩經》色彩詞研究","abstract":"《詩經》中有色彩詞或與顏色有關的詞約两百例，涉足近八十篇詩歌。由於年代的遙遠，《詩經》時期的色彩詞的詞義，以及它所承載的文化情感，與今天的色彩詞並不都一致。做好《詩經》色彩詞的考釋工作，無疑對真實還原先秦時期的色彩具有重要意義。全文除緒論外，主要分為三個部分。第一部分首先對《詩經》的色彩描寫進行剖析，從其最鮮明的四個特點來談論詩歌文本：色彩的豐富性、色源的廣泛性、物色相融、近色聯想。第二部分是本論文的重要章節，對《詩經》三百零五篇詩歌中出現的四十個色彩詞進行研究。一般一個色彩詞的釋讀都經過以下的工序：羅列該詞的所有詞例；結合其他同期文獻的該詞詞例，參考古文字字形，探討其本義以及最初的色彩意義；","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInFnm_Hns6j90Q4TM59CPJk9b_GWtdM4gUnTqYJtRqjyfJfiB-7OzY71juUi6-lRe6Hjcwic6kUyMNzxiDkOZqkTKsKBE79RrtLoc0uQ-llU3ej03SWvYxO0kb-YlYIU-MRmUjov58McG4G3-ZTHOqTHYLYOUkqnQDl_UhvO7jWNasGXM8zNZy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4355,"author":"徐超; 胡長春","title":"吳越兵器銘整理與研究","abstract":"吴越地区指长江下游地区，地处江南水乡，相当于今天的江苏、浙江、上海和安徽南部及江西东北部。春秋时期，该地区崛起了吴、越两个强国，两国征战数十年，与其他国家也有过不少的战争。吴越兵器铭文作为记载当时历史的资料，其价值不容小觎。近年来，随著考古事业的发展以及古董市场的活跃，很多吴越兵器显现出来，这些材料对於研究吴越历史和文化有重要的意义，但目前这些兵器材料比较零散，没有作统一整理。本文在前人研究的基础上，将吴越地区兵器材料汇集在一起，作初步的整理与研究。本文第一章为前言部分，主要介绍吴越兵器的研究现状，研究意义及方法。第二章是正文主体部分，主要是对吴越兵器资料的汇编，包括戈(戟)30件、剑99件、","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCBoAkDyLYJT0RrnUEu4Tn1GB_gkoW0gAlIF43LDRcwUmHyFR61SJOfttKgaLJnk1f21M1M3ligVe_qNWAvK5Q8KTiXqLN0G_ewp3lpnU0yv7OOwS9J2KweVcm7ZynQwtAHGkLHoS-IN_fQebfNy5n8-ODPg-PRwChXRRe_viXx1UKfCx5tkNh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4357,"author":"尤苗苗; 王洪涌","title":"楚地出土战国简册器物类词汇研究","abstract":"楚地出土战国简册是研究战国时期器物类词的重要资料,比之传世文献,其所载器物类词愈能反映当时器物的具体面貌。本论文以楚地出土的包山、郭店、望山(2批)、九店(2批)、曹家岗、曾侯乙、长台关、葛陵、五里牌、仰天湖、杨家湾、夕阳坡共十四种简作为研究材料,以它们所载卜筮、文书、日书、遣策等记录性文章为研究重点,将器物类词分为食器类词、酒器类词、水器类词、佩器类词、乐器类词、案几类词、兵器类词等,对楚地出土战国简册所载的器物类词进行研究。全文正文分为五个部分：第一部分为引言。介绍本文所选取的楚地出土战国简册的发现及相关概念界定,论述楚地出土战国简册器物类词的研究现状及研究意义,阐述本文研究所采取的计量法","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeyhNgn-JVeoxboy4hKIw-WFTb0f4Y5fVu_hYmF77xbTT04t57vtPyjKKNvVrYMnGtbqqJ1uaCin5URspreaVWnd6GIqccEKVDPKXnPFQ-f-9yTSPazbU9ucd1vWmrnw9ljLY5KMeFzZYfP42KetvMTTyBpaB0TrT6AetexE377C6laKgXeqGB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4358,"author":"石偉; 胡長春","title":"《殷周金文集成》鐘鎛類銘文校釋","abstract":"樂器铭文是铜器铭文中的一个重要类别,在古文字研究中估有重要地位。本文主要是封《殷周金文集成》(修订增補本)所收录的358件青铜锺鎛铭文做的一佃较为全面的校释。首先,参照《殷周金文集成引得》、《殷周金文集成释文》、《金文引得》、《商周青铜器铭文选》、《商周青铜器铭文暨圖像集成》,标出異文。其次,论文编排方面,按时代先後,将358器分为西周器舆春秋战国器雨类。西周器分为中期、中晚期、晚期三部份,所属王世附於器物之下；春秋戟国器按其所属方国歸於每一類之下。铭文校释方面,在全面吸收學衍界最新研究成果的基礎上,對各器铭文——校释。存在爭議之處,能做出判断者則擇善而從,不能做出判断者則詳列諸家之说,無法释","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUnfaz4VOgDJ0IHj1XFd_DPHV0C8dndW8ukpQOHNwYvG8sC_nhR2Hw1ku7iU8m8OMPrO8IjykKoMiixN-kn83M-6cgiZ88urCELm3A-8Bb8XGGqRTS8i2iX_Ho4uWFhR6ZWnM_6QYQUa7i5SO_7R3hNoDkuTGW6LxHAegDunegzmy8jShObm55&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4360,"author":"吴立业; 陈双新","title":"金文特殊书写形式铭文研究","abstract":"古文字研究应该立足于古文字本体既字形的研究，本文通过对《殷周金文集成》修订增补本中的特殊书写形式进行详尽的研究，统计其中鼎、鐘、簋、盨、鬲、鎛、鑃等类青铜器铭文中出现的特殊书写形式的种类、数量、频率、分布情况，并分析其规律和成因。文中所述的特殊书写形式，不仅包括字形整体的特殊书写还包括部分字形的特殊书写。文章从第二章开始详细分析特殊书写形式，主要是倒书、反书两类特殊书写形式，其中倒书分为全体倒书和部分倒书，反书分为全体反书和部分反书。第三章主要针对构件而言，对字形内部构件的特殊书写形式给予分类和解释，构件特殊书写形式主要分为构件位移，构件缺失，构件增加，构件讹混,并具体分析说明，此外还对异文现","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmiy5XZcJNBBHTseOs_09_LarcHnhf6mUXZghtG5BtjZft1-AVbItNUZ4ZSSNsRR5Twmjr7p2B6icg7EHmNpsAKIAx-x4ggAJMUICNHL_FMice8lnLQkv54Zxa1fB84Ef57LkQ_k5KV9EdbIIJao1X_ZTFVMgATPJWcqOFGwRtQ6CTr_4eR_Ah&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4365,"author":"颜敏玉; 董莲池","title":"战国前期楚系兵器铭文集释笺证","abstract":"本文是对战国前期楚系兵器铭文考释成果造行的集释和笺证。战国前期的楚疆域广阔、实力强盛,制造了大量铭文精美的青铜兵器。和礼器不同,兵器的铭文内容多记录人名、地名、官职,涉及古代历史的军事、地理、制度等方面。学界对这些铭文的关注已有多年,成果较为丰富,只是诸多文章的发表相当分散,(?)位学者的看法又差異颇大,而且至今未有人做遇成系统的整理研究。有鑑於此,本文位可能全面地蒐集了目前所能见到的战国前期或疑似战国前期的楚系兵器,以器为单位整理得到四十九条铭文,而后对每一条從十一个方面造行研究：先标明“器名”、“著录”、“出土时地”、“形制”、“现藏”、“字数”,再附上“图片”,接著“集释”学界已有的释读","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIRti9OpVk9VqZ6TcqokelAt1D0FkcU9vaPleTsYTefCtBaDFjcQue0MwpSFv9aonli5ThkQFi-twI9I_2hTdge0tcnekLoQyjZFbqB-huHi3YYN9QPDpUn1e2_PPKfpdnx9JGYYbEZTYanozSnrtgVvTZ6ggO8kenY2C9Zhxo1u6bCYVg3dZuY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4367,"author":"朱樂川; 董志翹","title":"章太炎語源學理論研究","abstract":"封章太炎先生的研究已涉及到他的方方面面,而成果也可谓汗牛充栋。本文当试对章太炎语源学理论造行研究,此裸题属於章太炎捂言学的范畴,而封章太炎的研究阴始最早且持续最久的即是他的语言学。经过百年的时间,封章太炎捂言学的研究理应进入既全面又深入的陪段,而封他语源学的研究也应呈现出這种状态,但由於章太炎捂源学的相关著作构思之精妙、理论之创新、说解之深奥、内容之充盈,所以读通并理解并非易事,加之章太炎的音转理输多被人所葫病,使得许多学者封以《文始》为代表的章太炎捂源学理输有先入为主的负面印象,从而尊致还没阴始研究它就已经排斥它。正因为以上诸多原因,所以现在学衍界封章太炎捂源学的研究呈现出魔而不深的状况,这","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpCTHY4J01JvuMvkjbJmvrxJaNcm5PM-je8uI1nfkFxSJQFU-qFkc66KAS3BOu8_-zAb2DvQNfwpkHb40qLbtufYzuglB-nH09HpGJZFyENWAG3_xXh_2uNncFipuJMplkFFAJChmIk9pFXDhFZwpEIczhi5laHe06dqb5EgaJW3YzpcERy-gr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4370,"author":"刘余力","title":"赵焦■戈铭考略","abstract":"赵焦■戈为春秋中晚期铜戈,戈铭10字&quot;赵氏孙焦■,乍造戈三百&quot;。&quot;赵氏孙&quot;,应该就是春秋中晚期晋国赵氏家族的某位后裔,&quot;焦■&quot;为其名。&quot;乍造戈&quot;,乍、造同义连文,制造的意思。&quot;三百&quot;表示戈的数量。戈铭焦、造字写法特殊,百字为目前见较早写作全形的例子。该戈对于研究春秋战国时期的文字,春秋时期赵氏、战国时期赵国的历史,提供了珍贵的实物资料。","categories":["02_字词句考释"],"year":2014,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK91vUsj_L2okUp3vXvIXOCDyy4lmz7dVmj-0s8GOwt14IFOiiEM8hoOf8MZmZqPXCAr3hHZ1ouP4MLIh2mMFAslO5iMVtaPsYdVO4BRxn59Wl-tKZSjpnEgq30QkyLZhrOGxCNMEoA8fdu8x64PO9mH58TiDyhVh5fqf0TABC8GA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-70, 77","volume":""},{"id":4371,"author":"孙银琼; 杨怀源","title":"金文“■”新释","abstract":"金文中的&quot;■&quot;和柞伯鼎铭中的&quot;共(功)&quot;是同义词,因而此字是&quot;供&quot;的初文,在金文中当破读为&quot;功&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"重庆理工大学学报（社会科学）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3SMvZL7--kNnLeY2R08e7076FpXBd22NapblQiEx4W7vrEN6vZ_Yac3loHvYEy2Hs1OK-W2vp1hFL7JZk-hL-drekeAO8RLCzlz4UFaJL_Oot8K1r0i5uLGqHf8Mw2cuge7ouh_EafUILPIkZFl1YQ0aZCXFpDOQuDZ5tvOa_6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-19, 32","volume":"28"},{"id":4373,"author":"周芬芬; 黄信初","title":"“和”字的历史渊源及文化底蕴","abstract":"汉字具有悠久的历史和鲜明的民族特色,其中,&quot;和&quot;字在甲骨文中是指音乐之和,后被引申为一切事物和谐关系之义。&quot;和&quot;字具有丰富的文化内涵,它经常在艺术领域、文化领域被广泛使用,它可以为建设社会主义和谐文化,实现&quot;中国梦&quot;提供丰富的传统文化资源。","categories":["02_字词句考释"],"year":2014,"publication":"艺海","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXtDViSK6HFr4gpFI63g2cDWbHqjDJ2ScVca5_77vL_cm_yfI2vKYURYr77kjoQ46a9mpKnq0iBngGH1bQQ_Y2-Xji2e89V1ECEh3amfhHFTn2d4Vvn1pUTg1cCrCOudYrP6Qe8RsJw941ySyjD1CWL8Lh5LRtskYIZA68peeQqA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"181-182","volume":""},{"id":4379,"author":"高會彬","title":"《左傳》所載銘文考略","abstract":"《左傳·昭公三年》和《左傳·昭公七年》分別提到了兩則銅器銘文,其中所記載的內容有一定的史料價值。現結合傳世典籍和現有的金文文獻,對兩則銘文加以考述。","categories":["02_字词句考释"],"year":2014,"publication":"学行堂文史集刊——2014年第1期","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIpUlSAs6iPY9R8YecswC-ICQtg_sXy21klezv4xu_cgq3Mxk02jNZ0cVb1MQrAYAUIwi2iFZoTeA-giOBO6hLwDDwdYYPplg4t97-vjPjmt8NT_5owj5f5ZD3sge9Jezmm2rMiJVEA6_tSDgjpYh6r18rf4ck8nJw2JzXgNjCDv_gIOEfAySX1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-20","volume":""},{"id":4383,"author":"王欣","title":"多变的“手”","abstract":"&quot;手&quot;这个字对大家来说绝不陌生,以&quot;扌&quot;为部首的字亦比比皆是,但除此之外,还有很多变形的&quot;手&quot;隐藏在汉字丛林之中——&quot;爫&quot;&quot;又&quot;&quot;廾&quot;&quot;寸&quot;&quot;ヨ&quot;&quot;攴&quot;&quot;攵&quot;都是&quot;手&quot;的变形。对此,人们常会感慨相逢却总难相识。下面我们就来找出这些在现今汉字中还依稀可辨的&quot;手&quot;","categories":["02_字词句考释"],"year":2014,"publication":"语文建设","link":"https://link.cnki.net/doi/10.16412/j.cnki.1001-8476.2014.10.009","pages":"69-70","volume":""},{"id":4387,"author":"丁一欢","title":"“丁”字考释","abstract":"&quot;丁&quot;字笔画简单,但历史悠久,在甲骨文中便已出现。针对&quot;丁&quot;字的本义,学者们也各执己见、意见不一。文章从&quot;丁&quot;字的字形演变、构造、字义、文化内涵等方面对&quot;丁&quot;字进行了多方位的考释。","categories":["02_字词句考释"],"year":2014,"publication":"连云港职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLt7pAk3U58axHGnJVPm3CGbh2sq0KuX84OfaT9AF_w2U6V3SEbeV9wb4DlSEXkbnDqf1oyjkYXOyITqPlSUfDaVDYDOQwIsUX1tRNY90tHsJVYqZ0PlUDlp9OEVGMiNjEUEXmTU9LegHvo0tbX6KNoJBITvjwgn6fFYnYIeP1UOw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-47","volume":"27"},{"id":4389,"author":"聶方園; 陳鴻","title":"出土東周齊系文獻形聲字研究","abstract":"近几十年来,战国文字的分域和断代研究一直处于相对较落后的状态,但是随著出土文献材料的挖掘、出土,战国文字的研究越来越受到学者们的重视。经过学者们的共同努力,战国文字的分域研究有了极大的发展,也取得了一定的成绩,特别是出土文献材料比较多的秦系文字、楚系文字、晋系文字,相比之下,齐系文字的整理和研究就稍顯滞后。值得庆幸的是,近数十年来,齐系文献材料不断出土、发现,如山东大汶口文化、龙山文化遗址出土的刻书符号,山东莒(?)陵阳河及大朱村、褚城前寨等遗址出土的陶文等,这些都是研究齐系文字非常重要的材料。本文立足于出土东周齐系文献材料,封出土东周齐系文献材料中的形声字进行分析、探讨、研究。文章内容共五章","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbdtPbYM1A9_q8VZOACEsvm0AbNbNDvyCX1XxxNQpUc0wJxlnH1vBkzTYJ5Fm0zmFLejeMSVYoQTJIvUXti-Ta8vR1XuBslCokPNB4SLaDyXUK7t_QozcYw3gkar4-nebUp3jgfFrRUV1hx2va73MMMCQ1xp4f34mxz3THwQIi35o8PctokHar&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4390,"author":"王进锋","title":"(戈丮)字、(戈丮)国与(戈丮)臣","abstract":"《说文》对于字的训解有误。从甲骨、金文字形和相关的字音材料来看,它的正确训释应为&quot;,贡也。从丮,戈声&quot;。这可以得到字辞例的验证。根据古文字文例,商周时期有个国,即灌国。灌国应是夏代斟灌族的后裔。金文中的臣就是贡臣。西周时期周王和贵族都有贡臣;贡臣有时可以表示身份,有私名。","categories":["02_字词句考释"],"year":2014,"publication":"湖南大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ8eiTuqn7X7PBrIvuFD1BYRZQZSNQEPTUhhaYWX766hJQVoP_Y1AbNUtz5Swqe60WE7V68Sufs1huwXCTVmoarwKa7qVCcC-e2JDRWXurIXB4OVRuyVRfjMHlAKMv5uq97-yoLr3OfwwiSvt_Csy8t0s7EIWnNw6h_-7tsETuYLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-101","volume":"28"},{"id":4391,"author":"晁福林","title":"好仁、好贤与朋友——简本《缁衣》“轻绝贫贱”章和《大雅·既醉》篇补释","abstract":"简本《礼记·缁衣》&quot;轻绝贫贱&quot;章所提出的&quot;好仁&quot;,今本《礼记·缁衣》变为&quot;好贤&quot;。这是社会观念变迁的一个表现。此章所引诗句中的&quot;朋友&quot;之意亦有概念的变化。西周时期的&quot;朋友&quot;指同族兄弟,而春秋战国时期则变为同志、同师者之称。&quot;轻绝贫贱&quot;章引诗虽然用了同一句诗,但此&quot;朋友&quot;非彼&quot;朋友&quot;,在引诗者的心目中,其意义是不一样的。此章所引《诗》句对于研究《诗经·大雅·既醉》篇的主旨也有较为重要的参考价值。","categories":["02_字词句考释"],"year":2014,"publication":"北京师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6v2COLy2CZytPPNjz-zjBL__5B5x1GQdYksjjuziSQvTgg4zKfFCYEOPcmlokZOvaX33l8Kl2xUeFGXCDjAi-a7_2HriKye_pvA7ef3JW0n0ldsB1xobZD0e_qJ79LWSPCsE6TEScbLdL4fT1AgtTIJ02W0nCk3V9e7E8G8AtKg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-77","volume":""},{"id":4396,"author":"李刚","title":"说“丙”","abstract":"&quot;丙&quot;是一个常用字,但其本义为何却一直存在争论。《说文解字》的解说并不可信,利用甲骨文金文等出土文字资料研究&quot;丙&quot;的本义是唯一途径。于省吾提出&quot;丙&quot;的本义是&quot;底座&quot;,信从者虽多,但仍有可商之处。&quot;丙&quot;字本义的研究不仅有利于探讨汉字的起源,亦有助于探讨汉语词义的发展变化。","categories":["02_字词句考释"],"year":2014,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2014.01.010","pages":"91-94","volume":"35"},{"id":4397,"author":"谢明文","title":"臣谏簋铭文补释","abstract":"臣谏簋铭文中的一些字,旧没有得到很好的释读,如&quot;处于軝&quot;后面一字,旧或误释作&quot;从&quot;,或误释作&quot;&quot;。本文根据不其簋、不其簋盖、引簋铭文等相关金文资料指出它应释作&quot;■&quot;而读为&quot;同&quot;,意思是聚合,并讨论了甲骨文中与之用法相同的一些&quot;同&quot;字。&quot;引又&quot;下一字,或释作&quot;■(忘)&quot;,或认为是&quot;闻&quot;字之省,或释作&quot;长&quot;,本文赞同最后一种意见。&quot;灷&quot;,旧或读为&quot;■(媵)&quot;,或","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLB0eRsx1TW3ybvBbtlquiQ5ylC4NikOkKPCYgOpXzHUYrky5Jw0fsTecgnDL_lck7OWdivGSX-p5lLl3ahCEJtRbhKRGruqtu2CGfIX45ioHfJnxOtQymKAjFxcj-I5C1PyPGSOfugO47MzLtq5t8RPMEzLXcm0zw_8oYF7g3IZw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-54","volume":""},{"id":4398,"author":"曹汉刚","title":"多友鼎相关问题考证","abstract":"多友鼎以其长篇铭文和丰富的内容,成为研究西周历史的重要史料。笔者经考证认为,金文&quot;广伐&quot;一词为专用贬义词,并非指战争规模,而是专指外族或敌方对周的&quot;侵犯&quot;、&quot;进犯&quot;。作器者多友不是郑桓公友,他只是武公的部将,研究者对于金文人名与文献人物的比较研究存在较多乱象,笔者认为金文铸人名不可能用假借字,所以金文人名间的考证也不适用同音假借。多友鼎铭文分别记载战后周王对武公的赏赐以及武公对多友的赏赐,是西周严格等级制度的反映,也体现了西周赏赐制度的一些特征。至于多友鼎铭文所记京师、杨冢等的地望,有研究者根据新出尚父簋认为其地在山西新绛,笔者认为尚","categories":["02_字词句考释"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIdYiNzxf9Yni698La5BVYTzarMR1dYx4XMk6495Vh3gDBdcIevxT7zv-dMyP4EWhVyOWDVPRx0o5vtu2e0M5Pbrbp_ar4ydcLJPTslOpcIFImIPAYBFWlQQXrbtiCSd_1H_NNuQO_juZys84NaIAyKoZFg_94D4DkLLpOH89DWMA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-63","volume":""},{"id":4401,"author":"董文强","title":"西周金文书体演进初探","abstract":"西周金文书体的演进特征明显,从早期的象形意味显著到晚期的抽象化、规范化和符号化有一个清晰的路径。这一错综复杂演进过程与西周社会&quot;礼乐&quot;之制互为表里,显示了西周先民对金文艺术美的超强理解力。","categories":["02_字词句考释"],"year":2014,"publication":"美与时代（中）","link":"https://link.cnki.net/doi/10.16129/j.cnki.mysdz.2014.03.040","pages":"87-88","volume":""},{"id":4403,"author":"苏傥君","title":"“乳”字考","abstract":"汉字的世界瑰丽丰富,吾对&quot;乳&quot;字情有独钟。借此想对&quot;乳&quot;字演变作一个系统梳理,挖掘字际变化的细节和规律,其中着重探讨&quot;乳&quot;古文字阶段的讹变情况,尽可能还原字体真相。","categories":["02_字词句考释"],"year":2014,"publication":"商","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaCS-gmCLnE7xOFhFc8RiAGlyAI0hH-l34pFdE5i4cfRyJSHhBcU4UIDP_zyiu-v9r2vTOJUWerjLnDd0dwWX6aGT_4JGYCPNLJAQuvcRW3krt45nuHbAwPppDwjkxao3l3pcro4yCoztwcqvuISnnSg-dX5JoLsiITSpqubRwuA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-99","volume":""},{"id":4405,"author":"赵洁; 周宝宏","title":"近出东周兵器铭文汇考","abstract":"春秋、战国之交,是社会大变革时期。这一时期诸侯纷争,社会动荡。由于各国战争需求、重兵尚武和军事兴国等原因,兵器大量出现,尤其是有铭兵器的大量涌现,吸引了众多学者对其进行研究。有对单篇兵器铭文的考释,有对个别字词的考释,有对某一地区兵器铭文的考释,有对某一国家兵器铭文的考释。但研究相对分散,目前还没有做到全面系统的研究。本文广泛搜集整理《殷周金文集成》后新见的兵器铭文,对这一时期兵器铭文进行全面系统的梳理和分类汇释,全文共分为三章。第一章主要是近出东周兵器铭文字词汇考,也是本文的主体部分。按照学界普遍认为的战国文字分域五系说,将兵器铭文分为秦系文字、楚系文字、晋系文字、齐系文字和燕系文字五大类。","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKiAICxKVF9i01OIxW7XK-ppxF8gbRh_Aoi1ltIvE-Ibqym4B62IK9ks5YsfLdJyG93oRItLR5JmOvwT-_Px072bSXIwWbhQu2lEg7xwb60_lCTSzrvReLUCPA-pjcNJF2gjCiM1um9NzdtNG7LJ2YLlMeEvKVOeKfXLflla6cqTkGIR5nm7V1q&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4406,"author":"王英霄; 陳曉強","title":"古文字演變美化現象研究","abstract":"美化是漢字發展過程中的獨特現象，古文字的美化現象貫穿於甲骨文、西周金文、春秋文字和戰國文字等各個階段。古文字美化的研究在美化飾筆材料的整理、飾筆演變結果的闡釋和單字的形體分析與考釋上取得了很多成就。然而也存在著不足，主要表現為以前的研究主要集中在對美化文字本體進行局部、零散的研究，對現象和規律作理論闡釋的並不多，對整個古文字時期的美化現象進行階段性分析的研究較少，對美化飾筆與分化、訛變的關係進行宏觀、系統研究的幾乎沒有。鑒於上述情況，本文在前人研究的基礎上，查閱了《甲骨文字典》、《金文編》和《戰國古文字典》，對古文字的美化現象進行了系統總結與分析。本論文共分為七章。第一章為緒論。主要闡述了古文","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJiTTYLIPh7lEq8DSS1z-CEVKfCeShiW9-25ZkCAdvQyVW9v8Obqs6YAyDeZ9YSWNUR4kHdZi86gKlJBvFfcoN4t3GsKYNKCu5rM-J9M9FBoEv_7UD5RUJosuWD3XXPhp6NMqbwyJZHYqIH1NgpT6I0Nu2wBet--Zgcp5wcR4k08VmptYHVMlV8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4407,"author":"喬二虎; 陳曉強","title":"古文字演變聲化現象研究","abstract":"声化现象是古文字发展演变过程中的重要规律。这条规律体现在汉字发展的各个陪段。论文通过对古文字材料的考察、汉字形体演变的梳理,运用历史比较法封声化例字造行归纳分类,对声化类型、声化成因、与声化相关问题以及聲化现象研究的意义进行了探讨。全文共分五部分。第一部分为绪论,作为全文的引言,首先介绍了声化现象被提出之后,聲化现象研究的成果和取得的成就。其次介绍了声化研究的现状。并且介绍了本论文的研究方法和取材范围。第二部分为声化类型。主要從变形声化、置换声化和添加标音部件的声化三个方面封论,且举相关例字进行解释说明。第三部分为聲化成因。從语言、文字、社会三个方面来探讨聲化的成因。同时就文字自身的原因分陪段","categories":["02_字词句考释"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJu1rSwOlpMaQ4BNpBUlZ2L1aOr0LtqsWLy5zGrQkKttGwTol--Shxg3nfkqvzhxWLdNl5VBXBxA7bdWeIbbgWjWzsVQoGCT67SJyXrojjolFvSX7FiSMSB_TcbYMaEviV3SughHP1eK3tTk4xhYLiSakjRmeMIFBEHz3ZI0hW0apVb1OqRg5Ve&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4408,"author":"董莲池; 宋琳","title":"释伯■父簋铭中的“冓”字","abstract":"本文论证了伯■父簋铭&quot;桐潏&quot;之上的怪字为&quot;冓&quot;,铭中表示敌我两军相遭遇,&quot;冓&quot;后的&quot;桐、潏&quot;是遭遇地。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdLe7TqcaVWlX_tppCKI5N0_Mo33q7V9twqAwob8jzgRoF0C71orLq4CALmDwzmMfg-gKOIpL6eTPZjB1m28am1FESBJjE77p7fJNXgRBJZw5p3f5II7T9nUpYHfLKuhXs2Lv7UjxIAk-uQjfHsYMmrdmAq8GFEJSpGM1jUF6c-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-19","volume":"19"},{"id":4409,"author":"陈英杰","title":"青铜盘自名考释三则","abstract":"本文对伯硕奢盘、苏公盘、家父盘的自名进行了考释和讨论:据伯硕■盘,青铜盘当有食器功能;苏公盘自名之&quot;鈙&quot;即&quot;鎜(盤)&quot;之异体;家父盘与晋仲韦父益同出,构成盘益组合,其功能是水器。文章还指出,金文的研究一定要把器和铭结合起来进行探讨,器可以为铭的释读提供特定&quot;语境&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4quxNEkI083qLJMCF45n3mO4zArnb8v_Zewv7aoVHySEsADxufSikEnzgY-gB9k9fxnTpktPiSmREpnVrTb5hpPQZYfsUGNyFO2o_AZN17VJOxGzQ3gYDvptRZl9lVwIaKnasgW8YlfA14A3OW9p7svqEZgFXMvio93elHej_LA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-28","volume":"19"},{"id":4410,"author":"李春桃","title":"庚壶铭文拾遗","abstract":"庚壶铭文是记录春秋时期齐国史实的重要材料,本文讨论了铭文中的&quot;■&quot;字,对其地理位置进行了论证,同时也涉及清华简《系年》中的相关地名,并对铭文中的&quot;要&quot;、&quot;入&quot;等字的释读进行了补充论证。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKsf76OM3iMrbU2ww1s30UFWesb0paCxXDgJhVFxKlnVmlOG2XQSgd5kv0ku1aKtsoA32C7yRMk_7Jti0n5tJnnli3Jm4HhlDNlzj93nSTEIZxxG4QfOjcP3o6GFiaXv0kcO-E-bFuezAAh9zhNn4umJ4LvjZW2g58SI5z4CC5z2A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-49","volume":"19"},{"id":4411,"author":"孙合肥","title":"越王句戋之子剑铭补释","abstract":"目前所见到的传世自名越王句践剑有一件,实际上传世的越王句践剑还有两件,因铭文误读而没有确认剑主身份。本文依兵器铭文的辞例和行款,对传世的越王句戋之子剑作新的释读和考正。","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL5N57_1098MMqQmLs2UzLqKlDdJVBthgNpixMlzckuEWxgG0LVrJmWhJvU4OZ4VlCWzUHZJp91oRskGzsU0Fl40GiwVO5hxYyMy_NZ2YO0yngD0izqDAy1jwQpEDaCKlL2UrJvLsfp9vX73f3QbGtjMUuDLbfJtB9jc8qj912e5Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50-53","volume":"19"},{"id":4412,"author":"河永三","title":"“贞”“真”同源考","abstract":"本文的主要目的在于:以甲骨文的&quot;贞&quot;和金文的&quot;真&quot;字作分析基础,从而发掘出中国早期对&quot;真理&quot;概念的认识和演变,以证明&quot;贞&quot;和&quot;真&quot;是同源字。我们得出如下结论:&quot;真&quot;是由&quot;贞&quot;字分化而来的;&quot;真&quot;和&quot;贞&quot;(&quot;鼎&quot;)字形成同源关系;后来&quot;仙人&quot;、&quot;真人&quot;和&quot;真理&quot;等概念,也是由商代贞人演变过来的。古代中国,也是与希腊语&quot;alethe","categories":["02_字词句考释"],"year":2014,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISEpopL_ziWHD66OErPBBmbv9i_jc8wkPXVFUqb4r3ZNemqbPjqlGvSLJT-HxGfXTr986_QkJ1mWNSBrV_6OQJrCvCoJyUcgCWSF7eYrvei_d4K-YextreQiSZrAJqIQGRGxHaeBRi7r4HDcG7XBbEjBX0TCIbY9-DldL2B5y8Pw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-116","volume":"19"},{"id":4415,"author":"张羽","title":"试释■字","abstract":"两周金文习见&quot;■&quot;字,卫盉、匍盉铭文有&quot;麀■&quot;一词。本文根据&quot;■&quot;字的形音义,从旧释读为贲。文献记载的&quot;虎贲&quot;与&quot;麀贲&quot;原本为古车上皮革类门帘等装饰物;不同等级的车配备有不同的实用或装饰物品,金文与文献称为服或车服;它标志着贵族身份地位的高低,有时也被用作蔽膝的名称。","categories":["02_字词句考释"],"year":2014,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfR4Rp0rakCuaKBYdC98mG0ucFRc4NuUEAPH3UQMr2rh5geT9AhLjYWnoPg9uFeFZUsnCJ1YSdkvSKslJDxcUjzyy4ZCnOrkKlcdUz6YDm03IxvYAWqSwoWn-YZ-SzohNt-L_B-Sr_nnpjnGoql-u4tHmt34DcANHD9L0QfsI1Cw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-82","volume":""},{"id":4416,"author":"杨明明","title":"“妃”“(女巳)”辨","abstract":"&quot;妃&quot;&quot;女巳&quot;二字本为形音义皆不同的两个字,&quot;女巳&quot;字出现得更早,甲金文中早已有之,前人多释为&quot;妃&quot;,从金文女性称谓通例来判断,该字当为女姓用字。《说文》&quot;妃匹&quot;之&quot;妃&quot;甲金文未见,春秋战国金文皆以&quot;配&quot;为之,&quot;妃&quot;为其后造本字,当为从女,配省声。隶变以后,由于&quot;己&quot;&quot;巳&quot;二形的混同,&quot;女巳&quot;形逐渐变成了&quot;妃&quot;字的异体,而金文中本来用作姓氏的&quot;女巳","categories":["02_字词句考释"],"year":2014,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIpa9LfNSDwrbMNpufhei4sGepn5SifOppM-fxaUrmzb_cNMZ_ykck4mqFu1Tuib11PeNP8ZUYcBFvSaAcl4oHv73O7RduCjisCxmAzCvG09iGRWp96CE9hD2dmVh9uZENsUIb3alt34CL1GnynnpvM7vcahHfNKNp6A86uAMQfhCQ9kkLeCj12&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-22","volume":""},{"id":4418,"author":"贺靓艳; 杨燚锋","title":"秦丞相新证——兼析“令相国昌平君昌文君发卒攻毐”的句读","abstract":"新近出土的地下材料为研究秦丞相职官提供了新线索。通过对新材料的分析,可以发现,秦有相邦和左、右丞相之分,后两者又以右为尊。在对秦相邦、丞相设置进行初步考察的基础上,可以断定《史记·秦始皇本纪》&quot;令相国昌平君昌文君发卒攻毐&quot;一句的句读应为&quot;令相国、昌平君、昌文君发卒攻毐&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"商丘师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJa6xd_w9V_v1HNbklOMgMdm9mNJ3U5IkfdhTE9fua7FfCVJ-jDouptptOrY7w_lCefc34PzVQWr9vibQdAgrm38LwXqZYYSrPzJc5KmBGxX8t1T6qW01RgpUcbMRn5mUBH41wKPDWVZjHes8xNz0vQHx6T2NYLT7WCXKNwtE0Maw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-42","volume":"30"},{"id":4423,"author":"马智忠","title":"释“沐斗”——随州义地岗曾国铜器铭文补说","abstract":"本文对《湖北随州义地岗曾公子去疾墓发掘简报》中的&quot;御斗&quot;进行补说,认为所谓的&quot;御&quot;应该是&quot;■&quot;,读为&quot;沐&quot;。","categories":["02_字词句考释"],"year":2014,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvtlxPtRKzYE3q3ZSGfp9UVQvuMA1rAPQvV_xeuD22EBO7ro7oq5VtDEEZQVEbxdqWDCgws17CUgaIqvhsMbJaXBDaXMGrcKG3OUSXK198RutwAFfnWYxD6H8gVuH5_eyH3FzEkPyDl8Iv6V3OzQweu4F7__rWWER1wHz4-jVRYw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-121","volume":""},{"id":4424,"author":"陈彦辉","title":"周代记事铭文的叙事特点及演变","abstract":"殷商中期铜器铭文开始出现,其功能由标识发展为记事,记载王侯贵族的立功获赏以及战争、祭祀等内容。周代铭文发展迅速,在现存数量庞大的铭文中,记事铭文所占比重较大,涉及赏赐、纪功、战争、朝聘、宴飨、渔猎等社会生活的诸多方面。在长期的写作实践过程中,记事的方法日趋成熟,逐步形成注重叙事的详略繁简、突出记事重点、记事格式相对固定、运用习语等特点,这些特点在秦汉时期部分得以继承。","categories":["02_字词句考释"],"year":2014,"publication":"学术交流","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvtlxPtRKzYE3q3ZSGfp9UVQvuMA1rAPRDL5CZKPOPjerwqxYk8GcIR-ZN0qGpGJjlDrT7gGleV8Op2HS0T70hzprSn_MN667azk9QmACJMzb-ZXEcCybIMR9_AMbA9ss13XbNocfWqPpXipfUxdetOaDj7cF8EqlqS6r1E7BVFw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"147-153","volume":""},{"id":4425,"author":"章婧雯","title":"考释“龠”部上层部首归属","abstract":"从文字学的角度来看,许慎《说文解字》中的部序编排是严谨的,但贯彻的原则是多头的,这就为至今汉字部首及其归部的混乱埋下了隐患。笔者依据&quot;同类相聚&quot;和&quot;形近系联&quot;部序原则,比较&quot;龠&quot;中三口与&quot;品&quot;的部首含义,&quot;龠&quot;中&quot;亼&quot;与&quot;亼&quot;的部首含义、&quot;龠&quot;字演变的历时沿革,分析&quot;亼&quot;所统领的其他字和&quot;龠&quot;的关联,说明&quot;亼&quot;相较于&quot;品&quot;更适合成为&quot;龠&quot;","categories":["02_字词句考释"],"year":2014,"publication":"大学教育","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKq6SSBSM7eE5cEMY9_VsREBlxWvVaS2lXOafzhfFdch8TQeamp6DIBuZEostpIkky5efkMhg542X59beZgynAuz-_xKzPpTYtUXY9lLoR2E_2epTtJ1S0O2HqVPkaUWINUusl5etzKXA3-XHsz9cIZirp9xCWr4VauVp-Qsf6TxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-75, 78","volume":""},{"id":4427,"author":"谭德兴","title":"试论山东青铜乐器铭文的诗乐批评思想","abstract":"山东地区出土的周代青铜器较多,而其中青铜乐器占据了很大数量。这些青铜乐器上的铭文蕴含丰富的诗乐批评思想,充分体现了周代山东地区诗乐思想发展的较高水平。深入研究周代山东青铜乐器铭文,可以深刻认知以诗乐批评为核心的中国文学批评思想在先秦时期的具体发展状况以及其中所呈现的地域特色,也可进一步探究周代中央王室与各诸侯国间诗乐思想互动的具体内涵。","categories":["02_字词句考释"],"year":2014,"publication":"湖南大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIt4IE54q18ppCTSS-SeoOmBG6n1dSWbVkY5eEx-m1H0QSF16SpiuScAjYqtnHIl3QXB7WKplzbAYM6ngDCVcWy2Ud6hgCGQA3sju6gNFUTBDOUjeFqoGu3Dh6ytbzEJO2mbyx5A-M7QkORQ8JgDzDKqz6hOBZ2MKUtrENAM4JEFw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96-101","volume":"28"},{"id":4429,"author":"尚伟","title":"释“陽”兼谈“陽”的观念形成","abstract":"许慎对&quot;陽&quot;的解说存在一定问题,为了正确释读&quot;陽&quot;,需要研究者对&quot;陽&quot;的构形进行深入分析,找到&quot;陽&quot;的来源和本义,并对哲学上&quot;陽&quot;观念形成时间进行了探讨。","categories":["02_字词句考释"],"year":2014,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIdSNZLiVUndVfEA6QL03K0O8kG0T1mQisamcofAYctmoV1iNZxqsmzIEwpVXFf1nLPbUE2B_pQY0kKxZTrNmP9iCp35KU_dwW_ZFgn6ydYS42jHtkQT8bGs3o12TONK5tvWK-69cUS8pgLTP_knQzDbe-IX8RYPpQjguBUbxjD1g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-105","volume":""},{"id":4432,"author":"张振谦","title":"齐铭摹误考辨四则","abstract":"铜器铭文摹本的细微失误,可导致对古文字的错误释读。在齐系铜器铭文摹本中,存在着一些因被误摹而错释的字。通过对庚壶铭文两个摹本中&quot;(甲)&quot;、&quot;执&quot;二字的研究,发现张光远本的字形摹写有误,而容庚本则非常精准。除此以外,少司马耳杯的&quot;(造)&quot;、陈逆簠的&quot;武&quot;;陈璋方壶的&quot;(将)&quot;等字,也因为摹写失误而被误释。","categories":["02_字词句考释"],"year":2014,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2014.01.007","pages":"69-73","volume":"54"},{"id":4433,"author":"房郑","title":"曾姬无卹壶的铭文集释","abstract":"搜集并梳理了几十年来各家对曾姬无卹壶铭文及其相关问题的研究成果,按照铭文顺序排列,为研究者提供更方便的资料索引。曾姬无卹壶于上世纪30年代出土于安徽寿县朱家集楚王墓中,共两件,两壶壁均铸铭文五行,《集成》著录为9710、9711号。两壶自出土以来,因铭文的史料价值而备受学者的关注,对这件铜器及其铭文的研究也层出不穷,尤其是近二十年来对其铭文的考释取得了重要突破,为解读这件铜器提供了更准确的参考。","categories":["02_字词句考释"],"year":2014,"publication":"淮南师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxjcdXt-VLoBaa6q9HBXxwKFpv9boACXv7xA9sUM0QVVi1-bMFkPGHqM30CCKgfPtjDihEwNkayW-7v6bf7b2ofcIjXXVm_vuZMWSDp8C1YfHhMJmYWW_UE29pF-74ulAMyDNZwCBDS6M8xUwwtrE9IL3hxTQkPNQX-RYOXVlUvQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-59","volume":"16"},{"id":4435,"author":"熊梅","title":"西周都邑的卫戍分区:立足于铭文“還”的试探","abstract":"西周铭文中的&quot;還&quot;字被释作&quot;苑&quot;、&quot;咸&quot;、&quot;县&quot;。通过辨析,以上注解均有不确。按《方言》,&quot;還&quot;释为&quot;积&quot;,通&quot;环&quot;,极可能是西周&quot;师&quot;具体驻屯在各地的卫戍分区,是以承担军事任务为主要职能的特殊地域组织,具有&quot;耕战结合、军农一体&quot;的典型特征,是国家军队实施分级管理和军事布控的重要方式。对西周铭文&quot;還&quot;的考释和重新解读,否定了&quot;還&quot;是&quot;县&quot;的观点,认为中国行政","categories":["02_字词句考释"],"year":2014,"publication":"中国历史地理论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJptldlcxRK4WtdbU7sLOh34QOOvUNjMTbhJMpzVuh8-qrHWbHPQFqLh9uqpjdivBRFQsVyw4kNp5N9gCIf1jbLhr2et-cG2NT5O1RS1VsDFutgRkUg6QvFlxLdT2TLjGlgmSo1Vway-k8ZzTbKsRYmfRm695wivwM5MgXPKMTknA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"93-101","volume":"29"},{"id":4437,"author":"周忠兵","title":"莒太史申鼎铭之“樊仲”考","abstract":"莒太史申鼎铭中讲述器主申出身的铭文作&quot;■仲之孙&quot;,对其中的&quot;■&quot;学界有不同的释读意见。不过,这些意见从字形到文意皆存在问题,因而&quot;■&quot;的释读值得进一步研究。清华简、上博简中有一类&quot;樊&quot;字的特殊写法,据此可知&quot;■&quot;从邑樊(或燔)声,在铭文中读为&quot;樊&quot;。铭文之&quot;樊仲&quot;即周宣王时的辅弼大臣仲山甫。器主申为名臣樊仲的后代,时任莒国太史。","categories":["02_字词句考释"],"year":2014,"publication":"吉林大学社会科学学报","link":"https://link.cnki.net/doi/10.15939/j.jujsse.2014.01.008","pages":"20-25, 171","volume":"54"},{"id":4442,"author":"王沛","title":"西周金文法律资料辑考(上)","abstract":"金文资料是研究先秦法制史,特别是西周法制史的第一手资料。在已公布的一万多篇周代铭文中,有160余篇资料和法律史研究相关。通过阅读这些资料可以发现,铭文信息往往彼此相关,如能结合传世文献加以整体性研究,将有利于廓清上古法制状况的面貌。本文对较为重要的西周金文法律资料进行考释,疏通字句,翻译大意,并对其法史价值加以分析。","categories":["02_字词句考释"],"year":2014,"publication":"中国古代法律文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQnZjbpERNtz6iGPIk2Go4jfIub77tYYfID5Ns6ESwD96QT-dq1BhEXWIcKKOx4VtSzCEQacwT73iqBLUpSg-E_TmUlrRfB4bW_zubjWfd9zv8y-GFtlCrq8fE6F-i95u55hHuucBFa3Xx3PZdCNKg9KLO2wX_qzBmL5X6RYuMYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-65","volume":""},{"id":4384,"author":"董莲池","title":"■诸器铭中的“肇贾”研究","abstract":"本文梳理了西周早期■诸器中写作&quot;■■&quot;的形体,研究了&quot;■&quot;字,认为它在西周早期纪录&quot;贾&quot;一词,但不是&quot;贾&quot;的本字或初文,也不是《说文》收录的&quot;宁&quot;字,而是一个失传字。它与&quot;宁&quot;的关系只是同形关系,与&quot;贾&quot;的关系只是音假关系。学者将&quot;■■&quot;读为&quot;肈贾&quot;十分正确,是我国先民西周早期从事商贸活动的可靠记录。","categories":["02_字词句考释"],"year":2013,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCf8DNCI6NJyeoio4TrGzlOu9yl_ltdgp3phO9OUl0QfiGFitzY6L0EgG2ieQ9mNAORf8w__izLvJPev31_vQcnqt5Pn4txExeKVII6Lzc0_DPy-tngLAjy9kHS15vZSb87od1UOu6tLHTiAGp_uzbOB0TGuEGvyzQRz2PjMBeZA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-75","volume":""},{"id":4385,"author":"周宝宏","title":"引簋铭文补释","abstract":"本文是对近年山东高青陈庄西周墓出土的引簋铭文所作的考释,对已有的考释成果进行了评论,对一些关键字词提出了新的看法。","categories":["02_字词句考释"],"year":2013,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFLnzi1650meR5PGDaxFp_wIrG_byWx2ioOVgQ8--2kF9V8-GUP0yqJYflt4Cko1Hm9D29OZHbquxUkgk0PyjF-PXlOpQ7_Ch2--eLvnridK1llneW8vm60YQDOSwb9pPNN_kJyzv_M9kpT3JYeo_9GJycawtDSyUhaEJYNCZtww==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-80","volume":""},{"id":4386,"author":"王长丰","title":"殷周金文“亞且”之“亞”内涵研究","abstract":"本文认为殷周金文中&quot;亚且(祖)&quot;之&quot;亚&quot;是殷周时期五世而迁,另立新宗后,对新祖的称谓。","categories":["02_字词句考释"],"year":2013,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIm6oLTUYh6IxJTMEhfcVUBiGru0NSQUIpGzmqGgQxIL8_TR33JbE3IGtKdFN9UARLXeGDNOpY81cvnb4Tm4fAq0dGvalrFRc-Y7e_u6ZIvUG8X5-Ne_WyKZTtBMZnEbPDjIGz3YqzlrKN5OpxC60WdltFy0nS5gSMY34wyZ2MPyA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81-89","volume":""},{"id":4438,"author":"蒋文","title":"长沙望城出土木楬签牌释文补正","abstract":"文章对望城坡西汉渔阳墓部分木楬签牌的文字释读做了补充和修订,指出&quot;相绪&quot;即马王堆遣册之&quot;霜绪&quot;,读为&quot;缃绪&quot;;&quot;炊緜絮&quot;即文献之&quot;吹纶絮&quot;。","categories":["02_字词句考释"],"year":2013,"publication":"语言研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0iuKC9floRUp9j7WufvF7sfnJjhlF_FCHW6KWBm01Nm0kbGWFycfD5v9UZRQst0y-HqKqmEM5Fy846N4Rvz0oYCYj92ZoJX4dcoTjyZ3LYlT2kxNNcVEQTXyTRPFVbGd6hz3u-OTFnzBPa_9OKwVeRcY41IUffxb29URE5CORsA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"313-315","volume":""},{"id":4445,"author":"张全礼","title":"读堇鼎铭文","abstract":"青铜器的铭文包含着丰富的历史文化知识,现把堇鼎铭文中的■、■和■,进行分析探讨,首先对堇鼎铭文中的&quot;■&quot;字,考释其词意,并结合古代文献和其他考古材料,去进一步理解这个字包含的古代礼制文化的内含;其次,通过&quot;■&quot;和图形文字&quot;■&quot;的排比分析,考释&quot;■&quot;的词意和本字,并根据它们的使用情况,结合考古发现,揭示商周鼎革之际,周初民族迁徙的概貌,进而揭示出堇鼎家族的族属问题。","categories":["02_字词句考释"],"year":2013,"publication":"首都博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIM--YS1cpifgsnl6SuhbptL8lzFX_DDJWrZdg54OWNSuxlLNfBBWaiUViW20radmHqD-HJ1gMLoUJWKtHWwzBes9zYkWw3CMzL94SooZsoNSn0wgYZOvl0mqFWsc9rjTDwLTtDpfO4NHl9T8qGnZzaLTugcHyKEXTyojtPeWTSWA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"230-240","volume":""},{"id":4446,"author":"祁普实","title":"宋公差(佐)戈考","abstract":"1982年,在北京铜厂废旧物资中拣选出一件铭文戈,当时释为&quot;宋公差(佐)之所造柳族戈&quot;,另发现在清代金石家陈氏所藏拓本中,也有同类型戈,唯族名不同,释为&quot;丕易(扬)族&quot;,笔者对两件戈的铭文进行了考释,认为柳族应释为茆(茅)族,丕易(扬)族应释为丕(邳)阳(汤)族,并结合文献和考古资料对铭文中两族的地理位置及两件戈的使用者身份做出推断。","categories":["02_字词句考释"],"year":2013,"publication":"首都博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJKURFY6n2aHw41q9OZrXBIQNuCg4wzlx6ZvVUCTxdhicfBLJKx2j-GPJ1VUBUKcuLnKWvcZz9kPYaQq8y5gb-0Ns82kHLwUUtNuCmtQPn-lYdFAUGv8qzPKnB_yvF5DSLnbSdiSLeF2jqsIgLt0q4g70UYX9HPmUB941t0Q9pkQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"241-249","volume":""},{"id":4447,"author":"蔡树才","title":"从新出文献看西周初期的铭文文学观","abstract":"简本《武王践阼》等的出土进一步证明西周时期存在大量铭文,而这些铭文实际也构成了中国文学的重要源头之一。铭文的记录、叙事、美颂等功能以及警戒、诰勉、不朽等内容都深刻影响了《尚书》《诗经》等传世文献所奠定的先秦文学。当然铭文也反映了西周巫术文化、祭祀文化和礼乐政治文明混杂的文化样态。","categories":["02_字词句考释"],"year":2013,"publication":"华中学术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJKURFY6n2aHw41q9OZrXBIQNuCg4wzlxnkpCtv2nUDCWg83cRPKCoRTln2AvVVFDFu4m0LD4_BawWb5V7YPcylq-Elb1ZB-O02yc5XgAlgi6ULk1LLBjole9VYlRvMR9Y7ryNhNYicY3yb0zFhmS-4AY9zVpJnx6ILr2RkaqcSw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-82","volume":""},{"id":4448,"author":"劉洪濤","title":"戰國文字考釋兩篇","abstract":"一、釋晉系文字的&quot;役&quot;《殷周金文集成》著綠的4688號晉系上官豆銘文,有下揭之字:A■一般把A釋為&quot;■&quot;,認爲是&quot;赴&quot;字的異體,①或釋爲&quot;■&quot;,②或釋爲&quot;府&quot;,③皆非是。我們認爲,A與戰國竹簡中的B是一字的異體。據我們統計,已經發表的戰國竹簡中B一共出現五次,主要有以下三類寫法:","categories":["02_字词句考释"],"year":2013,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLBXC7akOrU78xTylaImfxlm4tF0Rx2nLFoM4MXWTLE9IcJdTpbr8hjdl6hzZRseScAeYEptjyMitZz0_dL3GFRsVenoMn8lJP-xFQPJbwFfmTrw7B_Hyg14VENYAr2yTwL_FaC4RsdIHDLKM47lzgYifc2uvCRPPxLQCV65reVlA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-90","volume":""},{"id":4449,"author":"李學勤","title":"讀《繫年》第三章及相關銘文札記","abstract":"《清華大學藏戰國竹簡》第二輯刊布的戰國時史書《繫年》[1],其前四章追述西周歷史,第三章云:周武王既克殷,乃設三監于殷。武王陟,商邑興反,殺三監而立■子耿。成王屎伐商邑,殺■子耿。所說是武王卒後三監之亂等大事。這段簡文雖然不長,但在許多地方可與周初青銅器銘文對照,解答銘文中長時期懸而未決的問題。一個最明顯的例子,是大保簋（《殷周金文集成》4140）,銘文開頭為:","categories":["02_字词句考释"],"year":2013,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0zOFIBvUhyFpEckyGdeDw8pOSYeW48Wj2C8w-1A0BK30UfKz8ZakgfCobojwVAO2_6N1x2av0uCpQ3UqgvRNPZuhuyyr8IEhpw_1oMTIReBCV1bcVMi9GXEAO03W1uO-mB11k4BKDzThIvlNeJ6gBTABOiUt7ZyCnhxK5IT5NqXajy7DppFod&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-58","volume":""},{"id":4450,"author":"王子楊","title":"釋甲骨金文中的“將”——兼說古文字“將”之流變","abstract":"《說文·寸部》:“將,帥也。从寸■省聲。”又《說文·酉部》:“■,鹽也。从肉从酉,酒以和■也,爿聲。■,古文。”[1]從許慎的說解以及秦漢古文字“將”字形體看,“將”从肉旁是没有問題的。可是,學界一般認為甲骨文“■”即《說文》訓“扶”之“將”,“將”、“將”皆从爿聲,形體又相近,或認為古本一字,或認為音近而假。[2]總之,甲骨文“■”就是後世“將”的源頭。這就讓人疑惑,《說文》“將”的肉旁是什麼時候出現的?秦漢以上的古文字中果真没有从肉之“將”嗎?本文就嘗試討論這個問題。確定無疑的“將”最早見於秦印、秦簡和秦玉石文字,其形體分别作:","categories":["02_字词句考释"],"year":2013,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLQpngIMVvclrd7tnSVqTITDVVwdKGScvFSkedcdoOeiArUj7dFGWKWuz9V7rhvfnXS2XVHX0m9OGPVrdPFaH15dBm6XSajdsgIWY7hPjHvoR8uSYRciZdcqhh5tH798XuvjNrWeWUlIGLReUjREgzCL4sDnzFuVVDJ0aGxCCM6Pv8CCNT3TmwC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"115-120","volume":""},{"id":4451,"author":"李守奎","title":"出土文獻中“遷”字的使用習慣與何尊“遷宅”補説","abstract":"何尊是周初有名的銅器,銘文内容十分重要,受到學者的高度重視,研究成果非常多,但分歧也非常大。唐蘭最早詳細討論了何尊銘文,我們迻錄其釋文如下:隹(唯)王初■(遷)宅于成周,復■(禀)珷(武)王豐(禮),■(福)自天。才(在)亖(四)月丙戌,王■(誥)宗小于於京室,曰:“昔才(在)爾考公氏,克■玟(文)王,■(肆)玟(文)王受兹大令(命)。隹(唯)珷(武)王既克大邑商,則廷告於天,曰:‘余其宅兹中或(國),自之(兹)■(乂)民。'烏虖!爾有唯小子亡(無)戠(識),■(視)於公氏,有■(勞)於天,■(徹)令(命).苟(敬)富","categories":["02_字词句考释"],"year":2013,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQWNipG5jIWme6mU7eiELUQtKFRl2zLHdYsphbWTLJ5q95XJ7LOMjdS0nk8FqZb8VDJd-cQ2kn0sjKjB4kJK8ggWbU3pagFyIf8gCLtiI6FPswoCutDJHs9tLbmyptjZJ7H2ZagGRBVZuvKik6q7VAb2P0Bm3j0UeenJ6rVJVnzD6x8mDr6sr0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-129","volume":""},{"id":4452,"author":"吴良寶","title":"珍秦齋藏郾戈、鍾戈考","abstract":"《珍秦齋藏金·吴越三晉篇》[1]收錄一件三晉系有銘銅戈（見圖一）,戈的胡部鑄有下揭兩個字,原書釋作“郾寸（守）”,認為“寸（肘）”可讀為“守”,是“守令”的簡稱,此戈為魏國郾縣守令所監造（第172頁說明文字）。董珊認為,戰國時期的魏邑“郾”、“燕”與戈銘中的“郾”可能都有關係,“郾”在魏國南部,《史記·蘇秦列傳》記蘇秦游說魏襄王:“大王之地,南有鴻溝、陳、汝南、","categories":["02_字词句考释"],"year":2013,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItitFTYXJeyhCNwZJD1i5pYdPFm89WOt2srYJtFvkD5_fnVbkpPU59P2YgR9kq45Q9_jJwE3sajBJZyOrvbGcXfEhhzhx2JtT6h74cd5fHmuTfELQ24LQJqudpr0BeZjceZjFroY0I0LfeUePk6W0pnreqlf3ECljzbfl2HpBnyhcqjdibvG4c&amp;uniplatform=NZKPT&amp;language=CHS","pages":"136-142","volume":""},{"id":4453,"author":"王偉","title":"秦銅器銘文補釋三則","abstract":"一新刊布的一件丞相冉戈見於宛鵬飛《飛諾藏金》（圖一）[1],内部銘文中的紀年數字為銹所掩,編者推斷“最可能在昭王即位的初期”。這件丞相冉戈是目前唯一一件證明魏冉曾經擔任過“丞相”的實物證據。王輝先生《秦文字集證》中曾據《史記·六國年表》“昭王十二年,樓緩免,穰侯魏冉為丞相”和傳世十四年及三十一年相邦冉戈等資料,認為“冉實際上是以右丞相而稱相邦,這種情況文獻記載也或稱相邦”[2]。實際上秦武王二年分置左右丞相之後,《史記》等所記的秦“相”在絶大多數情況下","categories":["02_字词句考释"],"year":2013,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLk_czKGCWsa9U5Hh1Y5vmFyTYJNZubA42FY_nxuIosWOySNB92N_OmKNUvSU1SeF7Q2ZZKJaeylW6ZaURpj0VbOIWE6d_A2sXrTGMAaX2ekCwwuoU5wdV55xfK1rr_HZze1lJWYmyRI_vHLCwAquctbMZO-NMZ7O0JT-0OLDpTT6tAXlPkdwyZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-148","volume":""},{"id":4456,"author":"张滨","title":"试论汉字构形理论与汉字分析","abstract":"汉字构形理论作为中国传统文字学的重要组成部分,为人们提供了有效分析汉字结构和演变规律的方法,在汉字研究中占有重要地位。本文即以分析汉字古今字形为出发点,探讨了汉字构形理论在汉字发展史上的意义和作用。目的在于探索汉字构形理论的应用价值,进而找到一条有效学习和使用汉字的新途径。","categories":["02_字词句考释"],"year":2013,"publication":"牡丹江大学学报","link":"https://link.cnki.net/doi/10.15907/j.cnki.23-1450.2013.12.018","pages":"52-53, 56","volume":"22"},{"id":4458,"author":"刘书芬","title":"西周文献中“否”“丕”“不”的字词关系","abstract":"西周文献中&quot;否&quot;、&quot;丕&quot;和&quot;不&quot;三者之间的字形与词义的关系较复杂。西周金文有&quot;不&quot;和&quot;否&quot;,&quot;丕&quot;义通过&quot;不&quot;来表示;除了&quot;不&quot;作否定副词外,&quot;否&quot;也用表否定副词&quot;不&quot;。传世文献的《尚书》、《逸周书》中的&quot;否&quot;、&quot;丕&quot;、&quot;不&quot;三者皆出现,意义和用法已基本分开;《诗经》、《周易》只有&quot;不&quot;、&quot;否&quot;,《","categories":["02_字词句考释"],"year":2013,"publication":"广东第二师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRWEsZHEz4HJ5OrEhlwOSb-nEZt5WMu87mzLj0BhLnBMMem0j_JZNbwGIQ2NgHiBylxwOVJA3sF6ryg1Z5memOtR2LwYhorQGEGtgtyT0RSH9spJVKYuu9bTdmGsH8N__ECv8l7vqOwIhhFQtVG48ZJwsgzhi_ftIi_kfwIHW2pA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-77","volume":"33"},{"id":4460,"author":"李春利","title":"金文“某人”考","abstract":"金文中有大量关于&quot;某人&quot;的词汇,其中&quot;地名(氏名)+人&quot;应解为&quot;某族之人&quot;,金文中的&quot;地名(氏名)+人&quot;不能与文献中&quot;某人&quot;等量齐观,&quot;地名(氏名)+人&quot;加上私名或字表示单个人,其身份为职官,从&quot;地名(氏名)+人&quot;到&quot;地名(氏名)+人&quot;加上私名或字,显示两周时期政治血缘性向地缘性之嬗变。","categories":["02_字词句考释"],"year":2013,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_qOAcVl7cD04i7j-Vo6vdSg56cgMyuYGOua3x2w5GY3GmWNWxpFImOZhVw8218m3Rk1rJNdNTC8SZPR1i5Ng2JlJ9IjMqQIcu5_SGMykPjanCJW8tXb2iCst-cLUoSs0OSwNyjK4n9nrJ-9HpB_qSQoLOJaWLoMiCRRG-TMiw4w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-95, 99","volume":""},{"id":4462,"author":"白于蓝","title":"金文校读三则","abstract":"在以往研究的基础上,本文利用传世文献和出土文献两种材料,对金文中的三段文字加以校释,提出新的解释。","categories":["02_字词句考释"],"year":2013,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ26GF4Mf6B8eIo0_6Vqhpx4Ffgi-J0Fj-CQnHuj5wcfEcw13nfqL7weiGqHlaPMhe_ielmqF3bV83ywjDN1W3M_jFjkkl66gSEuedMTm88bYL3vX6sHm6_xrluyz82sFJ5n6IlpzEHCwqnAVoSPTrFLXnLPd9yCiyvotNF6WbeIQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-104","volume":""},{"id":4463,"author":"蒋书红","title":"论甲金文“册”之造形依据及简牍的出现时代","abstract":"简牍出现时代的确定,学界尚有争论:或认为与殷商甲骨文同时代;或认为更早;或认为晚于殷商甲骨文时代。依据对董作宾&quot;册六&quot;之辞的商榷释读,对甲骨文、金文&quot;册&quot;字造形依据的再探讨,以及甲骨文的功用等来综合判断,可以进一步推定,甲金文中&quot;册&quot;字的造形依据不是甲骨而是简牍,&quot;册&quot;字的本义是指简牍文册而非甲骨文册,简牍在殷商甲骨文时代即已出现。","categories":["02_字词句考释"],"year":2013,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2013.04.013","pages":"83-87","volume":"34"},{"id":4464,"author":"芦金峰","title":"论“疋戈为武”的形成和会意","abstract":"甲骨文中的&quot;武&quot;字早被学者识读。但有关武字的形、音、义三者关系,却始终没有得到较全面的揭示,从而使武字披上了一层神秘的色彩。本文将以甲骨文武字原形谈起,重新认识组成武字的两个字素。在确立组成武字两字素的基础上,结合武字的形、音、义形成,深入探讨武字的构形、从音的关系以及武字在甲骨文中的用意。结论显示:武字初意为足迹之义,且为神之足迹。武字从疋、从戈,武从疋音。","categories":["02_字词句考释"],"year":2013,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2013.04.018","pages":"15-25","volume":"34"},{"id":4465,"author":"陈正正","title":"易混字词考释辨正——以“侯”与“候”为例","abstract":"从字形演变上考察,侯和候是古今字,先有侯,再有候。从词义系统分析,候是为了记录&quot;侯&quot;引申义&quot;瞭望、观察&quot;需要,在侯字加上形旁叠床架屋形成的后起分化字。从社会文化背景考证,侯与古代射侯礼密切相关,是等级文化的重要表现。","categories":["02_字词句考释"],"year":2013,"publication":"吕梁学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWgqp-Obi_YfNedWxuiCxQYldQZl76qnRCYnOlvlRlV0NytH63xXg8tZNEooIjPOECAwNL_kc22eqJYLdFKCZbsbXKdOL5FZcRFEyDp2OB2fuBEMJEHZ4hdwlryhLMTvkxNZGJpIQ80cdHjsrenT6TrS7FhU8ppkzCOm67azODdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-21, 57","volume":"3"},{"id":4466,"author":"韩文博","title":"三省堂小学拾遗","abstract":"自《说文》出小学之兴盛被于千载。往来习小学者莫不宗《说文》,然又不可以其非而非,以其是而是也。及至近世甲骨文、金文、简帛文字发见以来,多补叔重遗漏,勘正谬误,至功甚伟矣。今从彭师习小学,经年有余,每于读书之际,或有感发,今草就成文,以期方家指正。","categories":["02_字词句考释"],"year":2013,"publication":"黑龙江史志","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQCyA5eA_CCRvOgWpZhNQohrcQb1tSGPwxUA9NdppduZJWbQbKS1o0sXN1hwF8-u8zrjsmljK_yAO1N0XoZsMO5XsmGD-DlGRqijRms9kO_vSQbVtcCx2Jdsc2ip3m_BWs8oHg0B7NJjHAZFGuz4ZB9cpkdqS7YVSMYC4vhC9NxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"151, 153","volume":""},{"id":4468,"author":"周宝宏","title":"引簋铭文补释","abstract":"本文是对近年山东高青陈庄西周墓出土的引簋铭文所作的考释,对已有的考释成果进行了评论,对一些关键字词提出了新的看法。","categories":["02_字词句考释"],"year":2013,"publication":"黄河文明与可持续发展（第八辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5msmuRVF_buxNvHW7fI-Few4vkcEE-JPRiL5dN0zlITM_BpwV5pYrYFgsfbno6wbqdAGWirMCOuRww4RrRWcUy4GC3QDdpgJ9xZrKugVUK_WUgXWTRKk3Nvy3gbyFxkyA6i5FAapg0evZJsnMlNh0EKufAhB4InL8hM7IpWIA21Cvv7nWOuc4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-81","volume":""},{"id":4469,"author":"王长丰","title":"殷周金文“亞且”之“亞”内涵研究","abstract":"本文认为殷周金文中&quot;亞且(祖)&quot;之&quot;亞&quot;是殷周时期五世而迁,另立新宗后,对新祖的称谓。","categories":["02_字词句考释"],"year":2013,"publication":"黄河文明与可持续发展（第八辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4zF8hv-k0fF2qYPCwrkHOFgnJ5SOYWdsNib6zOMTCSomiZqE7-avSnjB3pcE-BaQiMD7hK3U6KRrwMbT70PB44aNWpOTRfNbZ1TCDcnDfbHfSeuHAochuHuXnEEFqoItbkE3DehByXFejJx1ILO6nKSTBK9xfO4N0tsqy9_6QE7nUUgvZTkOc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-90","volume":""},{"id":4472,"author":"羅端","title":"從上古漢語構詞形態的角度再談商、周兩代語言區别","abstract":"本文考察商周時期的出土文獻以及先秦傳世文獻,以便找出充分的證據,能够證明派生詞綴的存在。在觀察了所有交替詞的詞彙意義的基础上,對基本意義和派生意義的顯現,做出時期的划分。單從詞彙意義來説,形態交替的證據都是西周晚期、春秋早期以後的現象。","categories":["02_字词句考释"],"year":2013,"publication":"历史语言学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaEoppmGetlyPtYcHoWdlHLvE_tDA3uwmoQ0tud0GByJVj206ENtxhK0zQb7xYDueIsmD1W-qbzqj7RO8ELILBxV5aUoIGrnsnh3W11dsE_H6LuvOpgN8-V1AN5Ikteq2ZzWpaYL-9-bM_UlTtQTnUHzcBtp4k8_q4AcNFSQVGzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-68","volume":""},{"id":4475,"author":"黄鹤","title":"西周金文王号为生称或死称问题述评","abstract":"本文对西周金文王号为生称或死称问题进行述评,并赞成王号死称说;并认为这些铜器在发挥标准器作用时,应考虑不同联系条件,具体问题具体分析。","categories":["02_字词句考释"],"year":2013,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLHR0gMkGYKNnu6Kdd9LA1wBwhYpDOCURE1XLvkRJCkRxbrbcI-Ft5zPgPiiJmZTKPmsm84UECDhWBqR_XxnDZecmywKQXyBsvPOORtynE35K5SHLiN3aZ4cfJhJbz2UUO4EI1KccSUOpgQagEnVSy7_UvJ5KxBTAVXlnCezPkcaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-27","volume":""},{"id":4476,"author":"李瑶; 孙刚","title":"东周齐系金文所见古史传说辑考","abstract":"东周时期的齐系金文中有很多与古史传说有关的内容,&quot;禹&quot;、&quot;九州&quot;、&quot;成汤&quot;、&quot;伊尹&quot;、&quot;黄帝&quot;、&quot;陆终&quot;等已见于当时的铭文中。通过对叔夷钟镈铭文的研究,可以发现至迟在春秋时期人们已经承认&quot;禹&quot;及夏代的存在,并已经有了&quot;九州&quot;的观念。陈侯因齐敦铭文中有关于&quot;黄帝&quot;的记载,对研究&quot;黄帝&quot;传说形成的过程具有重要价值。邾公钟中的&quot;陆&quot;即是&quot;祝融&quot;,二者应是同一传说人","categories":["02_字词句考释"],"year":2013,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGYlm0cG5jWhlh9hOMZH4iUUAlTvO4z_6S5zFep7l17T7rKTyjWIOK4Xref0zp0JNxTyGicA6Ehp-gfqgkt6uqVmcMgCTY6-l4YP58cxjLzc_Ww9Yk3Tq_DCE0JIOKyMQ2_1XVusf0l3kSGVg9eVI5AxxuGUON9GQF1o0zW501ZQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-31, 73","volume":""},{"id":4479,"author":"迟玉梅","title":"平行法则:早期上古汉语中“者”的出现","abstract":"文章为覆盖前期上古汉语Pre-archaic Chinese(公元前14世纪至公元前11世纪)与早期上古汉语Earlyarchaic Chinese(公元前11世纪至公元前6世纪)的历时性研究①,目的在于更好地揭示早期上古时代所出现的&quot;者&quot;之功用。研究表明,&quot;者&quot;的功能与前期上古所出现的&quot;之&quot;的功能间存在着&quot;平行对应&quot;关系,我们将此关系定义为&quot;平行法&quot;机制,此机制从属于&quot;类比&quot;。存在于&quot;之&quot;与&quot;者&quot;之间的&quot;平行法&quot;机","categories":["02_字词句考释"],"year":2013,"publication":"江南大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL4YM0NwndJSd2XAxLxT2eds5XywHNRoxmmaq_INDwpz6cuR4nW9NaJKdjIOH3Dw7iJ-5LxzKRs2ZmTzbJaZEcmkevs7KVYngo-Ztkk5E4fJVl91vlz0J3Qs9qzzPykaBPWRwLZv6KbrnwIfvf38ly8ao6aj3nd7XtH5tthZ-g6Gg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-124","volume":"12"},{"id":4480,"author":"刘厅","title":"中山王■鼎铭文“咎”考释","abstract":"上个世纪70年代以来,战国时期的中山王墓葬群和灵寿故城遗址被次第发掘,其出土器物繁多、华美,让史学界震惊不已。特别是闻名于世的&quot;中山三器&quot;,器表遍布隽秀的铭文,将严整规矩、悠长秀丽、刀法洗炼的战国金文展现于世人。其中一号墓出土的&quot;中山王■铁足大铜鼎&quot;(下称大鼎)铭文469字,是国内已发现的战国时期铜器铭文中字数较多的,为有关中山国的研究提供了宝贵的资料。大鼎铭文&quot;■&quot;(隶定为&quot;■&quot;或&quot;■&quot;)当释读为&quot;咎&quot;。它的存在,同时揭示出《礼》与《易》的文化影响在当时不仅兴盛于华夏诸国,","categories":["02_字词句考释"],"year":2013,"publication":"文教资料","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvnnFau870jMznpcKBn752hGGBc1za-A6PJT591vGk6uKNiYvsjBmGxnYYFlPZDNXeIzHiWkup9j8FAZqShUzS_CS7HlMRMlJyPCjkwFyegvRBha3WAWpOe2BnUCRGUCiTk6i_9C39_Xl3jU_2fEAdm6pEUPg17aHZGSCnzvuPtvZn4YTZ7gDY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-44","volume":""},{"id":4482,"author":"王珏","title":"宋代《复古编》“规范”小篆字形“走”对元明清篆书的影响","abstract":"北宋张有《复古编》所谓规范小篆字形&quot;走&quot;,有悖金文字形,而且与人奔跑时的手臂动作也不相符。元代小篆&quot;走&quot;绝大多数承张有写法,明代基本承元代写法,清代随着文字学研究的深入才逐渐回归正确写法。","categories":["02_字词句考释"],"year":2013,"publication":"文化学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWE996_MB8Pjs1NFw4UvCkgRibXXiH3nIdW5z_TJxrwpBDopsdXVbGTLJNzDzBRbMNy7SRS6wObtxZy7mua2HkQMujfJAteSu9ZChEX-YC9XWWnQUlfBC5tFn1pinl7jpcVp2eJ9X5I6RWz3C2uVg3YaDEzt1tpMf7NSsvnQd6Cw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"159-163","volume":""},{"id":4483,"author":"梅新林; 俞樟华","title":"“学术”考释","abstract":"&quot;学&quot;与&quot;术&quot;是分别独立出现,各具不同的语义;然后由分而合,并称为&quot;学&quot;之名;至近代才有今天所谓&quot;学术&quot;的意义。","categories":["02_字词句考释"],"year":2013,"publication":"浙江师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKj3Qlq0-D6TmSgCI0eiwOTWLNalru73XwfRpaDu-JEAwDgYImFYjTj6x9XX-P2ThPSuTn2Zx-1XaxSpsJxV30jhGaH4RlPLQp7hor3X1U277EGoLHerEqgfVfAjCCGT_GjZ5t-eQOWUcfH30vffDTI5uzLBu_p7bL5JOLWf_ltJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-26","volume":"38"},{"id":4484,"author":"谭步云","title":"古文字考释三则:释狐、释蒦、释飲/■/酓","abstract":"通过对狐、蒦、飲/■/酓三个未识古文字进行考释,揭示其形体的演变途径,分析它们在具体文例中的意义,并论及与之相关的文字的源流关系,力图解决一批出土文献释读的问题。","categories":["02_字词句考释"],"year":2013,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2013.06.007","pages":"63-68","volume":"53"},{"id":4485,"author":"陈斯鹏","title":"西周史墙盘铭新释","abstract":"通过对西周重器史墙盘铭文中三处争议较多的字句进行考释,可知:(1)&quot;髟伐尸(夷)童&quot;中的&quot;髟伐&quot;应读为&quot;剽伐&quot;或&quot;摽伐&quot;,为近义连文,与西周金文的&quot;敦伐&quot;、&quot;撲伐&quot;、&quot;搏伐&quot;等同例;(2)&quot;■尹■彊&quot;应读为&quot;万尹亿疆&quot;,&quot;万尹&quot;言各类职务长官之多,&quot;亿疆&quot;言国土疆域之广;(3)&quot;岁■隹(唯)辟&quot;的&quot;辟&quot;从用字习惯看不宜作开辟解,而应训作&","categories":["02_字词句考释"],"year":2013,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2013.06.011","pages":"69-72","volume":"53"},{"id":4488,"author":"謝明文","title":"说交鼎铭文中所谓的“即”字","abstract":"交鼎(《集成》2459)铭文作&quot;交从兽(战),仇△王,锡贝,用作寅彝&quot;,其中&quot;△&quot;字,旧一般释作&quot;即&quot;。陈剑先生根据金美京女士读&quot;即&quot;为&quot;次&quot;,意为&quot;比次&quot;的意见,认为交鼎&quot;仇次王&quot;理解为&quot;佐助王&quot;,&quot;交从战,仇次王&quot;是说交跟从时王出去征战,在王的一方佐助王①。研究者之所以把&quot;△&quot;释作&quot;即&quot;,主要是因为其左边与&quot;簋&quot;之初文相近,又&quot;逑△王&quot","categories":["02_字词句考释"],"year":2013,"publication":"文史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLGnyewGok-_5jHC7Y8xE8lf9271rnmmlMuPbhjQUHyR3rstBeOBULRr2zmopRexFBLZfRQE61iucOJPxLFp8Ut87Q6cUOG3nGbOqoTp1FlroawYNUmtyzpksOSC27CthfEXaWSWtylyRGmi1o4aCfTWSdgX-IcHXedv9l7bdsmhIUWWuFgx9by&amp;uniplatform=NZKPT&amp;language=CHS","pages":"265-266, 42","volume":""},{"id":4489,"author":"郭利芳","title":"春秋金文的异体字与构件差异","abstract":"春秋金文是西周金文向严重异形的战国文字的过渡阶段,从异体字的角度分析此期文字,从构件的角度观察其地域性,并比较春秋金文与前期文字的异同,尝试寻找文字发展演变的轨迹。","categories":["02_字词句考释"],"year":2013,"publication":"名作欣赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJVKrv5Xl4ErHe1NWTFhwPVv4SnYx3I6EJIg3NFq_s4rYcH9zr3mS44WPGTXXirrbXiSMxhBeSUoXRj33GFy875xcePPMqs1Gmzx760js9i9i_79uhfBoTHX2W6SSzZnMn9Yzw1JU2b_VBqmrYj-Snsax95t7pZHr4z_PvDMtrB1w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-33","volume":""},{"id":4494,"author":"陳英傑","title":"古文字字編、字典、引得小史、事、使、吏等字目設置評議","abstract":"史、事、使、吏一字分化,這是文字學或古文字學界公認的意見。①但對於古文字資料中史、事、使、吏等字的字際關係的認識,學界給出的都是一些概括性的籠統說法,記錄這些詞的文字形體是否有一定規範,這些詞在形體上的分化開始於什麼時代及其分化的時代層次如何,學界並没有給出具體而詳確的答案。本文對《甲骨文編》、《續甲骨文編》、《新甲骨文編》、《甲骨文字典》、《甲骨文辭典》、《甲骨文字編》、《金文","categories":["02_字词句考释"],"year":2013,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIT4O04ZyNVWJD0Vt2BWYRvTQ0kWvNVpOA5B-MpLEK18njf-oU5JzeSOPLFxddgoWDFeh57DOW1UOnYTXDyjFYZNCAZkAUKihPDUbpFi6_A1Z1mKZAPYDUpSXDcijblJI4-ZLW7B-kfDA9yOffy657yEa9pjqNTtcKtEvO8iBFryA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"555-572, 579","volume":""},{"id":4495,"author":"赵晓庆","title":"《尔雅》中“台”“朕”“阳”三字的重新解读","abstract":"《尔雅》是我国第一部训诂学专著,它把古代意义相同或相近的词收集在一起用常用词进行训解,保存了大量古义,为上古汉语研究提供了宝贵资料。但由于年代久远,后代人已很难读懂它,为《尔雅》作注者虽不啻百家(仅《尔雅诂林》就收雅学著作九十四部),但有些条目的解说仍然存在争议,现以新视角、新材料就其中一例详加考证,以求新解。在《尔雅·释诂》中有这样几条:","categories":["02_字词句考释"],"year":2013,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKnaqM3nCDGKgdcWbqkWSzEGXJVLxLLgNCZu1NcbAcVKvIf8iiFcv7UmI-TkUmK2yqlcb004Kxka_dBNwuOOYKXn_T2zDjirZqlkMcH7cKuoBgPccpTA8BlensfW0N302XaBu498shDKP5oVTKrzvW7nbcGZ0VCfmS4GX-_Tjql4w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-30","volume":""},{"id":4496,"author":"徐再仙","title":"齐国币文构形研究","abstract":"本文主要通过研究齐国币文,探讨齐国币文与一般文字的构形差别。并总结出齐国币文具有繁化、讹变、装饰、省符的叠加特点。","categories":["02_字词句考释"],"year":2013,"publication":"剑南文学（经典教苑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL8xgPTFPU_tLU0BS9IOu7giiVHqN4jBconPYe7RKutrVKoEoY4G-uUvVovXL7BPOwUR9EQPzlSVaNOWvw9g01EOy4stgfJJnygjAOVI_zg8Ql9aMw7Oy6SdYwO5Mn8qwWWQX1EcrYzNn-0ikcu0LIKp4DF61vw_b28ifgsVVdOXQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"172-173","volume":""},{"id":4497,"author":"丁世卓","title":"浅谈“射”“矮”颠倒论","abstract":"&quot;射&quot;字和&quot;矮&quot;字的意思是不是颠倒的,是古人弄错了还是在使用过程中发生了交换。从矮字的创造规律和射字的演变过程我们可以看到汉字字型的讹变,了解汉字的发展过程。","categories":["02_字词句考释"],"year":2013,"publication":"现代交际","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIRaWZw4XjRhOujTH0SGEIh4Y0qebhcMsUpegNWUfQUFwnMYhaGq-GpiuDSSTna0oIq9qRVvm9mV_byhDOqZHatAKJTlS1HU5poqcwg-7ijWCI8nnCizphKRcaq0YOx4-BAG3ojFLFwQrdqk-PMBVWC1hfQBckZiX47vziNd_SevA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30","volume":""},{"id":4500,"author":"王进锋","title":"春秋宗妇鼎铭文别解","abstract":"春秋宗妇鼎铭文中的&quot;王子&quot;是姓氏;列公意即列国国君;宗妇是指同姓大夫之妻;昔阝馨的称名形式是&quot;国名+姓氏&quot;,指代昔阝国的馨姓女子。宗妇鼎铭文大意是:昔阝馨——她是王子姓的列国国君的同姓大夫之妻——作器保治昔阝国。列国和昔阝国过去没有引起学者的注意。对于宗妇鼎铭文的考察,使我们开始关注到这两个侯国。列国位于战国邯郸附近的列人地;昔阝国先位于陕西鄠县,后迁至蜀中的临邛。它们的姓氏分别是王子、馨。","categories":["02_字词句考释"],"year":2013,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI70MOl8jmWT1_byW1Ig8goH8Hmcw59h9IbRADr_oQeQBF9IxBjHTQqqfThI3XgpXf6Gp9viNndyMz62nHJiAOI3DU225tnfYhI5NlxL02fyydog8ataDeW-08TD-wLntvCoslDgfh1sWNElMwX7PZzD4msprwjZSaMcIzwTVEsPQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-37","volume":""},{"id":4502,"author":"李学勤","title":"字源研究新的里程碑——《字源》序","abstract":"追本溯源是人类共同的兴趣。在汉字研究领域,对于字源的探求,同样令人着迷。在先秦文献里,已经留下人们探求字源的印迹。《左传》宣公十二年:&quot;夫文,止戈为武。&quot;昭公元年&quot;:于文,皿虫为蛊。&quot;《韩非子·五蠹》&quot;:古者仓颉之作书也,自环者谓之私,背私谓之公。&quot;都是通过分析字形结构,追溯造字意图,来阐明某种理念的。这种风气,对于六书理论的形成起到了强劲的推动作用。","categories":["02_字词句考释"],"year":2013,"publication":"历史教学（下半月刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJlPTM-pIgRjRwU5iWybr23zX8vpAIakmd3z7TFamYNjuk7wmP6hz_XhqhscTIpFYNz-TQKV5XdVXWUGgJQjGTyTR-gj7H3NC6nX1TEcd3Z6obpJDAzggR3VN0fnhRaz8Z_iX8jbRCiYr22ZFc2PGkFq4cye8jzoTfQOg0STc8w0Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72","volume":""},{"id":4503,"author":"刘秋瑞","title":"河南出土的战国文字材料及其研究","abstract":"河南历史悠久、文化浩繁,所出土的战国文字材料内容丰富。其铜器铭文、兵器铭文、货币、陶文和印玺历来受到众多学者重视,对铭文的文字考释、史实考证及战国文字的分域研究是学术界关注的焦点。应在疑难文字的释读和历史文化价值的探索等方面对其进行全面系统的研究。","categories":["02_字词句考释"],"year":2013,"publication":"河南科技大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15926/j.cnki.hkdsk.2013.05.009","pages":"46308","volume":"31"},{"id":4505,"author":"阮朝辉","title":"鼻音、边音汉字造字规律考","abstract":"通过对声母是鼻音和边音的两类汉字的形音义的逆向梳理,发现鼻音和边音汉字的造字规律是:凡声母是鼻音的文字,该字的元初意义所指称对象都跟人有关、或就是人本身的称代意义;凡声母是边音的文字,该字的元初意义所指称对象都是动植物或抽象行为、事物、条形物。","categories":["02_字词句考释"],"year":2013,"publication":"贵阳学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.16856/j.cnki.52-1141/c.2013.05.023","pages":"94-100","volume":"8"},{"id":4506,"author":"张延俊; 吕晓薇","title":"殷周金文“蔑历”的语法结构和意义","abstract":"殷商西周金文中的&quot;蔑历&quot;基本用于被动式,在主动式中则一般为&quot;蔑某历&quot;。&quot;蔑某历&quot;的语法结构是&quot;VP·间接宾语·直接宾语&quot;,而&quot;蔑历&quot;的语法结构是&quot;VP·直接宾语&quot;。&quot;蔑&quot;跟&quot;赐&quot;、&quot;赏&quot;的用法类似,意思是&quot;赏赐&quot;。&quot;历&quot;是一个名词,只能在句中充任宾语,它由&quot;厤&quot;、&quot;甘&quot;二字组成,意思是&quot;佳肴&quot;。因此,&quot;蔑历&","categories":["02_字词句考释"],"year":2013,"publication":"长江学术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmSCAJxwTTDoB0qO64j9_h09Yi2u1LSYF8vQgiYs8Ocwt5uLJhRN-ycvNBA2cCJfUqz6yYrwVT0vvQnDEpaL0LPPij8WCnQa2pz56ejY7QEEOC9PiNufE8-6iV_369PF1eM27gvvD-H6ptYpHiLGGXeL6J3-LQKBmeebCudR8zwQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"90-93","volume":""},{"id":4508,"author":"张桂付; 赵怀贵","title":"来自金文的疑惑","abstract":"在学术界,把商周时期铸造在钟鼎上的文字,统称为金文。金文《小臣艅犀尊》拓片上,共记录了二十七个字。首行竖读为&quot;丁子王省夔且&quot;。按照历史上六十甲子的干支纪年法,用十天干:甲乙丙丁戊己庚辛壬癸,十二地支子丑寅卯辰巳午未申酉戌亥,共同组成了六十进制的纪年表。其中最大的诀窍就是阴阳天干地支互不相见。只有这样才能组成六十进制的纪年表。如若是十天干、十二地支都能相见,那么它们一周的轮回只能","categories":["02_字词句考释"],"year":2013,"publication":"书法","link":"https://link.cnki.net/doi/10.16769/j.cnki.31-1067/j.2013.10.020","pages":"53","volume":""},{"id":4510,"author":"郭洪义","title":"《大唐愿力寺故瞻法师影塔之铭》释文校补","abstract":"《唐代墓志汇编续集》公布的《大唐愿力寺故瞻法师影塔之铭》释文错讹甚多,严重影响了对该通塔铭的有效利用。本文通过校补释文中多处可商榷之处,分析误因,避免以讹传讹,以便使这份宝贵的材料得到更科学地利用。","categories":["02_字词句考释"],"year":2013,"publication":"学行堂语言文学论丛（第四辑）——2013年全国博士生论坛（出土文献语言文字研究与比较文学学研究领域）论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBD_wtfS45dTRdiZBod2VNw_iSDN1bHFDropPPEYeTF7JMtlC8xj3jIoCG2LMOOJAjwN5nhBI_7_opfXgZjaaas4kXjopT80NsNcwV4ZBWYbm92v28DpBahj84juZvuJPgxCmOor8czSpFRX821UmLVlJfJBHu5Q7O578YnUm54e5zlmtWXyBg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"218-228","volume":""},{"id":4511,"author":"王月婷","title":"“如字”考辨","abstract":"古代注释中常用&quot;如字&quot;标音见义。关于&quot;如字&quot;的含义,主要有两种认识:(1)如字指本音,即构词变读中的词根音;(2)如字指当时的习用音。通过用例考察发现,用来标音见义的&quot;如字&quot;可分两类:(1)如字不是词根音,但是习用音;(2)如字即词根音,也是习用音。据此,并结合当时的切语用字以及&quot;如&quot;这个字的意义可以推断:&quot;如字&quot;指当时的习用音,记录相应的习用义;它们跟本音、本义不是同一概念,但时有重合。同一字的两个或以上读音若皆常用,则或不标&quot;如字&quot;、或以本音为如字。","categories":["02_字词句考释"],"year":2013,"publication":"中文学术前沿","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQZiY3pcdBJRrJWRs6L-hq4Kr9LzPvauudh2VK7mwnlaDn-tUqj02NA6fMSKwezSYLq07l5hgJ6SJmXVQi24h_HIkD4y1suhFU_Q2Y7T1Rc9hxwVpEj4K0mDHHB9xijM-9iY-0ABZvaDXNExWITqaDNeW1KHMPDbGIxUfhq9dqQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"181-187","volume":""},{"id":4512,"author":"朱德熙","title":"古文字考釋三篇","abstract":"一釋倉&quot;倉&quot;字西周金文與小篆寫法無異,例如:弔倉父盨鐘但在戰國時期,出現了一種新的形體。《綴遺齋彝器款識》(28·10)有鄭東盦,銘曰:圖一奠(鄭)東蒼(倉),(半)(見圖一)此乃韓器1。第三字當釋爲&quot;蒼&quot;,讀爲&quot;倉&quot;,此乃韓東倉之器。末一字當釋&quot;&quot;,乃容量之名2,方氏誤釋爲&quot;盦&quot;,以爲器名,非是。古璽印&quot;蒼&quot;字的寫法與鄭東盦近似:","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgmQaznuuatA0bxMj4kazfsFUogiDzWc5U9kiJGigsDNoAe2vBtcXsJRDp0kjzrV-OCVvQl9UpTZfc3XlqCOTc4HSw5B0JzaCSw-mzZAuICod8YZXN4QohOHwXbtecHVjrYCabQggt7c-2z2IbvlUQ2o_zwWWgFDLtPwma6E4POQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46027","volume":""},{"id":4513,"author":"陳劍","title":"釋“疌”及相關諸字","abstract":"一有關字形、用法及諸家説解湖北隨縣(今隨州市)曾侯乙墓出土的竹簡中,多次出現一個&quot;从又持兩倒矢&quot;形之字,皆用爲車器名1。簡文中還有幾個有从&quot;&quot;、&quot;糸&quot;或&quot;竹&quot;从之作的字,用法完全相同。有關字形擇要列舉如下(後所附摹本採自《曾侯乙墓竹簡文字編》):","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgmQaznuuatA0bxMj4kazfsFUogiDzWc5U9kiJGigsDNoAe2vBtcXsdQuM2sMlZjnC6CsL8vx4tj8n2U3CubWUFOhThaf9LsWMKGJs2jwtUzxon56doT9YrkEqROrISccnu2KS1Vvo6NHZQ6kVh88ofWQ0z12prxM1lDNzckFybg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"258-279","volume":""},{"id":4514,"author":"周忠兵","title":"説古文字中的“戴”字及相關問題","abstract":"一从首(或从頁)从之聲(或弋聲)的戴字戰國文字中有以下幾個相關的字,字形和辭例如下:A.■B.■C.■(1)首A茅芙(蒲),筱(蓧)執樝(鉏)1。(上博六·慎子曰恭儉5)(2)惪(德)之流,速(乎)B(郵)而(傳)命。(郭店簡·尊德義28～29)(3)是以視賢,履地C天,篤義與信。(上博二·容成氏9)這幾個字在簡文中的文意都比較清楚,A可以和《國語·齊語》中的&quot;首戴茅蒲&quot;對讀,可讀爲&quot;戴&quot;2。B可以和《孟子·公孫丑上》孔子語&quot;德之流行,速於置郵而傳","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL5DgD_tuolwBMUhGsLvgkUpdzfudElgQbz0ECZwGiPSXXeR5geP6C9S0CQoqZgGEhYudSR7R6rl3plIgY8sjUEMc-v0JLFgoYkRMajDJGMizl93vOfI0j3d6Tv_4KrNYhLO-9JAH6m41r-vW8oL0Llu-RvP7KhkGW627Ld-B4CpQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"364-374","volume":""},{"id":4515,"author":"田煒","title":"西周金文字詞關係的共時與歷時考察","abstract":"目次一、引言二、西周金文字形與音義關係的共時考察(一)共時一字表多詞(二)共時一詞用多字三、西周金文字詞關係的歷時考察(一)西周金文與商代、東周文字資料字詞關係的差異(二)西周金文字詞關係的内部歷時差異(三)字詞關係的完全替代與部分替代四、西周金文字詞關係的影響因素(一)用字規範與寫手的選擇對字詞關係的影響(二)詞的特指意義對字詞關係的影響(三)詞的社會意義對字詞關係的影響","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLeg_tuqA7qVRmmr3A4guL7DnRREEP0iWxzkZC8e3OVGd4w4euA8sAhCnplXBId8_lmNXqV6WL-jwhd4i_JMyax6jl9CHw19qA3wCeUzlm8nMU00zodoCe4_NHhHTOaU_xwkBoeaLJeLJWZO6Q1T8fRsTtA9w0b2ayNBAUbgHLORA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"162-215","volume":""},{"id":4516,"author":"鄔可晶","title":"説金文“■”及相關之字","abstract":"西周中晚期金文中有如下二字:A.■B.■所在辭例分别爲(釋文用寬式,下同):師旂鼎:旂對厥A于尊彝。(西周中期)1匜:伯揚父廼成B,曰:乃可湛,汝敢以乃師訟……(西周晚期)2A在有的文字編裏被摹作&quot;从死从貝&quot;的■3。于省吾先生指出此係誤摹,A實从&quot;丮&quot;,&quot;古文字从丮與从又有時同用&quot;4。郭沫若認爲A从&quot;斤&quot;5,大概受了下文會","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJnBBi1NnDUrs2Mpei8MCDLBatzaqJ3_S6i7KhWi3zZhefKWe6_tGlfXDDiGnUS1tNdkV-kOay12cHqiDVNDmcMI9giw-UERETa8MGShrLaxvz9Et1etgXNmcZc2WojSjf_fPxMTaiXORZUvoR2Qhn2NQMwMXktdi9JRbmm8A7ubw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"216-235","volume":""},{"id":4517,"author":"謝明文","title":"晉公■銘文補釋","abstract":"晉公■1(《集成》10342)銘文,流傳的拓本分爲兩類。《殷周金文集成》(下文簡稱《集成》)、《集成》增補本、《殷周金文集成釋文》(下文簡稱《釋文》)等收拓本爲一類,《三代吉金文存》18.13.3～18.14.1、《金文總集》6925、《北京圖書館青銅器銘文拓本選編》(下文簡稱《北圖》)259、《商周青銅器銘文選》(下文簡稱《銘文選》)887等收拓本爲一類。前一類拓本拓缺&quot;大廷莫不……&quot;一行,清人著作中關於晉公■銘文的摹本","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJnBBi1NnDUrs2Mpei8MCDLBatzaqJ3_S6i7KhWi3zZhefKWe6_tGlfCqmR3RhGxuzb5zfOYEtFoMP7xd6KVNKymCKJQ7f1-uCiiMS-MsVO7CcgCvxcfrC5BwpN0tipwXugddft5wU_CDbS2h5HoXfILsK5LXML4WoUYR8JyTmXhg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"236-257","volume":""},{"id":4518,"author":"魏克彬","title":"温縣盟書T4K5、T4K6、T4K11盟辭釋讀","abstract":"趙世綱先生在温縣盟書的發掘報告中對T4K5、T4K6以及T4K11盟書坑的發掘情況和盟書的内容做了詳細的介紹1。我根據盟辭内容將T4K5和T4K6所出盟書分别命名爲《聽耳類》和《討賊類》,T4K11暫不定名。本文將分爲三篇,擬就上述三類盟辭的考釋分别談一點補充意見。這三篇均分爲以下幾部分:盟書的出土情況;盟書釋文;文字考釋。考釋中用&quot;△&quot;來代替正在考釋的字。需要明確字跟詞的區别時,本","categories":["02_字词句考释"],"year":2013,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJWF0zuJXduEa7bxgomsPrZhtZwtrgFjIiLp_Oaf4b5WOZZrsa_3VYZHLpALjppotARNW3bKr3f4jP2VvaqKrCzmksT_QBDiJsS04-I8A61cjQDBAa-ruxqdQRpxpp49felOxXiSQ1iAePZ7QPlSmrGgA5vIuGtsdwuWFI6oYHJ-A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"280-363","volume":""},{"id":4524,"author":"李义海","title":"西周长铭金文中的自释","abstract":"自释是早期汉语文献中常见但又不为人重视的一种行文范式,它的整理与研究,不仅有助于拓展汉语史、汉语修辞史的研究视野及其领域,而且对深入探讨汉语句式的发展以及论说文体的形成也有着重要意义。","categories":["02_字词句考释"],"year":2013,"publication":"阜阳师范学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.14096/j.cnki.cn34-1044/c.2013.05.006","pages":"46149","volume":""},{"id":4525,"author":"窦苗","title":"汉字中的“虎”","abstract":"本文通过将甲骨文、金文、小篆对比,繁体字与简体字对比的方式,对包含&quot;虍&quot;的部件及汉字进行追溯和分析,藉此考察包含在汉字中的虎文化现象。","categories":["02_字词句考释"],"year":2013,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHRGYACjj8XJDZlghckRMcVz5JwR8cy4NtGjWx2fdTlwjv9kqkfbEy9dsQO3OTJ7PJe-EjopTPZMnZgQEiBgswdacvvXjXyexhVfwcYEmbm8qYHTh6zMs79Hq8qggaPq3EOnavvIpzXIJXHbv6GZv39_j5Un065392fYZ3R7rq91RPgGxjQcsm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-39","volume":""},{"id":4527,"author":"易德生","title":"金文“玄镠”新探","abstract":"东周金文中频繁出现&quot;玄(铉)镠(翏)&quot;(或&quot;玄镣&quot;)这一专有名词,该名词到底指称何种金属原料,学界观点不一。从东周青铜器合金配置角度看,结合文献及音韵学有关知识,&quot;玄镠&quot;可能是指称东周普遍出现的&quot;铅锡合金&quot;;&quot;玄镠&quot;之&quot;镠&quot;和后世文献中出现的&quot;连&quot;、&quot;镴&quot;音近且同义。","categories":["02_字词句考释"],"year":2013,"publication":"江汉论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvyundDG0OYDvOuzLsimozlb6gX_8UQbgthIw4mFBXhjGq43m7OrXiytSAiH5pvvdYA0eY9T96zGhO4RIY11gB2gnP3TbWfl9-Gcl8kSdPLv1p0oEWG9PeicHPAXz-rnyB5DbpCHFN-q0JH6af0gLp3eEjeZQHIwLvkME0fffA-Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-124","volume":""},{"id":4528,"author":"张素凤","title":"谈书写对古汉字结构的影响","abstract":"从目前发现最早的商周文字到小篆,很多字的结构模式发生了变化,汉字结构变化的原因十分复杂,本文主要分析书写对古汉字结构变化的影响。汉字书写者对于字形简便、有别和美观的追求及书写时有意无意的&quot;变异&quot;,都是导致汉字形体变化的重要因素,而汉字形体变化往往又导致汉字结构模式的改变。","categories":["02_字词句考释"],"year":2013,"publication":"兰州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8wtgo_jUi2t_LvtJ3CUOLCX2CFv7P5MMFgJyLFM10kmYFiv0lJbGL01Fao3XfKyMiseTuyVhn5a-muizg7RtLTb-yrgAlbduEvQEsNpp1R4hnn5CZWt2fJYd7TvBUqAu9v9WendpKET5jbquUszVX_yfFMjEoi2dNfHx5AF7Oxw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"180-184","volume":""},{"id":4529,"author":"武振玉; 梁浩","title":"殷周金文实词虚化研究","abstract":"殷周金文中的一些实词虚词并见现象,为探讨上古汉语实词虚化提供了很好的参证语料。从词义虚化的路线看,有经历了&quot;动词→介词→连词&quot;发展过程的,如&quot;暨&quot;、&quot;及&quot;、&quot;以&quot;、&quot;用&quot;;有经历了&quot;动词→介词&quot;发展过程的,如&quot;于&quot;、&quot;在&quot;、&quot;从&quot;;有经历了&quot;动词→时间副词→范围副词&quot;发展过程的,如&quot;咸&quot;;有经历了&quot;动词→时间副词→关联副词&quot;发展过程的,如&quot;既&qu","categories":["02_字词句考释"],"year":2013,"publication":"求是学刊","link":"https://link.cnki.net/doi/10.19667/j.cnki.cn23-1070/c.2013.05.022","pages":"149-154","volume":"40"},{"id":4532,"author":"黄锦前","title":"荆子鼎与成王岐阳之盟","abstract":"文章从字形等基础性环节入手,认为荆子鼎铭的&quot;■&quot;实即&quot;荆&quot;字,&quot;荆子&quot;即&quot;楚子&quot;;通过对器物年代、铭文内容的综合分析,考证荆子鼎铭的&quot;荆子&quot;即见于文献的楚王&quot;熊绎&quot;。又在李学勤&quot;保卣、保尊与斗子鼎记载的,正是成王岐阳会盟诸侯的史迹&quot;说法的基础上,结合文献进一步推阐熊绎在盟会上所扮演的角色,同时也进一步证成了李说。最后,根据相关出土和传世文献所提供的信息,对岐阳盟会的时间作了具体推定。凡此可补传世文献记载之不足,对先秦历史文化研究具有重要意义。","categories":["02_字词句考释"],"year":2013,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIx69nmqXy7XoWw6DytG2i_4kankSCUdsuYMrDumqm5UYhDZc9aqYfzC6VCXmA5Xt8ZFKymUPHnjIhkYhwYGTBBNsb7PwI_bA4d8ZC9T8w2ZHLnjHzrUO97Tgic61IkYtMMfbrFCEG1EEdw7EajM3ec2qpxcIAFITiEEqAtCmw6Fw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-70","volume":""},{"id":4536,"author":"洛地","title":"“樂”字音义考释","abstract":"&quot;乐(樂)&quot;,对其起源、本义、读音的考釋,古今歧说极多。本文作者以为:&quot;樂&quot;本义为商之谛祭;其读音当为y。&quot;音乐&quot;之&quot;乐(uèy)&quot;、&quot;欢乐&quot;之&quot;乐(uòl、l)&quot;、&quot;疗(iáol)&quot;皆其延伸义。","categories":["02_字词句考释"],"year":2013,"publication":"音乐艺术（上海音乐学院学报）","link":"https://link.cnki.net/doi/10.19359/j.cn31-1004/j.2013.03.015","pages":"82-90, 5","volume":""},{"id":4539,"author":"周宝宏","title":"鲁叔器铭文考释","abstract":"本篇是对新出西周早期鲁国青铜器铭文(或称鲁叔四器)的考释,主要以铭文中&quot;■&quot;字作为考释重点,并以此作为立足点,解释了其他关键字词、语句的含义,从而揭示了叔尊(卣)铭文中心内容是鲁炀公命令叔到鲁国教鲁人对新建成的宫室举行打鬼、驱鬼的仪式,得出了与朱凤瀚认为是鲁炀公命令叔教育鲁人遵守法规、董珊认为是鲁炀公命令叔建立宫室两种说法不同的另一种说法——打鬼驱鬼说。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKV8Rls_oLSPuISzAMzB5pdYiTI2xJiw1PZe-GdKu3_b0OyI6ijv-poLG2_wZRewN9KtU49B9yLog8k5aFAT_Um1uXLTTCbRk1HELed7cjsHNqGWC6thqq-f3HP28rbwSw7Qgv0LRrd7jFmhRpNfjALjMaYRTVNWdmLoePnE0Yrrw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-33","volume":""},{"id":4540,"author":"董莲池","title":"释公贸鼎铭中的“牝”","abstract":"本文对鼎铭中一般释为&quot;牧&quot;的形体重新做了考证,认为应该释为&quot;牝&quot;,铭中所用是承袭商代用字之习,表示牝牛。由此对铭文某些内容做了新的解读,提出器主应是&quot;■&quot;,所谓公贸鼎应改称■鼎。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIP8K3aI3pd839pKAr_GAS6YDs-_3ITuP_CbPcMSyjiWYRHC27wAQtmqX7nkTdDRnSephxKLRV4xlip_p5Nsp5jQlhHUs0EovEVHRughgca1JVPn61rfZ1MZUYw4sIrkYSFKchLyfEwTy6929qi71LDQBsrM47zgM0aRz-w4teXbg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-39","volume":""},{"id":4541,"author":"张再兴","title":"殷商西周金文字形块面成分演变研究","abstract":"块面是早期金文中的常见书写形态,在金文字形演变过程中逐渐消失。其演变的途径可以归纳为线条化和轮廓化两类。本文以定量数据为基础,探讨其演变的过程和特征。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFe35uLaDMcgnssh70TCxAUtQk70AHwGa4vdfz6Jv9EVEBwc5CLVfqYuW2G6J4vbly7EQFOFPIiFt254KC-kQ-bczcAeTabqyoVrQ9mQF98dCx-Rg4TbAaHYbvKRp8gM8r9E1RdnFpXuFlq7gFmFOM6uj5hDnRf9WbMVFEVXWVaQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-48","volume":""},{"id":4542,"author":"庞光华","title":"“李”字形声结构新考","abstract":"&quot;李&quot;字的形声结构问题让许多古音学家很困惑,&quot;李&quot;是来母音,为什么《说文》会称其作&quot;子声&quot;呢?古文字材料显示&quot;李&quot;在上古时代有从来得声的现象,在战国时代的秦系文字中是作&quot;李&quot;形。汉代以来的文字系统只是继承了秦系文字的结构,从来得声的&quot;■&quot;从而失传。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKOENsoIpBe8W25M5qW4gh9HTNAqHSrUUWgNrFQm8ps-YJgK20wG0qXHSPOksw0FOcAOiPTp-A8ndrpOhjXRBECwU5E7q2P98Ul5FrLTsw1-O4XIT4nrBWXE7RZ4yKn_qIcGmRMKEhUlZsqfas0kEva2BoMKTjeSKA9_mADkDJ5w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-51","volume":""},{"id":4543,"author":"禤健聪","title":"说“■”","abstract":"通过战国秦汉筒帛文字材料与两周金文互相印证,将楚简读为&quot;卫&quot;的&quot;(?)&quot;字分析为从戈、&quot;(?)(谷)&quot;省声,&quot;(?)&quot;是表护卫义的&quot;卫&quot;的专字。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMfW7Xlbfzqt8MLj52pICNmwDQpKFcgyZbDjDj6q2UIWFS-iawAuT4bj9ZkIO27HgGD15CCJYKYDZBHb25HagL9SuoJBNf1EH5urPFPLWrUzyLnE2kmY_d9NJye-pw_fl61GjN8s73wv2x_96GCUFkrN-sweltciwBkcXJGJH23A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-55","volume":""},{"id":4544,"author":"谢明文","title":"伯句簋铭文小考","abstract":"本文根据相关金文认为伯句簋铭文中的&quot;京&quot;应该读作&quot;粱&quot;,&quot;■&quot;应该释作&quot;■(稻)&quot;,&quot;(米焦)&quot;应该释作&quot;■&quot;而不能释作&quot;隹少&quot;,并讨论了其他铜器铭文中与之相关的一些字。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITuBIecbpURadlMnz38Y-mlpmk8J30rbAIW26RU48G0GTj_ppsOvRvmc0teERDrNoO7Q3gbK7Y8ZaYPNgqkxTm4O2ZDN1wKWn10p5VMHH6tHXtMX6Acwi3ax0p-d_aL9BNjGJRakwv8lL4Cr_Rl2lHDmmmz4yVDaB9r6T1YktD_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-59","volume":""},{"id":4545,"author":"王保成","title":"■字新解","abstract":"考察&quot;■&quot;字的形、音、义,推勘相关辞例,揣摩上下文意,对比相关字的语法功能,考究诸家之说,&quot;■&quot;字左上所从乃&quot;翼&quot;字初文,该字&quot;从丮羿声&quot;,在西周金文中假作&quot;继&quot;。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJBKFmlIzsbxR7ZTbm1RIA2FzJR6UwqkxUpgw037Qjrm4EiEOcLrikGjO2Thgfj6utjDIC95YfeG9VAsZkMfoC2ijr7ByeSBhrZs_g3_NDjF4TBRoF4LSA7TWVj0sE91VXiqsBLwtswjR32z53N0MomvDjpS4BTYugJm2ed3xFj1A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-83","volume":""},{"id":4546,"author":"肖攀","title":"包山简文字补释三则","abstract":"本文证补了包山20、47号简中的■、■乃从耳丁声,是&quot;圣&quot;字的一种异体;&quot;捭&quot;是楚人名常用字,125号简■可确释为&quot;捭&quot;;并从包山简中的&quot;■&quot;字出发,通过字形比对,进一步确认了古文字中&quot;■&quot;与&quot;歬&quot;的典型区别特征。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJk-qUMtK64Cjp_6RMKAejo98bC9Ew0_wFYXBjO7ijJekdTumGoOi2bHx_E6h2brZX9ihgV4wSQrjmysuozFIIhOO7tiTQ76A5I8M4eGq0QkMe2xhb6PPrHfHmvXoi0jvFrtWM2nYsFWQRpr2sGswqlWORhp5taf5GVjjrjUfAC5A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-100","volume":""},{"id":4547,"author":"黄鹤","title":"段簋“孙子牵引”补释","abstract":"本文主要对段簋铭文最后两字释读为&quot;牵引&quot;一说进行补证,并解释&quot;孙子牵引&quot;。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI56TJJbCaunlDtkSr-wWM4wsEMsI7uKh3tPL4pteqInAuIbMiQ4ZdwnDuZxavtQTC4W8djgEeYpURXot9ZqtUXv2qSkeWj0uJe1l9mQGDb44yNdIn-OkhGQRa9k4CQt-jsHWv2HfdNACcKbF44IoWVY_wLQTt6k6NaftDttvF8fg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-103","volume":""},{"id":4548,"author":"余淼淼","title":"季姬方尊“■”字补释","abstract":"本文通过形、义两个方面,论证了季姬方尊中的&quot;■&quot;只能隶作■,可读作&quot;畋&quot;,李学勤之说可从,而释&quot;卑&quot;,于形不合,于义不通,非是。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGPfUViFuKx4PimftH_kDojMfPgxgUBkQ4Gig5TVmSVTHo-HGkGRW_UV8S95zpPww874gSUz0h_BpUamWtPRnGhDD5PeXs4P50YfR-SOpUPtcvjoMfXxmxADNHnyf1-njuyN4o77B5Z6LqQM7mzGEULoJaYK8Wcniz6J5qm78snA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-106","volume":""},{"id":4549,"author":"夏利亚","title":"会意字造字表词方法举例","abstract":"古汉字造字表词方法的探索,有利于正确把握字的本义,有助于阅读古籍,为考释古文字提供有益帮助,对汉字教学也大有裨益。文章总结出了几种会意字造字表词的方法:1.特写强调法;2.提示符号法;3.关系表示法。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIb42bOdYz3yLTQEbS4CMfe_9HBBuXl0HxLEJHhmffbZfdZ_BRN8Hz21z72rfGAgYpDMcsaV_BjV8sDeHwELUfwMCkBG0nESbrLsjm7j-58dc0SJRFN2p8EQ6YQCa_JFSCFKx9XRJCrCFl_bt9Zr8O_JUdD82l4ysbeWdNWfTsKeg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"183-186","volume":""},{"id":4550,"author":"龚嘉镇","title":"汉字核心字根的构形表意及其历史演变","abstract":"数以万计的汉字是由四五百个基础字符组合生成的,内中52个核心字根具有超强的构字表意功能,其参构字在小篆字和现代汉语通用字中都多达七成以上。核心字根原是按物绘形表示类概念的早期象形字,它们的集合字词对应地反映了汉语语义的核心网络。语义化、偏旁化使核心字根成为基础的形符与部首,形声化则将字根的形义联系扩展为对字族的类联系。汉字逐步由单字的用物象表形发展为系统地以类符的语义表意,成为以象形字为基础、以形声字为主体的表意文字。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIDH3zy66C0_FDMNMZGDxQcao8gCsvabpTk9j3_YgooAsR6MbgkcLopDD8jcwuZqmMYXfwRZQbmo7MgCUtCqCkQDYxZoyHxVIyQTaywDuui7eM8EnKICskJ_eEiGqKpkEZDDpwnv1aI1sQMoYnddkpU3rcfP7121TXJkjmGpWZvA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"193-204","volume":""},{"id":4551,"author":"许嘉璐","title":"释“和”——附:释“齐”","abstract":"&quot;君子和而不同,小人同而不和&quot;,孔子名言已为妇孺咸知、多国皆晓,传播之速、认同之广,乃夫子所未能预期者。然则何为&quot;和&quot;?何为&quot;同&quot;?二者何以对应?差异何在?遍寻古训,未见&quot;精确描绘&quot;者,而当世似亦鲜予探赜。而不深究之,则至理名言难不&quot;泛化&quot;,言者与其所行或以不深知而脱节,乃至悖逆;闻者视为口号,颔首者未必首肯。是以略费笔墨,试穷《说文》所现&quot;和&quot;字之义,或非无谓也。《说文》口部&quot;和,相应也。从口,禾声&quot;。甲文未见&quot;和&quot;字,金文形体略同,","categories":["02_字词句考释"],"year":2013,"publication":"中国训诂学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6g8xm69FGJZcJWO50-5dBydlI_To3KfFNL6y1U86SJXjmt2ADOnSGhS5XYAStxPkMX3b4rmSgOZEN34pm62bC_uUhotQuJzWR4UETkqwVRU0eOpCfPEpeB_fdXwvp8wjERWfDQRh6TALOE6VT4aF3YDuh0HcdeqhC1Q_QIJpT-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46027","volume":""},{"id":4552,"author":"周鹏","title":"大盂鼎铭文“已”字辨析","abstract":"大盂鼎铭文■字写法比较特殊,学者多主张释为&quot;巳&quot;,少数主张释为&quot;也&quot;。释&quot;巳&quot;者一般读为&quot;已&quot;,也有读作&quot;祀&quot;的。读作&quot;已&quot;又有看作语气助词和叹词的不同。我们赞成释读作&quot;巳&quot;(已)和认同&quot;已&quot;是叹词的看法,并从文意、字形和语法史等多方面进行了辨析。","categories":["02_字词句考释"],"year":2013,"publication":"南华大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLidW5rEIzkUjR1v64DYCNA3Fg_qaz-Bz33-FPoKC1ozw_NplMgWs83ffS4WoJFPjBGM_v5YZSVLXgtdB4vBv6pE9cdCfdVh22xQQ8q-xosLXqxusJCVWz-PEkekNF_Ogx9F5JHCOFHvvFnlq1N3RlSsWYXyT13MFX1WkxkPpLEwg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"110-113","volume":"14"},{"id":4554,"author":"苏影","title":"邓公盉铭“公”字补释","abstract":"自1992年邓公盉出土面世以来,铭中&quot;公&quot;字,目前有&quot;共&quot;、&quot;公&quot;和&quot;未识字&quot;等三种解读意见。通观整篇铭文,发现其下字&quot;尊&quot;所从的偏旁在铸刻过程中错放了位置,导致学者们对&quot;公&quot;字误读。","categories":["02_字词句考释"],"year":2013,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcqljbjhNVyaF3ESr2WPFzRUOxINVIF9__Oc-SBE87VzzvMl65amzO_mdHAdG8TbYMZ7OU_uDwF6HuEajEqIrElo3YTVkRn8prE0pXQx8I7nxcG76q9mdZWQWJ4eD5js75vgAtsYRBBc28OmrLQw6lC2MBqAEWBzIB5-u5lQ2ce83JO7scR41w&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-37, 2","volume":""},{"id":4557,"author":"曲艳秋","title":"论周代金文中的方位话语及其文化内涵","abstract":"周代金文中有大量的方位话语,这些方位话语除表明事物的方位特点外,还具有丰富的社会文化内涵,涉及礼仪、军事、等级、方国等各个方面。","categories":["02_字词句考释"],"year":2013,"publication":"青春岁月","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIa6h69i5NacVEgNRtKmLfJfVai1V12zSjPGQWUTUL_Xy75GZxyrfl7Pvaghknpwk3AZV987e99MPYc_6f18tw8G8FLLf-bNtjWvzezZmVseB1iQGT7nSLXJOcYZ706eiXa7TO4JNNIPZLS9wbl0_3iwH9G5-VmKjgAVQWkvuhtHQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"122, 121","volume":""},{"id":4558,"author":"吴世花","title":"多角度试究汉字的性质","abstract":"汉字的性质一直是学术界争论的热点,本文从汉字记载语言单位分属、汉字记录语言的手段以及汉字自身的形态三方面分析了汉字的性质,认为古汉字属于表词文字,表形、表意、音义文字应该根据古汉字造字法分别论述)和图符文字,现汉字属于语素文字、表意文字,字符文字。","categories":["02_字词句考释"],"year":2013,"publication":"青春岁月","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLT83-wzxpDkMYT4aSfgaFWFRYgsTZ1ZkT1guE2NK02ZJ1xTtDf9TwVHXVHuX0YxtcD2o-TxP0hTb4a2T4rskIs8Z_UY4_F_opo65BCQVL8s8DG4bft2ZuwNDuxzLlG2gWFowFSRnaciZLjGNf8lhJ_9sccqAkWFLgwtai13FejIA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"142-143","volume":""},{"id":4559,"author":"汪紫丹","title":"春秋金文构形的区域性分析","abstract":"春秋时期,同一字形在不同的国家会产生不同的形体,存在着一定程度的区域差异。但如果我们从整体体统上比较各个区域文字后就会发现,它们的单字和单字的各项构形属性基本上是相同的,总体上仍属同一文字系统。其构形的主要特点是音义参构,之后义符系统、音符系统的稳定以及&quot;隶变&quot;的产生都是以此为基础的。","categories":["02_字词句考释"],"year":2013,"publication":"安康学院学报","link":"https://link.cnki.net/doi/10.16858/j.issn.1674-0092.2013.04.007","pages":"30-32, 43","volume":"25"},{"id":4561,"author":"罗卫东","title":"邾国金文及其相关问题研究","abstract":"笔者依据《商周金文资料通鉴》收录的61件邾国有铭青铜器分析邾国金文。它们既有传世的,也有出土的。出土地点包括山东省滕县、新泰县、邹县以及枣庄市等。本文计划考察现存所有邾国金文字形,比较同词异写、异构现象,描写分析不同地域、不同历史时期邾国金文的特点。例如&quot;邾&quot;字,传世的《邾讨鼎》写作■,传世的《寻伯匜》和《邾大司马戈》写作■■,1933年山东滕县出土的《鼄义白鼎》写作■,2002年6月山东枣庄市山亭区东江春秋小邾国墓地出土的《邾公子害簠》写作■,1981年山东滕县庄里西村出土的《妊爵》写作■。本文拟在考察邾国金文地域、时代特点基础上,联系《左传》、《史记》等文献典籍,验证前","categories":["02_字词句考释"],"year":2013,"publication":"第四届汉字与汉字教育国际研讨会论文摘要集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKsRjkMUJXg1pxgakj3b1-Bfg2aux0UYBDhwdaSKGxSRO5ND_3jaMfOwyRzwZQ14_20gqK3siOnb3MvpfQPzxN_DKHigMzKrTFDoTAPSBlRcUYNtJGU92K3SE86O86NVR6A1PrZojLcM4ezDVim-1Rxv19CGuJj6e6azFQiD54V_mxRY0xATfF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69","volume":""},{"id":4562,"author":"姜库","title":"商周青铜器铭文风格问题探析","abstract":"青铜器铭文始于商朝中后期,西周时最盛,战后逐渐衰退,前后历时近一千年。书体不断演进,美与美的创造也不断地丰富、更替、完善,从而可以看出人们开始有意识地追求字体的审美风格特征。两周铭文的艺术特色更为强烈,也更加丰富而多样,铭文书体艺术演进的特征比殷商更明显,随着商代晚期至西周早期书写简化对以象形字为基础的原始仿形的改造,正体规范的社会性需求即开始显现出来,以大篆的形成为标志,较早地实现了书法审美的自觉。","categories":["02_字词句考释"],"year":2013,"publication":"大众文艺","link":"https://link.cnki.net/doi/10.20112/j.cnki.issn1007-5828.2013.15.071","pages":"88-89","volume":""},{"id":4566,"author":"刘益明","title":"说“侃”","abstract":"目前主要的工具书对&quot;侃&quot;字的训释与现实生活脱节。《说文解字》对&quot;侃&quot;字的解释属于误训。&quot;侃&quot;字在殷商时期就已出现,其本义为喜乐、愉悦。裘锡圭先生认为&quot;侃&quot;字最初是一个表示&quot;衍&quot;的假借义的分化字。现代汉语口语和方言中把带吹牛意味的闲谈叫作&quot;侃&quot;,这种用法在元代就有,它属于&quot;永&quot;、&quot;衍&quot;和&quot;侃&quot;三字的共同引申。&quot;侃&quot;字的刚直一义很可能是假借义。","categories":["02_字词句考释"],"year":2013,"publication":"成都大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLOn6g2dqOiHjd8ko2FiP5lfp3LFXhaM-eWu2e4J6Hs2Emk3Pwq7_zvJTN_z1yxH51WO1w4Fqawzg5T_yv6Sh39_pdBvU5Rf8vhyiszv6_ceHVwNQleXONBss--0g24-5ugE4VG37CyrPb6WzGfkVSM9AuFMvgkjtRgaiEm1xL5IQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108-111","volume":""},{"id":4567,"author":"樊俊利","title":"从战国时期六国金文角度看汉字的隶变","abstract":"从本质上说,隶变是整个汉字系统由象形系统向音义符号系统转化的过程。在这个过程中,战国时期六国金文和秦文字一样,也积极地参与了进来。它们或调整字形,呈现与秦文字一致的隶变步调,或另辟蹊径,形成自己独特的隶变风格,但隶变的广度和深度都不如秦文字。笔画平直化、方折化也是六国金文最常见的隶变手段。","categories":["02_字词句考释"],"year":2013,"publication":"语文研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQy7vm3bL7M5RmeIpqKV__IYcx3w3uKAoimocn9RX6MQ_X9PDrv-I0o7UZRmABiqVUbvB6wTt-XWN4yU1qW0CF3B-1LtUiQtFMlM9EOyPzGzmWYjQ9vC-4yRtjRtUkKDp6C81eNGRxBRoHI7E2q7A3kcmrqXYEbbfNXDpkMiud2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46245","volume":""},{"id":4570,"author":"孙合肥","title":"舒城九里墩鼓座铭文校注","abstract":"舒城县九里墩墓1980年9月发现并清理发掘,出土珍贵器物共183件。其中有铭文鼓座1件,见于发掘报告。①对出土鼓座铭文的解读,学界已有初步研究。本文在诸家研究的基础上,对铭文内容作进一步的考校。九里墩鼓座是至今发现的两个有铭文的鼓座之一。②相关著录有:《考古学报》1982年第2期、《安徽省考古学会会刊》第五辑、《古文字研究》第十四辑、《安徽省博物馆藏青铜器》五六、","categories":["02_字词句考释"],"year":2013,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkn5jpw7HD1-GBf7MQABsI3-PvkSuSb-OGVNAYQy0pXOCPMKWjoPAB6l0MDcZvB9dFMPRdN_LOyiH5O4QHfTbVeMD7pVcoSE9r6CF4zjYlWZZbi3iBd3C3LfEgDGlF_mBP8ezGRNLufkEVSHJb6x5wnCfN1g28nJZUc0ZR832Pcw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"181-187","volume":"59"},{"id":4573,"author":"刘杰","title":"秦封宗邑瓦书铭文研究述补","abstract":"战国秦封宗邑瓦书为目前所知陶器铭文中字数最多的一件,也是具有断代意义的战国秦系文字材料。试对其铭文研究情况进行综述,并结合新出材料对其中部分铭文的释读进行补充。","categories":["02_字词句考释"],"year":2013,"publication":"湖南科技大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJbQzEa0tbNl32_GpFpEYz30DIeQyK1VzrtKCOKwojRECOFPYBnRxlBM6j0jjOvala3a73PJL3Xytw4vrPiegzpRA7ZY3FV4kpgSJoiq_Tu96V10G9sg2p2gb6aOScJ2dZzDSfeKXi4St1nUkaujRz7buuCaB-ONWENihWgf_ZGGg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"165-168","volume":"16"},{"id":4577,"author":"曲冰","title":"谈谈楚文字中的“■”及“■”","abstract":"&quot;■&quot;在楚文字中有多种读法,与金文中&quot;■&quot;字用法不同。治理之&quot;治&quot;金文中写作&quot;■&quot;、&quot;(辭)&quot;,楚文字多写作&quot;■&quot;。&quot;■&quot;可看作治丝之&quot;治&quot;的早期象形形体,&quot;(辭)&quot;为其分化字,&quot;辛&quot;当为&quot;■&quot;的附加意符,表示治丝的工具。楚文字借&quot;■&quot;记音,又孳乳许多以&quot;■&quot;为声符的形声字,其中&quot;■&quot;为楚文字&quot;治理&quot","categories":["02_字词句考释"],"year":2013,"publication":"齐齐哈尔大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13971/j.cnki.cn23-1435/c.2013.04.010","pages":"87-89","volume":""},{"id":4578,"author":"王晖","title":"从甲骨金文与考古资料的比较看汉字起源时代——并论良渚文化组词类陶文与汉字的起源","abstract":"目次一仰韶文化小口尖底瓶与甲骨文&quot;酉&quot;、&quot;畐&quot;及相关字出现时代二从&quot;丙&quot;形三足器、鬲形器看甲骨文&quot;丙&quot;、&quot;鬲&quot;出现时代三从考古资料看甲金文&quot;宫&quot;、&quot;雍&quot;等字出现时代四良渚文化组词类陶文性质与汉字起源时代五小结中国文字的起源不仅是中国文明诞生的组成部分,而且是最重要的判定标志,因此这一问题受到学术界的普遍重视。自从1899年发现了比周代金文更早的殷墟甲骨文之后,探讨中国","categories":["02_字词句考释"],"year":2013,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLX92ouT9P4YtYltOJ0Bbsr2K9idTVJBYaKCJN7YbN_Yk2wDN1zckAaEYw_Ww2KmprwojjViHkqgRLp3Cl0DvloVNBpzNlo6YkYI7BKcrs00VbAuLlgqedB16Dh-2erMUTVh-MAQ1zxnzK8GXDPpmCzRQOZel7m35lWMWcgBi2oFw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"283-296","volume":""},{"id":4579,"author":"王宁","title":"说“莱”","abstract":"殷周金文中有*字,曩不识。根据甲骨文和金文的&quot;鶆&quot;字可知此字当是&quot;莱&quot;的象形初文,乃蔓华之象形,也被假借为&quot;鶆&quot;。殷周金文中均用为国族名,即莱国,不过这个&quot;莱&quot;和东夷的莱国无关,当是与殷商同姓的子姓莱(来)国,本是为商王负责捕鹰养鹰以辅助田猎的部族,其地当在今天的安阳附近。东夷的莱国当是鷞鸠氏,乃是以鶆为图腾的东夷部族,为少皞族之一支,它很可能也是嬴姓或偃姓。","categories":["02_字词句考释"],"year":2013,"publication":"洛阳师范学院学报","link":"https://link.cnki.net/doi/10.16594/j.cnki.41-1302/g4.2013.07.011","pages":"46-49","volume":"32"},{"id":4580,"author":"王少林","title":"高青陈庄■簋铭文考释及相关问题研究","abstract":"山东高青陈庄M35所出■簋,器主之名不能确释,当依字形定名为■而非&quot;引&quot;,■的身份是齐国的高级贵族,可能是卿的级别,疑与天子命卿制度有关。铭文所见齐师当为齐国之军队,其辖属权也归齐国国君所有,而非周王朝所有,西周金文中所见的诸国军队为周王室所派官员职掌,多为联合作战时的统一指挥问题而非诸侯国军队归周王室辖属之证据。周王命■司掌齐师可能与周王烹杀齐哀公相关,其细节史籍记录不详,故只能做推断之辞。","categories":["02_字词句考释"],"year":2013,"publication":"洛阳师范学院学报","link":"https://link.cnki.net/doi/10.16594/j.cnki.41-1302/g4.2013.07.020","pages":"40-45","volume":"32"},{"id":4581,"author":"魏金光; 何洪峰","title":"介词“向”的语法化源义辨","abstract":"先秦汉语存在大量假借现象,形、音、义关系复杂,导致实词语法化源义不易确认。确定介词&quot;向&quot;字的语法化源义首先要厘清&quot;向&quot;与&quot;鄉/嚮&quot;的形义关系。&quot;向&quot;字自甲金文至楷定形,其形体未变,本义表示北窗,或表地名、姓氏;在用字上,&quot;向&quot;与&quot;鄉、嚮&quot;通假,&quot;面对&quot;和&quot;趋近、前往&quot;是其假借义,也是其语法化源义。&quot;鄉/嚮/向&quot;作为方向内含性动词,具有[+人,+朝对,+移向]的语义特征,在典型的连动结构中具有很强的介词化倾向。","categories":["02_字词句考释"],"year":2013,"publication":"汉语学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPZTmg1Xsqgjwxr5A9gMuNZQRWMIFwe43TGvQgCKo19rT_s055CVF0ND4X8G3u0-cBmCce41HkOTFtPvClG9poD-H6ma2Y0C9sdmr6MEacfoP727qD103NoM4DgxYioQ3kiRVGs5fnazUSu26sMUWkMKj34D5SKwqQjUE36fIujw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-67, 96","volume":""},{"id":4586,"author":"杨于萱","title":"殷商与西周铭文中“赏”、“赐”二字语法辨析","abstract":"周代宗法下的封建社会,长期实行等级严明的礼乐制度,以巩固其政治伦理。当时君王对于臣属时有赏赐,此类事件往往铸于鼎彝,成为足以与经传文献相互佐证或补充的实物资料。殷商、西周金文中之赏赐行为,大致可分为君王对公侯伯等群臣之赏赐;公侯伯对其下属之赐;诸侯国及臣属间之互赠;公侯伯等臣属对王之贡献等四类,综观上述的各种赏赐行为,可见赏赐行为实为殷商、西周政治运作之重要支柱,居上位者借&quot;赏赐&quot;行为以显示自身之权威,下属因受&quot;赏赐&quot;而有沐浴上位者恩惠之感。诸多学者先进对于&quot;赏赐者&quot;&quot;被赏赐者&quot;与&quot;赏赐物&quot;之间","categories":["02_字词句考释"],"year":2013,"publication":"国际汉语学报","link":"https://link.cnki.net/doi/10.14095/b.cnki.jics.2013.01.016","pages":"163-170","volume":"4"},{"id":4589,"author":"毕秀洁; 王继红","title":"谈谈商代金文与籀文的关系","abstract":"本文考察了商代金文中与《说文》籀文形体相同或相近的字形15个。通过对这15个字形的对照研究,得出:从文字的发展历程来看,籀文来源于商代文字,是商代文字的延续;籀文是西周晚期宣王时代普遍使用的一种文字的观点是可信的。","categories":["02_字词句考释"],"year":2013,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKnVtIguqgXg2ghmx-ZCf6q_janBizMfsGcD7dXjN76Vy3BHVPbOwuuO1vcmHKyV9tFS4su-UP7VwAkfvKXj05tpSxbKaXvcSJW7PqzWze2Yhos0lsbshDihNyijGuaO7cEn85DeAqDgt3Q712X9fLj8H3CV5g9Rjbogm7HIFDWhx1-iKwp9UwS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-85","volume":""},{"id":4591,"author":"贾澎","title":"古文字时期形声字义符的特点探究","abstract":"形声字的表义功能主要是通过其义符体现出来的,义符这一特点的形成不是一蹴而就的。形声字义符在甲骨文时期象物性强,数量多;金文时期形声字义符的图画性逐渐减弱,具有一定概括力,但异体仍较多;小篆时期形声字义符异体大量减少,示义能力更强,具有高度概括性。形声字义符的这一特点是受到文字学主客观因素影响的结果。","categories":["02_字词句考释"],"year":2013,"publication":"河北广播电视大学学报","link":"https://link.cnki.net/doi/10.13559/j.cnki.hbgd.2013.03.004","pages":"62-64","volume":"18"},{"id":4592,"author":"曲艳秋","title":"试析周代铜器铭文中的人物形象","abstract":"周代青铜器铭文作为历史散文的重要组成部分,内容丰富,许多铭文都涉及到对人物形象的描述,且人物形象类型众多,运用了多样的描写手法,使我们可以从篇幅并不是很长的铜器铭文中捕捉到许多生动的人物形象特征。周代铜器铭文的人物描写成就主要体现在人物形象的丰富类型及描写手法等方面。","categories":["02_字词句考释"],"year":2013,"publication":"三峡大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvCdplHYHCoX2K4QtpU6k1YZVUWDkSVKTp2w56t_UyPnXZhu_Mi7SFxJUhJTzU7kj4PgmPj_MoKZtVHYvdj8H_4y0dF1VNRdpAXErZiJoWTc64B1Tx9fxzBjnficRXJektmQzFM0YKafClPTZyZ1rQ-ZllFuhehI6K83cWG5ImXA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"139-142","volume":"35"},{"id":4593,"author":"王晶","title":"西周铭文法律词语“■”与“许”训释","abstract":"西周涉法铭文中的法律词语部分的研究尚有很大空间。这里,我们通过对西周涉法铭文的梳理,整理出了二个法律词语&quot;■&quot;与&quot;许&quot;并加以训释。琱生簋:&quot;必伯氏从。&quot;其中&quot;■&quot;字作","categories":["02_字词句考释"],"year":2013,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIOzQCsK7sti9-LxMmH2IIkGVOVdNye-7i7kjVPgnHuFZw7X3izhHwTQ03ecFbMgvV4GTPHPIf2R9zAKqXy38D-MxebRMc8OqJ4BXXca-aodJT2LR_GMp8qfWvUWudm-ePtpiGtfwX07v_WGXtVZV1_W_jop3ZKZq2liNo5iaJ_3Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-67","volume":""},{"id":4598,"author":"李义海","title":"别白行文与北庸父己爵铭文考释及其文化意义——汉语国际推广背景下中华地域青铜文明系列论文之二","abstract":"郭沫若、唐兰、陈梦家等先生以行文条例为视点进行的金文考释,不仅推动了商周金文研究的跨跃式发展,而且还丰富了文化考古学的研究成果与研究方法,为修辞学研究提供了新的领域和学术增长点。","categories":["02_字词句考释"],"year":2013,"publication":"龙岩学院学报","link":"https://link.cnki.net/doi/10.16813/j.cnki.cn35-1286/g4.2013.03.007","pages":"37-40","volume":"31"},{"id":4599,"author":"王晖","title":"甲骨金文■、■、■为“双音词组文字”说","abstract":"在商周甲骨金文中,&quot;■、■、■&quot;这几个字每个都是单独的一个字,但在句子中却分别都是两个词,也就是一个偏正性的词组,我们称之为&quot;双音节词组文字&quot;。在秦代之后,它们变成了单音节词,但仍然是&quot;词组文字&quot;。","categories":["02_字词句考释"],"year":2013,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2013.02.012","pages":"70-73","volume":"34"},{"id":4600,"author":"杨秀恩","title":"春秋金文反书研究","abstract":"春秋铜器铭文中有反书的共477件,占春秋器总数的30.58%,分布涉及各个器类,时间贯穿春秋早期到晚期,地域分布涉及秦国以外的当时几乎所有诸侯国。有反书的单字共101个,情形分独体字反书、合体字整字反书、合体字部分构件反书、合体字某一构件易置并反书四种情形。春秋金文中的反书无区别意义的功能,是甲骨文系统&quot;正反无别&quot;构形特点的延续。春秋金文反书的数量与功能表明春秋金文文字系统尚有较强的象形性。春秋金文单字反书字频比例与西周金文的比较表明:在象形程度上,春秋金文文字系统与西周金文文字系统无明显的阶段性差异。","categories":["02_字词句考释"],"year":2013,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2013.02.013","pages":"74-78","volume":"34"},{"id":4601,"author":"朱力偉; 吳振武","title":"兩周古文字通假用字習慣時代性初探","abstract":"通假是人們閱讀傳世典籍及古文字資料不可避免的問題，對其進行研究也是十分必要的。近幾十年來，隨著大批古文字材料的出土公佈，越來越多的學者在研究中注意到通假字的社會性即用字習慣的問題，並且取得了很多的成果。不過相比古文字其他領域而言，通假字的用字習慣研究比較零散、論及的材料也相對較少，無法展現當時用字習慣的全貌，因此對當時的通假用字習慣做一個總結、揭示是十分必要的。而兩周時期正是通假字逐步走向興盛的時期，對其進行總結、揭示更顯得尤為重要。有鑒於此，本文以該時期古文字通假現象為研究對象進行歸納、總結，並對相關內容展開討論，進而揭示出該時期古文字通假用字習慣在各個時代以及總體上的表現。本文主要包括以下","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLI6KEIO9Fvf4qWEgeFg7ucwhNUkiSeGCZqKXZ-P1UUp2_bkQsj05d443_UbCjDMHabwqDj71DJBbwbup7FB5nNF8ZyvWhhEPHVP5_05FBmwc8QyYYX-nBr5EJXB_z2m33qcZoreP3xhmM59KlzS6khoyBT1flsKRciton40xOxM8KrhE4TS784&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4602,"author":"劉波; 李守奎","title":"出土楚文獻語音通轉現象整理與研究","abstract":"本文主要是對出土楚文獻材料中存在的不同韻部的字之間以及不同發音部位聲母的字之間的語音通轉現象所進行的整理與研究，以期為出土文獻的再整理及上古音研究提供更多的參考與例證。全文共分為三個部份，第一章為前言，主要介紹本文選題的背景、意義以及研究材料和方法等；第二章為韻部通轉，因內容較多，故分為上、下兩部份來列舉介紹出土楚文獻中具體的韻部通轉現象，并以小結加以討論韻部通轉現象所產生的緣由；第三章為聲母通轉，主要介紹發音部位不同的聲母之間相諧相通的事實，并以小結加以探討其所產生的原因。最後是附錄部份，附錄一是《上、中古韻對照表》，更為明晰地見出上古音各個韻部至中古時的分合狀況。附錄二《出土楚文獻韻文材料","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3krLri6dStCVo9hBAfC71Oz9C0-AHddQxQv7z-5zRSnjQgyYI09QmPJfsbm_q-sVHJZhiA0dgaW41uQiTH31paTvgX3XPJkXAYJ51WLnMX326wAjysq8L0U1gUAhN7L_Z3amXntWpBF0ccS9v0vEGaCxs9qeDVZvKsKExA-xcXZ-zum0Uuipp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4605,"author":"吴慧; 程邦雄","title":"商承祚文字學之研究","abstract":"商承祚,著名的古文字學家,在甲骨金文、筒帛石刻、重印漆器、屋史考古、書法等多佃领域都卓有建樹,著有15部著作、60餘篇學術論文2種害法作品集,學衍影響深速。我们在全面觀照商承祚文字學相阴著作的基礎上,深入研究商承祚古文字考释的寅践,系统總结其方法與特色,挖掘整理其文字學思想,尤其是封古文字特點和文字發展演燮规律的韶識。全文共分七章,除绪論和结語外,主髓分為三個部分。第一部分是“方法論”研究,分別徒形、音、羲三個方面封输了商承祚考释甲骨金文、簡牘、石刻等文字畴所使用的方法,歸納總結了其考释古文字的特色。第二部分是商承祚的漢字學思想研究,将其散見於各著述中的文字學思想加以整理,總結和評述了他在文字","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIbcXUpZTBpItN6YIqrAbWMWd_n30kOuWE0TUjqw-MIhz3ZDjJiQyD5NjKnQA58pD1e4TNDU8_9dHEwO8BdiDhM8FJJvak_d0jP8EZxHXzzPycHEZWpX6JQpj5s-E0K7oQsISensNxXV0eu1ZeGiIm4SWeglH-1-LjKduNPXYIwnRf6swioEFYB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4606,"author":"康盛楠; 程邦雄","title":"杨树达文字学研究","abstract":"杨树达是20世纪初著名的语言文字学家,他学贯中西,一生勤于治学,勤于著述,在语法学、修辞学、训诂学、语源学、文字学、文献学、甲骨金文学、考古学等领域均卓有建树。在上述各个领域,均有被公认为经典的著述存留于世。杨树达的学术渊源与治学思想既根植于清代的朴学传统,又受到西方语言学思想的影响,所以在其学术成果之中既可以看到扎实严谨的作风,又可以窥见其不拘一格的灵活思路与方法。在清代小学和现代汉语言文字学交替的时代,杨树达很好的发挥了桥梁的作用。然而,迄今为止,对这位国学大师的丰厚学术成果还没有全面、系统、深入的研究,对其单方面的学术成果也挖掘得还不够透彻和全面。这与其学术地位是极不相称的。本文即以此为","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxgxb-Bze52m56FY4lVDKQ52Id_Z-7_0b9LQ94w-bDrzlgVnF6_tdoG42YTG8wptopRsPQ3ccdIhgMAEb5bju5HE-ibEV1rYQb29BEhLWC40oHKYUVcIjRVySeVh9GON0HyjZ5fhfFtU6wN-yVrW-XsM_PE-9VBrpUrQIUoIOAVf2Lv6gzFbra&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4607,"author":"吳慧; 程邦雄","title":"商承祚文字學之研究","abstract":"商承祚，著名的古文字學家，在甲骨金文、簡帛石刻、璽印漆器、歷史考古、書法等多個領域都卓有建樹，著有15部著作、60餘篇學術論文和2種書法作品集，學術影響深遠。我們在全面觀照商承祚文字學相關著作的基礎上，深入研究商承祚古文字考釋的實踐，系統總結其方法與特色，挖掘整理其文字學思想，尤其是對古文字特點和文字發展演變規律的認識。全文共分七章，除緒論和結語外，主體分為三個部分。第一部分是“方法論”研究，分別從形、音、義三個方面討論了商承祚考釋甲骨金文、簡牘、石刻等文字時所使用的方法，歸納總結了其考釋古文字的特色。第二部分是商承祚的漢字學思想研究，將其散見於各著述中的文字學思想加以整理，總結和評述了他在文","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYYTWefF3VBQydvL0_tsjbCjk-fH0ABbBGVlDt_5xPY1r_9cThwkb6YdSv6XM3RCXnt7UK1TpuL-dRb69Okha7pv35_lPd6ecNRpo2c0F8aLec9o9UPS9oExEiw2Jjy_1yhuY8cfE8JkKO748wb40IKcId3bvUfZU6QI44K9MW6eOAb2lQn5no&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4608,"author":"周园; 陈顺芝","title":"从汉字构形演变看简化问题","abstract":"从1956年《汉字简化方案》公布以来，汉字简化问题一直受到语言文字学界的密切关注。汉字简化认识的深度，直接影响汉字规范工作以及汉字的教学与应用。本文从汉字构形演变的角度出发，力图在前人研究的基础上，对简化的方方面面进行梳理和介绍，让人们对汉字简化有一个历史的、全面的认识，并从中探寻汉字发展演变的规律与趋向。全文共分以下几个部分：第一部分为绪论，主要介绍前人对汉字简化问题的研究状况，以及本论文研究的意义和目的。第二部分考察汉字的构形特征。既然本文的切入点是汉字构形演变，那自然要先围绕汉字构形特征展开论述。在这一部分中，首先对汉字构形特征作一个基本的描写，然后分析汉字形体演变的基本走向，分别对汉字","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDPucTKFgbZt-G6bBDbUs7Qkg9-v2FjfNVL0mmjoP1DU6N9TVr6-7HnlgXRrlg_n17dOkz6ZhVKZ5tHkCF7uqJIzAj9VN3i3fTF_ClX5eWpOGw8tSBJaB4l9iq6qTCZ_r03IB7AWLFDZ4TSbL_suLgMq3MmCoDyArh9BFZbzlAFfgKhHs1ri8j&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4610,"author":"武青松; 张振谦","title":"晋系礼器、兵器铭文格式及分域研究","abstract":"戰國時期晉系各國青銅禮器、兵器鑄造很發達，禮器、兵器銘文數量很多。本文的研究工作是總結銘文格式，研究銘文內容包含的信息，考證銘文中記載的地名，研究銘文中文字的字形。通過這些工作我們對當時的兵器鑄造、銘文格式、政治制度、文化狀況、歷史事實、地理變遷、文字使用、字形特點等多方面知識有了深入的瞭解和認識。本文對铭文格式的研究方法主要是总结相同的格式和區別不同的格式，對晉系國家兵器銘文格式中最顯著的三級監造格式進行研究。研究銘文中記載的相關內容，從而找出各個國家在銘文格式上和銘文所包含的內容上的異同。地名的研究主要是通过對記載該地名的銘文的字形特點和格式特點進行研究，從而確定鑄刻有該銘文的器物的國別，","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIFhGPNDgOsH_l-BsYmWRsYXMwa6Ma-6UhIuicRCb6AmKjcctksMMuD1H3SmefMGtW8C-rkJbzqc-8n5n1spjvKOEbKs5GmJH18MXYyo7-bRcRvrSuZ1tHtT_wvhrqyYOLOryp5ARS2m41jdW3D_5JtmSdex4bKr-hsFSPgS6tk6-IZVVQpn0s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4612,"author":"李慧楠; 柳建钰","title":"《古文字诂林》隶定字研究","abstract":"“隶定”作为古文字考释重要的中间环节，是目前考释文字和整理先秦出土文献时必不可少的工作。《古文字诂林》则为当代古文字隶定研究工作提供了一个优秀的范本。论文以《古文字诂林》隶定字为研究对象，试图从中初步探索、规范当代隶定行为与隶定古文字的新思路。论文以《古文字诂林》540部、部分木部字以及部分《说文》未收字为代表字进行抽样评析，认为《古文字诂林》中的隶定字存在标准不统一、严式隶定和宽式隶定的适用缺乏体系性的问题，这使得该书隶定字的宽式隶定适用过于宽泛，隶定范式的体例存在混乱。在此基础上，论文对《古文字诂林》隶定的相关原则和方法作了归纳，认为《古文字诂林》在严、宽两种隶定方式之间并没有严格的界限，","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHOxA_bOiN-kTL6R0g6-YBRrvtbfhTsdx-zZAirhd7DmWph68pWJzJWPWl2K66-gMAIMYvQytXyaYSINqBCYoKZ6kPwFTKFiyvlYH_RBXsrBtxHyNlRBr4VEoitVSswuoXkLeFiKMH7C4Cl8BLulLzuczfaqB_6EwKvtSXFj_mC8jDr9aYud8z&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4615,"author":"柳玲; 殷寄明","title":"“同字为训”问题研究","abstract":"本篇论文探讨“同字为训”这一特殊的训诂体例,着重研究训释词所处的语义系列,并据此进行初步的理据分析。“同字为训”是指训释部分与被释词存在书写形式相同的成分,即以与被释词完全相同的书写形式(或训释部分含有与被释词完全相同的书写形式)来解释词义。这种“同字”成分可以是词,也可以是词或句子中的语素。本论文主要研究“同字为训”典型式“A者,A也”,即被释词与训释词的书写形式完全相同。论文选取66条语料,按时间先后进行排列,依次对训释词进行语义系列的分析。首先,联系其文字形体和具体文献用例,确定训释词的本义。其次,联系语境和相关文献,确定训释词在语料中的语义系列(本义、引申义、假借义等)。在语料分析的基","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgc_en7feIK2gaxn85vjf4p0o_zeb1ki89gUbRlukvURtHpe8TTNVUtVJ_zu9qfuFAnDB_R7-d4_5fO8QG6olMsEKibLduPa4UdRD9p46BHA_ALWrrNy5opqHLO5V0y3kOQmu73Jqxt7ecNLzhe60Er-x_ykSrZ2Q_gbdQikFVkVdJTGhLvD2a&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4617,"author":"雷珊珊; 曾昭聪","title":"《二十四尊得道罗汉传》语言文字现象研究","abstract":"本文以明代刻本小說《二十四尊得道羅漢傳》中的特殊語言文字現象為研究對象，首次從文字學和語言學角度對該書進行了初步的研究。全文共分五章。第一章介紹了《二十四尊得道羅漢傳》的版本、主要內容、語料價值、研究現狀以及本文的研究方法。第二章運用漢字構形學理論歸納總結了《二十四尊得道羅漢傳》中異體字的類型。第三章全面梳理了《二十四尊得道羅漢傳》中的疊字，根據詞性進行疊字的分類，分析其語義特徵和語用價值。第四章是對《二十四尊得道羅漢傳》中佛教詞語的研究，根據語義場理論對書中歸屬“死亡”和“化緣”兩個語義場的詞語進行了求同辨異。第五章從補充詞條、提前書證、補充書證三個方面探討了《二十四尊得道羅漢傳》詞語對大型","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3_sD0OT9c20neo3gn0dbazkxz11hJ_BNki0vLk76GSG6__vZ2h_Omhc1eAeAf8fIm17QHx4lp1bI6fsLL7Q9Pqp05cSiCxcOD8dIYO4GcJFwdo6aAKy47uNZtu45QZXA2VlRPlKuBborjcTyPWaSyLS4Wz0Y_LpHQERn3pHTUqKFR34dSxFCq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4618,"author":"严鲁申; 郑振峰","title":"河北出土殷周非兵器类青铜器铭文研究","abstract":"河北是中華民族的发祥地之一。境內分部著眾多古人類遺址，出土了眾多珍貴的歷史文物，其中就包括殷周時期的青銅器。而青銅器上的銘文如實反映了那個時代的文字形態，可為今天古文字和古史的研究提供重要的材料和依據。但前人的研究并不充分，對河北出土殷周青銅器銘文的著錄比較分散，僅有的兩部著錄書——《河北省出土文物選集》、《河北金石集錄》，由於出版年代早，今天看來已很不全面。對河北出土殷周青銅器銘文進行系統研究的論著也很少，其中仍有許多內容無人涉足，許多問題沒有解決。所以本文擬對河北出土殷周非兵器類青銅器銘文作一系統的統計與研究。通過我們的調查，截止到目前，河北出土殷周非兵器類有銘青銅器共275件。全文分三章","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJtdp6whvW5_1WzNdyhoSutoIVUdIJOITt8bn_yE8Qgx7DbWtA5iSO7h3bbOpkiJgZGDA0fkuCr-6kBPq0QHJxS4Zqg67yecQkjhj8_xn1243AqN4wTaqRzJwION08_gLSmU_5jTK9jpWWPdK5_jzB5AHJ6nkHV-oDlbnf5p2M9X0apS1S9XXJG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4619,"author":"姜娟; 陆锡兴","title":"陆锡兴先生文字学之研究","abstract":"陆锡兴(1947——),上海人,博士；南昌大学人文学院学术、学科带头人,硕士生导师。2001年,陆锡兴先生被南昌大学人文学院特聘为教授,讲授“文字学”、“器物学”等硕士学位课程。现担任中国文字学会理事、中国训诂学会理事、中国辞书学会理事。陆先生从60年代开始从事文字研究和教学工作至今50余年,是中国当代文字学家、古代器物学家、训诂学家。他所涉及的学术领域广泛,普通文字学、汉字历史、文字训诂、辞书编纂、古代器物、出土文献等研究领域都有突出贡献。在文字研究领域,他著有《书法艺术》、《汉代简牍草字编》、《诗经异文研究》、《文字传播史》、《汉字的隐秘世界——汉字民俗史》等专著；先生对汉字传播、汉字民俗","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7qBIKqYu2bOwwpOaOgzqjYVcXr0nMRgj0iXuE9JxBOfIt8m-8URkCzkd3TufuTM28ZpDIQB_egdfY-Hn7pVArfqt2uLo-PwhQOLm871dgs3V_PCPs_qRaTskVzN7mdKKZChATGgH92xrAN_Gu1Ff-yr6IE4xs8jG228-HPjJiiOwH28iN48xV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4624,"author":"李光耀; 馮寬平","title":"從“豕”字的衍化探析漢字用字一般规律","abstract":"汉字是人类文明的奇葩,自产生以来一直在用字数量、结构形体、读音和字义上发生变化,而这些变化折射出来的就是汉字用字的一般规律。人们在使用汉字峙,总是根据不同的用字需求和用字习惯对汉字造行改造,这是汉字发生衍变的根本原因。本文以“豕”字衍化作为研究封象,在综合研究相关学术成果的基磁上,连用古文字学、音韻学、训詁学等学科的理论知识,梳理了“豕”字衍化的屋时轨跡。同时,结合甲骨文、金文、小篆等,将不同时代“豕”字衍化的特徵进行对比分析,试图找出汉字用字的一般规律。本文主要分为四个部份：第一部份为绪论,简要介绍汉字用字规律的研究情况；第二部份,“豕”字的意象与功能,主要阐明“豕”字的来源和基本文字功能；","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHQIoT-txIthJoNAVKBv1M2wcJiaFjRkWi6nuPzoWxp9Qcl12bihKi2QBXogVcgMe6JnLY5k88jm3NifIZHNAqL7uEBUoX4BhneOrbAuVLr866cyan9PDErQRxQkiIFF3ElNyKJcIrzqfRNaVJEEIIBmme2AbAgOcw-ywNAVcBUYkLZPxh5TOT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4625,"author":"张月","title":"古文字考释方法概说","abstract":"本文试对甲骨文的考释方法进行梳理,以期对古文字的进一步考释有所裨益。","categories":["02_字词句考释"],"year":2013,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7DG_um5lzmxdbkn-aitfdVBg_3PCA_nW3iag0iTXLFNOmXghCMVCBxs88A17k5jZLjXt_j_ysQbIIXHo4yg-dwcKtPHaOQn9Yg31GTQYaIYyCxEwOae5djH4S-Tm3MkcQd41ZOq6-2zX1NomHhzXnZ2LNOAIVB2TbG6Qb9V_mnkUmfF5wmE-V&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-40","volume":""},{"id":4628,"author":"刘文灵","title":"“三纲五常”与文化密码——汉字所显示的君臣、父子、夫妻关系","abstract":"汉代董仲舒所倡导的&quot;三纲五常&quot;是封建伦理精神的核心内容,对国民的精神统治有近2000年的历史,所以,它对人们性格的影响是深入灵魂的。但是,现实社会中&quot;三纲五常&quot;的起点并不是董仲舒的理论诞生之时。通过对相关汉字偏旁部首的解读可以确定一个事实:在远古时代,君臣、父子、夫妻关系就是不平等的,而且这种不平等现象不是偶然的,而是由当时的生产力水平、生产方式决定的。","categories":["02_字词句考释"],"year":2013,"publication":"内蒙古师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK46yRZ8hGuA_YaWIO9HQVNCMyWo3TFvW1lSi6gndxRlttdzrUJCK7XQZhsyaIopRaBfk5jjpcS20qyCfqAI9GTBBBM-EjG78BK16DmSd1jbWIJNdK7Sr4UuC7HU-6w92U70I_9x28ha_8blFdJADrVgIwSaNsc2AxpVwCGdTJBhQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-58","volume":"42"},{"id":4629,"author":"劉剛; 裘錫圭","title":"晉系文字的範圍及內部差異研究","abstract":"本文主要討論晉系文字的範圍和晉系文字的內部差異兩個問題。首先通過總結和歸納三晉文字的總體風格、字形特徵和用字特點，確定三晉文字作為一個整體與秦、楚、齊、燕等系文字的區別所在。通過比較中山國、兩周文字在形體特徵和用字特點上與五系文字的異同，確定其與三晉文字的關係，認為很多學者把它們歸入晉系文字是合理的。對存在爭議的鄭、衛等國的文字資料問题也進行了討論，明確了晉系文字的範圍。其次，通過全面梳理三晉文字資料，在學者已有研究成果的基礎上歸納、總結出一些分國標準，如各國專有的人名、地名、職官、辭例、特殊字形和用字習慣以及器物的形制、出土地等。按照以上標準對三晉文字资料進行分國，對一些國別劃分存在爭議的器","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMyrG-oYvGy9kuEf6de7v4q0Nju7DbTQWLKNVB42-VdCiBhv23WrkkzFgxIOtZGCIj00-rRiyCWVrvTQE0TXqqUTDsO4qjDADL14h0E916cqMCWncQeIzFqvv9SYhrew2E5MVdAa4ZL59kGgFcfaHGHgANdLrHNTsCIiFwQ3jgAgBchDAnXDh8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4633,"author":"周学峰; 杨琳","title":"道教科仪经籍疑难语词考释","abstract":"道經是道教的文獻典籍，數量龐大且造作時代自漢迄明縱貫中古及近代。作為漢語史研究語料的重要組成部分，道經文獻未能得到語言學界應有的重視。尤其科儀類道經，相關文字、詞彙方面的研究至今還是一片空白。本文選取科儀類道經中的疑難語詞作為研究對象，主要就俗訛字和疑難語詞兩方面分別加以考釋，具體考釋中對相關疑難語詞作了適當的分類，考釋詞義力求追根溯源，勾勒出詞義引伸演變的軌迹，同時嘗試從民俗、文化等角度考釋詞語的内涵，初步揭示出科儀類道經詞彙的特點。在考釋過程中對疑難語詞與道經文本校理、詞典编纂的關繫作了初步分析。我們的研究對道經文本校理、詞典編纂以及漢語史的研究有一定幫助。文章包括四個部分：第一章緒論。主","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKCpnJCtORjXLw3SoNn2KKqO51Mp21XwQLFYV0AUCpEe0bJsJTy6UR7iEovWxliHwTKaqBUU0H8NnI9mByYpZVV4VAmRh-AhRA8mDdVEasROCGG8_x7xGf-qoJmM-D4HIWZcvWy-RzQKep66dZSg_xxPGbvDBGH0uF9uJD9PKrwWN4jxOo4DKkE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4648,"author":"林志强","title":"《文源》卷三选评","abstract":"一闽籍学者林义光所著《文源》,运用当时所能采集到的金文和一部分秦汉金石文字资料研究汉字的本形本义,对《说文》之说多有补正。其书自上世纪20年代面世以来,颇得学界重视,常被称引,说明《文源》的价值确实受到了学术界的肯定。但从具体涉及《文源》评价的有关论著来看,目前学界对《文源》的认识还不够全面和准确。我们认为,为了全面准确考察《文源》的价值,首先必须对《文源》进行逐条评注,","categories":["02_字词句考释"],"year":2013,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5eME9wYwgAsqlbc0fhk53jI0m2ZZNQ_1Fg5WgTHoH4jD76U1fM0mNjh_ZYw1yiOG8K4KAWZ9yJU7CuV61mznJCx1n3_c8wrXqZjGMAj-Mdm7Ko94eK163ugod8sD6W8TaCV5W5VjkVJsbJYjGFSKfDo5G9u7dm5qYwD5LgdpDwQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46343","volume":""},{"id":4651,"author":"王保成","title":"翼城大河口霸伯簋试解","abstract":"翼城大河口M1017号墓出土的铜簋,内有长50字的铭文,内容为器主霸伯拜受井叔赠赐而作宝簋。铭文中有不少异体字,值得研究。霸伯簋铭中的井叔很有时代性,他是曶鼎中的井叔,也就是张家坡双墓道大墓M157的墓主人井叔釆,有很重要的研究价值。","categories":["02_字词句考释"],"year":2013,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLwCiQhKaTsw_TIGLyn3yPthTf0JRsKmQivk9NOJ_rdK8_C7lkWiMI58Kl-INcKr_SaxsOJIzchi2DB_nwrOSl2VeikY0bDTRw_fL5vQFrszuJ9NkQx1XRGLDx-f4Uhsi-3X3KyY01ToXuf-6qG_bHRLkjnZCpi4dtc6IOLXIYmuw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-47, 50","volume":""},{"id":4652,"author":"黄约琴","title":"从词源略看“声”“音”之异同","abstract":"&quot;声&quot;、&quot;音&quot;都可以表示声音,并且在现代汉语中二者组合成词表示声音。但是&quot;声&quot;、&quot;音&quot;并非完全相同。从词源学的角度分析&quot;声&quot;&quot;音&quot;的不同之处,&quot;声&quot;多指器物之声,&quot;音&quot;则多指人之声音。由于词义的扩展,某些情况出现混用。","categories":["02_字词句考释"],"year":2013,"publication":"广东广播电视大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIbrLWwnNvd256Cbmf8QQ3kf8wFU2WH55BzOQTLLA0N2kV21SJRLQJzmzGZ7GyLFv_OvgVGcrPpRvGtvuImXQtHtsW4wyXPhNfbReO3DBIhfiOY5zapQlhRuSBXH4dPu5UJ4OF_4PW2gqMSOF04AC-webShCjs2HtmjT_Vbpy0pMA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-73","volume":"22"},{"id":4653,"author":"江学旺","title":"“段”“叚”探析","abstract":"《说文》&quot;叚&quot;跟&quot;段&quot;小篆字形左半略有不同,如依谭长所说,二字左半并无不同。古文字中,这二字左半的写法完全一样,都是&quot;石&quot;字。许慎于&quot;叚&quot;字字形&quot;阙&quot;而不论,把&quot;段&quot;字分析作形声字。实际上,&quot;叚&quot;是形声字,&quot;段&quot;是会意字。","categories":["02_字词句考释"],"year":2013,"publication":"语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYO9cewkcHPLnOmJDgqf7EIP-tAg_65edkChPrI6G4LHxdNwA1z75SZqx-vzMvj52aj1qG2hL29BQ2iP-4QUSjSY1NGGZ9VVfZHUUbl02JgpgefCIpRoynTeLafhvZNErC8e_X4QHMZmwe_JgjwR2CsXMsWfa8PrjK7o5wuA9Blg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-91","volume":"33"},{"id":4656,"author":"郭利芳","title":"春秋金文构件统计及构字能力分析","abstract":"对春秋金文的字形作穷尽性的统计,并对文字系统各方面的特征进行描述,从而为构件系统的研究提供可能。对春秋金文中的构件进行统计,排除未识构件和非基础构件,得到基础构件476个。根据构字能力不同,把构件分为四类,分别是构字能力强、次强、中、弱。按照这个顺序,统计春秋金文构件的构字量。比较前后期文字系统中的类似特征,分析春秋金文在文字发展传承中的地位。","categories":["02_字词句考释"],"year":2013,"publication":"黑龙江教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJXuABgjTQUWqrUr32DrwXilKzvcOlJH0uy5Y7P_IaPXV_VgXWMCElVLEuGIJVWBYJKy4AKwN_bSICg9ntXVQPDpq8zBt9ApeO3dBMjZlFDaFupOmNUjJwj5mUB_Z8ghv6CxWfsuHmCmANwQKzWlr2kOpmqAGPrDK-hPqri3V8SIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"133-134","volume":"32"},{"id":4657,"author":"姚利芬","title":"一斑窥豹——从汉字字源看古代女性的生存状态","abstract":"汉字与文化同构,汉字集造字法与表辞法于一身,包容着造字心理和社会心理的全部流程,古今汉字概莫能外。通过探究与女性相关汉字的字源,我们可以窥得古代女性的生存状态及当时的社会风尚。","categories":["02_字词句考释"],"year":2013,"publication":"江西教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKVl8RFDJlp9NdnphAKYW0O6vRfvmIt--w0yFVTdFD2ZmCJLOfBdlg8xekpq2ysCxTVnaSehZA9xwIy_Yo_k06mh_171NjyXD4iDG-HBYrXhKFN32m77b3CAkgIrJQlrKnPrFDbldm2wcf4-H5QtsXtPM1KPyEYTMMv6FrrKLixhw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-116","volume":"34"},{"id":4658,"author":"郑继娥","title":"甲、金“于”字介词结构的语法特点","abstract":"甲骨文和金文中&quot;于&quot;字介词结构在语法上呈现一些相似和差异。甲金&quot;于&quot;字结构多出现在动词后,甲骨文&quot;于&quot;的宾语多为单音节名词,也可以是动宾和主谓词组;而金文的宾语多为多音节,以名词性词组为主。甲骨文的谓语中心语一般为一个音节,而金文谓语中心语多为多音节词或词组。","categories":["02_字词句考释"],"year":2013,"publication":"湛江师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJi3mK0EEflHdCz21jbjSHoQcy476DE7Ip19fabWDMaE29dDcTFSpXnHCSbpHmcgiysR0iy4gBPfbCr53zQ5Vze2ypo8-ousxHSJoDXSgeQx-Ts6yTNlRwPFfwGromBJm0ZaSsm97yu7E5XVG4qQS15ubj4KXSvnzlUfnNKXVC1QA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"146-149","volume":"34"},{"id":4661,"author":"王伟成","title":"金文书写形式浅谈","abstract":"金文是中国古代从商开始一直到战国时期仍然在使用的主要书体。金文主要书写或铸刻在商周时期的青铜器上,古文字学家也称为钟鼎文。因为青铜礼器以鼎为代表,乐器以钟为代表,是礼乐文化最重要的物质遗存,具有不可替代的史学价值。1925年容庚编《金文编》把商周铜器铭文中的字按照《说文解字》的顺序编为字典,从此金文成为一种书体名称。就金文本身而言,主要记录的是商周时期的礼乐和历史事件。从金文书写形式来看,有一定的象形特","categories":["02_字词句考释"],"year":2013,"publication":"中国书画","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhqofiO0wFlzVEymMIACcPCpffxlLVEK7bDoAK2yQ4Oz-4EBJclslKyC7nNTSqgja1Y5Ycu7-65E8FT2qD74OCHxtwcyAoc4ZJjVoIkOUMIc8BcVMnEkcL4O0EXbyBLomIot2qWbiD6Vf7TrVkdt0cGr0CoW_2PPBIR5PuGOalCQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"128-129","volume":""},{"id":4666,"author":"贾海生","title":"晋侯墓地出土伯喜父簋铭文索隐","abstract":"伯喜父簋是器主人伯喜父继体为君之前,依士冠礼加冠后,为祔祭亡妻倗母于祖庙所作礼器;铭中&quot;倗母&quot;之称,表明是倗国之女嫁于晋国而为伯喜父之妻;&quot;王宗&quot;一词,首见于伯喜父簋铭文,礼制与训诂皆可证王宗指祖庙而与宗法无关。","categories":["02_字词句考释"],"year":2013,"publication":"山西档案","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKekO-P_mMu3nmm0n9pN97-QEnvOZIFzjqQIRH_vQPy0amqL60F50PLsnCaCIK09tCKtyfZZWB5KSe0ULengxQcgF-GKGuS2SIrBKwRIvW6_Y7O2Whzq8XkzxkDPEkdC2Z3X5g3USqooZybY0V0d7xby_IVEGRv_M4eBrH5NnMcdQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81-84","volume":""},{"id":4667,"author":"王进锋","title":"甲骨金文释证三则","abstract":"学者们对商代小臣墙刻辞中&quot;■&quot;字的释读分歧较大。从战国玺印文字看,其应是&quot;弩&quot;字。小臣俞犀尊铭文中的&quot;■&quot;是一种古文字的形体省略,完整的字形应是&quot;■&quot;,即&quot;庸&quot;字。叔德簋铭文中的&quot;■&quot;是&quot;姪&quot;字,在铭文中通假为&quot;致&quot;。","categories":["02_字词句考释"],"year":2013,"publication":"中华文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ5TIZ0pR_gDTbRvsMkdasNAtHn5I2IPdLtPaSY2upQ5Sy7eOL_qRiSi0maTcUNq1EVi-wXiC3pUoZ56Uqo8I0MebT5CruiKEzl74DQZFJ0zksxAXWV_efUilXLMhkUKOhe4ULqggepXyPMKpHNV0c8pvVyvZZ_czw9onjEJO2MWg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-66","volume":""},{"id":4668,"author":"王治国","title":"询簋新探","abstract":"对于金文啻官■一词,学者们已有多种看法,笔者认为释啻为嫡当是正确的,但笼统的认为&quot;啻官■&quot;为嫡长子世袭某官或者世袭之官的意思却是不妥的,嫡有&quot;正&quot;和&quot;直系的&quot;等意。从孝王时开始,秦始成为周之附庸。近来有学者认为询应当为师酉之祖父,并将询簋定在恭王世,笔者认为与史实相悖。我们在为其母作器的西周金文中,从未见到称其母氏加母姓的例子,如将师酉簋中的■当作氏称,则不符合西周金文的通例。从各方面综合来看,师酉当为询之父。","categories":["02_字词句考释"],"year":2013,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2013.01.011","pages":"89-95","volume":""},{"id":4669,"author":"孔令远; 李艳华; 阚绪杭","title":"徐王容居戈铭文考释","abstract":"安徽蚌埠双墩一号春秋墓的发现对了解春秋时期钟离国与徐国的历史及文化具有重要价值[1]。此墓出土的两件铜戈最近经过清理,发现上面有铭文。这两件戈形制近似,均援较长,微弧,锋呈三角形,胡上四穿(图一、二)。其中一件戈(M1∶47)长援身较窄,中部有脊,前锋凸出,锋利,双面刃,栏出头。直内,内中部一穿,后端有残。通长20、援长14、内","categories":["02_字词句考释"],"year":2013,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2013.03.012","pages":"77-79","volume":""},{"id":4671,"author":"罗运环","title":"随大司马■有之行戈“■”字考辨","abstract":"随大司马戏有戈,是首次发现的随国器物。戈铭中的戏字因不见于已发现的古文字,分歧较大,有献、嘉等多种释读,均与字形不符。通过对比分析,隶定为■,确定为戏字的异体字。","categories":["02_字词句考释"],"year":2013,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQOIYR_FjfpXAm28kRNmzPl2dn-mwzD3BeEsv5673bWXoj6g4atLebPmuFbuPPC7momTcN2KH5_Aar_YHwxkZQ2F2C6Ge-m_nJsTQBMXXHH4EfyAjUVWqJJ3fXEctJYak8qSlByOK6asVWoQ3v-wnpeQiqoUW6spsI8xTH5k9h1g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"127-130, 126","volume":""},{"id":4674,"author":"侯书勇","title":"《释祖妣》与《耒耜考》之比较研究","abstract":"《释祖妣》是郭沫若先生的名作,《耒耜考》为徐中舒先生的代表作,二者同作于20世纪20年代末,在学界有很大影响。虽然两位学者所研究的问题不同,一对祖妣作了新考释,一为考察古代农具的起源和发展演变,但二者皆不局限于对称谓和器物本身的研究,而是藉此进一步研究中国古代社会。二者研究问题的视野开阔、方法新颖,其治学思想与方法仍值得我们借鉴。","categories":["02_字词句考释"],"year":2013,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2013.01.008","pages":"62-66","volume":""},{"id":4675,"author":"商艳涛","title":"金文中的“征”与“伐”","abstract":"&quot;征&quot;、&quot;伐&quot;是金文中表示征战的两个常见用语,一般通用无别,有时也存在使用范围和形式上的不同。金文中的&quot;征&quot;、&quot;伐&quot;与甲骨文相比也有使用范围的差别,而与先秦文献用法基本相同。","categories":["02_字词句考释"],"year":2013,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2013.01.010","pages":"94-97","volume":"34"},{"id":4680,"author":"闫华; 任乐雅","title":"西周趋向动词的类型学考察","abstract":"文章以周原甲骨、西周金文和《诗经》的趋向动词为研究对象,进行了穷尽性的分析统计。周原甲骨和西周金文中的趋向动词与《诗经》趋向动词的主要语法功能是相同的,当时民族共同语已在一定程度上形成。同时,《诗经》趋向动词的语法功能明显比周原甲骨和西周金文趋向动词更为丰富且灵活。《诗经》语言反映的是周代民族共同语,其深受商民族语言的影响,而周原甲骨文和西周金文则是周民族语言的典型代表。西周趋向动词可与其它动词构成连动式,能带宾语,但不带宾语的情况更为常见。趋向连动式仍以趋向动词位于其它动词之前为主,位于其它动词之后的仅一见。","categories":["02_字词句考释"],"year":2013,"publication":"新疆大学学报(哲学·人文社会科学版)","link":"https://link.cnki.net/doi/10.13568/j.cnki.issn1000-2820.2013.02.007","pages":"141-144","volume":"41"},{"id":4685,"author":"刘树满","title":"宝鸡戴家湾出土的用征器及相关问题","abstract":"本文对宝鸡戴家湾墓地出土的两件同铭器用征尊、用征卣的铭文&quot;用征&quot;进行了分析,认为作为西周早期器,较短的铭文与当时的征伐类铭文不符,应作为&quot;用于远行&quot;之意,因此,此二器是最早有征行铭辞的青铜器,而出土此二器的墓葬应属于以鲁侯熙墓为主墓的第三代墓葬群,时间为西周早期后段。","categories":["02_字词句考释"],"year":2013,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2013.01.006","pages":"46086","volume":""},{"id":4686,"author":"张俊成","title":"齐城左戈铭补考","abstract":"1996年出土于山东潍坊的齐城左戈,铭文中的&quot;左&quot;意为左武库;&quot;&quot;当为&quot;冶&quot;字,为&quot;冶尹&quot;的省称&quot;;洧&quot;字为人名。齐城左戈的年代当定在战国中晚期为宜。","categories":["02_字词句考释"],"year":2013,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2013.01.008","pages":"21-24","volume":""},{"id":4687,"author":"姚利芬","title":"从汉字字源看古代女性的生存状态","abstract":"汉字与文化同构,汉字集造字法与表辞法于一身,包容着造字心理和社会心理的全部流程,古今汉字概莫能外。通过探究与女性相关汉字的字源,可以窥得古代女性的生存状态及当时的社会风尚。","categories":["02_字词句考释"],"year":2013,"publication":"兴义民族师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIbAEfB7ZJRi8nZdXToleCjUoN46tH2ZvTwZeazs-9tK_5FakwmMpgELKVeNmE7JdzeZMMQ6mwx8eku1fV7clmVQt0P8PWl5GRBymlBJU4XQbsIg2vZSn0YuWr8Vysp9ZCgXtBFnSeI9b-byLcvqBuQOS-ZnT6vpLFCxZYx2QMvsA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-56","volume":""},{"id":4689,"author":"苏影","title":"佥父瓶铭“金”字补释","abstract":"文章从形体、辞例两方面对佥父瓶铭未作定释的&quot;金&quot;字作了补释,认为是金字无疑。","categories":["02_字词句考释"],"year":2013,"publication":"哈尔滨学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1DVmwmXoqoabaP42NjIdgze9N9tdCKjruoHLUBpsDhVSjyCgRa80IGwYYgwjdcU7m9rZlQGJFuAa3l0TtkNS2ezAcdGD_uVknVClWzC_ixkiJ1OV-RBUjK9x0hak-bIzFvrs7EYRyzQ7X26hEuVre2nUf5DzpL8hZvKsVDksL7A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96-97","volume":"34"},{"id":4690,"author":"汤志彪","title":"战国兵器铭文人名考释七则","abstract":"战国兵器铭文人名甚多,不少人名还需论证。本文拟将战国时期的七件兵器中的相关人名作重新考释。","categories":["02_字词句考释"],"year":2013,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4Hwl7_yNgBBWbgojNrdhXoTKAnlxs9APgxqIoY3OlV0YAYarvFRIXOcuR3XUMSa5YnzKAFoaxt84kOAlZIeWiddBYG5vAXm74rCudhNjKRbbktInBByfYVOCllaspuM9I5CKsL6J17w5zQDyFynqsRDn2at3TjIxrZS7SVTEkUA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-112","volume":""},{"id":4691,"author":"郑清森","title":"永城南山一号汉墓1号陪葬坑出土铜锺铭文考释","abstract":"河南永城南山一号汉墓1号陪葬坑出土一件铜锺,其肩部与腹部之间阴刻&quot;上御锺常从盗者弃市&quot;铭文九字。本文对铭文进行了详细考证,并根据历史文献,对铜锺发现于西汉梁国王陵墓地的原因做了较为深入的分析。","categories":["02_字词句考释"],"year":2013,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGUOlokcbdKFD1iKXDKUii8PnmAujdh4-tmETITvk0U9lt2-Jw97E76ZnUhSUs4CHE57PBmQrbFKjZiyk8V0MR0iO4XZ7Y8JlM1ZcPgj62NB6Dygpvb9Ccv5w9vroXuMPnPp5sVqdcHD-7RBoh5ks7NE00zo_3hecvyQdx71-4qg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-64","volume":""},{"id":4693,"author":"刘莉","title":"“丧”字音义演变考论","abstract":"文章利用现代语言学的理论与方法,梳理出了&quot;丧&quot;字音义的发展源流,认为&quot;丧&quot;字先后经历了词义构词和变调构词两个阶段,其词义与语音的分化不同步。&quot;丧&quot;字原始词与中古如字音不对应,是语言发展规律的例外。这些都表明&quot;丧&quot;字的变调构词是汉语的自然语言现象,而非经师人为之作。","categories":["02_字词句考释"],"year":2013,"publication":"语文研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKF4rG5soHpHGhzwV9BCvnVvHwRxl1jggNMP-pQRna7LnkwmLRFzN2x9DNJXXmDxU1XQL3FZv7gUHV_crf9n_3c7LGANaMXXri16adMBdU5O8WJVGbFw3UQeMdjGWTMfnRNRGEcrOiRldTY2VA0gIjA6s3kgnYepyTH9h8b4dEJsw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-43","volume":""},{"id":4694,"author":"王雅虎","title":"“叔”字最初指兵器","abstract":"《现代汉语词典》这样解释&quot;叔&quot;字:&quot;父亲的弟弟或称呼跟父亲辈分相同而年纪较小的男子。&quot;但在古代,&quot;叔&quot;字丝毫没有叔意,没有一点长辈的意思。&quot;叔&quot;字最早只是一种武器,一种仅次于&quot;箭&quot;&quot;戈&quot;的战争武器。甲骨文&quot;叔&quot;字左边是个&quot;箭头&quot;,下面系着&quot;绳索&quot;,像戈射之缴,中间弯曲得像一张弓。金","categories":["02_字词句考释"],"year":2013,"publication":"人才资源开发","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6hCUvnO6_3n1Ql3aJWWcPdIcBakYs_QmMMlLyQ4S198LcLxahM6cIsqc9j-NTBIkgYBCKh83kwhxjLWZJS--MnjyOvbsGfhnjuxBG-Z8Sxl-J-RkPl2GyM1FA2daXjNRmQGFVZELfTu9SyyHWooXypFYT1Q3nD3BX6t3nPBgtnA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70","volume":""},{"id":4695,"author":"王晶","title":"六年琱生簋铭文集释","abstract":"六年琱生簋是一篇西周时期的涉法铭文。在吸收各家研究成果的基础上,对铭文进行集释,并做出按语。为方便对全文的理解,在集释的基础上对铭文做了翻译,希望能对六年琱生簋的深入研究提供些许帮助。","categories":["02_字词句考释"],"year":2013,"publication":"嘉应学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJnxxkJY9yRR_FXXh9itihxmrdMj80gyNVDGg9EEFTz5Q6xgJMpB1t4MtVtPTXOPOB_nDgAFlHw0RlPs9wbOsxRa6BSiMdn-jv8nNa8eeHENVRxiMTKCCE-4Oyj6L2iM2YMnfjlHD__Sb1IZKB8E3vdNVxlBCsK7n7CrLknKncOTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-77","volume":"31"},{"id":4697,"author":"邓飞","title":"两周军事铭文中的同义动词","abstract":"两周军事铭文中的同义动词,有些是从殷商甲骨卜辞中继承和发展而来的,有一部分是两周时期新产生的,这使得该系统呈现出一些较为复杂的面貌:同义动词的来源千差万别,其抽象程度也存在很大的差异。有些是在词义发展引申的过程中,在某一个语义枝上相同或者相近,有些同义词概念意义反映的是同一个动作行为的不同阶段或者属于上位概念和下位概念之间的关系。造词时的深层语义差异、词反映的社会文化现象的变化二者对同义词的发展、演变有着至关重要的影响作用。此外,同义词反映的社会价值观念也是一个复杂的系统。","categories":["02_字词句考释"],"year":2013,"publication":"西南大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13718/j.cnki.xdsk.2013.01.005","pages":"117-127, 175-176","volume":"39"},{"id":4698,"author":"刘秋瑞","title":"战国有铭韩国兵器研究综述","abstract":"战国时期韩国兵器文字资料丰富,本文从三个方面对韩国兵器文字资料的研究现状作出分析,同时提出了今后韩国兵器文字资料研究的方向。","categories":["02_字词句考释"],"year":2013,"publication":"兰台世界","link":"https://link.cnki.net/doi/10.16565/j.cnki.1006-7744.2013.03.077","pages":"19-20","volume":""},{"id":4702,"author":"寇占民; 王圣奎; 唐秀伟","title":"西周金文动词研究的历史及意义","abstract":"西周金文是最早的成系统的汉民族书面语之一,保持着当时语言的原貌,因此它是研究上古汉语词汇的重要语料。西周金文动词的研究从汉代开始到现在已有两千多年的历史,并取得了很大的成绩,为西周金文的释读和应用以及上古汉语动词的研究奠定基础。","categories":["02_字词句考释"],"year":2013,"publication":"齐齐哈尔大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13971/j.cnki.cn23-1435/c.2013.01.032","pages":"46119","volume":""},{"id":4703,"author":"朱其智","title":"散氏盘还是夨人盘？——兼与张振林先生商榷","abstract":"从三个方面可证明《殷周金文集成》著录的10176号器的作器者为夨人:(1)授图之地豆为夨邑;(2)篇末&quot;厥■(授)图夨王于豆新宫东廷,厥左执要,史正中农&quot;中代词&quot;厥&quot;字两见,所指均为夨方;(3)此器为&quot;左执要&quot;者所作,&quot;左执要&quot;者当为付方/债务人一方,而非受方/债权人;&quot;左执要&quot;者即&quot;付散氏田&quot;的夨人,而非散氏,即此器为夨人所作?蚀似鞯倍獕魅伺蹋皇巧⑹吓獭","categories":["02_字词句考释"],"year":2013,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2013.01.010","pages":"89-91","volume":"53"},{"id":4705,"author":"毕秀洁","title":"《戍铃方彝》的摹本问题及补释","abstract":"本文考察了《殷周金文集成》第9894号铭文《戍铃方彝》现存的三种摹本,对三种摹本的铭文字形进行了比较和论证,对几个难识字提出了自己的看法,对整篇铭文尝试进行了通读。","categories":["02_字词句考释"],"year":2013,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLpts914kWDpzpnJp-7AlEFX2c-vRVcBS1beDzEFX12SA5a8MBUFwuXCKbiCBYlNkAbYZMwvGxQQsV0MWkhclpf9pcaPrYXESF8qwSFTQ3q7HE1jnVaZYIHvZ8CMfCcF003Ee0WGK7oRzd70KzJISil0pdTs_kNFueVIhhuVmKdFg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-70","volume":""},{"id":4706,"author":"苏晓威","title":"《文子》与《淮南子》关系再认识——以《文子》古文书写系统为中心","abstract":"今本《文子》某些文字仍保留着古文写法,如壄、是、眎等,而同样写法的字在《淮南子》中,则未曾见到。即便是《文子》误作的&quot;害众&quot;二字,仍有可能是后人不识古文&quot;周鼎&quot;的写法转写致误。同时,汉人识读、转写古文的能力极为薄弱,不太可能仍然用古文创作或书写《文子》,所以今本《文子》一书当在秦始皇统一文字之前已经出现。","categories":["02_字词句考释"],"year":2013,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLpts914kWDpzpnJp-7AlEFX2c-vRVcBS1beDzEFX12SA5a8MBUFwuXuQQyjnZZj7IHRf85Unf4TY6sOe7Ag4eSexKcMtWs9GArZUy1M47IlC5d2OTZXkfJSNrEGzC1hdVHjOZdz-bs1UCXSENqTQqE2Gb_HVDM6W8uOGq54LNYLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-90","volume":""},{"id":4709,"author":"于成龙","title":"吉金铸国史——(二)索隐金文说“册命”,钩沉匡正古今疏","abstract":"由‘颂'器铭文考察西周时期‘册命'之仪节,兼论《左传·僖公二十八年》所载周襄王策命晋侯文句‘出入三觐'之古今注疏《诗·小雅·北山》语云:‘溥天之下,莫非王土。率土之滨,莫非王臣。'此诗句是以强调西周时期周王对于臣民的至尊地位:一人之下,万人之上,亦如西周康王时器大盂鼎铭文所谓‘我一人'。又《诗·大雅·常武》云:‘王谓尹氏,命程伯休夫。'此乃是周王任命臣僚以职官。对周王而言,此任命、封赐,于典籍之中,称为‘策命';而于西周青铜","categories":["02_字词句考释"],"year":2013,"publication":"紫禁城","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjFTdLzN7fXbm9O38ZeqhEZsL6D1L5qEPyH0lhofsVRs9iV3a7Ac9KsX0cfxd-xlwYg9W4JLn-cdte2XGI7zP7yOu2vnZYmzLzcQ-MiNznE_06jQ1svJf0BgDryhYmih6WuVVFiTWfKIONhidPH2p1JGpXP8E3jnxQUIE5TIkI3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"110-131","volume":""},{"id":4710,"author":"郑晓行; 曹杰旺","title":"基于“金”字的汉字起源年代测定","abstract":"&quot;汉字起源年代的字测定方法&quot;从&quot;金&quot;字开始测定汉字的起源年代。人类认知金属的历史、&quot;金&quot;字的形态特点、&quot;金&quot;字与&quot;金&quot;字群其它汉字之间的形态关系及&quot;金&quot;字的本义都有力地证明:(1)汉字的产生远远早于铁矿冶炼时代;(2)黄金是我国人类发现和利用最早的金属,&quot;金&quot;字指称黄金;(3)从&quot;金&quot;字到&quot;铁&quot;字的历史与我国人类发现和利用从黄金到铁这些所谓的&quot;史前金属&quot;的历史同步;(4)&quot;金&quot;","categories":["02_字词句考释"],"year":2013,"publication":"淮南师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIcvmK3sd9i7UaRoy011VjtDHsuyEs4HzNl9U3j51d-hLhPBR1TqoXnGl5iyFMZQRBtG7W8eR5J-oSlb4Ew7feAiLzv4Sjjbkzp1pjf7UsbmJkNVirG-8-67i9pLxumUNhpIy27lcxYJqzVDW7bhnEF1nojvQmsSzDXs9IHUFkSUg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-78","volume":"15"},{"id":4711,"author":"孙合肥","title":"说楚大鼎铭文中的“安邦”","abstract":"1933年安徽省寿县朱家集李三孤堆楚王墓出土的楚大鼎,有铭文共十六字。其中前足膝部和左腹外壁下部有相同铭文&quot;安邦&quot;二字。关于此二字的释读,学界存在分歧,结合所见到的铭文拓片对其进行补充释读。","categories":["02_字词句考释"],"year":2013,"publication":"淮南师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZQNq31MzaLru7IrW48MX4kO_-AGdcKjBQ8o1yMxnRZlioMqRUy2MXfiJEscos38V4hfLXmJG5LaACFo873_a5Lt3JN302iSUv0Dqo9EhFnGNDIFa02l3hUUvjTTbMZyRig5lYfyU2xAwVQzNe6S6AQvoTOE1MrdqO9IQOr5wd0w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79-81","volume":"15"},{"id":4712,"author":"武振玉; 周晓凤","title":"殷周金文“献纳”义动词释论","abstract":"殷周金文中的&quot;献纳&quot;义动词共有&quot;献、羞、入(纳)、荐、尊、享、进、共(供)、稟、觐、惠&quot;11个,总出现频次为74次,除&quot;献、羞、纳&quot;三词外,其余各词的出现频率均很低,总体出现时间为殷商1例、西周46例、东周27例;句法功能上,不带宾语的略多于带宾语的,与同属取予范畴的&quot;赐予&quot;义动词相比,&quot;献纳&quot;义动词在个体词目和总出现频次方面均明显少于前者,反映了两者的不平衡存在状态;与殷墟甲骨文相比,殷周金文中此类动词的词目和出现频率均有所增加,与先秦传世文献相比,殷周金文中的多数此类动词都见于传世文献且出现","categories":["02_字词句考释"],"year":2013,"publication":"深圳大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLiQ-Q_e8uVOh-GOYb4MmYlC3N1AlXpjTeneBIYsolD4wG_a-hLfXPobgI63ARp8OU6p9SYiWkf2k5onL4uj1BXhr_7i4KuK9WbLUj2KVguYwHhX27F_02FsAvF5PFSB-7Xd2PFlIZJTE8oX7yyaXU3UAp0AX8d4eGsHnXq8m7F0A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"141-147","volume":"30"},{"id":4722,"author":"武振玉; 梁浩","title":"两周金文中“有”的句法特点","abstract":"古汉语中涉及&quot;有&quot;的研究主要有存现句研究、&quot;有&quot;字句研究、&quot;有+VP&quot;格式研究三个方面,研究重点为&quot;有&quot;字句的历时演变和&quot;有&quot;的词义及语法属性,研究范围则基本限于传世文献。在两周金文中,&quot;有&quot;也是一个出现频率很高的词,共约102例,句法形式上全部带宾语,除了一般所见的体词性宾语外(50例),谓词性宾语(52例)比例之高是其明显特征。&quot;有+VP&quot;有&quot;有+V、有+状语.V、有+V.宾语、有+V.补语、有+VP1+VP2、有+V1和V2&quot;六种","categories":["02_字词句考释"],"year":2013,"publication":"西华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19642/j.issn.1672-8505.2013.01.007","pages":"32-35","volume":"32"},{"id":6225,"author":"张晨; 江学旺","title":"《近出殷周金文集录》和《二编》西周金文整理与研究","abstract":"本论文以《近出殷周金文集录》（以下简称《集录》）和《近出殷周金文集录二编》（以下简称《二编》）两部书中的西周金文为研究对象，从文字学角度分早、中、晚三期对其进行系统的整理和研究。论文分为绪论、字量统计分析、字频统计分析、文字结构类型与构形方式分析和疑难字集释五章，此外还有结语和附录各一，附于正文后，不单列为一章，附录部分为已识字和可隶定字字形表、不可隶定字字形表。第一章绪论简要介绍《集录》和《二编》的出版及研究情况，在此基础上提出本文的研究意义和研究方法；第二章和第三章按照早、中、晚三期，分别统计两部书中西周金文的单字量、总字量及字频，并根据相关统计数据进行归纳总结，第三章末还附有全部西周金文","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfZS5Yetg6NLJAAR3Uuy4aImXHx5bW7E4Q0xQkorI0CpPyEU1giFhTS-HGH7hI-O6aCrfNEiHgAGeFdGji_hfimyG93NL9eDsKb9aI7mzkglqkHUv3VVrFUNuYUgaeZ2c4ePOFMaCVcSCiwVX94RCG8gIofT3HijfRPpCEA7cvBk4StKIcQkLh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6226,"author":"赵雪艳; 江学旺","title":"《近出殷周金文集录》和《二编》春秋战国金文整理与研究","abstract":"本文以《近出殷周金文集录》（以下简称《集录》）和《近出殷周金文集录二编》（以下简称《二编》）中春秋和战国两个时期的文字为研究对象，从文字学的角度对其进行基础整理和研究。论文包含绪论、字量统计与分析、字频统计与分析、结构类型与构形方式研究、疑难字集释、结语和附录七部分。绪论简要介绍了《集录》和《二编》的相关内容，并介绍了前人对《集录》和《二编》的研究及已取得的成果，进而提出本论文的研究对象、研究意义和研究方法。第二章统计分析了《集录》和《二编》中春秋战国金文的字量。第三章统计分析了《集录》和《二编》中春秋战国金文的字频。第四章按照象形、指事、会意、形声四种结构类型对《集录》和《二编》中春秋战国金","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoi_ztJt9peAX3ZXdQUdQzHuG2Vdnl5W4KckYm_0sSJunlhBDfLwd6ixFXG19PS7hXuw8tYTdYdm4ttLjh7opP6-vttziVso2cmbXCAbgfEGUxyKQBVyLsI2kWneTpc6slH9-eKYtx0GvGPQsHBWxfsnzrJnwNsEe_JcrvRxS6bC4rMB2TrTEe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6228,"author":"胡俊佳; 叶斌","title":"陈鼓应《庄子今注今译》训诂平议","abstract":"本文以陈鼓应《庄子今注今译》为底本,选取其中解释错误或不准确,尤其是历来分歧颇多的语词,进行意义及用法的探讨和研究,对诸家特别是陈鼓应的注释进行综合的评论和判断,在传统训诂学考据方法的基础上,辅以现代语言学研究的一些方法论的运用,力求为当世之庄学研究提供新的思路和想法,以期得窥庄学之一二,对今世之庄学研究有所助益。全文共分五章。除第一章绪论、第五章余论,第二、三、四章为文章主体。第二章补充《庄子今注今译》训诂解释,第三章讨论书中训诂值得商榷的地方,第四章收录有自己的见解的条目。第二章收录臣妾、中绀而表素、已之大循、目不见等5条,第三章收录外篇垂天之云、望洋、练实、上下之县、不庭、飦粥等13条,","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWVZflV7ymXpxSQav_tnxvV1X0Cmcp4dmyHuWZWMEaWFhxKHTYDOtpH95PXLIu8aE3clokFXAfCuJXG2XWvMYZWrxG2q5bDZuJPquGzRhe1kZC47r_zNi23Ps-LzAfR7HrirM79JL-ZeR2rT2upETQTkTO9bXcpCNJXf9rYWrFphVrgF5nnSW6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6230,"author":"姚远; 徐在国","title":"曾侯乙墓樂器銘文集釋","abstract":"曾侯乙乐器发现至今已有30馀年,在此期间,学术界对其进行了全面深入地研究,成绩斐然。曾侯乙乐器铭文的出土不仅是研究古代音乐文化的珍贵实物材料,同时也为古文字研究提供了丰富的材料。对於这批铭文,学者们多有研究探讨,成果亦非常丰富,研究内容多集中在对文字的释读、对铭辞内容的解读以及对墓主年代的探讨等方面。本文以对文字的释读以及对铭辞内容解读为研究重点,主要包括以下几个方面：第一章为绪论。简要介绍曾侯乙墓乐器的出土情况,并对曾侯乙墓乐器铭文的研究概况进行简单地综述。同时也对本文的选题意义及研究方法作了简要介绍说明。第二章为曾侯乙墓乐器铭文集释,这部分是本文的主体,全面徵引了学者们对曾侯乙乐器铭文的相","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1e9r0HNc_SYmcZuTa57xsf3-l3O7DWDjATx8xuwW6yq9HmFBvEIKDdvYUUbr9cUjwErcKgF9uqez4oBdIqrNVPoq0jZisH6LyRwvg4lQiaNVO0x39j92B62PI8_lnYm1-FGfdvn0JAkRCh-8Hc98JhDu6LZvEA73jbCyefIPZdp4j-5Ty68Ys&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6234,"author":"鄭邦宏; 喻遂生","title":"戰國東方六國銅器文字構形演變研究","abstract":"本文以戰國東方六國銅器文字為材料,編成《戰國東方六國銅器文字分期字彙》,並以此探討戰國束方六國銅器文字的構形演變。文章共分五章。第一章《緒論》,主要介绍了前賢時修對戰國文字分域的研究、戰國銅器文字研究的成果,以及本文的研究材料、方法。第二章《六國金文簡化研究》,對漢古文字簡化現象的研究現狀作了簡單的梳理,並針對戰國東方六國銅器文字的實際情況,對其簡化現象作了分類討論。第三章《六國金文繁化研究》,簡單地回顧了學界對漢古文字繁化現象的研究現狀,以戰國東方六國銅器文字為材料,對其繁化現象作了分類討論。第四章《六國金文替換研究》,首先對漢古文字替換現象的研究現狀作了簡單的回顧,接著對戰國東方六國銅器文","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAbPkuRhUN5yzULlYQQErSsH84fOLZ1C9w2NG810RVjy1yCYQtDgbyso1CAan6bINmg45XgZ6DQsZlosJ4iWhn1b8ZCaCPvVm-cT83XVMZPvAWmVsa7bL_vtL3KNZYaPK4M6RA6TKM2GXkKCXJX5LSnVVMTTm245u3I7_bbiGPZjgNOwNBbGVQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6236,"author":"戴文颖; 程荣","title":"《新华字典》复音词研究","abstract":"《新华字典》是新中国成立后出版的第一部以现代汉语释义、举例的字典。当时没有一本规范的现代汉语辞书，《新华字典》除了担当字典的重要作用，还兼顾词典的功能。魏建功先生制定的“以音统字、以字统义、以义统词”的编纂总体例，体现在《新华字典》复音词的处理方面有不少独到之处。本论文以《新华字典》第10版为基础，综合考察了从1953年首版到最新2011年第11版之间的13个版本的复音词编纂情况。论文采取共时与历时结合的研究方法，运用词典学、词汇学、认知学等理论，对《新华字典》显性和隐性复音词进行了多角度的研究，填补了《新华字典》复音词编纂方法研究的空白，为小型汉语字典的研究和编纂提供有价值的参考依据，推动现","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCb06viYHzIzidCkne90pHltGc636al6jqNNnozGTpwI5q37NKYOWFNuP-NGVUrYkAhGGTq2U6FXqHO0xD7z6-QaqBaTyjFjaTee505-TJzrWP-RqAsutBEz2e7qpqQP16wyxEhPZRAlSZLBOP7ojL5cVRCx8DYYHIDWDfSOHGMgad8xCsY0AF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6237,"author":"肖峰; 林志强","title":"杨树达文字学思想专题研究","abstract":"楊樹達，字遇夫，號積微翁，湖南長沙人。我國近代著名語言學家，他學貫中西，在語法、修辭、訓詁、音韻、文字等方面均有很高造詣。本文就他的文字學研究進行多方位的介紹。全文共七部分，第一章為緒論，介紹的主要內容包括他的生平著述、本課題研究現狀、研究趨勢、本選題的意義、研究目標、研究方法和創新之處以及該論文各章内容的安排、次序和詳略等：第二章全面介紹他在“六書”中的指事研究領域裡所取得的成就，通過對指事研究歷史的梳理，一是厘清整個指事研究的學術源流，二是窺探楊樹達對傳統指事研究的繼承，通過對他著述的研究，確定他在此領域的創新，他提出了著名的“符號理論”，這也成為了指事理論的研究的一個重要的里程碑，對現代","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKVsg-b--xLkp2hgfUgd6Jw47m48w6W88MsnpsuoxGgM9zppB7IlcVYaBeDleOVM3mdMTddMKKrAg6lgGwGghPYiXktaWzy2wbUHLRfRKhTGStAj-h8Blo9Uh28NahmDp90whJGXAZoNoqfLQ_O2j2gfDKuhJvDVfbi-GSL2Uap5tI2Zmuqu08I&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6238,"author":"袁方; 陳鴻","title":"戰國晉系出土文獻形聲字研究","abstract":"近數十年來,随著考古材料的不斷發現,戰國文字材料也日益增多,戟國文字研究開始飛速發展,學者们也開始關注戟國文字的分域和断代研究。經過學者們的努力,戰國文字分域研究有了長足的發展,取得了一系列的優秀成果。尤其是出土文献材料比较大宗的秦系文字和楚系文字的研究更為突出,碩果累累。相较之下,晋系文字的整理和研究就顯得比较落後了。值得慶幸的是,近些年來,學者們也發現了這種狀況,并為改燮這種狀況努力著。本文立足于戟國晋系出土文獻材料,封晉系出土文献中的形馨字進行分析研究。文章内容共四章,分述如下：绪输。主要叙述了本文中“戰國晋系文字”的内涵、文章的選題意義、文章研究材料的遴取及研究方法和步骤、形馨辨析。第","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZfs2R5k8JXogs67SLaMOUwU_9hO8gTuSbVhLd5PZh089_BGNEF7Slubva1e-HxKLSUzYfgBCLpEMChuma04RfrsllcQwuG-oFI1h4CJk-JmJzXB8CDwTBDA1CxzRKOqrWI5HJeqguMXFqxIOxwiirNseIi6noXMtHzzc4gfzUQF1FeBjlxgyK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6239,"author":"何頔; 涂白奎; 曹建墩","title":"先秦青铜酒器自名研究","abstract":"先秦酒器由于其发展的局限性，在西周中期就已不多见，其自名研究虽没有青铜食器等研究深入，但由于考古资料匮乏，文献资料混乱，造成酒器自名众说纷纭，对于器物的命名、用途、形制识别不清。本文通过对《殷周金文集成》、《近出殷周金文集录》和最新的一些考古资料进行整理分析，将青铜酒器自名器中的自名情况一一整理，借助甲骨文、陶文和金文的对比，从铭文特点、形制联系、用途等方面进行梳理，进而分为三类：形制无重大变化，名称无重要变化：尊，卣，罍，，尊缶，鈚，同；形制有变化，但有延续性，名称无重要变化：爵，；形制有变化，名称有异称：壶，盉，觯。本文通过对先秦青铜酒器自名现象的全面梳理，对青铜酒器的定名、功用、形制演变","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIteOV6azzXeIiAsaZRhrQO_5eJZAM7HXSUAcIbogTRNPf9ETOCLsqRcfXmkGD_nEwYUm2yLLvJSQR050IgLOAuMB2eX2cMSplAbfERe9JfUVGnWJWJVZej5mpugDCzVfpy_V0QHqsaHy-sh7Evo2390Tzy_1vkF3GVV0p4V4kOKCzntmqEwyMt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6240,"author":"李言超; 钱宗武","title":"《逸周书》代词研究","abstract":"《逸周书》是周代历史文献的汇编,是先秦时期一部重要的典籍。在历史上,由于自身源流不清等原因,《逸周书》的文献价值没有得到充分的重视。近30年来,《逸周书》的研究价值逐渐为人们所认知,研究成果大量涌现。然而《逸周书》词汇研究特别是代词研究却较为薄弱。因此,《逸周书》的代词研究尚有很大空间。本文对《逸周书》的代词进行穷尽性的调查统计,运用定量定性分析法,把代词逐一归类,演绎其语法功能和语用特点。《逸周书》代词分为三大类：人称代词、指示代词和疑问代词。把人称代词分为自称代词、对称代词和他称代词三部分进行讨论,研究它们的数量、频率、称数以及语法功能；把指示代词分为近指代词、远指代词、虚指代词和无指代词","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIbGstLtkWffSyjjlR05k1XwSe0apvIcsmlYiNM7lFGkgqBJwrkS3XcJi7Bgp9N99MxBiieBGl6Z_IqOqL2jundqIPVuq2SOjq1mn_42hMzwI0shpSX7GyPGnnecfu1zOMZUKOJnIuryhZqSMgAzv87Usi748qauUk2G_0xxqSQBjFAChEQSm1G&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6242,"author":"田珂萌; 董莲池","title":"近十三年新发表殷商西周金文的整理与研究","abstract":"本文搜集了2000年以来《考古》、《文物》、《考古与文物》、《中原文物》、《华夏考古》、《中国历史文物》、《文博》、《考古学报》、《江汉考古》、《南方文物》、《东南文化》、《南开大学学报》、《北方文物》、《中国文物报》、《西北大学学报·社科版》、《湖南考古专辑》、《史学集刊》等期刊发表殷商西周金文,囊括了近十三年来新发表的殷商西周时期的金文资料。根据考古发掘报告和专家研究讨论成果一一指明每个字形所在刊物、载体和时代,以《说文解字》为顺序,编成文字编。文章对新发表金文中几个特殊的族徽文字进行整理和研究,主要从文字学角度出发,整理研究了冀族、(?)族、(?)族、(?)族、西单等族的族徽文字情况；文","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINpm_ipfTajwgfLd6rDmE4Qt_3yJvrirDkt6SgvgvZEXKPji5cNkytvSAel2vUYcQBPS0QIqcIUQ-ZyAPsbqVfmiGM4PTg1gqNSh9xdtARtYQNR2tPTyqovkTRjTeRTStc_2fuDuaXKaV5KUwE2GWYJwGCAlB1f2ZNlVzELK7zpFw7I69XpaNr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6243,"author":"陈宝娟; 陈鸿","title":"晋系彝器铭文词汇研究","abstract":"晋系青铜器铭文的研究多侧重文字考释或铭文集释,将晋系彝器铭文與词集研究结合起来的系统研究工作仍未展开,在金文研究中,语言层面尤其是词集系统的研究是一个薄弱环节。本选题希望通过晋系彝器铭文词集的系统研究,客观地呈现当时当地的真实语言现象。文章共分为六个部份：一、绪论。本部份简要介绍晋系彝器铭文词集研究背景、现状、材料来源；二、晋系彝铭名词性词集；三、晋系彝铭动词性词集；四、晋系彝铭形容词；五、数量词、副词、代词、连词、介词、助词等其他词类。第二至五部份重点对晋系彝器铭文词集按词性和主要意义类别逐一进行资料统计、列举和分析,个别以表格形式予以展现,力求全面地搭建晋系彝器铭文词集系统地词频结构和意义","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkIFlxu2r0J1QjfP7OC6zIqxCGx9jehLytnP4CSViKsnTS73dflNA0xjMBS0pZsOW2yN2zkO7ulA4lEmhCHWLl_U5gq_y1HNtVpdKsfo1x6sorvgN92GmgEowTZavt_klC63goeTCxT9Tpylw2ySEPAubt8cnyF2LE3_oDPWP9Meu8jnkTXTwR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6244,"author":"罗秋燕; 林志强","title":"汉字讹变现象综论","abstract":"本文主要是在前人研究的基础之上对汉字的讹变现象进行综合的探讨,首先对讹变的定义进行了界定,然后对汉字讹变现象的发现及研究历程进行了简要介绍,再对殷商时期、西周春秋时期、战国时期、秦初小篆时期、隶变时期、楷化时期、规范化时期等各个不同时期的汉字讹变情况进行了探讨,以期对汉字形体讹变的历史状况有大致的了解。以往的汉字形体讹变研究大多集中在古文字阶段,但其实今文字阶段也存在不少汉字形体讹变现象,故本文还对今文字阶段的汉字形体讹变现象作了粗浅的探讨。又从汉字形体产生讹变范围的大小对所收集到的五百多个讹变字例进行了整个汉字都发生了讹变、部分构件发生了讹变、某些笔画发生了讹变的分类,并探讨了讹变产生的原因","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOHVfPQhHSh5kZQfehHhE1b6WPdluOX8oMUlRJYyN0gWr90EizcUrD2b6jz_YLzEEiJIfyEyb8YKUKnJo5tV9nuTYtLfToxCYmL77prH-htzIcn7tAtlzAU7GuiW5vCLBjQ43tkA3-XIAiximwVNg-CzUQBguo1pHHA8CZIrCkIgi0JlAmN7QR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6245,"author":"王晓云; 郝士宏","title":"《古文字谱系疏证（一）》校订","abstract":"《古文字谱系疏证》(以下简称《疏证》)是国家社会科学基金重点项目“商周秦汉汉字发展沿革谱系研究”历经十年编纂而出的成果。作为一部便于多学科借鉴和应用的大型工具书,自出版以来,这部书给古文字学科以及相关学科的研究提供了很大的方便,但是也应该看到,编纂这样一部浩大的工具书,由于当时的认识水平和时间的限制,书中难免存在一些缺憾和不足。近年来,新的古文字材料不断公布,文字释读方面的研究成果不断推陈出新。在这种情况下,对《疏证》进行校订显得非常重要。本文主要按照原书体例对《古文字谱系疏证(一)》进行校订。校订包括字形不合原拓者,辞例不妥或释读有误者,书写不规范者,释义不确者,出处有误或不明者,器名有误或","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZ3KVX8kU7vLA-A9sGDxaJGUx8odIRQdy8BohK8pGTOYSfXB2YXsidnXKNkXJsWdNBPqeI4FHkVj0cXP28RvS6Chu-W_keoEpoCWxeN_YBCS-c7W3lB3VtsBliacx9z91XupLFKFjK714vCKhvbeBOnTnmU9hIF0EaIECxWvFhnaix0d8s1Wx1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6247,"author":"黃萍; 胡長春","title":"新出兵器銘文的整理與研究","abstract":"本文是关於新出兵器铭文的整理与研究。收录商至秦统一以前(即公元前221年)一千四五百年间有铭的兵器。主要著缘器名、时代、国别、铭文、考释及附缘几个部份。按殷商、西周、春秋、戟国时代来分,商至春秋,兵器铭文的排列以出土时间先後为序,戟国兵器铭文部份,采用“系”进行分类,不能归入某一“系”的,亦按出土时间先後顺序排列；而同一时期出土的则儘量做到按戈、戟、矛、殳、劍、铍、钺、戚、削、斧、矢、镞、泡、秘、胄、鐓、秘冒、弩楼、牙、距末来排列。本文分上下篇雨部份,上篇重在封相关文字考释研究,进而试国展现先秦各地区的政治、经济、文化的原始面貌；下篇重在著缘兵器铭文的国像资料。本输文共分雨大章输述。第一章,前","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL8bHhgkAxWHF9nocBDJkCKPaSs9vJlf8i08fMPLczHBVVpeNbISYsEm9rO5myISOZTZij0NFeRW2tEbWyC9PD8o_juSlZvtPODT7lU0o1WJgHHdLXRv8_Ntk1bLLGs-8pqR2EZJlucsz-Jgx9JzOn2fzBN-LYAyYtRCxaOGqeC_siJ2mSl6ExV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6250,"author":"劉孝霞; 董蓮池","title":"秦文字整理與研究","abstract":"秦文字是漢字發展史上的一個重要環節，它上承商周金文，下啟文獻用字，又被《說文解字》(以下簡稱《說文》)小篆所本，成為後世文獻用字的正字，是文字從異形到統一的一個關鍵時期，亦是戰國文字的收截之處，是後來的文獻用字的直接源頭，不僅有著文字學的意義，對於文獻學也具有重大意義。由於秦文字種類龐雜，研究也較為分散，目前對秦文字進行系統的研究整理成果還不多，所以對秦文字進行系統的整理研究是極其必要的。有專家曾多次呼吁，要有一部供文字學、古文獻學、考古學等多個學科使用的秦文字編。本論文所指的秦文字不僅包括春秋戰國時期的秦國文字還包括西周晚期和秦代時的秦人所用文字，種類有金文、玉石文字、簡牘文、璽印、封泥、陶","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKlO7QzxKxPsi_0fpTxr-GhysY7NQk7ac0tuPFaxmDPaqR45rbrvdMgQH5WKQ15pqcmWbIERS0SIJYy-68oGOonFuCpuCggt2T3AgTh-Jo4f6s1LzwxdmeAzXQqpb5KxAmxidHhzcxV594VN7gm5YyNL8k4XNw0AqG5U_zqO2PtGhTEvDXVFLbH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6251,"author":"余淼淼; 董蓮池","title":"晉系金文整理與研究","abstract":"本文分上下编,上编是封晋系金文構形的研究,下编為晋系金文全编。上编分為雨章。第一章為绪输,封本文的题目造行了闡釋,介绍了本文的研究意羲,本文之所以選擇晉系金文作為研究封象,是因為晋系金文在同時期的金文中估有很大比重。晋系金文又是晋系文字的主流部份,能夠體现晋系文字的主要特點。通過研究晋系金文,可以窥見晋系地匾當年文字的真實面貌和燮化规律。研究现状部份封晋系金文的以往研究情況做了综述,分為雨類。一類是包含且提到晋系金文的研究成果還有一類是以考释文字的角度來研究晋系金文的研究成果。第二章是封晋系金文構形的研究,探索了晋系金文簡化和繁化、訛燮和替换等的構形特點和规律,是從文字學角度以“分析字形”焉主","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIS4b_HazDUtjQZM2XRKv3TkOMYb293L0LkUqn9DcGXVklCuXJamNuipPEvVDyoMU_8tyqPtZG5wAKkZ2diiTrLUw_fdaYP0lM4uRgZ3mxJV6Bfapn4yz7TJPW61AkthlZnuEAPBmT68tukne_fYWkzGUaqxC52Un2wxd6mX8YIx2Q-4EwgtEc3&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6252,"author":"付保珂; 胡玉冰","title":"宁夏吴忠市出土文献综合研究","abstract":"宁夏吴忠市出土文献,从时代看,自秦汉迄民国；从文字载体看,以汉文文献为主,也有少量的西夏文、藏文、梵文等文种的文献；从物质载体看,金属质和石质文献为大宗,亦有少量的纸质、帛质和木质文献。石质文献包括碑刻、砖瓦、陶瓷铭文文献,金属质文献主要包括玺印、钱币、造像、铜镜、权、钟、铃等铭文文献。另外,宁夏、甘肃旧志中也保存了不少吴忠市石刻史料。目前尚未有人对吴忠市出土文献做过专门系统的梳理和研究工作。本文在综述吴忠市出土文献整理研究成果、梳理吴忠市出土文献概况的基础上,将吴忠市出土文献分为三类：石质文献、金属质文献和纸质、帛质、木质文献。论文侧重于碑刻文献研究,共梳理出吴忠市碑刻48通,分布于唐、明、","categories":["02_字词句考释"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqT6lq-6T5w4hNPLfex_proaqEBO-VCrsCAHwKtycBZ-BdwkjBsrZ5tWC9D-BLwPSaUjB0xXMPmZ3F95vAGfMi4UqQ93qnDPXP5cipCbHCMhlcq7r6LIIuyJ7c8RSKrUGTqlvuJPOZ1FFiYpJpb8opewaHo5_YlD3JaUCbZBpEkxpf91rkg_Wm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6255,"author":"贾洪波","title":"关于《论令彝铭文的年代与人物纠葛》一文的补正","abstract":"笔者曾于《中国史研究》2003年第1期发表《论令彝铭文的年代与人物纠葛——兼略申唐兰先生西周金文&quot;康宫说&quot;》一文。最近重新翻检此文,推证说明过程有所未周。本着对学术严谨负责的态度,今欲再借《中国史研究》宝地一角,以作补正。原文(第10页)&quot;再推去两个小月的两天,则五月三十日为辛卯日&quot;句中的&quot;辛卯&quot;当改为&quot;戊子&quot;。再者&quot;如此间有连大月,则五月二十九日为辛卯日&quot;一句应删去,&quot;则遣器的十三月辛卯可有朔日和初二日两种安排&quot;句当改为&quot;则遣器的十","categories":["02_字词句考释"],"year":2013,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjco5EfyzApKzHwkdZvMP1o4YPbSRxkU0pDFhW7CCP1JxVIq87YzIdmQ3y-JhHNPbNE8kZD-x5UW3rrduiVx4VWH3ZCRvkGYGbN5QL0rV-BmyxKfU0I8oD6vei_spJnS7HPkrq1JHn6SPcXFEyxuii0fPKBEotlmP8PrzsqJLurA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30","volume":""},{"id":6257,"author":"王贵元","title":"汉字发展史的几个核心问题","abstract":"从形体特征看,整个汉字发展史经历了象形、亚象形、隶体和楷体四个阶段。商代、西周汉字形体为象形形体,春秋至战国中期为亚象形形体,战国后期至东汉为隶体,三国以后为楷体。象形、亚象形阶段构形依据是物象,隶体、楷体阶段构形依据是词的音义。在隶变后汉字新体系建立过程中,始终存在着两种力量的互动,一种是打破旧形体建立新形体的创新动能,表现为多途探索;另一种是结构平衡,从字形系统完善的角度来调整、确定种种异形成分的生存状态。在前期,多途探索处于主导地位,后期则结构平衡处于主导地位。共生式发展与替代式发展是汉字字形体系建立过程中两种发展模式,其中,共生式发展是常态。","categories":["02_字词句考释"],"year":2013,"publication":"中国语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINZswuc_f-MNbWyTzcxdr06SPB9x8vzaXytvDA25HYaOcomjYeTGNo6zsniD0kb1R1bVh9kO6_XIQqMUH4mcDgM2lI2pECn0WJvPBCzrb-J-A2wXwB1jre-5k3z8NimQ0iyHccIRlcChpBC8QpMSEG7aL8scLENY94lw7lqWmfAw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3-12, 95","volume":""},{"id":6566,"author":"陳絜","title":"利用出土文献校读典籍二则","abstract":"《左传》庄公十八年&quot;赐马三匹&quot;乃&quot;赐马四匹&quot;之误,其致误原因或为汉儒在禁古定过程中不识借笔合文所致。穀梁《春秋》经传昭公二十一年有&quot;蔡侯东&quot;之名,或乃&quot;蔡侯束&quot;之误释,出土文献中&quot;束&quot;、&quot;东&quot;形近易淆,而作谐声偏旁时,&quot;束&quot;、&quot;朱&quot;二字又音近互通,故&quot;蔡侯束&quot;也即左氏经传及春秋金文中的&quot;蔡侯朱&quot;,与昭公二十三年所见之&quot;蔡侯东国&quot;不可混为一谈。","categories":["02_字词句考释"],"year":2013,"publication":"传统中国研究集刊（第十一辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLquhCLhr_PN8sxwP6jxNuYk7W45lgHVB9mNznRH2yrsYH2T6hLkmKAWZFgjD0ORlsH1xVQ-JELCmmq9vEEhvVx2FmEN9IGPWrR85yPZcavjv5Rs3XBw-Afmq_XhiAclq2QN5cwECmnCn7xRuvwnp76-t_5wE-4jgIiXuVyHNLCJoK_25SPjXmF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-25","volume":""},{"id":6572,"author":"趙林","title":"説尸及《山海經》的諸尸","abstract":"壹、前言《山海經》中共記有13位以&quot;尸&quot;爲名者,這13名&quot;尸&quot;者在《山海經》的文本中,分别以神、人、獸、物稱之。唯傳統的注釋家或以形解、尸解及成神來作解説,①而現代學者則以爲《山海經》的諸尸或爲尸體,或爲尸祭中的尸,或爲女巫裝扮的旱魃,或爲神主、神象,或爲石主、木主,或爲岩畫、帛畫,或爲族名、部落酋長之名及少數民族所建方國之名。這些不同的看法當係出自對&quot;尸&quot;字及對與尸相","categories":["02_字词句考释"],"year":2013,"publication":"甲骨文与殷商史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUvxUTFJ2mveMoUEQGiw2PqB2Z3oX23vA_4JjpDWS-OScSyc7hdCdKz-pI43g8DvudeWgeNpKh35MHBtjw3L7v7DMnAJ8tZ7NZaaMQU3yx65Bl6LS3H_aHAjhuIKRZX9CijUrfvrBeSP457rWxYWX5UmUYN7kwQHzPI914rFWxGw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-81","volume":""},{"id":6573,"author":"董莲池","title":"释吕壶铭中的“豹”字","abstract":"吕壶铭中&quot;孚&quot;的下一字或释&quot;贝氒&quot;二字,或释&quot;得&quot;,或释&quot;兕&quot;,至今没有定释,是一个疑难字,本文援据新出土的西周金文资料,将其释为&quot;豹&quot;。并引证文献资料对铭意做了解说。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-DhPinh2qGVqHWkqyaK5jNqVlBkpb27ISN1HBqIWoySDxCoOwdIB7KeBOgutEI5WGOaozI-JgaRGnCGFMeXjUGUOA-AQo9FQ04Z_YRIjiq6pnD6sR6-H7RL4yJi2vCTgYO_2NZ0TkUOy-yAEWoVT1MrlQjQe6RLeNHetPALxYrg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46340","volume":"17"},{"id":6575,"author":"张再兴","title":"也说柞伯鼎铭“無殳”一词","abstract":"柞伯鼎铭的&quot;無殳&quot;一词应该读作&quot;舞殳&quot;,就是举起武器作乱的意思。传世的敔簋铭文中&quot;南淮尸(夷)■■&quot;中的■可以释为&quot;■殳&quot;,读作&quot;摇殳&quot;,也就是&quot;动殳&quot;,与&quot;舞殳&quot;的意思是一样的。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHHNNzv49qVW_QLnc02Z_bvnnR6I3VR1HR6HSsDbXsfyf9RDRcilTDvvkG686vo9GTUIxcGGVVOPbLqLoMpJtvBUjabmSNdiqmbg3ejkSabComd5Vjv1UYUoTCPqFS_KZQtTt1nkWu4mTffWvRyE_pGqHOrO34N11rdPcNZ0--4w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-22","volume":"17"},{"id":6576,"author":"陈英杰","title":"郑井叔钟之“霱钟”正义——兼说大克鼎之“史小臣霱鼓钟”","abstract":"文章指出,郑井叔钟&quot;霱钟&quot;之霱是形容乐钟声音清越、空灵而美妙的一个词,解为美善之义泛而不切。克鼎之&quot;史小臣霱鼓钟&quot;是一名词性结构,义即史小臣掌管的霱鼓钟。&quot;霱鼓钟&quot;义同于&quot;霱钟&quot;。&quot;霱&quot;字是从&quot;■&quot;派生专门表示乐音的一个字,在古文字字编中,应于龠部增立&quot;■&quot;字头。秦公镈之&quot;■(音)&quot;并非心灵专字,其中■符乃用其空明之义,此字与■之构形均与心之孔窍有关,乃形容心之通彻,由心之通彻引申指乐音之空灵。秦景公石磬&quot;靇&quot;与■通","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIzlGWfegfIeH5MpMnMgjGnrMF9hCbdZqD0i88O8YgS_7-QtzZf_qSVeCONA9dbJ_l4ZiVI6NE6zu3Aabf_CJhYe3GR-d1vTQjTVJtz0opu671sU1oU--GUkoKAlmF9Aahxcwm8JD9X2eZJbUlVjVHgRHO4bxZ6zo6m2PTo4Djr2g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-27","volume":"17"},{"id":6577,"author":"刘钊","title":"晋系金文札记二则","abstract":"本文由两则札记组成,分别对东周晋系金文(木大)氏壶和郘钟铭文的释读提出一点意见。第一篇结合器形纹饰,认为(木大)氏壶铭&quot;自颂既好&quot;之&quot;颂&quot;字当读为容貌之容。郘钟铭文&quot;(?)&quot;字读为&quot;陈&quot;之说似未获广泛注意,第二篇主要为之做一点补证。","categories":["02_字词句考释"],"year":2013,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJB9i_2tEvKh_It2Dw2UXfTi_GIHg7A6InSxmvyGOi_WkQg866gMBt2FkUOL9_sP2AQKWA2ziVp8Z_hvwSvF3j6h0G-MZ3GOmpK2KsLkFZQXI804lUjp9ql_Vj7TpB-kkK_MoYyVd4Ml8GWBfiQT3FVjZRuHfdXGia1yGfj_3hb-A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-31","volume":"17"},{"id":6952,"author":"肖辛格","title":"“辛”字考释","abstract":"&quot;辛&quot;字的历史十分久远,在甲骨文中便已出现。历来有一些针对&quot;辛&quot;字的研究,但对该字的本义等方面的问题仍然存在诸多分歧,意见不一。本文将从字形演变、构造、意义、文化内涵等诸方面对&quot;辛&quot;字进行多方位的考释,并从形旁为&quot;辛&quot;的字、&quot;辛&quot;字甲骨文字形等方面对本义进行具体考察,认为辛字的本义应为&quot;梓&quot;树。","categories":["02_字词句考释"],"year":2013,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2FwS_P0MGgktR_NxQtYB9H2G7_-3N4giM8pGtebBjSFZZ8jG3FDmykuZaBZ4ZGDXqzfCye9RNQHa8eDcn2CBIjFzHYgQgn6rxhpDUhoiqSrR3F1sf1oOK1HEQAob8qyw5MW9J3VxTlaYmTJ4i0-PqyV187_NO-XqfryVcRFpgL1nXOXFpn3dr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-60","volume":""},{"id":4717,"author":"郭永秉; 鄔可晶","title":"說“索”、“■”","abstract":"殷墟甲骨文中有如卜之字:A1:■《甲骨文合集》(以下簡稱“《合》”)20306乙(■組,字形取自《乙編》105)■《合》21306甲(■組,字形取自《乙編》124)A2:■《合》335(賓組)A3:■《合》15121(■賓間組)前人多以A1、A2、A3爲一字異體,本文從之。在没有必要加以區分的時候,統一用“A”爲此字代號。","categories":["02_字词句考释"],"year":2012,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrIlYUM1ZWRHvsfSwarv332LEwV5dPC-OX2XXM6gNtdsccpxU-Zj9o-QuKUeQUlis1f3xavjrh_umSE2Rv-Wlf7mqc9sU0PECmXHqc73aOOIgx6fdyP6v4lxGNn-9ep3fDfxtKLCnBZ4Y3uqj7GjQE5M5EQs3JcVtiamNAv5_xw6GXXP_j0_wh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"99-118","volume":""},{"id":4718,"author":"李學勤","title":"由沂水新出盂銘釋金文“總”字","abstract":"2012年初,山東沂水天上王城景區施工,發現一批春秋青銅器,内有帶銘文的兩件,已經任相宏等先生在《中國文物報》上撰文介紹。[1]兩件器物,據銘文一件是宋國華氏媵女的鼎,一件是江國公族自作的盂,都很重要。其確切時代,要等器物修復後,結合形制紋飾的特徵,才能推定。不過盂的銘文裏有一個字,特别引人注意,有可能爲解決金文研究中的疑謎提供綫索,我想在這裏試作討論。盂上面的銘文共有七行三十八字,兹依原行款隸寫如下:","categories":["02_字词句考释","01_新出器物"],"year":2012,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKSr3-SyzEPwixxYrceHJkmkdUuyWzhQAvWYMkWl0zQwtNpn0PMg_O2GC5V5lvQ8k2SO76nubnucN9UJONumVm1tSEsehtFTaWQtTpRyU4iPclxX3ntVFL5qGcjomjd9wbDXk3uKtSzeBSFTs7bQqrZBpNMyo1QUyGmwj94jq3USsEBPYM5CpCr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-121","volume":""},{"id":4719,"author":"馮時","title":"班簋銘文補釋","abstract":"班簋舊藏清宫,著録於《西清古鑒》卷十三。1972年北京市物資回收公司有色金屬供應站自廢銅中揀拾原器而得幸存,後著録於《殷周金文集成》4341(見圖一)。作爲西周穆王世之標準器,班簋所鑄197字長銘記述了毛伯與毛班父子勤王之事,毛班頌揚其父功德,具有重要的史料價值。關於簋銘的考證及文義的疏通,學者已有很好的意見,但有些問題仍待發覆。今先將銘文釋寫於下,爾後就相關問題略作補釋。","categories":["02_字词句考释"],"year":2012,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBhRec1OJyH29AUzGPHoFgZ2MddhI4uTxXZRDMxBn5JrxCeT26_v77zMuQP3rnsfG4t770U6TlMcood8Q75Cfugk6dw3ocNFCZmApPCcvyvYjF0mBm0udSzaAjTEC5ShDn-Y0Lb2nKnrvgGbzLGKkHcCF5jmy7TPnYw9g55Vza67PoseG9rzLQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-134","volume":""},{"id":4721,"author":"邢文","title":"西周金文書法的體勢","abstract":"胡小石先生論西周金文書法的體勢,有所謂“西周夷、厲諸朝,如大克鼎、散氏盤則用横勢。齊楚諸器則率取縱勢”等。[1]胡氏所論,是把金文書法的縱勢與横勢問題置於整個中國書法史的背景中來討論的:就大概言,殷、周訖秦縱勢多,漢、魏、晉、南北朝横勢多。殷書甲骨刻","categories":["02_字词句考释"],"year":2012,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfp535tnjI4JEAfeDZIbyuqTyGlfv86HXz35PLdiV6tqSngHEApvuXWrvDg7kY3EdjPvGECqYDd4PUdmqOAQCpZB2vXryI54j29DcR57GgjQaDRlXB1Wm6qu-I7wqm6u1-11yFG-1IO6sH6g4nZ5AmsuOH-LkxQgc4jSofX1N1UxvPOzRoVxCq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"138-157","volume":""},{"id":4724,"author":"马超","title":"从古文字形体看古代社会的风俗与文化","abstract":"字形是汉字三要素之一,其本身具有重要的价值。由于汉字形体总量巨大,加之汉字具有以形表意的性质,因此,汉字形体隐含了古代社会众多方面的信息。依据甲骨文、金文等古文字形体材料,我们可以了解到先民们所处时代的风俗与文化方面的一些内容,例如当时的饮食起居、生产劳动、刑罚战争、神话传说等。","categories":["02_字词句考释"],"year":2012,"publication":"商丘职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2dulnEJvnKYXYSlbnrfM7hAabr4jaxK0PIObPMBAMeIX2fSPXC4cHpBJs-W4xdIvrGKLfJ-xH-pB2ifwa2WLcB8zPs2l-goRXTqNv6sQDz41FG2yxE0_OYcpZzjUbf_jFIIUqA7fUoN4dw0UxX4LEiEJPrSZs1Wa3b2bpcFRexw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81-82","volume":"11"},{"id":4727,"author":"邹芙都","title":"铜器用途铭辞考辨二题","abstract":"商周青铜器中的&quot;弄&quot;器非为以往学界所论为专供把玩欣赏的&quot;弄器&quot;,&quot;弄&quot;有表&quot;珍&quot;、&quot;宝&quot;之义,&quot;弄&quot;器与金文中常见的&quot;宝&quot;器类同,是为礼乐重器,&quot;弄&quot;器的用途可能与时人为修德而作的宝器有关。&quot;行&quot;器非为单一的表征行巡狩时所用器,包含多种用途并运用于不同场合,如为邦交盟会出使时所用器、随葬的明器、征行巡狩时所用器、外出娱游时所用器等。","categories":["02_字词句考释"],"year":2012,"publication":"求索","link":"https://link.cnki.net/doi/10.16059/j.cnki.cn43-1008/c.2012.07.035","pages":"109-111","volume":""},{"id":4729,"author":"刘原","title":"秦青铜礼器铭文文学意义考论","abstract":"秦青铜礼器是秦文明的重要载体之一。作为秦文化的重要物质遗存,它具有物质文化和精神文化两方面的宝贵价值。秦青铜器铭文作为秦文学之萌芽,其内蕴丰富,文笔凝练,韵语优美,颇具西周青铜礼器铭文的叙事风格与艺术特色,说明它与西周礼乐文化有着密切的渊源关系。","categories":["02_字词句考释"],"year":2012,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIezNd12gXZGdfCa1StbVc10bAZMH29EeVPar5ERhbPFbzM4Yeutt-o7k5SCuvkJCj5CVrmBLQD3PdlDNDF2RjK-gtYlPT_npwsC_xBEUwD6_8FGLP-Sy-5OhAoBHenH4I2AcBKpWjjvfHTo2Gd5vacBFSleNE-pne8U0_8wQjPww==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-94","volume":""},{"id":4730,"author":"汤志彪","title":"鸟虫书三考","abstract":"《集成》10407号&quot;鸟书箴铭带钩&quot;中的&quot;毋诈毋挴&quot;,指既不要诈伪,也不要贪心;&quot;汲于利&quot;当读作&quot;急于利&quot;,与&quot;重利&quot;意思相当;&quot;母产又苟&quot;当读作&quot;毋产有苟&quot;;&quot;悊冬&quot;当释读作&quot;慎终&quot;。《集成》34号铜钟铭文中的&quot;搏武&quot;是形容军队阵容鼎盛壮大的。&quot;鄬子受编钟&quot;铭文中的&quot;月&quot;字下的两短横当是合文符号。","categories":["02_字词句考释"],"year":2012,"publication":"东北师大学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16164/j.cnki.22-1062/c.2012.04.034","pages":"96-101","volume":""},{"id":4731,"author":"张再兴","title":"金文语境异体字初探","abstract":"语境异体字是指在具体文献中受上下文语言环境影响而形成的异体字。这一现象在多种文献中都存在。本文探讨金文的语境异体字。根据形成语境的差异,可以分为形体语境异体字、意义语境异体字、形义语境异体字。语境异体字在数量、形体结构、字形发展过程等方面具有独特的特征。","categories":["02_字词句考释"],"year":2012,"publication":"兰州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8rz6zw7ZVrtVqLU6ht8YVspxqx3wKZGuDUxIse8BN0m3LEXcNIu80Vpsb79Ep4hFJ_ysRspI6rwyo5x3U0DA1UuCN42m-nOMemMGFHu_Z6yUTJya1ya70U8Uc7GrkI5T4YNs-zDD3cixgk5Q_Od1wcFNgIUDLTy4AQO27HPOm-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-115","volume":""},{"id":4732,"author":"刘孝霞","title":"“郭大夫甑”补说","abstract":"文章对&quot;■&quot;形体进行研究,提出三点理由,否定了《近出二》&quot;淳于&quot;的释法,认为当从李家浩先生释为&quot;郭&quot;。文章还对&quot;■&quot;形体作了研究,从金文中钧字的构形出发,否定了释&quot;钧&quot;的可能。","categories":["02_字词句考释"],"year":2012,"publication":"兰州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8rz6zw7ZVrtVqLU6ht8YVspxqx3wKZGuDUxIse8BN0m3LEXcNIu80vRk3RoX2MIIBgGHin40dt8iYj_qE7tPH2mY5yenmXM7vVe-2wO_kH-Jfn78qNPmnNUtfG_gtZ_xHN2d8ncDdmSQ0Hy8avEk3255oysQUjA4WoQ64yU7iDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"116-117, 120","volume":""},{"id":4746,"author":"杨秀恩","title":"春秋金文构件定位研究","abstract":"汉字形体的演化表现为构件的定形、定量、定位和定向。《殷周金文集成》、《新收殷周青铜器铭文暨器影汇编》所收录的春秋金文中,构件未定位的单字共91个,分形声字的形符、声符位置不定;会形或会意字构件位置不定等情形。通过对构件未定位的单字的各异构的频率统计,描写了春秋金文在构件定位方面的特征。在共见于西周金文和春秋金文的单字中,构件不定位的有87个,其整体及异构的字频统计、比较显示:春秋金文文字系统较之西周金文在构件定位方面有所迈进。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.02.006","pages":"74-78","volume":"33"},{"id":4748,"author":"邵崇山","title":"试论鄩仲匜铭文及其相关问题","abstract":"鄩仲匜是出土于春秋时期墓葬的一件有铭青铜器。对铭文所载撰内容,历来有诸多学者对鄩氏族存在持有较大争论。鄩仲匜铭文的正确诠释与解读对于研究商周墓葬中的青铜器组合演变、鄩氏的渊源、地望以及各方国的关系具有一定的作用。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.02.021","pages":"29-32","volume":"33"},{"id":4749,"author":"薛来","title":"秦始皇用“朕”新考","abstract":"先秦的语言中,第一人称代词有余(予)、朕、我、吾、卬、台。自秦以降,秦始皇仅将&quot;朕&quot;作为自称而独用,这和先秦历史文献中将&quot;朕&quot;作为自称的人物的阶级背景以及&quot;朕&quot;字的甲金文形体所蕴涵的历史文化意义有着重要的联系。对这个问题的探究,既能促进先秦、秦汉史的发展,又对文字学、古汉语研究等领域大有裨益。","categories":["02_字词句考释"],"year":2012,"publication":"重庆交通大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPXlebRC4ZGShWEu8Opfu--qlPv08l0sqnUOLTL5jzaj75yMOIMv50F65XmxLZZiVDJozc_y7hWItR9T7hX5Sdo-2HnYMtpAS-749BC66nFdOk-vy5lPLgFdXhv-vfbPNqSAukYSz_puO_rMDVoOH0c9RJdeCfpmkrRA1_MLOp8w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-79","volume":"12"},{"id":4751,"author":"朱学文","title":"有关秦漆器铭文的几个问题","abstract":"通过考古资料及相关秦陶文、瓦文、兵器铭文的比较研究,对秦漆器的部分铭文做进一步的阐释。","categories":["02_字词句考释"],"year":2012,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdBONthVzE-OZcGwp6OVd2TmMBza_1mqyEQbpkEKSbI206OsG_X7wSLDN6oz-gvvoBi5S-1OkQd2xw1GBLtkQT-7rzR6jjFYrEKLXS8mM7FNa27bANCogOxi6gMZqxr5G7Gb1EFO_oVUy61JCryVX-Du6_xGK2UTTOInzLSbsZQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-58","volume":""},{"id":4754,"author":"陆德富","title":"三晋兵器铭文中的“冶事”与“冶人”","abstract":"三晋兵器铭文中旧或释为&quot;冶吏&quot;、&quot;冶史&quot;的词当释为&quot;冶事&quot;。&quot;冶事&quot;是以冶为职事的意思。&quot;冶事&quot;可能是冶的别称。反映三级督造制度的三晋兵器铭文中,最后一级还有称&quot;冶人&quot;的。&quot;冶人&quot;是冶的别称。","categories":["02_字词句考释"],"year":2012,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvE-DMgzcvW5XeuM1YydjCUV7xSB60CKPQcHZmuVyrlQmOMJNmv5OY0JIF7RlTShAyGkLPpyDcHaXrRDywBmRzNiDGS9kiJ_73PfJY8frMrU_E-y2NbBxrTyR3m5J1Hof7JCTGiE8-8hUG5QUCSx5dizvyaE0Kyu3mlrgbgx7bbw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-114","volume":""},{"id":4755,"author":"张全海","title":"“巫”字的起源","abstract":"说到&quot;巫&quot;字的起源,李零曾专门将先秦两汉文字材料中的&quot;巫&quot;字进行排列比较(《中国方术续考》,东方出版社,2001年),使得我们可以清晰地看到&quot;巫&quot;字字形的发展变化历程。就已有的研究成果看,目前所能追溯到的最早的&quot;巫&quot;字是甲骨文&quot;(?)&quot;字。学界对于甲骨文中的&quot;(?)&quot;字研究由来已久,最先将其定为&quot;巫&quot;字的是唐兰(《古文字学导论》,齐鲁书社,1981年),他以秦代《诅楚文》石刻中的&quot;咸&quot;(巫咸)二字反推甲骨文和金文中的&quot;(?)&","categories":["02_字词句考释"],"year":2012,"publication":"寻根","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_jy9OOm52nkFz84CQL_3oXqEocqTVbEoc-D_hWVyYNQ_Wuui0bHPXF8VlCE58lWI03LYEjtSvn3Map_bCdHS2YWXQTE1WdXIs85hdLLu_v3LVdUHzKD6_Q5LnLFfWwQ9OhA5FiBPYehcEZ9vsP74AeHK0WjxtMt5rQAR1Wx5_eQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-99","volume":""},{"id":4758,"author":"寇占民","title":"金文句读释例","abstract":"句读既是学习出土文献的第一关,也是研究这些材料的内容之一。两周金文内容丰富,长篇较多,由于它们本身没有句读标识,学界就一些金文句读的理解上仁智互见,从而导致对同一篇金文的解读出现了较大的差异,这些分歧便成了研究和使用这些宝贵材料的障碍。今就利簋、墙盘、师■鼎、麦尊、六年碉生簋铭中具有分歧的句读加以疏证。","categories":["02_字词句考释"],"year":2012,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLFGQpWA-Oj4A3vXGzcvjVClwgjEyp5E86Oz1X2mqkwOUyTtl3dtO0UagFm-6bp7k2mR3hgSaLSQLfchxuW6H7VuuoQHwJ0X2Kz28mPLg9vcxZB28s4XEpMfOpWbi94OwaxHS9U3_RQ6qjl_UXRrERfSwyd3H31_TAx5High2DDoQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-87, 103","volume":""},{"id":4759,"author":"杨秀恩","title":"金文考释三则","abstract":"齐大宰归父盘(《集成》10151)中的&quot;祈&quot;作■、蔡叔季之孙■匜(《集成》10284)中的&quot;祈&quot;作■,应隶定为■,从&quot;兽&quot;,是■的另一个异构字。而学者多隶■为或■,于构形皆无说。两周金文中,&quot;单&quot;&quot;兽&quot;可互代。曾侯子镈(《商周金文资料通鉴》15762、15763、15764、15765)有■,应隶为■,为&quot;鐘&quot;的异构。■簋(《集成》3888)中的■字,应为&quot;得&quot;之后起形声字。","categories":["02_字词句考释"],"year":2012,"publication":"吉林师范大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInNwYOHdiG3nLVTP_OvY57wBdxzAjxgo3UK3RPSonPIGHyspxJieQkTZ-2hA6ZSpxtqho-0tyO-1ns1x7ZU_XpvYePhZBz_ZrpwAnS0G3cxPdTatwGDqbgb9nZ6N-kHtqhYxg5hWUeTdTY46sIQxC19BXQtCq_7Qe5Xdwp3EDC0g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-34","volume":"40"},{"id":4760,"author":"王秀丽","title":"金文复音词同词异字现象探析","abstract":"同一个词语的不同书写形式称为同词异字。同词异字是从词的角度来观察记录词语的文字,它不等同于异体字。对金文复音词同词异字现象进行分析,有助于探讨汉字本身形、音、义之间的关系及同词异字的字际关系,对汉语词汇史和语源学的研究也有积极的作用。从文字关系上看,金文复音词同词异字之间不只是简单笼统的异体字关系,还有通假、古今、同源、增繁、简省、字形错讹等字际关系。","categories":["02_字词句考释"],"year":2012,"publication":"黄河科技大学学报","link":"https://link.cnki.net/doi/10.19576/j.issn.1008-5424.2012.03.025","pages":"103-106, 109","volume":"14"},{"id":4761,"author":"王瑞英","title":"西周金文异体字的动态考察","abstract":"西周金文属于早期汉字体系,由于汉字体系发展尚不完善,异体字占西周文字总量的比例重大。从动态发展的角度对西周金文异体字加以考察,对于了解西周金文文字系统及用字实际,更好地理解古今字、异体字、假借字等传统文字学概念及其之间的关系多有裨益。","categories":["02_字词句考释"],"year":2012,"publication":"黄河科技大学学报","link":"https://link.cnki.net/doi/10.19576/j.issn.1008-5424.2012.03.026","pages":"107-109","volume":"14"},{"id":4762,"author":"黄锦前","title":"霸伯盂铭文考释","abstract":"近年来,山西省翼城县大河口西周墓地出土一大批有铭青铜器。其中M1017所出一件霸伯盂,器铭所记关乎古代宾礼制度,内容可与《仪礼·聘礼》、《礼记·聘义》、《周礼·秋官·大行人》及《小行人》等所载之相关文字互相发明,由此可窥见西周时期较为完整的聘仪,对于西周时期礼制的研究有着重要意义,是近年来商周青铜器铭文最重要的发现之一。本文对该篇铭文文字进行了详细考释,并结合传世文献对铭文内涵进行了初步解读;还结合该墓所出其他青铜器及铭文等有关资料,对该墓墓主和年代作出了简要的论述。","categories":["02_字词句考释"],"year":2012,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBKRccM4pqdDZA_4zx_mvbwvLpxNh2Y7XhafiiFX8r15L6r8YgqG5TUWUNigWSo_f0sr__cw21_R6qMcDbOjFbmnhWSm5iqoMfoRSH2tm-om6A4Rpsx_JmdyTnJvfwPR0c_ddwEtYGg0aTeYXDfLPJBbFN5YPDMqkDYcLSuUnQ3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48-54","volume":""},{"id":4766,"author":"王毅","title":"《周易·大畜》考释三则","abstract":"《周易》大畜卦的爻辞&quot;良马逐&quot;、&quot;童牛之牿&quot;、&quot;豮豕之牙&quot;,历来各种见解较多。细究起来,对&quot;逐&quot;、&quot;童&quot;、&quot;牙&quot;等关键词的释义存在很多疑点。本文运用训诂学的方法,一方面通过对词义引申发展脉络的梳理分析,确定义位在引申系列中的位置;另一方面系联同源词,从更广阔的视","categories":["02_字词句考释"],"year":2012,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK3zT0vGo2eFL1BkU4OS-yoXtPq5n6nBWBA7q_GpIjn5nhPLV3AaT0n1rKY0wlXLpszDyRhXldKac47GD1bpyYTGBj74SywhUALcf6uouPwtU4oiwMIHVq9ue51RA-Z0OQSqsLc8gT95MxYYc1IbN7rHZty4o2GSHG7mDRp2tqQvQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-79, 70","volume":""},{"id":4768,"author":"刘书芬","title":"西周金文中的颜色形容词","abstract":"阐述已释的西周金文颜色形容词,探讨它们字形义和词汇义,判定一些有争议的颜色形容词,确定西周金文颜色形容词的个数及各词出现的次数,分析它们的语法功能。","categories":["02_字词句考释"],"year":2012,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHo9LetgIrcBBHr3O8SAp9IxrC3M9JoGvopR2Oj-OufFHDj4LN_q8ARligOtYKEo6rTI15MM-nrmobdosr5CDOU31kjXwVrPZwRtEp7itlBpVPkXB1J8bpCMeHAdMFM2_zNSQVRc8h3fpU5jFhbd7Y8y2zC0rhH9HkWFmuVQBHZw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-127, 159","volume":""},{"id":4770,"author":"刘攀峰","title":"两周金文中的动词同义词连用","abstract":"同义词连用现象是古汉语复音词产生的主要途径之一,而动词又是词汇中较大的一宗,本文就两周时期金文中的动词同义词连用现象做了一些考察,这些对我们正确理解两周时期的铭文内容都会大有裨益。","categories":["02_字词句考释"],"year":2012,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2DlX7vjthfT3-tRDEG7yxW_Za2UcyEKp9-7iFSx-2k6MhGpF8lSx6LOcVJu-0jFgKKFznYe2xuPFR2P-nuUs8f0SYDOBOZUeJKmO5a6WubYpxabVFEd6HEhX6ithjM43LyLZP8O85uUD6gIlgZ8fV1nd0zfgq0joR2v_-toUOmg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-56, 103","volume":""},{"id":4771,"author":"顾涛","title":"论古文字通假的文献释证法","abstract":"破古文字通假,形音义释读在上下文中得以密合,是第一步的基础性工作,之后必须具备文献求证的实验过程。文献求证如何有效地进行,是古文字考释的方法论问题。本文以王辉《古文字通假字典》(2008年)为举证范围,从所据文献之有效度的强弱入手,将古文字通假的文献释证法分作六种类型依次加以论述。","categories":["02_字词句考释"],"year":2012,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsfBeGfryQsUvrlXS6wa4OXpXDhQFOTX0pVxEX2Dn6kPUgJT6UolVqhoeCX6ihjfGrE8D3iAv263KPJ8kQpAiUxnNjuwq8Y9sE1_mFxmuwTGzMuXdWAeWYlSZ7ZgWP-oglkJxqnltjaxkApylHppyJlRf7tNihOaUlU0z3JDShDQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-102","volume":""},{"id":4773,"author":"路国权","title":"“复合族氏”铭文研究的一种新视角——以殷墟晚期“告”作有铭铜器为例","abstract":"殷墟晚期铜器铭文多数较短,其中又以类似&quot;亚某&quot;、&quot;寝某&quot;等形式的短铭较多。以往的研究中多将这种形式的铭文归为&quot;复合族氏铭文&quot;。通过对殷墟晚期&quot;告&quot;作有铭铜器的梳理,我们认为这种形式铭文中的一部分可能不是&quot;复合族氏铭文&quot;,而是&quot;官职+私名&quot;。这对认识殷墟晚期短铭金文的性质具有一定的启发作用。","categories":["02_字词句考释"],"year":2012,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFM3OXuqQPdNZali-rM-7ootU8oCuE5vv2ZnV7fO8XbzHabKxW_xCJb2Am7Unxqf6Jg78RzRwDITLc_FIUCKyECFocMhcbRfOc38nciENPEUzF-SPw0Qk0XRBjjLzZDuXaYsoQvdI7OC1lkNO915fR1tmM5uhoN9i0cm3VY5g4lA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-28, 47","volume":""},{"id":4774,"author":"雒有仓","title":"试论商周青铜器族徽文字不同于一般铭文的特点","abstract":"与商周青铜器一般铭文相比,族徽文字具有象形性和标识性较强、美化装饰色彩明显、书法色彩浓厚、词位和句法不固定、章法布局不合文字排列常规等特点。深入了解这些特点,对于族徽文字的正确隶定、考释及其性质认识,具有较为重要的意义。","categories":["02_字词句考释"],"year":2012,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsZ8bLH0jxl0roGFWnBNBsu4rIp0Lk8D_1olwI-UaAfl0PSbzF75bY3EZNsvwKuD6HbavSaG4EJ9rDTfW2dWofwBvb0iVzGCVeT1amTEDaBSDfxuLiw-s9BUkzylQFNP_1WFmijc5nWHG8hbF-rFHNnP9FlJNfGUdquPOq_uJBCQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-34","volume":""},{"id":4775,"author":"张振谦","title":"陈矦因咨戈考释两则","abstract":"目前所见到的陈矦因咨(齐威王)兵器包括新近出土的和传世的共有7件,还有2件没有被考释出来,本文从文字字形考释的角度出发,对2件陈矦因咨戈的铭文进行释读、考证。","categories":["02_字词句考释"],"year":2012,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLQXNiE0sWBXItWhMqp4W_u8kNmOJmbQjA0Q1IjjWn78wzxUeasl83uVew88g7DxPRdmQkN0bTtNTUrnNGkDt-F8_YgrCMaPB9Jpnrs47QkVYD-NLA52cTFx8pMCqXj-4xWuEMALCZ8W180x_XU91iVyJSMyQndNrgNErusbmoPug==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-110","volume":""},{"id":4776,"author":"王瑞英","title":"西周金文构形特征探析","abstract":"西周金文处于汉字体系的形成和发展时期。西周铜器铭文中图形文字向方块字体转变,偏旁部首增加并趋于成熟,汉字形体结构日益完善,形声结构迅速增长。对西周金文构形特征的考察能够深入了解文字发展变化的过程,从而有助于探求汉字的发展变化规律。","categories":["02_字词句考释"],"year":2012,"publication":"辽东学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.14168/j.issn.1672-8572.2012.02.012","pages":"110-113","volume":"14"},{"id":4777,"author":"闫志","title":"中国国家博物馆藏“王命传遽”虎节考","abstract":"中国国家博物馆《古代中国陈列》展陈一件虎形节,有铭文四字,以往未见讨论。本文考证铭文读为&quot;王命传虎(遽)&quot;。&quot;传&quot;字和&quot;传遽&quot;一词带有燕、齐文字特点,但从形制和铭文语言环境看此节当属楚器,应是战国晚期楚灭鲁后,与齐、燕文化相互影响的产物。","categories":["02_字词句考释"],"year":2012,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLO6KkzyHTtfRo16WPCvdOj57Mq19J2GhV3uM_D8i3yJ9zbgOTW3z0mCC0qIE534ckt6_7Dz4pI-uRudHC-mcaKM0-7jTsYE5gJ3rR2mtgvKdAoye7wCwgQhvrGg8PMnjvvDCF1HcD7nNu93DGEh75VwPGFo5KjHNcuc29otlQlfw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"140-146","volume":""},{"id":4779,"author":"王晶","title":"五年琱生簋铭文集释","abstract":"五年琱生簋是一篇西周时期的涉法铭文。本文吸收各家的研究成果,对铭文进行集释,并做出按语。为方便对全文的理解,在集释的基础上对铭文做了翻译。希望能对五年琱生簋的深入研究提供些许帮助。","categories":["02_字词句考释"],"year":2012,"publication":"嘉应学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJG0o-oELqhwrUx4TsVNOddCI-mm2lzRewl2Z_HQQ2NZu-VQ8UTke3KXoTUvicQ9quF9fVIrKo8-z8hbTbaDQzPfVFIxjd1PT5s55Dumkve7_hXB5bLIn1hV0KUGHCkfeVs-r8DjfIrT-D1kAvrUaf14XmCVTT3K2oaakgTo_jPXQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-69","volume":"30"},{"id":4780,"author":"苗利娟","title":"试论商代金文的装饰图案特征","abstract":"商代金文特别是族徽文字表现形式独特,构形近同图画,与青铜器上的装饰图案十分接近,若混于装饰图案中,则难于分辨。附于文字左右的装饰图案主要有三类:兽面纹、夔龙纹及鸟纹,而易与文字混淆的的装饰图案主要有目雷纹、双目纹、龟纹、蝉纹、火纹等等。","categories":["02_字词句考释"],"year":2012,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2012.01.010","pages":"81-90, 152","volume":""},{"id":4786,"author":"郑勇","title":"西周昭王时青铜器铭文文体特点简论","abstract":"西周早期青铜器铭文,大部分字数不多,记事也很简洁,但也有部分铭文具备了人物对话和故事情节,使得整个文章增色不少,而更有详细记载周王新册命诸侯的铭文,既记叙了事件发生的详细过程,又弥补了传世文献的不足。家族观念的出现,又标志着一种新的历史意识的诞生。这些特点在昭王时期的青铜器铭文中尤为突出。","categories":["02_字词句考释"],"year":2012,"publication":"内蒙古电大学刊","link":"https://link.cnki.net/doi/10.16162/j.issn.1672-3473.2012.02.010","pages":"24-25, 54","volume":""},{"id":4787,"author":"劉瑛","title":"寢戈考","abstract":"《左傳》所載名物,多有不可識者。本文以出土實物考證《左傳》所載&quot;寢戈&quot;的特點與用途。戈是古代各兵種作戰中常見的進攻型武器,戈的形制根據兵種的不同和實戰的需要而有所不同。《左傳》所載寢戈,屬小型貼身自衛的武器,自然在形制上與徒戈和車戈等實戰用戈有明顯區别。","categories":["02_字词句考释"],"year":2012,"publication":"中华文史论丛","link":"https://link.cnki.net/doi/10.16837/j.cnki.1002-0039.2012.01.013","pages":"245-254, 398","volume":""},{"id":4791,"author":"马楠","title":"据《清华简》释读金文、《尚书》两则","abstract":"一清华简《系年》曰:盍(阖)(庐)卽(世),夫秦(差)王卽立(位夫秦王指夫差,殆无疑义。又清华简第一册《楚居》:至霝(灵)王自为郢(徙)居秦溪之上,以为凥(处)于章[华之台]。竞坪王卽立(位),犹居秦溪之上。至卲王自秦溪之上(徙)居郢,","categories":["02_字词句考释"],"year":2012,"publication":"深圳大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDPCy7phFuD8xmflJd6Ms4ZuNOxkIhRuumpvSscLBFrRY7GVOIDIObLgHun_ShviV3eEwNite-iY-FmM9O40J64J6bbZpaZaQ7oPFaGRJro-FTIK52bYtYW_D1DgQZCwgIsqYXWOdEqLsQp1H6yLRZXl_peQ2QMSp_4hOmpRrVrg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-61","volume":"29"},{"id":4792,"author":"郑勇","title":"从天德到人德——由青铜器铭文看西周“德”观念的演变","abstract":"西周青铜器因其独特的载体,保留了许多原始珍贵的文字材料。本文从西周青铜器铭文入手,结合青铜器分期断代,尝试分析西周&quot;德&quot;观念的发展演变轨迹。","categories":["02_字词句考释"],"year":2012,"publication":"艺术设计研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLriHVNVoVDVHSy-N05iYhe7717fRcxeOHhSLK3w1wRzTN0MwHhI4e2ddIvcL2X64mffyXiV4qLDtN5sbdG7VCgSAFXypEvnjy8LkFkdB1VaWHCjPtXuQpKKqUMy62dkLHXw7SmmzJPC6jdeKlI5lOlejXxONHFdgRCE1UF2HV11Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-87","volume":""},{"id":4793,"author":"蒋书红","title":"金文动词研究述评","abstract":"金文动词的研究虽然已取得了许多阶段性的成果,但是还不可谓已臻于全面与完善,尤其是金文动词的系统性研究,包括系统性的比较研究方面,欠缺较多,而且其中关注的重点通常是西周部分,而殷商、东周、东周之后金文动词的系统性研究空缺更多,这值得引起学者们的关注与重视,更值得弥补与推进。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.01.008","pages":"80-86","volume":"33"},{"id":4794,"author":"邱冬梅; 温远鹤","title":"两周金文中评价语的使用考察","abstract":"两周金文中使用了较多的正面评价性词语和赋量语法手段,评价客体主要集中在关于上帝、先祖、王及作器者的品质、功业等方面。这种评价性表达不仅与金文记载的内容有关,更与当时的政治制度及社会意识形态、评价主体等因素存在密切关系。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.01.009","pages":"87-91, 113","volume":"33"},{"id":4795,"author":"王瑞英","title":"西周金文构形特征探析","abstract":"西周金文处于汉字体系的形成和发展时期。西周铜器铭文中图形文字向方块字体转变,偏旁部首增加并趋于成熟,汉字形体结构日益完善,形声结构迅速增长。对西周金文构形特征的考察能够深入了解文字发展变化的过程,从而有助于探求汉字的发展变化规律。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.01.010","pages":"92-95","volume":"33"},{"id":4799,"author":"张晓明","title":"山东出土商代青铜器铭文字频状况探析","abstract":"对2008年12月底前公布的山东出土商代青铜器铭文资料进行统计,可得单字645个,不计重复字为154个。进行字频统计与测查,发现:字频分布呈现两极分化,最高字频覆盖率达9%,即每11字就出现1次;仅出现1次的有109字,约占单字总数的71%。高频字集中在亲称用字、日名用字、作器或器名用字以及部分族名。亲称高频字是&quot;父&quot;。日名高频字集中在双数日,未见&quot;丙&quot;、&quot;壬&quot;。这些情况反映出商代山东与中原铜器铭文的一致性与差异性。","categories":["02_字词句考释"],"year":2012,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2012.01.006","pages":"24-28","volume":""},{"id":4807,"author":"康少峰","title":"兮甲盘铭文考释三则","abstract":"兮甲盘所反映的西周晚期周王朝以及南淮夷的政治、经济资料十分珍贵,值得深入研究。首先就铭文所涉及的&quot;貯&quot;、&quot;■&quot;、&quot;■&quot;等字做了进一步考释,进而尝试对西周晚期周王朝对南淮夷的政治、经济政策进行初步探析,并在此基础上就西周商业问题做了相关的探讨。","categories":["02_字词句考释"],"year":2012,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2012.01.016","pages":"18-20","volume":"32"},{"id":4811,"author":"吴红松","title":"西周金文名物考释三则","abstract":"结合传世文献的记载及部分学者的研究观点,从古文字学角度考释西周铜器铭文的&quot;昜金车&quot;、&quot;白马(每黄、发微)&quot;、&quot;鐈&quot;三种名物,以期能为研究者提供一些参考。","categories":["02_字词句考释"],"year":2012,"publication":"滁州学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaQ7QG6FMVh8jyE4s7n6MV6QRbfT3qTlNI1WHHMCiV-QatwHNEpXT6QoNyeT03LqnmiVCEfun5bS9u06bI1vohN85TgwG9UQgV8Dl9butiivF9RzXYU6ofHRv0fA3ap7DjxC7zsORxo6VN2UD_Bw-hDxnc7GoHtnwsvaNPMbhh8g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-23","volume":"14"},{"id":4813,"author":"杜廼松","title":"青铜器铭文的辨识","abstract":"青铜器上铸或刻的字,现在一般称&quot;青铜器铭文&quot;,也习称为&quot;金文&quot;或&quot;钟鼎文&quot;。青铜器在中国起源很早,但何时开始有铭文,这是学者们一直关注的问题。商代铜器铭文也是揭示商代历史的难得的重要资料,可以与文献和甲骨文相互补充和印证。铭文的内容不但可以印证和补充史料的不足,而且也是研究古代字体发展演变的重要材料。王国维先生很早以前就提出研究古史的&quot;二重证据法&quot;,即用地下发现的材料来印证和补充文献资料的不足,以及纠正文献记载的失误,或由于古文献","categories":["02_字词句考释"],"year":2012,"publication":"艺术市场","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVsWZF4gyqqc5YgyyryXojyf72lTx-W8q-F3JFGsyN6HXxrO4Z2ZA119sfhHb_NdWh8sh9GkL7WBPZMhBjseWQUMKfrDk8kjZ4JxxJsysx9-4_wZA89vC3LmVRF1_38S8hL-RQlzFO1eK8bsnfBohYCskCqGNgh3XJnAO4ideClA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-99","volume":""},{"id":4814,"author":"李勇; 马建明","title":"汉语个体量词考释举要","abstract":"个体量词用于计量名词时,不是随意的。从文字学角度来说,在汉语中,名词和个体量词的搭配都与个体量词的字形、字义有密不可分的关系,同时也与名词所记录事物的外在形体和语言使用者的观察视角也有很大关系。这种关系,也正是汉语个体量词与名词搭配的理据。","categories":["02_字词句考释"],"year":2012,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0ZmQSSom5BuwFy62IXNjstPRIBFO4AdE5gmN9ESsEMhINTcvQWzWLeIpfZgHRbCBwhd7TZmQ1aWUZ1O5edpG4csDP9flM1201ZaZq6HHlI-wKtN3546j-bZSgU4vVMgo6sQJGYWul_RFXdjH3zr-qHcjMCg5F0VRIjPtFnj1iQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-45","volume":"34"},{"id":4815,"author":"吴艳丽","title":"河北出土商周青铜礼器、杂器中的族徽文字考释","abstract":"近代以来,随着甲骨文的大量出土和对这些材料的深入研究,甲骨文可与族徽符号印证,这极大地推动了族徽性质的研究。本文对河北省出土的族徽铭文作了考释,叙述了这些族徽的历史地理渊源。","categories":["02_字词句考释"],"year":2012,"publication":"产业与科技论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0ZmQSSom5BuwFy62IXNjstPRIBFO4AdEJUq1kP-_uV4Ksr9uA7h_wvrG4QyaqsJO6hAIRwmCgnEK1Iew65b_dty_FwMd_Wjv6hcaph-bNXqMxWWpDarCYN7KKrga0-WC0NSpBPH4nNleup7SJjd7AqIT930Ny-07T_BMISbAEEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"140-141","volume":"11"},{"id":4818,"author":"丁进","title":"利簋铭“岁鼎克”的再认识——兼论“岁星当空”诸说的困难","abstract":"利簋铭文&quot;岁鼎克&quot;之&quot;岁&quot;有四种解说影响比较大,但没有一种被普遍接受。&quot;岁&quot;字解释成岁星、祭祀名、抢夺九鼎均有困难。&quot;岁&quot;是&quot;右史利&quot;的名,&quot;岁&quot;与&quot;利&quot;一名一字。&quot;岁&quot;本义是斧头、镰刀之类的砍削切割器;&quot;利&quot;本义是锋利,&quot;利&quot;与&quot;岁&quot;名字相应。铭文记载右史利因占卜预测准确,受到周武王赏赐,因而作铜器记载荣耀。&quot;岁鼎克&quot;不能解释为&quot;岁星当空&quo","categories":["02_字词句考释"],"year":2012,"publication":"安徽农业大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19747/j.cnki.1009-2463.2012.01.023","pages":"100-105","volume":"21"},{"id":4819,"author":"谭德兴","title":"清代金文著述与《诗经》研究","abstract":"将《诗经》与金文互证,此法滥觞于北宋,至清代达到高峰。与《诗经》发生在同一历史文化背景的地下材料如今亦只有金文,而二者的互证,对解决《诗经》和金文各自的许多问题,诸如辨字释词、名物制度考证以及诗篇与铭文断代等无疑有巨大作用。清代金文与《诗经》的对比研究成果颇丰。在文字方面:通过互证,发现汉代四家诗诗文的本字与假借;借助《诗经》来正确释读某些金文;通过邶伯等青铜器的出土地域,探讨《诗经·邶风》所涉地域的地理位置及历史文化内涵。在名物制度方面:通过互证,揭示《诗经》学内部的某些分歧及其成因;正确阐释某些诗篇发生的文化背景与主旨。在史实方面:借助《诗经》中某些诗篇的发生时代,对相关的青铜器进行断代,","categories":["02_字词句考释"],"year":2012,"publication":"湖北大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13793/j.cnki.42-1020/c.2012.01.004","pages":"45-50","volume":"39"},{"id":4821,"author":"傅华辰","title":"从西周金文看形容词的发展及其影响","abstract":"把殷商甲骨文中的形容词和西周金文中的形容词进行比较可以看出,西周时期形容词的数量增多了,结构复杂了。从词汇的角度看,形容词的发展丰富了汉语的词汇,形容词的语义系统在形容词的发展过程中逐渐完善,这是词汇系统性增强的体现;从语法的角度看,形容词的发展引起了一些性状概念要素表达方式的变化,也就是由综合的表达方式转变为分析的表达方式。","categories":["02_字词句考释"],"year":2012,"publication":"淮南师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLA9iwdMqnC0dF82scqmdzZvH0VLdWQPOv9i0Ar1CoWzFMSUzfJN6H5eZ-0VsA4nLuvebhGME2-Lb2TKIwZylbR6lVS6xDWFQXE1LQsRzvmAfaz7HHjawU84p3ldi6oUw9UVPitUUb3k22NMKPJ63kZqhI2sSBAwW_tLrpPK3K9Fg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-120","volume":"14"},{"id":4823,"author":"董莲池","title":"说山西浑源所出鱼■匕铭文中的“■”字","abstract":"文章从字形分析入手,研究了&quot;鱼■匕&quot;铭文中的&quot;■&quot;字,否定了将其释为籀文&quot;顶&quot;的传统看法,论证了&quot;■&quot;是三晋文字中的&quot;颠&quot;字,在铭文中应就本字解之,不得读为&quot;鼎&quot;,由此出发,对铭义重新做了解读。","categories":["02_字词句考释"],"year":2012,"publication":"山西大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13451/j.cnki.shanxi.univ(phil.soc.).2012.01.013","pages":"26-29","volume":"35"},{"id":4825,"author":"李春桃","title":"释番生簋盖铭文中的车马器“靷”","abstract":"西周时期的铭文有很多关于车马器的记载,为我们研究中国古代车舆制度提供了丰富的材料。中国古代的车马采用的是&quot;轭靷式系驾法&quot;,在这种系驾法中,&quot;靷&quot;的作用极其重要。但奇怪的是,西周时期的出土文字材料中却一直没有关于&quot;靷&quot;的记载。笔者认为西周金文中有&quot;靷&quot;,就保存在番生簋盖及伯晨鼎铭文中,只是以前没有被正确地释读出来。本文在考释&quot;靷&quot;的同时,也梳理了传世、出土文献中有关&quot;靷&quot;的记载,以明确其在车马器中的重要性。","categories":["02_字词句考释"],"year":2012,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKEaauLGcBnqvD_vWlHaWmEftDABIMVQzYrGohoLvFsuAPGlSeRvxkqnoeJBwGh1mrtFFuzHFIDNysKGy57sNmcmzFvstyEuzmWctEpZ4Tn6cPQFNpF3zVIKNsNH2t8_LzD5vxKUO_z1q4FECQL-6uUxVzQs1XOTGhTpnFrPYTmkg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-71","volume":""},{"id":4831,"author":"陈双新","title":"“射”与“矮”、“厉”与“历”的形义颠倒了吗?","abstract":"在2009年《通用规范汉字表》公开向社会征求意见期间和最近的网络与手机短信中,有人一再提出&quot;射&quot;与&quot;矮&quot;、&quot;厉&quot;与&quot;历&quot;的形与义颠倒了,应该换过来。如果仅从现代楷书汉字来看,这","categories":["02_字词句考释"],"year":2012,"publication":"语文建设","link":"https://link.cnki.net/doi/10.16412/j.cnki.1001-8476.2012.01.033","pages":"53-54","volume":""},{"id":4903,"author":"吴红松","title":"再论画■","abstract":"本文在总结、吸取前人研究的基础上,以对出土文字资料中&quot;画■&quot;的分析为切入点,将出土实物资料中的伏兔、轴饰等作进一步的分析研究,指出部分学者认为&quot;画■&quot;与&quot;轴饰&quot;为一物的观点不确;&quot;画■&quot;仍应从前人之说,指&quot;用来捆缚伏兔的革带&quot;的物品。","categories":["02_字词句考释"],"year":2012,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2012.04.016","pages":"92-95","volume":""},{"id":4905,"author":"彭裕商","title":"越王差徐戈铭文释读","abstract":"珍秦斋收藏的1件越王戈,已有好几位学者作过研究。由于戈铭较难通读,学者也各有解释,至今仍未取得一致的看法。笔者近来也对这件兵器作了些考察,撰成此小文,供大家参考。","categories":["02_字词句考释"],"year":2012,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJufO7HOaAGUMg2FRKZhrUXzwOAFjHA5Yxmfa3C-KJaElh0fn1Y_ZKIorYbqzz9KGTZeuX-PyAMbn4dV8FPi420y5WAFG1ee4XJso5paP74C0yANfTQ05VktpEsEDgCCsf_04xHQetBi4oHp4GRql041XE0GByzVtAyH_uiNGuGjA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-90","volume":""},{"id":4907,"author":"方稚松","title":"谈谈甲骨金文中的“肇”字","abstract":"殷墟甲骨文记事刻辞中的&quot;■&quot;字前人未曾论述,本文结合新出花东甲骨材料对甲骨文中的■、■、■字用法作了一番考察,认为它们实为一字异体,应释为&quot;肇&quot;之初文,含义上有&quot;致送&quot;一类意思;并强调了金文中&quot;肇&quot;字所从的&quot;■&quot;并非是&quot;启&quot;字,&quot;启&quot;在殷商甲骨文及西周金文中都是从&quot;又&quot;的,讹变成从&quot;支&quot;应是西周以后的事。","categories":["02_字词句考释"],"year":2012,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLsgRIrDMkdfssZYENUzGBaKUwUJMtMyImYM5gNkeshNed2kCYXkdZFMvOCv1Ed5gpnRAgB_MsEc_9Zd8a8o3h4ZKAG5HrXKG8nk7V-dIWfZd00owloPdTzsoZeSLRn8gwWkNBSNh45u2EoRCdt2sbDpIh5WCWQ8r7KH37NyCRSyQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-59","volume":""},{"id":4913,"author":"曹定云","title":"论殷周时代“司”、“后”二字形义及其区分——兼论“司母戊鼎”不可改名为“后母戊鼎”","abstract":"&quot;司母戊鼎&quot;更名为&quot;后母戊鼎&quot;是不慎之举,&quot;司母戊&quot;之&quot;司&quot;不能释为&quot;后&quot;,殷时无&quot;后&quot;制。春秋以前&quot;司&quot;&quot;后&quot;虽同形异义,但字的区分有严格的限定;春秋以后,两字在字形上开始渐进分化,至战国末期至秦汉,二字分化基本完成。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.04.009","pages":"46030","volume":"33"},{"id":4916,"author":"刘书芬","title":"西周金文中的“册”“典”“书”","abstract":"西周金文中的&quot;册&quot;有3种含义:人名(族名)、职业、(官职)、册书。&quot;典&quot;的用法和含义有两种:一是典册义,是名词;一是记入(典册)义,为动词。&quot;书&quot;也有两种解释:一作动词,表示书写、记录;二是名词,表示册书义。&quot;册&quot;是象形字;&quot;典&quot;是册的一种,由&quot;册&quot;引申而来;&quot;书&quot;是书写产生的结果,引申出册书义。","categories":["02_字词句考释"],"year":2012,"publication":"南昌航空大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvEz7Dm9U6f5v0LmlqYePtcdZ2_QDBaqbViQhREZqkkH4Fs4K3GK8gogAiXXQs6M5lEvtpsZhi-0XYkyMHEJOYqSEgaS0s7cHa3kyEXR_fSreB0fDGF6awcvLDXv3hT1Nd8opqQCoQAu15w6QWmADHdCQN43m9VlLehp1p-EUcaQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-115","volume":"14"},{"id":4917,"author":"肖辉","title":"河南南阳春秋楚彭射墓铜器铭文补释","abstract":"自河南南阳春秋楚彭射墓文物出土至今,学界对于墓中铜器铭文的考释基本上有了定论,但个别字的释读尚存争议。其中,考古挖掘报告中对&quot;酉关&quot;一字的解释,文章认为非也,并从该字的偏旁演变、器物命名等角度分析此字应当释读为&quot;朕(尊)&quot;;同时,文章对铭文第六字&quot;曳&quot;和第七字&quot;会&quot;,做了进一步的补充解释,认为&quot;会&quot;当读为&quot;沬&quot;。","categories":["02_字词句考释"],"year":2012,"publication":"铜陵学院学报","link":"https://link.cnki.net/doi/10.16394/j.cnki.34-1258/z.2012.06.010","pages":"95-96","volume":"11"},{"id":4920,"author":"王秀丽","title":"金文词汇同义连用现象探究","abstract":"同义连用是上古汉语中一种重要的语言现象。指的是两个或多个相同或者相近意义的词形成的并列式结构,在句中能够表达一个相对完整的意义。本文以两周金文为语料,对金文同义连用现象进行研究,重点分析了金文同义连用词语用字、词义、语法的特点以及产生同义连用的原因。","categories":["02_字词句考释"],"year":2012,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQQ1ybp-KE5_GZVTZ_c9v1ieCiYlEpkvSWpYPyQd4VOOh_b74F2aIGMiwA1qFzUzkCq-yug2d_CttijSx_rRylzzEeJAyF0o8ZFmpdQc95shdhycfgwJJliY37LguK2rwtFQTIgqfYtC8MTfOwRL7CG6vUITMhdaH78T3iuH6RFQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46028","volume":"34"},{"id":4921,"author":"毕秀洁","title":"“亚若癸”组铭文补释","abstract":"文章对商代金文中的&quot;亚若癸&quot;组铜器铭文进行释读,认为&quot;亚若癸&quot;组铜器铭文的含义是&quot;若&quot;、&quot;受&quot;、&quot;■&quot;、&quot;■&quot;四个族氏共同为祖先作器。文章还由此出发,讨论了&quot;亚■覃&quot;组铜器铭文,认为&quot;亚■覃&quot;组铜器铭文含义为&quot;■&quot;、&quot;覃&quot;、&quot;受&quot;三个族氏共同为祖先作器。","categories":["02_字词句考释"],"year":2012,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQVQ-T9S3EfrqE9PON3PgvqTOlGsmhqINrSPkretTKgN-Bz_4kgREcWiwfnpMPGrG9e9EZMqXpsuJcsWut8Fyhe7NrbByM3mVdnaKKxTqVOnlCw9AzMsEWManji8FuYxHbCjHjYnDpm3HR0V-3dUmPgrNmuz1IUQuV1V7rKTknWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46215","volume":"34"},{"id":4922,"author":"王晶","title":"西周铭文法律词语训释四则","abstract":"西周涉法铭文虽不多,但因涉及铭文考释、研究方法等问题,目前研究比较薄弱。整理出&quot;讼&quot;、&quot;告&quot;、&quot;罚&quot;、&quot;白&quot;四则法律词语并加以训释,可填补西周涉法铭文的研究空白。","categories":["02_字词句考释"],"year":2012,"publication":"江苏大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13317/j.cnki.jdskxb.2012.06.011","pages":"70-73","volume":"14"},{"id":4924,"author":"张世超","title":"评《两周金文虚词研究》","abstract":"在汉语史的研究中,对周代虚词的整理与研究是一个重要的课题。然而由于传世典籍中西周时期语料的匮乏,使得早期的研究成果往往集中在春秋战国时期,这也使得一些研究者将目光转向金文语料。以金文为语料研究周代的虚词有着得天独厚的优势。比如说,材料的真实性,不像传世典籍中所反映的那样复杂;时代的准确性,也可以借助考古","categories":["02_字词句考释"],"year":2012,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIuHnw5cpH49Or6_yE40oVjW2JjvGQnY19RCZLik1qnVbnk7KUtkCGTEswemELNhYtxgAAECSQ85oDrHgDER6oROj2dwB5RvaaMKYtQTMFKUOT4cQSVME-LNxvdur3FU-A7z_qnmFU62kRAPm2jgpk0ltPrAbWBJPhqUmpi_5WG9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108","volume":""},{"id":4928,"author":"","title":"赵诚《探索集》出版","abstract":"赵诚著《探索集》于2011年2月由中华书局出版。该书是作者1991年以来所撰写学术论文的选集,是继作者《古代文字音韵论文集》(中华书局1991年出版)之后的又一部论文集。全书共收录了《西周金文构形系统二重性探索》等论文42篇,内容关涉到汉语文字学、音韵学、训诂学、词义学、语法学及相关","categories":["02_字词句考释"],"year":2012,"publication":"语文研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIcrcXyMQI0nusCrMlFxp541UhC3S3BovydfYLoLY0Rwqqow52rgzt34I955c83R9ngFZwIexJxIV8Xo9PGGbOJzk57o5_oauk6PIe88-GYmLTd9equ163raGxYM6KKQaY907DKC9WTmPJHbEj_IESFTKGDWxrFz1sOA3ZldP-MkQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50","volume":""},{"id":4930,"author":"兰碧仙","title":"论“唯”从语气副词向范围副词的转化","abstract":"在前人研究的基础上,结合时代明确的出土文献重新梳理副词&quot;唯&quot;。通过&quot;唯&quot;在殷商卜辞、两周金文、战国文献中的语法位置、语法意义的分析,发现语气副词&quot;唯&quot;向范围副词&quot;唯&quot;转化的过程。范围副词&quot;唯&quot;至迟在战国时期出现,语气副词&quot;唯&quot;仍继续存在,后者逐渐减少。","categories":["02_字词句考释"],"year":2012,"publication":"集美大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLd_fKJb61DOJXczHnpq87UPbCNmHiflHUXC1YGgHfRgwcF4oZ8BwV5nVcjwqyfPEe1rYPMR-bSXmHPxs7Ns2Mz9X7W_dNcjk4a34j3NTYzonXMaF5RH3HEvlqVFGb5R_uWg1vDxjipInoCZUFOlmfN5NVU4jVxLdH8YyTU6gBmsQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-81","volume":"15"},{"id":4931,"author":"雷春辉","title":"释“串”、“患”、“古”三字","abstract":"《说文》收有&quot;毌&quot;字,漏收&quot;串&quot;字,似不合情理。一则先秦及西汉之前的典籍中有&quot;串&quot;字用例,二则成书早于《说文》的《尔雅》里收有&quot;串&quot;字,三则《说文》所收&quot;患&quot;字及其古文字的上部明明是&quot;串&quot;。正因为如此,导致许慎对几个从&quot;串&quot;之字解形不准。甲文、金文中有大量的&quot;串&quot;字,&quot;毌&quot;实为&quot;串&quot;字的合笔横置;&quot;患&quot;应为&quot;忧也。从心从串,串亦声&quot;。&quot;古&quot","categories":["02_字词句考释"],"year":2012,"publication":"北京印刷学院学报","link":"https://link.cnki.net/doi/10.19461/j.cnki.1004-8626.2012.05.017","pages":"61-64","volume":"20"},{"id":4932,"author":"马保春; 袁广阔","title":"妀善鼎铭文考释","abstract":"首都师范大学历史博物馆近年征集的妀善鼎,器、盖同铭。铭文记述了(己其)晏生之孙为其母或妻子妀善作器。根据器形、纹饰及铭文判断,妀善鼎属于春秋早期的可能性较大。妀善鼎为探索先泰时期(己其)国的地望、历史以及其与晏族的关系等提供了重要资料。","categories":["02_字词句考释"],"year":2012,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2012.10.008","pages":"66-70, 1","volume":""},{"id":4936,"author":"王琳","title":"《保卣》铭诸释评议","abstract":"《保卣》是解放后洛阳出土的一件著名青铜器,各家对其铭文的解读很不一致。本文认为做器者&quot;保&quot;应为召公奭,因他参加周初迁殷遗民的工作,作出了重要贡献,因而受到成王的赏赐,为其父文王作宝尊彝以示纪念。","categories":["02_字词句考释"],"year":2012,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRkikd8FfNzC841iBfVEERA9d3FTHfdWfzP1NDLTZD5ycPRiZoHpEr_7aaCsY2KaGTosU5qVO6AcXYrVmZ6-d7dUAo0d5qF-7nggqzsSGlRdjeeKl_4NOphvljm5YuZ1ipFB4bar0z5xmQ3n_ENjtABTz8vtBZtapm6BzoBOTosA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-52","volume":""},{"id":4938,"author":"黄耀明","title":"《行气玉铭》探微","abstract":"在充分吸收前人研究成果的基础上,本文综合运用各相关学科知识对《行气玉铭》进行深入探究,以句为单位,分别从字形隶定、句义阐释两方面提出新观点。确释了铭文中的&quot;■&quot;、&quot;■&quot;、&quot;■&quot;等字;用丹道、中医、文字等文献,深入细致地重新阐释了铭文含义;证明了铭文确属晋系,其产生时间为战国中期,地点在中山国及赵国。","categories":["02_字词句考释"],"year":2012,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4knVwa3eo6OyERuIwJKmMlpSxyny_d8JFEMf2UQPn6q7LCTwmEq2qOh9TkUCujlOQzpyLiL16dJqUzs8wN3odDWlHfe3W08yDHMDbifooSHe3eUuCUJuI128zvHV5c3-g0atJD9ZUoXnShm1yPoX8WKopaWbcEjTJy9KD-3JbDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-38","volume":""},{"id":4940,"author":"吴卫; 王祯","title":"“司母戊”与“后母戊”鼎称之辩","abstract":"2011年3月中央电视台新闻频道《新闻30分》爆出了中国国家博物馆已经单方面将&quot;司母戊&quot;鼎改名为&quot;后母戊&quot;鼎的消息,引发了相关领域的学人重新探讨上个世纪70年代末考古界就争议的&quot;司母戊&quot;与&quot;后母戊&quot;鼎名之称的研究课题;回顾司母戊鼎从被发掘到入住国家历史博物馆的简要历程,从&quot;司&quot;&quot;后&quot;字形和文义上结合被祭者称谓,从图像、文献入手探讨了&quot;司母戊&quot;与&quot;后母戊&quot;鼎称之辩的各自核心史料;指出在没有得到准确且科学的答案之前,大可不必随意更改&quo","categories":["02_字词句考释"],"year":2012,"publication":"设计","link":"https://link.cnki.net/doi/10.20055/j.cnki.1003-0069.2012.10.066","pages":"144-146","volume":""},{"id":4942,"author":"郑慧生","title":"“我”字之义探源","abstract":"商代甲骨文中有&quot;我&quot;字,写作(?)。此字从戈,戈像一支长矛;长戈上张挂着一面旗子,那就是&quot;我&quot;字。&quot;我&quot;字像长矛和旗子,标示着那是一个武装集团。远古时代的氏族单位都有武装,一个武装的氏族单位就是&quot;我&quot;。甲骨卜辞里的&quot;我&quot;字很多。它们大部分都可以当作集体代词使用,应该训作&quot;我们&quot;。如&quot;我受年&quot;就是&quot;我们的庄稼获得丰","categories":["02_字词句考释"],"year":2012,"publication":"寻根","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJE2J86IRBS8LgA9wnpBCcOrsS2hV-A5wFfvylDvF64u8Ppfc4ibrO-PbhCztVCgQmekchynyPw3k6r_BINcJCd5aHJBmNMkG2awggxQHZGnhGDZQl4HjaBVpYSkZgrB1T22kpSGXTqRVsd4rmcDfpQjzwArkvSB58cRKByo2ZBkA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46119","volume":""},{"id":4944,"author":"刘洪涛","title":"也说师■鼎铭的“困(韋東)伯太师武”","abstract":"师■鼎铭&quot;困伯太师武&quot;一句的&quot;困(韋東)&quot;二字,原文写法非常奇怪。裘锡圭先生释为&quot;東(韋東)&quot;,读为&quot;范围&quot;,认为是遵循、效法之意。本文同意把后一字释为&quot;(韋東)&quot;,但把前一字改释为&quot;困&quot;。&quot;困(韋東)&quot;也是遵循、效法的意思。","categories":["02_字词句考释"],"year":2012,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2012.05.009","pages":"73-79, 161","volume":""},{"id":4945,"author":"韦心滢","title":"关于故宫博物院所藏邐簋的定名及相关问题","abstract":"故宫博物院所藏旧称为&quot;邐簋&quot;或&quot;簋&quot;的殷代青铜簋,其铭虽简,但言深意远,语境复杂。作者细致释读剖析铭文,认为作器者应为&quot;京&quot;,此器似应称作&quot;京簋&quot;。此外,本文进一步讨论了铭文中牵涉的相关问题。","categories":["02_字词句考释"],"year":2012,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2012.05.010","pages":"80-88, 161","volume":""},{"id":4948,"author":"郭永秉","title":"穆公簋盖所记周穆王大蒐事考","abstract":"西周穆王时期的穆公簋盖,因其铭文中个别字词的误释误解,导致盖铭所记事件性质不明。本文释铭文首句的地名为见于殷墟甲骨文记载的一个著名田猎地;又结合对铭文&quot;商师&quot;、&quot;周&quot;两地的考证,并与商代铜器宰甫卣铭文相关史实进行比较,判定穆公簋盖铭所记的乃是周穆王时期的一次大蒐活动,从而为研究西周时代大蒐礼和周穆王游行之事发掘了一份珍贵史料。","categories":["02_字词句考释"],"year":2012,"publication":"复旦学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjwv7bdZpdfmfGt3DZNuSTiPwGPCMffFwKj90PrRMJn8jRrWZTV1c5ViSrNIeYxGSH5DQ-VdF-Oa-MuuxjMS9nx2OhyvUbRjCbQQNJO-hWtk5Y2O7LKLVtVzkYu1uf7W5Pku2vOIqc7u8cTc6BFg7OYGrT7TISLUtgONGiSkDvKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"130-140","volume":""},{"id":4949,"author":"赵雪","title":"古代表示“鼓励”义的词语考释","abstract":"古代表示&quot;鼓励&quot;一义的词有&quot;勖、勉、讚、敦、励、劝&quot;等。试结合古籍,对这些词进行分析,找出其发展变化的规律。","categories":["02_字词句考释"],"year":2012,"publication":"鸡西大学学报","link":"https://link.cnki.net/doi/10.16792/j.cnki.1672-6758.2012.09.061","pages":"139-140","volume":"12"},{"id":4952,"author":"谷斌; 刘雁","title":"释“巴”——兼与曹定云先生商榷","abstract":"&quot;巴&quot;字自甲骨文到金文再到小篆,字形一直在不断的简化,但始终保持蛇形的特点,只有识出甲骨文(巴)字中的两根竖线为毒牙,才能使巴之本义浮出水面,也使&quot;巴&quot;字的演变有了合理的解释。《说文》释巴为&quot;虫、蝮&quot;,更是证实了巴之本义为毒蛇,并形成一条完整的证据链。历史文献及现代动物学证实,这种蛇远古时期称&quot;巴&quot;,秦汉时期称&quot;蝮虫&quot;,民间又称&quot;反鼻虫&quot;,唐宋时称&quot;蝮蛇&quot;,明代也称褰鼻蛇,现代称五步蛇或尖吻蝮。","categories":["02_字词句考释"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.03.022","pages":"46342","volume":"33"},{"id":4957,"author":"俞绍宏","title":"辽宁所出商周铜器铭文辑、解","abstract":"迄今为止,辽宁地区出土了近四十件商周有铭青铜器,它们不仅是辽宁地区青铜文明的物证,其铭文更是承载着极其丰富的历史文化信息。对这些铭文进行辑、解,既是语言文字学及古文字学研究的重要部分,又可以为揭示辽宁地区悠久的文明史提供更为可靠的文献学依据。","categories":["02_字词句考释"],"year":2012,"publication":"大连大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJONKMNjFdxGBOtT-1CoI-gZr1Tm46o2WOC0s9MKxawpaH1Kr5zLRDbEcI27W5bNNv9hS7YfX14g6P8dVPAgqNGY68tx4a57hpQ-HlY9hUaSjxAefCMGrJ-Zyx3iBPGVoyV079O7AAzegNnVHY4qFp-nUnbBAWVVGWEqGTz1QyY3w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-61","volume":"33"},{"id":4959,"author":"黄锦前","title":"楚系铭文中的“孟庚”与“孟甲”","abstract":"本文对■夫人■鼎铭文中以往误释的&quot;孟甲&quot;进行了补释,并就相关问题进行了讨论。","categories":["02_字词句考释"],"year":2012,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLNbm5q0pbP3lpny_FtJeDN7dHIsiqhZuY-NgtmbIgI6YiM0db_c5h7EMNF7Eqbnn8LxDerML4i6LYrXE0aNQAls09wTTAfQs1DNH89SSmSg4mI7a5Fx9kfNZbcKo6-KFiW4gcxkNnKPbG-dSQCIrtI_1oMV3Wq1CKJctTI7O0ksw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-70, 74","volume":""},{"id":4961,"author":"裘锡圭","title":"翼城大河口西周墓地出土鸟形盉铭文解释","abstract":"本文在学者研究的基础上,对翼城大河口西周墓地2002号墓所出西周中期的鸟形盉铭文作出解释。文章同意&quot;余某弗称公命&quot;的&quot;某弗&quot;是双重否定的意见,指出全句是誓言的主体,意思是我遵从吾君的所有命令,认为&quot;余自無则便身&quot;是违背誓言的行为,是假设自己目无法纪,求一己之便。文章指出,从鸟形盉铭文看,&quot;誓&quot;和&quot;辞&quot;至少对文有别,发誓时所说的关于如果违誓应受何种处罚的话,可以另称为&quot;辞&quot;。铭文&quot;曩余亦改朕辞‘出弃’&quot;是&quot;以前我也曾把我誓言中关于惩罚的话改为‘出弃","categories":["02_字词句考释"],"year":2012,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoQNpjNH2yZ8ELc_2SJYT_sy4Vu9FmkrFKz8oAq01_BUAz66PAQ5byjXucdwNIaZUPpBoxACF1x0DDvFcxDw4usYnvrpzBtG7Gkvw39bThx5Rfj8wzbk3cvYTUQCftCoLg8S44bRfiNp-QiILHlimRO_YwuPQgeVXsA78vjeqAIA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"5-11, 2","volume":""},{"id":4962,"author":"寇占民","title":"殷周金文“即立”考","abstract":"殷周金文中的&quot;即立&quot;是利用一个形体兼表&quot;即立&quot;和&quot;即位&quot;两个语词,它经常出现在册命和赏赐一类的铜器铭文中,总共出现43次,其中作&quot;即位&quot;讲的有37次,作&quot;即立&quot;讲的共有6次。在殷周铜器铭文中,&quot;即立(位)&quot;还没有凝固成一个词,而是一个短语,指的是宫廷仪礼中归列规定的位置,它与传世文献中的君主登位之&quot;即位&quot;不仅意义不同,而且在用法上也有区别。","categories":["02_字词句考释"],"year":2012,"publication":"学术交流","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIDcuOyczzvtOfU1W3k1u0TH4uEQ0HMhBQRftrMmH4WEgThG9Bc8MjmMpTZ-WgJ-1dUtBLicKWCARPii3kN9lxCb-xD1cYBtxH__UCbOgcZ8aq_wv6jGa9pspdxuRH2H3l22pByMgJIhnUyt0IW-yHjyFqwFuJDGywjntRrXnb-Pg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"191-193","volume":""},{"id":4963,"author":"武振玉","title":"两周金文中的第二人称代词","abstract":"两周金文中的第二人称代词有&quot;乃、汝、爾(尔)、而、若&quot;五个,。从出现频率看,&quot;汝、乃&quot;为高频词,后三词出现频率很低。句法功能方面,&quot;乃&quot;和&quot;汝&quot;截然有别,即&quot;乃&quot;几乎只充当定语,而&quot;汝&quot;可以充当宾语、主语、兼语,几乎不充当定语。出现时间上,&quot;乃&quot;集中于西周时期,且各个阶段差别不大;&quot;汝&quot;亦集中于西周时期,但西周晚期比例更高;&quot;爾&quot;(尔)东周时期比例更高,&quot;而&quot;则全部见于东周时期。与殷墟甲骨文相比,","categories":["02_字词句考释"],"year":2012,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJWUczf4McOCHsOhw1aNdDDrJOqsn9HBiCEod3ejTYLyvqJL5an-dBuS2fbQGTtJt_on_QXEA-tJ2nDRUVixclvwaGzX4Gz0SKoK_p2MndD1tEh62n4oCsGrsqZDSSnGby-74aQvjKpYIsiTih8JvHSVrUABSdgXd4hJTgzXXxbPg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-87","volume":""},{"id":4965,"author":"刘美霞","title":"《汉语大字典·异体字表》所收隶定异体字构字部件分析","abstract":"由隶定而产生的&quot;隶定字&quot;是汉字中客观存在的一种文字现象。不同历史时期的字书或多或少都有收入了一些隶定字。本文主要从构字部件的角度,简要分析了《汉语大字典.异体字表》中的部分隶定异体字。","categories":["02_字词句考释"],"year":2012,"publication":"宜春学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9HWjz7oMCJLRVuHmZ_mo9JL21iVW4pjpYOJMAA3Go4sVI_VXJoVxHhENYoflmMXE-moKT7_4Ul9fdpXDCVywCQFIIqHK8kwu6DShtBifdDklUTRAl6kvwr7S5RVYYzdMztc5uUrdQwIbfmqfdnWjGSfjJo2i1SqCuQznbfIdF9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79-82","volume":"34"},{"id":4966,"author":"袁金平","title":"《荀子·不苟》“吟口”考释","abstract":"本文在各家研究的基础上对《荀子.不苟》&quot;吟口&quot;一词进行了深入分析,根据战国楚简帛资料中&quot;今&quot;常写作&quot;吟&quot;或&quot;含&quot;形这一用字特点,指出&quot;吟口&quot;当是由&quot;今&quot;字在流传过程中误衍&quot;口&quot;而成,并从文献传抄、文例特点等角度进行了论证。","categories":["02_字词句考释"],"year":2012,"publication":"长江学术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJB9mP3xzw6Q_sPOHyMNPXOp-koEKvNRoKZHqnwemqi2BTDYZV-aJZl0AntQtdQRFwGhR533nm2X2dY1Gw0PEPmsopmrm4rnksE3TCWX-rGdOSh3gMU-nveMZ5GAEnG7XHuXIFkKWfHfLNiHStLErBWPgy_-RgUJ3mack_1aj1sjw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"145-149","volume":""},{"id":4967,"author":"孙颖颖","title":"“告”的本义考析","abstract":"在此从&quot;告&quot;的甲骨文字形分析入手,从文献资料及古代文化等方面,论证&quot;告&quot;应是从口从牛,构意为对着祭祀所献的牺牲—牛进行祷告,本义即向神灵祈祷,以求神灵保护。","categories":["02_字词句考释"],"year":2012,"publication":"传奇.传记文学选刊（理论研究）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFCTBi7N3UWyFKaGsu4aNOj2GFzpFqItLKToPz8ZgBnoSpwxFyn5ATW6O1xc-ohXu2mvynTWb19gDs4XT0W4fmSGNb3AqcwNcAZcjyF_zVkvbzY_3mYQ-u4Y_wgLtvDEdQsJgH8aqwTQk-F-5tb1v1M5tJbnJ-gE6-xbNy14HiSQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-54","volume":""},{"id":6259,"author":"張明瑛; 程邦雄","title":"《上海博物館藏戰國楚竹書》的異構字研究","abstract":"1994年出現於香港文物市場的春秋戰國楚竹書，由上海博物館收藏並整理。從2001年到2008年，由馬承源主編的《上海博物館藏戰國楚竹書》（以下簡稱上博簡）一至七編陸續問世。這成為本文研究的主要材料，本文主要研究上博簡中的異構字，對其中的異構字進行全面、系統的整理。主要包括對異構字的分類，以及對異構字產生原因的分析。文章共分為三個部份：第一部份，引言簡要介紹研究緣起，上博簡和異構字的研究現狀，選題的目的、意義以及研究方法，並對本文的異構字做出明確的界定。第二部份，異構字的分類，查找出上博簡中所有的異構字,並對他們逐一分析，在此基礎上根據每組異構字的字形情況分為七大類。主要包括改變表義構件，改變表","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2yFB5GzKcMbD-pxJArSy4W4f7zU6Pd0UkZxykA1JpE-qy4_mYRT8slHzNLVRNJMhvbWPcgIcymuhvRk9WzDtJnUFM4ioyYqysigp_Lyy3WT0KswZTe9jrR5clX79ZwuiXP8X3BIdV4BCNbGHNU4BCO8M-F6sQvGcIdy8HN6SeQH6l6bGFzvEP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6264,"author":"雷蕾; 亢世勇","title":"1979版《辞海·语言文字分册》与2009版《辞海》释义对比研究","abstract":"《辞海》作为一部集字典、语文词典、专科词典于一体的大型综合性词典，在我国辞书界有很大影响力。目前，围绕《辞海》的选词、释义、编纂历程等方面的研究成果较多，但针对《辞海》不同版本间某一领域词条所进行的系统的研究尚未出现。本文以1979版《辞海·语言文字分册》和2009版《辞海》共有的890个词为研究对象，对这些词的释义进行对比研究，然后又探讨了2009版《辞海》释义的科学性及在释义系统性上的不足，并提出了自己的建议，试图丰富《辞海》的研究。全文共分为六章，第二、三、四、五章为论文的主体部分。第一章是绪论，主要包括研究综述、研究对象及其获取、研究目的和意义、研究方法。第二章对1979版《辞海·语言","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMASP7RPLBhbGRwulzdEGA1CZEmm_wsok-2E5HDuGRUxEIPUKtYjwjEc2C3dy0f5qkZY37q_3xrdPRfSkOeyU_Jq4HIO953qOc_Y3A24twXmMjh6DcLrIXSlZ5YUEesty2NqG94UXfeXUqC2kN_FIMWRrBZSRIEGGFRXt6C3hrotNvUKG7aHAI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6265,"author":"牟昆昊; 潘朝霖","title":"水书天干地支与商周同类字形的比较研究","abstract":"水书是水族人民创制的古老文字，它的起源以及之后的发展一直是学术界探讨的重要问题。虽然由于同时代考古证据的缺失，水书一直无法与汉文化的甲骨文、金文做直接的对话，但是在现有水书明版本与清版本的基础上，也可以做一下有益的研究。由于水书文字与汉字之间存在的千丝万缕的联系，这种字形上的比较也就具有了一定的意义。水书的发展存在着诸多与汉字不同的特点，这些特点一方面显示水书所携带的独特魅力，另一方面更使汉字有了可以相互比照的依据。水书字形整理，不可能跳过对汉字形体的研究，同样汉字文字学更不应该将目光局限在原先狭小的研究范畴内，既然甲骨文与埃及象形文字的比较具有价值，那么汉字与水书的比较就应该可以包容更大的意","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIax2t66tJ1F7JSqhyRVS-t44SoRVlYLZ-HQYPgNh62RZfPCkwk2fvtHHh0npqjMxXZGPXxve6MolcnWts6wBluf1sH8aaghuN14opDIL166fRIdtg-PApQJkXYUJ4dEVSTRjouWb9UTT5aRs0Z6q_O5oUOJEAxKwD2iO2k25zHWjiG27ds-t17&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6266,"author":"曹凤霞; 徐正考","title":"古代汉语标记被动式研究","abstract":"吕叔湘把汉语分为古代和近代两个时期，本文研究的时间节点是以隋为结点的古代汉语，又把古代汉语分为上古汉语和中古汉语两个主体部分。1运用构式语法及语法化理论对古代汉语部分的“于”、“为”、“见”、“被”等标记被动式作历时与共时的全面考察。考察中充分利用甲骨文、金文、本土文献、佛传经等语料对标记被动式的类型、构式特点、施事宾语的特点、被动式中动词性成分的特点以及被动标记的分布、层级和功能等进行了详细的描写和阐释，勾勒出标记被动式在古代汉语中的历时发展轨迹，同时，着眼于同一标记被动式的历时比较研究，以揭示古代汉语标记被动式发展演变的特点和规律。全文的内容如下：第1章绪论，回顾了汉语被动式的研究现状和发","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLp5Iu5Ew0XCWBTAUM-vBNiZNCwPT3A6FvqXpXiM44Ho8KgBGxgzL89Z8tAgMFEv0Vxv43kpuqmv9kc75aUJH0iIi6CBU7ejHJeo4PwknL2hyjXSKBHcpXjyhG_AB4q5hwp_lgm-GcPWk3Byjuq-CWXXZ016IzZ0jEUR1REwX1Q5dBDKCmFjjLa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6268,"author":"刘洪涛; 李家浩","title":"论掌握形体特点对古文字考释的重要性","abstract":"本文通过形体特点在古文字考释中的作用、形体特点在古文字考释中的运用和运用形体特点考释古文字应该注意的几个问题三个方面的论述和大量的举例,来说明掌握形体特点对古文字考释的重要性。我们希望,通过我们的论述能够引起研究者对形体特点重要性的充分认识,在他们考释古文字或思考跟古文字考释有关问题的时候,能够把形体特点作为首要考虑的因素。本文共分六个部分。第一部分为引言,介绍研究运用形体特点考释古文字的意义。第二部分为古文字考释方法与古文字形体特点简介,概要地介绍了古文字的考释方法、古文字的形体特点以及二者研究发展的历史。在这一章里,我们提出构造分析法是一种独立的古文字考释方法,其地位与形体比较法相当。这是","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIm-tjltrp3H2TRZsWjOyPQT7FeCSuAalmCudMwoBGaeuPV3LnInODSErujKm1e55JPH2kyLNhHLJ2SpOK0Wybp46zIHqh85jsLvKgd4j1CqQ5GkGZkdNTDvVjAHnaZMlYV_tUhBxSFsLs8G0Tg_tUvZ-4lcYmdymNoS8JpRed-LqMWJ3qEkMcG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6269,"author":"张丽莉; 陈双新","title":"甲金文中实词虚化问题研究","abstract":"实词虚化是汉字发展中的普遍现象，它作为促成汉字多义化发展的重要途径之一，一直备受语言学者们的关注。尤其是上世纪90年代语法化研究热潮的掀起，促使实词虚化的研究成为热点。但大多是单篇论述，且仅以一个或几个字为例证，从而得出单一的规律性结论。本文是以现代汉语中18个常用单音节虚词为例，逐个分析其在甲金文中的用法，梳理其虚化脉络，最后在丰富前人研究成果的基础上得出较为全面、客观的结论。各章内容如下：第一章是实词虚化问题的研究概述，分析了实词虚化的研究背景及现状，指出了前人研究的不足之处，以及本文研究的可行性，说明了本文的研究角度以及几个相关概念。第二章是文章的重点，首先确定选择单音节虚词的两个标准：","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-t-S7-UNRBbBxy28SkaBtTqcDhnEZ-ZEKHdyG6oRTKV5r_Qnc-S6FX8ze_NYsUmBSNw9--vfP991tHTP-VZmo4bRxfwkouEVmmIhbbQROy3VGtskGwxuBQWkSc4oC97KoRqzVfgWIIq8dU4_0AxUUGRwgFG2NV1qWGvUxN4K5A6sX_yhmvy80&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6270,"author":"范珊珊; 陈双新","title":"古漢字構件功能的多樣性研究","abstract":"“口”形部件在古文字中出現頻率較高，同時又具有表形、表義、表音、標示、裝飾等多種構形功能。因此，對“口”形部件的構形功能進行窮盡性研究，具有典型意義，可以由點及面地反映整個古文字階段漢字構形功能的多樣性，以及古漢字發展演變的規律。文章以《甲骨文編》、《金文編》、《戰國文字編》為主要材料，選取其中含有“口”形部件字形157个，並對其構形功能進行分析，得出“口”部件的構形功能具有多樣性、複雜性等特點。此外，文章還分析了古文字中與“口”形構件相混淆的幾種情況，有利於字形的辨識和考釋。","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIj-5ZMypORDCohmo_EzFVIA3ChRRs7wJzE2WrwMrhiid--n6jN0nZH814KaSV0gxhC_PGSSAYTGVbe2mx-u88RKsBUGviuQRIIMXLqkqhVNjwkglYvZg_AX7M0OpehJEkVRf4IH0s3QEFo1teTTehDhuHv3h4rtpQhjlk9sEaM0HPwvNEslnqi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6271,"author":"王丹娜; 陈双新","title":"西周金文单音节形容词研究","abstract":"本文的研究对象是西周金文单音节形容词，以《殷周金文集成释文》为主要材料来源，以《商周青铜器铭文选》、《商周金文》、《金文今译类检》、《金文形义通解》、《金文常用字典》为补充材料，通过对西周金文单音节形容词进行整理研究，结合传世西周和先秦文献资料，认定西周金文单音节形容词共有125个，可以作定语的是70个，其中只可以作定语的是40个；可以作谓语的是60个，其中只可以作谓语的是29个；可以作状语的是36个，可以作宾语的是16个；可以作补语的是4个。西周金文单音节形容词的主要语法功能是作定语、谓语和状语，也可以作宾语和补语。本文的主要内容：一，绪言，介绍本文的研究目的、思路和方法以及有关研究现状。二","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSYeiq_qr7VGYaTUd-dQBMKVQpiELhn7RegUoihSgntlgD-XepnF8lCYwsAZuuziAiLVfUbD1axi82YQABwDdZX_8muywSz5LOBxtMFQVk3RqM--wkcWM84Xj0RaAq-MVPTGbvt9cLsVjviALwr_fkPBUj1ZABqrOgDwKubA0k1rLAIk6nG7pb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6272,"author":"闫翠娟; 张振谦","title":"《传抄古文字编》形声字研究","abstract":"本文以传抄古文形声字为研究对象，以徐在国主编的《传抄古文字编》为考察范围，在分析古文形声字构形的基础上，力图客观、全面地描写古文形声字的构形系统，揭示其构形规律，并通过与楚文字形声字及形声系统进行比较，进一步探寻其与出土战国文字的渊源。本文共分为5章：第1章为绪论，介绍传抄古文的相关材料和研究状况以及形声字的研究概况，并介绍了本文关于形声字的界定方法和整理原则。第2章为传抄古文形声字的来源及结构类型，在参考前人研究成果的基础上，根据传抄古文形声字自身的特点，将其来源归纳为八种（增加义符、增加声符、替换义符、替换声符、声义皆换、累加声符、累加义符、形声相益），又将其结构分成三类（典型形声字、次典","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL765AabfbCnV5NR9nJZSCnIIlcZ9Owlm3HcAlnnqFZZ4k6mb_5sYpSxVo_QCG0yIGQKcO0EpnlFeb5Wn109wUETSn_ymDhkmUVDpoTNPpAiSuo5n3qxp1W3_YMVxbc5A3NfzOHT-7_CZKAYXxqU5v0gKmpUba6ffYlvcQ_58X7DTOmhp8R4xIi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6273,"author":"张奇男; 班吉庆","title":"战国燕兵器铭文构形研究","abstract":"兵器铭文,就是刻写或铸刻在兵器上的文字。在兵器上铸刻文字由来已久。发展到战国时代,诸强纷争,兵器大量制造,兵器铭文日益丰富。由于地域差异,各国兵器铭文异写、异构现象非常严重。前辈学者在兵器铭文方面己做了很多研究,但仍有可深入研究之处。燕兵器铭文是战国文字的重要组成部分,对其深入了解及研究,在考古学上,有助于兵器的国别、层次断代分析；在古文字学上,有助于进一步完善古文字历时、共时结构演变的框架,丰富汉字史的研究。论文主要内容如下：第一章绪论部分主要梳理燕兵器铭文的研究概况,并对语料及研究方法作简要说明。第二章首先说明单字整理的目的与意义,再根据单字整理的原则,对单字进行系统的整理与分析。通过整理","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInUL5aTf5fWOw6F-pqY3V3pUpPAm0Wy4fg7bbZQ-jrUhUnUUw5l5M-mkdng37Ha9SS3KvPDwplrlt7X8Fp34NX7vr2uwUqOA91FOJ2cJ7eOofpL_vWi9WooaRV67Fq8TaYS6llpD8vS7nd4OzdDYajwFdd7-6SXxq6_mcMtE4lHqxxqUmxGJX6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6274,"author":"郝立新; 殷寄明","title":"《尔雅》同源词研究","abstract":"本文只对《尔雅》前3篇中的同源词作全方位、穷尽性的研究。后16篇主要作为名物训诂来研究,不在本文的研究之列。同源词是出自同一语源的词,即语音、语义上都具有亲缘关系的词。《尔雅》向来被认为是一部同义词词典,因此,只要找出每条中语音相近的词,基本上就可以确定为同源词。《尔雅》同源词出现的类型大致可以分为两种：被释词与解释词互为同源词,或者被释词与被释词互为同源词。每种类型又有若干种形式。《尔雅》同源词之间的语音关系大致有五种类型：语音相同,双声叠韵,双声韵近,叠韵声近和声韵皆近。语义关系有意义相同和意义相通两种类型。《尔雅》前3篇的同源词在同义词中占一半以上,这说明,先秦时代声训占有相当大的比重,","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSRprrs2T-e2Qsptp0Z_BK0Y0LiVCHt6eqG4GcSKn5GDHsTkdfSPyI-EpPzhskSle3AIx7MY3E1urVKQBY2jSHqQjRqwaJhGn-KFBFxYMqQI00-VTWt5jdi6JjOesK2G3robDoDBRbqbinOXqW6GzDe6-R8fEd6ZBkXa7bI6rFs2E_eyT9h2Nl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6276,"author":"孙振兴; 张怀通","title":"西周金文中的伯与伯爵研究","abstract":"伯字在西周文献和金文中常见，一般是作为称谓出现。西周金文中的伯作为称谓，含义比较复杂，主要有两种：一是作为贵族男子的排行；二是作为诸侯或采邑主的爵称。而这些称伯的贵族或诸侯往往活跃于西周的政治舞台。西周青铜器铭文中作为家族内部排行的伯，可以分为死后所称之伯和生称之伯。作为爵称的伯，可以分为三类，即确定是爵称的伯、疑似是爵称的伯和无法判定是否为排行或爵称的伯。确定是爵称的伯只有弥伯。疑似是爵称的伯按照地域可以分为王畿内疑似爵称的伯和王畿外疑似爵称的伯。伯与仲、叔、季经常作为同一家族内部兄弟之间的称呼。由于西周时代是宗法制社会，故而伯、仲、叔、季的排行就有了明确大小宗的功能。伯作为王畿许多采邑主的","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6_nuJSUxWmSu3MVaA0VI0RsxtPBC0Wze9AZ1KMsFVGnyLb5b_Y6K0eoCplxazicEKKU9TF6nwYkn5t4sERv96oSF9xrSpwonfK9MRZT3oidA2DCqLBhPCM3YjAEHWAUeGfWQ_xl4HIyhYHVo3VERglOaP9O9ni8jCeVlEOJ75Ta31_kSCwjiH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6278,"author":"朱晓青; 陈五云","title":"汉字对称性的存在及其演变研究","abstract":"汉字作为表意系统的文字，其中的部分本身就具有对称这种显著的结构特征。本文正是着眼于部分汉字所具有的此特征进行研究，并延伸到相关史学、汉字学等领域进行佐证与说明。部分对称性汉字结构其形成本身就存在着既定的客观事实，即在外在形态上，具有和谐、对称的视觉美感，当然，在形成的过程中，也有许多历史性的原因，既有八卦这样具有原始象征意义的符号的影响，也有古代初期计量方式的影响。同时，官方通过严肃而又端庄的祭祀仪式，或是宗教膜拜等途径，对百姓进行了权威性的文化强制灌输与压制，从而在一定程度上促生了部分具有对称结构的汉字的形成。从汉字的本位角度而言，汉字本身也包含了丰富而又多元的对称汉字学，既有天人合一的世界","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLIrBO6yWCE9FCQkzbEdOISZXRaV4X8AhV0z1l0vyv7UFYGLo_Amjw1qn-a28hO8JBJz2ZuWOYx5SENzqJ7OcNeSNH2qZLJ4BKisawd2uxsLMfz6lvMW42lCniywCSf1CoyVKQE2c7Lry9pgB7abZ9ZFDw9tcMkrWIrpQTIt3ej52E7YoUUjfes&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6283,"author":"刘莉; 耿振生; 孙玉文","title":"汉魏音读异读字研究","abstract":"汉字的一形多音现象在汉语中表现得十分突出。汉字不能真正表音的特點,使得汉语中,尤其是害面语中,存在着大量的異讀字。研究这些具有復雜音羲關保的異读字,封於探究汉字形音羲演燮的歷史、汉韶的音羲關系以及汉语發展史都有十分重要的作用。汉魏时期的音讀材料是目前已知的明確記录汉字讀音的最早语料。本文立足於這一源頭材料,收集其中同一字形具有不同讀音的语言材料,並封与之相關的语言现象进行探究。本文所言的“具讀字”,指的是同一个字形具有雨種或兩種以上不同讀音的汉字。除“绪输”外,本文分为五章。第一章分雨部分：第一部分“整理方法”,较為系统地歸納了汉魏经师直接注明具讀的方式,指出汉魏音讀中同一经师或不同经師给同一","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsv4G0B-GIeD1y9PCVyw2MPYUocE8SOvAykBHRjYwrg4MYv06eW8mLOQnQPt_uuLDCEAR6804PwkyhodUHC9wBS5jbMQC4S5o-q6h9jlwvFfCZUfu41k7X7TgEdFlkB11hNGMJFxmZLg-tM9o1jeKnDSn8rMDm5M95d2e8ha73U_-h0geLV8PZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6284,"author":"張院利; 程邦雄","title":"戰國楚文字之形聲字研究","abstract":"形聲结构在漢字發展史上是不可或缺的一环，楚簡帛文字是對戰國時期實際使用著的文字真實狀態的實錄，與歷代傳承的字書文字有性質上的不同。對楚文字中的形聲字進行考察，將大大有助於我們了解戰國文字形聲字的實際使用狀況，并有助於對形聲字發展及整個漢字史的研究。我們將2008年以前公佈的楚國簡帛材料全部納入研究範圍，參照漢字構形學理論所確定的原則和方法，對楚文字中的已確釋單字進行字樣整理和結構分析，在個體分析的基礎上，歸納出楚文字中含有標聲構件的形聲字，並進一步分析有聲構件系統的不同組合模式。在對共時平面的楚文字進行斷代測查時，我們堅持共時描寫和歷時比較相結合，同時在定量統計的基礎上，對納入視野、可進行構形","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJybJs3Xyucc-p-Z_DOmPg7rRn6fR8IC3JsV19I6kQ-juQeoKmPdBQ2Wr-SkghujWYGiuo535NWM8XQsaIOnE3fLQDf_wzOzngnhd1itcMhg-n_L0ywdaQGTcFTZR8_pS-eQTkIHS_19kT9QdgND7CSf_bxMjzVsKo29BzQKfiL3sgmWljm4IXC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6288,"author":"蔡飛舟; 林志強","title":"經典釋文周易音義疏證","abstract":"《四庫全書總目》云：「《經典釋文》三十卷，唐陸元朗撰，元朗字德明，以字行。」是書「撰集五典、《孝經》、《論語》及《老》、《莊》、《爾雅》等音，古今並録，經注畢詳，訓義兼辯，示傳一家之學。」「所採漢魏六朝音切凡二百六十餘家，又兼載諸儒之訓詁，證各本之異同。後來得以考見古義者，注疏以外，惟賴此書之存眞，所謂殘膏剩馥，沽溉無窮者也。」先唐《易》注，傳世者题。唐陸德明《周易音義》尚可闊覲一二，亦可謂吉光片羽。是書所採凡子夏、京房、荀爽、鄭玄等四十餘家音義。後儒藉之足以考見古義，輔佐挈經。故爲《周易音義》作疏證，其義大焉。疏證體例，要而言之，有如下数端：一、於《釋文》每條音義之下愼採前人校勘，以佐參省。","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRquUjCMzyyMLR-2HwrN_YTl1ZuOEW2sSeXUcE37j5nG6LsQrASSogsXEnLVw8VdQjv5J84i5a7jII9O90SbJmORcr_QWL-isgwcch4lexqo54r69uEGho1byjc1SA45EKDtShHIK91vTn1677wyxsF4zebQC7SaXf2lOJ_GzsJg4lpTpzI_A8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6289,"author":"汪太舟; 林志强","title":"同符合体字研究","abstract":"本篇论文研究的是汉字中的同符合体字这一特殊字形。论文通过对历代传世文献和出土文献中的同符合体字进行共时的分析与历时的比较,以尽可能多的字例对这一类特殊的汉字进行结构上的阐释与表意类型的探讨,并叙其流变,分析同符合体字的演化情况。论文共分四个部分：绪论部分指明同符合体字的概念和研究的对象和范围、研究的方法及意义。第一章主要讨论同符合体字的结构特点。同符合体字从构件的数量上分为二符合体字、三符合体字、四符合体字,还有若干字是由四个以上构件组成的。一般来说,构件数量不同起区别字义的作用,也有二符、三符、四符而无别的情况。同符合体字排列方式表现为：二符合体字的排列方式主要有左右并列和上下相叠两种形式；","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKG5r0ng7p1NV7SOdoTJfpI_3ISUv4pKoPk0cfV52KYBvJF1ZeTbGCFrurx8qUFQcW4A91I4UhvlwfUrotmIsV_6eYD-1Cjq6lRjkOkXdfMc7Ixkv2X10dkVjhEUfG69NbyuJg-RQb0BhPg9wT2qZIGFFWjMeAINV2yYh11a9jCWIijZkm9kOtv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6290,"author":"廖敏; 甘露","title":"古文字中从肉之字研究","abstract":"古文字是距今兩千年以上的文字，漢字在這個漫長的發展歷程中已經發生了很大的變化，並且古文字的發展又與社會的發展息息相關。古文字的發展演變過程也能夠反映出一定時期的社會、政治、經濟、文化等多方面的狀況。本文主要是以古文字中从肉之字為研究對象，通過對古文字从肉之字形體發展演變的分析，總結出它們整個發展過程中的規律，進而探視古文字發展過程中的一些普遍規律；通過對从肉之字的意義分析，還可以發掘出古代先民的一些食肉飲食文化、祭祀文化和人體醫學文化等資訊。古文字中从肉之字是古文字的一個重要組成部分，通過對它們整體系統的研究，對我們在認識和使用从肉的相关之字方面都具有重大的意義。本文主要分為四個章節來敘述：第","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ93sZoYnkiDCs39_YEGoq4M98kZq5j45ncRGPUwcuCaP-up452eiSioMHOcT3iPgB3yNL0oEzrDoKd8UV1ola7J7Umpz3Zos9iCQbbBDQHNwW4zDdv9LVOZJtoMwI4pNnG10gQtgHaESGsGN7vbR5OF1FltoRLvtxphN0hcOcUUeRx8opzcmHR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6291,"author":"王旭东; 甘露","title":"古文字从辵、彳、行、止之字研究","abstract":"漢字作為表義體系的文字，同時作為一種最古老的記錄人類文明的奇葩，在其檢字與構形上都有獨特之處。從許慎《說文》始，漢字部首便出現在一系列的字書中，統領規劃著漢字的使命，便於人們識記和檢索。本文便從漢字的部首入手，分析有著相近或相關意義的从辵、从彳、从行、从止之字之間的內在關係。本文首先結合文末表格對从辵、从彳、从行、从止之字做了簡要的源流演變舉例，分別從甲骨文、金文、戰國文字以及《說文》小篆的字形為依據進行分析，目的是明確漢字字形發展脈絡。接下來以唐蘭先生提出的形體相通的理論為依據，分析文字發展史上存在的辵、彳、行、止作為夠字構件異體並存的現象，並舉出這些異體並存的例子，解說从辵、从彳、从行、从","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ93sZoYnkiDCs39_YEGoq4M98kZq5j45ncRGPUwcuCaDGjHHQAJYMoll_tcFCGGsAtVuXg9jDoljpD9U7mtnbHsBvvLd-gfWphojvx-aIP5kAQT7m0lUIBEnFLnJnE81jozml_n_tq29wqoc5U9sHiroYP-4epBCtK4Z-OgpdyOzuWzjddxMM-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6292,"author":"何迎竹; 張世超","title":"《文字蒙求》研究","abstract":"《文字蒙求》是清代學者王筠應好友陳山嵋的請求，教其孫子識字而編寫的識字課本，全書於《說文解字》中選取2050個字，从字形分析的角度加以解說，以滿足兒童學習的需要。《蒙求》全書體例按象形、指事、會意、形聲分卷，采用多種注音方式，解說字義簡潔易懂，同時運用當時所見的鐘鼎文字對許慎之說加以印證或者糾正其不足之處。《蒙求》不僅對兒童識字提供極大便利，同時也是研究《說文》的入門之書，由於受時代局限的原因，《蒙求》也存在一定的局限和不足。《文字蒙求》不僅體現王筠對文字的深刻見解，同時也貫穿着王筠文字學理論，包括王筠的“六書”觀、“六書相兼說”以及从中體現出王筠卓越的語言學思想。王筠不僅是清代著名的文字學家","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTRrQKdt4uPqQ6L2V8kimTdxTpEds7nZ5CvKG0o9g6uK-0LJOSBGDuNRaS6vud-ajJYudML542z9hOFrrhcnoSjVVzt6JJkaeoxCuZ4QjpDHDHH7rUEUkUWfuQS8gwM7QbuX-mOoM6wVvGeAAy1vBazd3i8nQAuGpxqKReNteDUu9BHntuls5T&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6301,"author":"龙正海; 喻遂生","title":"西周赏赐铭文用词与句式研究","abstract":"就目前所见,西周有铭青铜器数盖在六千件以上。其内容涉及征伐、祭祀、冊命、赏赐、训诫、诉讼、契书约剂褚方面。赏赐铭文乃为商周青铜铭文重要组成部分。较之而言,其捂言文字研究仍滞後,仍较为薄弱。研究赏赐铭文语言有助于人世西周语言,有助於西周历史文化的研究。本文研究西周赏赐铭文用词舆特殊句式。囿於篇幅与能力,本文仅对使令、赏赐、职司、勉励四类用祠造行研究。输文的第一章是绪论部分。第二章至第四章从句法、捂羲两层面详细研究使令、赐予、职司三组九个赏赐用词；第五章重点研究冊命铭文的勉励铭辞。输文的末章重点研究西周金文双宾语句式。通过如上褚方面研究,笔者发现西周的语言及用字习惯仍有较多为我们忽视、误认和不晾解","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0Fu_j1wR5zC5-7FvMaIpoeLOrlrzHB6Jy412A3tKlYaYIrXpgJyxQJL6n2iFHd9jZUODRgdpDKE1SyjNIAN2kBBDxMn7JFw4v4-oZFs1OzpmyNbSc9DKafcctv9n6PXaEPrR500MKQcRqwbpVgpQVge8HWfYLaXCTQq5-LU5dPEAH6R-t9jwe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6303,"author":"李丽; 喻遂生","title":"古文字意符演变研究","abstract":"漢字是意音文字,意符是漢字的重要构字部件类型。意符的演燮理據性较强,较音符而言更能明晰地体现漢字字符系统的发展燮化。本文以《古文字类编》(增订本)为基本资料,参考各种古文字编字形,调查研究《古文字类编》所收字意符演燮的情沉,裂成字表。再依據意符的演变情沉分增添、減省与替换三类进行具体分析说明,阐释了各种演变情形的特徵,并探讨了造三类演燮情形之间的错综复杂关系。最后,造一步探讨了古文字意符演燮的内部勤因舆外部勤因。文末附《古文字意符演燮字形表》。","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfDuVJXDf7VlhJmu7MeWUiFvzdzDK-SLYzof06GyqOaIQQXWvyuCwR5srtkyeRL2Do7Q5cmsDadTuIxZbXCenkUKu0joun4uXPwYK4WCu_aGCUPmxdttWOZ8ykaklw1CdNv5-1-zSoinAb5x_j2cLomQtCfRBf7CVtGyUCwtepllHscLIXoe0Y&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6304,"author":"张军; 喻遂生","title":"金文字词典常用词释义辨正","abstract":"金文字词典是我们阅讀和研究青铜器铭文的重要工具书,但它们封常用词的解释卻多有不同,其中有的释羲值得商榷,而且近年来出土了许多新的青铜器,其中不乏新的词羲和更典型的用例。我们选取《甲骨金文字典》、《筒明金文词典》和《金文常用字典》三部工具害,封其部分常用祠的释羲加以辨正,进而探讨了金文常用祠的特点。同时,也筒单地评僵了三部字祠典各自的特点及得失,封今后金文字词典工具书的改造提出了自己的看法。","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6qcViKTPUZtdohNTko39lOalAR7tTN9ItnJc9sIy6dArXSR3H9oQcxRj4E5_M7OAgLMJiSkZQ-8vRMR-XMOeyqkZqC8lun2LpcBgBiwcX88TmvTeENCwyE0rZK4Jn-m7d7Mb6ip7-yRybgR3vB-qyzS3D-L7_EJ5AGb53HO76mER9hyPvFXXw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6307,"author":"李笠; 胡新生","title":"西周 春秋名 字研究","abstract":"鲁大夫申蠕将周人取名规范归结为“五法”(“信、义、象、假、类”)和“六避”(“不以国、不以官、不以山川、不以隐疾、不以畜牲、不以器币”),但随着社会变化发展,其总结已经不完全符合春秋时期的情况。春秋时期的取名类型可以归结为神示型、纪念型、生名型等。命字是冠礼的重要步骤之一,是男性贵族进入成人世界的重要标志。西周时期男性贵族完整的称字模式为“伯(仲、叔、季)某甫(父)”,到了春秋时期,“伯某甫”型称字方式逐渐为“子某”型取代。在日常称呼中,通常对男性贵族并不以完整字相称,为表示对年长贵族的尊敬,常只称其排行。“伯”作为称呼时,即可作为对嫡长子的尊称,也可作为年长贵族尊称。春秋时期存在双名现象,其","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVjRW1RQFZwGodhnhsgJ3-ZcNY6CgqxOk93otijz7o9CCxlZNJ852RmGS1b9fqmJpMHzX6s0x0SshBrif_N_s9nWGhm_7Mmf9MjAtCwR8baXwrqh592yO2qhiehSFQ_I-nU2J-8H3eRUlmn77KTMwizwgtcENVd4X8NB8gWFiHbcn91-FR8kiM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6309,"author":"潘夢麗; 張顯成","title":"《吐鲁番出土文书》校補及字形谱","abstract":"一九五九年到一九七五年，在新疆吐鲁番县阿斯塔那和哈拉和卓两地发掘出了大量漠文文书，这批文书被称为“吐鲁番文书”。这批文书属出土文献范畴，文献真实性强，数量丰富，能反映常时社会现实和用字的基本面貌，对释文进行校勘和对用字现象进行研究具有重要价值。本文由前言和两个专题(正文)组成。主要内容如：前言：先介绍研究材料和选题意义，然后介绍材料的研究现状，最后谈本文的研究思路和方法。专题之一：《吐鲁番出土文书》释文校勘记。本专题从内容上把《吐鲁番出土文书》分为官府文书和私家文书两大类。每一大类下一再分为几个小类，对各小类文书原整理者释文进行校勘。校勘的主要类型是校原释文的失娱和补出一些文字。专题之二：《吐","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIrISo6vrQ8LrG7UjspHLZJCoqKNTgdimT8tjV2myMMltmMlJFvjtV2a8TOeHJKamTa1HJLJFM_XFMOp9kfWBAcmf6KOmcKBfHuPjnZt9bamHGCcj2HeWC_7ItfanU8aGtvWiuogbCmjCW_7hAfjdtNVrFhaVx1sJsSrs4jkEd3-ktwTt05SWig&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6310,"author":"肖金云; 罗积勇","title":"《礼部韵略》多音字音义规定及其执行考析","abstract":"《礼部韵略》作为专为科举而设的官韵,具有简洁、实用、权威的特点,其多音字只取经典中常见、举子常用音义项。我们从《礼部韵略》中具有代表性的多音字的角度出发,分析其音义特点,并结合宋代科举诗赋中相应的用韵实例,观察科举实践中是否严格按照《礼部韵略》的规定来押用,考察《礼部韵略》规定与科举执行之间的关系,分析《礼部韵略》不合理之处以及考生是如何面对的,探讨科场纠纷中考官和举子判定诗赋落韵与否的依据,进一步探讨《礼部韵略》规定的“出处”与“泛押”在诗赋押韵中实际运用情况,分析经典音在科举中的重要地位,更深入地探讨《礼部韵略》与科举的相互影响的辩证关系。我们按照以下几个部分来进行研究：绪论部分主要说研究","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrH60Bs2Chj3_3ieHz43-qBXokINVysORAStTm4WZW_21Rceg0DooS0kqwo5wARfqsh9lYCNnHvL-UEzjkYfQTBLnT8CTztrCMfOZuu6G8PkeN5sBzVTd9qYRwl9P5RLP1SHzpW2NGDqH3r_Ol0bogIEfQMMkcA8kePZtUBabUL2fKwO2krJHp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6312,"author":"邹烨; 劉志基","title":"金文字形差異研究","abstract":"本文聚焦商周金文字形差异,以《商周青铜器铭文选》为材料范围,根据金文字迹分析的要求,确定字形差异分析标准,对41187个铭文用字进行逐个目验整理,并以电脑字体手段支持,形成差异字形整理的数字平台。基於这个平台,完成了如下研究任务：一、选择较适合反映金文字形内在差异度的高频字(前90高频)字形进行具体分析,归纳其差异类型,总结出金文的整体差异状况。分析导致差异产生的原因；确认商周金文内在统一性的存在程度。二、根据前90高频字形差异的对比,以精确数量描述各个断代差异字形的新生和淘汰状况,从而揭示金文字形差异的断代发展变化,并探究其原因。三、关注由避复因素引起的金文字形差异,立足既有相关研究的基点,","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3GrMiwqB-n6leId6Q2zJHRnLddPeWP9nk7lqMofZ52zwC7lkPJ3S8e21HNny-xbnFuvIk7v3VEbNRnGwa6zIQHwbClWsAAF9LRjjohI1TpETccldaLWjgPhpgn2BoKKpUbQROG8CJyhptMf3HVk5PV3Z0jjMWJ3hK8HjDXmsjgQL3sMLIllZd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6314,"author":"邹帮平; 徐难于","title":"秦系正体文字发展性研究","abstract":"秦系正体文字是秦始列为诸侯国到秦朝灭亡期间秦官方使用的规范的汉字。目前,秦系正体文字材料或者比较零散,或者把它与其他秦文字收罗在一起进行研究；传统研究往往停留在秦系正体文字的稳定性上,其发展性虽有涉及,但没有连续而全面地描述。秦系正体文字发展性研究课题中尽量把目前能够见到的具有代表性的秦系正体文字材料收集在一起,以作一个专题研究,尽力揭示秦系正体文字的发展面貌。秦系正体文字研究分为五章：第一章是绪论部分,概括了目前秦系正体文字研究的状态及存在的问题,课题研究的范围、目的及意义。第二章界定秦系正体文字的时代、地域、研究对象及正体文字的特征。第三章根据文字材料的时间线索、出土地域、秦主称谓、文献记","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWuwWBppsv-qtNJYG20QjqJVXOFF6NxqBl04dIpG1COUvYOq-JtGoUxLGRru0nXvM-YjGeIyjasKM9ccZ1NeZdGSBBFzWgDkm4BDeEE-gDp7g1Lk98AwYvVSdMiHhFj3CiGc-aYihSFY3kcFsvDmZO4ZDUDZLTsGF6E4ywuwUQyikY03wLzIKb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6318,"author":"柳菲菲; 潘玉坤","title":"西周金文幾種短语及其相关语序研究","abstract":"本文以短藉为抓手,通遇封西周金文的捂料進行短語角度的切分和標記,梳理并描寫西周金文中的聪合短語、偏正短语和主謂短語,造而封输這三種短語内部的结構和藉羲特徵以及短語在句子中的語序差翼。本文所作研究,把金文短語與语序問题结合起來考察分析,将徒一個不大的角度展示早期漢藉藉序的某些面貌,從而豐富漢語藉法研究中的語序研究。第一章緒输。主要介绍了三十多年來金文及其語法研究的已有成果,說明本文選题的思路和研究意羲,並交代了本文在材料的選挥、處理以及體例上的相關問题。第二章聯合短語與韶序。按照時間先後,分爲西周早期、中期和晚期的聯合短語。分别封不同時期的聪合短語内部的结構和韶法功能做了詳细的梳理。按照是否使用","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJz3R1-SYpt7jCeIyWtA3kjkXEoOPpsdbEXcr-cXoIYW8uIYwbpkWoHhslKl-9u26jphYCTyOU7P9VPXHc8GaflwNLXAK8sQxLilen242JEjG0WaMkU9cCt3RBuMALK4OOoZp2Gtkh2IswtKwdrc3URy3ndnwxQAIFWJkul8FF6vT6lXgwvnwTO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6319,"author":"单利勤; 胡长春","title":"《殷周金文集成》兵器銘文校释","abstract":"《殷周金文集成》于1984年8月阴始出版,至1994年12月(實爲1995年4月)全部出齐,共18册。收铜器铭文11983件。中華害局于2007年出了修订版《殷周金文集成》,共八册,其中所收兵器铭文有戈戟類817件、矛類157件、劍颊152件、雜兵颊279件,共计1405件。本文首先是以《殷周金文集成》(修订版)爲底本,校之以《殷周金文集成释文》和《殷周金文集成引得》,標出異文。其次是封《殷周金文集成》所收的兵器铭文進行一個全面的、系统的梳理,封兵器铭文分時間先後,按國别造行分颊校释,校释畴吸收最新的研究成果。封有一些專家学者释讀不一致的铭文,则群列諸家之说,封前人的研究成果能作出判断的,擇善","categories":["02_字词句考释"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIMe5y3sLoCfYNyi8wx5IGzXcSmWfA80ybmk7RWSYT_JofK-hJuTfgHy-NeJusrfrvWDOcLMqhAUt7_VXTQZT1_fBGdMOCHCRwjXhbhjJaqf4ba8Kbo2tk3gZoZMa_2ZTGqF3OJidiAdms0Cxs2_JvoiRKUP60KamLKyvfgvL0LwoLKHhEr29xe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6580,"author":"谢明文","title":"从语法角度谈谈金文中“穆穆”的训释等相关问题","abstract":"金文中&quot;穆穆&quot;之语习见,但对它们的理解,研究者意见并不一致。本文准备从语法角度对&quot;穆穆&quot;的训释及其相关问题作些讨论,并对与之有关的几例&quot;&quot;的训释,提出一些不成熟的意见,希望大家批评指正。为了讨论的方便,我们先从语法的角度把金文中的&quot;穆穆&quot;分为两类,并把相关辞例揭示如下(本文引用古文字资料时,释文一般用宽式):A类:","categories":["02_字词句考释"],"year":2012,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKEbaBx-QIo6u2FgogRAbwtaA-x_5Z-v-WKSVHvP45ElnqIyj0SFHZsVG-JRSetarRCE7nA3jEvN9U0I75zo6XyaTXG4Qv3x9h7OamK9xz2kDdhfOrtNlUN-6o6qLKW1l-G_UPTo88u8KTXi8RgZWOPAxVndgG_LLeOjJCcXfnbVQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-61","volume":"57"},{"id":6581,"author":"张德苏","title":"“仁”字产生于西周初年考","abstract":"&quot;仁&quot;字出现于何时,是儒家思想研究中的一个重要问题,所以学者多有探寻。清人阮元遍考早期文献,结论是:&quot;‘仁'字不见于虞夏商《书》及《诗》三颂、《易》卦爻辞之内,似周初有此言而尚无此字。郭沫若先生也曾指出:&quot;仁字是春秋时代的新名词,我们在春秋以前的真正古书里面找不出","categories":["02_字词句考释"],"year":2012,"publication":"黄海学术论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIuW15kZlhMsty1bEOqVJpBWUwLzeA3uHbmG5tJlib-ZO4si5HJMuJ80QA3mVdJrUft59LdhZU15R12qWVRc5Y3N4Ojs_rCljppAiSP-Cd8sPlNRrI0Nd1YZcucJ9pNTjj6fxWJGXDv1cskA2DEH2UjYLuJBAw-NVqoWMGnyuaNwg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-92","volume":""},{"id":6586,"author":"李守奎","title":"《周公之琴舞》補釋","abstract":"《周公之琴舞》爲《周頌》研究提供了全新的材料,使我們耳目一新。整理報告和拙文《清華簡<周公之琴舞>與周頌》①對之進行了初步的整理和研究,但由於關乎周初禮樂制度,關乎《周頌》的作者、體例以及與樂舞之間的關係,内容重要且牽涉面廣,許多問題尚無確切的答案,都有待深入研究。本文在此對一些重要問題加以强調和補充。全篇語言估屈聱牙,十分難懂,所歌之詩,押韻很不規律。由於其文","categories":["02_字词句考释"],"year":2012,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsTnHICQ7l6T98NUH2z2uGRFV5cGQVTqkWFDsX4eWoiFt6wmMAOrKcITW8CtEy0-iMJwxHt8DnE9VLErk4IBOaYYfCofFEDjM-ziW1SHFjTQcsdH05MUJH-YqM1toV8UEocfRthHciCiiYiuA24V8xOuJdstNqQAWri1cV7reeBg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46165","volume":""},{"id":6587,"author":"單育辰","title":"作册嗌卣初探","abstract":"《作册嗌卣》(《集成》5427),原藏潘祖蔭處,後歸上海博物館,以往拓本漶漫不清,自從《商周青銅器銘文選》第一册發表新拓(著録於第142號)後,清晰度方大爲改觀。此銘異於常例,號稱難懂,可惜討論它的文章並不多見。這裏按我們的理解先把釋文寫在下面,再作進一步討論:作册嗌作父辛尊,","categories":["02_字词句考释"],"year":2012,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgbWMoXH8AVT4b90NTRH8raq3P3nwpu7h23jzJ9MgKcf5L8pR5n9Be6dTpV7KBu_eI209ex0UijDczs8Tr0yv9S2PW2EZQf01zBxhVXlazH-Z3PCpToqDqbHzyl0tVI73vR9cLFiA2sZGipp0fJ_aIZnHZW2xrrPYgg5lifxJ6Og==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-31","volume":""},{"id":6589,"author":"郭永秉","title":"談談戰國文字中可能與“庖”有關的資料","abstract":"先秦古書中有關&quot;庖&quot;的記載頗多。單説《莊子》,就出過&quot;越俎代庖&quot;、&quot;庖丁解牛&quot;這些現在還常用的成語。古人當中,夏代少康逃奔有虞氏,&quot;爲之庖正&quot;（《左傳》哀公元年）;伊尹舉於商湯庖廚,更是先秦古書膾炙人口的典故。凡此皆可見在古人心目中&quot;庖&quot;之源遠流長。從出土文字資料觀察,戰國文字中的&quot;廚&quot;已頗爲多見;①然而關於&quot;庖&quot;的資料,除了《臨淄齊墓》著録的一件春秋晚期或戰國早期宋左大師","categories":["02_字词句考释"],"year":2012,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpxIvtaHlAEU0Z_M92FColgeDLZsutM-Do4qW7yQQNowLJSYY3hJno6MQhwzzCOqPdy0o2DWKAqiz1W8SxONTP3gr2Je5nOR67pMtsWPXYS1100BwwFYtlppYFoTgOtMXuOEbkXMI78qAcxrPHgzhKj0sN4BD3w2v-n_rLiccIUw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-112","volume":""},{"id":6591,"author":"夏大兆","title":"说“■”——兼论双声符字","abstract":"本文主要对《殷周金文集成》9618号着录的一件铜壶铭中的■字释读进行了探讨。提出了两种释读可能:一是该字有可能是个双声符字,上部所从是&quot;上&quot;,下部所从是&quot;向&quot;,皆声。无须看做是&quot;上&quot;或&quot;向&quot;的异体,可能是用做人名时的特殊写法。二是该字也有可能是&quot;上、向&quot;两字合文。","categories":["02_字词句考释"],"year":2012,"publication":"学行堂语言文字论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKa5_90ZWvAy8_s0_gv5tOHIV8TwEa5dnNSjHtxvzEPUiCjv32G0rsytL_XNdPTZeCwCLfSq2-5WZaGrP6v3MgwscH145VRUAyXwLxcL6LzNnAtJwfnVe7LItkcHCRtFOz0eOY8AO6GYj-uLf3hVPtXPHKAi7Bsvpg3W1rkDzZxLw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"148-155","volume":""},{"id":6592,"author":"肖峰","title":"形声字若干问题的探讨","abstract":"本文试图从一个新的视角即依于《说文》而不囿于《说文》,本于小篆而不泥于小篆,通过一些新的古文字材料与小篆书写系统比对来揭示&quot;类&quot;与&quot;首&quot;形成和定型的年代、考察古文字的&quot;类&quot;与&quot;首&quot;的发展脉络;通过一些新的语言学理论如词汇扩散理论、语义场理论以及范畴理论来解释和分析&quot;类&quot;与&quot;首&quot;的形成机制和过程。即通过比对甲骨文、金文、战国文字与小篆,追寻它们的历史演变轨迹,探讨&quot;建类一首&quot;的发展形成和确定过程,分析&quot;建类一首&quot;的两种不同模式,探讨&qu","categories":["02_字词句考释"],"year":2012,"publication":"学行堂语言文字论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5TbKA4fN_NNKad1VUs7BL1Qa_sH8PdST0rPMYGvnNEwaqWnMkJ3htlLlUt0QC_D_mN37fiuXdOVSc-XF2DlR_tSRKNFT0n-FZWULERlOnSpAU8U0pRD1RgERkRA7XsbMMpy6VJY7zHfHvPUP43l-ZlHGtpJ8q36Ih82zfyrF8Vw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"156-167","volume":""},{"id":6596,"author":"杜小钰","title":"“蚩尤匕”试读","abstract":"罗振玉先生曾收藏一款春秋战国时期青铜匕,学术界一直称之为&quot;鱼鼎匕&quot;,或&quot;(虫虫)匕&quot;。本文认为匕铭首句可读为&quot;曰■(蚩)(虫又)(蚘)匕&quot;,匕名则为&quot;蚩尤匕&quot;。&quot;蚩尤&quot;二字也使得整篇器铭语义连贯,更符合逻辑表达,极易通读。&quot;蚩尤匕&quot;铭文的主旨则是警戒下民不要重蹈蚩尤的覆辙。铭文反映了蚩尤与黄帝战于涿鹿,失败被杀的历史传说,甚为重要。&quot;蚩尤匕&quot;铭文类型则属于春秋末期较为典型的四言韵语箴铭。","categories":["02_字词句考释"],"year":2012,"publication":"学行堂语言文字论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjD0CIWbxDlbF5DCtSuy73ZD8d61Wxs5colWwV1aItzYzFYtOdcqp1-O4n2HdzJGY4x30dPQtRYek_nPXAMPd4a8QZ6ZTkAwdUS90Lvj8ZxajPe2uNG17JiTNmXuNU0QKat2UnLyFYrjOP9T-kmImitCCkNAOJSws-uXR0Jdsojg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"122-128","volume":""},{"id":6597,"author":"王治国","title":"询簋新探","abstract":"对于金文啻官■一词,学者们已有多种看法,笔者认为释啻为嫡当是正确的,但笼统地认为&quot;啻官■&quot;为嫡长子世袭某官或者世袭之官的意思却是不妥的,嫡有&quot;正&quot;和&quot;直系的&quot;等意。从孝王时开始,秦始成为周之附庸。近来有学者认为询应当为师酉之祖父,并将询簋定在恭王世,笔者认为与史实相悖。我们在为其母作器的西周金文中,从未见到单称其母氏加母姓的例子,如将师酉簋中的■当做氏称,则不符合西周金文的通例。从各方面综合来看,师酉当为询之父。","categories":["02_字词句考释"],"year":2012,"publication":"学行堂语言文字论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3fBbOQYv_l35YXGKbyIqCj3RzajrueatnY7-wEY2iKywyfPWQHgy5H0avUsyOrkIezz1EP8TaAsa2iEvt6WE2yKYtDedeYnrfZKVWlS11419DfyzI6KXEMwQltkWB1TSulXcuyjZt_Iazu9mQf2q1eM0p5du8vloInxwkOHFaoA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-121","volume":""},{"id":6600,"author":"赵静","title":"从《积微居金文说》看金文的释读方法","abstract":"杨树达先生开阔的研究视野和新鲜可靠的理论依据,以及不拘泥于古文字研究领域的思想,对于古文字研究的学者而言,很有借鉴意义。《积微居金文说》是杨树达先生考释青铜器铭文的专集。通过对众多名器的考释,阐述其治金文的方法。","categories":["02_字词句考释"],"year":2012,"publication":"学行堂文史集刊——2012年第2期","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJTJExLX1ofZmjRRWD9Ojsc3BY2fvYGrTyMUpXXdkUznHU1Ox930lomoSzeOAtLggRpHpWc5DVvAd7xHsvvdrZVE19xeMjqKLEIkoT1rokoZwSkg5G5Aq7W76vHCguReF497HOoBLQvc5_bsmmHm_5Z6QWTE4u7rD03UIxCVeCdkZ41IvIKDn7k&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-27","volume":""},{"id":6603,"author":"毕谦琦","title":"以《经典释文》“大”字音义辨析为例看异读和形态的关系","abstract":"&quot;大&quot;字在古代文献中的音义关系非常复杂。《经典释文》中&quot;大&quot;字共有五读,五读之间既有韵尾交替,也有声母清浊交替。这五读中&quot;如字&quot;音是&quot;定母泰韵去声&quot;;歌韵读音来自上古歌部,与中古新产生的歌韵读音没有关系;泰韵透母读音和泰韵定母读音之间有严格的形态关系。","categories":["02_字词句考释"],"year":2012,"publication":"语言研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKodDgS-eGsf1qzfMouQLNdyrr4xGpyaS-FdObLvaAHNpIKV8jFGP_8uk6Ph63F7UBT8UQAkRTrG_rilkUIk1uVUDp9BmqXBNsuqS8x1BVWTKEc1IpoSN-II_CrZM4IUHkduW1nLoPwTaB8jUeE5BLEWLFmqetTkGJylmct96fAtw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"288-299, 361","volume":""},{"id":6604,"author":"李冬鸽","title":"“智”“知”形体关系再论","abstract":"&quot;智&quot;的产生早于&quot;知&quot;,从大口于,西周增从甘,后来字从&quot;知&quot;是形体演变的结果,其最初记录&quot;知道、认识&quot;义,后引申有&quot;智慧&quot;义;&quot;知&quot;在&quot;智&quot;已具有上述二义的情况下产生,从矢口,形体来源上与&quot;智&quot;无关。","categories":["02_字词句考释"],"year":2012,"publication":"燕赵学术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJrtdhtFr7bCawVZ8kwqnXouxwl4pjvHZ8fV5anjFp7lxb8oPMOvAjsLrWZv4tPkLSpTfGAnfTZ-LUnIYAvzHw5MEbnW1Yp2VC3Sv4fGKU4WNyjjZYzOvBeVVFMM3hx1mg4v2yFgm-eULWVmSRteXNgFoPu3dJz3Iz5hAi47d3ETg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-66","volume":""},{"id":6605,"author":"陳劍","title":"《上博八·顔淵問於孔子》補釋兩則","abstract":"~~","categories":["02_字词句考释"],"year":2012,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_JXIlsvKDOadCXHIuc3HFXyyPtcu9b0E5zc9JscVm_8JuWM94JxBWYzei1Z5kjxWJ-sxbqOas_MfYI_Nl-tWz3mChhKSR6El5Sa7rSWJvv-E00v6v_nPaAsNEkSFkHe2N9m2kbZlBXRcCAM537Vp1gLtOokK5xCY0e9Ow38iqoQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-42, 435","volume":""},{"id":6606,"author":"陳英傑","title":"談金文中一種長期被誤釋的象形“甗”字——兼論“鬲”、“甗”的形體結構","abstract":"西周晚期的鼄伯鬲(6691)是一件媵器,其器形和銘文拓片見下圖:其銘云:&quot;鼄伯作塍(媵)鬲,其萬年子子孫孫永寶用。&quot;銘辭簡單,沒有什麼難懂之處。其自名■1(《銘文選(三)》2494所收拓片清晰完整,作■),吴式芬《攈古錄金文》、","categories":["02_字词句考释"],"year":2012,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYdYJTiSUuPoaiGJBXvOYQhSPYMDO-wPineBqBZA3OFMhJqorf4WTTPMeP-S7UnH0LhFausn1YxlzHg4D_BSfmFQjeg-Ueye5_l18b5r8L5AwKHJj3PnhVtWfEiIomob_5oaB-ukaaY7ekCERONF0FYGap5ix28DV1KO_kIy4SLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"297-315, 435","volume":""},{"id":6608,"author":"鄧佩玲","title":"《詩》《書》古義與金文新證二則","abstract":"《詩》、《書》成書甚早,其文辭古雅,歷代學者多有《詩》、《書》難明之嘆。比年以來,考古學發展迅速,出土文獻材料與日俱增,且多爲先賢所未曾獲睹。二十世紀初,王靜安先生嘗提出著名之&quot;二重證據法&quot;,謂以今日之新發現、新材料、新學問補足、印證,乃至修訂傳世文獻、古籍之記述。從今日新見之青銅器銘文可知,金文用語形式更靈活多變,不拘一格,細審其用詞、用語,實有不少能與《詩》、《書》等先秦古籍參照比觀者,吾人固可藉此契機,將兩者作比觀發明,互補有無。因此,本文以新見金文材料與傳世文獻作相互印證,從而對《詩》&quot;假以溢我&quot;及《書》&quot;乃命寧予以秬鬯二卣&quot;","categories":["02_字词句考释"],"year":2012,"publication":"人文中国学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKoPYyO-P_DQ9MKAGeZYX-E7B5gNgN2MzDY8UYeiIHHOFdpyDQKwWBRqwrsmv0weFRP-vXyb6pYKjA4Rd1svdf9moCXs1cuvGbRz_RE6EYYrxDjuAIY4fMGpTstkMYl1SrMi2X_cuBsEX8WhLiJ6VETBTdk4GqS629KNryRGsJHig==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-101","volume":""},{"id":6612,"author":"张世超","title":"关于金文“眉寿”之“眉”的说明","abstract":"周代金文中&quot;眉寿&quot;之&quot;眉&quot;是最常见的金文字形之一,字形变化多,字义及其来源也引起学界的争论。本文从词源学角度入手,讨论了所谓&quot;眉&quot;字及其意义的来源。对于&quot;萬&quot;字的古代意义及金文中的&quot;世萬&quot;,作者也提出了新的看法。","categories":["02_字词句考释"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKNNXKZh4AMf8WPjuYhA-N7VYUKx6KsPnm5Lv-ENEsYa-9TdLEuFpXWH-qZtzi5b896zSKldHyvYtzs1bJ3Of-BrmmC3wBsbTXSWLw80c3OkPNjt1wmIMAji7znB3ILzv5r_3CD_8vC6HspPx27eXaEmHUwbN8Uu8qVE0KEdMSepA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46028","volume":"16"},{"id":6614,"author":"张再兴","title":"中觯“于庚”意义探索——基于语义搭配的统计分析","abstract":"对于安州六器之一的中觯铭文开头&quot;王大省公族于庚(辰升)旅&quot;一句中&quot;庚&quot;字的理解,学界一直有争论。介词&quot;于&quot;字在金文中的词义搭配的统计分析表明,金文中的&quot;于&quot;字后面不与干支纪日名词搭配。因此,&quot;庚(辰升)&quot;不可能表示日期。","categories":["02_字词句考释"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIDG5Ny1PtxQ4umgG1K21lGIg-6SyT6RVzdhyBEjX4ZPuVIV38-eWLirH1WR7dq5xrBtC4bs4I1uB9H4Sfx9oD2FY8llQbCZWBB8TtD9LZ6olEuACwXziHVNXFKIb9u_EY1Rf96fLshG-9najln6WKNOj6Wjs4VQ4kCFfxPPiu9pA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-25","volume":"16"},{"id":6616,"author":"董莲池","title":"释王子姪鼎铭中的“致”","abstract":"本文纠正了《金文编》等重要字书对王子姪鼎铭中&quot;姪&quot;字摹写的错误,考释了这个字,认为应释为&quot;致&quot;,&quot;王子姪鼎&quot;应改称&quot;王子致鼎&quot;。","categories":["02_字词句考释"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWG9CU_e4AiqRb6ZBvBjRyf0FoyrQvTYRHlId_yy9g8i2NmA6e6JN0KPFH50FU2aaVAzWWuzBr9NpFS5RRsNfmf0_82zmh_aT6Xs2oMmC9CqxXUHrndwr3W4YynR2V460tepPwOMhU-Vkye6tQY3O4ZyH-Iz1zsz-2-NSHALyETQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-21","volume":"16"},{"id":6617,"author":"鞠焕文","title":"子璋钟释文及定名问题重议","abstract":"本文通过对&quot;子璋钟&quot;各著录材料的对比与研究,厘清了铸有同一铭诸器的保存和著录情况,通过对&quot;子&quot;字重文符号有无情况的考察,对器铭作了重新的释读,得出了此编钟的作器者名为&quot;璋&quot;,而非&quot;子璋&quot;,此套编钟应定名为&quot;璋钟&quot;,而非&quot;子璋钟&quot;的结论。","categories":["02_字词句考释"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhSaTHUpskbaAwW--8pzyCR2x5hJJHK93Oqxj0NfN286iFQ2Okf8B0rIh2VXhbwE0aQ2fqtqXUtV_Vr_Cs2-3m0HdA732SP8gpfxf1FovBxaXJiwn6fkkAc2kJEGuC54YYnNUoaBF1HZl0rhEiEsXzaiERC8GqG1NvYRg88bzSpA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-32","volume":"16"},{"id":6618,"author":"刘孝霞","title":"读《近出殷周金文集录二》(第一册)札记","abstract":"《近出二》是继《集成》、《近出》后又一部金文集成性著作。该书在考释上尽可能吸收学术界已有的研究成果,大抵可以反映现在金文的释字水平。由于该书收录的金文资料庞杂,而金文考释又浩如烟海,在对铭文的释读上,难免存在疏漏。本文就《近出二》第一册中出现的一些考释问题,如误释、应释未释、隶定不确等情况进行了校订。","categories":["02_字词句考释"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIkm_ER4Z1zjBMu3IN-DbyWPjZ2hKFNI8ATT4D8ey8jp-FaV6DRWjePuiECBHvbcJKhFlL56T28CL0MxeXEtOUQW6-7Wen9qSnr4ifWBtQCAPSAieye_9Tb_7B3xz0n-zhWga5C04oGqClgSmAbFgA98E96Y9MiY1GGJfvi6hJt9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-36","volume":"16"},{"id":6619,"author":"苏影","title":"山东所出公■豆“■”字及相关问题研究","abstract":"本文运用偏旁分析的方法考论了山东沂水刘家店子春秋墓发掘出土四件形似盖豆的铜器铭文■,认为它是《说文解字》的&quot;■&quot;字,并推测&quot;■&quot;为彝器通名。通过器形比较考证为&quot;簠&quot;,而不是豆和铺,因此重新定器名为&quot;公■簠&quot;。","categories":["02_字词句考释"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJz8p_lPdhdt8FzT6Pf72zG4g9wXNXVtQJ1Lfwk1XG8iM1EdlgjLytBoYZ0g5DDETJQFV8BFc3tXmF1M5BN8HBmfMsrqi-Sy4um4AxbTLBm5M3T2HqmdwVeu-B25xQvcUOCeHbAG7M4aZuOanLP37pTO1ya4a4oy12yJfwn-KqmjQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-39","volume":"16"},{"id":6620,"author":"黃海波","title":"“覓”字源流考","abstract":"關於&quot;覓&quot;字,眾多學者因未見早期金文,而誤以為是它字之體或俗體。本文歸納典籍所載,理清其脈絡,以就正于方家。","categories":["02_字词句考释"],"year":2012,"publication":"第三届汉字与汉字教育国际研讨会论文摘要集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxoje6c_J8KwRCMjAyCxHil0NZ9cGmThizvqKCM26BJxeC4LcZk8_E1ug2XrxpF5ek44XeoJo8IKncz44J-2iQNg_PC4VYNe7fzp-m58ScdXQuyfXCveCR-0Rpwk1q96S7Ra0MTC-X2IXVYkSUaESXXVKmaVs6Sy3k5d616ZsAGyRxD9yCXBqb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39","volume":""},{"id":6621,"author":"罗卫东","title":"黄国金文及其地域特征研究","abstract":"《商周金文资料通鉴》收录的黄国有铭青铜器共40件。它们既有传世的,也有出土的。出土地点包括河南省光山县、罗山县、信阳县;湖北随县、京山县;山东沂水县等。通过对现存553个黄国金文字形、87个不重复单字的分析,笔者描写了黄国文字在不同历史时期的特点。通过比对黄国金文和楚、中原、齐系、吴越、晋国等其他地区金文,我们归纳了黄国金文的地域特征。同时,本文联系文献典籍,在分析黄国金文的基础上,阐释了黄国金文的历史文化意义。","categories":["02_字词句考释"],"year":2012,"publication":"第三届汉字与汉字教育国际研讨会论文摘要集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLan-v8mieRC00PEDawXv8lviFOJ3f2LB7IZ1CGwlQMFUek1gu_ogmOYWxLCKCzm3GAvd5h07yigVH3k6DOyL2M_v2Q2U3NGhwtailxDC9qIdNquE-oeiwhNoKlj2-oZiTYW3bgkhUynN1p57iXG-9DAepdpS9PbyOEQNKqhAWGHdvRbB1zK2Lp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59","volume":""},{"id":6623,"author":"王伟","title":"珍秦斋藏越王差徐戈铭文史地补释","abstract":"澳门珍秦斋藏越王差徐戈有铭文34字。通过对比各家对铭文的释读和断句情况,对铭文中关键词语重新做了解释,认为&quot;未&quot;为否定副词;&quot;得&quot;为动词得到;&quot;■(居)■乍(胥)&quot;即&quot;姑苏&quot;,是地名;&quot;金&quot;为名词,即铜。另结合文献对铭文中涉及的有关历史和地名做了考证。","categories":["02_字词句考释"],"year":2012,"publication":"秦始皇帝陵博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDXz0Xeg6ui9o1Zp-P2OqzhFekWjglbNUiA8kfE_qBycAPHDZgQ7uFxnDMO1iowsNIXaUUnwLvWCSGtg_w4riFxBDxJ76s4DGPIABNaUNs_xpLJ3pL5iWk8dreeogarU9kwmkigUiEJYN1cO3vixlLob9feePkplgiD56C4bdy0g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"372-376","volume":""},{"id":6626,"author":"吴镇烽","title":"新见十四年上郡守匽氏戈考","abstract":"新见十四年上郡守匽氏戈是一件很重要的战国中期秦国兵器,铸造于秦惠文王后元十四年,即公元前311年。此戈的监造者匽氏就是清川木牍中的内史匽氏,此时担任上郡郡守。该戈发现的意义在于它纠正了过去人们对青川木牍&quot;王命丞相戊(茂)、内史匽更修为田律&quot;一句的误释误读,该句的正确释读应为&quot;王命丞相戊(茂)、内史匽□□更修为田律&quot;;同时也证明了澳门珍秦斋收藏的十四年□平匽氏戟应为十四年上守匽氏戟,&quot;□平&quot;二字应释为&quot;上守&quot;,即上郡守的简称。","categories":["02_字词句考释"],"year":2012,"publication":"秦始皇帝陵博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKtnffuIYlN2wBWrSF6gc_-w7qhPB_wGRWwLSUe6enPOx4WVmNHFPREDWBQl6Bw0PIgL1UNbCpSjAKMEkaJ0dLbAOiJGIS4jKXXL8gPTXvG5yp7NwKrs9PNQ__bLIQO8-eXEEkwEmkIIUxS6Nca9PUHIAAaFJ_cwhdb8xtDOTyWLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"319-323","volume":""},{"id":6627,"author":"刘玉环","title":"马王堆汉墓遣策名物考","abstract":"一、&quot;■&quot;&quot;■&quot;的考释和&quot;铜泡形饰&quot;的实名马王堆三号汉墓2简牍遣策第343号竹简共七个字(见图一),整理者释读为:&quot;单一繡平皃(貌)百&quot;。释文只作隶定,没有任何解说。究竟&quot;平皃&quot;所指为何物,令人茫然。","categories":["02_字词句考释"],"year":2012,"publication":"西南学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJYCgac-6eFf97PM8x1Z3LfwJGL7kUDEFd4NTWikk9MX2mQxMuxM2yTm78K3Rh5LAh0vaJjcISBgJRLclAS32QDTGxpy6Ud91ilsx377p3MG4HX63jbjJahVLstCDGzI8qL0HqMhyWVY0Q87OKodWW5gsoj7EorMpvI2L1H0kRH2g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"248-255","volume":""},{"id":6631,"author":"张懋镕","title":"试论西周金文中同名人物的区分","abstract":"在西周金文中,出现诸如&quot;周公&quot;、&quot;单伯&quot;、&quot;荣伯&quot;等人物,研究者往往根据此类人名来推求其他同名人物的铜器的年代,这就是&quot;人物系联法&quot;。这是北宋以来一直使用的方法,郭沫若、陈梦家都是利用人名来为青铜器断代的高手。但是,随着研究的深入,学者们发现&quot;铭文中同样人名,有时不是同一个人;即使同一个人,也可能生存于一个以上的王世。&quot;&quot;假设将同样人名都列诸一王之世,特别是以几个人名辗转联系,便会把本不同时的器物'浓缩'到一","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIEjx6RfB1HroRkkYl5U0RrbZcfdztzcEUpEFqiDmvffwmtkNJNFgqZQxN4l381m1xcwINSh4Jop88dnHVtlk5WPlwXKEeg5aDicUgFZy92qB34bkH_7cvEeIuJ3MGke0EtCyLdNBs6Gp1SUApoZ2uatwrU7vTnLZvyyCi4oQjVJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"259-263","volume":""},{"id":6632,"author":"周宝宏","title":"近出商周金文字词考释(八则)","abstract":"一、释西周金文&quot;逨&quot;西周金文以前被释为&quot;逨&quot;的字,目前有很多释法,新出逨盘、逨鼎又引起一些学者对此字的考释。学者们的具体考释及本人对诸说的评价见《何尊铭文集释》。下面按照时代先后顺序将西周金文中&quot;逨&quot;字形体作如下排序,从中或可见其演变之迹:西周早期:■史逨角、■史逨方鼎、■逨觯、■何尊、■小臣■簋、■小臣■簋、■小臣■簋、■鄘伯簋、■交鼎。西周中晚期:","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIcGtocBA5jFIFz9VxKmMRtYq2pEyW4JXbD12-hppp9hvKp0uC895WRsVcKpQWx9CSsYBk8UatxTJPWJYxKNinj4M30pOqFswzH3ZI_ZEQh4j0fjtdDzp8CoeDFyJ35xZ2XXkg5DAYMjndXAgDjAxCztXn3MIopBX8CAyBQ4IWaDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"264-271","volume":""},{"id":6633,"author":"陈絜","title":"读金札记二则","abstract":"一、■进方鼎&quot;■&quot;字考释1981年,陕西省长安县花园村西周墓地曾出土一批商王室后裔&quot;朿&quot;氏族的青铜礼器①,其中有■进方鼎一对,其铭文现著录于《殷周金文集成》（以下简称《集成》）,编号分别为2725、2726,二器铭刻内容、行款相同（图一:1、2）,铭文共计30字（若算上作为外框的&quot;亚&quot;,则为31字）,其辞曰:隹（唯）八月,辰才（在）乙亥,王才（在）■京,王易（锡）■进金,■（肆）■对扬王休,","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIcGtocBA5jFIFz9VxKmMRtYq2pEyW4JXbD12-hppp9hvKp0uC895WRPWMCC_2Rq4CWd1786vLLAO8p1uxs8wifcrgZ6wR25zBbPy6SAd5ebt8PvAovOnsy-ij1TuSc88KlKP23SD6sXLOnfts9NXvTYUuCifMyoEIXaDawUMFwUg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"272-276","volume":""},{"id":6634,"author":"陈斯鹏","title":"新见金文释读商补","abstract":"地不爱宝,先秦有铭青铜器不断有新的发现。这些新见金文是可贵的先秦时代第一手的语料和史料,值得好好研究和利用。笔者近年对新见金文资料略有留心,于铭文之释读间有一得之愚,今选出数事,以就正于大方之家。一、释&quot;■氒众■&quot;《首阳吉金》著录西周晚期应侯视工簋盖铭,有云:&quot;唯正月初吉丁亥,王若曰:'■(应)侯视工伐淮南尸(夷)■。'敢■氒(厥)众■,敢加兴乍(作)戎,广伐南国。王命■(应)侯征伐淮","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI76yuEJ5-nWUZ-aEpSmkdQIDQogzAe2r7nwEJg7iO3w1XmmwxN74cVg7P-mPWlrNXwh_1YcTcS5TBEDh4waQPMQouL5bCUGdqbNLHaSFzNI14ecjdaix2nV0rx3Q_51cd0i_kHEKFr1xImxkZCS5rqQpmw6sNrdHaWsH_zPXYAyQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"277-281","volume":""},{"id":6635,"author":"蒋玉斌","title":"释西周春秋金文中的“讨”","abstract":"一、释五祀■钟&quot;A不廷方&quot;西周晚期的五祀■钟于1981年2月出土于陕西扶风县白家村,现藏陕西历史博物馆。钟的钲部与鼓左铸有89字钟铭,最早著录在《人文杂志》1983年第2期①,后收为《殷周金文集成》（下简称《集成》）358号。钟铭后段有&quot;（文人）授余纯鲁,A不廷方&quot;一句。A字旧拓作:■这个字正好位于钟背钲部的右上边缘,在拓片上很不清晰。旧或释为&quot;■（■）&quot;②、","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBvbT3FiU5ODQRLm2YBhEiYIGvq-HD2pCXzyyI8-MIm3NwWhThZaPK1J7Tv5yxN2pTIQpx-cP0ihhBX2AaaV0aufamVieaUiuAIO3K6RUS8lJvRcPsd6iwhWKh_Se2ud5ZZja0LHXLG5mZSF1IqB25UpvZUD4xZP3DSJo8qU6z2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"282-289","volume":""},{"id":6636,"author":"张富海","title":"金文从宫从九之字补说","abstract":"西周金文中有一个从宫从九的字,《金文编》收在&quot;宄&quot;字头下,字形有■、■、■三种①。这三个字形显然是同一个字的异体,下文统一隶定为&quot;■&quot;。&quot;■&quot;字不见于《说文》,其相当于何字,前人主要有释为&quot;宄&quot;和释为&quot;宫&quot;二说。释为&quot;宄&quot;者如林义光和商承祚②,《金文编》将&quot;■&quot;字列在&quot;宄&quot;字头下,即亦主释&quot;宄&quot;之说。&quot;■&quot;字的结构可以分析为从宫九声,而&quot;宄&quot;字是从宀九声,从宫与从宀（古文字象宫","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBvbT3FiU5ODQRLm2YBhEiYIGvq-HD2pCXzyyI8-MIm3NwWhThZaPKNzrwM3XZrLNqjpWPwyLb7ainCYIrqgUVJeH8o2Wpywmb8dyMhE3DVaVoAH2npZhIb4FFINNpvq9ZjpGSNaWz0WpOAIjJPduclmgo3wFiKYGpMSo3t0dhxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"290-293","volume":""},{"id":6637,"author":"田炜","title":"读金文偶记二题","abstract":"一、两周金文中的&quot;■&quot;字补说两周金文中有一个写作■（《集成》2836大克鼎）、■（《集成》198者■钟）等形的字,或可省写作■《集成》21奠井弔钟)、■（《集成》22奠井弔钟）①。自清代以来,学者对此字的释读就有两种意见,或以为一字,或以为合文②,直至现在,尚存分歧,故仍有必要对此字进行辨析。下面我们先把该字文例录出,以资研讨:","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLgwlmxTe_r3k6lr4xSNJGPRmIIZ7salJxDCl3BPH2D1vme9qhMcSIsohlxVi71wDjYHPNkx2VEG-zFecz_e1NVx7V0rLmOeDuruHizvzN_hruEOn6FDbeNeZH7bJCqLWKeDOoDGLequHMC1ULxOZleKVbJuXvCjJL0s7AZvjjAQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"294-301","volume":""},{"id":6638,"author":"赵诚","title":"《作册般甗》补释","abstract":"商末作册般甗铭文基本清楚(见附图),各家所释大体相同:&quot;王宜人方,無孜,咸,王商(赏)作册般贝。用乍(作)父己尊。来册。&quot;马承源主编《商周青铜器铭文选》(文物出版社,1988年)第三卷第6页有比较详细的解释:注(一)王宜人方,王宜社于人方用兵之事。宜,出兵祭社之名。王宜人方,为对人方用兵而宜于社。《左传·成公十三年》:&quot;成子受脤于社。&quot;杜预注:&quot;宜,出兵祭社之名。&quot;又《尔雅·释言》:&quot;起大事动大众,必先有事乎社而后出,谓之","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIEHFtVGRWrfXwRvzKvxzRVkWGDz3Ehn4mf5C6G3v06OIav62pWdRpQrKRHlNqIeJ_1otIg9_0TqyctqsPNhJFVUHpvh7t80E_A5BHjPey4sbCHU8sZaX1KE1DdoFf3kpnPAj6DPAYQgBSF1_DzilL95P_P1rxL5tteWppFGAAzog==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"302","volume":""},{"id":6639,"author":"罗卫东","title":"单叔鬲“■”字及相关问题考释","abstract":"2003年1月19日,单叔鬲出土于陕西省杨家村一西周晚期窖藏,同出9件鬲。该组鬲同铭,自名为&quot;■&quot;。《考古与文物》2003年第3期公布该组器物隶定的铭文:&quot;单叔作孟嬭（祁）■器,其万年子子孙孙永宝用。&quot;①将单叔鬲&quot;■&quot;字释为&quot;器&quot;,是依据李学勤先生的意见,李先生将此字隶定为&quot;犬&quot;②。其后,董珊先生也考释了单叔鬲的名称③:单叔鬲自名&quot;尊彖&quot;,前所未见。&quot;尊&quot;字右旁中间从&quot;豆&quot;,写法特殊,是&quot;尊&quot;字异体。","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIEHFtVGRWrfXwRvzKvxzRVkWGDz3Ehn4mf5C6G3v06OIav62pWdRpQ_6YWS5REncVN-BUGuXmB_1ewEiKrYOKj-21WZUD_FhxjFyYxCu46Xu7aQHDKC8ljp5TeEKVFundBuGA2Wp7WuPreCr2nbVidbD6G7iq-YJrPLYRJdw2UDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"303-310","volume":""},{"id":6640,"author":"董珊","title":"新见鲁叔四器铭文考释","abstract":"承蒙朱凤瀚先生将他主编的《新出金文与西周历史》赠送给我一册,其中收录朱先生的论文《蚁器与鲁国早期历史》,披露了一组四件西周早期铜器及其铭文①。朱先生已经做了很好的研究,我一再拜读,受益匪浅。本文在朱先生研究的基础上,再做些补充。这组器物属西周鲁国,器主之名为&quot;叔&quot;②,为了今后便于称引,不妨总称这组铜器为&quot;鲁叔四器&quot;。一、叔尊与叔卣叔尊与叔卣均为素面（图一）。叔卣的器、盖对铭,与叔尊的内底铭文相同。下面摹写叔","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXCeb-QO0CSOgYrr-_doMArEU7OIlCfv0XUaUEC4nuxqoSC6HPs47xog4LNYaux1Zpq7Qd9TgVMm4oKgfiZPuhwh6GCB8o7FCZg-8jHvmokfaadhHBoWZe8oYgvRfSigvsB43C9MrLLkafjkad4eWkxkfjkUVkPjEqQe0BCr8VPA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"311-321","volume":""},{"id":6641,"author":"董莲池","title":"从金文勻、钧的构形说“■”为金之初文","abstract":"西周金文中的&quot;勻&quot;字,一般认为即&quot;金&quot;的重量单位&quot;钧&quot;的初文①。普查截止目前所发现的西周以降金文,清晰可辨者共得13例,为研究方便,表列如下:见于西周者,除勻作宝彝簋中用为人名外,一律表示&quot;钧&quot;。而&quot;钧&quot;字稍后和它平行使用,共得9例,表列如下:将上揭&quot;勻&quot;和&quot;钧&quot;的构形仔细比较可以发现,&quot;勻&quot;从&quot;■&quot;得义（&quot;■&quot;西周中期开始线条化）,以初文旬为声。&quot;钧&quot;从&quot;金&quo","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIiS-VzjXeqOQ3w0twjfwnlSFFNi3vlrq2FANT3QIHiqoQ-F6_z35HyFE4S0WrdphwSSbT4SUct-lUFninIqFBdVBWxf3ziPg8a4cr4adzEEGLEyEIhCdP1ROt_uStY8ZvgcTxgiI3-U0rReA6q9kTbgOmzBufgYkIFMeqM0NnMcA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"322-326","volume":""},{"id":6644,"author":"何景成","title":"琱生尊“有司眔注两屖”试解","abstract":"2006年11月,陕西省扶风县城关镇五郡西村发现一青铜器窖藏。据报导,窖藏共出土文物27件（组）,其中青铜器计有鼎1、簋2、尊2、斗3、编钟5、矛12件。在这批青铜器中,最引人注目的是两件青铜尊,其形制、铭文相同,器形独特,腹内有铭文113字。据尊铭可知,器主是琱生,铭文内容与传世的两件琱生簋铭文密切相关①。琱生尊铭文公布后,即引发学术界的热烈讨论,内容涉及文字释读、人物关系、器物年代","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIatIsEch41KpjVN6jw6V7-yVkTax4xb-EG7kHkEMbv7a9uIxFRIC0aZXw3SK9ZCptpIGF9Hc89Thny1vmIPMkoGnz9Y8T_D5L9ORv0JKO29UdCuePYKtPGGnEE6CxDZq4MsfieZg5kUmz6ICuuvtTGvlaWMXsGNLWmdz2mvo4vYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"342-347","volume":""},{"id":6646,"author":"邓佩玲","title":"山西翼城大河口出土鸟形盉铭文考释","abstract":"2009年,山西翼城大河口西周墓地（M2002）出土鸟形番乙件,器形及铭文可参见《中华遗产》2011年第3期及《2010年中国重要考古发现》（附图一、二）①。鸟形盉造形特殊,形制虽与近世出土之凤形尊相近②但器身正前方置筒形长流,当为水器之属,彝铭则自名为&quot;盉&quot;,若此器形实乃同类器中首见。器盖内铸铭八行五十一字（重文一）,主要记器主宣誓、报命及祝祷之辞。盉铭资料公布后,旋即引起学界广泛关注,不少学者于网上发表讨论文章,探讨铭文","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZzY0kibmaVc8GD3FqPSddqczXs90SlOQ37HyP3uYqyBre4bKf9bNJfCO6h4x8pKL7g_nktF_0TYEPaDO0g-VmyJw5vsafiLCWZpD7Kpm9DgHhdCpHsLsNnSZpAW7rwHt7ZJduqkEL2wdof0BkzXXteQ0n22Y74O5HvHSifuArbg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"354-362","volume":""},{"id":6647,"author":"商艳涛","title":"略论金文中的“■”及其相关诸字","abstract":"&quot;■&quot;字最早见于商代甲骨文,在一至五期申骨卜辞中均有出现,字作■（《合》4214一期）■（《合》24249二期）■《合》3290三期)■（《合》34718四期）■（《合》,36440五期）,金文字形与甲骨文一脉相承,于西周早、中、晚期多有出现,字作■（小臣单觯《集成》2. 6512西周早期）■（班簋《集成》8.4341西周中期）■（禹鼎《集成》5.2833—2834西周晚期）,该字有&quot;阜&quot;、&quot;堆&quot;、&quot;■&quot;、&quot;屯&quot;、&quot;师&quot;、&quot;■&quot;等多种释法①,对于前四种释法","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQPoIrWCkxHC-pHiSov5sUtbTVJVp514qE2bpQhAIsvAjhpbFknY55Ro6xNGGo3vALzMf0bGapJC6-Xc_sFglm2LRWAx_j4xnfy2mJ8pMEzi_Bhey1UQeM5DGBkn8MvB11DQQrHAO5T8QphqcVrkttnEGM68b4Is50Nqjdc2sPQw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"363-368","volume":""},{"id":6648,"author":"王帅","title":"西周金文字体演变的类型学观察——以“宝”字为例","abstract":"一目前,学界对金文字体演变的研究工作,实际上是围绕着两个领域展开的:其一,区别行款布局、书风特征及文辞格式之间的时代差异,商周金文书体&quot;三期说&quot;①即属于此。这类研究在描述时往往采用&quot;瑰异凝重&quot;、&quot;雄奇恣放&quot;、&quot;质朴平实&quot;等较笼统的词汇,所谓&quot;三期&quot;也多与依据形制、纹饰进行的铜器分期一致。仅仅注重行款布局、书风特征及文辞格式,不仅无法","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5G1qjmmSmJr09qX0vBgmULs9KLZPYffjFK41ynVKzdmaq6IN3O4ukRJ8iSMcFOt7NyiW82EGkVmhvZ8rJ7HTsbq4oBeubcdma8G9Q0QvP8dZZ5S3zmin6VGE3gGBNv0RalfoHKcbxnB0Azn2Q5azJq2CQJEKlNx3E_HnTpQX0hA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"369-376","volume":""},{"id":6649,"author":"李刚","title":"■、簠补释","abstract":"《文物》2011年第3期发表了《河南南阳春秋楚彭射墓发掘简报》,简报公布的彭子射兒■铭文为我们区分■与簠提供了新材料。关于簠的形制,自汉代以来学者间就存在分歧。许慎《说文解字》簠下云:&quot;黍稷圆器也。&quot;《周礼·地官·舍人》&quot;凡祭祀共簠簋&quot;郑玄注云&quot;方曰簠,圆曰簋。&quot;《诗·秦风·权舆》&quot;每食四簋&quot;陆德明注云&quot;外方内圆曰簠,用贮稻粱。&quot;陆德明的注释明显是为了弥合许、郑二说。","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdES9ykBGJ8F8WCK2uqQ9vF6WzcFOpJeUfBqnu0QCL_t0fT53WfX1MIwgcbgrvkVSp3Oi3tscvTE32yJJvbFkkXEpZqrkZiNWl-ogpy1BTQF2OmA5nyVIWLP3KdzktbsdGkZHhgsSjGTosEcnhR44SMpzjjfsWpwK7aT3FkdRhaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"377-382","volume":""},{"id":6652,"author":"程鹏万","title":"试论吴王光钟铭文“条虡既■(设)”的连读","abstract":"1955年安徽寿县西门内发现了举世瞩目的蔡侯申墓。出土的青铜器除了蔡侯申铜器外,另有吴王光所作几件铜器。吴王光铜器包括两鉴和一组编钟。吴王光编钟残损严重,只有一枚完整的青铜甬钟和47片青铜钟残片有铭文①。青铜钟的残片,唐兰先生曾做过缀合复原②。之后,郭若愚先生联缀了这组钟铭,将其复原成一篇79字（合文按一字计）的铭文。经郭若愚先生研究,钟铭的内容大略可知。郭先生","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmQvzMqM07aIQAhC6X5AZy9ZtpIMuk6mzvyITdj-Wv6NQE1-0G-BUM8Kb9A9kOZ2ttN2tRK0Q8zPpErV69P3n0xrPlB90q6T77__I6IN-oWJiRjUhfQ0_kDLeI7dIOJlTi7ABvsdHWnYBYTUAuxpg4xhk_kQpCiqEKAAcNhE6CoQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"409-412","volume":""},{"id":6655,"author":"白于蓝","title":"释■羌钟铭文中的“乂”字","abstract":"■羌钟铭文中有如下一段文字:唯廿又再祀,■羌乍（作）■氒（厥）辟韩宗■（帅）,征秦迮齐,入长城,先会于平■（阴）。铭文中&quot;■羌乍（作）■氒（厥）辟韩宗■（帅）&quot;这句话,过去曾有多种解释。朱德熙先生研究指出本句当连为一句读①,笔者认为此说可从,故本释文暂依此释写。关于&quot;■&quot;字,过去曾有四种解释。第一种释为伐②:第二种隶定为■,释为匕③;第三种释","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgrp_kgu4-sg2SWMZGMCpuB2eJCG1ahUONt12z5Sx3_cvgtBLLr-sMiQ7KwAWgoixP9JY-HD1nEuhL2_EscIi99w5lQa5hbkAkQJtu5sMXdGdarv_uvvw5IL9Rkp8pcq9eyR87hUBsPHk0Pzqn0q895mRZ04VZa-ETWRWALwileg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"437-441","volume":""},{"id":6656,"author":"陈英杰","title":"战国金文补证三则","abstract":"一、十三年上官鼎(2590战中①魏国器物,铭云:&quot;十三年,梁■（阴）命（令）率、上官冢子疾、冶■（铸）,■（容）半。&quot;所谓&quot;梁&quot;字本作:■（反白后处理）黄盛璋②、张亚初、《集成释文》、《集成》修订本、吴镇烽《通鉴》③、殷周金文暨青铜器资料库④等均释为&quot;梁&quot;。《金文资料库》3295无释文,云&quot;待考&quot;⑤。此字左半从&quot;阜&quot;是没有问题的,右半上部可辨,而下部不清,其形应该是■。","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3ltTxNYRESLcltEqJD8pt5ZS-PElY_ay_ZSSfCsyKpwXntD_4pC-RudD48t-N6wBNKiY01JQDVTpCW36y9rTR5vNdmTjqXYnpRlFd0U6kYi6mlNdeOPe0c7bBiPjtqaYdjsB05CYfoPJXjeAmZxbbDYBZeY96u_XV4iGg4GVUoA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"434-440","volume":""},{"id":6657,"author":"广濑薰雄","title":"释卜鼎——《释卜缶》补说","abstract":"笔者在《古文字研究》第28辑(中华书局2010年)上发表了《释卜缶》(以下简称&quot;前文&quot;)。前文的主要结论是:楚简遣策所见&quot;■缶&quot;之&quot;■&quot;与中子鬓缶所见&quot;■缶&quot;之&quot;■&quot;是同一个词的不同写法;根据&quot;■缶&quot;的形制可知&quot;■(■)缶&quot;是一般所谓&quot;浴缶&quot;,这说明&quot;■(■)缶&quot;是洗浴用的;从&quot;■(■)&quot;的读音、意思看,&quot;■缶&quot;、&quot;■缶&quot;当读为&quot;沐缶&quot;。","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3ltTxNYRESLcltEqJD8pt5ZS-PElY_ay_ZSSfCsyKpwXntD_4pC-RQ4dK9XqRJqrVzqFFZc0BLmRedZoZF3pAkIhppXe_TkJiedMqc6TUbBi4j8Lhtk1nBR0zespVdNLsDvZ5yRV-1GUGnjPNhKjhg6riVBcSLias-LDwFcy4jQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"441-448","volume":""},{"id":6658,"author":"周波","title":"战国魏器铭文研究二篇","abstract":"一、说梁十九年鼎的&quot;■于兹从&quot;魏惠王十九年(前351年)的梁十九年鼎铭云:■(梁)十九年亡智■(遝)■(戟)啬夫庶■(择)吉金■(铸),■(载)少■(半)。穆穆鲁辟,■(徂)省朔旁(方),A于兹从,鬲(历)年万不(丕)氶(承)。其中A学《殷周金文集成》(下简称《集成》)2746拓本作■。此字从&quot;身&quot;从&quot;口&quot;,诸家隶定作&quot;■&quot;,可从。关于其读法,主要有读&quot;信&quot;、&quot;身&quot;、&quot;躳&quot;三种意见。黄盛璋先生将A看作&quot;躳","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDtKK3dorw4nPrqN_Y05WPq1eRG_nWUnlfBgBtv0dvvkhRG8jSH1HJivfLmVP1l4MScKCEhdojqG51_fcaGhetNc_Fj-xE9HSjjTChvly95FlGYyWJuG0WN17VlV9sPcqTor-JSO3P1fLoGWgy0vrk-ImrVrbLLeBJDISu-IghCg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"449-453","volume":""},{"id":6659,"author":"张振谦","title":"燕、齐文字考释两则","abstract":"吴振武先生指出:&quot;燕、齐接壤,两地文字在写法上互有影响,自属情理中事。①我们通过考释、考察燕、齐两系文字&quot;或&quot;、&quot;惑&quot;两字形体,发现两系文字的&quot;戊&quot;旁写法相近。此外,我们还对燕系文字中的&quot;声&quot;字作了考释,并对&quot;声&quot;、&quot;圣&quot;、&quot;听&quot;三字的字形演变做了一个细致的梳理。一、释&quot;或&quot;有一字见于燕系金文,其字形、辞例作:■新收1483燕王职壶（摹）:东■～,周亚先生释","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLWbE7uhcs6ny2xEJJ1YduQccV1SZVlA3uS5yog6HDCWDF8Iwx-ZnyeWB1ONUgFZKuei_6Ad7sJIpFCQLMNiVIwZLL3XGS4g_F31dO0dDMCXm4zc14nBlyr131xiyXyBbWsApIKmrmbgwXZ-Y6G1a1WCcDuOna4wJLObdWZgE3_ow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"457-461","volume":""},{"id":6660,"author":"李春桃","title":"传抄古文考释四篇","abstract":"《汗简》、《古文四声韵》成书于宋代,是专门辑录传抄古文的书籍,书内收录了大量古文形体。传抄古文记录的是战国文字,所以随着近年来战国文字资料的不断增多,《汗简》、《古文四声韵》也逐渐为学者所重视。但也应注意到,这两部书成书于宋代,人们会把一些当时不熟悉的文字误当作古文收录,致使古文中包含了许多后世文字。研究这部分古文有利于后世文字研究,同时也可避免学者误把这些后世的&quot;古文&quot;当成战国文字。本文拟对一些以前无释读意","categories":["02_字词句考释"],"year":2012,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXkFCcIlvOjW9Bx6X32OEaC1iDPf4AXSmLkYc6VvnWIU8XLNtyZsO1htV2jT5JvsRsmX_6EsCkiRzbi77Suf-_VJ3uu7Yk6SnjlsrcxKcnQRFAmU6JX9Ba3_UhoLv3lNmVHqks4kFyTVqEkbzdLItyfeBCNlWMJgo9-n0wjqZCrg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"682-690","volume":""},{"id":6663,"author":"刘孝杰","title":"“孝”词义源流考","abstract":"&quot;孝&quot;的词义源流发展经历了以下过程:人类&quot;孝&quot;意识的起源、发展和成熟导致了&quot;孝&quot;最初意义的形成;&quot;孝&quot;字产生之初的本义为&quot;善事父母&quot;;&quot;孝&quot;词义在后世逐渐引申出多个义项;我国当代的&quot;孝&quot;对传统&quot;孝&quot;的辩证继承。","categories":["02_字词句考释"],"year":2012,"publication":"学行堂文史集刊——2012年第1期","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKKTsaWqlHvxYM9t5qxSYyuTCVodcNnoBNfcboFgcZtznthOb_U6sYV1VL3W8J_hmyUXyqRN7ZrlLrDQw6TRofhcea6hCVFMD8tuwILg2wlJixeEJylGmb3anm6MZXiGtnGqNoxuesBs8Nij146Y7sjRGVebx9Sm_yupJ5DK5nmg55HyoUHf5b&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50-54","volume":""},{"id":6665,"author":"方勇","title":"读金文札记一则","abstract":"文中讨论了金文召卣、君夫簋、簋、女乍簋、仲等铭文中的■字,以前学界将此字释为&quot;&quot;或&quot;每&quot;字,现改释为&quot;(髦)&quot;字。召卣中的&quot;(髦)&quot;表示马鬣;君夫簋、(髦)&quot;表示马鬣;君夫簋、縣妀簋中的&quot;(髦)&quot;应读为&quot;懋&quot;,表示勤勉义;女&quot;,表示勤勉义;女妦乍簋中的&quot;(髦)&quot;为人名用字;(髦)&quot;为人名用字;妦仲簠中的&quot;(髦)&quot;为姓氏用字。","categories":["02_字词句考释"],"year":2012,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJlnxbGjJXKI8wlh-xrxuAcfQfMpt2XY4RIBhhGYcLoeQx83Jg384ocGS9aNldCbnkvXTHG6i6aq3Ue9FSC5SAN11tzUsTKuqIGXYRgzd9H0O56b8G4dvJ9BfE5uYPcYGOLpFClPLbQLrfF3hqOu2XhI6vVd6ClGPGeufsCjJcYUg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"271-275","volume":""},{"id":6666,"author":"刘珏","title":"秦骃玉版铭文释读述评","abstract":"秦骃玉版是20世纪末发现的一件重要的战国时期秦国文物。玉版出土玉版是世纪末发现的一件重要的战国时期秦国文物。玉版出土后曾引起极大关注,学界对玉版铭文的释读等问题讨论比较热闹,本文主要综述诸家之说,加以简要评议,并间附个人之浅见。","categories":["02_字词句考释"],"year":2012,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJk_pToboy-d7nMKNO-YuhI994D3xsaOkN1XHSy-r4f2GeVc7bTnuUva21IXAN42J76RpSR5CVmblayA63PmgvMvr9KEse8NCAxSfopmCFgsFrALBoGtQtCIKEBMD0oFllr8NAEZJEbSrxA-6L3ndH7XDi0QXCdSK7pvAxn504nEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"332-338","volume":""},{"id":6954,"author":"宋玉坤","title":"释“文”“字”","abstract":"文字是人类记录语言的书写符号系统,是语言的视觉形式。我们现在把它们看作是一个词,但&quot;文字&quot;在刚出现的时候是两个词,即独体为文、合体为字。本文以&quot;文&quot;、&quot;字&quot;为对象,研究其本义和引申义,以及二者之间的关系。","categories":["02_字词句考释"],"year":2012,"publication":"成功（教育）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLWcvAV87fu_VXExmnvCX3Wg3bwaqwpxG80UXR2RgnnZCcX1M97CydUPz7dZQRydc89dygDJ1CS-U7fEoODx48xK_BqlodptVgR47ztcxWVnXCPHC1gR6ALfRto3MqrlCUHSM65e5798n_Jhgn4H0C9inQfkmETHkxH5keOdzv2ibMJdr7HM9wV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"284","volume":""},{"id":6955,"author":"杨现昌","title":"《国史金石志稿》所录西周克钟铭文校释","abstract":"克钟是西周时期重要的青铜礼器,共出土有六件,铭文清晰,内容丰富,为多部金石专著所著录。《国史金石志稿》也收录此器,但在铭文释读上还需完善,对该器铭文中一些重要词语的阐释有助于对该铭文的理解。","categories":["02_字词句考释"],"year":2012,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRZ-nz8OaJNy-_U4KxAa3rdWyBjEP3IfG-6g09ZY0DlM7mJ24qA9dXXPqHK4EXX97ZdTixjH8BHoqkI4Is5y2TKiFx_QHKuCm7666E8VIXwVjM-OQh4XVQvS91e1RFxI4GxB6RYvr_RH0XCq9Q4fAfaFYrWZojmL6TN68_8KM3W_w-dmQfYyVK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-25","volume":""},{"id":6956,"author":"郭利芳","title":"春秋金文构件的通用与混用","abstract":"在春秋金文的文字系统中,有一些构件在构字时存在互换的情况,我们把有理变换的情况归入构件的通用,而把由于形近或者其他原因造成的构件混淆归入混用。构件的通用中我们又分为两类,一是意义的相近相似,二是构字原理不同之构件通用。","categories":["02_字词句考释"],"year":2012,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRZ-nz8OaJNy-_U4KxAa3rdWyBjEP3IfG-6g09ZY0DlD_6PHHb6vd8JLwKMMbK8IqDCg0qOaZ5t6ycUpHKK_V89WEbdZ4NaNN11mNx7QJR2CDMBTz1GGZwSodFjI5DKtduBQ1fN_A9hktRQ8Dc5aEMZeZZqr-18cdCA1SUQDetsSBB6ZVrMzrX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46118","volume":""},{"id":6957,"author":"杨现昌","title":"分析古文字构形,探究一些常用字的本义","abstract":"对一些常用字的古文字形体进行分析,探究这些字的构形原理,有助于理解这些字的本义,把握其真正含义,这对于正确理解古汉语,特别是上古汉语的句义、文义是很有帮助的。","categories":["02_字词句考释"],"year":2012,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZZef8bgjOoQp-g7FGXX5SrJQDeFWbc3E54vbI1AHrAU3b5fMi-pute9BgOuKDuZOZuAP63p7-0USvFMc1GLtQ_vaXqvnsFVHY8j_OBwhe-JFYT3ojwCqn-IopVIrtH9bNL07b_kDGg2y3rcM7vmTRwyGxhpuH4yyb_02RWVJmCTK7Ud-YQuLm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-28","volume":""},{"id":6958,"author":"包金曼","title":"试论汉字起源与初期演变","abstract":"汉字是世界上历史最悠久的文字之一。有关汉字的起源自古以来中说纷纭,结绳说、八卦说、河图洛书说、仓颉造字说和图画说等。我国学者历来认为图画说(原始图画与象形符号)是汉字产生的主要源头。本文将会就汉字的起源和初级阶段的演变过程做一定的研究与考察。","categories":["02_字词句考释"],"year":2012,"publication":"青年文学家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAXNB3wJWw9bseLWnIcjWnVyjQAq6slt4bHuJv1iGNcsSI2sz_zPKd_ySrbcd6vmoLMhtGXptysoNNFgjHjuB3WbvtqnDNcWMWsYvJK6wGgjeLm0OUbheFC2NEEVw6ISqL_FBcyCb7PshRntks6rpBFOj-UJ3znoHnwGrbDx6r6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"145-146","volume":""},{"id":6960,"author":"郑勇","title":"由《遂公盨》看西周金文中“德”观念的演变","abstract":"西周青铜器因其独特的载体,保留了许多原始珍贵的文字材料,结合青铜器分期断代知识,通过对其中关于&quot;德&quot;内容的铭文研究,可以帮助我们了解西周&quot;德&quot;观念发展演变的足迹,为研究西周思想史打下一个良好的基础。","categories":["02_字词句考释"],"year":2012,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI-usmnf9umiiq02xp0DMf8pfo6FwA8r1dgIkjfcNaohzNwXVsheRuGjwM0qOFGItGyot9dd9DCsbhpdyUC7EKV6iC1E2PGPe1-wdGZJRmTFDpsqVmd1GEz-bJLOF8SsqSJE76AEhFamCtEq0apD2mEo7ed3g_w_QYVlxPXj_ICQJpWsglFmx3C&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3, 8","volume":""},{"id":6961,"author":"彭吉军","title":"释“彭”","abstract":"&quot;彭&quot;的声韵调历上古、中古、近代而变为&quot;péng&quot;;字形经甲骨文、金文、小篆逐步定型;字义由初始义&quot;鼓声&quot;发展出一系列引申义、假借义。","categories":["02_字词句考释"],"year":2012,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL259tpTe70b2fEDy2oPA2zToF7BHyZ2Ib0u33uVofxEsmCf-KsQxjzAh6zWbQ1685doMvdsLF68Qt6Y81L-uu9lxoUHovdlTWeLzXAsVEKL965Mlr3leWndn8AS3cvC3Nj1tFM6XHAuS897BNA5ECVXMCCEGD-oYC6fRz5txUjPNv9ihrS_AR4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-50, 152","volume":""},{"id":6962,"author":"秦凤鹤","title":"秦公簋铭文“噚”、“徵”略考","abstract":"本文对民国初年甘肃省天水市出土的秦公簋铭文中&quot;噚&quot;、&quot;徵&quot;字训释的现有研究成果进行搜集整理。参考学者们关于两个字的隶定及解释所提出的不同意见,并结合古文献资料,我们认为前者隶定为&quot;噚&quot;,读为&quot;寻&quot;,训为&quot;用&quot;;后者隶定为&quot;徵&quot;,读为&quot;昭&quot;,训为&quot;明&quot;。","categories":["02_字词句考释"],"year":2012,"publication":"丝绸之路","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL259tpTe70b2fEDy2oPA2zToF7BHyZ2IaeLKgbxQTNjMhP2e1v6YFkOykk_PYG_Qn4ciDA7Qhc9qJaMi4WsVidvx9aQa7igNAjZq7hymOhbyv5xWSlu9HgAbVab7z-s3J61ZXQ8DiD85PfdHoGvweMQygnXd4MViKt5DsXJ5FowA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-90","volume":""},{"id":6963,"author":"郑一","title":"《双剑誃殷契骈枝》中“从×与从×一也”研究","abstract":"&quot;某字从×与从×一也&quot;是于省吾先生早年立名之作《双剑誃殷契骈枝》中常见的重要观点,其在1979年被修订成《甲骨文字释林》时多被删除了,但这些观点对我们识知古文字、研究于老的释字思想仍有裨益。","categories":["02_字词句考释"],"year":2012,"publication":"文教资料","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJk_D_jrgaIwapCMnNAI6Nxg9p1n1owyAibVQKGPIw98O0eZ2iamBHnK8PQCzYiR7bYCro0jg4IehxHS8sE2CcbmOcVhPjXgHg63wdUCUaekyRSiK3uc9IdUjeTpFIwM1borCANMEgxgcEKNd65Qyv7y6I5xLybkv5ukf7wZDY43gX6YF1-TIhS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-31","volume":""},{"id":4832,"author":"董珊","title":"釋西周金文的“沈子”和《逸周書·皇門》的“沈人”","abstract":"西周它簋銘多次出現“沈子”一词,為便於討論,錄全銘如下:它曰:拜稽首,敢敏卲告:朕吾考令乃■(?)沈子作夃于周公、宗陟二公,不敢不夃休.同公克成妥吾考,以于尹顯=受令。烏虖!惟考■(捷)敏,念自先王先公,廼妹克卒告剌成工,且吾考克淵克,乃沈子其顧裹多公能福.烏虖!乃沈子妹克蔑見■于公休.沈子肇畢■(豚?)賈嗇,作茲簋,用載饗己公,用各多公,其丮哀乃沈子它唯福,用水靈令,用妥公唯壽。它用裹佐我多","categories":["02_字词句考释"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIp7xcGreZ5jyd7r5NOz3XynJs9OmbGeQ6NebbR24b1QBSbaPjNaGcaP_jfmwjaRfQP-Mx4XtBCGM1oVJxRLZJgab6B4JfT-rHZL1hyztmo0kuaSNRPnUPVCHxBKPjD6bXmHW9qsEGC4bNMP8nN0r1d4EHuG4x7lGuUpaYA52_VdQwc6sGhc2ts&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-34","volume":""},{"id":4833,"author":"蔣玉斌; 周忠兵","title":"據清華簡釋讀西周金文一例——説“沈子”、“沈孫”","abstract":"清華大學近年搶救入藏的一批戰國竹簡內容十分豐富,有極為重要的價值。其價值之一端,即是對古文字的釋讀有啓發作用。《清華大學藏戰國竹簡（壹）》[1]出版前,李學勤先生在介紹該書內容的《清華簡九篇綜述》一文中已經指出:“像《金滕》這樣有傳世本可資對照的簡文,在研究上還有一種特别的益處,就是使大家易於識出許多過去不識或者誤識的古文字。”[2]李先生並舉出一例:","categories":["02_字词句考释"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIItQx4Dk7P-7r7XsFZ6V_Me4GkZPsEVpGhUveVuNk-kV4oANe3yUTu_l8Oc5_2GToURg93_ZpXLyu3rJ1HEgvSLHvSrVJGVWTPreYZNY1xhDLFPspe85kN7MKXfvS82lZiVenoDR4dSEEEitOemwClc5LQafL8M2stQAaKSYtzyGijttbbCo4E&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-38","volume":""},{"id":4835,"author":"袁金平","title":"鮑子鼎銘文考釋商兑","abstract":"《中國歷史文物》2009年第2期刊發了吴鎮烽先生所撰《鮑子鼎銘文考釋》一文（以下簡稱“吴文”）,介紹了一件2007年4月發現於西安的春秋晚期齊國鮑子銅鼎。該鼎内壁鑄銘文45字（包括重文3）,内容非常重要,吴先生的考釋亦十分精彩,後侯乃峰、程燕兩位先生又有所補釋[1]。拜讀後,有一些不同意見,在這裹提出來向諸位先生請教。根據吴文,將鼎銘釋文轉寫如下（采用寬式）:","categories":["02_字词句考释","01_新出器物"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIw1S3Lv1pIp5gi4cqC9XW7qTlrewlp1lK9zM_vOVZKOTNnmQA7czPRRasPOayvDHYabED70HK2_EdSsK9HsgDRE4G7QvOWiwZX9bjJqpnqRVxpQlt7_YmQMKAYBiLDdQg6EOyXt0LzThPmQQ6i81I3ONTtq-WgacYRetn0o85H-u1LuN66FC3l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"152-155","volume":""},{"id":4836,"author":"張桂光","title":"金文札記二則","abstract":"一、釋■申王襄、葉玉森說■字卜辭及彝銘併見,諸家據文義推定其當讀作翌若昱,作翌祭或翌日解,無異議。而對字的形義分析,則各家頗見分歧。有認為“象毛髮■之形”而釋“■”的[1],有認為“肖蟲翼或鳥翼形”而釋“翼”或“羽”的[2],有認為“本象刀形”,“古讀昱如刀”,“翌从羽乃刀形之訛變”的[3],近年則以象羽翼形、釋字為“羽”之說最占優勢。筆者則認為王襄、葉玉森釋“翼”更為合理。","categories":["02_字词句考释"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKVlg3AQ7Em20opOG8pCCLI_env01Q68dDXgJsYdkC8IlOymbv-mm1bdhAL7gRAGjt1gTEo8igCRtlXX5ROMgAlsy2dzrI6jvguY71ABEP_RWDi5RxsUkBi9vNNwiteSoAS9C_R6aFOpDnR9qGk9T6qZzLo1gkbe9OPeWudf_WYSVb-YrMoqJcr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"156-158","volume":""},{"id":4837,"author":"黄錦前","title":"談兩周金文中的“■”字","abstract":"一安徽壽縣城東丘家花園出土的鄂君啓節[1],其中車節3枚,同形同銘;舟節2枚,同形同銘。節銘的最後一句皆作:見其金節則毋政（征）,母（毋）■槫（傳）飤（食）;不見其金節則政（征）。這里要討論的是該句中“■”字的釋讀問題。車節該字字形較清晰,作■;舟節該","categories":["02_字词句考释"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdprrR5DmAoyMI6oAemDiAfAjA5bizb9WRg_uC46LI8Y2u6-AAKt8Nea8NikJREZWHFonIpjtYt-DRXdiVxzv25xckqPptdJc0jCb_wlDHhoyKAzzq0sWyCxP_-440TPxpi6PN9aj2x9otyUOPcplDiA_3dDIcOOh57f6ynRdVBigWeMo_wKcY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"159-171","volume":""},{"id":4838,"author":"劉釗","title":"古璽格言璽考釋一則","abstract":"某私人藏家手中藏有如下一方格言璽:璽面基本為正方形,從字體看,國别應屬於三晉。該璽印文共四字,右邊兩字為“敬事”二字,其中“事”字因璽面佈局的關係偏旁有些割裂移位,本該作“■”形的“事”字被割裂寫成了“■”形。在戰國古璽中,因出於佈局匀稱美觀考慮將字形割裂移位的情况很多見,如《古璽彙編》所收如下幾方璽印:","categories":["02_字词句考释"],"year":2011,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtjOP4eHEvrtkNNyQN3mgqoKwMr0VUqwuB2BFMVvRzTwnDGH0BXcT6tATs74UI0UYqk8bh6Dm4QZBgTSS9ipXdexq346y5FjgfM02mhMpMlAhJ32pvYOFY81U1weCpoiX7kDvfTCDhvpSYXqTt4mupmqnP_wk1_YnrhNzTIvyuRuv06VB792qi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"172-179","volume":""},{"id":4972,"author":"傅华辰","title":"西周金文形容词的系统性","abstract":"对西周金文形容词的词义系统进行研究,发现西周金文形容词不是孤立存在的,而是相互联系的。词义上的相互联系使西周金文形容词形成一个系统,其系统性主要体现在同义词、反义词和类义词的聚合关系上。从甲骨文到西周金文同义词和反义词的聚合关系是不完全相同的,这说明词语的变化不仅是单个的词的变化,也是词语聚合关系的变化,从一个共时的词汇系统到另一个共时的词汇系统,词语的聚合关系进行了相应的调整。西周金文形容词中同义词、反义词和类义词的聚合关系有的一直在语言系统中传承,直到现代汉语词汇系统中仍然存在。","categories":["02_字词句考释"],"year":2011,"publication":"皖西学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL94qIaHUAPIzWj4b3pl_7jA1oKa07byK_5COAY_feuLGe7x_5rmI-56i173MWO059yc0zoeltP_7iX1kcSTd0ybKtNP1aaZXYd6i33eKxlPa7XMUERlQBcXr1qFUqUdCrz4u6TP7UFZTJ8IQ6BoE5bOgUsM3SeRic1-3dOKJE5KA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"112-117","volume":"27"},{"id":4974,"author":"雷春辉","title":"论“合笔”","abstract":"&quot;合笔&quot;是汉字演变发展过程中省减笔画、简化结构、美化字体的一种方式,即把相近、相同的两笔或三笔合为一笔。明乎此,有助于准确解读某些汉字的形、音、义,纠正许慎析字的错误。","categories":["02_字词句考释"],"year":2011,"publication":"科学·经济·社会","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQhFtXQVYCOoo3su4XL3IDGm96oi5hLEpXMcpiGWn8GeHdT08bYtVbX3y1bRxatmuRWPdPJ0NsamwjUCsVlBWTkewPbv1VoOjETp--Qg30VlTF0iUfRpjkqnku_KDqs7hbyPMzCVTpRA1t5v8Oes47snMQWSJ_iizeexoogeuMUQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"172-174, 180","volume":"29"},{"id":4975,"author":"刘益明","title":"释“■”","abstract":"甲骨文&quot;■&quot;字象上古一种储粮建筑之形,但历来对它的解释却众说不一,陈梦家、徐中舒、刘志成三家的观点是:露天的堆积禾麦之处,或者不明确指出是将禾麦藏于室内。其说法与实际情况不一致。甲骨文、金文中的&quot;&quot;字所揭示的其实是一种兼顾防潮、通风、防野兽(偷食)、防雨的实用型储粮建筑形式,它的特点是拥有圆锥形或人字形屋顶,底部抬高,四周围筑以石木厚墙。","categories":["02_字词句考释"],"year":2011,"publication":"成都大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIwovTFlZ3G96XYp-41kIMvjT2Nb5o7EGg_k53CYPJA0e8_S-8OLD_SKcDdRMyEIrnAxIkcS-6Nm1JvbM0nYUFsi4J6fdCfG_ko9-ZTdGWzehbgIqIptdlm-I-9b2utAmQ7Je9LUTjwjFzsmZGCaMBdHGZty1eurgijalJ8jHZzdQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"126-129","volume":""},{"id":4980,"author":"王晖","title":"宰丰骨柶刻辞与功能考释","abstract":"晚商雕纹宰丰骨栖根据其刻辞及骨料鉴定,是用商郊所获赭红色爪哇犀牛骨料制作并雕刻上文字及图案花纹的。其器自命为&quot;(?)&quot;,实即&quot;栖&quot;字本字。古代匕、栖用途与形制式样相同但所用场所不同,普通实用者为匕,而以兽骨做成并雕上花纹在宗庙、朝廷等重大礼仪场所使用者为&quot;柶&quot;。宰丰骨柶为古代匕、柶之别提供了范例。","categories":["02_字词句考释"],"year":2011,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFTtpTKKRPKqV_kVWZZXiZNfQB6nPCOUUU8jDNM4BP25xuCAwq_Ay_4ioLvR7LYjDs2b5C3Dj0Fl-aurx-qz4xoTOTyStjOwKANlK7XT_I-3Chwsd_kXWG4GdIKD-eoh3UfSY31W7C-wMGKp0bJaO9dybp0sT_nIaVaCgXgxaFtA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-61","volume":""},{"id":4982,"author":"杨敏","title":"金文的“萬”","abstract":"金文的&quot;萬&quot;分为主要用作族名或所祭人的名号的&quot;萬&quot;和用作纪数的&quot;萬&quot;两类。前者较特殊,主要出现在殷商时期。后者字形分为单个的&quot;萬&quot;、&quot;萬&quot;与&quot;(辵)&quot;构成、&quot;萬&quot;与&quot;彳&quot;构成、&quot;萬&quot;与&quot;止&quot;构成、&quot;萬&quot;与&quot;言&quot;构成、&quot;萬&quot;与&quot;土&quot;构成、&quot;萬&quot;与&quot;(〓)&quot;构成七种。&quot;萬&","categories":["02_字词句考释"],"year":2011,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ0A7OUy4K0jutDdOB7QPBz5pgZEJUQWNLi-Wgt9LIf-m64iaVN79_apF1Z5vTqyixrkokJYjlvsUB4s9dc_WnxFDvjzfQ4UsUGyOFZRrWWRGNP7DFukUhdu1OWaadrr0JplvhSNHH_S_6zw880677qF1LaW74OYCxmNQy5NH1g9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46311","volume":"33"},{"id":4988,"author":"崔南圭","title":"西周青铜器盖铭器铭之异文","abstract":"以中国台北故宫博物院馆藏西周时期盖铭、器铭皆有的青铜器为研究对象,归纳了盖铭、器铭异文的十二种类型,即:笔画添加现象、笔画省略现象、笔画方向差异、笔画弯曲程度差异、笔画位置不同、字符添加现象、字符省略现象、字符位置的差异、不同字符的使用现象、同字符的讹变现象、伪作而风格差异现象、文章顺序不同。","categories":["02_字词句考释"],"year":2011,"publication":"重庆理工大学学报（社会科学）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCba5Gocz_052JL1qUpmHT9ALWe6n-XubQrc8tGIgxkU0vnR_ArYglH6SW-QKB7PrrfJj5O4Ok1qMwFEH0uNaHVjtxUHyVbC7hm77-2NgSevGDQZj28hnFHplAgSrVs5JdaWoc-lkkNekmn9pmzYHewQykOScvjDkSLMx1-_ucdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-26","volume":"25"},{"id":4989,"author":"魏芃","title":"再论“益公”及“益氏”——兼论西周金文“公”称中氏名的使用规律","abstract":"西周金文中所见的生称&quot;益公&quot;之&quot;益&quot;皆为氏名;死后称谓中的&quot;益&quot;字并非皆为氏名,其中的一部分属于美称或谥号等个人称谓。从现有资料看,益氏与毕氏、单氏皆不存在分支与大宗的关系。生称&quot;穆公&quot;&quot;、武公&quot;中的&quot;穆&quot;&quot;、武&quot;很可能皆为氏名。传世&quot;谥法&quot;不足信。","categories":["02_字词句考释"],"year":2011,"publication":"历史教学（下半月刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIC0okHz4wWfGHWS5EgtC4mjXmLULrZkRNibV9Aw7giyyJrD2WpUx3OfMr-QkRrRoAWB9SjaN5ZXIvKRWxiptzqkohmj_JWAat7BREWjmDLcWhBaezcssaHa_IlmyGtmbyQSKp2S4onD1LfFB4dp6UFANLvrc5NgwyKsuh3YEVog==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-70","volume":""},{"id":4990,"author":"郝红霞; 马孟龙","title":"汉金文“杜宜”考识——兼谈汉代铜器铭文的宫名“省写”现象","abstract":"容庚《汉金文录》卷一著录有两件汉代&quot;杜鼎&quot;,两鼎器盖各有两组刻铭,现将两鼎器盖铭文转录如下:杜共。第九十八鼎盖,重一斤八两。名曰九十八[1]。/杜宜共。百廿八。(&quot;杜鼎&quot;一)[2]杜共。第百五十五鼎盖,重二斤。名曰百五十五。/宜共,二斤。(&quot;杜鼎&quot;二)《汉金文录》卷一还著录有一件&quot;杜宣鼎&quot;,器身同样有两组刻铭,其铭文为:杜共。……重六斤十两。名曰百五十。一斗。/杜宣共,一斗一升,六斤十两。廿六食食。","categories":["02_字词句考释"],"year":2011,"publication":"文物世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-53qw2pOhf6TlH3boi7qTbBwAMcNJXSWIM4_E7UaCqRYDMhPyUGKcozhaJbRvI8vjxzH0IiDXcJRoJnJguRPa89gS1bR-oik-SujuczoGBmZ9_bNo3maO2P9XFBhV4Nt7dg_fftgZP5Sk8rYQ1ctMwgJcmfCGyGPoKh_LV6IFAA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-42, 51","volume":""},{"id":4994,"author":"王应龙","title":"从西周金文看汉字的形声化","abstract":"从语言本体研究出土文字资料是进一步揭示出土文献在思想、历史、文化等方面价值和意义的基础。简帛文字脱胎于周代文字,不仅是沟通古今汉字发展的重要桥梁,也是研究古文字构形的重要参照。康少峰博士的《读简札记两则》是关于简帛资料本体的研究,它以传世典籍和出土文献互证的方法对西汉竹简本《老子》和清华简《保训篇》文本予以讨论,对已有学术成果进一步深化;王应龙副教授的《从西周金文看汉字的形声化》立足于汉字构形,从文字阶段史的角度分析探讨西周金文的形声历程,以期窥视中国文字的发展趋向;王宝利博士的《殷周金文颜色词探析》则立足字形,联系词的音、义,进一步探讨殷周金文颜色词的使用以及语法功能,是将本体研究向文化方面","categories":["02_字词句考释"],"year":2011,"publication":"河南社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUN0b4OqJdciply1hAMT_O-s0KKfBD9_kRqfpZfCui531F0WUmaRT6y7yxG5zLqCg6X1A6Jbc31J8fefg3k7YAb8NWq1oU2BL0WXXqmzI9WIHo0RXZ16zRCb3w5EyAwrwhQS2GoWP4T1FD8g7MXU3O2ak7nbOv7PCuYF49iG4AEg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"174-177","volume":"19"},{"id":4995,"author":"王宝利","title":"殷周金文颜色词探析","abstract":"从语言本体研究出土文字资料是进一步揭示出土文献在思想、历史、文化等方面价值和意义的基础。简帛文字脱胎于周代文字,不仅是沟通古今汉字发展的重要桥梁,也是研究古文字构形的重要参照。康少峰博士的《读简札记两则》是关于简帛资料本体的研究,它以传世典籍和出土文献互证的方法对西汉竹简本《老子》和清华简《保训篇》文本予以讨论,对已有学术成果进一步深化;王应龙副教授的《从西周金文看汉字的形声化》立足于汉字构形,从文字阶段史的角度分析探讨西周金文的形声历程,以期窥视中国文字的发展趋向;王宝利博士的《殷周金文颜色词探析》则立足字形,联系词的音、义,进一步探讨殷周金文颜色词的使用以及语法功能,是将本体研究向文化方面","categories":["02_字词句考释"],"year":2011,"publication":"河南社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLeAGForOo1XzTSYJbfLdm_aCKtpl55a8ExUtOlVMgkUdRdvMLN_J-Kud69UksADyWfSxgH1bvJD69hMDVHiYIa3TCk1j-e60nUWTSO538IJ3UANkF8E_9TzA_PbSnuhDCjsmCbYHkVRAXoKcvhokREP6npTRsEOR9C7hjtgW02ig==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"177-180","volume":"19"},{"id":4998,"author":"武氏玉璧","title":"说“西”","abstract":"&quot;西&quot;是&quot;栖&quot;的本字,由象形转为假借,专指方向。《说文》&quot;日在西方而鸟栖&quot;的解说不妥,应该释为:&quot;日落鸟■,故因以■为东西之西&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"濮阳职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFURnVJw5QATwbh5VeEu5McNqLDMn_LMFBPcuCzl9gKf6zYlQmss5ykubyQ4sfNQrH0mUhEhLNAGIZ7AHqULW9ZgdbbaFQpxrAYw8vL5Ipkl5uvyQRiAikklpQLOjsR5sstchlKmmrXXJq-gs8ICZkKzOPA3BzmFLAPS6oaE5zuw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-71","volume":"24"},{"id":5001,"author":"蔡运章","title":"曹操高陵出土铜印考略","abstract":"河南安阳曹操高陵出土的一枚铜印,印文篆法工整秀美,构形奇特诡异。它的上部呈圆圈状,下部则与金文及《说文》篆文&quot;■&quot;字的构形相类,当是&quot;■&quot;字的别体。曹操名操、字孟德,因&quot;■&quot;有平定之义,与&quot;操&quot;的含义相关联,故印文&quot;■&quot;当是曹操的本字,而&quot;孟德&quot;则是其功业有成后新增的字号。这则印文中部向内凹陷,它可能是曹操专门用于钤盖封泥的印章。","categories":["02_字词句考释"],"year":2011,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK3ROigcrWDurMChdmYMQHfXp8VZfgPBKa3ZCu4JUNyjJ7ZVidXWpHPbZ4UbtslRnr3_NYwBw03EyyouXI8IaqWzYMEfHTDqG9V12Z0K898ilR_IOV8-KmdtqvdrUbiyxrlM24hhB5gkNH6Y_d3jiEvXzR2wZzAxH_iHpyczDpv2g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-67","volume":""},{"id":5003,"author":"袁金平","title":"齐金文考释二则","abstract":"一、国差铭&quot;造&quot;春秋时齐器国差(《集成》10361)铭云:&quot;工师铸西(墉)宝四秉,用实旨酒。&quot;其中&quot;&quot;(下以A代之)字,学者多释作&quot;&quot;(&quot;何&quot;之异体),认为是工师之名,至今似未有人明确提出异议[1]。而《释文》做法比较谨慎,保留原篆,将其视作未识字[2],似乎反对释其为&quot;&quot;[3]。","categories":["02_字词句考释"],"year":2011,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItLAUHofSsH9f4P5pQyRsqx-fbcMuHo_w1zCKwFirqu8tC03P0letvxVKGsCPVABEamMYU4eAJcTjFdqhh6GWPM25i0LNQ1L6RVbuJy0xiB4UGzlF1lIbxaMjWPQahz4OgPyVG31fNnX_9mxde6ppscmhlzzdqaJzmPCeO3pFUpQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"93-96","volume":""},{"id":5005,"author":"孔令远","title":"徐国青铜器群综合研究","abstract":"目次一徐国铜器铭文研究二徐国青铜器的组合、形制与纹饰特点三徐国青铜器的特点一徐国铜器铭文研究由于徐国史料的匮乏,徐国铜器铭文作为第一手资料,对研究徐国的历史文化有着至关重要的作用。20世纪30年代,郭沫若对徐国铜器铭文作了初步整理〔1〕,其《两周金文辞大系图录考释》收录七件具铭徐器。1990年代初,董楚平对徐国铜器铭文作了较系统的整理〔2〕,其《吴越徐舒金文集释》收录二十三件具铭徐器。两先生对徐国铜器铭文的整理工作值得充分肯定,但因相关条件的制约,他们未能充分利用考古学方法对徐","categories":["02_字词句考释"],"year":2011,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWD7dXWbkZk20-1qZ3Le6_eV1NNfRLQnA8eiXz5fOPtdGxh-yMHp3F7tAFQzpEtjQzgyBBoSaABR9Mbh_yyJz-t-q1_DCyE7u3NHWZFnI4Du7dmwNyPSqMuwsiLlT8s1x8uxFSi2jYBgAmZ3-4s4hm0rrigGIfjBFkHUif7iu9GQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"503-524, 578-579","volume":""},{"id":5009,"author":"钟如雄; 胡娟","title":"释“況”","abstract":"&quot;況&quot;《说文》释为&quot;寒水&quot;,段玉裁认为许说&quot;未得其证&quot;,且自古以来并无书证。从甲骨金文看,&quot;況&quot;象一人跪(坐)于水边看自己呈现在水中的影子之形。铜镜尚未发明之前,远古先民以水为镜,或以皿盛水而监,或临塘湖俯视。水中的影子就是自我的形象(像),这种影象虽然不能保留,但可以不间断地监(照),将其印在脑海里。所以&quot;況&quot;原始的字形义是照像时映在水中的影子。&quot;监&quot;是看见自我影像的行为,&quot;況&quot;是呈现在水中的视觉形象。","categories":["02_字词句考释"],"year":2011,"publication":"西南民族大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJkMlDNO3gIWC5x17qDb8Ua6NzlCbR6d9UFDAkvSjtHzqbtBHnn8d_0XsgzwTchrJT6VY8bqzJt2eB-204kleykMopbwD2NeejUqdvrx7-RyJeZFitaQzTvJjS6xrhbMuGvfOKnqUL6CweWZ-QkHJiMOBio6dM_mKicPNX9XneNIQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"161-163","volume":"32"},{"id":5010,"author":"赵玉艳","title":"浅谈“堇”字本义及同族字考释","abstract":"&quot;堇&quot;在《说文解字》中释为&quot;黏土也&quot;,分析为形声字,一直存在争议。从古文字角度,结合先民社会生活,对以&quot;堇&quot;为声符的同族字进行考释,探析&quot;堇&quot;字的本义,考察其引申义,得出&quot;堇&quot;从不同角度进行引申孳乳,显示了&quot;堇&quot;字族的发展轨迹。","categories":["02_字词句考释"],"year":2011,"publication":"新余学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIljZ_aj_PDl7gEqy8NfIkXzYaJDoBenrsX-Qvy_Ix6UvqfLjifVmBRZSKtUsmur03ROxw251zQdYUBgVynqiS12boNepBP7QaDph6rcJQVmk2H2zQaW-vFODDq5iILq_xG1P3AeQ2QMCTCmrLi4g7DosLu_38VVgJJrLHGvIoumQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-99","volume":"16"},{"id":5011,"author":"朱蓝凤","title":"“信”之意义阐释","abstract":"大约春秋晚商时期,&quot;信&quot;就在金文中出现。&quot;信&quot;在古文中出现的频率相当高,词义也相当丰富。通过论证,笔者认为其&quot;随意&quot;之义的产生是因&quot;伸&quot;而起,就此义时,&quot;信&quot;为&quot;伸&quot;的通假字。","categories":["02_字词句考释"],"year":2011,"publication":"山西师大学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxda21bGVSVPWhl32TrpJQYrjL85tO3-Cl4Gzgtl71FMOPHdRyHn9-VgmjEYR4GHOMpNN0yoUYlq2CLMXwG84sn0LMtgHtuOg2pTfozanybR52qV6fv6zOQ4rDbuVldx524aQrv4_TnX2KHwq2SefxUdU6rtbbHb2grRxl2U4vgA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"130-131","volume":"38"},{"id":5012,"author":"李友广; 王晓洁","title":"郭店简重要范畴及其思想管窥","abstract":"20世纪90年代郭店简出土与整理,虽有不少学者对其中的文字做过相应的考察与辨析,但还有值得继续深入研究的必要。简文当中从&quot;心&quot;的字特别多,我们特选取几个在哲学史、思想史上非常重要且颇具代表性的范畴,并结合当时的社会背景与思想特征进行考察。一、&quot;惪&quot;字考察德,甲文为(?)、金文为(?)、小篆为(?)。从字形结构可以看出,甲文德字字形中间表示道路和方向,用眼睛直视的样子表示正直;在金文中,其字形加上了&quot;心&quot;字,表示用正直的心去做事;而在小篆中,其字形与金文并无太大差异,&quot;彳&quot;是形符,","categories":["02_字词句考释"],"year":2011,"publication":"华夏文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwhtNHN1w0NgcId8nkk5LZ9auflqZzICjcha2qNLL47PUELczolcIZN3y48pNADoQAYwcTheVZgw8zRscnGOgQ98ZfMFk97_DrG5a6CX4xmVtgtgtVcSnLkMGNz4t9SFwnLqFwDIKKFCPHgCDtjtnNZTLUaEAnAezlpguyaJ1_JA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46339","volume":""},{"id":5013,"author":"杨怀源","title":"金文语音研究述略","abstract":"学者们对金文语音的研究可以分为三个方面:一、金文韵读的探求;二、利用金文语音对上古音研究进行补苴;三、探求金文音系。","categories":["02_字词句考释"],"year":2011,"publication":"重庆三峡学院学报","link":"https://link.cnki.net/doi/10.13743/j.cnki.issn.1009-8135.2011.05.023","pages":"95-101","volume":"27"},{"id":5015,"author":"徐山","title":"古文字考释四则","abstract":"&quot;匄&quot;字的甲骨文形体为&quot;从刀、从亡&quot;的会意字。&quot;亡&quot;的字形义为刀锋状。&quot;匄&quot;的形体中的部件&quot;刀&quot;和&quot;亡&quot;为&quot;刀&quot;义的叠加。&quot;散&quot;字的初文作&quot;■&quot;,而&quot;散&quot;为&quot;从■,夕声&quot;的形声字。&quot;刅&quot;字的金文形体中&quot;刀&quot;旁的两短划为血状,即受到创伤者所流出的血。&quot;疌&quot;字的小篆为&quot;从屮、从又、从止&quot;的会意字。&qu","categories":["02_字词句考释"],"year":2011,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2011.03.018","pages":"111-114","volume":"32"},{"id":5020,"author":"朱红","title":"上古汉语第一人称代词“朕”的指称和语用功能考察","abstract":"上古汉语第一人称代词&quot;朕&quot;主要用于殷商、西周汉语中,可以指代任何说话人。殷商汉语中的&quot;朕&quot;只是一个普通的第一人称代词,没有谦敬等语用功能;西周汉语中的&quot;朕&quot;具有了表尊敬义的语用功能。语境在&quot;朕&quot;语用涵义的判断中具有重要作用。西周汉语中的&quot;朕+称谓+名字&quot;模式对战国汉语仍有影响。","categories":["02_字词句考释"],"year":2011,"publication":"渤海大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13831/j.cnki.issn.1672-8254.2011.05.014","pages":"76-78, 124","volume":"33"},{"id":5023,"author":"张玉金","title":"出土战国文献中的“主之谓”","abstract":"出土战国文献中的助词&quot;之&quot;,不但可用于定中之间,也可以用于主谓之间以及主语与介宾之间,其基本功用是充当定语的标志。","categories":["02_字词句考释"],"year":2011,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKhn_7G7GMB5LiZL0Ei4-QBCpMjqtwswN_qZky8rD4PDGTfgyuqeV9HGNpCuYKQ1ZJgE-WS84wC0a0Rxtafqj6LUcvnjzUwQ1v_hJnjLNLjK0A4KMtyTrkGvWOZXd-hY6CvHz1m4UsfcLxgvhqsbcei_MCnixxwiPOs1js9bodgzA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-38","volume":""},{"id":5025,"author":"李学勤","title":"试释翼城大河口鸟形盉铭文","abstract":"山西翼城大河口2002号墓出土的鸟形盉,盖内有长51字的铭文,内容为器主乞关于遵行君命的誓言,表明自己的谋画如系私自策划,不合君命,甘受刑罚。这在西周青铜器铭文中首见,有很重要的研究价值。","categories":["02_字词句考释"],"year":2011,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0db6_o33rqxiWSb2QedopSVR9c5Dcz5MUz0y6t78PKkqVjfX9J5LNXY8DlF_rHPdPN_m-a-ZCq0DZ0--IUoQEI6_YDNHhwlu-dzWNJDU98EszaZbCXC6qLSH2p5nFBgN95Vaqeb8TuG7NJOTVIWRG6TW0Ob4V97Woxsqz18yrXA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46085","volume":""},{"id":5026,"author":"王怀义","title":"释“铸鼎象物”","abstract":"&quot;铸鼎象物&quot;是史前时期中华民族政治宗教观念和审美观念的总结:&quot;在德不在鼎&quot;的观点,反映了史前至战国时期神人关系的变动轨迹;&quot;远方图物&quot;、&quot;铸鼎象物&quot;和&quot;百物而为之备&quot;等,是&quot;物谓鬼神&quot;思想观念的集中体现,反映了铸鼎象物说以原始神话和巫术为基础的思想背景;&quot;禹铸九鼎&quot;是铸鼎象物说提出的神话学背景,这一事件有着极为复杂的社会历史原因,既是史前人类艺术审美观念的集中体现,也在某种程度上影响了中国神话的传承方式。","categories":["02_字词句考释"],"year":2011,"publication":"民族艺术","link":"https://link.cnki.net/doi/10.16564/j.cnki.1003-2568.2011.03.022","pages":"53-58","volume":""},{"id":5034,"author":"樊俊利","title":"新出战国金文考释三则","abstract":"对《商周金文资料通鉴》中著录的三件新出的战国铜器上的未释或误释铭文进行了考释,认为18851号器首字不为&quot;衣&quot;,而是&quot;黾&quot;字;17301号器第三字阙释,我们认为应是&quot;寍&quot;字;17320号器首字,邹芙都先生考释为&quot;玄舍&quot;合文,我们结合战国兵器铭刻制度及字形变异特点,认为应改释为&quot;舒&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"西北大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16152/j.cnki.xdxbsk.2011.04.014","pages":"160-162","volume":"41"},{"id":5035,"author":"李义海","title":"别白行文视点下的(亻賸)匜铭文补释","abstract":"在人物事物称谓中起着区别的作用&quot;别白&quot;性字词,标志着该事物相对于所属事类的特异之处。这些标志性特点,有助于对含有别白成份的词语做出正确的理解。","categories":["02_字词句考释"],"year":2011,"publication":"华东师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16382/j.cnki.1000-5579.2011.04.005","pages":"137-140, 156","volume":"43"},{"id":5036,"author":"王爱民","title":"燕系文字研究综述","abstract":"近三四十年战国文字研究进入空前繁盛时期,很多文字的释读有了定论。对学术界在燕文字研究方面取得的成果,按铜器铭文、兵器铭文、玺印、货币、陶文等不同载体依次作一回顾和总结。","categories":["02_字词句考释"],"year":2011,"publication":"大庆师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwe0Lq0rhssS0DUs0cQ5w3A_RuRutmQVgFmHfT5okKAhZG8k5n3dVM0cT6WSaXcMF0k7a6nknQKc-mXO6DjxQy0aT7jA1hxZWzFstKkORmzxtJveDQF5noOIWEd6jFk7Sk95i1lEZHp_t8ImZ5jetc5lLj-YgoqNsHfx3H9IpOmg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"115-118","volume":"31"},{"id":5037,"author":"刘建峰","title":"论战国阜部字的增土繁化现象","abstract":"《战国古文字典》和《战国文字编》共收录阜部字单字68个、字例461个,《殷周金文集成》收录阜部字单字55个、金文字例372个。从这些单字及字例来看,战国时期阜部叠加义符&quot;土&quot;的现象比较普遍,并呈明显的地域性规律——战国的齐、燕、楚地阜部字均增义符&quot;土&quot;;阜部增土现象始于春秋时的齐地,而有的文字可能易土为石或易土为山。","categories":["02_字词句考释"],"year":2011,"publication":"山东大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJD9Bf0XOoeEVku1x0fzgQXAplzCwdalCuoETY8EkUFaXeKJvqkLoRnjxFOwxUKsKhdQHD5IbhB_INln2ARKhcT67XEmdAEBJlhaSy7D6elQQW6D9YZdhxidWB0AUScXOX5nzloJN3UlZXimgJ8RS1vVUwjC7w6l2wghIuJFyisUg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"147-151","volume":""},{"id":5039,"author":"刘志贤","title":"“公”字字源新说","abstract":"对商周卜辞、周初金文之&quot;公&quot;字进行字形比勘和义素分析,尤其通过图像学比较后发现,商周金文&quot;公&quot;字形构多与阴茎轮廓相吻合,提出&quot;男根说&quot;,并从语源学之形义通道、音义通道,以及文献学、考古学和文化学诸方面进行了广泛的验证。","categories":["02_字词句考释"],"year":2011,"publication":"淮海工学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhmnOTzm3csguiskTFEvLJkLclfaPT2p6sLlBnVweEcKsmbXat0lQUWDJT18Jh84IhPMXmEF_4sOWawhKDN04JwrpVwjsYwO-C0756SPj6cPOlqk5P58JLmeWfzyKcImPS1ouzeuOsThFe4QyNJ8nrflaERdCCYOoElb_UyTVEaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-51","volume":"9"},{"id":5041,"author":"袁俊杰","title":"伯唐父鼎铭通释补证","abstract":"伯唐父鼎铭文,关涉古礼制,内容非常重要。发掘简报只有释文,未作断句与考证[1]。张政娘先生首先断句并作了简要考释[2],此后刘雨[3]、","categories":["02_字词句考释"],"year":2011,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2011.06.004","pages":"38-43","volume":""},{"id":5042,"author":"曹锦炎","title":"彭射铜器铭文补释","abstract":"《文物》2011年第3期报道了河南南阳春秋楚国彭射墓出土的一批有铭铜器,器主为彭子射,简报作了很好的释文[1]。读了之后,觉得2件尊缶","categories":["02_字词句考释"],"year":2011,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2011.06.018","pages":"94-95","volume":""},{"id":5044,"author":"乔雁群","title":"试论传统观念中汉字演进序列的不合理性","abstract":"长久以来,汉字一直被认为是按照甲——金——篆——隶——草、楷、行这样一个直线序列发展演进的。随着汉字出土材料的日益增多和汉字研究的不断加深,传统观念中的这个直线演进序列便逐渐显露出它的不合理性来。本文试举例来就其中某些不合理性进行简要探讨。","categories":["02_字词句考释"],"year":2011,"publication":"贵州大学学报（艺术版）","link":"https://link.cnki.net/doi/10.15958/j.cnki.gdxbysb.2011.02.005","pages":"61-64, 68","volume":"25"},{"id":5045,"author":"袁俊杰","title":"再论柞伯簋与大射礼","abstract":"柞伯簋是考古发现的西周早期重要有铭青铜器,因铭文记录了西周早期柞伯参加周王举行的一次大射礼而受到学界的重视,但各家看法不一,意见分歧较大。本文在已有研究的基础上,对一些关键字句作了新的考释,并对铭文所反映的大射礼及其相关问题进行了探讨,同时对目前条件下可能存有多种解说者,也本着实事求是的态度一并论证,提出了自己的看法。","categories":["02_字词句考释"],"year":2011,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2011.02.003","pages":"134-147","volume":""},{"id":5047,"author":"唐洪志; 白于蓝","title":"金文校读四则","abstract":"在以往研究的基础上,利用传世文献和出土文献对金文中的四段文字加以校释,提出新的解释。","categories":["02_字词句考释"],"year":2011,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYp01vWkLvgBq6d9WRqliEgZVHyMSw35mLtM1JEh3v8-_2ZOTr5N5vSYahnAQkfiTeFDfLj4cc1K7Wq0r24R1hX_h7RY5xVyJG9hyc_o9XIT-V03jqeQnZPdQ6sNZOC-r1H_QsEe3c9c5y2i8mNHmtAFDGzrFcHrV43GgqqFfs1Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-47","volume":""},{"id":5048,"author":"杨秀恩","title":"春秋金文用字研究","abstract":"对春秋金文用字进行全面的整理和研究,集中反映已有的用字资料和用字规律,对全面认识春秋金文的阶段性特征,进而理清汉字字形字用的发展轨迹,为正确描写汉字发展史提供依据有重要意义。春秋金文用字问题表现为字形与表义功能的关系问题,就现有认识,有异写字、异构字、据音借用字、同源通用字和同形字五类。","categories":["02_字词句考释"],"year":2011,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2011.03.013","pages":"19-21, 26","volume":"31"},{"id":5049,"author":"苗利娟","title":"商代金文字频分级的初步研究","abstract":"以2009年底已公开发表的商代金文材料为限,商代金文可归纳出字头1343个,可释单字569字。其中,常用字即出现频率在10次及其以上的单字计203字,次常用字即出现频率在2次及其以上至10次的单字计515字,罕见字即出现频率为1次的单字计625字。&quot;父&quot;的出现频率最高,过千次。&quot;亚&quot;的出现频率仅次于&quot;父&quot;。商代金文高频字中无虚词、动词、数词,全为名词,主要是天干和亲属称谓用字。","categories":["02_字词句考释"],"year":2011,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2011.02.005","pages":"27-31","volume":"32"},{"id":5053,"author":"张卉; 吴毅强","title":"戎生编钟铭文补论","abstract":"北京保利艺术博物馆收藏的戎生编钟,全套共8件,每件均铸有铭文,8件钟的铭文连读成一篇完整的铭文,共153字,其中重文9字,合文1字。这是目前发现的两周成套编钟中仅次于晋侯苏编钟的长铭,其所记史实为史书所缺载,且铭文中有几个新出现的字形,对古文字学、晋国史以及两周历史文化的研究都具有非常重要的价值。到目前为止,已有李学勤、裘锡圭、马承源、王世民等学者在文字考释、史实阐释及断代","categories":["02_字词句考释"],"year":2011,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzUs9zBbSHLLj3QZMzTdpOVB-BqPqfSFzWTOD03u-fpazUrd5qxj81n7542QiRVkgDL3nj_sUtvygo1yBc-XgLwe4CyVF0NN8SzX-lg88NHGGj4rzDJTcSWyuWdrnjCGLtc7r2ZJjJUpggbkYjDulCt_wKk4QjAFuJeVsWxOvOlg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-107","volume":""},{"id":5069,"author":"张富海","title":"毛公鼎铭文补释一则","abstract":"毛公鼎①是西周晚期的重器,其铭文长达将近五百字,不但字数居全部西周青铜器铭文之冠,而且内容也很重要。自从清代道光末年出土以来,毛公鼎铭文历经诸多前贤和当代学者的考释,已能基本通读,但仍留下","categories":["02_字词句考释"],"year":2011,"publication":"中国典籍与文化","link":"https://link.cnki.net/doi/10.16093/j.cnki.ccc.2011.02.024","pages":"152-154","volume":""},{"id":5070,"author":"傅华辰","title":"西周金文形容词的句法功能","abstract":"对西周金文形容词的分布进行了研究,发现西周金文中形容词可以分布在定语、状语、谓语和补语的位置上。西周金文中单音节形容词作定语一般修饰单音节的中心语,双音节形容词一般修饰双音节中心语。单音节形容词作状语一般修饰单音节动词;复音节形容词可以位于句首作状语,也可以位于句中作状语,其语义指向都没有偏离所修饰的成分。西周金文中形容词一般单独作谓语,两个形容词联合作谓语是个别现象。而形容词作补语的只有一例,这说明西周金文中形容词作补语处在萌芽阶段,可以论断西周时期形容词的结构方式发生质变的同时,其语法功能也发生了质变。","categories":["02_字词句考释"],"year":2011,"publication":"宿州学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLyct9YBAr0gT78WddueWiTJMIDGYSpnGIBqbym_eg-u1HZI_AtGruiFRXbbat3b4KpKtP4RbCX8LwkMPYY62az687RacRHYm32OJEhvrHihQ2I6ZJ6TxyvX4oSsbmV4G2ZvWJf1qP8ITNRRS0m8TS5JgmtjOfYu9NDOX6Uf3vDrQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-44","volume":"26"},{"id":5071,"author":"许洪明","title":"青铜器周敦盖铭文解读与探讨","abstract":"西周末期或春秋初期流行过一种青铜器叫&quot;敦&quot;(音队,不读蹲),乃是一种容器,由器和盖两部分组成,器和盖形状相似,既可合二为一,又可一分为二。这种盛放饭食的器皿,是由鼎、簋的形制结合发展而成的。下面介绍的周敦盖铭文就是来自这样的青铜敦的盖子。由于种种原因这件青","categories":["02_字词句考释"],"year":2011,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJbjaQOQ4K7lohOoPw_T-kPcc83P76VQJfyyR__sHrLrYd0wQjOKPLgoSKUU2HQ8EJUnZIFzxh4bk1g793vFVR1jx-lPF8bGwV1Yz7qjwX01QlF8a1DRNyxpcs2C5DI3TRS-1Qi97DrFcmLjR5QVUnFSuAqVpEg-O-h2goxOK3ctA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-49","volume":""},{"id":5073,"author":"麻爱民","title":"逨盘补释","abstract":"逨盘为西周重器,出土后,经李学勤、裘锡圭、王辉、何琳仪等先生深入细致的研究,使得铭文的释读问题得到了比较好的解决,但在某些文字构型的分析和词语的诠释上还存在一些分歧,至今尚无定论。本文就其中&quot;盭和于政&quot;、&quot;明(?)于德&quot;和&quot;幽明厥心&quot;三个词语的训释问题进行补充证明。","categories":["02_字词句考释"],"year":2011,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6mwIHkTeh_GENXX9_UQlifnd7hKALYn_hXpShbhA2vULQJ4BofrXXBFBaGdgKdt1Sr4HYA9HSjS53gn7AN2YtMm26fcYKEjZyPpb48fIxR8jdSwq4dCRIJ1dmBc278p5hYQTKbJthVEoZlu0ZHQxRvwNye7GWv8NPvruqfRHkzA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-26","volume":""},{"id":5077,"author":"李亚楠","title":"两周铜器铭文的语言特色","abstract":"周代的铜器,有铭文的达数千件。随着铭文字数的增加,铭文内容也逐渐丰富起来,长篇铭文大量出现,一些文学手段在尊重史实的前提下被使用于这些记叙历史的文字中。铜器铭文的语言简洁,同时有韵有散、长短相杂,这些都为铜器铭文增加了不少文学性的积极因素。","categories":["02_字词句考释"],"year":2011,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjg8YAC1YK-cWJrg8-D_d7Y1DB368xLWZurWOYk00zDgOrHyPXS2GIIkluk6PY7L5MapjpQ9-SFy3RD4s0xN08tSg4AUMLhlYfHbSZsJ67xBqbXcGZebG3btvpnDOWYVbD7LB_ZAZGGI7zKqQtXBGKw04Y3FYcOCZ49dqDUW0LOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"244-245","volume":""},{"id":5080,"author":"肖娅曼","title":"汉语原初“是”为“是”指代词——对早期金文和《诗·颂》中“是”的研究","abstract":"文章通过全面考察西周春秋金文和《诗经?颂》的&quot;是&quot;,采用统计、替换、对比等方法,通过考察其指代对象,发现原初&quot;是&quot;与其他指代词不同,它是一个&quot;是&quot;指代词,除具有指代性以外,还含有&quot;是非&quot;之&quot;是&quot;义。表现为专门指代神灵、祖先、尊贵者等、即&quot;是者&quot;,不指代卑贱丑恶者、即&quot;非者&quot;;而&quot;兹&quot;&quot;之&quot;&quot;此&quot;&quot;斯&quot;都可指代非者。原初&quot;是&quot;不能被&quot;兹&quot;&","categories":["02_字词句考释"],"year":2011,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLWPZv7kg_8eM0hUZ4I1AP1GdQ6FFO1VWh_XFgoj6NTD1NOz_TOsKwfbxSe6Vy3fdHUKkXAmelDOHbrbbOvh1FgYWCHIB143K25eHuaWOQq0OKK8rua7TPYVprW_SRUxT-Wrt-1z-I36kQr4EV3xxwsYcrDQmvHM-0xSG0326vT_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-51, 96","volume":""},{"id":5083,"author":"毕秀洁","title":"商代金文量词研究","abstract":"文章对商代金文中含有量词的21篇铭文进行系统的研究,总结出朋、具、珏、年、品等5个量词,词序以&quot;名词+数词+量词&quot;为常态。含有量词的铭文绝大多数是赏赐类铭文,赏赐物不仅有贝,还有玉、璋、积等。","categories":["02_字词句考释"],"year":2011,"publication":"中国海洋大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfENf5ToVp2xAfRgRV_gQA7VRU4hmWyxWvGXhgUpANlhmNPTLlUt6yj2cDMsYEPu1BokhRVdv7QGJcerIPRdgtELjDCA6gJsV8FUcDQG6iI5uJrZFWQmYzha_DiHvxoBTDnXIZf03nihXcSlkXYL5DV7VimSZl6IqZijnm3V8IcQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-113","volume":""},{"id":5085,"author":"李义海","title":"西周长铭金文事物别白初探","abstract":"缘于对&quot;名&quot;的十分重视,&quot;别白&quot;成为言语交际中常见的一种修辞现象。汉语早期出土文献别白修辞主要有人物别白与事物别白两类。而事物别白主要有明确所属、明确所处、明确种类、明确功用、明确来源等几类。","categories":["02_字词句考释"],"year":2011,"publication":"陕西师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIN2kNk6G7HyBkxhRtA5171LfZJrlF1uOe2cqOu2K84tf2BHUTzkK3gi2ljeP7HhRBrIY-s18DX5hMlaIYlgIlmN8v4q4KNmU_JBhZnbcRd19mtifAHhmPKZct_VDYvY6_Y2ff7VUy188ejwwQnF8do4NL5WB0bUnsOcvMU65Ll9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-133","volume":"40"},{"id":5086,"author":"王圣奎; 寇占民","title":"西周金文复音动词判定标准说略","abstract":"西周金文是探索汉语复音词起源的最可靠语料,西周金文中复音词的判定标准的确定是进行复音词研究的前提,而对西周金文中复音动词的判定标准的研究则具有典型意义,西周金文中复音动词的判定标准的研究对确定西周金文中复音词的判定标准有着重要的支撑作用。西周金文中复音动词的判定主要坚持意义和形式两条标准,其中应以意义标准为核心,意义判定标准具体包括同义复音动词、偏义复音动词和变义复音动词三个方面。","categories":["02_字词句考释"],"year":2011,"publication":"学术交流","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWL1WBCw4SV_lAibVwHXeUPwaodB3Sp6iSXSOj-xbyJ7yaLGYP7q_BVU32TL0laJsUvyEZrZjL5m6tlhL41HlT3-Y77DOKNxYdTkibU_vs3cVpnd9-fwXRP48zUzpnEfd_saXjMeUgJcvgO6WJM5utL7-RAM4lypuVwB2l28IvlQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"161-165","volume":""},{"id":5088,"author":"洪飏","title":"簋铭文释读及相关问题","abstract":"&quot;(无可)簋&quot;铭文的&quot;■公休&quot;,或可读为&quot;扬公休&quot;,这种释读涉及上古音鱼部字与月部字的相通,鱼月相通属于&quot;例外音变&quot;。文章试图利用文字学和音韵学成果对此种现象进行解释。","categories":["02_字词句考释"],"year":2011,"publication":"社会科学战线","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYFUS18TPqLkeK_z8K_ASGzg5xU2M7ArcJmSiHL9uwc0YBCipQElO-WK26NT5ySS2Y7JUwqZnr7rA1rnBZ9NjZ-2JzJnpA_YMm9YJlqLl9HNq3j74nlmtVaZtK-HkazWLEBIHsmthYRj12Tru1DGbehfR9gj_RqpX_1QI9wsAqEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"242-244","volume":""},{"id":5091,"author":"袁俊杰","title":"作册般铜鼋铭文新释补论","abstract":"&quot;王射&quot;,与&quot;获&quot;、&quot;贯射四&quot;、&quot;无废矢&quot;一样,在当时都是记录射礼的专门术语或固定句式,也是射礼文辞有别于田猎文辞的显著标识;铜鼋既是铭功的庸器、展示商王射艺的实物模型,也是颂扬商王射技武功的纪念物,三者并不矛盾;铭文记载了同一日王所举行的弋射和射鼋两种射礼;当时可能是把鼋悬挂在两个立柱之间作箭靶的,这说明商周时代的射礼曾经历了一个从田猎竞射到射牲、再到射侯的发展历程,而铜鼋所反映的正是由实射动物到射侯的过渡形态。","categories":["02_字词句考释"],"year":2011,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLisWWRYWiwIL6K6rAh0aitmVsX0NUf4-0dC9eoTVRBkxT5e_nLnF1cCelCzd-T9i8-R0Biuyjtk3C2YvOasnzcXV7nyNzwYyVfJQ4ZvvUkvvCBwGozclZrjI-AdUleHhzccr-zE-ZV0XPbE42W9gwf82lAcuNQLD-peQr0w_FPXQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-52","volume":""},{"id":5094,"author":"黄国辉","title":"新见■簋再议","abstract":"《文物》2009年第2期刊载了张光裕《■簋铭文与西周史事新证》一文,作者对&quot;■簋&quot;铭文做了精彩的考释,并指出了这一器物的重要价值,读后颇受启迪。然笔者以为,&quot;■簋&quot;铭文的考察尚有略可补充之处。","categories":["02_字词句考释"],"year":2011,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvTZK1-_de8Rq_RE_5CRbSYywDPcAG6-babXsCIY7rgPfbtbFTRR1Ob5GhGISEPTaqNoHB4p7_cqJ1hzH_tVFZOAD3g54omosQFkYtBC449W90zZzhHScBdBvDIMgp4nlTwiAM-mB1R-snBqFBmpg8GJjRCr9t1Ce2BKHH7vNbyg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-106","volume":""},{"id":5096,"author":"刘明","title":"试论古文字形体的演变","abstract":"作为内容极为丰富,历史非常悠久的古文字,在几千年的发展过程中随着书写工具和使用范围的扩大,其形体不断的发生变化,为了更好的了解古文字,本文试图通过对古文字的发展变化过程、古文字的演变特点来研究古汉字形体变化对当今文字改革的意义。","categories":["02_字词句考释"],"year":2011,"publication":"辽宁工业大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyZ8oE7L2Vm_F0xPiBwA3KdXoJ1-IcGvcLiUxFkQIb7fHlVgfkpbXxY4gubXLLju6UVmcztARwu02NuqeWFaBZPuGnC9cATW89IjSLZX_Bhtks7t2bqvZaNVQJfYdwJIvORJtTVX_RNTodUlfcw5PkyHAYJbpDB6ok-tIKic0-7g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-51","volume":"13"},{"id":5098,"author":"陈文敏","title":"转注:古汉字创造的简化法——兼谈转注不明的历史原因","abstract":"&quot;转注&quot;成为千古之谜的主要原因,在于其文字对象甲骨金文在周代以后就沉入了历史的汪洋大海。1899年殷墟甲骨文大量出土后,近百年来先贤对甲骨金文的大量&quot;识字&quot;和&quot;分类&quot;成果为破解转注之谜奠定了坚实的基础。转注实即甲骨金文中最常见的&quot;把象形字简化为一系列符号,形成简化链条&quot;的造字方法。转注的重要目的,在于给本音转注字注入新音、使之产生引申义成为注音转注字,从而表达华夏初史中此事物与彼事物之间的密切关系。","categories":["02_字词句考释"],"year":2011,"publication":"理论导刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKiUlaGfCH93PkF8DhJjv48WLBMoYqa_UyjwqLKE40YWXqi035VZx1L2nImJps-BVSq-Y5gGDGJTxL89gR74rC64gsBctn9kgsKDt5bWhBc1rRNYf0xhyI5iQRQKh5jWup0yHQXAuxoLlebKbrfJH50stF1b5jfhSStxmUtXi5jUQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108-109","volume":""},{"id":5102,"author":"武振玉","title":"两周金文第一人称代词述论","abstract":"两周金文中的第一人称代词有&quot;朕、余、我、■、辝(台)&quot;。就出现频率看,前三词为高频词,后二词出现频率很低;就句法功能看,&quot;朕、我、■、台&quot;以充当定语为主,&quot;余&quot;以充当主语为主;出现时间上,&quot;朕&quot;主要见于西周中期和晚期,&quot;余、我&quot;主要见于西周晚期和春秋时期,&quot;■、台&quot;只见于东周时期。","categories":["02_字词句考释"],"year":2011,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDgrFKWpZxRo7AKZK7XiZT5YqSE5WNr894h00OK83pT28G0-TMEHKx5IunGWewKxbwY5gJiYtgo0JsY_5JVObS98XQpHhlZ9bd0sLQ8nZKtuwZU6ON0bNjCpxvWwZLUycc82jJewHXYmJqgr1V-Fc3L1H2cCO5CBNEXgb9A0sWsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":""},{"id":5107,"author":"寇占民; 曲殿宇","title":"西周金文动词用字例释","abstract":"上古汉语中词义的演变往往表现在文字上的假借和分化,西周金文动词字与词的关系可分为三种:假借关系、同源关系和异体关系。对西周金文动词用字中孳乳和分化现象的考索,既是对西周语言中字与词关系梳理的重要组成部分,也是对上古汉语动词词义演变脉络的必要补充。","categories":["02_字词句考释"],"year":2011,"publication":"齐齐哈尔大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13971/j.cnki.cn23-1435/c.2011.01.012","pages":"30-33","volume":""},{"id":5109,"author":"罗小华","title":"释尊","abstract":"包山楚简遣策部分255、256中有一个字共出现五次。此字上部从&quot;网&quot;、中部从&quot;日&quot;、下部从&quot;廾&quot;。学者们对此字的隶定基本一致。然而,对于此字的释读却存在着不同的意见。我们认为此字与郭店楚简《唐虞之道》简7中一个&quot;尊&quot;字形体吻合,因此将此字释为&quot;尊&quot;。可能是一种器物的名称。","categories":["02_字词句考释"],"year":2011,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgYlI6OUGvFGlDYQDAe-lrUzCwKqioi1PpCXLg-GtIYFz_37UgZW5B4-aRpfgOjTOYfFyuA88ezLVgupY-kMOQqSbZ7Oz5JlT99ty6oHCbolDYOzxDE0dtyOxTusRmm4p1inSrUZ6kO32P11KuSGue21sjTpbLa7646efpvHnA0g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-119","volume":""},{"id":6331,"author":"陈丽; 陈鸿","title":"出土秦系文献形声字研究","abstract":"近數十年來秦系文字材料不断出土,随著雲萝睡虎地秦簡、霎萝龍崗秦簡等的出土和文字材料的公布,學壇掀起了研究秦系文字的熱潮,秦系文字的研究進入了新纪元。秦系文字具有的文字材料罘多、内容豐富、匾域性特征明顯等特點,成為許多學者關注的焦點,具有一定的學術研究價值。本文立足于出土秦系文献材料,封出土秦系文献中的形聲字造行分析、探究。共五章,分述如下：論述。主要說明本文的研究動機、研究材料及研究方法。第一章,形聲辨析。分別條列各家的形聲分颊,對形聲問题加以探討,并說明本文形聲判断方法,試圖使形聲定義更加清晰明了。第二章,文献材料形聲字研究现状。分别阐述甲骨文、金文、戰國文字形聲字研究现状,包括主要研究方向","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2cNH-y1kWUN2LDhFlWsqJCanb7E9hs66un6QTejKISRYzurMtmHnyj9PTvcdLuBv4aON_YeWzanGxTXXKsNhZYKBIRrcIv3bxPGYGUZg_XJfljUc-jCRN71gVTMruXHpEk9GCwpGM3o16NENq9LiRkNX9sp8YqO85GuIbQ4NamjGttF1PThT1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6333,"author":"张海燕; 刘乐贤","title":"《诅楚文》补论","abstract":"《诅楚文》是战国时期秦国声讨楚王熊相,并祈求神灵保佑秦国战胜楚师的刻石文字。共有三篇,内容相同,惟所祭神名有异,分别为《祀大沈厥湫文》、《祀巫咸神文》与《祀亚驼文》。《诅楚文》出土日久,研究成果亦丰。然其中尚有未能尽解之问题,故作此文以为补苴。本文共分五章。第一章,近几年主要研究成果述评。张翀先生通过对《诅楚文》版本问题的研究,指出《诅楚文》为真,但《金石索》本更接近《诅楚文》原貌。有关“三神”及其地望,史党社、田静及吕静等先生研究认为巫咸神是随着商人势力的扩大和文化交流而逐渐被神化的,而裘锡圭与雍际春二位先生则研究认为亚驼神地望当在今甘肃正宁县境内。对于《诅楚文》与《吕相绝秦书》存在相似语句","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCEhJVnxL07cO7LdgSHxWHH6zovZrBg2x-MPewZZSfq2Kt9yaGmIp7rvAAzEz6BhV4fdmRu8G1despGstFXvWC4CADgGZJMSjvxC8u0tj6HQyFcLvSFC8xs_NbC6lvXvVlnHgaUioGE3VXauAfMsxUIKsE-55tK4LjoTLNGc1pbJGSU1LJJ8L5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6334,"author":"刘思媛; 黄亚平","title":"商周图形文字构形研究","abstract":"商周青铜器上铸有一种象形性极强且相对独立的特殊铭文,我们称之为图形文字。这些大量出现的图形文字的性质基本被认定为标识族氏名称的族徽,是研究上古国族、地名的重要补充资料,但一直以来因其表现形式孤立、定性不明,大部分音义不具备又缺乏辅证,学术界对其争议较多,关于图形文字的性质和作用等问题一直是文字学界和考古学界关注的热点话题。图形文字的研究历史已有上千年,其间在图形文字的释义、定性等方面取得了不少学术成果,尤其是近几十年随着大量新考古材料的出土,对图形文字的研究不断获得新的进展。本文是在前人研究的基础上,以宏观理解图形文字性质和特点为前提,从微观层面深入图形文字本体进行构形分析。本文主要内容是对图","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHRjzizbKUx-sAuRYeiM9zsKh1weF_CsOLQWMxRsCY7y5yytB_Sy5184kUTQA86NMvVR5EslJSM-HyvfEyhU_Z9uiiDK9G5n4QGebkoHMM-7E5tlqywdppP0MfkXR-I3BaNLqID00JY85BoLA0HqjBUg-sGkUUBmCF7dBXe7nkUlkmUrL2X9fs&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6336,"author":"史富红; 林志强","title":"战国文字宀部字研究","abstract":"前贤对于战国文字的总体情况以及宀部字的个别字有遇深入透彻的研究,也产生了一些相关的论文,但是还没有系统的专著。本文从文字学角度分析战国文字中宀部字的整体发展脉络,造而总结戟国文字中存在的独特文字现象、分析宀部字中与义符相关的问题、对宀部字的发展规律进行探讨。因此,本文在总结前人研究成果的基础上,首先结合目前几本权威的古文字工具书,封宀部字造行了一番梳理,将甲骨文、金文、战国文字的形体造行详细的封比与就明,统计出了宀部字在古文字阶段的存在状况,尤其注意宀部字在战国阶段的情况。在共时层面将宀部字在结构上造行分类,并且对每个宀部字造行逐一分析,分析其在古文字阶段的形体演变关系,尤其注意宀部字在战国时","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRoqnDCfj6LGMUaek6hjxZTFCbX_cDHiK283f8DS_KDF7L6u5VglPZTFpwpYVj1d3L3HSSuAZOJbISXvy1j-g8Sdbg4ZaCF9HxFLU4F8uC4S1tz3sYJbeCFwW-yP14nIi56hLmT6Z_FOrbzaZuLqJr_rC5AwVy6-Gj3AgcR-qWQfPHu8qkKqza&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6339,"author":"石继承","title":"加拿大苏氏藏秦戈铭文补释","abstract":"《中国历史文物》2009年2期刊载的梁云先生《秦戈铭文考释》一文,公布了加拿大苏氏所藏的一件具铭秦戈,并对戈铭内容进行了探讨。本文是对此戈铭文的补充讨论,认为戈上所刻置用地名应当改释为&quot;沙羡&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKSqO47OtYCC4wGU7BoYkve8I2MGiyg4TpMACF_y7MsCsc5FT6sgllMA2JTw3SfEq7PAT5r5TUin-zDvf33QIZRnrYjkVGsce8B7g22vdim-KjCXHnkGPFvj5mgoXNqrurxcJGLvpU8OyrrBYnzAai-ZAPZWmsh6FKrZeQohRK5ig==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46370","volume":""},{"id":6341,"author":"劉秋瑞; 黄德宽","title":"河南所出战国文字辑考","abstract":"自20世紀初中国开始有了以发掘为基礎的近代考古以来,特别是新中国建立以来,在考古发掘中,河南地区出土的戰国文字材料数量多、品类齊全。系统梳理這些材料,封研究河南地區的历史文化有重要的学術价值。本文盡可能全面搜集這些文字材料,並對這些材料做了綜合分析研究。論文分爲上、下雨编。上编按戰國文字分域研究的五系說進行分系封論,共六章。分别封河南地匾出土的晉系、楚系、秦系、齊系、燕系文字從銘文内容、器物形制、涉及的歷史文化信息等方面作綜合研究。緒論部分主要描述了今河南地區在戰國峙期的状熊,介绍了河南地匾戟國文字的研究现狀,闡明選题的意羲和研究價值。在晉系文字研究中,本文封河南地區出土的韓、趟、魏、中山、束","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLAEEuCBTiep98PQxtJocqE0J-eu4EuKH_ZQKIH6lKEaWR3r-zSCbngLd7ecokC6mjgAMt7AkECZ7EBrPRFe-NXcKnOf99TmhXSCK7D_CoK5hqyVmd7N6Wa2sbhVMylbm-5nvwFXexBKAbOJ5jTbR2mA4JnN3RK8qDx0pvTz9OxIDH9BFE_AP1l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6348,"author":"吴劲松; 胡长春","title":"近十年新出殷周青铜器铭文的整理舆研究","abstract":"商周金文是中国古文字演燮史中的一個重要發展階段，其時代自早商晚期一直延續到戰国晚期,歷時一千二百年以上,後则能與秦漢金文,尤其是隸楷化以後的漢金文相街。這些材料封研究中國文字發展,研究上古音以及歷史文献学的研究都有重大意義。青铜器铭文本身也具有的重要的史料價值。本文主要针封21世纪以来已经完整公怖的出土的有铭青铜器资料進行综合整理,共收七百四十七器,著力於全面的搜集原始材料,在各批资料整理者最初發表的释文文本以及随後褚家考释、订正的基礎上,對識字、断句、考释各個環節重加審視,在最大程度上订正错訛、完善文本、解決相關问题。","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ2EPWMKHyAdub4jAPsspWryy9gbXQvHPP659wUex_0sfplviGvi7jKkE5BI1oK74Rk_DUpT07SbXH9DjUXxYg-m5FtwK-JnraHq1Bj3V7687wDgdSf_Kl1955R3mqa-lrEebl1kqi_XOEmcKtUjanij1HXImGDdnJWuNd3MnPCHVhk_w5fdORi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6349,"author":"司燕飞; 陈建中（大中）","title":"商及西周早期金文的形式分析","abstract":"金文最早产生于商代早期,这个时期的铭文相对较少,但字形活泼生动,极富天趣;至西周早期,其金文亦较多地保留了商代金文的特点,字形各尽其态,潇洒自如;金文发展至西周中后期达到了鼎盛时期,此时的特点为铭文较长,布局趋于秩序化,规范化,后人多取法。然而笔者认为,在金文的整个发展过程中,正是它的早期形态而非鼎盛时期所具有着天真烂漫、无拘无束、错落奇崛的构成特质,具有着更高的艺术价值,当然不排除其中也有粗糙潦草之作。正是由于这个时期先人还没有形成一定的规范性和秩序感,多随字形大小排列,一任自然,很少有整齐划一的感觉,反而使得字形活泼生动,朴茂自然,一派天机。本文即以此为出发点,运用形式构成的基本原则,着重","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJl7_JRRj6v0RI6LJt_2rWVxGdBVo0tmNgbrGp21IcRPNtl9CGMZ_d_aEK0Vy9Ic_B2iXqpsdCQ_iB3GXMy92jqTp3dsch79AiIq5QsQBhyVhl4mf33nZMsc3yYR0re8eyhKHurXjb-0HLcOdaL2IeZx6TJeOV4K7YFUuK5KZ3JkbUR9cr1nMMd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6352,"author":"侯凯华; 甘露","title":"古文字中从金之字研究","abstract":"作為一種具有表意特點的文字,漢字在其形義之間、音義之間,以及意義變異的聯繫中,常常折射出社會生活的某種文化信息。《說文解字·金部》收字197個,是其540部中收字最多的十大部首之一。从金之字從產生到現在,經歷了漫長的年代,積澱了厚重的古代文化，是漢字發展史中重要的一部分。金屬工具的問世,為人類社會生產工具的應用帶來了翻天覆地的革命，標誌著社會文明進程進入了一個嶄新的時代,由此可見,金屬與先民文化的關係是多麼密切。金部字在古代文化中屬於一個大類,它所反映出的文化蘊含是我們值得研究的一個課題。本文以古文字中从金之字作為研究對象，對其意義類別、形體和意義演變及其所蘊含的文化信息進行研究。本文分為五章","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_1ikx_CK3SR3JGDlpnQIfrE4NCwxb8Y1o1vJJ9HP8sUzaJ26f-RQ209zBpiJS49tqMvbe3q8_HjBbKswIbj3TGTNV9ueLWmLVI7vUohUGzL2GnGgod_RZqhaOHkn0EkcZlS2S2rqWmdB4XfPb3w7BIhn3d0s9I9haR9eZxYuBFZKiAuLe_GIa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6353,"author":"徐新亮; 江学旺","title":"春秋战国金文用韻考","abstract":"本文是以春秋戰國金文為研究對象，以韻文韻例、韻譜、韻部、入韻字聲調四個方面為主要內容，對春秋戰國金文用韻現象所作的初步考查。本文共分五個部份:緒論,概述了金文用韻研究現狀、研究意義、研究內容及本文的研究對象、方法及意義。第一章,對春秋戰國金文的韻例進行分析,主要包括四個方面的內容：一是指韻在句中的位置,得出以句尾韻為主，存在倒數第二字入韻。二是歸納韻在韻段中的押韻方式,分為一韻到底、一般換韻、交韻、抱韻幾種類型。三是論述密韻疏韻及合韻。四是比較春秋戰國金文與《詩經》韻文押韻方式,得出兩者押韻的方式基本相同。第二章,對春秋戰國金文的韻譜進行整理,包括陰聲韻、陽聲韻、入聲韻,共計21個韻部。包括春","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_1ikx_CK3SR3JGDlpnQIfrE4NCwxb8Y1o1vJJ9HP8sZSLBmghu3kmz47aTICFbhWnQ6pf06YSqAfefBnE53nOlOn3yXUfTKbjNtsnaZEw5fblm4DMKSLyzkus4HgVgyAwhAePTLyQqtNCM22s9zJXaN3UbQ5tSHPsFMjkwZBJ-nMBd6SJ2t7E&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6357,"author":"刘伟乾; 张德劭","title":"古文字构件朝向研究","abstract":"纵观汉字形体的演变过程,汉字形体的重大变化都基本上发生在古文字阶段。构件朝向不定是古文字基本属性之一,我们要全面地认识汉字,了解汉字发展规律,就无法回避古汉字构件的朝向。通过对古文字构件朝向的特征及其发展演变的研究,能够体现出古文字的构形方式,从而把握古文字形体构件的内在规律与机制,这不仅有助于我们理清古文字产生发展的脉络,更能为古文字形体演变特点的深入探讨提供佐证,为古文字的研究做好基础性工作。本文首先对前人在古文字构形学、古文字构件系统、古文字构件位置与朝向等相关领域的研究进行了梳理概述。然后尝试界定古文字构件朝向的概念,并对研究材料的选定,研究方法及操作原则进行论述。接着,利用计算机数据","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJu3RyzYg0LeJOfWhUgMjA5HcYE_MR8WR3oiW6j4M5ioN4lW2sTOBkrmKRzECPysRRf3lkTA1ZRDsFsmnbPdZuKD6RbH4-7vcWOG4IoJqz6IlEElc5-LUoxynRki2sj3tfPpqRrt_pyzhIljBXz8bK07BoYLNnD1jtEgBsvpghGfmcBXJ8kQr09&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6361,"author":"于胜玥; 刘志基","title":"基於《战国文字编》的战国文字地域特徵研究","abstract":"自許慎在《説文解字·敍》中提出“文字異形”之説,戰國文字的地域特徵就成爲了戰國文字研究領域頗受關注的問題。建國以來,戰國文字材料的大量出土為我们全面研究戰國文字提供了可能，湧现了許多對戰國文字地域特徵進行研究的成果,而同時也有一些學者對戰國時期“文字異形”的结输提出了質疑的意見。我們利用《戰國文字編》作為材料,對戰國時期各地域的文字字形進行全面的橫向考察和分析,力求從中發現戰國時期“文字異形”的真實狀況。《戰國文字編》是戰图文字研究的重要階段性成果,收錄了戰國時期的金文、璽印、陶文、封泥、货幣、兵器、竹簡以及帛書等大量文字材料,涵盖了秦系、楚系、晉系、齊系和燕系文字五個地域文字字形,所取得的成","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6SKwL1ldsLsE0IKJe2q2Pm9Sw17By2zEGUr_AwjuU4cAQie3lwwhUOh8CqKO9JmmFLAAFiqdEBR90JUbRS7JiTzGTN-Da7lrW67-bOgPOD-dtzkpXIYsfd-4pv49lDyMVWiUAQc4ow7sVI4BdLSRD1QiGLrpDhV-jzZTTBh0ofhbTcUX0ag3J&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6364,"author":"毛静; 张显成","title":"汉墓遣策校注","abstract":"遣策,是记载随葬物品的清单,是舆墓葬年代大致同步的一种特殊文献。遣策上所记的物品,都是富时的人们在日常生活中常使用的一些器物。每种器物都是建立在当时的社舍风俗、礼仪制度、以及生产力发展水平的基础之上的,因此,封汉墓遣策的研究有助于我们对汉代常时的社舍风俗,文化、制度等的认识。本文封所有汉墓遣策造行通篇校注,有助于人们封遣策中的名物进行整体把握,从而更好地瞭解汉代人的生活状沉。本文把客观静態的描寫方法和比较分析法相结合,如寅地摘錄遣策原文,并舆原图版相封比,做到尊重原筒。在封遣策释文进行校注时,当遇到较有争议的字或词,查阅一些舆之相關的害籍或文章,比较各家说法的可取性,儘量做到接近原筒文意思。全","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpstwayKwKZH2VzUUY3BzvAulTxfw6QcF5J0ZElOd8D9dALnGtI7m5DtPKQBrgT-28seOlPIu4TCUSzaeb333U5Mpa9V-H5nNnYDy2Wtjnhs369zHKwBmkC7frP3MaPpoNQDk5xzmfAUHvRI9wHqMlmgj8-73b-dHUAAYl4S3Nq--S_34K_AsN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6365,"author":"步连增; 冯春田","title":"语言类型学视野下的汉语量词研究","abstract":"量词是现代汉语词类划分中确立较晚的一类词,直到20世纪50年代才被单独列为一个词类。量词确立的过程反映了中国语言学摆脱西方语法体系束缚的种种艰辛历程。从语言类型学角度来讲,量词是名词分类系统之一种,但需注意的是：这里的量词只限于通常意义上的“个体量词”。它和度量词、容器量词、集合量词、临时量词之间存在着诸多显著的差异。鉴于这些差异和精力所限,本文将量词研究的范围进一步框定为语言类型学范畴内的名量词,即俗称的“个体量词”,尽力排除度量词、容器量词、集合量词、临时量词及逻辑意义上的量词的干扰。纵观量词的研究现状,我们发现有关量词的研究越来越受到中外语言学界的重视,特别是近些年来,量词的类型学研究逐","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJkFt_u2Vmh3VXnzupFwt4csGiYMSodr87H-GUyeG2jSTi2S_Hj0LpXL5Yzb87sB0Xkp_aw9nXrGNpOdWf7Gp5Eb_k1gOtu5h-YXrJKynoFBU3KRgJNSn8TWmvRmvAZNrEMziwPo77uqqU0kgITdzSCyO9GuTpQYUe-khMSpCrjQMhJfcM6tF5V&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6367,"author":"韩荣蓉; 李冬鸽","title":"《金文大字典》隶定研究","abstract":"随着铜器铭文出土的增多以及金文研究的日益深入,金文隶定研究经历了新字不断被认识,误释不断被改正的过程。然而,目前对金文的隶定仍存有较大的随意性,同一个字,隶定出的字形不一。究其原因,是由于金文隶定的原则和方法各不相同,这就导致了同时期或不同期文献中隶定文字的出入。因此,找出金文的隶定原则,归纳整理其科学之处,对隶定工作的进一步开展大有裨益。本文选取《金文大字典》为研究对象,《金文大字典》是金文隶定研究重要的参考资料。由戴家祥担任主编,全书共收可释字2661个,分隶258部。部首及部内字头均按笔划顺序排列,字例包括金文字头、器名及句子铭文等内容。该书所据资料详实,内容涵盖了《三代金文文存》、《两","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKlIqfvryf96VSYUOK0iNvobXuteMKSZCO31YCk3wE9gLHM3Xdiv8F0VebIWszMi0krl1__bbxSpfnT0jbm58NSzOihGGCaPxgFKvZngDATnJtW1G0_5TQOUKbYpszTfQMGBxpQvp-kokLC8k0NSN9ks_70mNoYofoVfQMvgGoYqhEvShV9KPDl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6368,"author":"张文峰; 李海英","title":"《两周金文辞大系》训诂研究","abstract":"郭沫若是现代著名古文字学家,他在甲骨文、金文、石鼓文等古文字研究领域成果丰硕、成就斐然,与罗振玉、王国维、董作宾并称为“甲骨四堂”。然而其在金文方面的研究却有着划时代的意义,主要体现在《两周金文辞大系》一书中。台湾学者江淑惠说“金文学的内容可以说是由他建立起来的”。《两周金文辞大系》不仅创立了《彝器形象学》,在金文考释、训诂方面更是硕果累累。郭氏在书中释读了大量铭文,他所考释出的金文文字,很多已为后世学者承认,并被《汉语大字典》等权威工具书所引用。他在书中所采用的考释方法,种类丰富、形式多样,为后人研究金文学、训诂学提供了很好的范例,值得继承和发扬。郭氏深厚的考据功夫,是建立在他对《说文》深刻","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINjSzIAGBGvNQqIA8KVGOQIzHQQvjiOpaWZxZ8EK6nawbcYIR2iRtPk0x9kwmw6hz0nguOKIwn8MPkZfpNhhFUhf28LbIIUtjou8g_55FVa5e-VFCmuOKIE81zMcv34HseOKE69QqiPS1hUF6803sxDGAyOOHgUL7LwlQVWywANsmUNaIT_Otk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6374,"author":"毕秀洁; 董莲池","title":"商代銅器銘文的整理與研究","abstract":"本论文是对商代金文的整理与研究。通遇对商代金文的已有研究成果造行详尽的梳理,在封商代有铭铜器全面搜集、整理及封商代金文通盘把握的基础上,提出在探索汉字的早期形态上,商代金文有著优于商代甲骨文的重要价值。论文探究了商代金文的文字构形特点,指出铭文的方向性随意和形体的对称是商代金文构形最大的特点,在释读商代金文时,应充分考虑到辞例的重要性,验之于辞例；徒商代金文的文字构造看,象形、指事、会意、形声这四书在作为汉字源头的商代金文中都已出现,商代金文中的绝大多字都能够用六书理论来解释；铭文行款对受布局、书写空间等因素影响的部份商代金文文字内部结构临时发生变化而产生的变体有一定的作用,这是商代金文的又一","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKS0vIkpZKHC4mWIK3s7UF3yFHd7uOXmU0zBj2GOixrdA4CI0NyDM-t13fZUKnh1IL7CETyp7n1UganY-VRW9AqQv-XpPHurKdD77Ld-ykP4YyUI39s25VtFvnKW8RkCjoioVKFICSKJzCYiQdgv3fZm1Zpkm-r30a8PDTBbugMPYYuIIE4ym11&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6375,"author":"郭爱玲; 洪飏","title":"通假方法与古文献考证","abstract":"有清一代,是小学的辉煌时期,上古音研究取得了重大突破,成绩斐然。古音学上的成果为训诂学研究提供了重要的条件,加速了清代训诂学的繁荣。“因声求义”理论在这一学术背景下被正式提出来并被广泛地应用到训诂实践中,其中乾嘉学者戴震、段玉裁、王念孙及王引之等是最杰出的代表,他们不仅是训诂学大家,而且在上古音研究上也取得了突出的成就。他们把自己的音韵学成果运用到训诂实践中,以古音求古义,突破汉字形体的限制,破获了一大批通假字,解决了许多前人无法解决的问题,取得了惊人的成绩。他们的代表作《方言疏证》、《说文解字注》、《读书杂志》和《经义述闻》都是运用通假方法考证古文献的经典著作,书中考证通假的成功例子俯拾即是","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpkxxJE2x0nKS3JsmrcjUd-TLtYxla1pxQgvHVkOnpr4q56h4HW24htWdBr-QhyJaMB3SZP9LAxwlVaMmrJpCDpj11gwG4WxI0rBFRJWWb9HAxUO5Sw4F1yo9hzHpcnO3TogBsdawQED8CZ8bbDq9-ggFS8CXyMhPnS7wJrOI-Ug_EPrH_mw0_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6376,"author":"李亚楠; 夏先培","title":"两周铜器铭文的文学观照","abstract":"两周铜器铭文,到目前为止已集数千件,铭辞最长的近五百字,内容广泛,涉及两周社会政治生活的各个方面,是我国历史文化的宝贵遗产。这些遗产的文化价值,已更多的学者所认同,因此,有关铜器铭文的研究也受到了越来越多重视,但是文学范畴的铭文研究依然薄弱。具体而言,论文分为四个部分:第一部分,首先根据铜器铭文中描述的主要内容对铭文划分为祭祀典礼类、册命赏赐类、颂扬先祖类、征伐记功类和约记律令类五大类别。然后分析铭文的文学价值:叙事性增强;不断追求语言美;初具文章的社会功能;真实地体现了周代社会文化生活。第二部分,是对两周铜器铭文的叙事特色进行分析。铜器铭文的叙事较之甲骨卜辞有了明显的变化,有些铭文已经可以看","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKqMqCK_ef5ct6dUlAf7CjODX6oOeI2El73HbGrBKpE2Oh_502m_cThxnAtURMAVkvcZLoZc-WOG5UpYXEj57Pm73CPDz9oYt5TRnVF_te517N0XyNxVtb4ZZKIdruscvpx9jEmISyHmSvj7brJEIpcMdhEaeIJ74vjIL3L-IAyOp_S2zBX08l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6377,"author":"何珊; 江学旺","title":"西周金文韻讀研究","abstract":"本文以西周有韻的銘文為研究對象，分析銘文韻例,歸納該時期韻、調特點。論文包含緒論、西周金文韻例、西周金文韻調分析、西周金文韻譜、結語、附錄六個部份。緒論簡要介紹了金文韻讀的研究概況以及本文的研究對象、方法和意義。第一章歸納西周金文韻文的韻例。從韻在句中的位置來看，韻文大多是句尾韻;從一篇韻文中韻字的相互距離來看，韻文大多是句句押韻、隔句押韻的密韻例,也有一些相隔兩句以上押韻的疏韻例。從韻文所用韻數來看，有的一韻到底,有的多至一文七韻。換韻形式已出現較為規則的交韻、抱韻。第二章歸納西周金文韻文的韻部,考察入韻字聲調。西周金文韻文共出現韻部28部,其中陰聲韻9部、陽聲韻9部、入聲韻10部,較多合韻","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKqMqCK_ef5ct6dUlAf7CjODX6oOeI2El73HbGrBKpEwzP04Bc184l8OilgmkZCDZsoz5FQY0vbZJGSo1x8od99shLR61eAoYq1S28iEQe5L2fEJGI2mOg6PZPODfZC5k64aTq0JtaqEe0qJuQGcmg1_1qBQVEz7ShYq7KDE6d5WJQgEs70iPv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6379,"author":"张艳辉; 吴良宝","title":"洛阳金村古墓出土器铭集释","abstract":"1928年，在今河南省洛陽市孟津縣平樂鎮金村(即汉魏洛阳城东北角)發現了一處東周時期的墓葬群，造就是聞名於世的洛陽進村古墓。墓襄出土了一大批精美文物，其中部分器物上有銘文，因此引起學術界普遍關注。本文已確定有銘器物约70多件。關於金村出土器物專著有懷履光的《洛陽故城古墓考》和梅原末治的《洛陽金村古墓聚英》二書。研究文章有劉節《驫氏編鐘考》、唐蘭《(?)羌鐘孜醳》、溫廷敬《(?)羌鐘銘釋》、孫稚雛《(?)羌鐘銘文匯釋》、朱德熙的《關於(?)羌鐘銘文斷句問題》、董楚平《者(?)編鐘》、何琳儀《者(?)銘校注》、饒宗頤《者(?)編鐘銘釋》、郭沫若《者(?)鐘銘考釋》、李家浩《戰國時代的“冢”字》、黃","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZX-XAcgzMG6NGfvQyaA0c86PNdAVKr68GmgyZb9l5k5EzORAQ_gV7wKmPXFaNi86EpO5HNQnHRkIPTv3iPFJ3lh4HSGjRuMPcpE8dkSmXlsoW8-zQkfBNXThqSX2b6CszKi-JpBQ6-2otZ6LK5QTKEJwpxdQVXA62D2OteVCTUPeTt6fyxOin&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6382,"author":"张春梅; 谭代龙","title":"上古至中古人体降落类词汇系统演变研究","abstract":"常用词的研究是词汇史研究的中心,而在汉语常用词的研究中,问题最为复杂、以往的研究最为薄弱的一项,则是同一个范畴内成员的变化情况。本文考察的是从上古至中古(先秦-隋)这一历史时期内,表示人体降落运动的各个成员的分布情况,以期找到从上古到中古降落类词汇系统的面貌及其演变机制。通过考察发现,从上古汉语到中古汉语,表示人体降落运动的成员主要有“颠”、“越”、“堕”、“陨”、“坠”、“下”和“降”等7个。为了数据的全面和准确,本文考察从先秦至隋的传世文献共计81部,包括史书、小说、小学字典等传世的中土文献和佛经文献,涵盖了散文、韵文等各种文体,以及甲骨文、金文等出土文献。对各个成员的观察,采取句法与语义","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKd8XTfM14Ui50w4Q6oPffuIt3c7_FSHzEFXJTzwFLlAMhAvAjrhSDIu4X5sYkUQD5777WqhzvqlzBGCKYV8RkzM0yu_bi4JaPIRwSbdOEDdXylCWSLQJvroavT-tFpoWeJ0_lSubb0ZbKOcb0BP5Q8RO-09Xbo_dyHSTuzw7b6xBHwkyeMJ1OH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6383,"author":"李瑶; 吴良宝","title":"战国燕、齐、中山通假字考察","abstract":"“通假”是人們在古籍整理和閱读文献遇程中經常要面封的問题。在出土古文字材料中也存在著大量的通假现象,舆傅世文献相比,這些材料時代大致清楚國别十分明確,通遇封通假现象的揭示,更有利於我們瞭解當時的语言情沉和用字習惯,這無論封於古音研究遗是封於古文字研究都是極其有價值的。本文僅就戟國畴期燕、齊、中山這三系的古文字材料中的通假现象進行研究,以期能夠反映出當時通假關係之一斑。本文分为上下雨编：上编主要列舉戰國時期燕、齊、中山古文字材料中學術界意見比较一致的通假339组,每组通假檩明通假字及被通假字,並列舉相阴辭例。各组通假按照被通假字的音韻地位,以王力先生所擬定的上古三十韻部爲序,同一韻部内按照被通假","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIiBMZoNaymlk5HFBJGIyTTKlyTouhNWW_77TEqEod7f8I4PVdObqRbljAGZw81tKt-8PdbTYq0XMZhpx5X3nMNipV1aAN9AmxIS1H97LGpsiIc2vCgSgzgTuLi_755r6VUASdi0tDnZybtwAf3Ki2w6KbsBn6j3fFe4ubFTx_i0hXwxtIraiVN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6422,"author":"金菲菲; 蔡万进","title":"长沙马王堆一号漠墓遣策集释","abstract":"本文是关于湖南畏沙马王堆一號汉墓遣策集释整理论文。马王堆一號汉墓自1972年3月发掘以来就一直为学界所重视。经学者近40年的研究,遣策文字大部分都已初步认识,遣策内容基本可以读懂。但仍然存在一些误释,或不识的字。随著近年不大量新的竹筒的出现,提高了我们封属王堆遣策文字认识的水準,使我们有条件封此前的竹筒文字进行重新榆讨,反思。本文本著这个出发点主要搜集近年来学者们封马王堆一號汉墓遣策的研究成果,并结合新材料封焉王都一號汉墓遣策进行综合性匯釋,并尽可能的和随葬品对应,使我们对汉时的丧葬习俗,名物制度有进一步的认识。本文分两个部分,第一部分筒罩介绍马王堆一號汉墓遣策的发现研究情況,重点介绍马王堆一","categories":["02_字词句考释"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8rzZUVujAZHb6q_XGFCC-KjtIFtYYHkachWto1ZBdhRYYsTFsrGot7sIp0EPaHduvchqKCeCn_v-4N76BV95yF_hCenDXdGPqcUUyWM8e1nBEDXL7bGVLEqgygoKgdP5m-boM_Ro8-fA4WX7S9ZV-xfpA6fGJqqI4xmwLbcky0ctHKZa7Z3_v&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6676,"author":"逄方慧","title":"试论上古汉语“于”、“於”的发展及其用法——以出土文献为材料","abstract":"从上古汉语看&quot;于&quot;、&quot;於&quot;的发展及其用法,我们发现在甲骨文里只有&quot;于&quot;,即可作动词,亦可作介词,但没有&quot;於&quot;的字形;在金文中出现&quot;於&quot;字,它大致产生于西周晚期,&quot;於&quot;字最初写作&quot;乌&quot;。&quot;于&quot;多数用为介词,也有用作动词的;而在《上博简(一)～(五)》①中,我们发现&quot;于、於&quot;没有用作动词的辞例,它们均可用作介词。","categories":["02_字词句考释"],"year":2011,"publication":"学行堂文史集刊——2011年第2期","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJD_2RwMgvC1MB1PeOcg3TiHTNAGJc-U_Q_Vb-qG6ncvo02-ST8NVYC4TepcwoMTzKsjPco4SGotwFol3IlPLm6dmJWGqmuhEKA73HW9wLSLcxUwDxYfthW3u5K7L7mIJT98qt9sZw_TfItrbLVfWI3v8pS0jbkrJazwRf1oMzs5K1CfpI0mFf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-29","volume":""},{"id":6677,"author":"龙正海","title":"西周金文札记二则","abstract":"勉励铭辞&quot;敬乃御毋败绩&quot;、&quot;勿替乃工日引&quot;分别首见于2010年出土的《高青陈庄引簋》与2011年新刊布的《卣》。学界对勉励铭辞中的&quot;御&quot;、&quot;工&quot;释读皆尚有分歧。文章以常用勉励铭辞&quot;用事&quot;之&quot;事&quot;为&quot;政事&quot;、&quot;职事&quot;义为突破点,对此两则勉励铭辞中&quot;御&quot;、&quot;工&quot;分别进行了补论,从而认为它们当释为&quot;政事&quot;、&quot;职事&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"学行堂文史集刊——2011年第2期","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ0mhbnZ_CVuYcIQ96n-99wBiCLAd1D01WC9lD3ep7zTSEnzmQJctjy8ZmAHgBlipIBJ6XdVqoCMS0T95csrWjwYe8vf0MVaiD12lPGxBM1DT7zcDVfPIphW9b4KIsIvynaGvwilHVqXDf8PyLB8tuCMjmnywTYK5Cvp-FeOLV8n8TVFTnhHeQx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-33","volume":""},{"id":6678,"author":"郭永秉","title":"商周金文所见人名补释五则","abstract":"本文对于商周金文上出现的五个人名提出了新的解释。","categories":["02_字词句考释"],"year":2011,"publication":"语言研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIl4iF_blutewR4KLhn72jhKWZzuJu4uxATjmcYZDwK0_moPumEjFd_MsbSEhCbvcsFtgjh9r9EgNEfYK7FccYZOqYD5Fu7gVLmTzEoNSPwzqwbD3FPyYaAOs1KQL-LiBwwF8aaF30ROko_hZWR0qMqFspTczCAyPFSKIpfvM5PbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"267-275, 327","volume":""},{"id":6679,"author":"谢明文","title":"试说商代小臣■玉器铭文中的■","abstract":"小臣■玉器铭文中的&quot;■&quot;,有读&quot;献&quot;、读&quot;谒&quot;等说法。旧有的解释皆不妥当。根据相关材料,我们认为应该读作&quot;匄&quot;,训作&quot;给予&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"语言研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJg_qVvgOuIyUhyDXnjkN_vdvbnE1uFFmH_2Uy8B1fDdYiOgMMNRA7XzhMM4F0V8czw_ALc3I87ZVsOS82YrWEISd6C8FO7f0wlIvyZssMbPYEgMem7py2a5B5IlBV0LoEQ5FyPMlJ1staMC0x5E1xHZmBBBgEagZTFXRy3HSFkKw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"276-281, 327-328","volume":""},{"id":6680,"author":"李霞","title":"“馘”“聝”考辨","abstract":"对于&quot;馘&quot;与&quot;聝&quot;,自古以来就有很多的说法,或认为二字实为一字之异形;或认为始本为两字,后世被用成一字。近来也有很多人对这两个字进行了考证,如苏庆红、王秋先的《&quot;馘&quot;与&quot;聝&quot;辨》。但大多数学者都是从用法、例证等方面进行考证,本文尝试从文字字形的角度对该二字进行考证。","categories":["02_字词句考释"],"year":2011,"publication":"学行堂语言文字论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5di9HwyHS6E9PlqL4rG5hCEQgFGa0W_-jS2UurjTEAxAlnMl42_d3Mq-8jpKdzNknMEwfHticAE4di_O5Uogq9Xj2x5I94zyy5htptYL0OVcp_QqlWGk6qVDrG7zqqsxCsnQa9RKU5d4iAJ2aBi2fcjGx3Nf4DVqbMQ0WNmIJng==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"180-190","volume":""},{"id":6682,"author":"黄人二","title":"释《庄子·外物》“曾不如早索我于枯鱼之肆”——兼谈《鱼鼎匕》之性质","abstract":"《庄子·外物》的&quot;索&quot;字,应作&quot;求&quot;讲;古书上之众&quot;枯鱼&quot;,指刚网及而尚未死去的鲜鱼,非已加工之咸干鱼或鱼干,传统的说法,必须加以改正。再以中国古代文学典籍之中,常有以鱼水主题为象征、比兴者,分为两类:第一,以鱼水之离合,与其出入,喻人之立身行事必须谨慎。第二,以鱼水之离合,喻夫妻之欢、男女之淫媾。并从此论青铜器铭文《鱼鼎匕》之性质。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK3jaw2COfMpWKfWrv-CxckXJmL4ZjB88n_UdA8iKMv97Q4X1QACdwx8nMLEvDWzWmxSx-qRHXRMkSXxIR2L-hE-MAtNSbi1xeJVBpIQk_iG_Vh1Aa_HM7KEMCQn-3TGrkCYPI58ZD-a8x0SgJYXzrDEOoiUxBKfDG0LCH6kGPyeA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"93-96","volume":"15"},{"id":6683,"author":"张世超","title":"西周诉讼铭文中的“許”","abstract":"西周铜器铭文中的&quot;許&quot;,又作&quot;■&quot;。不是后代&quot;应许&quot;之&quot;許&quot;,其义来源于&quot;交午&quot;,指在诉讼中对询问的应答或平时受到责问时的辩解。后世之&quot;語&quot;,亦来自这个&quot;許&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYP61Trky1Rvx3eTzWNd3OE-7FHHNabDyHvzT-EPHjBzD_q8agLHOeqonayyDR9UWxCkVeIQT4ksr6BxdNcajwCWxLaTYN-dqRNO78GkdTIZNP9O5bJ65zsVh8pfB0E_SgUNIB0Svo3LItYMACsxx42CD2NP2vI2AlMC5kwHlU5g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46025","volume":"15"},{"id":6685,"author":"张再兴","title":"近年新发表西周金文字形小考","abstract":"本文对近年新发表西周金文中的■、■、■、■、■■、■、■■、■等八组字形进行了考释,并据此对早先的一些金文字形的形义提出了新的看法。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIydWLmnznYroSrZ6I_cWn8b3qbLUqnFWapnGR3K9kxwjuwSaXRFzh6pq_48bY1v0Kq4LxIsiHQV4Z4TNs_RO-JF50YXWNzb-zB2-M1lyB2t_zjFZV8emeYHloxSA39R87ZEc0CeDDwqEyBnAdYD7cHmmoCZRpvzOB7Rj-hsJgLZA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46379","volume":"15"},{"id":6686,"author":"董莲池","title":"鲁大司徒厚氏元簠器名用字研究","abstract":"本文研究了鲁大司徒厚氏元簠器名用字,认为其构形应分析为从匚、从肉,甫声。这种构形表明簠在春秋时代可能主要以盛放肉食为主,《说文》解说其盛放黍稷并不全面。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6fhFKbXX84jN6UMV0VkpSUHjH3Y52wSmiyEV-VynyKOd4RkXNiC_fhe4eovQ3gofw9NefnY4jX8HFx8S8EDAsdjf2ELwPPMatpcimoCYERnXITzaN9ndAp6gAKM_Jr740rrEDtFSMz0bGzkEDUS9CDh3S5e4ogLtDmhk4gNhJEg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-26","volume":"15"},{"id":6687,"author":"唐洪志","title":"释“龏■”","abstract":"本文认为毛公鼎和四十三年逑鼎铭之&quot;龏■&quot;应读为&quot;妄浮&quot;,&quot;浮&quot;训为&quot;罚&quot;,&quot;妄浮&quot;即&quot;妄罚&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPNTjhyoKNwz_96vVqS9YC-_W87cZOv0OUreO8tnoRIcLGwT7aiK0kQb4Xn4azbdSU8K48CQtnjqCWtTqZoeLLCW8DkYKnKMwYmRMw23seDBwgvIv8naRLQPS0G36QOhf5qSfB_O6-iF1hWUZxBvX3rggJedV97elM5wo7YViEmw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"226-228","volume":"15"},{"id":6688,"author":"武振玉","title":"殷周金文同义词运用及其修辞特色","abstract":"殷周金文中的同义词运用主要有同义连用、同义对用和同义换用三种形式。同义连用以动词为主,其他词类很少见;连用的两个词或者都是常用词,或者一个不常用。同义对用有本句内对用和上下句对用两种具体形式,亦以动词为多。同义换用主要出现在语段中。殷周金文中同义词的运用多数是出于或强调或避复的修辞目的,有时则缘于同义词之间具体词义的差异。","categories":["02_字词句考释"],"year":2011,"publication":"华夏文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4VfY0MLuPGwE0YIj6we0O1TKpXYStzeVVPK_JZfHuOX3uztqqTbtHYbS9Zjehi9R2KGTJFviRDUqbjPCBuKBaXyY3c1f3ZHu35w7RdAat6nBxE8yRYrmvPB4Vhd2lD27zVH6GeAzMT6pkWYqw-5RyYMZxEGMP5GJf1ubLmvLa_w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-149","volume":""},{"id":6690,"author":"陳順成","title":"金文虚词研究综述","abstract":"商代金文虚词研究尚处于起步阶段,两周金文虚词研究成果相对较多。从总体研究、各类虚词研究、具体虚词研究等角度,重点梳理了两周金文虚词研究的相关成果,分析了学术界目前存在较多争议的一些问题。","categories":["02_字词句考释"],"year":2011,"publication":"汉语史研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKVTyfZbqyV9rO-2ig3FzYuXGP1FoDn8UfeyIa8X9TE4mZ3VMN3WeBpX2MkxxZyZRqSJLSYgRVj7LVf0GRkuARGWTd8LBCVEpRIpAE4-2jGK4SdT-r4_J1N5BIYkWAf7uTy-3bIcwuJORCb6hLyVJEuH9cqXgEHHfO5jW2bvtrJ4w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"148-163","volume":""},{"id":6691,"author":"王占奎","title":"何尊铭文的释读与营建成周的纪年问题","abstract":"西周初年的一件大事是营建东都成周。关于其建筑年代,历来有第五年与第七年之说,又有所谓周公返政前与返政后之说。千百年来,莫衷一是。本文试图将出土与传世金文和文献记载结合起来,对这一问题作一粗浅的分析,若有些微之利,则所幸也。一、何尊的释读何尊铭文发现之后,引起了对西周初年纪年问题的又一次热烈讨论①。其中有数处的释读存在分歧。所以,有必要先对何尊铭文的释读试作一检讨。","categories":["02_字词句考释"],"year":2011,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKAo_UBRu2CFbe3mDqFOrs1nh9qMs0VT14f54NEforY-MWc8peoIP0Mo15hRIH201ZedbG7jMfPlmd8mX75ne34KyuSgpLeHazXxcXR_33WNfBi35j2XKY62W1uCUyXEx2WQfSAd_0UlYIIcXx74IdGSIOZ-Lhxd8QuV-SNbwj2rw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"267-278","volume":""},{"id":6703,"author":"董莲池","title":"谈谈师酉簋■字的释读","abstract":"本文考证认为见于师酉簋铭中的■从升甾声,仍应释为段玉裁所改之《说文》&quot;■&quot;篆而不是&quot;弁&quot;。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYL30D5y8s_bV5bbnlWGLxSAdmUBs4UBhuhpS0HAstZGAmftCe4sUddBHeiB8U-pO4scG2LDoRhXFKHZ-ytLuvZnfbBeASj7NRdG8bU-j8KPkE7TaRzQ4L4HqzfUoTIbIyA-CsS4cqL_BwqtRcwXF67yITcxCjOW8lJ37U5BvrLA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46149","volume":"14"},{"id":6704,"author":"张美兰; 刘宝霞","title":"西周金文的双宾语","abstract":"本文在综述学界西周金文双宾动词和双宾句式研究的基础上,对其中37个双宾动词的用法特点一一陈述,归结出两周时期汉语双宾结构的特征:双宾动词数量的增加、双宾动词的复化、双宾构造的繁化以及不同语义双宾动词在句式语序选择上的区别。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxwHBgtp4pcsv1k1NCFwfluv1LBaWtktd3SUToqwQ1787l7ktbKs5dYXro8P_2w85T44noACCF3a2jZ78_a_NNKXHYd5b7miiUYEEqXxouWmDNmCDOgHjnIYVeZLSfKSrF4anGWnTfRG-ILztaDSaBZgybzvVsdebXAQkjMIrrwg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-68","volume":"14"},{"id":6705,"author":"张玉金","title":"春秋出土与传世文献第三人称代词研究","abstract":"春秋时代语料中的第三人称代词有四个,即&quot;厥&quot;、&quot;其&quot;、&quot;之&quot;、&quot;旃&quot;,常见的是&quot;其&quot;和&quot;之&quot;。&quot;厥&quot;只作定语,&quot;其&quot;常用来作定语,偶尔作主语和兼语,&quot;之&quot;都作宾语。&quot;厥&quot;的所指有两类,一是人神,一是国家。&quot;其&quot;和&quot;之&quot;的所指都有六类,即人神、国家、动物、具体事物、抽象事物、处所。但&quot;其&quot;最常见的用法是指人神,而&quot;之&quot;最","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxwHBgtp4pcsv1k1NCFwfluv1LBaWtktd3SUToqwQ1787l7ktbKs5dcvbYD5_tMRnZLlzaqwAW9hIryRSbaehJNqzOzCj37tQ-cju9riuU4U6uPEdf-bzDGZEvimURwte7BmDndNPNVf_SNbon6nmVGDoQLnaZwSBQayLK6lf95g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-87","volume":"14"},{"id":6706,"author":"张再兴","title":"殷商金文考释两则","abstract":"殷商及西周早期铭文的一组者女、者(女司)器中的&quot;以&quot;字意义当与&quot;铸造&quot;义相近;《殷周金文集成》7288号商代铭文中的■字,当隶定为&quot;■&quot;,即&quot;铸&quot;字。","categories":["02_字词句考释"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZmHV6cZppJrRD2x4CPpX1AliTQ-0HV3qrUkUXVmlxrqbeNG6jJ61leziqAQbpHgQ5JMQm_fKchZGEGnpsegiFuvvG5JfsOBKe85_ERIPzCOUOftIqNncNtAg9prkOw1oGFUkbeozl9oObjM-kZnaOpVYAM6cEiU30vSGvg6dVQA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-23","volume":"14"},{"id":6964,"author":"郑勇","title":"试论西周早期的记言铭文","abstract":"西周早期的记言铭文,数量和篇幅都较殷商金文有所增加,情节更加完整,而《何尊》不但首次提出了&quot;中国&quot;的概念和&quot;天命观&quot;,更在铭文中出现了感叹词,增加了文章的感情色彩。","categories":["02_字词句考释"],"year":2011,"publication":"现代语文（学术综合版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDfRzTYifPK80pJqLOYsP4BLFlxhcTfLEBiGTMMHTPoN9K3HCCiZHuIsN06w87B3d0ZClskNt6iip2GxvrysI4W2GBnIbkMZJy9yBrAQxgbA1PyhF3dIRxvg3J0C2YnNOGdea1hDbk639A3zoc2zhUNP_9qHxjt8gzU14gCtouOQqK6TZF0Kox&amp;uniplatform=NZKPT&amp;language=CHS","pages":"153-154","volume":""},{"id":6965,"author":"王颖","title":"“醬”之语源考","abstract":"《古辞辨》中认为,&quot;醬(酱)&quot;来源于&quot;將&quot;,因为&quot;將&quot;有&quot;辅助&quot;义,酱对主食起到辅助作用,因而得名。但是,本文从字形和饮食文化两个角度来考察,认为这种说法有待商榷。首先,从字形来看,&quot;醬&quot;金文的字形从&quot;酉&quot;、&quot;爿&quot;声,&quot;爿&quot;并无&quot;辅助&quot;义。其次,从饮食文化角度来看,&quot;醬&quot;开始是作为主食而非调味品。关于&quot;醬&quot;的语源,笔者认为&quot;醬&quot;来源于表示&quot;稠&qu","categories":["02_字词句考释"],"year":2011,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3qKxEzieXDnJkf0MGMVRBLQAiG-g07RJrCg49c0f_U60U3FitHsa_Xy9KshFTnndAqMdLvktec5_rRHv41SbDEp5loB7i5N92_NrFCcqnjPTom33T-LZoDkAa9jg3ck_MA5cVKm_BHaGdrK14ka2lmq-pgwWDXOsCt2PQxbdA8Rwdx_xZAjaS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-50","volume":""},{"id":6966,"author":"李万里","title":"“戈”字探秘","abstract":"&quot;戈&quot;是一种盛行于先秦时期的长柄格斗兵器,秦汉以后逐步退出了战争的历史舞台。在汉语言中,&quot;戈&quot;字蕴涵着丰富知识:它描绘了古代兵器&quot;戈&quot;的样子、反映了古代&quot;车战&quot;的作战方式;&quot;戈&quot;部汉字记载了&quot;戈&quot;发挥的作用;含有&quot;戈&quot;字的成语多与战争有关。","categories":["02_字词句考释"],"year":2011,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUgi7S1fPeEWXpbsL2H6v8-gjIBSQ_WYJx-X64z5bYu-GwXfTmBFRoEwecCcOilqZ827toP-uD-4ZQm-wlfbrG2rXu-ZTyDQptu6ztlDf78oNipCL5DdTbI-qmGfH-HJ2vu1B2FUlvQVAHr2OyZh1o9HuG6iGUQ2w9llZEZ1OiCb9EEGibjpl4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"153-154","volume":""},{"id":6967,"author":"胡世发","title":"从与古建筑相关的汉字看社会政治经济发展","abstract":"甲骨文、金文、小篆等象形或会意的汉字古形体,反映着我国古代的社会生活状况。本文研究&quot;穴&quot;、&quot;容&quot;、&quot;家&quot;、&quot;牢&quot;、&quot;宋&quot;、&quot;宣&quot;等与我国古代建筑相关的汉字,查经据典,观察其甲骨文、金文、小篆体,溯其本意,探究其中蕴含的社会政治经济秘密。","categories":["02_字词句考释"],"year":2011,"publication":"青年文学家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI59u0qRM6fzZVocp19l_9ZSPxUskaReSQHlRktNhe3uaQ8cn5O24XABeHi0Y7jqONZZoCtjQfODg2wVm4tS6IVgNQVjnV5UV0xUZvSx2nbW7zZMgaSWXTyyPG93MyQvu9rNUraHRrRRCrWQyfILVXJGa8Z6R5Mh0cvCxcKduyZTA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"157-158","volume":""},{"id":6968,"author":"杨现昌","title":"纪侯鐘、纪侯簋铭文阐释","abstract":"纪侯鐘、纪侯簋是出土于山东省寿光市境内的西周青铜器,铸造精美,保存完好,上铸铭文清晰。正确阐释这两件青铜器之铭文,有助于认识这些汉字的构形原理,有助于揭示其中的历史、文化内涵。","categories":["02_字词句考释"],"year":2011,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJT2K-m-QxqxVZWDD2PIjZlKkZ40usYgBSwQWQ2bGBhmiyklse2SrWZ48NzI136G4a5IT1mZx9IFbLRwNrWPGjr_jpMRCrJkXXvPI_-ghGPeSOaflGVmzazyCw1UUXMTpOgL8Nx6SWa52ck89Hel22FIvsZkQbSU0qT14GQ7U3ETYA_3-zMJac-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46024","volume":""},{"id":6969,"author":"王丹娜","title":"西周金文中的形容词作修饰语的铭文研究","abstract":"西周金文中的修饰语是形容词的可分为表示&quot;长久&quot;义的,有&quot;永&quot;、&quot;弥&quot;、&quot;畯&quot;、&quot;引&quot;&quot;疐&quot;等;表示颜色意义的,有&quot;赤&quot;、&quot;白&quot;、&quot;朱&quot;、&quot;彤&quot;、&quot;玄&quot;、&quot;金&quot;、&quot;幽&quot;等;表示&quot;珍贵&quot;义的,有&quot;尊&quot;、&quot;寳&quot;等;表示&quot;虔敬&quot;义的,有&quot;每&quot;、&q","categories":["02_字词句考释"],"year":2011,"publication":"青年文学家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLQcVtNpGOcwiMJC2bKPi4kSbTR5-KDJ4WgMaZk_3_IVL9nTSpKRdh6OVktDdLPV0E0HMVZ5sYr5r50sqNbtPjtw02x3vasU8tMgb73r5socZ0u1hsim6LIRSHVxZFcT4c7EyRnr2KiH4UO7Yns45r-tUpr_74Ee5rkXbbwjvYPlw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"154, 156","volume":""},{"id":6970,"author":"张文峰; 付成波","title":"《两周金文辞大系考释》初文等术语初探","abstract":"郭沫若的《两周金文辞大系考释》中的术语对训诂学、文字学都有非常高的研究价值。通过整理,文章对初文、繁文、省文、异文四类术语做了较详细的归纳分类,并将其与权威理论进行对比,阐明了郭氏在《两周金文辞大系》中使用这四类术语的体例。其中省文是郭氏训释铭文的方法,而初文、繁文、异文则体现了古文字发展分化的规律。","categories":["02_字词句考释"],"year":2011,"publication":"现代语文（文学研究）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9nMk3L5yEImf_4rV3eQzYclk0523gVQVy0zFwsUpsdD_CzNkYdU3otiENg-7O37gLHksKfYLMUFJwDYkvV7xTzPH_74VyFJQ7s0XHPb69o8UZTIjHo6Jvqa19JrFsv5r7BSaNOgLY0teggpVJ1OMkJdLr0o14wHHFGckZXuj_njWMo_mv5h4C&amp;uniplatform=NZKPT&amp;language=CHS","pages":"158-160","volume":""},{"id":4839,"author":"馮時","title":"天亡簋銘文補論","abstract":"天亡簋自清道光末年出於岐山之後,學者研釋不絶。其作爲武王標準器,史料價值極高,然於銘文内容之理解,器主之考定,猶多分歧,兹聊爲補述。[乙]亥,王又(有)大豊(禮),王凡(般)三(四)方,王祀于天室,降。天亡又(佑)王,衣(殷)祀于王,不(丕)顯考文王,事喜上帝。文王德才(在)上,不(丕)顯王乍相,不(丕)■(肆)王乍■(賡),不(丕)克乞(訖)衣(殷)王祀。丁丑,王卿(饗)大宜,王降亡■(勛)爵復■(囊),隹(唯)朕又(有)慶,每(敏)■","categories":["02_字词句考释"],"year":2010,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtjOP4eHEvrtkNNyQN3mgqoKwMr0VUqwuB2BFMVvRzT6g88q7V13y_jrG1oCniIjexlEmaYEe6MjPsJOgmzepkQpXdBrUBWO69mR5yYuw9QovmZSKX-bphXe2teKN-C8NoDboKIgbPm0piI2b7NRVxCjYWvVRasqmoKKyoByzOj8LR6JOUcJHd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"122-128","volume":""},{"id":4840,"author":"趙平安","title":"■簋銘文在文字演變上的意義","abstract":"《文物》2009年第2期上發表了張光裕先生的《■簋銘文與西周史事新證》一文,首次披露了某私家收藏的■簋器形、銘文,並作了細緻深入的研究。張先生指出,此器無論器形、紋飾,俱見西周早期特徵。銘文與周公敉平三監之亂有關,以“公陕殷”之年作爲紀年,可以提供周公是否稱王的重要參考。銘文對青銅器的斷代,對史學研究具有重大的學術價值。","categories":["02_字词句考释"],"year":2010,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISPLDlOiFb0QiTvm0ocQe6KXXGSrME_OdUcjGP7r9zk0bCm9uccQntscyp8sVoS-nCesd0MoNKk_zpU-yQZCDTc1vTKHKT3z8McWNOGsJmomVhrQxM8Ulc3IyRLwQRMtfkoxd2O12P4u8IPbgop9LCDaWrK6HoVciC-tz69G_U6oWIqUrgMFle&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-132","volume":""},{"id":4841,"author":"張懋鎔; 王勇","title":"遣伯盨銘考釋","abstract":"一近來在西安某藏家處見到遣伯盨一件,失蓋,通高10.9釐米、器口長邊24.7釐米、短邊16.1釐米、圈足長邊22.6釐米、短邊14.9釐米、兩耳間距30.6釐米。體呈橢圓形,器口略收斂,中腹微鼓起;器腹較淺,圈足較高,圈足下端外撇,四邊的中間各有一個較大的果葉形缺口;器身兩側爲附耳,高出器口。(圖一)器口沿飾斜角目雲紋一周,雲雷紋襯底,腹部飾寬瓦楞紋。(圖二)形態自然,線條挺拔,棱角分明,紅斑綠","categories":["02_字词句考释","01_新出器物"],"year":2010,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKihuanlzGXvm3Fbhf64SeWawGFjvvz4dJR1xU8xL93kAc280oZhlNr7pnzv_SKqEh7hquu0T81gt3l_NjkV3xdceqafCrRbhw73jWZrNkKf8o1PwNe9Pcf2L0WrPZ9zAKuvHbZE3AkPjV34wY8MwVdsWpStj90OWNN6BKrCeZ8txDgN04sPzdN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"133-139","volume":""},{"id":5113,"author":"王长丰","title":"近出■■盉铭文考释","abstract":"■■盉出于山西,应为西周穆恭时期器。此器铭之&quot;■■&quot;应是器主。《左传.昭公十五年》说,诸侯受封皆受明器于王室……故能薦彝器于王之礼,由本铭可以得到验证。&quot;■&quot;字应释为&quot;盘&quot;字,此铭文为盉亦可以称为&quot;尊般(盘)盉&quot;提供新证。","categories":["02_字词句考释"],"year":2010,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITbIO7GY3LIW5D1biDmzjXBhrfi8t__uHhm7PEJYxuqwYPbAQQzT3vu_t22I9LAS1280tC1hSacbS_YdjEr5ImjiedhHXj5cg-G76Yxtec4AefLdVy1cBeliY8Pk2oVKRLV8aJXiuN3nXDo4848zlhVamtndOVU1v6-McfYiwGaQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-70, 75","volume":""},{"id":5114,"author":"张利军","title":"释西周金文中“服”字义——兼说周代存在“服”制","abstract":"Extended from its original meaning of obedience,the character 'fu' in the Western Zhou inscriptions is also equivalent to tasks,duties and tributes.For instance,the Zhou King called official and retainers' duties as 'fu'.Marquis' tributes and tasks were also called by the Zhou King as 'fu'.Besides,o","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXfxO_DK4EDjho0GWG5knOrvQSEOhiCClmML2sIdVVaAieyBZ3ykiVGZkOEqgT0WzB-ferTNDTH6UVmU1IxEHBwu9fvs1ZFrwLRTi4sI4iHctaMXkvBvuHLW5Smu9_dPIh0fsE2HQ1TqN6IEsheWj9FGk_595KLJU-lO-rPjEHog==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-98","volume":""},{"id":5115,"author":"张金霞","title":"汉字发展过程中的调整与完善","abstract":"汉字在其发展演变过程中,一直在不断地进行调整与完善,汉字的分化是其中一项重要的调整手段。一方面有同形字的分化,另一方面也有因词义引申和汉字假借等引起的分化。这种分化是遵循一定的规律的,发现并研究这种规律,对于我们认识汉字历史、指导汉字改革均具有重要意义。","categories":["02_字词句考释"],"year":2010,"publication":"山东师范大学学报（人文社会科学版）","link":"https://link.cnki.net/doi/10.16456/j.cnki.1001-5973.2010.06.015","pages":"40-44","volume":"55"},{"id":5116,"author":"闫春慧","title":"释“鼎”","abstract":"&quot;鼎&quot;是中国历史上最重要的礼器,历史文化含量极重,所以该字演变发展出许多引申义。汉语中的&quot;鼎足而三&quot;、&quot;鼎足三分&quot;、&quot;鼎足而立&quot;均是在此基础上产生的。&quot;鼎食&quot;指列鼎而食,古代只有生活富裕的贵族阶级才可以列鼎而食,因此用&quot;鼎食&quot;比喻富贵人家的奢侈生活,形象生动。","categories":["02_字词句考释"],"year":2010,"publication":"内蒙古农业大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL7_gleUrDdaMYL8bI9tDnaLZ5f6xwvZEZ_XsNpE0fFrRo8P7Z45oAXQ8L3hUcinfc4GwetLqhDW9uJczrx39DLWYNPHEpviql1XBjhzXDtGNpihfi_h4E8luM6O7pAEQZvoBsDF7fVmhezOErD6NNuhWXIRS9lIPj6pCTebBLwdA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"200-201","volume":"12"},{"id":5119,"author":"邓飞","title":"“余獻婦氏■壺”考辨","abstract":"琱生簋铭文&quot;余獻婦氏■壺&quot;的解释和断句分歧较多,主要集中在&quot;献&quot;和&quot;■&quot;上。论文从上下文断句、句法结构、礼仪、甲金文内部用例、传世文献用例多方面对关键问题进行考辨,认为&quot;献&quot;当释为&quot;献酒&quot;,&quot;■&quot;当释为动词,义为&quot;给&quot;、&quot;致&quot;。其断句当为&quot;余獻,婦氏■壺&quot;。","categories":["02_字词句考释"],"year":2010,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-L1rrmLQKMX44oo0IC-IOtrDdubkyCu2iDw1YiI5Ldhh-GjL_Nqw9RZPVQef9UwytAJFEKKh0_oCXmzM3SPaMXAKEN-beZ689UfWJVwRCmMn3OM4toRf3hyyIhFBC_QpjkaHysf-U8-zHVWvYPtZ-7izcHGc374iZKNgJ48861g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-66","volume":""},{"id":5120,"author":"王秀丽","title":"金文叠音词语探析","abstract":"汉语叠音现象由来已久,本文以青铜器铭文为语料,对金文中的叠音词语进行探讨。金文叠音词语主要出现在西周晚期和春秋时期,包括叠音单纯词和叠音合成词(含词组),从形式上看分为AA式和AABB式;叠音词语中异体、通假现象多。金文叠音词语是汉语词汇双音词演变的一种方式,具有增强表义效果、补足音节、协调韵律的作用。","categories":["02_字词句考释"],"year":2010,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCirrUNEb9DbBDTsPbxEJ5flHqTVjozn3N_wcRpkIuTmmGXwIlME2dKYiA56_SGMIp3r3aIwTn9L-KtB22e56X723OfuLJHoI_J5MuNy9snfM-KTRT0Yiufx_1AZsS1A-yt3t6MmmZBoTrPftCmf5UN75cWmHR-Rew3bqqNeEAFg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-132","volume":""},{"id":5123,"author":"麻爱民","title":"近三十年两周金文语法研究述评","abstract":"二十世纪八十年代以来,利用两周时期年代可靠且未经后世修改的金文材料进行语法研究成为学界热点,在词法和句法研究方面都取得了长足的进步,很好地弥补了先秦尤其是西周语料之不足。在取得成绩的同时也存在一些问题,如各类研究还不平衡,新理论新方法的应用较少,对金文语料的使用和理解还有偏差等。","categories":["02_字词句考释"],"year":2010,"publication":"安庆师范学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_EBkBrSGSYpicjLwj4rHtr7gdPMDna55fMozqABMC5OlPM4v55vDNuFW-QEvKofXiDK4aIgwRI5f34JCM7E1LnYgt9pWclbfmFyzc1mnYVYv2pZu_Pw_0vO7bskRfuTJ2T8HxkCW6HrZ7hONPjoiPxyt-83yG2H_A6mAW-B4c4g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-117","volume":"29"},{"id":5125,"author":"王晓君","title":"“巫”字考释","abstract":"本文在综合梳理了有关&quot;巫&quot;字的各家观点的基础上,依据&quot;巫&quot;的文字初形,辅以有关&quot;巫&quot;字的古籍文献对其进行考释,证实&quot;巫&quot;即古代巫者使用的一种工具。","categories":["02_字词句考释"],"year":2010,"publication":"大众文艺","link":"https://link.cnki.net/doi/10.20112/j.cnki.issn1007-5828.2010.21.108","pages":"130, 129","volume":""},{"id":5126,"author":"武振玉","title":"两周金文“承继”类动词试论","abstract":"两周金文中的&quot;承继&quot;类动词可大体分为表示&quot;接受、承受&quot;义的,有&quot;受、膺、承&quot;三词;表示&quot;继承、踵继&quot;义的,有&quot;赓、嗣、缵、肖、绍踵、■、■&quot;七词;表示&quot;遵循、效法&quot;义的,有&quot;帥、率、型、異、用、经&quot;六词;表示&quot;秉持、保有&quot;义的,有&quot;秉、持、宝、尚(常)&quot;四词。出现频率上,除&quot;宝&quot;很多见、&quot;受&quot;较多见外,其余各词出现频率都不高;出现时间总体集中于西周中期和晚期;句法功能上,前三小","categories":["02_字词句考释"],"year":2010,"publication":"社会科学辑刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLbDYp4vW0-biUmvMFN4xAWVXSE2ke2bVIijI2C-Afzjgq4TP8XUPw7dM5hSdasAWCWOtAMcN60Ajo00ZxPCoyjpAQw-Z6STABFjlsI7UxVxRe17DcmBN9-rr4B1UQDO8Wl-J1l3_xUdqckPdYQ5UhQB1dBaUZjQE_Ctv_ISDuXg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"254-257","volume":""},{"id":5127,"author":"杨泽生","title":"释“怒”","abstract":"古文字&quot;怒&quot;有&quot;■&quot;、&quot;■&quot;、&quot;■&quot;、&quot;■&quot;、&quot;■&quot;、&quot;■&quot;、&quot;■&quot;和&quot;怒&quot;等多种写法。过去研究者除了对秦简&quot;怒&quot;的释读没有异议之外,其余都有不同意见甚至误释。笔者对这些&quot;怒&quot;字作了正确释读,并进一步揭示相关资料丰富而重要的内涵,如结合花东卜辞&quot;丁怒于子&quot;等,分析&quot;丁&quot;和&quot;子&quot;的身份及其地位关系,商王武丁的喜怒性情和权","categories":["02_字词句考释"],"year":2010,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMYWKKtM52FMR4evgj_4_Lwjh14ObJBt66sT0VKh5mH5uerRK9-sWiTr01vKnrCMAvcoRYfGGFLtQCBZF6k1x9mTXmVWIJU5kA_aPt3CU5oGqo1dl6JGcCK6UtnB5KKgbEt89sd4kqGPnk7EReyhex5HCmvlCccbONNDjbw-Xa3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-52","volume":"50"},{"id":5128,"author":"朱其智","title":"“蔑■(历)”新说","abstract":"对传统各家考释西周金文&quot;蔑■(历)&quot;一语的主流观点进行了归纳总结,其共同点是&quot;动词+定语+宾语&quot;句法。接着从&quot;蔑汝&quot;之&quot;汝&quot;为宾语、&quot;穆王蔑长&quot;和&quot;长■蔑■&quot;上下文互勘、&quot;蔑某■&quot;和&quot;赐某金&quot;上下文对举等三个方面来证明&quot;蔑某■&quot;是&quot;动词+宾语1+宾语2&quot;双宾语句式。再从张光裕发现的新铭&quot;加曶■&quot;一句出发,系联&quot;加子白义&quot;一句,以传世文献作为旁证,提出&quo","categories":["02_字词句考释"],"year":2010,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFbmuUsA1gr8XZKPl-7kVXo07r-JODKjKHNFJA2oFqTSAnL20pKTwKWk2LpSOiINOnqMDV1isEtUjXz7RETiVVLbG6CRbpLys7SP3wJDIxqH6gnqFj0DrcC3rc62LTKg7bxftxoGmMb8gG--XxMFIgOg7Di14G4YHAf1j5OlVqWw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-55","volume":"50"},{"id":5129,"author":"郑振峰; 李冬鸽","title":"书写载体与古汉语复音词","abstract":"文章考察先秦、两汉、魏晋时期以竹简等为载体的出土文献与以纸为载体的传世文献,比较其中复音词的数量,发现在相同时期两类文献中复音词的比例大致持平,进而说明不同的书写载体没有影响文字如实记录语言中的复音词,东汉时期复音词的大量增加与纸的普遍使用无关。","categories":["02_字词句考释"],"year":2010,"publication":"语文研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFbmuUsA1gr8XZKPl-7kVXo07r-JODKjKTgQiZ8e0jDZNJzsCC2EadHDDN-tSXLhojEtJOvqH7Agn_ZKNHjtabhSARuY24gC2jaC4699V8eAlzGXkPdB7eugiRzrIq2kSO-w0WtvjdufNDz2E63lXN0GlOJDF8-eF0vB-0CthPNA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-58","volume":""},{"id":5130,"author":"寇占民","title":"两周铜器铭文“倗友”考","abstract":"&quot;倗友&quot;一词最早见于两周铜器铭文中,它与现代汉语中&quot;朋友&quot;的理性义相差较远,对其古义所进行的考释仍不够全面、深入。在铜器铭文中,这个词写作&quot;倗友&quot;,其构型真实地反映出了它的原始内涵。对该铭文的研究,有助于探索上古社会的组织形式,进而揭示出商周社会形态下&quot;倗友&quot;的真实身份。","categories":["02_字词句考释"],"year":2010,"publication":"东南文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIXOyQ00RpTVVxDumnZTwHjIcmSs-tE6Sk0f6btCi_W5lPP0imBcrv2n5szNSnnPSJwfnrHYZUhZvSWsylfod_5K_3Y12bXX8EMEuubXPEYMoxTiWkxeG-LjfacF8KiYZP6jfBd2FoMOSW57m9mQudsVs-ZmhMe9W-WQtm6P-BYwQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-98","volume":""},{"id":5133,"author":"李学勤","title":"论高青陈庄器铭“文祖甲齐公”","abstract":"以甲乙等日干作为庙号的习俗始于夏代,盛行于商代,至西周而逐渐为文武成康之类的谥法所取代。高青陈庄器铭&quot;文祖甲齐公&quot;则证明,西周初期,吴、齐、燕等封国与周王室一样保留了日名,直到西周早期后段才逐渐完成了由日名过渡到谥法。","categories":["02_字词句考释"],"year":2010,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2010.10.013","pages":"40-41","volume":"31"},{"id":5134,"author":"戚其章","title":"甲金文字偶拾","abstract":"本文通过对甲骨文■、■、■三字及金文民字的考释,提出自己的新解。","categories":["02_字词句考释"],"year":2010,"publication":"东岳论丛","link":"https://link.cnki.net/doi/10.15981/j.cnki.dongyueluncong.2010.10.014","pages":"42-46","volume":"31"},{"id":5136,"author":"陈魏俊","title":"从古文字角度谈几个与女子相关文字的文化含义","abstract":"中国文字神秘而古老,汉字除了表达语言的意义外,其构造形体本身还给我们传达了更多文化层面的意义。文章试着谈几个与女子有关的文字——&quot;父&quot;&quot;女&quot;&quot;母&quot;&quot;妇&quot;&quot;婚&quot;&quot;妻&quot;&quot;妾&quot;&quot;子&quot;&quot;毓&quot;&quot;后&quot;&quot;好&quot;的文化含义来说明这个问题。","categories":["02_字词句考释"],"year":2010,"publication":"青年作家（中外文艺版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvkVFH8GeGsfS1jBEHe7CLiY9e6T7c_9lDjUFeB6sBrgTQL0P5U44N2kPSYjL-f0KLyFJ7xNkXJakeZay_JHHIbmMavzL97TCUJfEIYs1LX8p2d1CBDWg4QUfRKbysDujtTgWa5Ga4LuSKrwBrvwLdcxC6wbriNgeVWEM6roAV8g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48-49","volume":""},{"id":5138,"author":"白于蓝","title":"师永盂新释","abstract":"Among the Middle and Late Western Zhou bronzes,the Shiyong yu container is a quite important one as its inscriptions involves land transfer.Based on previous research,this article tries to discuss and further explore the character ‘jue’(厥) and issues of punctuation in this inscription.In addition,th","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKnMbOtH-YeNNI50Y23qpLZw0n2h22Ui0CvMkmut9K5iBlTTXtBEn2qV_mEQPv6cylo5poiJmqwdybHhp_4Ij_RcGsaxPgKUYQDOZEwi_eAt8riJqcqqe0T1p8_oB2CX4_kHlVn6MBljcmdTOQxOmS3bRAH3KD5yiBSSlqQpExLYw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-34","volume":""},{"id":5139,"author":"邓飞","title":"铭文考辨两例","abstract":"师簋有铭文&quot;今敢博氒眾叚&quot;,马承源等先生读&quot;博&quot;为&quot;薄&quot;,读&quot;叚&quot;为&quot;暇&quot;,&quot;薄&quot;义&quot;迫&quot;,本文认为铭文应该断句为&quot;今敢博氒眾,叚,反氒工吏,弗蹟我東國&quot;,而&quot;叚&quot;是表示语气的叹词,表示吃惊和不屑的语气,且&quot;博&quot;当读为&quot;搏&quot;,其义为&quot;捕持&quot;。&quot;行气玉佩铭&quot;是一篇叙述道家、内家拳术关于行气养生的铭文。铭文中的&quot;■&quot;字形、","categories":["02_字词句考释"],"year":2010,"publication":"绵阳师范学院学报","link":"https://link.cnki.net/doi/10.16276/j.cnki.cn51-1670/g.2010.10.008","pages":"66-68","volume":"29"},{"id":5141,"author":"何景成","title":"论师酉盘铭文中的“弁狐”族","abstract":"师酉盘、师酉簋铭文中过去被释为&quot;身&quot;的字应改释为&quot;瓜&quot;,读为&quot;狐&quot;。师酉簋和询簋铭文中均有夷族&quot;弁狐夷&quot;,在师酉盘铭中作&quot;弁狐&quot;,是指&quot;弁狐&quot;地的夷族。作为地名的&quot;弁狐&quot;可能当读为&quot;番吾&quot;,地在今河北平山县一带;&quot;弁狐夷&quot;指居住于&quot;番吾&quot;一带的夷族,或可省称为&quot;弁狐&quot;。","categories":["02_字词句考释"],"year":2010,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxE6XxCMgMSA_DLCQNOdYuJvjRKhPfrs3gtN_lLptapqe7ch4A-Y3MAlUa9ZKGz40gzYfln6BDu3jVyemX7xVxhyhKlbC8UGwNt1fq4z6YxT260dfZzN0YwSf_mm0IZ3PDWZ0b52RLfEXdpYQLzkR4gk1BZApkWmHZC1I7i9ELtg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-68","volume":""},{"id":5143,"author":"昌文彬","title":"“孝”字的创生及其原义释","abstract":"&quot;孝&quot;字是人对生命来源不断追问中,记录男女交合而创造生命这一发现的符号。&quot;孝&quot;原义为繁衍生殖,本文从甲骨&quot;孝&quot;、西周金文&quot;孝&quot;象形义;西周&quot;孝&quot;铭文的解读;孝原义在儒家孝义中的顽强呈现三个方面予以论证。","categories":["02_字词句考释"],"year":2010,"publication":"理论月刊","link":"https://link.cnki.net/doi/10.14180/j.cnki.1004-0544.2010.10.006","pages":"69-71","volume":""},{"id":5149,"author":"李秀亮; 张秋芳","title":"《俎侯夭簋》:“易在俎王人□又七生”考释平义","abstract":"《俎侯夭簋》&quot;易在俎王人□又七●&quot;一句,&quot;七&quot;后一字当释为&quot;生&quot;,学者或释为&quot;里&quot;,不确。无论从铭文字体、铭文内容、同时期分封铭文的格式与内容,还是西周时期&quot;里&quot;的性质等,皆可得到有力的证明。","categories":["02_字词句考释"],"year":2010,"publication":"石家庄学院学报","link":"https://link.cnki.net/doi/10.13573/j.cnki.sjzxyxb.2010.05.015","pages":"30-33","volume":"12"},{"id":5151,"author":"王继洪","title":"汉字字形叙事之管窥","abstract":"董乃斌先生《论中国文学史抒情和叙事两大传统》(刊上海《社会科学》2010年第3期)一文中提及&quot;古老的中国文字,就是为记事——叙事而产生,而进化,而成熟的&quot;观点,并有所示例。班固汉字&quot;六书说&quot;中有&quot;象事&quot;、&quot;象意&quot;两项,董说也许可与之印合。董说似还可以拓展许慎&quot;六书说&quot;中有关&quot;会意&quot;等构字法的诠释思路,为汉字学研究提供一种新的视角。故在借鉴总结前人说法的基础上,试对汉字与生俱来的象形表义、音义结合、立体叙事的特点进行粗浅解析,以回应补充董先生的观点,并说明中国文学的叙事传统之源","categories":["02_字词句考释"],"year":2010,"publication":"上海大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLT7XkEXLlW5eclmHL7BKs0qj-Zr82NGJRoudO1G0NE_8nyCRg1Jj14PmsF-pGxFgtCvfhXwbnCuUBT2PTQL-svcSlUXG_y692dTmvx_VDSklY6NwWSB2xA9CMyg8hjM-UKnonklUZ0RGXm8-0YQYUZTjqTb50FW6klFW884_0_rA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-108","volume":"17"},{"id":5153,"author":"谢明文","title":"金文札记二则","abstract":"一秦公器&quot;事&quot;字解秦公镈(《集成》1.270)&quot;虩事■(蛮)夏&quot;之&quot;事&quot;字,孙诒让[1][p2]、郭沫若[2][p250]、张亚初[3][p13]等学者直接释作&quot;事&quot;而无说。秦公簋(《集成》8.4315)&quot;虩事■(蛮)夏&quot;之&quot;事&quot;,薛尚功直接","categories":["02_字词句考释"],"year":2010,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmokQHF2y3IAB3HoTrAYIKwpAEJKpE-QBU-PI_v8rASmUVD_1TBx49PFzBB4T1cGOxr_43W3PqEFzAGk5bkqYOTEzhI0_eentuj25OnYDhhs4hjupJEjneg4w6W7qCSi8DGKt8flQugilZfxAuBDfbLzeSe3OQ0ZsI04cuETchIQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-24","volume":""},{"id":5154,"author":"王耀东","title":"“番”字本义蠡测","abstract":"《说文》认为,番字从釆,是兽足义。对此前人已有怀疑。番字上米下田,意为播种;从词源学角度看,凡从番之字皆有散开之意;春秋时番氏曾掌管土地人民,这与他们擅长农业有关。因此,番的本义是播种,是播之初文。","categories":["02_字词句考释"],"year":2010,"publication":"沈阳农业大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJrx4Vi5chk6xoWBCXZnVKIGACl7uFwGFRT7iWkUr6Vfjf2khFjBTLKrfpeoBu_CjemSq5e8ptyVGxc7puGSjDxk4vl2AW9G-8QQIqY6WGwwKXi5LxC7J9oFv5dATiTdW478dBdcn6CnXIDB3jK08t_dGfKdyzLaYX21ABkfEZHg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"622-624","volume":"12"},{"id":5155,"author":"刘光裕","title":"商周简册考释——兼谈商周简册的社会意义","abstract":"二十多年来,书籍史与出版史界一再宣称战国以前没有简书,而在前辈成果基础上进一步考证的结果表明,殷商与西周有简册。从商卜辞&quot;册&quot;字字义考察其字形,可知&quot;一长一短,两编&quot;为商代册命的专用简册。到汉代,&quot;一长一短,两编&quot;仍旧是策书的专用简册,不用于诏书或其它天子命令。考察西周金文所记册命具体过程,可知册命书于简册无疑。不论西周东周,册命的原件都是简书,不是金文。考古所见金文中册命,其实是受命者自己将册命文书从简册&quot;迻录&quot;到彝器上的。简册是华夏先民的专业传播工具,以高效而价廉之优异品质,长期独步于世。最初,简册与汉字一样主","categories":["02_字词句考释"],"year":2010,"publication":"济南大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICLfOFTt_QGIJaLbIf0elcU7bFiBHrhI9tx1fetlSqRtTZZAVA29B32C9NDshy_YCMMYolgwEgwi0PBtzk624fUhvhaOR150gxmlYZWCHcHRdvbgR29PH_BMwq27eVxV4MDNY8ddgmzgwKJlhdgYGR5OCiaThQDLiq1C-3xe2RSw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"1-11, 91","volume":"20"},{"id":5156,"author":"吴国升","title":"春秋文字字形区域性特征的初步考察","abstract":"春秋文字中,壴、竹、丮等25种字形具有典型的区域性特点。春秋文字大体上呈现出南方诸国、山东齐鲁诸国以及秦与中原诸国三大区域格局,战国文字的区域性格局在春秋时期已经初露端倪。","categories":["02_字词句考释"],"year":2010,"publication":"安徽大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4GTLrOiYHiZzAg0YxxQxUZkmxDfwRkIeCElemmQLOMHRv6qViPG6wLN6dyfMr7NVulqA-xWs41grBWnWBD1A3LvcEFAGpEb_8XplaA9rG7N7e55cJN3plUOKGyqDhBfD9oXp_9BtuMCYQedVkr-0XQAjQVN_6VT2ICvCr7stiXw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-93","volume":"34"},{"id":5157,"author":"陈英杰","title":"金文字际关系辨正五则","abstract":"字际关系指的是在形或音或义等方面存在关联的一组字之间的关系。文章对金文中&quot;■&quot;和&quot;召&quot;、&quot;友&quot;和&quot;■&quot;、&quot;嚴&quot;和&quot;■&quot;、&quot;寶&quot;和&quot;福&quot;、&quot;辟&quot;和&quot;犀&quot;等五组字的字际关系进行了辨正,纠正了对相关文字形义释读模糊或错误的认识。同时探讨了不同文字构形系统比较的方法,为各个时期文字构形系统运行机制研究和不同时期文字构形系统的对比研究打下基础。","categories":["02_字词句考释"],"year":2010,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLpkLgaQaUr-GQorOknXKWSY4TPNfXnPdzOqKZ2BK54ZDEAtbEqm_7-UW8d2PaUHp031AbWtqCp7QSDvPbEywvX3PjZlaxjgsQuKSJVKNdtnMOMx1u9th64E09iu3WTFp4QhPW_2kYB6Lqmch82NS3xebXPh9-Q07IxBdQULqrVyA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"532-541","volume":"9"},{"id":5165,"author":"孔令远","title":"越王州句戈铭文考释","abstract":"The inscription on the bronze Ge-dagger ax of King Zhougou of the Yue State in the Spring-and-Autumn Period collected in Zhenqin Study noted the historic fact that King Zhougou of the Yue State continued the policies of the late kings to aid the ruling elite of the Xu State to recover their state.Re","categories":["02_字词句考释"],"year":2010,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhaZzgukKK_ujK1EXx5llLTpPjJZ1AHRhFHelV01phkBkxxTTwFWDoGj0BJY-MCtMap39tMIMtLxWUz55lv8FJn5TwJrOk8FPeBixOcToZrADNy1cpXCOiXDsRie-I64r0J4TYeq-TAwHqh44EdsJta21uMTJsQQBWR5Ww25_JYw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-90","volume":""},{"id":5170,"author":"陆德富","title":"战国兵器铭文研究二则","abstract":"In inscriptions on weapons from Sanjin States,ye(冶) is the abbreviation of 'yeyin',which was the title of lower rank official. On bronze weapons from the Qin state,inscription'gengzhang'refers to gengren zhizhang (the headman of gengren). In the Qin state,criminals were generally called as 'gengren'","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzeAEQd48pdgOTwBWvGorLIX5HVhytPkeBDV7BvyUdzIlfLsQ8YyZhCJyxDK-Il7S2Au3FNoyXqepg_RQBOypD3PKXOclRJIfCG2AcD6qt5jc7RSi0_wouxlXaEA8F1TT4th9F5auVfH45IqjUX5lFWp3i1u3fXUK4d9ZBVFnOTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-51","volume":""},{"id":5171,"author":"李建西","title":"西周金文“白金”初探","abstract":"Based on archaeological discoveries and relevant research,this paper comprehensively studies &quot;baijin&quot; (white metal) mentioned in Western Zhou inscriptions. Results show that &quot;baijin&quot; should refer to tin (probably include lead) which is one type of important raw metallic materials","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcsQBhRoLIgjcjZSHG_tjHme6CbegpS80DX5fCastMpOZ17bI1Dj9Y6NFaRLAEKH4jJLhKg0aEt-4RLz3A4b7MuCJynRNcxj3N4cOH6xSwK8hB-2Ye-mWOqye7_GtxpnbCcBiWS1fTNnbev1VaGnyXd1BpZC5QEqTxxbzgfUTugg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96-101","volume":""},{"id":5172,"author":"陈英杰","title":"商代金文中之“女子”铭辞说略","abstract":"This paper discusses the inscriptions 'nvzi' (女子) on bronzes in the Shang Dynasty. The author points out that 'zi' (子) in inscriptions which structure is 'emblem + zi (子)' refers to 'zongzi' (the eldest son in a clan). Compared with 'zi',inscriptions with similar structure like 'emblem + nv (女)' mea","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyodccg_zhDfnj8r5-5zvYQnwN9Rq8aoFRaOXKKdJyP6W8pApJbZb4pmtxsaPlP_V7ldZfyPCohlxd9Z11iPPyQqUyVr-3vgQQwb6eK0sws5Ws27T7x9sImAV9aISMl8pMaPO6FtlixynyJ6_EHrbUfWKuT15viYxvJ9HnUxKKOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-109","volume":""},{"id":5173,"author":"钟义荣","title":"汉字构形系统发展规律及简字造字规则","abstract":"在分析汉字构形系统发展各阶段特点及其继承、衍化过程的基础上,探讨了汉字构形系统发展的整体趋向和规律,并以之为基础,总结出汉字简化与造字所应遵循的一些规则。","categories":["02_字词句考释"],"year":2010,"publication":"安康学院学报","link":"https://link.cnki.net/doi/10.16858/j.issn.1674-0092.2010.04.010","pages":"28-29, 55","volume":"22"},{"id":5174,"author":"史党社; 田静","title":"从称谓角度说“秦子”","abstract":"在传世文物与考古发现中带&quot;秦子&quot;铭文的器物有多件。对于&quot;秦子&quot;所指,学者有不同说法。本文结合文献和金文,从称谓的角度分析,认为&quot;秦子&quot;应是春秋早期的秦文公太子静公。","categories":["02_字词句考释"],"year":2010,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL9272uhL_5uYwSw6LzN6SqvWbefdi8mB9CP-gskzUUEQ24y_JE5F-zqkLcZkRVeIqOmzam8_i98TtzaPdteWlc7WYaV5RGjH761CoQJ4M5glzKZTpT_lIgypvzgmFQOJXgBV_39Kgobzo4elVhYrAq1xYgQah9N9mADoVjPbXeLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-72, 77","volume":""},{"id":5175,"author":"李彬","title":"“日、月”时间词考释","abstract":"从汉字构形本身出发,对与之相关的&quot;日、月&quot;时间字形资料进行系统地分析考查,从而揭示出汉先民传统的时间观。","categories":["02_字词句考释"],"year":2010,"publication":"新余高专学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFE6ZEvTbm-_bq0QY4sLBJLTwuQJlRmyx63lL74E6NTTWyU4gnQGNCFGBraxes80Jc8SoNU8mpV5Zcz4VrZrqaLpC-213ADFgNodkg9kXZzYnxJmJmkx3MitVhEfod1yQ6K-06z1yEUiayLAqslnF_5wsxuq4siRoXxEPsgqXAeA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-66","volume":"15"},{"id":5177,"author":"杨怀源","title":"金文常用词“休”及其赐予义同义词","abstract":"&quot;休&quot;是先秦文献和金文中的一个常用词,论文讨论了金文中的&quot;休&quot;的意义系统及其&quot;赐予&quot;义同义词。","categories":["02_字词句考释"],"year":2010,"publication":"重庆三峡学院学报","link":"https://link.cnki.net/doi/10.13743/j.cnki.issn.1009-8135.2010.04.019","pages":"112-114","volume":"26"},{"id":5178,"author":"秦晓华","title":"“各(格)”、“至”、“到”的演变与更替","abstract":"通过对表&quot;来、到达(处所)&quot;义&quot;各(格)&quot;、&quot;至&quot;、&quot;到&quot;的考察,认为商周口语中,&quot;至&quot;已占绝对优势,至于金文&quot;各&quot;用例较多,显然是由于金文典雅庄重的风格所致。&quot;到&quot;是&quot;至&quot;的分化字,《诗经》中虽已出现,但用例罕见。传世文献中,&quot;到&quot;和&quot;至&quot;的竞争历时很长,但在秦汉口语性很强的出土文献中,&quot;到&quot;的优势已然显现。","categories":["02_字词句考释"],"year":2010,"publication":"河北广播电视大学学报","link":"https://link.cnki.net/doi/10.13559/j.cnki.hbgd.2010.04.003","pages":"46369","volume":"15"},{"id":5181,"author":"徐新亮","title":"春秋金文用韻韻例簡析","abstract":"春秋時期的金文押韻時韻腳字在句尾,有逐句入韻和隔句入韻兩種方式,銘文中押韻時有換韻、交韻、抱韻三種類型。","categories":["02_字词句考释"],"year":2010,"publication":"宁德师专学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMRdFq4atYzVuJ8jfvyWOgkdPA892YAuKGbLsBMQRWXbPM39vHY6D2cHmCXBXtQPIMGpeZA9Kx-D8zHMBeGuiIZM6CNHq9wnZjFH5YB9moXbEBmRMMDBWIPuc-abpjuTUQMkuIZuNDVQzqCbROhm__hsG5bxAHQiiV_DlduV_C0w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":""},{"id":5184,"author":"高嶋谦一","title":"古文字诠释的一种新方法——以■(■)字为例","abstract":"文字考释是甲骨文研究的基础工作,是甲骨学前进的基础条件。自甲骨文发现以来,文字考释取得了巨大的成绩。但随着有较多资料可资佐证的文字的被解读,剩余文字的破译越来越难,甲骨文字考释面临很大的困难。据粗略统计,甲骨文共有单字约四千多个,得到考释的约两千个,得到学界公认的约一千余个。还有大约一半文字没有得到考释,这其中有相当一部分即是因为这些文字只见甲骨文,后来不再被使用,缺乏传承和沿革的历史脉络,缺乏足够的材料推考其字义。对这部分文字的考释,只能依靠甲骨文本身,这就要求在考释方法上加以创新。高嶋谦一《古文字诠释的一种新方法——以■(■)字为例》一文另辟蹊径,提出一种新的文字方法。作者认为■和■、■非","categories":["02_字词句考释"],"year":2010,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaI2zcIZw2yn7ohG3NdIWZFu1UQfmIwNzIz6RPBSwGB3u1IBQwMBm9h8dJ5iwZdSB_5qVlli8KFP3GYGxI-_PR0LXx2Qz5S_9rxAt9l3xzoUl2GFzIn1Pcb-WRGoZ5rP1gw5EKYkr5cOM44PfBWDt5VcHscym9T400GZuKowyQLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-62, 58-59","volume":""},{"id":5185,"author":"谭佳","title":"《春秋》与“義”:“義”的文化渊源及内涵之探","abstract":"虽然《春秋》全文并无&quot;義&quot;字,但&quot;三传&quot;通过阐释《春秋》之&quot;義&quot;,正好衔接了&quot;義&quot;在此前后的文化内涵,将本来仅是针对&quot;天-王&quot;关系的&quot;義&quot;扩展到&quot;天-王-诸侯-大臣&quot;、&quot;中国-蛮夷&quot;的维度。孟子和其他战国思想家又进一步将其扩展到君子修养和普通个体的心性使用层面,&quot;義&quot;成为一个重要的伦理道德性范畴。这种衔接并非巧合,&quot;義&quot;之所以成为阐释《春秋》的核心,其根本原因就在于《春秋》的文本性质与功能具有&q","categories":["02_字词句考释"],"year":2010,"publication":"百色学院学报","link":"https://link.cnki.net/doi/10.16726/j.cnki.bsxb.2010.03.003","pages":"13-20","volume":"23"},{"id":5187,"author":"连佳鹏","title":"释■","abstract":"甲骨文&quot;■&quot;字习见,作■、■、■、■、■、■、■、■等形。&quot;卜辞用此字凡有二义:一为方向之名,即后南析为南字者;其一则所祭品物之名。例如‘一’、‘二’、‘三’、‘五’、‘八’、‘九’、‘十’之类。&quot;①但所祭品物具体为何,原来学界看法不一,现在虽趋于统一,然亦误。","categories":["02_字词句考释"],"year":2010,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8cWOPdvO4YJquq4G6EuKcXRS3KU7FtoUbO2j1c2mzHOB6HXDQMFcnf0DrWIgUiJNWdRl8qK4q-wOTlusVTHxQO1z7OHQ1JcKyvZP-J_Y6-j5U6vtiK44U_1fSBi_KN-plJbr7mgelf-yzti8zUI65Yzul52SyM-qOc8vC2zw2VA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-41","volume":""},{"id":5190,"author":"韦心滢","title":"季姬方尊再探","abstract":"本文对2002年刊布的季姬方尊铭文中的几个问题做了新的探讨。本铭的君(即宗妇)不仅能命令宰,并且拥有支配宗族内财产的重要权力。君对季■姬的赏赐内容采用土地与民人结合计算的方式。铭中首见的&quot;(田又)臣&quot;是依附于贵族土地上的农民,在此作为集合名词,包含师夫及厥友,拥有牛马等生产资料与一定数量的生活资源。","categories":["02_字词句考释"],"year":2010,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6YoP10EURntFlEDRmicV1RJI_RsONdvyupNFNvPK7tFz51Ehdrk1C-GAZuB8PyVwWt8tJ9oBu1Xum_ey2bAkrWPmfNtV9f0p7Ndp_Z_KEYX6XZhi9ClCkm922cFDy9XcpO6nlDO3WyxY5N5GaG5gJo0IpGTc3hr1XmiUH-UKmlA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-61, 66","volume":""},{"id":5192,"author":"徐子涵","title":"“父”字别谈","abstract":"汉文字记录了中华文明的进程,祖先在造字当中运用的智慧使得后人能够读懂几千年前的文字经典。本文以&quot;父&quot;字的甲骨文为例,从两个方面对其造字进行了新的解释,主张用最直接、最原始的感官去感受每一个字与我们每个人的生命。","categories":["02_字词句考释"],"year":2010,"publication":"青年作家（中外文艺版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpG4DWBsB2U20Q5lttb3YpPT2PkRzSvR-C9ik-Z28s18xTzPzLgG91aig3hsOyhVrDP63AJN_dQZ40w8Qz5J0lRsSu5xzo-tuyZQQH9LRwDzSvlZP06ruMkIk85_EIAfr_iL0Ae4hgkcoIWexaEujqZI0oOVi0wZQYRdDTN7BDmQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36","volume":""},{"id":5193,"author":"余佳","title":"释“保”","abstract":"本文首先分析了&quot;保&quot;字从甲骨文、金文到现代汉字的形体演变的大致情况,同时从古籍中翻阅收集了大量的实例并综合各家的看法,力求从一个更开阔的视野出发,再现&quot;保&quot;字的字形演变和字意引申变化的历史。","categories":["02_字词句考释"],"year":2010,"publication":"青年作家（中外文艺版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJN7T-E-GUKKYKIav55yYVnWlNe4_MFtj3e_ERmwz-N7TotZ5bBSAy7rO1YwnDLx3jjgdmtfibZzgELd1RC4jFY7V52N2x60aMSwlGHmfVphjj3K7pQgrLJbucp7z_N4fqS2LqGDKH3FTq5EpmPFysInEd7NO3ZDIAEiicVKH4Ng==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-38","volume":""},{"id":5195,"author":"王兰","title":"释■及相关诸字","abstract":"《金文编》■字条下收有七个字形,学界原释&quot;造&quot;。本文结合字形辨析、铭文文例、典籍文例等综合论证,认为其中仲爯簋之酝字可释作&quot;送&quot;,可能是金文中送字早期出现的附画因声指事字的形体;而傦字条下其余各字可能是金文中送字早期出现的表意字形体,其字形承甲骨文紃而来,可看作送字分别添加辵符、宀符、水符等的繁体。","categories":["02_字词句考释"],"year":2010,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLchVAeJ_8-WhELVIqofKrxH4FqhrAYb0DXO0t_wjGFQXHJ9CpwKHAo45Qu13SQDE5-MZ1WgQg-AYJSV1KtDZEy5_HU1ootmn09KO9T-KmhDPr4U6B1GOzpZ59JegHofHnl01TIf2GLsOajMf_1i2Gtftp2bJ2X9ceLxXoNaYDMlA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-76","volume":""},{"id":5196,"author":"秦晓华","title":"三晋彝器铭文札记两则","abstract":"本文包括两则札记:1.将十七年平阴鼎盖及兵器&quot;叚工师&quot;之&quot;叚&quot;读为假,为暂时代理之义;2.读十一年库啬夫鼎之地名&quot;贾氏&quot;作&quot;五氏&quot;,地在今河北邯郸市西。","categories":["02_字词句考释"],"year":2010,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJAHjaz2tX4P9faBKkgvq3jjdCAZNT-oy_r6tw--ZPinArraNHLfk8vwgHQsTzsoZyRf9gLSkTtinCgCc-ycsEUOpFRLtC-9oR7mkaMMc8ZoGJ7IsVIF3sGZg6nNAfgPizfEX0N6mZ6XeVPnmHD_wGv2rO1RtOKPiNh8pvE9kIFw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-120","volume":""},{"id":5197,"author":"李建西; 李延祥","title":"铜料名称“■铝”考","abstract":"本文在前人研究的基础上,进一步分析了金文&quot;■铝&quot;、&quot;赤■&quot;、&quot;黄■&quot;、&quot;玄镠&quot;等词的词义和词性,初步厘清了&quot;■&quot;与&quot;铝&quot;、&quot;镠&quot;等字(词)之间的区别与联系,表明&quot;■&quot;是一个物质名词,是西周晚期至战国时期金属铜及其合金的统称,它可以与具象的个体名词&quot;铝&quot;(金属锭)构成双音节个体名词&quot;■铝&quot;(铜锭)。由&quot;■&quot;构成的铜料名称有&quot;■铝&quot;(铜锭)、&quot;黄■&q","categories":["02_字词句考释"],"year":2010,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIC1pF_-zZea1ODBXK8GKvua3pyViTE0Y4DbRPV8KNVSs4OjHT0MRg9qwBZqHKSc5ZZ6yhDk_Q1Y6rzuTF_V6WxnwrHxYRxi36jkQichWqA0J9VvSEzdCUgv2TjBQ8oCsjp26iHymmi5lf1I1Bm0NpQZkUq0uqklHfY52QvZFC2Aw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-130","volume":""},{"id":5199,"author":"李学勤","title":"楚国申氏两簠读释","abstract":"《楚系金文汇编》六六、补编四四两件春秋晚期簠铭器主分别为&quot;申文王之孙州■&quot;与&quot;申王之孙叔姜&quot;,学者以此认为申曾称王,当时且已复国,此说同史实不合。两器均属楚文王后裔申氏,叔姜则系申氏之妇。","categories":["02_字词句考释"],"year":2010,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLb1cWvNHbw_eML8_9BPY6ZimS1RmJ_ux27i0ZZMgd80E_l1b6LDY5EPeQkyZRFpJbyYnjY5ugW7dciTUcV3Uzhw-J7rchN8LmPC9MU4OJRox5CMDCAK2tt2M6DolItgO7qpoGapjA5ZlstMk7wU2d-sivCzySnmRAM3yBMtzKB5w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-118","volume":""},{"id":5201,"author":"王宏","title":"(旡可)簋、(旡可)尊非同人之器辨","abstract":"本文拟在参考《(旡可)簋铭文与西周史事新证》一文的基础上,将(旡可)簋和其他相关铜器以及铭文相比照,在确定(旡可)簋为成王时期标准器的前提下对(旡可)簋与(旡可)尊器主的关系作以尝试性探讨。最后附带说明学术界对于&quot;(旡可)&quot;、&quot;(旡可)&quot;二字的隶定标准。","categories":["02_字词句考释"],"year":2010,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2010.02.025","pages":"21-24","volume":"31"},{"id":5202,"author":"蒋书红","title":"闻尊铭文考释","abstract":"闻尊是一件新见西周铜器,目前对其铭文的释读尚未完善,尤其是其中&quot;朕采田外臣仆&quot;一处,为整篇铭文中的一个重点,在释文、断句及释译等诸多方面,尚需做进一步探讨。这一处应该独立成句,无需点断,意思是&quot;监管(那些居住在)我的食采田外围的臣仆&quot;。其中的&quot;外&quot;与其前的&quot;田&quot;构成一个方位短语,而非与其后的&quot;臣仆&quot;构成一个偏正短语;&quot;&quot;作动词,意思是&quot;监管&quot;;&quot;田&quot;是食采的具体名称。","categories":["02_字词句考释"],"year":2010,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7otElumH4KCpdpp0JNoIuwWE1AiaZHDiYaIxJ2zQOORY4ZpMEJgwr6He85_jOe6KsEXyWoOWIZppDyCgkowHgJEcDyxtx_V07mhHrklbjZ9RGRzB8NM-IyFDOqssfVNscPffYrIyFiCtnc5fQK3bIIG2AFMXkVQqhH3bgVvHPAQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-73","volume":""},{"id":5204,"author":"任相宏; 张光明","title":"高青陈庄遗址M18出土豊簋铭文考释及相关问题探讨","abstract":"高青陈庄遗址的考古发掘是近年山东乃至全国商周考古的重大发现,尤其是西周早期城址、大型祭坛、甲字形大墓、殉马和甲骨文(见图一至图七)的发现,填补了山东商周考古的空白。特别是18号墓出土的青铜簋,铸有11字铭文,且自铭&quot;齐公&quot;,为首次发现,为确定该城址国别和性质提供了绝好的证明。所以这些发现为齐文化的研究提供了极为重要的实物材料。","categories":["02_字词句考释"],"year":2010,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2010.02.021","pages":"97-102, 0","volume":""},{"id":5206,"author":"杜廼松","title":"论西周金文父祖宗亲辈分称谓","abstract":"中华民族对祖先的称谓,有着深厚的历史文化积淀,在商周金文和文献中均有一定的反映。近年发现西周长铭铜器中,一些铭文内容为祖先称谓和辈分的研究,提供了新的平台。本文结合甲骨文、典籍等资料,对西周金文中的父祖等辈分称谓进行考证研究,其中尤重&quot;亚祖&quot;、&quot;高祖&quot;等的考释和分析。","categories":["02_字词句考释"],"year":2010,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2010.03.006","pages":"140-149, 161","volume":""},{"id":5210,"author":"吴国升","title":"春秋文字字形讹变现象的考察分析","abstract":"据当前所见出土古文字材料,春秋时期发生讹变且有明确线索的字例有宜、穆等25个,其中9个春秋时期即成为定型,7个成为后来形成定型字形的重要中间环节,另9个仅流行于一定时期或地域。讹变进一步增强了汉字构形的系统性,同时也是导致《说文解字》对相关汉字析形说义不确的重要原因。一些字形讹变还呈现出地域性特点。","categories":["02_字词句考释"],"year":2010,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKhd2Mqud2v2UYGTTR3kDQw7Ke7eNTOhnVvoxaH4tO6fRNbtw-FPUb1yhmGxoYKgvavrI4S6zm8tEtj09yuNJdLzbZimUxbZ81bvFuHYROT7RaiULr3-m6rMDre9nXmUy7QzsQlPUhbO_OoxY9Nclo0OC23h8Pw6O6mGyjsSoPn6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-99","volume":""},{"id":5214,"author":"武振玉","title":"殷周金文中的赐予义动词","abstract":"殷周金文因其特定内容的关系,表示赐予义的动词数量较多,计有赏、赐、贶、釐、饋、齎、贿、赠、畀、舍、授、稟、遗、降、绥、宾、令(命)、休、惠、、匄、↑诸词,构成了一个丰富的同义词系统。这些词在出现频率、出现时间、具体词义、用法等方面都表现出较为明显的特点。对其进行全面调查探讨,对了解殷周金文乃至上古汉语同义词的应用情况将有所裨益。","categories":["02_字词句考释"],"year":2010,"publication":"陕西师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKNWHnX14hVUeJB9QdsH5zNk87r3ZLDKwteSS3N9YHMvG8IVJOp6-2vKDyonIxNkCT4HJUebDdkbdva_JhuAYczfrodBTAVh1IZkGDMb6f57tHK5uN9qwCiAQRXHEPl_hO7se7YJA-pIbKlTp4lEqDyfd4BB8BqTwbaRXAqdUiPWw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"156-160","volume":"39"},{"id":5215,"author":"武振玉","title":"殷周金文词汇研究综述","abstract":"与殷周金文有关的词汇研究,可大体分为两类:一是对具体词语(特别是疑难词语、特有词语)的释读,这方面的工作,应该说从宋人就已经开始了,经清而近代现代,成果众多,但或作为研究历史、礼制等的佐证,或为铭文释读的具体目的服务,语言层面的专门研究还很有限;二是从语言角度对词汇进行的研究,或将殷周金文视为上古汉语词汇史的一个重要组成部分而展开全方位的研究,或侧重复音词的研究,或关注构词法问题,或侧重同类词同义词的类聚比较,或对某一个词进行深入的词义探索,或致力于与传世文献的对读比堪。角度不同,但对语料的挖掘已日益深入。这方面的研究起步虽晚,然成果已颇为可观,且未来的发展态势极佳。","categories":["02_字词句考释"],"year":2010,"publication":"西华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19642/j.issn.1672-8505.2010.02.016","pages":"82-85","volume":"29"},{"id":5216,"author":"徐山","title":"古文字考释四题","abstract":"文章分别考释了&quot;存、衡、晝、宁(zhù)&quot;等四个古文字。","categories":["02_字词句考释"],"year":2010,"publication":"南阳师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLcEpXabNMkOnoFB4h0JrUr3ybPglM3B0puT-RQ2POtw9Re37Gu8wVkfINH7gPX7qxHu2QCTZYEhSWWg3cjpCrAjhY58jbYwtttRxCHPiui6Zo1LeMJMyVR5hYnDVXW6rhBCwVfzRkeZWz67Dn2U8cVlpkARgE0lA-TEZCjfCs8RA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-65","volume":"9"},{"id":5219,"author":"刘林鹰","title":"德字古义新考","abstract":"德字在古代有利他论和&quot;德者得也&quot;两大类解释,其中&quot;得&quot;论在文字学著作里占主流地位。&quot;德者得也&quot;一语始见于《管子·心术上》,后世文字学作品以之训诂,是断章取义,因为,其内涵性论述语境是&quot;物得以生生&quot;、&quot;舍之之谓德&quot;,而且,&quot;德者得也&quot;之解释,前后句子一般都是自相矛盾的。&quot;得&quot;论的当代形态即甲骨文里德字没有道德含义的观点难以成立,当代学者提出的德为全生保生之新论也难成立。德字的本义是指修身或在公共关系中处事正派,这是对德字古义的否定之否定式的新认识。","categories":["02_字词句考释"],"year":2010,"publication":"船山学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFS7WAkCii74swMCnIE_OCnyYyrPbRpodYN9Emr0WtAmMoeokA7qcvb0UaxkwKvpQVCOWQLjRlcDzuu-3tmSbPDOEmwQOHwL3OKi1gNaIyASIIN6FondAZ20DmijyOoyzGBqgE1D0C3nTSgn-5Cxne6Fiq8gQgd6Xp2UN-iHSRNQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"183-185","volume":""},{"id":5223,"author":"吴镇烽","title":"内史亳丰同的初步研究","abstract":"内史亳丰同的初步研究本文介绍了新发现的一件西周早期内史亳丰铸造的青铜&quot;觚&quot;,自铭为&quot;同&quot;。铭文记述了成王赏赐给内史毫丰祼酒,毫丰为纪念此事,铸造了这件祼祭用的酒器——同。该器铸造于康王时期,其铭文可与《尚书·顾命》&quot;上宗奉同瑁由阼阶隮……,太保受同,降,盥,以异同秉璋以酢,授宗人同&quot;的记载相印证,冰释了千年以来关于《尚书·顾命》&quot;同瑁&quot;的纷争。","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZDp1VaC1EBGNrCF6iGXQERHmIbV-79ozOXoWFM6LnPTRZgZ0YZ_JswO7Ldn4agOUjCRbIMozEVQcFQiu-ir7Ou0b52SOCQSz3uV__--WkYKUVh6tsL1OuQkLhvNEyCKxNuFq-D5_Ux0LBxezBtdmaCy-DFPeBWnkHTDOBmcSiag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-33, 129, 2","volume":""},{"id":5224,"author":"王占奎","title":"读金随札——内史亳同","abstract":"本文经对内史毫同铭文的考释认为:1.该器属于康王之世;2.作器者亳可能是见于文献的作册度;3.器名为见于同篇的饮酒器——同,而该器器形是以往所称的觚,应当根据此铭改称作同;4.同当来源于竹筒。","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLP4XHZvAefw3TPZy2mSkgOdo1e50vKMwzLzigwF9wFlOdz5-F28DGdFgTlUv0Xu9R_diEBX4i-0K5KlTBK0ppHyW2djQkf1ikK5Vuw4nKKtOVd7zwzCyw1nim097pnAKHNLwPJIhaJ-dLFXbDVrXO9ABbBJYXmb0f8-E1B3zbBfA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-39, 2","volume":""},{"id":5226,"author":"李学勤","title":"试说青铜器铭文的吕王","abstract":"1924年,王国维先生作《散氏盘考释》,文中论及盘铭&quot;夨王&quot;,说:夨僭王号亦见他器。……当宗周中叶,边裔大国往往称王。《史记·秦本纪》有丰王,彝器有邵王鼎,有吕王鬲、吕王壶,而录伯(?)敦云:&quot;作","categories":["02_字词句考释"],"year":2010,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLlNizIMM-4FMXdPfmgX0gwGGSH0S_UwRFEyH6sB0Xu1JmdqN9j9PljudmcmeCtvSQdi979I-ZOp5iQecSJYXXtFvZrH82WpE7c8OCM8PDerQb9Oo5Bozsv3jL8xMBHF-hZGu1Wgayikj7Yrtj9NqOepNd712q45ORitTNqSCDpPw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3, 42","volume":""},{"id":5227,"author":"郭静云","title":"幽玄之谜:商周时期表达青色的字汇及其意义","abstract":"先秦时期已有白、黑、■、黄、幽五种基本颜色的结构性概念,其中&quot;■&quot;表示血红色,&quot;幽&quot;则表示青色。将&quot;幽&quot;理解为&quot;黝&quot;,应是汉代以来的颜色观念。殷商祭礼中,牺牲的颜色受到特别关注,具有神秘的象征意义。&quot;幽&quot;色在殷商时期的语言中,可以涵盖天之苍蓝与草叶碧绿等色。在形象上,&quot;幽&quot;为高山之景,故其字形始终从山,这也影响了&quot;幽&quot;的字义向昊天不明、黝冥的方向转化。从文字发展脉络看,&quot;玄&quot;与&quot;幽&quot;原为同一字;两者字义直到周代才开始","categories":["02_字词句考释"],"year":2010,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvMFvzMkl8JC_iELG09YaGEWsK6N5XfrEWbihyrMMSXJ3WLp1OZ3cgKKgBytICTTFO0qpgvmeoOyXzusJwlR0OvyV14psAQYxDAU80mvYI8S527hQteTZ0YGJ7By4IIbo-pACcevaIJJiCsoNs05mNjqn3qK_j6_EKra-rhSiTig==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"4-24, 189","volume":""},{"id":5228,"author":"侯乃峰","title":"鲍子鼎铭文补说","abstract":"新发现的鲍子鼎铭文,经吴镇烽先生考释,基本无疑义。本文仅对铭文中&quot;君&quot;字的理解略事补苴,并对&quot;柬&quot;字的考释提出不同看法。认为&quot;柬&quot;当读为&quot;间&quot;,训为&quot;间隙、嫌隙、隔阂&quot;等义,是作器者鲍子委婉地祝愿鲍家的女子仲匋姒不要被夫家所出的意思。","categories":["02_字词句考释"],"year":2010,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGTZWMMhP_Q0I92ehz2OtsAxM9npBo3f8rUENa9UXjOYsH_4C3qHOkzzfckTI0Jv6ZWOK7cR6MrKmAGrm_sqJmtjrsN_xS38IZy3f8-v2M_dIrSCl8l5ubaVIco2lINLGkzSq5nUzzHqRUCk_ufomavfXODK4vZ6-JG5-2vE7yow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-72","volume":""},{"id":5229,"author":"程燕","title":"鲍子鼎铭文补释——兼论邿子姜首盘铭文中的“及”","abstract":"本文根据字形比照,将新见铜器鲍子鼎铭文中的&quot;思&quot;改释作&quot;瞏&quot;,并将鼎铭与邿子姜首盘铭文进行对比,认为二器中的&quot;及&quot;用法相同,皆应理解为&quot;跟、同&quot;之意。","categories":["02_字词句考释"],"year":2010,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVpIw8EddvSuh4KN0t1HSaP10zNWXAwfCw8JbfnqnXrsT7-HZbvpWLji239KVrW14N0uhYXpeTsIFxT9CK_emqFOuGYpolk3gvF3qi7_aTECNHHFwSjmOxoQunMD5OVZaaRsir1di43yY2HHD_dBjCK1UK0uF805grVnrm3JO6wQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-74","volume":""},{"id":5232,"author":"李品秀","title":"释“享”","abstract":"&quot;享&quot;字古字应写作&quot;亯&quot;,先秦&quot;亯&quot;字即有&quot;献&quot;义,但关于其造字笔意,各家说法不一。&quot;亯&quot;字笔意应为城邑内供祭享祖先、神主的较高建筑物之形,本义为祭享之所。引申出宴请、孝养、享受、亨通、烹煮诸义项,后分化出享、亨、烹三字。","categories":["02_字词句考释"],"year":2010,"publication":"乐山师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIwHSF2jqC0DPqQxvBG9bUBjpuiPss1hbgIkRCcNPeXFF9WiifENUVvuqwwTrBslZYx3Q3rr3zzmb3EnvI4Us2QLpsyXAov-kVUwLjbo8q47hpuIn_SibMSEJFpQ4q5zb7-HZBNAMM5gbpYMTfahAWx8zVZPH5g-CzzXAIJPEexLA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-57","volume":"25"},{"id":5233,"author":"刘光胜","title":"《大戴礼记·曾子立事》篇题考","abstract":"根据战国时期的青铜器、陶器铭文,&quot;立事&quot;意为主持事务,禀行政治权力,但《曾子立事》主要讲君子博学、笃行、忠信、事君父、敬师长之事,篇题《立事》与内容矛盾还是有更深刻的思想根源?隋唐时期,《曾子》有两个版本,一是《大戴礼记.曾子》,一是二卷本《曾子》,它们之间最大的不同是《大戴礼记.曾子立事》篇题,二卷本《曾子》作《修身》,它们谁先谁后?谁真谁伪?我们借助上博简《内礼》和战国时期的立事铭文,对这些林林总总的困惑进行了检讨。","categories":["02_字词句考释"],"year":2010,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2010.01.027","pages":"18-23","volume":"31"},{"id":5234,"author":"张富祥","title":"利簋铭文新释","abstract":"利簋铭文直接涉及武王克商的重大史实,记载周武王&quot;甲子朝岁鼎,克闻,夙又(有)商&quot;,&quot;岁鼎&quot;即&quot;岁正&quot;,&quot;克闻&quot;犹&quot;克殷&quot;。全句意指周人于夏历的岁旦之日打败殷人,清早占领商城。而旧释多不可据。","categories":["02_字词句考释"],"year":2010,"publication":"山东大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIk_pe90MIziDUiBmuu_bHTHA9xBCu40RpZLDiYUf_QqF1pwGmfmS-orAybSS5eM0ZdpS736LtGJ9a1R0Z5pbzMjsXhJVGGGr_XjQ34RWZuaI1_4LqfioJaXgGRREpq_1oUDkflms62KqBRQ8TzmD05B-TvNXOhtniqsGVGAXUrw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"132-137","volume":""},{"id":5236,"author":"周克林","title":"东汉“五利后”铭文解考辨","abstract":"文物是一个民族社会文化的重要见证。&quot;五利后&quot;是东汉时期主要分布于西南地区的特殊随葬品上的一种铭文,研究该铭文具有重要的历史学术价值。到目前为止,具有&quot;五利后&quot;铭文的文物已出土四例。对于&quot;五利后&quot;铭文的含义,鲜明先生在《再论早期道教遗物摇钱树》一文中认为&quot;五利后&quot;三字应分为&quot;五利&quot;和&quot;后&quot;两个组合,分别意指汉武帝时期著名的方仙道代表人物栾大及其后人。然而,经我们考据,这种解译尚为不妥。我们以为,&quot;五利后&quot;铭文中的&quot;五&quot;字应该是指&quot","categories":["02_字词句考释"],"year":2010,"publication":"求索","link":"https://link.cnki.net/doi/10.16059/j.cnki.cn43-1008/c.2010.02.047","pages":"214-216","volume":""},{"id":5237,"author":"祝振雷","title":"从铸叔皮父簋铭校正古书中对“一月”的误识","abstract":"本文从铸叔皮父簋铭文出发,首先论述了作为月名的一月和正月在甲骨文中的更替过程,再论证从西周之后,金文中没有以一月为月名者,由此证明铸叔皮父簋之&quot;一月&quot;在很多著录中旧释不确,当释作&quot;二月&quot;。并以此推断传世文献《逸周书》和《伪古文尚书》中出现的几个&quot;一月&quot;亦当释作&quot;二月&quot;。","categories":["02_字词句考释"],"year":2010,"publication":"西华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19642/j.issn.1672-8505.2010.01.015","pages":"79-82","volume":"29"},{"id":5240,"author":"徐山","title":"古文字考释三题","abstract":"分别考释了&quot;麗、鹰、刀&quot;三个古文字,以期对古文学学习者有所启示。","categories":["02_字词句考释"],"year":2010,"publication":"安阳工学院学报","link":"https://link.cnki.net/doi/10.19329/j.cnki.1673-2928.2010.01.022","pages":"74-76","volume":"9"},{"id":5241,"author":"吴毅强","title":"赵孟介壶新研","abstract":"赵孟介壶,共两器,20世纪20年代出土于河南辉县,现藏英国伦敦不列颠博物馆。该器有铭文19字,铭为:&quot;禺(遇)邗王于黄池,为赵孟庎(介),邗王之惖(锡)金,台(以)为祠器。&quot;(《殷周金文集成》9678及9679)该器自出土以来,已有十余位学者对之进行了探讨。目前,诸家对该器年代的认识基本一致,多数学者","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKauBZU_mwHPQc2WLA6ngtuzBg0GjNrWdTMbhBiBP2PzzrfhpZXjGZy1EpPApIvzkjc3XFHoGI2ePpfHJOlcf7beXvWbyWxma4IxAe3E4V87gkd_cvevfEVLXSEzScmN8VORVRATUWyrJZOcpLQU8O2L4dw8bJZyvzI4z14uSyGVw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-68","volume":""},{"id":5242,"author":"涂白奎","title":"说何尊的“復……自天”及相关问题","abstract":"何尊铭自1976年发表以来,经过多家的考释,虽然在某些问题上还存在分歧,但文义似乎已经比较清楚。可是如果对个别被大家认为明白易晓、不难理解的句子进行认真推敲的话,或许还存在一些问题,这些问题影响到某些关键问题以及与此铭相关的其它铭文的理解。本文要着重讨论的这个句子,就是铭首的&quot;复禀武王醴裸自天&quot;。为行文的方便,先把何尊铭以及在讨","categories":["02_字词句考释"],"year":2010,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ7WwiYBadBiYfV8znW2273S77DEFJuztVG-J5cp7ihthJCfI11mmo32uD5qn7qdliNxf0lNWaAZYYm12ihQZorU4_Pu4G6x8dakMyURdltrL3Eq4u8XwTyJ_dAzn1JMjjsCoo34nvfAkht_fvWy4voWEd9ru57sE8oWAlePc-h3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-94","volume":""},{"id":5243,"author":"何渊; 李蓉","title":"西周金文联绵词初探","abstract":"我们共确定西周金文中有七个联绵词。根据联绵词的语音特点和使用情况,可以把西周金文中的联绵词分为三类:双声联绵词、叠韵联绵词、非双声叠韵联绵词。研究发现,西周金文中的联绵词与传世文献比较,意义没有太大变化。","categories":["02_字词句考释"],"year":2010,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL1AjnSQ8GxGc2B3iDyCSG4dQZ6KJLH_8-hl32H-N8KYU1qRjEKeAyJjLs6bUT_rRho-TG8WAT5E-HMXt6zUoQTfGXhFsXRyRUKXtOFf71h0omH2KRgH2_0IL5ZAxMOhdl4hjP83UgaKxw06IvY4FXdsryc-3XdE7f8QHuiXIbs0Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"212, 211","volume":""},{"id":5245,"author":"刘桓","title":"商周金文族徽“天黾”新释","abstract":"商周金文族徽&quot;天黾&quot;,近人多释为&quot;天鼋&quot;,即黄帝轩辕氏,其实此说乃出于对《国语.周语下》&quot;我姬氏出自天鼋&quot;一语的误解。是语主要讲周武王伐殷时的天象及相关传说,天鼋即十二次之玄枵,玄枵所对应的齐地有殷代逄(逢)伯陵的后人大姜嫁与周大王(古公亶父),因为周人从此勃兴,故有此说法。郭沫若误将&quot;天黾&quot;释成&quot;天鼋&quot;,又以轩辕氏释之。古文字黾与龟、鼄三字,现已可以区分清楚,从而可知前人对&quot;天黾&quot;二字的释读无误。解读&quot;天黾&quot;,所对应的应是进入有史时代的夏商周史料。&qu","categories":["02_字词句考释"],"year":2010,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLh8-ylfEwGpm1WgKMiLhRm5DyBMXhA5y0DUGuY8dQ7agUaXuWgDKqLvD3robQVmnMWDPeqERBc2I76m49ueWjoHXQbapj2F2ki37lKHueQEjeQdMG9Usw_PQRX51eHVuQkMZCfY96fLf7YBXGgiLAG-wWyrrAur-br2ZJ6w0ZP6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-43, 189-190","volume":""},{"id":5246,"author":"杨亚长","title":"天亡簋与太公望","abstract":"天亡簋器主的名字叫天亡,孙作云先生认为天亡就是古书中的史佚,于省吾先生认为天亡是文献记载中的太公望。本文赞同天亡为太公望之说,并申述其理由。","categories":["02_字词句考释"],"year":2010,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3u1qZE7iqZJhvzU1-PwhS2T4NHvDbVgrOTslutgaCYwwj0dNK-f_OqO4kiLrQas_JcTCes2EYQALOESfagpL838XdI6mxN-6GpQIJnhmVEULe6ALorXG6dYSrmCFhuoFd8Gyi-pozagSAAS1CupxtgaX7xlc9Bf2Wm7s40uMSlw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-87","volume":""},{"id":5247,"author":"王望生","title":"西安北郊枣园南岭M1西汉墓铜器上的铭文","abstract":"西安北效枣园南岭M1西汉墓出土了数百件文物,其中铜量和带环铜附件这两件铜器上刻有铭文,分别是&quot;私府&quot;和&quot;中厨&quot;。经研究,&quot;私府&quot;为当时皇后系统主要官职之一,&quot;中厨&quot;则是&quot;中宫厨长或中宫厨丞&quot;的简称。","categories":["02_字词句考释"],"year":2010,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIpUADvKm7V_MDqPXQ9f_eEMup_HQpPN9CNfZWBiyhY029ym0rOVxzTMJV6FUYx9sUj1RBSWj9UwiZqDoMQDleqxNEPYIDD_Etb1GNjssPXtbShCrU9U17BpVUJmu_322_CLI6dKUllcbEoaW9wTpug4y4gnoLrTGy3Kr1oP3w0EA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46275","volume":""},{"id":5249,"author":"武振玉","title":"殷周金文范围副词释论","abstract":"甲骨文中是否已有范围副词,各家尚有不同意见。殷周金文中能肯定为此类副词者计有&quot;咸、具、皆、率、並、凡、一&quot;七词。这七个词皆为表示总括的范围副词,但具体用法又有所不同,其中&quot;咸、具、皆、率、一&quot;为一类,用于总括其前主语或其后宾语所指事物的范围,为典型的此类副词;&quot;凡&quot;为一类,主要用于总括数量范围;&quot;並&quot;为一类,有表示&quot;皆尽&quot;义和&quot;共同&quot;义两种用法。与同时期的传世文献相比,殷周金文中此类副词的个体数量和总体出现频率还比较有限,但因其时代之早以及材料之可靠,其于传世文献的补正作用还","categories":["02_字词句考释"],"year":2010,"publication":"长沙理工大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16573/j.cnki.1672-934x.2010.01.011","pages":"103-106","volume":"25"},{"id":5251,"author":"冯时","title":"琱生三器铭文研究","abstract":"对旧出五年琱生簋、六年琱生簋与陕西扶风五郡西村新出的五年琱生■三器铭文的考释,揭示了铭文的本质内涵以及其反映的西周宗法制度、礼仪制度及社会风尚。结合对文献的分析,将三器时代定为西周厉王时期。铭文内容与《仪礼.乡饮酒礼》多相契合,证明《仪礼》一书来源的古老有据。而五年琱生■自名曰&quot;■&quot;,也是青铜器新见的器名。","categories":["02_字词句考释"],"year":2010,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCEhUkNCPIaNOCqCTHLKbqtyjTM-ksDpunHvMIbfhymjVDkEb-gMHaVa-HJqog0V-9OeKjdI1n2VsZ2xyo9QsCFiOIWQnW3gFMqP1v2Wogu2rqeG5sVRGxKivhfZhdK9K7Kq8KLINfxAPUb2OT7370VHn22RIiHt1e3c1Kz0E7Hw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-77, 113","volume":""},{"id":5252,"author":"何有祖","title":"广州南越国宫署遗址出土西汉木简考释","abstract":"More than one hundred inscribed wooden slips of the Western Han period were unearthed from the Nanyue Kingdom palace-site in Guangzhou. Their contents are mainly residence booklets and legal documents. The present paper makes a study of these recently published data, deciphers some characters, such ","categories":["02_字词句考释"],"year":2010,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCEhUkNCPIaNOCqCTHLKbqtyjTM-ksDpunHvMIbfhymjVDkEb-gMHaDILtstgf3_TOxCalhdjxDukkFQAyFha4NUy2Vb9bHWhCNuGBe-SpDCzv6DszTyRRb6kXXkmzrKple__pn9b1NoHqH49IYFNlqthKw9MQ50pfOyrtBBtoMA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-80","volume":""},{"id":5255,"author":"武振玉","title":"两周金文并列连词初探","abstract":"两周金文中能肯定用为并列连词者有&quot;暨、及、雩、以、与、(且)、而、兼、又、唯&quot;十词。从用法看,这些词可分为三类。一类是&quot;又&quot;,主要连接整数和零数,多用于计时的场合;一类是&quot;(且)&quot;,主要连接形容词,基本只见于四字韵文中;其余各词主要连接名词或名词性成分,表现出用法上的一致性。从出现频率看,除了&quot;又&quot;用例很多,&quot;暨&quot;略多见外,其他各词都很少见,表明两周金文中的并列连词尚处于形成发展的过程中。出现时间上,&quot;暨、雩、以、又、唯&quot;只见于或主要见于西周时期,&quot;及&quot;主","categories":["02_字词句考释"],"year":2010,"publication":"吉林师范大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKCoL2ALgHKTd6fKRxiCVwcVpEP0WYdQzwotrUzbSkFZWs6Y6Jgi4PauFJYkjGAovItO71-fehzknFwKFvBunYmizKHU03k7e5FmDH4OFvpZG68xKGYstPW4BYlzeH9pcxsWkH1GDugIS24Ge4IWk42C51sW7wWQ1xqRO8ovVKeQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-83","volume":"38"},{"id":5256,"author":"徐山","title":"释“藝”","abstract":"&quot;藝&quot;字的初文作&quot;埶&quot;。本文考释了&quot;埶&quot;的甲骨文、卜辞用法及其金文形体,分析&quot;藝&quot;的形体构造特征并梳理&quot;藝&quot;的词义系统。","categories":["02_字词句考释"],"year":2010,"publication":"艺术百家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK7f50V1TyYoBPjOFMcJwmm4yI4HcawJXxGT693m_BRQJbzC7xVN7gitgfGzBKmsaTnHVNoTaghw8O-KB79bFQrVJzDr1w5PgU6exDSNNi4rRY4gogztNSSAFY8T_rsjimuno0pfI1zyjNinix4nR3UJGWXhgZmZOpRMpxZtPHdfA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"195-197","volume":"26"},{"id":5262,"author":"刘志基","title":"西周金文字频特点成因初探","abstract":"文章立足于西周金文字频研究的既有成果,分别统计了西周、春秋金文的字频,并完成了对其分布状况的断代分析。以此为基础,进行西周字频高低端集中的原因分析:字频高端集中与铭文程式、嘏辞、义项数量及是否记录基本词等因素相关,而其中以涉及青铜器铭文文献特点者为主导因素;低端集中首先与专名类用法字相联系,此外,又与文献用字数量的限制和文献内容对文字单位的选择性限制,乃至相关字的特定断代用法相联系。","categories":["02_字词句考释"],"year":2010,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJXab9V1l-Zxku0MuX0tA1PLwRYA8gJPUDyeB88hWzopYJ6eNDFMjblmXZxn73YVSFI1q3p4TC5yKw0z88PV_G_0KEoW5Qfe6H5vfYOs9r2xrMuBfM3nvJcy1aivOP1_mhrHuOWklvrBnTnk0UV1uzhjGVABT0VvuLvedugurzow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-90","volume":"9"},{"id":6390,"author":"高正方; 郑振峰","title":"西周金文非声合体字构形分析","abstract":"西周金文是早期汉字的一个重要类别,它上承甲骨文下启春秋战国文字,在汉字发展史上占据着重要地位。西周时期(公元前1046—公元前771)文字的使用已经不仅仅是殷商甲骨文那样作为少数史官的专利,而是逐渐普及到大众中来,在更广阔的范围被运用、发展和演变。本文以汉字构形学理论为指导,运用系统归纳和综合比较的方法,借助计算机技术,对西周金文非声合体字材料进行了整理和研究。我们从325件时代确定的西周有铭铜器中,整理出605个西周金文非声合体字,以及236个基础构件,并对构件的功能、分布和构件置向等多项构形属性进行了探讨。同时,将西周金文非声合体字与甲骨文和小篆中的非声合体字作了比较研究。论文后附西周金文","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKLBvr2F88e04Wp_r2fHgDxCf92x6yo7fKMohG_vG-dGnzR1D16rqFGujYTT3M6eNPyHNvnjdX6C9poy85yAFQZnpgXVnCqmNWzeUAwAVDT9wWUL_B23xn6pVSmrCIJXr5ggARzjRGLxz8dvwozAHmubm85VkinDWUHh3h2nOtxjsKXvqq0NRTf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6398,"author":"安真; 冯良珍","title":"同体构形字的历时性研究","abstract":"同体构形字即由两个或两个以上相同的成字构件组合成的一类字,属于会意字的一个小类,本文亦简称为同构字。文中以这个比较特殊的群体为研究对象,对各个时代有代表性的字书中同构字进行了搜集整理,从数量、组合方式、构件属性、词性等角度进行了分析,采用历史比较的手法,先分层描写各个时代同体构形字内部状况,再进行纵向的比较。在借鉴前人研究成果的基础上,对这一汉字现象进行了较为客观的统计、描写和分析。最后还对其现状和发展趋势提出自己的看法。全文分为五章、七个部分：第一部分为绪论,通过《说文解字》中汉字形体的分析,引出主题,即旨在分析“同体构形字”。第二部分,总结前人相关研究成果,介绍本文研究的目的和意义,说明本","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ8NSPICb1af-4OB03R-RpaYk3ZbO0QR3O6jrLE2oTZaTnFyGDGQ8NfdLwtpTULhZ2JDxcSahhXlf1Lk2hZgYe_Q7F2p7t_5ycoWZbiRmucbf3oyu6N4gzdBbRG7KF7-6ahzcPHo85JaLp7d8AgKRhWx5p9Kg0XAY31g1HwhJgRk-jHCeWF86Ti&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6404,"author":"单晓伟; 刘信芳","title":"秦文字疏证","abstract":"秦文字上承商、周文字,而在發展演變中,秦人不断融入自己的民族風格和文化,在春秋早期渐渐産生了具有自己地域風格的文字,到戰國時期最终形成小篆和辣害雨個字形體系,而這種雙向發展並且同時並用的现象在中國文字史上是罕見的,今天所用漢字正是在秦隸書的基礎上發展而來。從文字學發展史来看,秦文字既是中國古文字之终结,又是今文之發端,是中國文字發展史一個極爲關鍵的轉折點,因此封秦文字的研究就顯得尤爲重要。封秦文字的研究我們主要從以下幾個方面入手：首先,我们封秦文字造行系统的整理,全面把握秦文字出土和研究现状,掌握第一手材料。整理主要以兩種方式劃分：根據秦文字時代不同劃分爲：西周晚期、春秋早期、春秋中晚期、戟國","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJrawqwAxAmrHKaGT9D1Sb2C3BeZNVMukY9Ij5IHCs0EFPLpuIF0dWyoljQmp3XewnLjI9hA5MIySwPmuwK85ACXu_w0JhC-RiiIw7BuMXxcz610UUvp_nCgrHZcqMsku19p-H-ZD-h3P5PvtiV4s531DFesFiTEH6LmzuycSGoIsoyQfp5cWlm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6408,"author":"史玥; 江学旺","title":"商代金文研究","abstract":"本文以商代金文为研究对象,从纯文字学角度对其进行综合研究。论文包含前言、字量字频、字形结构、集释、结语、附录六个部分。前言部分简要交代了金文的研究现状、前人已经取得的研究成果,并且针对商代金文已有的研究成果作了分类说明。字量字频一章全面统计商代金文的总字量、单字量以及字频,同时根据相关数据作了归纳总结,以求掌握其用字情况。字形结构一章详尽地分析了商代金文已识字部分各个单字的结构类型,并且作了相关的共时的以及历时的比较研究,以求了解汉字结构类型的历史演变及其调整。集释部分针对隶定字中的一些疑难字做了字形(少量涉及字用)方面的考释,集释所引文献截止到2009年12月,限于客观条件,无法直接引用原文","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaS3eZUctPTqdlR_2GI1GyKpVqUodP3-UnpdFC5w88LmWXYgKSQ0XnvCqB_Nz1SihwXROGTnIYHAHe4ai0tGaILh69c18SGaJexnenWvdJYZZecsiitXqn3DEcHNknqeKx_ZtHFqWWa8ttRhpvP_pUFp_xa6SCIJOdX2iIpWgC9lm7-oQmVQz_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6411,"author":"刘翠翠; 张再兴","title":"战国金文词汇研究","abstract":"由於战國時期是奴隸社含瓦解封建社會建立的雁史燮革期,社會、经濟、文化等有了很大發展,金文的载體青铜器的地位也發生了燮化,青铜器逐步消除了作為奴隸主階级禮器的特性,向著新興地主陪级生活日用器物及戟爭兵器轉化,青铜器銘文也随之有很大的改燮,像西周那檬普遍出现的畏篇銘文已经很少見了,大多铭文和已往作器記事的主旨無阴,内容更多的是“物勒工名”、“物勒主名”的筒单銘文。這少量的畏篇铭文及大量的筒罩铭文雕不能反映戟國詞彙的全貌,但是也能從侧面體现词彙發展的陪段,因此值得整理與研究。本文正是以這些戰國峙期的青铜器铭文作为研究封象,参考前人的考释成果,利用数据库進行整理分析,并藉助同畴期傅世文献的材料,完成封","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIUgYV4kpC5AKMlPrd-TwrmoyMR-_S85AHuXJ4YMi2K_gRjOP9hpUbewzxxSO7mY-IECdNMFNwSARVw__Jkay-gGfbctj4PLnL0-V49fjVZ-um7wFMgi5D-IBNjeH3NfccWwj0p9eRNGmFeAGk5CVJEAsV2WsHRAQJaHCmO5kGqgykxxYOGb0b7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6412,"author":"丁瑛; 张再兴","title":"西周金文语义系统研究","abstract":"從西周金文詞彙的研究現狀中可以看到，雖然青銅器銘文的字義、詞義考釋論著很多，詞彙相關的專題研究近年來也不少。但從語言學的角度，全面深入研究西周金文詞彙系統的專著卻很少，這使得在漢語詞彙史的研究上，西周部分成為薄弱環節。西周二百七十多年的歷史，金文正處於發展繁榮期，前後時代變化明顯。但同時，有別於處於轉型期的春秋金文，西周金文又具有一定的穩定性。通過構建一個詞彙語義系統，能從一定程度上看到一種語言文字在書面成文使用上的歷史性變遷，同時也反映出當時的社會生活、人們思想文化的變遷。這不僅為詞彙學史的研究，也對文化史的研究提供一定的參考價值。本文以西周金文詞彙的語義為研究對象。納入本文研究範圍的西周銘","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKNWUa7M3zpd31bRPEGrxK_n-Laty8yCpeo3_6V0BwxUn3AGixO7v8ixAYkl_VHj87gI5sWRDaS7BgWagw3fp7eiQ58Fr3RZUJJO_3AftJrRFI-zzW5EJ1cbEF60AylwXfkOVSZwlAtcfEb4wE8dQ-fGv_Jg9IeDe0sf-iQpmPILkSoqTNQnJs&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6414,"author":"梁春妮; 潘玉坤","title":"春秋战国铭文句法研究","abstract":"本文以春秋战国时期的铭文语料作为研究对象,以专书研究的方法对其进行语法研究,着重对其中的句法进行梳理、分析,以期丰富和加强春秋战国铭文明显薄弱的句法方面的研究,填补汉语句法在春秋战国铭文这一特定语料研究上的空白,全文共分五章：第一章绪论。主要介绍近三十年金文语法已有的研究成果,说明课题的研究意义和本文的研究方法,并交代清楚材料的选择、处理以及体例方面的相关问题。第二章名词句法研究。(一)春秋战国铭文中未见否定判断句。“主语+名词性谓语”、“主语+隹+名词性谓语”是肯定判断旬的主要结构形式,与西周金文相较,肯定判断新增了“主语+殴(繁)+名词性谓语”、“主语+名词性谓语+也”两种类型,还出现了复","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8pfawb45L1J8JGeubHcNstN0BxBDKssZ0YcaQrHiRBmSlKbor_mAo0Iak9eiSM1zFMprdnkOEWw10ZMu2iLY0QqK2CyJzBsJJHodSvHZ4RVA-us_Ua4So-mpkICqYSj1S-tpsXmneHWNocS-kjqFyupon_pzxVFHD37DReqIKQYa0FpZv1W2U&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6415,"author":"邵琦; 张再兴","title":"春秋金文语义系统研究","abstract":"本文根據選取春秋時代這一橫斷面的文字語義系統作為研究物件，以目前已經出土的春秋時期所有的青銅器銘文作為材料，依託《金文资料庫》等資料資料庫平臺，完善補充了春秋金文詞彙語義系統，並以對比分析法，對春秋金文的語料進行分析對比。第一章是緒論主要闡述了春秋金文的研究現狀，明確了春秋金文語義系統研究的目標和意義，限定了材料範圍、研究方法和原則。第二章是本文的核心章節，主要是春秋金文語義系統類述，把春秋時期的金文按照西方語言學理論分為開放性詞類和封閉性詞類。並具體細分成小類。對每個詞語的語義，詞頻，並舉例以示用法。第三章主要比較共時春秋金文語義特徵。詞義的國別比較，以主要國家齊、燕、楚、秦、晉，為主體，分","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8pfawb45L1J8JGeubHcNstN0BxBDKssZ0YcaQrHiRBsq5mzz1fKpegDcS9ovSXDgSQ2KvEaeddsuEkpf0ofjyWlncD6GQrXSmZYPW_Yk7Rg2lBpwQ0Ji9lR_fB9NBzIzOTKbZniT155gUiJ1gQfNdpJtryA9r981-y70KvvbTGXQb8S8YL3eH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6421,"author":"吕全义; 巴新生","title":"《臣辰盉》铭文研究","abstract":"《<臣辰盉>铭文研究》在前辈研究、探索的基础上,对以下若干字(参见下表)的隶定提出自己的看法,其中有些是对其考释提出自己的看法。序号(1)应当是“造”,释为“进”,与传世文献中的“降”相对。序号(2)应当是(?)或者惋,祭祀名,铭文中用为动词。序号(3)隶定为国。《礼记·王制》郑注：“馘或为国”。序号(3)之字应当与“馘”有关。吕忱之《字林》认为馘与聝有别。“京”,《说文解字》谓“人所为绝高丘也。”可见,“京”在汉人眼里为高大建筑。笔者继承杨希枚之说,认为“京”为献俘礼之后,陈列(或者说悬挂、或者说存放)战争中所获馘(头颅)之建筑。“国京”即属于宗周如此功能之地方,乃某一集团(具体到本铭,当为","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJUJ4fHftEQIubVeLff3o4VFs9NWFSLJg-SLUGOqAuFaut_NTiz-6coxg3k1iFyCLwPJgCgr2E-EC9jHZ5iumKmvVNgDKf4MRZZd93DPLc95eXcH5KQOvvPHmu72A7vZb7INX_1wtwLyl1Fdd3PYzyvO7dey7PpC6K2m_RVASOsOQ6-GErQB1hM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6428,"author":"胡志明; 林志强","title":"战国文字异体现象研究","abstract":"本文主要从共时和历时两个角度对战国文字异体现象作了初步研究。全文以共时描写为基础,突出历时考察和分析。共时层面,提出了战国文字异体关系的认定原则,以楚系、晋系、秦系文字为例考察了战国文字异体字形的地域表现,并对战国文字字形作了分类研究。历时层面,通过举例考察分析了战国文字异体字形的历史传承情况以及战国文字异体字形与汉字形声化的关系,并深入探讨了战国文字异体字形产生的原因。","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI9dIMBF9rCt1OxzV_En77BZuldflJfjXZOws43PmPo52D2mz0m5q30BkVmsFNbt0VK5cUNIEecOnD3LNnZCIgezCAxoBN4_PXXvH_taDcXUmN0IQ1P77CABWZ4a9E9vF0oZRjYX3LEXHc3Wt3JJPoBZyIDrGGsE2rdxrPxRfkyVHcSvUCWIspj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6430,"author":"魏红燕; 林志强","title":"古文字中“囗”形多义性研究","abstract":"对于古文字中“口”形多义性,前贤学者早已有所认识和论述,也产生发表了一些相关的论作。但是,这些或多只是略微提及,或分类不清、条理不明,尚缺乏全面系统的考察研究。有鉴于此,笔者在借鉴前贤学者研究成果的基础上,将古文字中“口”形所表示的意义系统地归并为七大类型,并对每一意义类型举了较为详实的例子进行论证。同时,通过对古文字“口”形多义性的分类考察,进一步探讨了造成其多义性的原由及汉字构形与汉民族传统思维习惯之间相辅渗透、息息相关的密切关系。最后,本文还结合“口”形这一选题,探讨了与之相关的一些汉字发展演变的规律,以期对这些规律能有更为细致具体的认识和把握。","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVClFVnLJok_3B0F4ApdbwosloBiTOs2nXUcrl-HVkx9kx7u_8tnN2_Bxoz16mW7e6eHPE2u24f7LD2tTtVW6orDZInic-p24NyRMyH7wbQ6xEa0hPGl1SAK0JR2_lKi-rfHhhbB57cSReV1zMm5YYrj45hlp0B_yyNa43pP-VM-nj6JbYsTAw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6712,"author":"黄耀明","title":"《行气玉铭》释义集评及新解","abstract":"以句为单位,汇集此前对《行气玉铭》的49种释文,分别从隶定字形、阐释句义两方面逐一简评得失,纠正错误,在此基础上综合考虑各方面提出新释义。证明了铭文确属晋系,确释了铭文中的&quot;■&quot;、&quot;■&quot;、&quot;■&quot;等字。","categories":["02_字词句考释"],"year":2010,"publication":"励耘学刊（语言卷）","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2010.02.007","pages":"94-122","volume":""},{"id":6713,"author":"侯乃峰","title":"齐国故城发现的石磬铭文释说","abstract":"山东临淄市齐都镇齐国故城东南部韶院村发现的石磬,上刻铭文二字,其中第二字有多种考释意见。根据齐系古文字类似字形的释读,可推知石磬铭文的第二字当分析为&quot;从宀,垖声&quot;,读为&quot;殿&quot;,训为&quot;止&quot;。石磬上所刻的两个字铭文是要标示此石磬在演奏时的音律位置所在。","categories":["02_字词句考释"],"year":2010,"publication":"励耘学刊（语言卷）","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2010.02.018","pages":"87-93","volume":""},{"id":6720,"author":"苏建洲","title":"金文考释二篇","abstract":"本文内容分为两篇。首先考释邢叔采钟&quot;用祈福■&quot;的读法,本文认为(?)就是见于郭店楚简《语丛三》31简的&quot;■&quot;字,也就是&quot;寡&quot;字,在铭文中应读为&quot;祜&quot;。同时对&quot;■&quot;字的演变作了厘清,并认为《仪礼》&quot;永受胡福&quot;可能也应理解为&quot;永受祜福&quot;,叔多父盘&quot;受害福&quot;亦有可能读为&quot;受祜福&quot;。第二则是考释河南淅川徐家岭十号墓所出土&quot;玄镠戟&quot;的■字。本文认为此字直接释为&quot;镠&quot;是不正确的,应该隶定作","categories":["02_字词句考释"],"year":2010,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLo80UgV3a6KrfW6MP-JdmZtQKRZkUibEolWc17Z6Vm8Xs_iNhomTmZNuQ3mXyurU1kAtZH6RvxyLqnzJN2YxEHhcCyrO2VewOizk7t71noIk5ORXwkX1uEruJgz4stEjnHlbMbPQZtgks8LI-uN1L55qZSBwvs-XbtN-8qq5LDTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-54","volume":"13"},{"id":6721,"author":"李义海","title":"体用同称与西周金文释读举隅","abstract":"体用同称这一汉语古籍常见的行文范式,不仅利于传布文章辞采、彰显为文才情,而且还利于再现动作的情状;它的整理与研究,对于文献内涵理解与历史语言文化考古的深化都具有重要意义。西周中期史丧尊铭文中的&quot;匜&quot;便传递着上述信息。","categories":["02_字词句考释"],"year":2010,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIAem_J9pwwMgswjcn9L98pHaZ85w6CO2rDtyMDd_Da97L5jyp0lolo9Xkbqpn1GHD-ME8gPpE69vFU3mLozb4KTtVPM8NoPBXK-z8WYTNRv26aI7YabGmM6fVsbzJtyHHzH8PAst3kHuaJde68hx4uMuSHff3IOuts614_k_H1A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-59","volume":"13"},{"id":6722,"author":"蒋玉斌","title":"令方尊、令方彝所谓“金小牛”再考","abstract":"西周早期令方尊、令方彝铭文中的赏赐品,今世学者多读作&quot;鬯、金、小牛&quot;。从字形、书写习惯、行款等多个角度考察,这种释读都存在问题,应予改释。实际上,对这几字的释读,较早研究该器铭的学者态度审慎,并有别种释读,十分值得关注。其中柯昌泗等释为&quot;鬯、徐、牛&quot;的说法,应该是正确的释读。鉴于当今学界不从此说,实有重论的必要。","categories":["02_字词句考释"],"year":2010,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJF6mRJaVz5g69M44A9RRJAJFEVa2XO7hdTU6LlFHzF6ji9vE5TecP2ebEWV0sy-1MhZxOowpjrUXrj8JWnYG70jVpc0D0Ih4a0CYaGVxXggxmuo-oTauOiWzoNpnBBdyD792Q3YHcJWvyi22yKrAB_7oU4ezzsd_OWXzCM0ix_ZQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-83","volume":"13"},{"id":6725,"author":"袁仲一","title":"西汉铅梳铭文考","abstract":"1991年在西安北郊西北医疗设备厂福利区内的一座西汉早期洞室墓内出土铅梳一件。梳作马蹄形,由梳柄及齿两部分组成。通高6.4厘米,宽5厘米,九齿,齿长3.1厘米,柄的正、背两面各铸有&quot;土仁&quot;二字。两字横排,两字之间有一太阳纹图案。另外,在四川涪陵县的一座夫妇合葬的西汉早期墓内,也发现一件铅梳,形制亦为马","categories":["02_字词句考释"],"year":2010,"publication":"秦汉研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKorXx9EnxHvjWHx6Js_sFnlqLbvFG37TnAcgZGI_kuevXC-IplJXDus9EXFKYjZ2nv18ms91h4KWSk4f6HnIOM7FjbEHRPo3NdVTvVx1cTJAQV8iXRssp1b4UcGyGb-hwv1wQEUBGn1hss8via8LEBXKrlNmJJSVyvZ37lHSc6rw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46026","volume":""},{"id":6726,"author":"李开元","title":"“十七年丞相启状戈”之“启”为昌平君熊启说","abstract":"1982年,天津市文管所发现一件秦国铜戈,其一面上有铭文十七个字:十七年,丞相启、状造,郃阳嘉,丞兼,库(?),工邪。据此铭文,该铜戈被定名为十七年丞相启状戈。据田风岭先生和陈雍先生考证,&quot;十七年&quot;当为秦王政十七年。&quot;丞相状&quot;,当为","categories":["02_字词句考释"],"year":2010,"publication":"秦汉研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKyIHCLfEqTAiTRTG77tyvkwERAhhZ8QtyPd_3u2yd1doXfZhpc875AwPBOHAEraidSF3sIRVy0dHcsdqt1XU6X-RLJ94O6mdNMRQFzcuuI3ysdqslKyoLt_DwJx-_IorWSWd45F0vDdsTTpt4w-3F39TEcrVJ6uyHpCoIFA2CgpQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-17","volume":""},{"id":6738,"author":"申青云; 徐在国","title":"河南出土战国青铜器铭文整理与研究","abstract":"青铜器是我國古代文化藝術的瑰寶,青铜器铭文也是我们研究戰國時期的社會歷史文化、語言文字的寶贵材料。河南地處中原,不僅是文物大省,也是青铜器出土最多的省份,青铜器及其上面的铭文是中原文化的重要组成部分。了解青铜器铭文的内容能更好的帮助我们理解當時的语言、文化、政治等诸多社會因素。本文以河南地區出土的戰国時期的铜器铭文爲研究封象,首先收集河南地區出土的戰國青铜器及其铭文,然後对铭文進行释讀,對有爭議的字词盡量收集各家說法並通过分析擇優存之。具體内容如下：绪論部分主要介绍了河南出土戰国時期有铭青铜器的概況及研究现状。論文主體部分便是封河南地區出土戰國铜器铭文的整理與研究。本文共收集了長葛縣(1件)、","categories":["02_字词句考释"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsMwk9C4Gim8TVGaKPxmI-67OBNkqs_YLO6j-M6_EEhsPci3FaNz9ahO_Np8RgMgXfUTD9i96q6_Nv8IyiZpijTzDmX7t1tj5bJCyIbmCDQB_v2sKUOBn4168evdnqk270kdKOrmBd8SYSvpX_DukcJCY4Mgi28-E8Mitwo6tM4F_E9E0hf-0e&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6739,"author":"冯时","title":"二里头文化“常旜”及相关诸问题","abstract":"三代旌旗,因实物无存,形制不明。《周礼·春官·司常》以为古有九旗之制,清儒则以唯有五旗,但有旜、物之分,所说极是。本文通过对二里头文化绿松石镶嵌龙形遗物的研究,认为其性质即为大常之旗旜,其出土时覆于墓主人身上,即以旌旗移用为明旌,目的则在于引魂升天。作者就与此相关的一系列问题进行了研考。二里头文化绿松石龙通长70.2厘米,原应镶嵌于一长条形的有机物上,有机物髹以朱漆,现仍残留朱漆痕迹。龙配一铜铃,铃上残有织品和朱漆印痕,与龙当为一体之物。《尔雅·释天》:“有铃曰旂。”旌旗配铃为古代旌旗制度,故此龙形遗物当为旗物。绿松石龙为镶嵌之物,必不能设于帛质之縿旒,当置于旗旜。《司常》谓“通帛为旜,杂帛为","categories":["02_字词句考释"],"year":2010,"publication":"考古学集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6VrqeSpjRsr_X_Rpu52LFZ2N4DslGqlHDZUNYuFiqlQ2iHncrYMcNqAkKMDt1ifZdd9pLMHMU_Tp0Nz6R4cPW1KUwyj95kh4Yu0Z5vG41B0KETOywJgEnmFQDtmXz0DRKtwCcalTvLzhmbqvHS9kwSRdCQcb17773MzM8VpHnWA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-204, 216-217","volume":""},{"id":6743,"author":"唐冶泽","title":"古文字考释二则——释丙、帝","abstract":"本文采用语源学的方法,对&quot;丙&quot;和&quot;帝&quot;字进行考释。&quot;丙&quot;字原为人所居窑洞门框之形,与&quot;穴&quot;、&quot;内&quot;等字同源,故凡从&quot;丙&quot;之字皆有门、穴等义。&quot;帝&quot;字原为草扎人形,其供祭用与后世泥塑木雕之偶像同,作靶用则与后世箭的同,故其孳乳之字,亦多与扎结、祭祖、箭的等事类有关。","categories":["02_字词句考释"],"year":2010,"publication":"长江文明","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxQ3FLlWliOC3Q3ZPXV-EQL8hOcF0VyjSC8TskA2i735OU5Ob0-ER0-Yr421rCj5eymb6PNXisgBI0jBldGwEW_B7RmfI0Tq9P13b7Dhw2aVrEsu05aIzkurR1KWS_agUvOmAXljNNKxOeA25tQy4aBLY0nfL2M7yKPhmGBQf-lA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-73","volume":""},{"id":6746,"author":"黄锡全","title":"新见古文字材料与古代货币研究中之疑难问题举要","abstract":"本文主要说明古文字与古代货币研究有密切关系。根据新发现的古文字材料,论证海贝是西周时期的货币,推断商代的海贝也是货币,主张货币的历史应该包括实物货币,认为货币在中国可能已有四五千年左右甚至更久的历史;论证新发现的楚简材料为解决古代货币研究中的疑难问题提供了不少重要证据,如楚国铜钱牌铭文&quot;(?)金&quot;应该释读为&quot;视金&quot;,楚金版&quot;(?)&quot;、&quot;(?)&quot;应该释读为&quot;郢称&quot;、&quot;盐金&quot;,楚国黄金货币称量单位&quot;(?)益&quot;应该释读为&quot;半镒&quot;,齐国&quo","categories":["02_字词句考释"],"year":2010,"publication":"中国钱币论文集(第五辑)","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImDnBUwBFk1s6t1D0PTPTZWx0G6H6X7-iLVgCaHYekWbSIquE7DOxAlhkmmKJBo88WaTIDcNSq6gWi-sKOXn3Ud5Zaqs2w4pI53y871akylMmEbn4yumfBaKIboEZRnnu7EG6nfjaBD0YHk6JKNFY000tFZkja5076Pm3vlLqL0vXk0M-Ij9-i&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-40","volume":""},{"id":6971,"author":"唐金玲","title":"“好”字意义流变的文化内涵","abstract":"自《说文解字》起,人们便将&quot;美也&quot;作为&quot;好&quot;字的本义来解释,这实际上是&quot;好&quot;字的后起义。从最早的甲骨文、金文的造字形体中我们也可以考证出&quot;美&quot;并非&quot;好&quot;字的最初意义。本文将从汉字结构、社会文化的角度考证&quot;好&quot;字的本义,并从本义出发寻求它的引申义。","categories":["02_字词句考释"],"year":2010,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmdIkT-GYYhIXxsTD-FGNNdpAugE-m0S-HveYWZbee3tOTZsZf-NdipU9HAPZ5wqziGaXeSb9o23IJfOEI57MDBx1ZCLvaOPBPx43cRgbod_8Lor252ZhKXQ0aQdMi-a_q-U0dBwM783KK9INPb9jfBMmQ639d5tn6a5oETDKLahHePOQzZPvC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-150","volume":""},{"id":6972,"author":"李秀丽","title":"殷周金文否定副词“毋”之用法","abstract":"否定副词&quot;毋&quot;在殷周金文中有自己的用法,在语法上可以修饰否定动词和形容词,既可以带宾语也可以不带宾语,前后都可以加状语;在语义上既表示禁止性否定也表示一般性否定,而且表示一般性否定的用法也非常多见。","categories":["02_字词句考释"],"year":2010,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmdIkT-GYYhIXxsTD-FGNNdpAugE-m0S-HveYWZbee3o4qZ6Gwr_C7FexlkZ-t3lrXmXr0MlNGFeIpnpg60zc5spoetdf6oDLBvaFonyo6vJkZHGPpXB1Cn_IFEiHf2msascTgtRR7ZuIwizoWfGDXf_Y1JMC01mmxQAToZQIEo_cOkkQ49AlC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72, 75","volume":""},{"id":6973,"author":"孙会强","title":"“名其动”与“名之动”","abstract":"&quot;名其动&quot;结构在甲骨金文中大量出现,到西汉时期基本消失。&quot;名之动&quot;结构萌芽于西周,普遍运用于战国和西汉。春秋战国时代,&quot;之&quot;&quot;其&quot;在很多情况下可以自由替换,这导致了&quot;名之动&quot;对&quot;名其动&quot;的取代。&quot;名其动&quot;结构和&quot;名之动&quot;结构是出现在不同历史时期的一组同义结构,它们具有历史的继承性。","categories":["02_字词句考释"],"year":2010,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAu22P1I10N6hG6EIDQ65mUV2-MzvszSx7OOSo3pNQ8rwq9vE3TlgfaaixTQS3vrJY2TuT8LjmHlkbpTT4F7FjxTh3aFr2KdpoZ1dKdjU2KOLKo-LIYsNUZ90108tmleOpzNuNGjG7fybbWDQo9Bu77WSuL3T2TT83Jr_GZAVDSzmgGctQ2xEj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-118, 122","volume":""},{"id":6976,"author":"王玲","title":"《盘庚》之“民”字新解","abstract":"迄今为止,众学者对于《盘庚》篇中的&quot;民&quot;字未作明确界定,结合&quot;民&quot;字在甲骨金文、春秋战国时期的流变,并根据《盘庚》上下文之意,推断文中之&quot;民&quot;指称贵戚大臣,非甲文所指,因而判断《盘庚》成篇年代在周代可能性较大。","categories":["02_字词句考释"],"year":2010,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLD1qWFg4tEbRNPMMkEwhY2-T1_xqI1satDsSN4tqcFg4b2697RqqpilJOIiN3RXHnPX0WClarNdQ-E7B_VcoQXAQVQ1adCDwatTCUBa3Chsig2Y0Yyjs3Lz1EYyCNQ3w0JoSFLTmau5rono4u6JjAnya6XngW-x6iHSB01NMDtwMKYyOMr6VaJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-26, 30","volume":""},{"id":6977,"author":"许丽","title":"“鼎”及其词义演变探析","abstract":"汉字有迷人的魅力。一是有独特的结构形式,二是有深层的文化意蕴。&quot;鼎&quot;作为一个汉字年龄古老,起码在甲骨文时代就已经产生了。在古代汉语文献里&quot;鼎&quot;较为常见,在现代汉语里&quot;鼎&quot;并不是一个使用频率很高的词。本文梳理了&quot;鼎&quot;字字形演变过程,并且从认知语言学角度探讨了&quot;鼎&quot;字的意义变化,这些意义的产生都是转喻和隐喻的结果。由此探析&quot;鼎&quot;蕴涵的文化内涵。","categories":["02_字词句考释"],"year":2010,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdNoMszLAXDZcgm75keoS_QIVUcVhokHY5xWfOUCd4wogTLmudieaxMS3A2EAnBcD9I8BBcCzfROs2oEzHDetTtwPj3CAaL-HvmSvpKr33UYMfmTgcePVNuD9k27iP3mXOuaHf8452uRvgl9oBnL7NLbqdoo4zJIosb1vBDvYyZQyfgk07em3u&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48, 53","volume":""},{"id":4844,"author":"苗利娟","title":"《近出殷周金文集录》所录商器器铭校订数则","abstract":"《近出殷周金文集录》所录商代器物铭文中有不少讹误。刺取其中15则略加考辨。","categories":["02_字词句考释"],"year":2009,"publication":"语文知识","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPvmciD5w0xaCPVZwZoTJ51TDbdr5RHTbg3gImjb5fzNovvLqFPEfdJGjr8r9XYJtck_JGXPIWt3b_L8huZH-WicJ1amrBkWXiR1xNP6PQXf2quJWYxKmu5jJk9rQ2QY7VR6tEXOlkACz6EGeZfA3XVh0aMcx6o_SIEQmmAX65UP2NDPGhTz4w&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-61","volume":""},{"id":5273,"author":"胡长春","title":"钟离氏始祖“宋襄公母弟敖”新证暨“鷔鷔雝雝”释义的再探讨","abstract":"","categories":["02_字词句考释"],"year":2009,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2P3CTAvMYvuasHOgSK_jBF8HR6HsI1JT7_Ee_oBrcuIEh08ixaTIbymE_tCeR4zsqQGwFGbR8PLzjFbxSyTTae5XI7nxOslT0tveOpkG1jZ2emKwnb7_XlwUn21RcInCdWDDTR-vbPu6IGGM47tsuCn0hFfFuTKHRno6DY2puSQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-112","volume":""},{"id":5274,"author":"尹志强","title":"“尹”字文化源流及其他","abstract":"作为百家姓之一的&quot;尹&quot;字,历经几千年的发展,它的形音义都不同程度地发生了变化,造成现代人的一些误解,通过对&quot;尹&quot;字进行文字学方面不同方向的阐释,便可对&quot;尹&quot;字的发展脉络有一个大概地了解,从而使人们对&quot;尹&quot;不再产生误读或误写。","categories":["02_字词句考释"],"year":2009,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2P3CTAvMYvuasHOgSK_jBF8HR6HsI1JSqlL10Sb05iKPI9taIOnfsA3r6ecWxibv_Ymo1Msg2Hi9vnTPC4UEFn4EIYmHKaPwMxQhqpMr6b7aQ5mDTpPuSnoXsYO72THu7rr0mwg-MZRGha7vXJVXz90KnrwN5FJHtIvpB2G1lqw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"340-341","volume":""},{"id":5275,"author":"肖瑜","title":"湖南郴州苏仙桥J4三国吴简文字校读记","abstract":"湖南郴州苏仙桥出土三国吴简中的文字释读略有瑕疵,现就吴简中的&quot;窴&quot;、&quot;檸絏&quot;、&quot;顿首&quot;、&quot;華&quot;等釋文进行商榷。","categories":["02_字词句考释"],"year":2009,"publication":"河池学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2MC_5kRnPirlsRP_pwlxPQqnpN6xSgMxVxWHWEe4vjphpeZjpr_ifGii-KHmq3FUBKXxbSh3UDFYJgm9VoEBtBLxvZ8m8qUTdzVmoYmuvAS6VdEuXbqk6N8eJhwKF1A1mkfLKQom4IO8HPadHFipnZF0eWGWw1eO962xp4gvIlQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-62","volume":"29"},{"id":5276,"author":"吴伟","title":"利簋铭文再释","abstract":"利簋铭文涉及周初史实,且可与文献相证,引起学者的广泛关注,释读和研究文章不断,然聚讼多年,迄今未有统一意见。目前,争论的焦点在于&quot;岁&quot;的释义,岁星说和岁祭说相持不下。细审持岁星说的学者所列诸证据,皆不足信,故岁祭说是恰当的。我们对铭文重新断句,参考文献、甲骨文和金文材料重新释读铭文,梳理过后,基本上做到了文通字顺。","categories":["02_字词句考释"],"year":2009,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVsiTOxX35nnfXzrihDjkBoWfIW8pOCNJkMXUsMX7EfVr_abrKfpS09BE1GtduB9_QLLK0WkBEEX3L_hqBVdVz122uX4hkbzpC99CDejt_QIiWaP57cQcxa80WMmKGpOmnlc6uUinvMDS5-ZkKR92FIp00urAz_4G1qiWnfm53xg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-32","volume":""},{"id":5278,"author":"吴国升","title":"金文“塍”字辨析——兼说西周春秋“土”、“士”两字的发展演变","abstract":"关于金文&quot;塍&quot;字的构形,学界说法不一。通过排比字形材料可发现,早期金文中&quot;士&quot;与&quot;土&quot;区别明显,&quot;塍&quot;字无疑从&quot;士&quot;作,系&quot;媵&quot;字异构之一,与&quot;塍&quot;是不同的两个字。","categories":["02_字词句考释"],"year":2009,"publication":"贵州师范大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16614/j.cnki.issn1001-733x.2009.03.017","pages":"130-132","volume":""},{"id":5280,"author":"潘飞","title":"《新收殷周青铜器铭文暨器影汇编》山西出土战国铭文考释","abstract":"《新收殷周青铜器铭文暨器影汇编》一书是相对《殷周金文集成》(中华书局出版,1984-1994年)而言,收录《集成》出版以后新出土的有铭铜器以及漏收部分,时间截止到2005年底,共2005件铜器。该书充分地将青铜器形制、纹饰、铭文等资料综合起来,极具价值。本文在前人研究的基础上,试图对山西出土战国铭文进行疏理,草以小文。","categories":["02_字词句考释"],"year":2009,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxikt5nVfb2hvakHOk4qr5MLIRAZlrNDoasxVhA68dPYdNTDM0cH_bwTwWdmzIeHdtzlzbcNgTBQIH1DIZoU-DcMlcfow9QEftsAHNuv3XqX1BEc-0-LWtimAqnRf1Yms3BzMv6ANkf0a_0lu8zQfoJqcXSfkIYmtjqyBuHt31Ag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"314","volume":""},{"id":5281,"author":"余志鸿","title":"“毓”:一幅产妇生育图","abstract":"&quot;毓&quot;是会意字,它由三部分组成:左边的&quot;每&quot;,右上的&quot;■&quot;(倒过来的&quot;子&quot;),右下的川。三部分各有特殊的意义。","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoj9rhGXojemejh0Cu2lugr_eyxchjL6rKvTA9gnIojv9b6jEHmPe48eqkjxogoXDO_Nr2gF3InFlojNX9B5T4qFeu2NIWIPsjGRITFOJiykfXLXVr6fMsIGT4Bu_CQ9o4NKRucRl7kC8o7aV_qmAQTE9Z3QnnIoxua90kdd2Skw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16","volume":""},{"id":5283,"author":"商艳涛","title":"战国中山器铭“■”字辨","abstract":"河北平山战国中山王墓出土的十二年扁壶,其器铭中的&quot;■&quot;字多家释为&quot;师&quot;,这既不符合战国时期的用字习惯,从文例来看亦不当。根据该字形体和文例分析,此处是作为偏旁的&quot;邑&quot;字,应当是制造者&quot;工&quot;之私名。","categories":["02_字词句考释"],"year":2009,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2009.02.004","pages":"18-19","volume":""},{"id":5285,"author":"吴镇烽","title":"鲍子鼎铭文考释","abstract":"新发现的鲍子鼎是一件齐国望族鲍氏与郑国公族联姻的陪嫁礼器。此鼎的造型与光绪十八年(1892年)河北易县出土的齐侯鼎、1956年山东省,临淄县姚王村出土的国子鼎非常接近;所饰蟠螭纹和铭文字体也常见于同时期的齐器,是典型的春秋晚期齐器风格。经考证,作器者鲍子是齐景公至齐悼公时期的大夫鲍牧,鲍叔牙的五世孙。子思是郑献公、声公时期郑国的大夫国参,字子思,郑穆公的重孙。","categories":["02_字词句考释"],"year":2009,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2iJkEQzN4aSGnxETxR5mmNA_VRejc-GgXCelFZjs0-m0PrSMlbx2UKGz5s0_pEh-719UTujqHxh_Vzy3pJx7sVxeXD0k7CQMnnConTNehtxfYLIL1be4na-xKfU2CuweoeW20XHJoX6B4r5F7h13bg8rZl-GTeYQxrEBxo9Jluw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50-55","volume":""},{"id":5286,"author":"梁云","title":"秦戈铭文考释","abstract":"加拿大苏氏藏秦昭王七年戈铭记载了当时左丞相奂和右丞相殳,其中奂就是《史记·秦本纪》中的庶长奂。可补史料之阙。","categories":["02_字词句考释"],"year":2009,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2iJkEQzN4aSGnxETxR5mmNA_VRejc-GgXCelFZjs0-m0PrSMlbx2U3Dq4cffRPniZUa3t0SG6U7bxbn9e3d-OeMckFNNBrRrm-qlm5jEWxStyLjvkguWKWY8Yoc_bImTJP-85ennOmIwkJpe-t0i5eBVlQCbQY3DQNrkpjnot_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-58, 79","volume":""},{"id":5287,"author":"武振玉","title":"据金文补正《古代汉语》的若干注释","abstract":"殷周金文作为出土文献,具有语料早真实度高的独特优势,对补正、校正传世文献的相关训释具有重要作用。本文即据殷周金文相关语料对王力先生《古代汉语》中的十余条注释作了尝试性补正。","categories":["02_字词句考释"],"year":2009,"publication":"佳木斯大学社会科学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIYH3TScPuGgYiatUQ0y97zTzFlzSXAkgJxPRAerqk2osl4m5qdPfeIPgLe0ZuWR-p9UoAAmijJ79JdW_uTqmdDdFEt0wj8NWZoez7kP9U2HXm_V3coTQxvumIh3UZ-bHTakiQeAZTyYAdv50QBgwXKoKNERpZ6BC0633U72m9FRw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-54","volume":"27"},{"id":5288,"author":"庄裕","title":"“章”不是“立早章”","abstract":"&quot;贵姓?&quot;&quot;姓章。&quot;&quot;哪个章?&quot;&quot;立早章。&quot;这是某报在介绍《汉字部首表》时的一段问答。作者认为&quot;立早章&quot;是一个常见的拆字错误,正确的回答应该是&quot;音十章&quot;。","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK400jzSKnrdSqiFrz8d4y3suFLDwQHuAaK8oXmM-aowjHAh8pZo5rB2OKGB_aVyiEfmA93Nv4WIUHmkDuVo98Oo_K0R8xKWY8kM88Ww-1AXg2Wv8GMYh49RTDCeXcwQTwVZ5IpNX6b7W1eiWp2agfCSsTxUhoTcf9T4Rdv_gfG5g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15","volume":""},{"id":5291,"author":"延娟芹","title":"《秦子簋盖铭文》及其相关问题考释","abstract":"在辨析前贤观点的基础上,联系《秦武公钟铭文》与《史记》的相关记载,推断《秦子簋盖铭文》中的秦子应该是出子。铭文中的&quot;姬&quot;姓女子与《秦武公钟铭文》中的&quot;王姬&quot;系同一人,她是宪公的正夫人、出子的生母。出子被称做子,既不属于子爵称子,也不属于&quot;公侯在丧日子&quot;,而是秦国特定政治环境下的产物。由这件簋盖铭文可以推断其他几件秦子器亦为出子时作。","categories":["02_字词句考释"],"year":2009,"publication":"兰州大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13885/j.issn.1000-2804.2009.02.008","pages":"49-54","volume":"37"},{"id":5292,"author":"宁登国","title":"“序体”源于商周铭文考","abstract":"序作为一种文体类型,主要用于介绍著作动机和作品内容的编排次序。商周铜器铭文旨在介绍铜器铸刻的因由和展现器主身比先人、序列功名的内在意图,这正构成了后世序体文章的根本特征。因此,将商周铜器铭文视为最早的序体文章是合乎历史与逻辑的统一的。这一点可以从《诗》《书》等小序的创作事实中得到进一步验证。","categories":["02_字词句考释"],"year":2009,"publication":"广西社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK_3Pm_V-hc935j96ktIibHZuMX9ZjQrBLnfvJWojEprImmOuKBedDhUoDoCvqywJ74KMoFSgkai2uzihnwwkWWHEfpL5uhHLNg62vAqV0T2vcoLLi2ofiHFVUVbwLOHRhq_NHzja7tOYl8pq0dkk4jJt8HDkLeJrFlO9kDy2npIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-109","volume":""},{"id":5293,"author":"徐难于","title":"《尚书》“雍”与金文“雝”义新解","abstract":"《尚书》之&quot;雍&quot;,一般训为&quot;和谐&quot;或&quot;和善&quot;;本文所涉周铭之&quot;雝&quot;,一般释为&quot;和谐&quot;、&quot;协和&quot;,然而固有训释皆非达诂。本文以传世文献与出土文献相关词语的比较研究为基础,再从社会思潮比较、语义传承比较等角度综合考察,认为《尚书》之&quot;雍&quot;与本文所涉周铭之&quot;雝&quot;,其义为应和、顺应、遵从。","categories":["02_字词句考释"],"year":2009,"publication":"中华文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIy9wQzbXOwbIwckIkStJu7LjanlYE4OaaFqIzAXa8pA8F8hZLa5ZgUwDfj7ViCtvX2Lgjs7iFbcRJga2R7_Bx4c0iTvP6Cl2oonU_PBc5BkaQU7EMHz2f_9O_1Kphewbc0tRYg6tcRf5w5fTK1_xO87Yatmk4RLYJ0rThaPjOaSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46340","volume":""},{"id":5294,"author":"余少红","title":"师酉簋铭文中的“瓜”字","abstract":"分析、比较《殷周金文集成》及其他一些古文字材料中的&quot;身&quot;、&quot;瓜&quot;字形,认为师酉簋铭文作&quot;&quot;等形者,实为&quot;瓜&quot;字,在铭文中当读作&quot;狐&quot;。铭文中的&quot;弁瓜夷&quot;可能是指有戴狐皮帽习俗之夷部族。","categories":["02_字词句考释"],"year":2009,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2009.01.012","pages":"141-143","volume":""},{"id":5297,"author":"李义海","title":"曾姬无卹壶铭文补释","abstract":"","categories":["02_字词句考释"],"year":2009,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKY2r_cy-0vyxu48h3gpu0G2keRQNn3Dkq8xjAmEILgprvVLMHoDvxOq_c5iH5iSirbOqHtjiCXHzkREzY-Beko3ZF5vSduUJKug_CvE1JMNKwBgqfrVSdPbV1HYMx0tFDdz1O_8Os23XqP1jVh5kAp4fw9P68Eg8lssZgMl0rO2A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-70","volume":""},{"id":5298,"author":"商艳涛","title":"金文中的“征”","abstract":"文章从字形、用法两个方面对金文中的&quot;征&quot;进行了全面的考察,指出金文&quot;征&quot;系由甲骨文&quot;正&quot;发展而来,后衍化出从&quot;辵&quot;之&quot;&quot;,《说文》从&quot;廴&quot;之&quot;&quot;亦由此演变而成。&quot;征&quot;本义为&quot;行&quot;,&quot;征伐&quot;义由此引申。金文中的&quot;征&quot;与甲骨文中的&quot;征&quot;使用范围不同,而与先秦文献的用法基本相同。&quot;征&quot;后一般直接带宾语,也有用介词&quot;于&quot;引","categories":["02_字词句考释"],"year":2009,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmT1ix1AqfBRSwr-LgOwW5TGSv0LFMiPjEc1mkyGcqZG6jSe59m2RHNiJ_SdT4xNOztf0Il9UtXCUsc2RJhURpErW6edWHPwsmff7WSj8imWvpCF8KknMTxGkJnv5fkpT887Tg8PDokptWqkPKP3V1BLOczvrBINlCd2rpQQY9RA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"147-154","volume":"8"},{"id":5300,"author":"闵家黎","title":"“盾”后的那只眼","abstract":"一说起&quot;盾&quot;,连小学生也知道是啥玩意,这可能和&quot;自相矛盾&quot;这则寓言的广为流传有关。可是,甲骨文中找不到&quot;盾&quot;字,可能&quot;盾&quot;作为防御性的武器,是在人类社会的战","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKiJmI9Hz5e-48ahwsqvoQCgKF3IkJHpXyIS6wSCjd-csA9ObNY9WgR1gjt4aUOrnIi8MSRpU5Y5n90KpPJmyIms0pRNsafcQGVl6owi8PH9j46EIF44A2bWCx0hDpLAB0ayy9c0CAS2jDlc06FcaSOs4wK36rCQTQvzrvGbkSZDQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"12","volume":""},{"id":5301,"author":"浩义","title":"“荆”和鞭刑","abstract":"&quot;荆&quot;作为植物,当归之于灌木,但因为枝条细长、柔韧,古人视之为草本。金文中&quot;荆&quot;字是这样写的:■——上面是个草头,下面是个&quot;刑&quot;字。为什么以&quot;刑&quot;作为声符呢?原来,古人常用&quot;荆&quot;作为刑杖。根据古书","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeAwXa7ZKQ8WtLtuSHERT3rfUM4OFd52CY_7KKC8DPEmr_ZwAPwTjfJrDd6dpP7nH7tKqbM_h1DCwDA8NU5Hc9ovn-aiuNS1aFwDeiXnNTYLkyrdAihJUD1Y1BwuOuEsshjQQEyNzWe6-LDOdETPyq5aVjH9JS_MIvr0iazOgUOQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15","volume":""},{"id":5305,"author":"栾维权","title":"“家”字本义补释","abstract":"一、&quot;家&quot;字本义应是&quot;豕之居&quot;《汉字文化》2006年第5期刊载了刘庆俄先生的《释&quot;家&quot;》一文。文章提出家的本义当为邦,即诸侯的封地。我以为不妥,理由如下:家、邦两词产生年代不同,家较早,邦很晚。若家本义为邦,那么邦出现以前家的意义是什么呢?猪在仰韶文化时期已家养,那时还没阶级,更别说诸侯邦国了,","categories":["02_字词句考释"],"year":2009,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJbAU62x_twBtHXWyx4_Fb8mfR_M8-Z9vP_lisNB5c9QGs3oas2MLVMDiUF_sW12rU1cfhFHJMN97A3-_npqxJd92TfH2nCjb26tLgZLWAxbYpIcp_VwmfxqAG08fTpVq8lUJVp9QVFx93gxCSwrpfhiI9_S9z0zXioSO5rOVDSwg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-80","volume":""},{"id":5306,"author":"张秀华","title":"从金文材料看“禋”、“柴”、“燎”三种祭礼","abstract":"从金文材料看,文献中关于&quot;禋&quot;、&quot;柴&quot;、&quot;燎&quot;的记载,有一些可以得到金文材料的证明,有一些尚未得到证明。金文材料在一定程度上可以补充传世文献的不足。","categories":["02_字词句考释"],"year":2009,"publication":"牡丹江大学学报","link":"https://link.cnki.net/doi/10.15907/j.cnki.23-1450.2009.02.025","pages":"46085","volume":"18"},{"id":5312,"author":"张良皋","title":"鄘戈释名探义","abstract":"结合古代文献和古庸国的历史,对&quot;鄘戈&quot;的名称含义进行探佚,有助于人们认识在古庸国(今竹山县)出土的&quot;鄘戈&quot;这一器物。","categories":["02_字词句考释"],"year":2009,"publication":"郧阳师范高等专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLeI0zWEc61BE-zOtz2cg66n-9QMO9KjVaHAkttbMUuVb0x4E63P2drvXd5QxVDc3HVoMBTo73Xa_LXmej1wR1IiTi9R9txBEWmQ2UVdILI7AS5-vbmydq39dH_uwGlRuqT_TJRThtehWRJNAVIzzGW7gCwLTFPWk6Aaqbt3LTmPg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-17","volume":"29"},{"id":5316,"author":"商艳涛","title":"金文军事用语释义二则","abstract":"金文&quot;搏&quot;字有从干、从■、从戈、从厂等不同的形体,其所从之&quot;■&quot;当由&quot;干&quot;演变而来。两周金文未见从手之&quot;搏&quot;字,该字直至战国时期才出现在石鼓文中。由于早期表示打击义的&quot;博&quot;字后世多假借为博大义,打击义则由后出从手之&quot;搏&quot;字表示。金文中&quot;搏&quot;可单用,也可与&quot;追&quot;、&quot;敦&quot;、&quot;伐&quot;等征伐类的语词连用,传世文献中的&quot;薄伐&quot;即金文中的&quot;搏伐&quot;。全文&quot;敦&qu","categories":["02_字词句考释"],"year":2009,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqyI_d41liNuIhJ14LSv8_1_Q09POtzeumGgOZuKtKb4FbvX_2QmmJDpeKXL0jzWCmotdST9cP7a47DPabQb6T8PfAMufiC7YTyRmQC0TmMsKgKSL8K6mqvKnsdJILD1N1wWcc3BUsBRBobqdi18Pgg1-IHM3gq8Wuzu72pvWVcg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46029","volume":"31"},{"id":5317,"author":"方先兵","title":"略论“青”字本义","abstract":"&quot;青&quot;字本义在和《现代汉语词典》中的解释并不完全相同,而且大多数人对其理解较为模糊。作为五色之正色之一,它的本义比较明确,只是在汉字的演变过程中,其本义发生异变,又包含了蓝色、绿色、黑色等。本文试图从对其演变过程的考察,略述&quot;青&quot;的本义。","categories":["02_字词句考释"],"year":2009,"publication":"巢湖学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCsNBM2AAyu4mIrVmnklHZweOb5Z14n3z46VS6q2QTISnAk3zkkEUpnfyUWB7QTPBhS0QgONL5nqy2Tlvac28chJ93wxyzDno8WCUoViA1mYYSUL733efpklo2hgdzP2az1gE5nE8YFC7csBb2F7XIuTe_MdPpuFGsi6jNoKsq2g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-98","volume":"11"},{"id":5319,"author":"武振玉","title":"两周金文中“雩”的词性和用法","abstract":"&quot;雩&quot;字甲骨文已见,但不用为虚词。两周金文中用为虚词,有介词、连词、语气词三种词性。用为介词时,可以引进动作行为涉及的方面,与古文中常见的介词&quot;于&quot;相同,但出现频率和用法的复杂性皆不如&quot;于&quot;;用为连词时表示并列关系,与后世常见的&quot;与&quot;同;用为语气词时主要位于语句之首,具体有出现于时间词语前和主谓句之首两种。","categories":["02_字词句考释"],"year":2009,"publication":"重庆三峡学院学报","link":"https://link.cnki.net/doi/10.13743/j.cnki.issn.1009-8135.2009.01.021","pages":"94-96, 124","volume":"25"},{"id":5320,"author":"杨小召","title":"西周金文中的祖先称谓","abstract":"西周时期的祖先称谓制度沿着两条线发展:一是以周人为中心,一是以殷遗民为中心。周人的祖先称谓虽源自商人,却形成了不同于商人的祖先称谓制度;商人的祖先称谓经过西周早期和中期的发展演变,至西周后期,二者逐渐趋同。祖先称谓制度的演变为商周文化的比较研究提供了一个新视角。","categories":["02_字词句考释"],"year":2009,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJR7x8LjYDZmm2wfHrfG_tHbjdFx5mtYOljXIk5hQbeAXKQ_b6BUH32_WXgJvEI1-PvmJBaizIXiR-Aa_A3E5Cx5A43ox_FTRNxXaydJkvVc943tT-Rpy3GIUg4kliEtoYVB_5BowYPzYwC_3ax674wGIALlFZmQIJ9saOe4fA6zg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-88","volume":""},{"id":5321,"author":"赵晓龙","title":"子犯编钟铭文补释","abstract":"自张光远先生在台北《故宫文物月刊》发表了子犯编钟的著录情况后,引起了学者的激烈讨论。子犯编钟共有铭文132字,铭文内容与著名的城濮之战有关,有重要的史料价值。本文仅对其中几个颇有争议的问题试作以探讨。","categories":["02_字词句考释"],"year":2009,"publication":"文物世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJku3krYV8R8-7Uxgfx-nQebcrG5eElbMhMkJSxJXz4ZH32Iauudwc3DjIbPoRoPvmFdfVtrfevb_jseKQfYU0_EG2T0rwe5YmkElK-J55MrbFOtykyeqolsxhkK3Zcfkif0DvT77O9goWz6FycMkYcXFX2W2exL59vhCpDaNhqlg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-16","volume":""},{"id":5324,"author":"张德良","title":"金文套辞“严在上,翼在下”浅析","abstract":"西周晚期铜器铭文祝嘏辞中常出现&quot;严在上,翼在下&quot;等套语。根据对晋侯稣编钟和四十三年逨鼎等新出铜器铭文的研究,可以推断&quot;严在上,翼翼在下&quot;是此类套语的最完整表达,同时可省略为&quot;严在上,翼在下&quot;,进一步省略为&quot;严在上&quot;,或表达为&quot;严在帝所&quot;,&quot;严&quot;和&quot;翼&quot;均当训为&quot;敬&quot;。《诗经·六月》中与之对应的&quot;有严有翼&quot;也当释为&quot;敬&quot;。","categories":["02_字词句考释"],"year":2009,"publication":"齐鲁学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iILq4WxboFhGWdT_CqG7iD0YDDiMx06SvKtZLZLqMgJfnL5bm-ai0NgrKRLHM0NhCzeH3i7FHVZtHlCmmnrJ3KEAi2y-qFanc4qy3GDNVm8iOWGgOMlgeFRAnbu3NTjlecRXOQcVAoIEq71ZxEWfJGeoTxxcCEcCY0-B_lBB3c_rQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-46","volume":""},{"id":5326,"author":"彭武文","title":"《溪洲铜柱铭文》古奥难字解读","abstract":"《溪州铜柱铭文》中的古奥难字难倒了无数历史学家,上千年以来,尽管解读者无数,但一直没有一个令人信服的结论。本文从古代书写中的&quot;避讳&quot;规律入手,对其中的古奥难字进行逐一解析。","categories":["02_字词句考释"],"year":2009,"publication":"吉首大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13438/j.cnki.jdxb.2009.01.015","pages":"45-49","volume":"30"},{"id":5327,"author":"张秀华; 邵清石","title":"作册般铜鼋铭文汇释","abstract":"作册般铜鼋记录了商晚期的一次射礼,公布后有诸多学者进行考释,但各家看法不一,汇集各家之言自当成为最要紧之事。","categories":["02_字词句考释"],"year":2009,"publication":"黑龙江教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJc-7DH2dZzX74ZwFoDfInNlFdJx1tf8Uk2Q3zztHS_aKuU32Csipcc0kgx8DGwRsA6FJlgn-kVexEHdn-Zfl9saZzwyVU3FgAIUTi5Ukg2VJcyR7mnZJ9xk7J49P5aZ6Ab3sDLFnLyLrhKVJsduBsg4HkOQWQge_qESFuQ-ML11A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-101","volume":"28"},{"id":5329,"author":"罗端","title":"从甲骨、金文看“以”字语法化的过程","abstract":"在汉语史上,&quot;以&quot;的演变状况甚为复杂。西周时期它在状语修饰词组的位置上由基本动词意义&quot;率领&quot;转变为伴随介词以后,就可以引进各种意义不同的介词词组。所构成的介词词组的位置,是由介词词组本身的语义地位决定的。论元介词词组一律出现在动词后面,而非论元的介词词组主要出现在动词的前面。至于&quot;以&quot;做目的连词和工具介词,这是在春秋时期由&quot;率领&quot;引申到&quot;携带&quot;和&quot;使用&quot;以后才发生的现象。","categories":["02_字词句考释"],"year":2009,"publication":"中国语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhp8msOG5-MlseQMgWQozJes98atF1ZFnqFIG9eqt4U2_QwEHTqUg7O40cA-1iwEufp_h4vCDKVjTeiXlb7yYlwTqKJDFvhQOgZFjuWdikmrW-xqUMn20b5gwUFvw-AlpX4--orzuZmbGZXVVlkKX7By2yfaftePJ4iOiLIOv2eQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3-9, 95","volume":""},{"id":5330,"author":"寇占民","title":"西周金文动词判定标准说略","abstract":"西周金文动词的判定主要依据两条标准:一是词的语法关系,一是词的语义关系。在实际运用中,这两个标准又是相辅相成的。","categories":["02_字词句考释"],"year":2009,"publication":"河南社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6Eyj4hm7RgPtJBfG9ecFgK8VU-j5cWwyc1XaNuwkoq69FsTXXL6AZyUIE0dOQ3PJCbSeZOdSVVvoSTEZHLnvW3mt4sfrFBzNaM4av-qWEEWXXvfxlNxdOSg1yJZY0ZKI_sY6xiLCSkZrH6cSw6MBhCqH6mhFvNcvScziratTg6w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"182-184","volume":"17"},{"id":5331,"author":"武振玉","title":"两周金文叹词初论","abstract":"叹词是汉语词类系统中比较特别的一个小类,甲骨文中是否已有叹词出现,各家尚有不同意见。两周金文中可以肯定为叹词的有&quot;■&quot;、&quot;乌虖&quot;、&quot;■&quot;、&quot;巳&quot;四词,虽个体数量有限,总体出现频率不高,但却颇有意义。特别是四词均能与传世文献中的相应词对应上,显示了出土文献对传世文献佐证和补充的语料功能。","categories":["02_字词句考释"],"year":2009,"publication":"西华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19642/j.issn.1672-8505.2009.06.010","pages":"62-64","volume":"28"},{"id":5332,"author":"何崝","title":"蜀中汉碑三题","abstract":"本文主要对蜀中重现或新发现的三通汉碑的碑文内容和文字进行了考释。其中,简述了《何君阁道碑》的重现经过,对碑文内容及其书体进行了一些考释;对《汉赵仪碑跋》文字的释读作出补正,并对碑文中提及的掾史一职的源流提出一些看法;对《郭择赵氾碑》文字的释读作出补正。","categories":["02_字词句考释"],"year":2009,"publication":"西华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19642/j.issn.1672-8505.2009.06.005","pages":"26-30","volume":"28"},{"id":5333,"author":"吴红松","title":"释西周金文赏赐物“甲”","abstract":"本文通过对西周金文赏赐物&quot;甲&quot;进行全面的分析,同时根据铭辞文意和诸赏赐物排列规律,推测传统释为&quot;盾&quot;的一些形体应为&quot;甲&quot;;并对&quot;甲&quot;、&quot;盾&quot;二字在西周金文中的演变做了较为详细地阐述。","categories":["02_字词句考释"],"year":2009,"publication":"东南文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_Cwr8aPEyimBiDGdm6QHTWvKfRk93-7EMOSt6C0wtIeKj0w_yBa8mZjmaCvpdYfgWP3dBcaqHlZmbbA6l_yIdNIMIc87wToaDzi5N_9E2qd7USdYB1kv1rsjSjT5Gz-bIAzjcW1G0BS5Skd6Plw-xYVxmqw1WhZpjC-Vw88dltA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"110-112","volume":""},{"id":5335,"author":"高江涛; 庞小霞","title":"索氏铜器铭文中“索”字考辨及相关问题","abstract":"本文先从文字考释出发,认为糿字与索字无论在字形还是在含义上,都有明显的不同,山东兖州西李宫村发现的铜器铭文应为糿而非索,是糿氏之器,而非索氏器。糿氏受到商王朝的重视,经常参与商王朝的重要活动,拥有较高的地位,很可能是商族的一支。进而在前人研究的基础上,利用甲骨文、铜器形制以及商文化在泗水流域的消长情况,进一步确认糿地在今兖州地区。本文利用甲骨文、青铜器和考古学资料,对糿族铜器进行了新的解释,并对其地望进行了旁证考察,对于研究商代东方地区的历史情况有重要的意义。利用铜器出土定位古族地望,是研究中常用的一种有效的方式。但是,由于铜器具有传世性的原因,所以用铜器定地望之前,还需要对铜器情况加以详细的","categories":["02_字词句考释"],"year":2009,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYdixcOSGljDVMnVnIA15EhE5hE4YPI1M3AudNYCZsvmRsNttK7C_0xMHzj8sC1dX2DjzBCTbEahAKvVhXCoLLk7yvZ8ZlKe2CFB7tC07pmV3ZL_IISftIo6M0Wq46EpnNAAhF7j1nyAU-xTLYrTkq-UgoDZrl-i2bck-psj52qQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-96, 77","volume":""},{"id":5343,"author":"黄锦前","title":"楚公逆钟铭文补说","abstract":"本文对北赵晋侯墓地所出的楚公逆编钟铭文和宋代出土的楚公逆钟铭文进行了对勘,并对铭文某些读法提出了己见。","categories":["02_字词句考释"],"year":2009,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvzsUvBVpk0cUe7l6fbtPkepo9M9vffmbI59c6GSHulTPOfgQWES_nAc_A09xCNsR6XvSJUxHDZPM1gQXoGakKlHt_2VOu5wdzGv56uu6fgwchdHBPz_Fhw6sCYLdJlmbqBMZSoJbNhNwADNuw-qFsZwt-9CDanDbPEhAIMkCa7Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-78","volume":""},{"id":5345,"author":"邹芙都","title":"“玄舍”戈考释","abstract":"&quot;玄舍&quot;一语金文首见,&quot;玄舍&quot;当同于&quot;玄室&quot;,为墓室之意;&quot;左&quot;系&quot;左库&quot;之省,&quot;玄舍左&quot;为视死如生观念的反映,意指为死者在墓室中建造专供储存或铸造兵器之所。","categories":["02_字词句考释"],"year":2009,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ01nB2SQ5XR20iCQBhQfZ3wqu-sajZ5EkK-1PgJeqbXklH6VUHsIkkupDnyYvygVNEMwnPAFzxQzIpOVKETJrJzKF1gsZGAD49Qk_wiwI4WaRbZtYcmsKOw0_sSwncrEuS4452Scgayv39yvg6JXatK7g95J97D9mjeTOkeb-D-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-86","volume":""},{"id":5347,"author":"黄娟","title":"释“■”","abstract":"对于&quot;■&quot;字的形体和结构,&quot;■&quot;从甲古文、金文的诸形体看,主要有从木、从未和从来三种,学术界现在比较通行的看法是以从&quot;来&quot;字的为最古,从木、从未的为讹体。但是通过对其他古代典籍的研究,甲金文&quot;■&quot;字的结构,应是从木从反人从攴会意,后&quot;木&quot;讹变为&quot;来&quot;以表声。&quot;■&quot;字的本义,应与&quot;治木&quot;有关,可训为&quot;治&quot;或&quot;理&quot;。","categories":["02_字词句考释"],"year":2009,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOYVaYp5TE3hlMYtA7y7RFz3xkTT9S9YM2JfDINiLgQK9KTeYsZhFnOz4-X0HD7M7AnKG0NKlY0ctHelsC55ehGdqBLQqu1rMptIxYn0HpZUv-JiJKgOGaAMojiM8TmWBj7yVtARREA5rDA5TrIFvCvFRP2c9qwNUy9mAq261A6g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"271","volume":""},{"id":5348,"author":"萧晟洁","title":"“疾”中有支“箭”","abstract":"没有人能摆脱疾病的侵害,认识汉字的人,大概没有不认识&quot;疾&quot;字的。疾,金文写作(?),从&quot;大&quot;从&quot;矢&quot;,描摹的是人被箭矢所伤。金文的这个字形为什么表示&quot;疾病&quot;呢?在进入农业社会以前,人类经历了一个漫长的狩猎时代。弓箭是","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLJ_oMDUAwOaNTxYOSXl6SJHvenVpKEUB4VrapT0ZwUp98IzSzvgWPOaDd_Ep1AmtMO86GWwnNF8v0RhHFSXGgv4qzqwaRLJcXB0_pfKRY96AuKVCKnT6kg7UWQZsBdsdspdHEyP7w8pYvqrADDmS7eb0FN3ZYq0BFzit1z-XVjg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13","volume":""},{"id":5354,"author":"李学勤","title":"“天亡”簋试释及有关推测","abstract":"&quot;天亡&quot;簋是最著名的古代青铜器之一。由新作读释,推知该器作于克商后不久,铭文所记是武王祀天与文王的大礼,器主名退,当为朝中乐官。成王五年时何尊铭中所叙武王告天,可能与簋铭为一事。","categories":["02_字词句考释"],"year":2009,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKW7khMrQugHBDWJ8SQbUHl1R9PV2Kaf--DuCzx7s4XaHBxBLSQLDpL8WY_9de-U1HnLx4StSgNq-5SkYUt0uuwFUazcUyZRLJ3Or6swmyURvnZT4ISdAqnuXZUNe0LWspEK22WyVVLUkNU3aDc4yUJ1d6urfN6eBoldOkYTkxr3Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46150","volume":""},{"id":5358,"author":"武振玉","title":"两周金文语法札记(四则)","abstract":"&quot;余、我、朕&quot;是常见的第一人称代词,其不同主要表现在句法功能上,即&quot;余&quot;以充当主语为主,&quot;我、朕&quot;以充当定语为主;&quot;我、朕&quot;的差别表现在&quot;朕&quot;主要见于具有庄重色彩的语境中,而&quot;我&quot;没有类似特点。&quot;不、弗&quot;、毋、勿&quot;是常见的否定副词,&quot;不、弗&quot;主要表示一般性否定,&quot;毋、勿&quot;主要表示禁止性否定。四词在出现频率、出现时间、句法功能、组合功能、其后动词是否带宾语等方面都表现出或同或异的差别。&quot;乃、■&qu","categories":["02_字词句考释"],"year":2009,"publication":"内蒙古民族大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEuB_uabx9uoJIt4gXrQdnSL2ONqEM7d1V178eQEjyrpKQzmZZ62W9V1tatEGV3RS0stY_-u7noFg9FRkU2dDstXzpQqt2H_xyeQBUZJgoL8V-xdBOExZtVYP9dUazFgghh3Vha5sSkPmKk-ifObVkRQJnXmu57ZPqhfFpIagf_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46117","volume":"15"},{"id":5359,"author":"武振玉","title":"两周金文中“用”的词性和用法","abstract":"&quot;用&quot;字在两周金文中出现频率很高,其词性和用法均呈现出多样化的特点。就词性言,有动词、介词、连词三种;就用法言,&quot;用&quot;为动词时有&quot;使用&quot;义,&quot;用&quot;为介词时可以引进动作行为凭借的对象和动作行为发生的原因;&quot;用&quot;为连词时主要表示原因。","categories":["02_字词句考释"],"year":2009,"publication":"广东技术师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItIyUoQnPRTVDzKvrDTgo1gar0RIRdAZVFyFzAGItF7b4HOUwfbCbry7HW9_tDfHcY6w5Iediac69NQh2OkqvN_C_zozM3aytZVCXOEtAYJ0n9ixTEbj-RXa969tyRoS0XRwSzJPzri0m-V31ppuR4h_mDwUcI1kNkxGWD57xDtQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"25-28, 154","volume":"30"},{"id":5363,"author":"王龙正; 刘晓红; 曹国朋","title":"新见应侯见工簋铭文考释","abstract":"最近面世的应侯见工铜簋,其铭文记载了属于&quot;淮南夷&quot;的毛、衰等氏族,侵犯周王朝南部边境并被周王朝打败的事情。铜簋年代应在西周中期之末的孝王、夷王时期。铜簋的器身与器盖铭文各不相同,可能是同一批盗自应国墓地的随葬器物。应侯见工簋的发现,更证明应国是周王朝南方不可或缺的屏障,担负着护卫周王朝的艰巨任务。","categories":["02_字词句考释"],"year":2009,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqVbSVRQ_KSQqGcIpX3mEbSbpEpiLbp3CuwGIfChzm83PHAuSjVqWWT_sfDKFlkE_3Ug82KRzEtmWj49esKOXU2lufevFPaPTKVf-7QjG6RW-5PuN-Z3Dxk3Sx_b-__1zFgOFMbnagZBnPsyqYX8anG4BspV7bVyVU-xr8uVRfxw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-58","volume":""},{"id":5365,"author":"张淑一","title":"两周金文女子称谓“规律”再探讨——兼论“杨姞壶”的问题","abstract":"","categories":["02_字词句考释"],"year":2009,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCkFW0Z6rbyeXYH3KP8MtSxvacwBpsIHYLQ-mn6rGF9Q58PPo4ou_snrUzvQldRnlRrdhhT1TtsQIudjUsrYyoOezQ6KZ8cT7tgHsGauHxC14-yi3KyCxvgDlFBLaxaHywTGt4WE9j-bZp03Tn-jCaf85CeZF6yiR_niwkrplYBA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-67","volume":""},{"id":5366,"author":"杨亚长","title":"再说金文所见之益公——兼与韩巍先生商榷","abstract":"","categories":["02_字词句考释"],"year":2009,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEFzEwDH2v3dG609o89DhzYQERpM1--EWVtaFVGS_R5MzcX8HL1f-IMCo_a60Z9XbLC8qkt0M_AvsFYvadecyPPbMSsODIdKvSl1ULj_6pX_PEEL1Wc3udPBOgxthlzFP6hed3qx1v5oVo8LsmVohKY85qkDZarF4cTKiJxxbNNA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-62, 67","volume":""},{"id":5369,"author":"陈英杰","title":"两周金文“器主曰”开篇铭辞研究","abstract":"本文对两周金文各种类型的&quot;器主曰&quot;开篇铭辞进行了全面梳理,重点探讨了跟爵位世袭有关的铭文,指出这种铭文在西周晚期曾是器主承继世袭爵位祭告宗庙时普遍采用的一种铭文写作格式,对这种格式的来源、形成、发展、消亡进行了探索和总结。同时对关于墙盘、逑盘为家谱的说法作了修正。","categories":["02_字词句考释"],"year":2009,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2009.03.014","pages":"92-102","volume":""},{"id":5370,"author":"赵立伟","title":"出土秦文献文字研究综述","abstract":"秦始皇统一中国后推行了书同文字的政策,规定以秦国文字作为全国的通行文字,这一政策的推行决定了此后汉字两千多年的历史,也奠定了秦文字在汉字发展史上的特殊地位,因此秦文字的研究一直是文字学界关注的焦点。本文以出土古文字材料中的秦文字为重点,对近年来的秦文字研究进行了全面回顾,并就今后的秦文字研究提出了自己的看法。","categories":["02_字词句考释"],"year":2009,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2009.03.016","pages":"108-119","volume":""},{"id":5371,"author":"吴铮","title":"殷周汉语名量词辨析","abstract":"论文分析了殷商西周的甲骨文、金文语料,经过辨析考证,认为其中只有集体量词、容器量词、度量衡量词,还没有出现个体量词。论文对以往认为是个体量词的词义和用法提出了新的解释。","categories":["02_字词句考释"],"year":2009,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2009.03.009","pages":"111-115","volume":"30"},{"id":5372,"author":"王建军","title":"“省化”——殷周古文中一种特殊的造字现象","abstract":"殷周古文中有一些字,实际上是截取或移植&quot;母字&quot;部分形体来充当新字或新字的部分形体,这种造字方法就是&quot;省化&quot;。被&quot;省化&quot;出能独立记录语言的新字不仅有利于汉语的表达,而且可以克服由宽泛的假借而引起的字义模糊现象,其功能完全有别于&quot;六书&quot;。","categories":["02_字词句考释"],"year":2009,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2009.03.010","pages":"116-119","volume":"30"},{"id":5374,"author":"万瑞杰","title":"金文“宝”字构形中的文化因素","abstract":"&quot;宝&quot;字是两周金文出现频率最高的铭文之一。其构形受到汉民族文化多方面的影响,其中图腾崇拜和艺术活动影响着其构形范围和取形对象的选择,同时汉族文化和古代科技对宝字构形也产生重要影响。而汉文化的影响是正确分析、认识两周金文构形的重要因素。","categories":["02_字词句考释"],"year":2009,"publication":"文化学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIecEhlfHYdn-43lle6diS7yhG7nTNRXgba4Jc9HxFbioCMkCAQaQX5rShE3fsPAOeUywEdkHMvImoDoIWKoYTBZR3NIHmh6C-opp8dlg_PlLAA7p2fRoD52u13fAJhU85Q2rHuDtWytC3yRMEDFkLqf1yiKt74eyLxPVkD74j3ZA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"116-120","volume":""},{"id":5377,"author":"陈英杰","title":"金文“顺”字说略","abstract":"金文中有从页从川的&quot;顺&quot;字,荣簋之&quot;■&quot;,与濒事鬲之&quot;■&quot;、簋之&quot;■&quot;同字,一般释为&quot;濒&quot;;效尊、卣之■、■,一般释&quot;涉&quot;。从形、音、义三方面考察,这两种字形均从川得声,读为&quot;顺&quot;。","categories":["02_字词句考释"],"year":2009,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3fZLOLdLG4bhF8g12CBG99qg_unM_P_n_tdb_8mj9f67Y6_8flQvvvnmrol_wlU1kdZR6KiXkLjKwLnuiMH-YRYo12xdSC8V0UMB4iWZrxkANExh9rQbuPWO0NeoZA6h1iN6AU6xUstkUi5Hn_4eDCZw80xTojEM_fTQu9fbSYQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46025","volume":""},{"id":5378,"author":"何飞燕; 李春艳","title":"从伯诸器铭文看周代祖先神崇拜思想的特征","abstract":"伯诸器铭文在研究周代历史中有着重要的作用,特别是铭文中所显示出来的先神崇拜的痕迹,为我们研究先秦思想提供了可靠的文字资料。从铭文中我们可以看出,周代的祖先神崇拜是存在的,祖先神崇拜的主要内容包括祈福、求佑助、求官职三个方面,并且,从铭文我们也可以看出,周代祖先神崇拜有着浓厚的灵魂不灭思想。","categories":["02_字词句考释"],"year":2009,"publication":"兰州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL5dkP9eE1i8qv6UgnbbS0eO0r3CZ7avJvyeQ0E_N2s-61KbLUXtNju9EKpPT1MzPhR3rKMCTIGMJffYha4l1WiBvY7LrnJr-mAWk0G4CejyNqOwHX2AuGiTi9KChFOyShSaVAwdJK5ld1lZWo1xoHfs1bhXjzodfQZ9dp7QbS-yw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"217-220","volume":""},{"id":5379,"author":"张光裕","title":"乐从堂藏■簋及新见卫簋三器铭文小记","abstract":"文章对所见簋■诸器和新见卫簋三器这两组铜器资料重加整理。通过比较可知,两组铜器除器形、纹饰差若相当外,铭文用辞及句例亦多类同,文章据此推断&quot;■&quot;、&quot;卫&quot;二人为兄弟关系;推知卫簋&quot;各于康太室&quot;应读为&quot;(王)各于康太室&quot;;■簋&quot;祀于其百神,亡不鼎&quot;之&quot;鼎&quot;读作&quot;则&quot;;■簋&quot;金车金■&quot;之&quot;■&quot;,原形作&quot;■&quot;;并就■簋、卫簋&quot;日引勿替&quot;一辞对青铜器断代的指标作用进行讨论。","categories":["02_字词句考释"],"year":2009,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL5dkP9eE1i8qv6UgnbbS0eO0r3CZ7avJv4XOcA2IbV8-G6JFqYlq0shSFK_xLQSGexzKZ3RlaEkGge8iKY9Z9bd5wZJmS_m2tmLMphbFQILnDwpv6Voo5YldXYsiPG5--saFNkOm1rJic4eKystmJ9JOY1VUvz3XUBjKdumPO-8Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46343","volume":"49"},{"id":5380,"author":"陈伟武","title":"两件新见曾国铜器铭文考述","abstract":"文章介绍两件新见曾国铜器曾子伯皮鼎和曾太保簋的铭文,过去均未著录,作了初步考释,指出两器均属西周晚期或两周之际器物,为曾国历史研究提供了新资料。以考古材料印证朱芳圃先生之说,辨析&quot;曾&quot;字上两笔为甑器两耳之状而非蒸汽上出之形。《曾国青铜器》所著录的两件曾太保簋,甲簋亦见于《殷周金文集成》4054号,从器形、纹饰、铭文内容、铭文行款和残存的痕迹看,当是同人所作同铭之器,我们可用流入香港的曾太保簋铭文订补《曾器》和《集成》二书释文的缺失。","categories":["02_字词句考释"],"year":2009,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInUSxRmbuaAfPGdPN2Kj1csw9wQnnIkUUqcnzUgXImWloO15_YzVLE7cWLLRLcth5EN3Aq5E_606ox9lAv3VGZk3Zn_t7Mz6w_hH1wXYsUyb5jO2l1h9N_my8gksPAsOkDj2dClmYuerTqQ4Soj7BLJg4vSJ6EMjwD1YtNyQXnFw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-21","volume":"49"},{"id":5381,"author":"张桂光","title":"商周金文量词特点略说","abstract":"文章主要研究了金文量词的特点,认为金文量词有如下特点:1.商周金文见证了原身量词的发展、转化与衰落的过程;2.商周金文存在不同事物共享一个量词而所代表的数量不同的情形;3.商周金文数量组合形式仍在规范过程中;4.名词的量词已开始由名词后向名词前移动;5.名词性较强的量词向典型性量词发展的趋势。此外,论文还讨论了与量词有关的&quot;再&quot;、&quot;两&quot;、&quot;铃&quot;等字的用法问题。","categories":["02_字词句考释"],"year":2009,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjE5G0oND3zuP7FETDFcX-UsOzeDpKCZEMEIAEB5NF_y-EBVnvKd2vqenxGcxr6CTaNdD4GmlBt0aFXW-9vRIS-t6WNyy26BNBSHnaHQ6odgRRYjXJ7sP_b26DFI2RwqrP6tHjDfhdaxMuzM7XDaBsNjtvh8ztDNKLidIk8Cj3rA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-28","volume":"49"},{"id":5382,"author":"蒋书红; 赵双喜","title":"“女毋又一不闻蔑暦”新解","abstract":"闻尊是一件新见西周铜器,目前人们对它的认识还相当有限,大家的见解还存在分歧。尤其是&quot;女毋又一不闻蔑■&quot;一处,为整篇铭文中的一个重点,分歧又多,在释文、断句、释译方面,需要做进一步深入、全面的探讨。本文对此进行了详细的考证,提出了一些不同的看法和独到的见解。","categories":["02_字词句考释"],"year":2009,"publication":"和田师范专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjV3phtM-7NahHBMsMH3QcbGlL6x29CDeL1mKYpviL4sP4W6pVVYZcDg5wWnlLG2Gni2lTsBSXtgT0tALmlhRLCFR23bJ7zb60icMSrb7harBo8euSuulbsLjHc0S53JjZA3plgr6SJvWOxIVrEga4pvTKH_7UYGXlO3mB963Iow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-69","volume":"28"},{"id":5383,"author":"张素格","title":"再谈殷周金文中的“(雨于)”","abstract":"殷周金文中的&quot;(雨于)&quot;字曾引起金文学家的广泛关注,但认识不同。本文对殷周金文中出现的&quot;(雨于)&quot;字进行统计分析,归纳其在金文中的含义和用法,除少数用为实词外,大多用作虚词,最常用的是介词,其次是连词。并辨析了金文中&quot;雩、于、与&quot;和&quot;雩、粤、越&quot;的使用情况,确立了&quot;(雨于)&quot;字在殷周金文中的词义系统,有助于铭文的释读和汉字史研究。","categories":["02_字词句考释"],"year":2009,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoU0wyMO0MP4bjuQiciec4hl2GFzdxOuKrYTzeHwaJPY_Vzd_Faz1zSjvGno7ApBba_F9RwHO_FTQpeaO6n_U1_cRRWXdRw6jiFiyHWoMpB-jS8-XpR8bqrMtR3VdJ0TTUx5Q5jvfkD4nMVzK7N4BmRe1bKI6M62wg3l3CXsXRFA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-61","volume":""},{"id":5385,"author":"简卫仁","title":"手持凶器日“寇”","abstract":"&quot;寇&quot;这个会意字,称得上是一幅速写图,很有视觉上的冲击力。它让我想到了两句诗:月黑杀人夜,风高放火天。据郭沫若的《卜辞通纂》,甲骨文中的&quot;寇&quot;字是这样写的:(?)。中间的半圆,表示是一座屋子。屋子里的景象让人大吃一惊:左上是","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIwepyE-TSm7cKx32J2-qQped8s2RZyTZcODL0sK7cgLnpNqTICo-HMGaBTyQanQKPJoDWuCyTXsaS-xEyWRnATnjtCcvzS_rCEGp1OpEzUJX3LblLa5LULAJOld4RHvqb_rnVPk4maeZrQHpQpeSYdWmrBr6RoSm1g0N4xDBXPqw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14","volume":""},{"id":5386,"author":"李燕","title":"神秘的“玄”","abstract":"有些汉字,看似简单,其实深不可测。&quot;玄&quot;字便是其中的一个金文的&quot;玄&quot;字写作&quot;8&quot;,就像一个阿拉伯数字、可是,这个&quot;8&quot;字到底是什么玩意呢?文字学家左思右想不得其解。某些字典只能老老实实地写上一句:&quot;构形不明。&quot;然而,关于&quot;玄&quot;字的探索并没","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJG5g3uPGZs8HbnP6Jfmt6L9KpxjW_CsBfrZTBotwAFNe0arDopiu8sI6NlZCcshQk57VGfOuLqworJn4H_UwB6S-XtOHT7UeZcHIsoMTEaa23wMPdT2-rYqJk49S8EOV0G3ok4n9uTWW2IaWki1O1IilbyUDWzLFX0dvfiMOU5VQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17","volume":""},{"id":5387,"author":"胡继明; 郭小龙","title":"“见+V”式被动句“西周说”辨证","abstract":"一被动句的研究,不少学者进行了大量而又深入的探讨,取得了很多有益的成果。然而在一些问题上仍然存在分歧,其中之一就是&quot;见+V&quot;式被动句的形成时间问题。学术界对此主要有两种观点:西周说和春秋说。持&quot;西周说&quot;观点的学者主要有杨五铭、管燮初、李瑾诸位先生,而","categories":["02_字词句考释"],"year":2009,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJG5g3uPGZs8HbnP6Jfmt6L9KpxjW_CsBdi3V58AA89K85zpIchjfGpBXmbxiu8iaP70BR2xC_AS3sTeqstQ_LjCl0SJVRGtvbT0SI5mqhK7Cugw8hGLPaluTUY0YQ1IXWk0PdoU0JMkF_yI6GY52_rD88RmlE8yYOltUwPzihIYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-33, 69","volume":""},{"id":5388,"author":"魏宜辉","title":"利用战国竹简文字释读春秋金文一例","abstract":"郑与兵壶是一件春秋时期的郑国铜器,其铭文中有一从东从殳从土之字,旧误释作&quot;敕&quot;或&quot;陈&quot;。这个字也出现在上海博物馆所藏战国楚简《容成氏》及《周易》篇中。根据与今本的对读及文义分析,这个字应释作&quot;墼&quot;。本文根据这条线索,指出了与兵壶铭文中的&quot;墼&quot;应读作&quot;懈&quot;。&quot;不懈[于]春秋岁尝&quot;,意即&quot;对于祭祀不敢有所懈怠&quot;。这种解释也使我们对文献中过去释作&quot;四时&quot;的&quot;春秋&quot;一语有了新的认识。","categories":["02_字词句考释"],"year":2009,"publication":"史林","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXrR34qg9GInHgeKN4YknZOJvDRh8GaJ7BZ_8gXmb5Fz0SWTK40AjmdNfIpnetvvLbiIW2FJqZcEnUsfOXpWjRmnj0JD6ELxzd5XO0VUVBICdNtuAGvkKCv_nzj11RqW-_OS6Pg_g6oHiEprnL0U7Hity1CZIrWtLT3mYXv57iQA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"151-153, 190-191","volume":""},{"id":5389,"author":"岳洪彬; 岳占伟","title":"殷墟的镞与甲骨金文中的“矢”和“射”字","abstract":"","categories":["02_字词句考释"],"year":2009,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2009.08.006","pages":"46-54","volume":""},{"id":5391,"author":"王晓鹏","title":"释召器铭文中的“■”字","abstract":"西周早期青铜器召卣和召尊铭文中有&quot;■&quot;、&quot;■&quot;二形,实为一字。唐兰释作&quot;■&quot;字,所释字形不正确。&quot;■&quot;、&quot;■&quot;二形应当是金文&quot;黑&quot;字的形体变异。在召器铭文&quot;用■不(丕)■(■)&quot;中,此&quot;黑&quot;字假借为&quot;熯&quot;,表示&quot;戁&quot;,有&quot;敬&quot;的意思。","categories":["02_字词句考释"],"year":2009,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK3Sb71dZNPRK11Kzsb6jbgcwkffLKvx6EAi0rAB5vq50Fak_T9CwBAopADPMinUoLORl_aIVXTvfwiy4lQHr0KaFVW1snUyhcLSmnRg43XNAVtIOxNSiOeRQGQFHn-tLRMhIV9HUExOJtIpy1QsoGkOl5_gLe23q7aZnQhZYoSCw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-71","volume":""},{"id":5392,"author":"李义海","title":"郭沫若对西周金文修辞研究的贡献——以《两周金文辞大系考释》为例","abstract":"古文字学界较早从辞章的角度来考释西周金文的郭沫若先生,不仅从整体上把握铭辞命意,进而自上而下地观照词语意义,并因此对两周金文的考释作出了重大贡献,而且他在考释过程中所总结或暗示的修辞格式,又为西周金文修辞研究提供了范例,便于汉语修辞史早期语料的整理与研究。","categories":["02_字词句考释"],"year":2009,"publication":"商丘师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIr8npFD-TmmNwF4XX8VfJIZus0Tj_vIbyWIeXnkFOt6OsVxXSYzzmq0YyqaYvNbPo7FwYwILalCgQGlr7d1UDz3YYkv30lyVIzY9tbEYkhzrXhIZ0f6a3XSvZk0eH1y6FwP1t8UtD9L8ztrsdcDTOtpKbX58PkziGLCIz5fI5bbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"123-126","volume":"25"},{"id":5395,"author":"武振玉","title":"两周金文中“休”的词性和用法","abstract":"两周金文中的&quot;休&quot;有形容词、动词、名词三种词性。用为形容词时有充当修饰语、单独成句和充当谓语三种句法功能;用为动词时主要表示&quot;赐予&quot;义,可出现于多种句式中;用为名词时表示&quot;恩惠&quot;&quot;美德&quot;一类抽象义,是形容词&quot;休&quot;的词性转变。三种用法中,形容词是基本用法,名词和动词为其引申用法。","categories":["02_字词句考释"],"year":2009,"publication":"长春大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJa9GBQpyTA05PvMbX4_Y157JaSVHQ9FPZ1870DbsJ2mz609Tz5wS8molLfyg6F3IgQ6eUozVXrSVgIyW7bP5f6wpiX_npGrCo2MOtQUsHu4-YrZ9OnOSL_ui7E6XNohfs6IRrtUyA0xP4myIqKpfsIRl_jq5oFAIcnPNDTsGpJaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-36, 57","volume":"19"},{"id":5396,"author":"武振玉","title":"殷周金文中的运动类动词","abstract":"殷周金文中的运动类动词据其运动的方向性可大体分为表示&quot;由彼及此&quot;方向的,表示&quot;由此及彼&quot;方向的,表示上下方向的,含有&quot;循&quot;义的及没有明显方向性的五类。就出现频率看,除&quot;各、入、即、从、至、立&quot;外,其余各词出现频率都不高。就出现时间看,第一类相对多见于西早和西中,第二、五类中的多数多见于西中和西晚,&quot;征&quot;&quot;行&quot;则多见于春秋时期,第三类普遍偏晚。句法形式上,第一类多出现于连动式中,第二、四、五类多带处所宾语,第三类多单独出现。就词义沿用情况看,此类动词基本都沿用至后代,只有&qu","categories":["02_字词句考释"],"year":2009,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHmuz-aHQraThhGzh2hSrT1kd1pkHRqYTpp3oaO8cocO6xU0AKIlf-BPTGYl602yStCudjkbBNRDM16WAJ-X6XwgDU0HTrnsyBkrLcTX3wW35d7u5Os99HJb_JmjrWoD4wm8L4m29RKv9sDzqHwGeIsqSa3cFzPQ5k6U2N4vRPAA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-65","volume":""},{"id":5397,"author":"杨怀源","title":"西周金文中的“■”","abstract":"西周金文中&quot;■&quot;的释读是一个至关重要的问题。这个字应该释作&quot;贮&quot;,大多读作&quot;贾&quot;。这可以从字形、词义、语音上得到证明。","categories":["02_字词句考释"],"year":2009,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkWQlTNIdOfv60VzPh6FUt46-_GiAjkFV-rED5YVEEvRIqgdJeJ2BDA8NAEhd68sVbZmBVsbRUJtJ9Mv63njZgD9WmLbXuh6XEK3bWIkhmkLo4119pVWRyDMJfnqgC19X4Iaj7jHb9r0Mo1OwFaCYSI368kSDpZ64yhrW0vTVOSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-71","volume":""},{"id":5398,"author":"程鹏万","title":"试说朱家集铜器铭文中的“集既铸”","abstract":"本文是对朱家集出土的铸客甗铭第六字的考释。以前研究认为此字是&quot;铸&quot;字,不确,当释为&quot;與&quot;。铜器铭文中的&quot;與&quot;可能与古代管理收藏的官吏&quot;舆&quot;有关。","categories":["02_字词句考释"],"year":2009,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ0hOztUR4jHeK6b3TXFU7ZE6w43_Nqww_ljA0ex4w0dR4ThfDjBcrwiEMFDEtTwwDhhavgWna67HDvwgTKci-VYmvrmKUc4jHl8xuN3Q44WKLpNyNZsHDv8_ztkvjGLlRijB7ZL3Napj7wa6oWkjw-2o87Cn7x8nwzj06knPHo6g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-73","volume":""},{"id":5404,"author":"吴良宝","title":"战国韩魏铭文考释","abstract":"新公布的邢丘令鼎盖从铭文格式与&quot;邢&quot;字写法来看可定为魏器,具体王世待定。新公布的韩器&quot;成皋令鼎&quot;铭文,从用字的角度来看&quot;咎奴&quot;不应释读为&quot;高奴&quot;,而可能是&quot;廧咎奴&quot;的简称。珍秦斋收藏的十七年相邦戈铭文中的&quot;&quot;应释读为&quot;卯&quot;,戈铭可以补充史书缺载的魏昭王时期相邦的任职情况。","categories":["02_字词句考释"],"year":2009,"publication":"安徽大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKn2CTgPHAR-pw_Mi1qfEz9bCSBQGU7O3JWYJyS8vumsxUt65ZcgaVWHyeMZG6U5K7glh7a8_cnT5I1J2GRRkLVwtzLO86aT-J2iWToee7fGmJMiQ23RXMJbFJsU5BWefeQ8iFQkLIi-bcguRucDRP_Zly3IXWs1E5nm2_A0jdcgw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-68","volume":"33"},{"id":5405,"author":"余少红","title":"寡子卣铭文试读","abstract":"寡子卣是西周中期青铜器,从清代晚期开始,就有学者对其铭文进行研究。然而时至今日,其铭文中尚有个别文字未能正确隶定、识读,部分文字未能正确考释。现试对其铭文中某些文字进行重新考释,并疏解其文义。","categories":["02_字词句考释"],"year":2009,"publication":"安徽大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXLrJGqAIIQSRVacKXWF0yV-7l0JHNhbYu_ZAxfhuEK-IqDz7YvDS4RJytZoF56DVe3LLeqQWr7redRkvKtWrKTNW9B1vToWfnZgk0JFhFygpkF1Ws6i5i-HhoyUgVqDTlEPglsO8JyTRUExatohlBAy6smdo16kDzW2Q7OztIBw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":"33"},{"id":5415,"author":"姚杰","title":"说“古”","abstract":"&quot;古&quot;这个字,古已有之,字形虽然简单,但人们的认识并不一致。甲骨文中的&quot;古&quot;是这样写的:(?);到了金文中,上面","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLz67ueysBPBQZI9hWrm1MGTmzLW5La0XFfzsWlMzySJevoc90o50fMAdPADx50J3y8bz4kaLcBcsszl0-6sU-gWn3vr6a-ZXE-guQY9fjlHrisZzeKk0B8wi5BeVATRC83ARzST1-CPXsAP2vGbBiTPAWGwaQjnKla2WmPEpyL5A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"12","volume":""},{"id":5416,"author":"李坚","title":"谈“今”","abstract":"俗话说,无古不成今。谈了&quot;古&quot;字,不能不谈&quot;今&quot;字。在甲骨文中,&quot;今&quot;字是这样写的:&quot;■&quot;;到了金文中稍有变化,写成了","categories":["02_字词句考释"],"year":2009,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJynoePuI78rt0qPCHPM1tkyUmOVP2X2SGMN2pvo6ZpFNt2e_jH3aBN0nYOUn3bZgrlPL1z5WDKhnVEm7-xVtJuYwPF4vSUYAI95JoseRF6fS55ML7mMLoxbTzXl39ozZM4jLLvU6IhbKBwZQjvBTKp6LjOCeCUxEDO8HjVVVcEiw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13","volume":""},{"id":5419,"author":"徐海斌; 陈爱和","title":"中山王方壶铭文“愿从士大夫”的释读及相关问题","abstract":"先秦中山国乃北方少数民族白狄所建,曾经是一个&quot;地方五百里&quot;,兵车千乘,实力仅次于&quot;七雄&quot;的二等强国。但由于时代悬隔,先贤旧闻传之甚少,历史文献散佚严重,有关这一古国历史的诸多问题长期处于扑朔迷离的状态。河北平山县战国中山王墓葬群和灵寿故城遗址的发掘为揭示其真实面貌提供了宝贵资料,其中一号墓出土的方壶铭文&quot;■&quot;当释读为&quot;士&quot;,铭文印证了传世文献中有关中山国尊贤重士的记载,揭示出&quot;士大夫&quot;阶层当时不仅业已崛起于华夏诸国,而且开始活跃于夷狄之邦。","categories":["02_字词句考释"],"year":2009,"publication":"井冈山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvnk30K-qfrCZ0I28eNQ-aviOUO1MCLippCRzmA5McAaqDCyIAke65IZVBfjLZKsIH13OgdQ8-F_2BsVZILD5SZvEqEGbA-yeo8HQiETsQ5SJTjh8rU9iAzPzIuFhXY46MXsJBri4byvFo_8GLaWBSva-KopH8nHvIHEmOx5UGhg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-74","volume":"30"},{"id":6437,"author":"郝晓金; 陈双新","title":"金文羡符研究","abstract":"羡符作为汉字构形中一个独特的成分,是十分值得关注并进行深入研究的一个课题,目前学术界都认可羡符存在的事实,并有一部分学者对其进行了分析和阐释。本文通过对《金文编》中的2420个字头及其19357个重文的金文字形进行研究,大致统计出金文羡符的存在状况,并对这些字形进行分析,将其与《甲骨文编》、《战国文字编》、《楚文字编》、《说文解字》等权威工具书中有相承关系的相关字形进行对比分析,研究金文羡符的存在情况和演变情况,从而归纳出羡符在汉字演变体系中的地位和变化。本论文分为四章。第一章是前言,主要介绍古文字羡符的研究现状,探讨古文字羡符研究的意义。第二章介绍学术界对于羡符的描述和界定,并阐述了论文在处","categories":["02_字词句考释"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLglzWqNU_ebFbbGIYZc2Du2GW6SRjMYN6a8Xy-xBGRCiYEUCL5g-_jpoSveXWX5UrdnhtalkJJwOy6SwFNArMs4nHX7_A76R4SbewlF8LXDz_vcug88ZrIGzvbmL7M8q0KbuiXMuh9kYMg611TSltVFiBqixjtP7TXjbC7Xn7kgidqwEDwEUOK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6440,"author":"寇占民; 黄天樹","title":"西周金文动词研究","abstract":"西周金文是最早的成系統的漢民族書面語之一,保持著當時語言的原貌,是這一時期語言的真實地記錄,因此它是研究上古漢語裏文字、詞彙和語法等方面的重要語料。本文選擇西周金文動詞爲研究對象,對其詞彙意義和語法功能進行全面的梳理。全文共分爲以下七個部分:緒論部分概述金文的的語料價值,介紹金文研究的歷史和現狀,闡明西周金文動詞研究的意義和方法。第二章對西周金文動詞的判定標準、數量和分類進行論述說明,確立研究對象爲單音動詞493個,複音動詞102個;依據語法功能,將動詞分爲九類。第三章對西周金文動詞詞義進行多角度地闡述,從單義和多義、本義和引申義、同義和反義、虛化四個方面加以論證。第四章對西周金文單音動詞的組","categories":["02_字词句考释"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3p2Qxu5RA30AAndfuQSWCUV712hP_dlAHRgyEBlXvA_RZS0xls6PmVmMvRUwTGcgWeTBRiSX0c-yHa2pTBZA74yb5bxaKNxQrMwtbCLusMTHxJKv6Li8RpNlJlOsaXKANrzqDlkHtSWi8loHjQP28NqEHqtz0GhzWYRoH8OyNUTWp9Q2370kF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6442,"author":"刘孝霞; 张再兴","title":"金文字量研究","abstract":"研究漢字發展的歷史,必須通過斷代的漢字測查,獲得相關的數據,然後進行歷時比較,確定歷代漢字在漢字發展史上的地位,從而逐步了解漢字發展的歷史脈絡。漢字的斷代測查是多方面的,文字字量的研究也應是漢字斷代測查的一部分,然而對漢字的斷代測查一般容易被人忽視,但其對我們了解漢字整個發展歷史來說,它卻有著重要的作用。金文是我國文字發展史上的一個重要階段,前人已對它做過很多研究。隨著青銅器的大量出土,出現了許多以往不曾見到過的金文形體資料,並且隨著考釋工作的深入以及新材料的發現,以往釋出的一些字經證明可能屬於誤識,還有一些以往未識的字,又有可能被重新識別出來,這樣金文字數也在不斷的變化之中。基於此,本文選取","categories":["02_字词句考释"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLpH3X6Y5GvK8wbYKKgeplKFunJ5KY2DHsjLAwYktqPGxVxLjjXv8qOuCF5mWmvM-lJXPtZG5kCA6Vju3sKJ9JEAFGJpEsQdTKKzfl_QlGxlCfU3mh9skd9yCbS8XBwkz6PEhJtKsXwhUXhPY8__WL55159M7qNBIMuhd4MHd9p632nbD4b1whX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6446,"author":"王卉; 詹鄞鑫","title":"汉代铜器铭文词语通释与研究","abstract":"漢代的銅器銘文既包含著重要的史料,又是印證中國文字書法演進過程的實物依據和豐富的藝術遺產。經過前人與時賢的努力,漢代銅器銘文的著錄與研究均取得了不小的成績,這不但為以後的研究提供了豐富的材料,而且在研究思路、研究方法等方面也頗多可借鑒之處,其研究成果也為我們的繼續研究奠定了堅實的基礎。總體而言,以往的研究的重點是對銘文的釋讀與考證,以及文字内容的闡釋與曆史文化問題的探討;個體的考證和例舉性的研究比較多,相比較而言以文本本體為研究對象的基礎性研究遗不多見,和語言文字相關的研究還較為薄弱。本論文分緒論、漢代銅器銘文詞語通釋、文化研究專題和附錄四部分.緒論部分,介紹本論文的選题緣由、漢代銅器銘文研究","categories":["02_字词句考释"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKX6tJF9L57tRiKgf0JXXPyNeJCIzO4MuvcXdaitpV847-nHmQTuAfxLYIitBBZRM67qBlvpqvoLZ76066Ly85QE7x6img6IKGBGvBhG8Tcs5bkg5F2wOaga0tcHPxP1d62Gq6s3xfJsmx9d73bPjQVCR2J_BifRKq4v-798zRouyuRneDPzniN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6741,"author":"邬可品","title":"谈郑臧公之孙鼎铭补释","abstract":"《考古》1991年第9期发表了湖北襄阳团山东周墓的发掘报告。一号墓随葬器物有鼎,整理者释写其鼎盖铭文为:①隹正六月吉日隹己,余郑臧公之孙,余剌之闙(?)子(?),作铸(?)彝以为父母。其(?)于下都曰:&quot;乌呼,哀哉!剌(?)剌夫人,万世用之。&quot;第二十字腹铭原拓作&quot;(?)&quot;(盖铭此字不清)。春秋时期甚六之妻夫申鼎的&quot;(?)&quot;字作&quot;(?)&quot;(《近出殷周金文集录》2.354、《新收殷周青铜器铭文暨器影汇编》(二)877页),与此最近。黄锡全、李祖才先生曾对鼎铭作过考释。②此文后收入黄锡全先生的《古文字论丛》,所附盖铭拓片","categories":["02_字词句考释"],"year":2009,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxbbvTScVuLyArr-ITUXEUKc0w5gO0BhCvRxxB3B9dyydPbeONRjSGGnmU0VdOGc7pLGEylqsdRNQWQngoWqqWHZD9-1_xUpbsI66TeEB9e9LUXx15Vrc7Vm5vF_Hp312np3awb1ZrJxKamnvZFpqlr8AonTMOB5eYpdgao6HOEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46341","volume":""},{"id":6747,"author":"张懋镕","title":"试论商周之际字词的演变——商周文化比较研究之一","abstract":"本文依据&quot;周人不用日名说&quot;、&quot;周人不用族徽说&quot;的原理,将商周之际的青铜器区分为两大系统;以殷遗民为主的商系统与周氏贵族为主的周系统铜器,从而发现两大系统铜器的主人在字词使用方面的差异,进一步勾勒出商周之际字词发展演变的过程与特点来,并结合文献记载,指出:这一发现将为商周文化的比较研究提供新的资料,也有利于判断某些古书的成书年代。","categories":["02_字词句考释"],"year":2009,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgFtcVhWXiR17W5JxBKqXTiXQia-eJWh2pDd6h8CkQio652MeLoj5XYpZe9q85epAnr--xzTt8DZFaJyWe5bhrommC680PrmlbqZMcys2kxfIQUYHioHU0cJ_ZVpbEP0z1pnyo7_yA4oR4oJp24-IybG3vsLxJH5-DKSxfMLKpzw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-113","volume":""},{"id":6749,"author":"祝振雷","title":"赵孟庎壶铭文补释","abstract":"赵孟庎壶传出于河南辉县,其上铭文记载了吴晋黄池之会,虽仅有十九字,亦可谓春秋时期之重器。关于本器铭文的释读,已有诸家论证1,今不揣鄙陋,作一补充。为方便读者,先列本器铭文于下:禺（遇）邗王于黄池,为赵孟庎（介）邗王之惖（赐）金,台（以）为祠器。本器铭文争议之处在于对禺、庎、惖三字的释读。对禺和惖的读法,笔者赞同将禺读为遇,义为会见。《三体石经·庄公》&quot;遇&quot;写作&quot;禺&quot;,《战国策·秦策五》:&quot;吴王","categories":["02_字词句考释"],"year":2009,"publication":"辽宁省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvAO53S33nn038Gk7X7lRQxj2SPwWQOsVxn86-Y65oD8JONLUSPszftOxpRWPCsyzPL3SCvPkwCBvNZcvLq_lP3LSe8kZDpRGD8lyTMhOpnnpYvHqYmnyd6-JIY344smuEfmgP0VjYqhdNltXsdzxT_Tkf4ZIocuHSq_s6AEY8wQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"187-189","volume":""},{"id":6750,"author":"李家浩","title":"关于姑冯句鑃的作者是谁的问题","abstract":"姑冯句鑃是春秋晚期越国的一件著名青铜乐器,按照过去人们将其铭文所记作器者自述身世的文字&quot;姑冯昏同之子&quot;连读,作器者的名字实际上没有出现,不符合当时铜器铭文的格式。本文根据春秋时期铜器铭文所记作器者自述身世的文字特点,认為应该在&quot;姑冯&quot;与&quot;昏同之子&quot;之间加上逗号。按照这样断句,&quot;姑冯&quot;是&quot;昏同&quot;的儿子,也就是该句鑃的真正作者。&quot;姑冯&quot;不见於文献记载,但是其父&quot;昏同&quot;却见於文献记载,即越王句践时的大夫舌庸。","categories":["02_字词句考释"],"year":2009,"publication":"传统中国研究集刊（第七辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvAO53S33nn038Gk7X7lRQYu2frnTACg5wj5E7N-x7t8aRvZU2OqO9EXtsow3VWdGGstdx4A5ROh_qqwD6meWiyQULZ6NDzgbfW9dCGn1ZrR64ydwlrZ9hT3goTAjloxzqS-xaSV-XoIjU47nXNgfswbPuboQ4TCAEBFmMojyKIRJXmS_VTjS_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46280","volume":""},{"id":6751,"author":"岳洪彬","title":"殷墟的镞与甲骨金文中的“矢”和“射”字","abstract":"镞是中国古代最为常见的射杀兵器之一,殷墟遗址中也有大量出土。从其形态来看,不外乎带尖锋的锋刃镞和不带尖锋的平头镞两种。其中锋刃镞数量占绝大多数,其用途已明了无疑义,而不带尖锋的平头镞和圆头镞虽占比例较小,但其用途却往往令人费解。陈星灿先生曾对国内外所见非锋刃镞资料进行过讨论,","categories":["02_字词句考释"],"year":2009,"publication":"夏商周文明研究·九——甲骨学110年：回顾与展望 王宇信教授师友国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.001725","pages":"371-381","volume":""},{"id":6765,"author":"麦里筱","title":"商代甲、金文是否已使用合文符号","abstract":"本文是我讨论古文字的重文符号的延续,也是继提出解释重文符号的&quot;同形异用&quot;的那个假设后,有关商代甲、金文符号的另一个探讨。重文、合文两个符号都是汉古文字里罕有的书写标志。由于本质上带有量的组合或重复性,这两个符号在使用的演变过程中,可能存在着某些内在联系。然而本文的重点,将是决定这个合文符号开始使用的时期(见麦里筱2008)。","categories":["02_字词句考释"],"year":2009,"publication":"夏商周文明研究·八——纪念王懿荣发现甲骨文110周年国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.001773","pages":"236-240","volume":""},{"id":6766,"author":"赵林","title":"论出土与传世先秦文本中的生、姓、甥","abstract":"壹前言先秦时代的&quot;生&quot;字,以及从生的姓、甥、■、眚、性、牲等字,在传世古籍及出土的甲骨金石竹帛文本中,常互为通假,或一字多词,用例有异,造成了不少释读上的分歧;而其中&quot;生、姓、甥&quot;三字的问题,更与古代社会结构和亲属制度密切相关。","categories":["02_字词句考释"],"year":2009,"publication":"夏商周文明研究·八——纪念王懿荣发现甲骨文110周年国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.001784","pages":"335-354","volume":""},{"id":6768,"author":"刘志基","title":"简说古文字异体字的发展演变","abstract":"立足汉字发展史的视角,分殷商、西周、战国三个时段描述古文字异体字系统状况及其发展演变。殷商阶段,甲骨文异体字形总数占字形总数的比重大大超过后世文字系统,表现了字形系统内在规范性较差的早期文字特性;甲骨文的异体字呈现单字所含异体字形数与含异体的单字数的反比例增长趋向,多异体之字具有高频、多义、表达文献热点语言单位等特点。西周阶段,虽然金文异体字形占总字数比重较甲骨文有明显下降,但多异体字头所含的异体字形数大大超过甲骨文,而青铜器铭文更大的地域国族差异是其重要成因。战国阶段,整体战国文字异体字形占字形总量比重较之西周金文又有大幅度的降低;相对整体战国文字异体字比重,楚、秦、晋、齐、燕五系文字的同口","categories":["02_字词句考释"],"year":2009,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iILx8AYBKUzuGMVXoBxcbmDfXivcTk_hyBkotAmTxzI-mNaSi1codENIW7pGvlegQVES6pXMLyWlSaamysmRWBNfTbtYDTpgIlMg8ZuOnOnxw1-ga8SwgGmBKrgoo2SMWRbpSKwO3TRANeKJVq2W8BPb9y8S0icLi0A8QhGNmEvhA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-46","volume":"1"},{"id":6770,"author":"孟蓬生","title":"越王差徐戈铭文补释","abstract":"珍秦斋藏越王差徐戈经过曹锦炎、吴振武、董珊等三位先生的考证,已经基本上可以通读。本文在董珊先生所作释文的基础上对铭文中&quot;未&quot;字的构形作了补充论证,并对其中&quot;居乍&quot;、&quot;金&quot;、&quot;得&quot;、&quot;就&quot;等四个字词的训释提出了新的看法。","categories":["02_字词句考释"],"year":2009,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLpVKokw7-dhY_qecpMPxMBEJ0CivRmOxhXFB6KNZMSj9EF8MIoaHUMQ1Vz5c-COiBnUrVMM-rxDfgm6JS2oFw1VcXS5OVzeqp2tB8ZJSwygJZnYJycWQ25fT3ZWi2BqX1JQaq-8VA88eEJHkxm5zp9kAdgczUVNumhLT0_aqCEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-49","volume":"1"},{"id":6771,"author":"张振谦","title":"邾友父匜考释","abstract":"《殷周金文集成》10236鼄□匜,旧有一半字因残泐而没有释出,且释文不能通读。本文利用电脑技术对其文字进行考释,认为其铭文与邾友父鬲相同,并予以正名曰&quot;邾友父匜&quot;。","categories":["02_字词句考释"],"year":2009,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkoNNR1gmUevGNwd0fHUH9dqH2RuriXF7zJszTYE4sELQqNrKEWwwcrLREmHOryUEUrht5inb0vC-dBzS_kMb6ZTF2pYg0zuFdPgB3HFiZpMmSi37BCrWthQ4wftQYIj_nQ4wOPW7ui5GExttPq1s6nqyUIUQFy68CUa3670F5Pg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-88","volume":"1"},{"id":6772,"author":"何家兴","title":"金文札记二则","abstract":"本文认为者■钟中的■是&quot;■&quot;字,读作&quot;濁&quot;,铭文&quot;不■(濁)不清&quot;的意思是音色和顺优美、清浊协和。关于樊君鬲中&quot;■&quot;字的构形,我们认为应该分析为&quot;从人从贝,興声&quot;,并进一步探讨了楚简、玺印、帛书中&quot;興&quot;的构形演变轨迹。","categories":["02_字词句考释"],"year":2009,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKx12d6z5BQoqq6NrqBdl3BD4E7rAsaeqJ3Rm6phzBxmdUV0uEam4E0Ef3dGmeUHuFoLPOMl-R5ipkvb1L0HOQLHBLMgvSicLIMuwmccOCWjJSW5YDE_HYm3ytE1UkFO3AacmAYn_X-7SplzRqVgwd38_GA4Oh2GZASda761vQRrw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-91","volume":"1"},{"id":6773,"author":"顧丹霞; 趙振興","title":"西周时期否定副词“不”与“弗”的比较","abstract":"&quot;不&quot;、&quot;弗&quot;在表义、功用方面既具有强调否定的内在一致性,又因为原词的语义积澱不同,存在一些区别:&quot;弗&quot;主观色彩较强烈,而&quot;不&quot;在句法、语义、语用层面极具灵活性。","categories":["02_字词句考释"],"year":2009,"publication":"汉语史研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDDsRO3QwNtv-SrMWpxY5gT_40fzdOEqv3nUNPYR5e7FxPxKu7-8DElRObjRpt8zrTECKOdveTPWz4dNbYSfHP3Qy-LeMX-X8y9YdsLeUjVWOlR21XPC_lI33mLdkd82LqAGBMayTdbbmkDKgQ-LMzdtWYV6-Ue9icbce8cJ-UeQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"115-128","volume":""},{"id":6774,"author":"鍾如雄","title":"《诅楚文》“■■”考释","abstract":"《祖楚文》中的&quot;■■&quot;,前人或释为&quot;■■&quot;,或释为&quot;■■&quot;,或释为&quot;■■&quot;,均觉未安。从后出转形字构形的规律考察,&quot;■■&quot;应为&quot;■■&quot;,是&quot;襜褕&quot;的初文,意思是古代已婚女子做事时穿围在胸前的围裙,与今西南、中南地区妇女穿戴的&quot;围腰&quot;或&quot;长围腰&quot;相似,亦与今藏族妇女穿戴长的裙衣相似,在《祖楚文》中代称家庭妇女。","categories":["02_字词句考释"],"year":2009,"publication":"汉语史研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDDsRO3QwNtv-SrMWpxY5gT_40fzdOEqv3nUNPYR5e7FxPxKu7-8DEzDcQDnR_L00C49L_AHx_tzCPMT8gyUYLlYQVLf1fDk0sThNqvd-ppdHJ0pUYm0d7olI2cwfZJ8fyvuvt05H0u7HotqodLYzHW6OO5VUQXpgKleVZoffoHQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"345-357","volume":""},{"id":6781,"author":"武振玉","title":"殷周金文中的特殊句型","abstract":"殷周金文中比较特殊的句型有宾语前置句、双宾语句、被动句、处置式、连动句、兼语句、双重否定句。宾语前置句有以&quot;是&quot;和&quot;唯&quot;为标志的两种,前者集中于春秋时期,后者数量有限。能带双宾语句的动词主要是取予义动词。被动句只有用介词&quot;于&quot;引进施事对象一种形式,多见于西周早期。处置式只有用介词&quot;以&quot;引进处置对象一种形式,主要见于西周中期和晚期。连动句中的第一动词主要有运动类动词中的&quot;来、返、于、从、出、入&quot;,征伐类动词中的&quot;率、以&quot;,辅佐类动词中的&quot;左、右、胥、召、夹、匹&quo","categories":["02_字词句考释"],"year":2009,"publication":"燕赵学术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBAAcLRprTGxRpKCaMNxJs-rgOX-RZrhqNKd8R9Gq-TC3dTJXT1V9HM9WiGeTLp2br7PkllXkvaZr7YfbUXMUoad9eet2nxQBmnEjF4jbSMNkk_q5UMUAxKg6U1hnqzsB1FcriWskQCjrjbS71-Ra3ASTG8kLtk1XBAfdyWAHWEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-123","volume":""},{"id":6783,"author":"林志强","title":"“貞鼎”、“貝鼎”、“則鼎”疏釋(摘要)","abstract":"《说文》大徐本:&quot;鼎,三足两耳,和五味之宝器也。……籀文以鼎为贞字。&quot;末句小徐本作&quot;古文以贞为鼎,籀文以鼎为贞。&quot;郭忠恕《佩觹》作&quot;古文以贞为鼎,籀文以鼎为则。&quot;段注本作&quot;古文以贝为鼎,籀文以鼎为贝。&quot;各家之说,互有差异。","categories":["02_字词句考释"],"year":2009,"publication":"福建省辞书学会第五届会员代表大会暨第十九届年会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLntVg_ZgdEuHVqzeREej-Fbdqk69Xf_hSp1MD3aXwH4hboSP-utnejYnL5s4qv-rG4Ix0LhXyJDtHQ-ljw4zJSpCc6Is20Wme9lzXI_wVwBcQPh6t4-zXYDwBQeC57iXnIv0mjUEFvVGBhYQLRF8wHj-Call9NvIkaTjXYNd3iIpjDzFPR1rev&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87","volume":""},{"id":6784,"author":"刘信芳","title":"安徽凤阳县卞庄一号墓出土镈钟铭文初探","abstract":"2007年,安徽省凤阳县卞庄一号墓出土镈钟一套,有铭文的计5枚。铭文内容涉及古钟离国之先公,并可由此确证舒城鼓座铭文&quot;童鹿&quot;亦应释为&quot;钟离&quot;。这套编镈及舒城鼓座铭文对于研究钟离国史以及锺离与徐、吴、楚诸国之关系具有重要的参考价值。以下我们先作出释文,然后讨论文字以及相关问题。","categories":["02_字词句考释"],"year":2009,"publication":"纪念徐中舒先生诞辰110周年国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.002831","pages":"194-201","volume":""},{"id":6789,"author":"张桂光","title":"金文札记两则","abstract":"一、说■、■、■分别见于《汉金文录》卷四著录之熨斗与镬,容庚先生释作&quot;千万&quot;合文,并分别定名为&quot;千万熨斗&quot;与&quot;千万镬&quot;（1）。容庚《金文续编》及孙慰祖、徐吉甫《秦汉金文汇编》以及徐正考《汉代铜器铭文研究》、《汉代铜器铭文文字编》均依容说释为&quot;千万&quot;合文,无异议。","categories":["02_字词句考释"],"year":2009,"publication":"纪念徐中舒先生诞辰110周年国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.002828","pages":"175-176","volume":""},{"id":6790,"author":"陈英杰","title":"两周金文“器主曰”开篇铭辞研究","abstract":"我在对两周金文进行分期分类整理时,发现有一类&quot;器主+曰&quot;开篇的铭辞具有一定的特殊性,引起了我的注意。后来在搜集材料过程中发现,这个问题有两位学者也予以关注。一位是裘锡圭先生,他在《戎生编钟铭文考释》中说:&quot;戎生钟和晋姜鼎的铭文的开头,都先记时,接着以‘某某(器主名)曰’引出铭文。在过去所见的西周铜器铭文中,以器主‘曰’开头的例子是屡见的,如■方鼎以‘■曰’开头,师望鼎以‘太师小子师望曰’开头,大克鼎以‘克曰’开头,禹鼎以‘禹曰’开头,厉王所作的?簋以‘王曰’开头,■钟及簋以‘■曰’开头,虢叔旅钟以‘虢叔旅曰’开头,梁其钟以‘梁其曰’开头等。","categories":["02_字词句考释"],"year":2009,"publication":"纪念徐中舒先生诞辰110周年国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.002829","pages":"177-188","volume":""},{"id":6793,"author":"罗琨","title":"商代寝官初探","abstract":"甲骨文中有■,从宀、从帚,隶定为&quot;■&quot;,金文同,或加又,作■,是寝字的初文,研究者往往直接释为&quot;寝&quot;。对于此字前人多有考证,如丁山论金文&quot;■&quot;字从宀、从帚,帚为妇省,妇人所居之室《礼经》谓之&quot;燕寝&quot;。天子诸侯有三寝:高寝、路寝、小寝。小寝即燕寝,王侯食息之所;路寝即大寝,亦王听政之所,甲骨文中的寝都该作大寝或路寝解（1）。","categories":["02_字词句考释"],"year":2009,"publication":"纪念徐中舒先生诞辰110周年国际学术研讨会论文集","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2009.002851","pages":"306-314","volume":""},{"id":6796,"author":"张娜; 郑振峰","title":"战国中山国文字构形系统研究","abstract":"本文以汉字构形学理论为指导,运用系统归纳和综合比较的方法,借助计算机技术,对战国中山国文字材料进行了整理和研究。我们从可见的中山国以“平山三器”、“兆域图铜版”为代表的有铭器物中,整理出552个不重复单字,并对单字的异写、异构现象进行了比较详细的分类及描写。单字中,有544个按其构形理据予以拆分,对字形拆分得到的构形元素的功能、组合模式及层次等多项构形属性进行了探讨。最后,通过与其他历史层面的汉字构形系统的比较研究,分析并归纳了中山国文字构形系统的系统性及特点。经过对所见全部中山国文字的考察,我们发现:作为特定历史平面的汉字用字体系,其文字构形具有系统性,且已经比较严密,但尚未完全成熟;中山国","categories":["02_字词句考释"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI964AiuPj0HqJqPb4SCb0Kvq_vgktp1o8wmyBMhfTf1OoDoGTSMdC_0CePdABTLNZBSjVC8oNPuVKok2k6XE5RRZYkpc9h7b-2ztdgrBVxwL3-NL4DMJlBbZ1npgc_kPkDChd4edhH4JOhb0OGDBQSmjPMUbWwzhbN9k4L_FWPNMbnyugNpQ_b&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6798,"author":"金东雪; 吴良宝","title":"琱生三器铭文集释","abstract":"本文所说的琱生三器是指传世的五年琱生簋、六年琱生簋及新出土的一对同铭五年琱生尊。由于三件器铭文在内容上相关联,所以学者把它们放在一起考察,称之为“琱生三器”。五年琱生簋和六年琱生簋早在清代就已有研究,现在已取得很多研究成果。例如:确定器主是琱生,铭文大体已疏通等。五年琱生尊的出土再次引起了学术界对琱生三器的热烈讨论,并给解读铭文带来了新的启示。例如:破解了“止公”的身份谜团,即“止公”非人名。本文就是在搜集和整理诸家研究成果的基础上,对琱生三器铭文进行集释并梳理相关问题。前言部分,对琱生三器形制和年代、著录、相互关系及人物关系等问题进行说明。集释部分主要汇集了孙诒让、郭沫若、杨树达、陈梦家、林","categories":["02_字词句考释"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKnoXuzRWbWQB0XxdfS-o6tEKGhZFQVOLsb0QvDgNz6gkoi25fZ55x5m5Eb7vuNqfPldSljripMAdVmeZzwzx4qkJmQghnoxvjmlUJtkjc-inFLTY_VwZ2uyyw-11h7enfulIfcy2AvtI9aQuuZ1hu9LwSXg46QMBMBagkLUy674ybKmE3Mrt4V&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6983,"author":"王志强; 王磊","title":"“曰”字探释","abstract":"《说文解字》是我国历史上第一部字书,对汉语言文字学的发展具有里程碑的作用。其对字义的阐释亦为多数学者所信服,但是,不可否认的是,《说文解字》一书中也有一些不尽之处,其对&quot;曰&quot;字的阐释便是其中一例。本文试用相关材料对&quot;曰&quot;字重新进行阐释。","categories":["02_字词句考释"],"year":2009,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmHp-uDHmk7h8dH5gzJALwIWf2IR7KEsS3dkNDnlE7MiNTmwHLGELOtLivwD887AfQN79G4PnXrVFaNQUvDbIfXPOdfP2sHP9GVmpw6k4f6BSoWkZG7jWgVhYX1ADsB4bCJQ052lFttuDZZ4Huhkx-hElIcXyT-zqWF6cAS3F6FuHBuJNqIefE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-35","volume":""},{"id":6984,"author":"武振玉","title":"两周金文心理动词试论","abstract":"两周金文中的心理动词可分为表示&quot;恭敬&quot;义的,有&quot;恭、敬、虔、寅、祗、严、翼、(?)(恪)、齐&quot;九词;表示&quot;喜怒&quot;义的,有&quot;侃、喜、乐、娱、慈、爱、哀、忧、怒&quot;九词;表示&quot;畏惧&quot;义的,有&quot;畏忌、畏、惧、恐、懅惕、虑&quot;六词;表示&quot;谨慎&quot;义的,有&quot;谨、慎、恤、毕、小心&quot;五词;表示&quot;顾念&quot;义的,有&quot;欲、愿、怀、念、恤&quot;五词;表示&quot;荒怠&quot;义的,有&quot;荒宁、宁荒、怠荒、逸康、康、懈","categories":["02_字词句考释"],"year":2009,"publication":"华夏文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLk3MvC5qRxFlb0snZw33BS8UUF2kP9sBDmwGYba6MAswGBHZ5Qnv4TDgU1Y39qBILXKGQPxIMrNxKZvA8jyXb648pn6l_3jA8Z_LjZDBopeYihZ2DvMIllTW2GuPzcAifL08yK-TxBhUGxh5pDXYQHGX521j88HdTGXRkzw_3kew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"181-185","volume":""},{"id":6987,"author":"胡平; 陈春风","title":"“己、巳、已”考辨","abstract":"&quot;己、巳、已&quot;是三个字形简单而且形状非常相似的字,无论是单独使用还是作为构字部件,它们都比较容易被混淆。本文从它们的产生发展历程、字形字义和构字能力三个方面进行分析,以便达到区分和正确使用的目的。","categories":["02_字词句考释"],"year":2009,"publication":"青年文学家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbdWT7gdZ9BfpXE9EYYrfWo7k_s64VD81JaqQr7O0aY-bWYT_6N0Z0bcCt4iFZM9MGSQvw8T1GN0yLnQ-EwQLkkKzTuzgtVJp8rmzdPNdWRta8-D0CQ1JoyNl2B8XeijS2D1j_pUgja3Su_L9PtkWO5t5vtZK5Rn4-gelLBSZphQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-67","volume":""},{"id":6988,"author":"曾四美","title":"近年所见湖南出土商周铭文概述","abstract":"近百年来,湖南发现并出土了较为丰富的商周古文字资料,有铜器铭文、兵器铭文、玺印文字、简帛文字、货币文字等。这些材料对研究湖南地区的历史文化乃至于楚文化都具有重要的学术价值。本文对这些文字材料做了系统梳理,并在综合研究材料的基础上,对当前研究中存在的问题,提出一些初步看法。","categories":["02_字词句考释"],"year":2009,"publication":"当代小说（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK7uwa4N3uiMk1GUbikEuU8oJ4mmWTFzSW4t6ZRohJD1oW8W1nyIsG4QHgKflYdhdBwyz-V7a_lGg3lqdNAEu1TigqkG2efMNVc9XR8K7b7vU672vPrq-_o-0ZZgdxflkO1rU6pQ1MFWtkoIGmSjeFohssVwGK1PkJXFuE11LTfMw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":""},{"id":6989,"author":"王立军; 温英明","title":"汉字与古代兵器文化","abstract":"中国古代的兵器种类繁多,那么,在造字时代,哪种兵器最具有代表性呢?关于这个问题,我们可以从&quot;兵&quot;字的构形中找到答案。&quot;兵&quot;甲骨文写作,左右两边的构件是两只手,中间的构件是&quot;斤&quot;,也就是斧头,整字是通过两只手捧着斧头的形象来表示","categories":["02_字词句考释"],"year":2009,"publication":"中国教师","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL3pRuFGV9Q_QLKgy4T7jTWcg6-5Ye3qrTx3LhJBCu-Anxy784v8Z0BvB7IA5lZmfbRZzRBrrZK91GN1HF0Bd7UdYQe7nagUWbmKXcOUyvZfq5AZJ35-rk7YxwtKRBf-pRIzO2PKk89dKDYGWNzp_9ovAR6fZhTeaESa77-uUd2FxfXmoXnhVNf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-56","volume":""},{"id":6991,"author":"薛培","title":"“匕首”考释","abstract":"&quot;匕&quot;在现代汉语中的解释是&quot;匕,<书>,匕首&quot;。匕首是一种尖而薄的冷兵器,但在古代汉语中,&quot;匕&quot;最初用来指一种取饭用具,类似我们今天使用的羹匙。现代汉语中的&quot;匕首&quot;之&quot;匕&quot;与古代&quot;饭匕&quot;之&quot;匕&quot;是否有联系呢?本文试从&quot;匕&quot;的本义入手,结合饭匕、匕首的形状与性质,对&quot;匕首&quot;一词的形成发展做一解释。","categories":["02_字词句考释"],"year":2009,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5z2_32DFVUciu83zJiDhjyL9fS0LBTQvOa78IWMp7cGls1e8SUwMY7LirgKLaEgnwHgwzUHn2Ev7LqkBtlIgeCAXyh437lIFoYLlq1H8FNzZdMns2zSJb2tbh2LTxrrrvUsEFFy71M07fTbWG_ahyk4PYPHH5T4h9FkAWk08G2Fxph2btEXVN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-150","volume":""},{"id":5421,"author":"赵平安","title":"从语源学的角度看东周时期鼎的一类别名","abstract":"东周时期青铜鼎的自名緐、■、钣、■,过去对它们有不同的理解。通过考证,它们是同一个词的不同写法,共同语源是笲。笲的形制和功能与鼎相近,所以用笲表示鼎。这种现象主要见于江淮流域的南方诸国,它们属于楚文化和受楚文化影响的地区。","categories":["02_字词句考释"],"year":2008,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIB3x8AbE_hJ3cf7ain7L-4l9PRNPl6W0Q6pANyA9L66puBenTSE6p0DrRel8mWd_6Rg5oo7CJlzX86X8j4_6mJGaS_1Z9bvP_J0dkHFmA4ZOSjBPgb1n1ImcCAT6w1jdaK7ahFHEe_NxJADFJxnWhw_ueIzMjdf5avG7sRJiIPMQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-70, 2","volume":""},{"id":5425,"author":"何景成","title":"试论焂戒鼎所反映的“羡卒”问题","abstract":"本文讨论了焂戒鼎的年代和铭文中&quot;羡&quot;的含义。认为焂戒鼎为西周宣王时器,铭文中的&quot;羡&quot;指&quot;羡卒&quot;。器主受命管理六师和羡卒的时代背景,很有可能与周宣王时期因战争规模的扩大而加强对民众的管理有关。","categories":["02_字词句考释"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdFGDKdD_bB2pWfG_Zap9Xqbqm8VRydfR-S1c8Wsua-6jBjYLzh3DUQlhLU0nHFJCHZCv-5kz_VadSTEqyouCRCLDxWkXdxq-wowTmEdgVnOfQCGap2CM1vcDFDMkvmErhO08fPME4YOjYcozPPgU5XMZWHScDGZ-zq96IRoiiqQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":""},{"id":5426,"author":"寇占民","title":"金文释词二则","abstract":"戎生编钟铭文中的&quot;倝&quot;,读为&quot;榦&quot;,应训为&quot;防御&quot;义;史密簋铭文中的&quot;雚&quot;,读为&quot;觀&quot;,应训为&quot;觀兵&quot;义。","categories":["02_字词句考释"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAuWV08tbj1781ZZCOtitlYcSFpon9E0VIvfKGXehKksOdWmymvWoN-TWhsuvz38QGbA7XX77_Y5L06yuWNmPjKUQyC5nSkhfyebPBYiNT1X9CAWKHEO_ml-RwfKnL3xz8UrtvLmZm9gv2x_l3u6C3jd-TkjLaMSXqbdh-z7S6Ew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-91, 106","volume":""},{"id":5427,"author":"韩丽","title":"五年琱生簋关键字词集释","abstract":"五年雕生簋是传世的西周重器,《攈古》云:&quot;见洛阳市中,后归山西马氏。&quot;图形见《商周彝器通考》311页,铭文见《殷周金文集成》4292,现藏美国耶鲁大学博物馆。内底有铭文11行104字。又名召伯虎簋、五年召伯虎簋。五年雕生簋、六年雕生簋和2006年陕西出土的五年雕生尊是紧密相关的。在前人研究的基础上,本文结合各位先生对六年雕生簋和五年雕生尊的释读,对五年雕生簋中分歧大的关键字词做了集释,并提出了一些不成熟的意见。","categories":["02_字词句考释"],"year":2008,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2u-z8LpcqjevzNUOiHQDdfmxUDUXcOgnCQPcwzv9AMd3-A0dfaSjtu-phWQr4lnzmRJBbCTqOsRdwnZRxMF5dGCt8SM8Y2INgi_aKoFNoQG0n7zCwmA8_ChBs2fMX0f4_PW_1fhkm6jSQEnTk4MZKiHLciDrDgFQmystloyFuWw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"303","volume":""},{"id":5431,"author":"张利军","title":"释金文中■字——兼论青铜器匜之得名","abstract":"金文中■字,专家或隶为夗,读为虚词爰。或隶为(尸月)读为虚词夷。或隶为屑,或隶为肩,或隶为仴,或释为佾,诸家释读都忽略了伯庶父匜这一器物,此器铭文是解释■字的关键所在,器作匜形而自名为■与匜形而自名为盉的现象是■字训解的突破点,■字隶定为(尸月),读音应为盉,取盉转输液体之转义。由此而得见匜器与盉器的关系,匜器功能承袭盉器而来,又逐渐分离形成盘匜组合新制。又由此而知西周中后期天子的臣与诸侯、大夫的家臣可以相互转任这一重要社会现象。","categories":["02_字词句考释"],"year":2008,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInrHpz8mWmx-pghz6MYRkGsWItPiF_zRGv8pkh6EwbHLwbI_kIwLOT1OFJTvtoYMsT1FaqOu7LJTXwgZX6AL5D1mNd-rIjrIShTStAA3a77VeH4OFsJeopt3gID02-3fu1YF0VJJJzG6j-YsI7CZ91046VGuPT5VoPxNRtjoGJag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-36","volume":""},{"id":5435,"author":"武振玉","title":"两周金文助动词释论","abstract":"助动词是汉语动词中比较特别的一个小类,已往针对传世文献的相关研究已取得了比较丰富的成果,但甲骨金文中其应用情况尚有不明晰之处。如甲骨文中是否已有此类动词就存在不同看法,两周金文中已有此类动词是可以肯定的,唯具体情况也有充分调查之必要。通过调查,可知两周金文中的助动词虽个体数量和出现频率尚不高,但已形成了包括&quot;能可&quot;、&quot;意愿&quot;、&quot;事理&quot;三类的助动词基本系统。与传世文献相比,表现出一些有同有异的特点,可为传世文献的相关研究提供参考佐证。","categories":["02_字词句考释"],"year":2008,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2008.04.017","pages":"114-117","volume":"29"},{"id":5440,"author":"张德良","title":"金文“嚴在上,異在下”浅析","abstract":"西周金文中常有所谓&quot;嚴在上,異在下&quot;,出现于铭文的末尾,属于祈祝辞一类。自郭沫若起,学者多有研究,但也意见纷纭,对此有再研究的必要。为便于分析,拟列相关铭文如下。","categories":["02_字词句考释"],"year":2008,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJVmmR-_BZT40MhIZqSCzZaQvL7mDrKZDYxbh_hEiGlRUpvJfTJ7Ip0aklEt7c5IaMwqgmpv2HNGLFPrTK76uQCEZ4mtdtyzo47FUhcDxX306aFfmn4COULbcrWtA4SzHJBLHrbxxyM2cd3OLMD_JwIu6r2JA7Y7KSMxSPz8zeDLw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-99","volume":""},{"id":5441,"author":"严志斌","title":"商代赏赐金文研究","abstract":"商代末期铭文字数渐次增加,记事性金文也逐渐流行起来。商代青铜铭文中最常见的内容有族氏铭文、族氏铭文加祖先称谓、单纯的铭&quot;某作某器&quot;等。另外还出现了记事性铭文。这类记事性铭文,字数多在10字以上。这些记事铭文,以赏赐为其内容","categories":["02_字词句考释"],"year":2008,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXUTeYSRJIG5WGwKvNKTrplwh25APChgAhEKb6A3L4iG5MMB3qlPY37CFmuCxN3dTw4a5B7ge3ylZ6LcvVUy-QPYKQ6abuGQc2XwYcouDerLemeqsm3eAwTgeExxscXHaHOsUInHXLCQwB3LzKVffh4Hb7RCfo2j-pNCfbxqxGag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-103","volume":""},{"id":5446,"author":"常玉芝","title":"由商代的“帝”看所谓“黄帝”","abstract":"早在20世纪20年代,顾颉刚、胡适就指出秦以前的&quot;帝&quot;是指天神&quot;上帝&quot;,&quot;黄帝&quot;是西北秦民族的天神,而不是指人帝。在商代甲骨文和金文中有许多&quot;帝&quot;字,总结这些&quot;帝&quot;字的用法可分为三种:一是作祭祀动词是指禘祭;二是作名词是指天神上帝;三是作庙号表明商王不称&quot;帝&quot;。由此看来,既然三千年前的商王朝,&quot;帝&quot;仍是指天神上帝,商王都不称帝,那么,传说生活在四五千年前的所谓黄帝,就不会是指人帝。","categories":["02_字词句考释"],"year":2008,"publication":"文史哲","link":"https://link.cnki.net/doi/10.16346/j.cnki.37-1101/c.2008.06.009","pages":"35-48","volume":""},{"id":5449,"author":"陈絜","title":"应公鼎铭与周代宗法","abstract":"河南平顶山应国墓地新出应公鼎,其铭文有重新释读的必要,也有重要的史料价值,可促使今人对周人是否行日名之制、周代宗统君统之关系等问题的深入思考。该器铭文的&quot;■&quot;字,属祭祀动词,其义或与进献稻粱祭祀祖神相关。&quot;珷帝日丁&quot;是指周武王。武王以日名为称,纯属个别现象,既不能说明应国始终行日名之制,更无法证明姬周王室有类似习俗。综观文献及相关铜器铭文资料,西周及春秋时期并无后世礼家所谓的&quot;诸侯不敢祖天子,大夫不敢祖诸侯&quot;之礼制。","categories":["02_字词句考释"],"year":2008,"publication":"南开学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4pp5knsmgqwwt0cUUnqvMoCI8xZ46OBcLUymCyOvQD_L1SoXvSwv504Ud6DBKbbuQROoyPFA-V7W7lKY8VEVsfyZvIf_PpP-4ENvhYRBkXrwvGJe5gC4VjeXQnX3CeP8kWkLqgxr3y8m9TLrd9YzmGTdSCB56t9B04COGk1oXJg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46251","volume":""},{"id":5452,"author":"刘攀峰","title":"浅析“于”字在甲金文中的用法及比较","abstract":"在汉语的发展过程中,现在的虚词大都是由以前的实词虚化演变而来的。&quot;于&quot;字早在甲骨文中就已经出现,到两周金文时,它的用法和意义又有了新的发展变化。由于它在甲金文中是一个高频词汇,所以弄清&quot;于&quot;字的来源及其语法化过程中的一些变化对我们正确的释读卜辞和铭文都至关重要。","categories":["02_字词句考释"],"year":2008,"publication":"和田师范专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKC-DLVzgFyvZZNBZYDCdu0ON38kykYOs53ctnqDo42jzahjatcVsaSu4yufqFR0NGdAjt7KnnKcZDy9aunbolS8hRRXbrxiA5RPtJHN2vAAFwOxCeWe3LNJhIh48e60KfISaE2kisYETPURR8ZO7o7j7lxhIiS2ZmSWqQczEeZA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-79","volume":"28"},{"id":5453,"author":"李义海","title":"先秦时期汉语中的合叙与铜器铭文的释读","abstract":"合叙是古代汉语尤其是上古汉语的一种重要表达式。它不仅在传世书面文献中大量存在,而且在两周金文中也有所发现。对它进行整理与研究,不仅可以丰富汉语修辞史的内容,而且对古文字资料的释读也有着重要意义。","categories":["02_字词句考释"],"year":2008,"publication":"修辞学习","link":"https://link.cnki.net/doi/10.16027/j.cnki.cn31-2043/h.2008.06.017","pages":"51-56","volume":""},{"id":5454,"author":"李义海","title":"据合叙行文释读金文二则","abstract":"合叙是上古汉语的一种重要表达方式。以合叙辞格为视点,从铭文辞例入手,依据书面文献资料,有时可以有助于古文字资料的释读。本文便是对两篇东周时期青铜器铭文进行释读的尝试。","categories":["02_字词句考释"],"year":2008,"publication":"吉林广播电视大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoeFwu0ZcJDrPa_bJX1FiF4BM08RRp2Yw2Zqww3_4VZyNEsem1GhAVJ-urVxlKTdbGSpWBHo5igpthUbvWzKWpaUH_rnzIcCjWy3ge_r3K8_uInaexAhwbE6dTenCRbb5aK9XrRrVSwC7IxYpByyr6zemoeX7PMlwrFWYwHF2syg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-68","volume":""},{"id":5459,"author":"徐海斌","title":"中山王器铭文补释三则","abstract":"本文对中山王■墓出土的斧钺铭文&quot;(丸心)&quot;予以考释,推翻了&quot;丸&quot;不见于出土先秦古文字的说法,也为器主的确认提供了依据;同时对圆壶铭文&quot;燙上&quot;、&quot;氏&quot;、&quot;隹&quot;等字词作了改读,有助于进一步理解文意。","categories":["02_字词句考释"],"year":2008,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2008.05.012","pages":"28-30","volume":""},{"id":5467,"author":"苗利娟","title":"商代金文字■探微","abstract":"","categories":["02_字词句考释"],"year":2008,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtvS9Cjq_6DMcKdIHsNA8a1__MSyva26h4zo6_7qPZLdHYZboVy94NW5QyuX8Y9ZpHrAlr8-0XdWQs5tnouBDiocoCTeOoHxKFVaWQbsCkf32nDG-Liocw_qyyN_xNeAORks-crzgfbPtUmVI6Gk-d5aWbWyeLH6_gENWC4QMAbA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-33","volume":""},{"id":5469,"author":"武振玉","title":"两周金文介词“用”“以”用法比较","abstract":"一、引进动作凭借对象的&quot;用&quot;和&quot;以&quot;此种用法的&quot;用&quot;和&quot;以&quot;在出现语境方面表现出明显的相似性,故下文以语境为纲,描写二词的使用情况。(一)出现于&quot;作(铸)+器名,……用/以+动词……&quot;形式中,如,1.师器父作尊鼎,用享考(孝)于宗室,用祈眉寿、黄?、吉康。(5.2727师器父鼎,西中)","categories":["02_字词句考释"],"year":2008,"publication":"绥化学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPmH9dhIYzsN41lR9pxzEr4XJ81Isrs1j3pGJSnN1wYUWpt8CJbHBQ1Nv2E7jSt4v4aexhIhhI1To_kBmREYCQCwJxT85YUErWWRDqBryBG4NUpP8DkPwAbHra45O0AXEEH_wEcsR3K-4yLnLfwYdtVeftp1fH36cJQdsOuoJD0w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"113-114","volume":""},{"id":5472,"author":"陈隆文","title":"楚铜贝币面文■字新释","abstract":"楚国铜贝币中有匡字形铭文一种,对此字的释读,学术界尚无统一的认识。此种楚贝币的面文应释读为匡,匡作为地名应在安徽肥西一带,此地应是这种货币最早的流通区域。","categories":["02_字词句考释"],"year":2008,"publication":"河南大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15991/j.cnki.411028.2008.05.031","pages":"91-93","volume":""},{"id":5473,"author":"梁玉振","title":"漢字中的“足迹”探微","abstract":"古文字產生之初,先民們造字一般遵循着&quot;觀物取象&quot;、&quot;遠取諸物,近取諸身&quot;的原則。脚作為人類自身站立行走、參加生產勞動和社會活動的主要器官,從物象和取向上看,當為造字的首選。甲骨文、金文用脚趾表示脚。趾、止在甲骨文中相同,&quot;■&quot;和&quot;■&quot;,同時,它還是表示脚的甲骨文構字部件(或符號),其形態有的正置,有的倒置或侧置。金文則演變為&quot;■&quot;或&quot;■&quot;,或倒置、侧置,小篆則演變為&quot;■&quot;。這些符號經隸變至楷,已變得面目全非了。據筆者歸納統計,它們中有的已演變成别的部件,有","categories":["02_字词句考释"],"year":2008,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJXTvb2x79Sg1iKmD6ER33Fv6cCmuy27ZKML940fWmG6N5dU5JXxA6P25ZHOIwLoRE1P6aMpyq6zfbObpCWjqlN0yvcB2jqpto97fH4mjrJtxrDWVkcYFUtU_vVQ_9YWWbwjKk0ZUCXYquex4zmEUNdssOkIa8T2k7cX26XWpKDew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-38","volume":""},{"id":5477,"author":"陈絜","title":"中子化盘铭文别释","abstract":"中子化盘过去通常被归入东周楚国之器,但疑问甚多。本文通过分析,提出另一种解释,认为该盘之年代或为两周之际,铭文中的&quot;保楚&quot;当读为&quot;保胥&quot;,与它器所见的&quot;楚(胥)保&quot;一样,为同义复合词,可训作&quot;辅助&quot;、&quot;辅佐&quot;等义,&quot;用保楚王&quot;是指辅佐周王。西周晚期,中氏的族居地在岐周一带,该族为当时的一个中级贵族家族,且其族姓为姬姓,可能属&quot;周公之胤&quot;的同氏之分支,而盘的主人&quot;中子化&quot;应该就是两周之际该宗族组织的某一代首领。所以,中子化盘乃王朝贵族器物","categories":["02_字词句考释"],"year":2008,"publication":"东南文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIzAq8olNvFCjbXgN5bdV-gXToB7dCLQXNNTY-0IP3myjkv9Ak-AKVwCN9u9si0fE6P3ohaQ1WDYNG7OA9QWd19QzX-1I3X65f6p9YGFPx51dZkjXzatpTRhZtJWbDO5KqBV78C5olLNEkde_TUATiqiPRqXAJ10l3FdkSNd8tYkw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-46","volume":""},{"id":5479,"author":"杨怀源","title":"西周金文复音词的来源与复音化动因","abstract":"西周金文词汇中复音词已有一定规模,其来源有两类:凝固词与原生词。凝固词形成的动因是语言经济原则的制约,原生词的形成则是修辞的结果。","categories":["02_字词句考释"],"year":2008,"publication":"重庆三峡学院学报","link":"https://link.cnki.net/doi/10.13743/j.cnki.issn.1009-8135.2008.05.019","pages":"90-94","volume":""},{"id":5481,"author":"张懋镕","title":"关于青铜器定名的几点思考——从伯湄父簋的定名谈起","abstract":"本文从分析一件定名有争议的青铜器——伯湄父簋入手,认为青铜器的定名是个十分复杂的问题,不能孤立地看待某一件器物,必须了解这一类器物发展、演变的全过程,以及它与其它器物(同出的陶器和其它铜器)的关联与区别,才能把握住它的性质,给它以正确定名。利用这些定名原则与方法,本文总结出包括伯湄父簋在内的豆形簋的基本特征以及它与豆的区别,认为伯湄父器是簋而不是豆,并据此分析了其它几件定名上有争议的青铜器。","categories":["02_字词句考释"],"year":2008,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL86lnnxBKNXsob0v3gS-Ry4nngfkZnnJ0ffZwURjzVBidbhZiEQaxnVSFRlYWrhypMHOGv-KNVVv2LDPrdofKQIF4RJH2FgY4UbeWM0TuEazTZyFMjJxMRcK41OpBWqZyUiqbjjOoy1NggrCmYy5lac4GyElpzLsYJsiQXS6Uqeg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-24","volume":""},{"id":5482,"author":"李凯","title":"应公鼎“珷帝日丁”试解","abstract":"新公布的应公鼎铭文中首见&quot;珷帝日丁&quot;的称谓,&quot;珷帝&quot;应不是指周文王,而是指武王;帝&quot;不应是&quot;禘&quot;,而是&quot;考&quot;之义;&quot;日丁&quot;是武王的日干名。这是周初统治者&quot;修商人典&quot;的体现,鉴于此时殷遗民仍很强大,殷人文化仍较浓厚,周人不得不在政策上与殷人缩小距离。应公鼎在西周晚期还称&quot;珷帝日丁&quot;,是因为应国试图从习俗上与服从于周的殷八师靠近,团结一致抵御楚和淮夷。","categories":["02_字词句考释"],"year":2008,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2008.03.027","pages":"37-40","volume":""},{"id":5484,"author":"周光庆","title":"昜暘揚陽词族考释","abstract":"上古汉语中的&quot;昜、暘、揚、陽&quot;四词依次组成了一个同源词族,隐含着汉语词族形成发展的特定的认知、文化机制,具有一定的典型性。本文对此进行了考证、描写和解释。","categories":["02_字词句考释"],"year":2008,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJigmu4dqPKpUtoPskFfclrS80kJK3fOOcoFZJ1bVmenx1JjX-BE0aUDG509dj39E1mwjC-ZRUD9lCKafl1BdZqe4KeLsXiNjNVuWg67SedL24a_pDdFcyYwR5-qXcSKeL-Poul2pAfyxVAuR-Ni-wCB65j90RN7ABIUZt8YqIB1w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-17","volume":""},{"id":5485,"author":"丁红杰; 余秀忠","title":"释“爰”——兼与唐兰商榷","abstract":"&quot;爰&quot;在甲骨文中作■ ,上■为甲人之手,下■为乙人之手,中■乃一棍状物。其本义当为援引。约在西周时,其拉引、援助之义便另加一义符写作&quot;援&quot;来表示,&quot;爰&quot;义则趋虚化。唐兰将本为&quot;&quot;字之金文■误为&quot;爰&quot;字,不妥。&quot;爰&quot;作实词时主要意为&quot;迁移&quot;,犹&quot;曰&quot;和&quot;到&quot;,作虚词时主要用为介词、代词、连词和助词。","categories":["02_字词句考释"],"year":2008,"publication":"桂林师范高等专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxEBfPFrp4Cb9SwjHUuN7qBJz5TRejYz9oK723V67e5lNd0aCaGGjRJENzUf1vbig8o3PbZ6_GoqZtXR42dQgda8pFH7yn7RtUZ7yzCRwOPHHbCKzKK0lhkDbZ4SBMlmhEuCcavUNUgjIxfO7pqd7BOKFgTYUzzRpzFRfdrJtewQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-57","volume":""},{"id":5486,"author":"寇占民","title":"无叀鼎铭补释","abstract":"现藏江苏镇江市博物馆的无叀鼎(《集成》5.2814譹),依据它的纹饰和铭文一般认为是西周晚期的一件青铜器。譺对于该器铭文的隶定和解读,一些学者已经进行了考释,铭文大体可以通读。尽管如此,对铭文中的个别字的释读,仍然存在分歧。这里,我们在前人研究的基础上,对铭","categories":["02_字词句考释"],"year":2008,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI-65qyxdHFNGObYIiEzUg5_MOW3_Qb8YvXgc0xxqkjj87Z6stXoBNTN6rXT8wq_WntYSDgAWrrS3mb8165KozEUZGQvWtlCfchyIUCMeI3-EmVQa3ekenZOU7nYcR0aHiLlBKS3LsOMXCW4yGoUT5Z9r5c0QJhJaqeLX5PZvA6AQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-32","volume":""},{"id":5487,"author":"张桂光","title":"金文同义词辨析三则","abstract":"选择三组金文单音同义词&quot;岁—年—祀&quot;、&quot;人—民&quot;、&quot;父—考&quot;,结合出土材料与传世典籍,从词义的侧重、用法、概念的内涵和外延、通行时间等方面进行辨析,以明了这些同义词的异同点。","categories":["02_字词句考释"],"year":2008,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgQzSxOE2hmvo7_Gub51pYmQFNBZFEl0FYpMW_EBqgUkvr_wrrZkm4QgSYlJkHrbMTanPe9m6j87CVZzzuMMZbzLPnml8PIxzhR3R756fHPBi2yL1k0VoMg9yKgaVJUidWF1pPKhxdW6Gnu3LZKscQCLUok1A7_4Q2_CVHUZ-9-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-77, 158-159","volume":""},{"id":5489,"author":"詹挽强; 史婷","title":"浅谈铭文类出土文献的历史意义——以眉县杨家村出土青铜器铭文为例","abstract":"青铜铭文在出土文献中占有非常重要的地位,它虽然字数不多,数量较少,但记载的往往是重大的事件,对史料有极大的佐证作用,对于历史研究中&quot;二重证据法&quot;的运用也具有很大的意义。本文以眉县杨家村03年出土青铜器上的铭文为例,浅谈铭文作为出土文献的历史意义。","categories":["02_字词句考释"],"year":2008,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-fU1FqZ_WeWB1mgZNLhSiibtW3gtJ3z2BTvAxU1X8C1oUdOW1V4fGvyygC2C5n5B8fXSWiHXFwd49O3BKh-FneCxLGDEBwpiL6WGaTMwMiiQLjdCmSefhgf4a4TNptHUjio0uCRJoiwvlwO5soLC5OPFOnnyoG379dtjUJSQ6vg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"213","volume":""},{"id":5491,"author":"卞仁海","title":"杨树达文字训诂商榷(六则)","abstract":"杨树达辞世以来的半个世纪,文字训诂之学取得长足进展;以今日之成果检讨杨氏文字训诂,既有千虑之失,也有其时代局限。今就杨氏训释之&quot;畟&quot;等六字提出商榷意见,以就教于方家。","categories":["02_字词句考释"],"year":2008,"publication":"信阳师范学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4RttwIcg828q6BDoNXi-92Taj5g8w6dWEIjvNoE5GvaVB1kHElHGoXtI_9rW3tPpcpwWkA3B9ORoFAhT1n_DCChfp3VMY9j_BaPLXaS5x7o6hei43gBnrWSfv0YXYfAyhmBzLSh5cq-YUxv6kNGx1BPO5Pr1YVPw6rsOv7LeqTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"103-105","volume":""},{"id":5493,"author":"董珊","title":"越王差徐戈考","abstract":"本文考证了珍秦斋藏越王差徐戈铭文,认为戈铭记载了越王初无余迁都姑苏之事,可以补正《竹书纪年》的有关记载。此外,论文系统介绍了差徐戈的形制、纹饰和工艺方面的特点,认为差徐戈代表了越国铜器铸造、装饰工艺发展的一个高度。","categories":["02_字词句考释"],"year":2008,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2008.04.005","pages":"24-39, 157","volume":""},{"id":5494,"author":"洪之渊","title":"“关关雎鸠”考释","abstract":"&quot;关关雎鸠&quot;是以雎鸠鸟的雌雄和鸣,兴起&quot;乐得淑女以配君子&quot;的主题。这种说法,不仅渊源有自,且亦可由《关雎》一诗的音乐性质得以证明。认为此句是以鱼鹰求鱼象征男子向女子求爱的观点,其实未必能够成立。《关雎》诗以本句起兴,取义有二:一以春季物候兴发婚姻主题,二则以雎鸠之&quot;挚而有别&quot;兴发婚姻之性质。其内容和音乐都吻合西周之端肃典正的礼乐精神。","categories":["02_字词句考释"],"year":2008,"publication":"温州大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSBXhO5TVL3I8Dul6xHSPNBUFHzmdV2mI4VcBaIYQUAS-9seu7FtExmT7HifNA6xtin5KV0renyIMO0HyjeNz3pRwBo-5tNe04ICkY-LSMYSyxZnJZv1XgTS6BQ5KljEdCr9jIT0kHk3EUeWBuBOjo4Ij8MP-oN93DjtOB7KSQWw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46372","volume":""},{"id":5497,"author":"罗运环","title":"楚王酓章镈铭文疏证","abstract":"在举世闻名的曾侯乙编钟最显眼的中心位置,摆放的就是楚王酓章镈。楚惠王酓章五十六年,得曾侯乙讣告。逐赶铸祭器,送至西阳祭奠。可以断定,西阳是曾国的国都,是曾侯乙宗庙所在。","categories":["02_字词句考释"],"year":2008,"publication":"武汉大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKqXjAWVViiYv5Cqbo9X0etgfQEkCCC-FLoWvpd4Go0FFoUPuJD0SqUyQRT_nUsfZ3OfFxKJEFOa_yF-bQa7xWsMPt0olzb49C2XxUT6J94sAmZ4HMT9BC356wmQeln1QCkQgTEaMTFeOLfg8iE37ZIrvhu6tV98QEXYXVAgu9LAg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"431-434","volume":""},{"id":5498,"author":"刘志松","title":"释“罪”","abstract":"运用古文字训诂的方法考察,&quot;罪&quot;原作&quot;辠&quot;。&quot;辠&quot;由&quot;自&quot;和&quot;辛&quot;构成。&quot;自&quot;指鼻子,&quot;辛&quot;是刑具。&quot;罪&quot;由&quot;网&quot;和&quot;非&quot;。&quot;网&quot;指捕鸟之&quot;网&quot;,&quot;非&quot;指飞鸟。我们得出这样的结论:&quot;辠&quot;原指以刑具加于人身,先指割鼻之劓刑,后引申泛指各种刑罚。&quot;罪&quot;本指以罗网捕飞鸟,引申为捕罪人或监禁罪人。无论是&q","categories":["02_字词句考释"],"year":2008,"publication":"江苏警官学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKr7_mUsRX6bbqBjQmo1zWummIcS10mZ3pgatHT-wxGLQYauzWs3K0sYKwqr6846kk8QXJexIetwtFwnmeMP-Ln_AyJ93aDphDK7dHAAgUoPpoAu0qw9arAYjxS9NqpJJtDqxvfKFfpATinbrQn7RjBlCl2efVnS6Ho3XX4y3VCog==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-115","volume":""},{"id":5499,"author":"王彦辉; 薛洪波; 刘举","title":"对《二年律令》有关土地、田赋、继承制度中几则释文的思考","abstract":"《户律》318简&quot;有籍县官田宅&quot;一句,应释为&quot;又籍县官田宅&quot;,即又登记国家所有的田宅,并上报所在县廷。317简&quot;卿以上所自田户田,不租,不出顷刍&quot;的句意颇有争议,其实,&quot;所自田户田&quot;即户内经营的户田;&quot;不租&quot;即不出田租。《置后律》384简&quot;女子为户毋后而出嫁者&quot;主要是指女儿&quot;代为户&quot;,意味着原有家庭已经&quot;户绝&quot;。","categories":["02_字词句考释"],"year":2008,"publication":"东北师大学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16164/j.cnki.22-1062/c.2008.04.012","pages":"87-91","volume":""},{"id":5502,"author":"张玉金","title":"出土战国文献中“焉”的研究","abstract":"出土战国文献中的&quot;焉&quot;有&quot;焉&quot;、&quot;安&quot;、&quot;言&quot;等写法,有兼词、语气词和连词等用法。兼词&quot;焉&quot;是介代兼词;语气词&quot;焉&quot;表示肯定语气,同时有将事态往大处说的意思;连词&quot;焉&quot;表示时间先后关系。","categories":["02_字词句考释"],"year":2008,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0-BnkbM7FibTumLygdIiE78c5y9AMchBZJQSUlj-7jv2nQdkIVdNu3HivHCPJWJ8vhPlVXdwrn_mbxSWz75Ud_cHmOnfkYROEybVT4iYZygI1yWwm0M3FY1krjeynlkF4OeDoST8uflWQcwQBhPINE-5S6DLD6znqgodnLKR46w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"406-414","volume":""},{"id":5505,"author":"黄国辉","title":"小子■卣记时新证——兼谈“薳子受钮钟”的记时辞例","abstract":"小子■卣&quot;中的记时问题长期存在争议,而&quot;蘧子受钮钟&quot;的出土为解决这一问题提供了新证。此外,其他近出青铜铭文的公布也有助于进一步探讨&quot;小子■卣&quot;和&quot;薳子受钮钟&quot;里较为独特的记时辞例。","categories":["02_字词句考释"],"year":2008,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_F3bdiv8BrK9aDulOByLvOEnbw2FaMcriEzA3gDRGeAQKxstyrk_Cd0yAiVXM9LSW_jed1BJCEt5TqkBWlNtH3pdnvvb1YkVMac3sLpKrDBnnDAh7V-PvewAoTy7WDQ4a5KRfOCHfp2c088_wDAA8EmHfu8ZArwiL0yMHzBE87g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79-81","volume":""},{"id":5508,"author":"裘锡圭","title":"■簋铭补释","abstract":"■簋盖铭中的&quot;燹夆&quot;二字,可释读为&quot;芬芳&quot;,&quot;芬芳馨香&quot;大概语带双关,兼指器主举行的祭祀及其德行的芳馨之气。铭中&quot;■&quot;字应是&quot;■&quot;(廩)的形声异体,当读为&quot;稟(禀)受&quot;之&quot;禀&quot;;&quot;百生(姓)&quot;的含义是&quot;族人&quot;,而非&quot;百官族姓&quot;。","categories":["02_字词句考释"],"year":2008,"publication":"安徽大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhCRNcBdbI1OLK1gZNuxYvpKNeLtzZGaWVhlKuAran6X6AqKiXCLW9gJ_8eCDY5upQAFsGU_zl8NQ61-sF4PBa6kBIrKDAZJEj_go_TC7y9DUUBAJpl5kNjvEi_G0DfA4wW_VQdMfpdyJc9K9X6OXiU0cPtXRE3uqnTtdlAkz1tg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46029","volume":""},{"id":5509,"author":"施谢捷","title":"秦兵器刻铭零释","abstract":"秦昭襄王三十三年诏事戈胡背铭文旧释&quot;邑&quot;,疑当释为&quot;予&quot;,应即&quot;予道&quot;。秦始皇兵马俑一号坑出土的三年相邦吕不韦戟戈内正面铭文中之诸工匠名(■),过去释为&quot;&quot;或&quot;窵&quot;,应改释为&quot;沱(池)&quot;。秦都咸阳故城遗址长陵车站南沙坑出土的残戈内,刻铭二字可释为&quot;郁郅&quot;。黄浚《尊古斋古兵精拓》著录一戈,戈内两处刻铭(■■),可分别释为&quot;朙&quot;和&quot;白水&quot;。","categories":["02_字词句考释"],"year":2008,"publication":"安徽大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjYvHhXd6zG2aUIPuB3pjNWqUcaM-6oT6rBYpsAcdkM_Nh06Qw0B5lK3uHUMO9VO2WKkUvrhGW0KJPbSAaMtkGi6Sc0KR8_nUbbHU-HHnREPI3a2iF2yo5sf9oNAkKellPzTmZEyhwjYHCRmRZ3SnGgDImJ1DfYBVH4jog9ksdbA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46247","volume":""},{"id":5510,"author":"武振玉","title":"两周金文中的祈求义动词","abstract":"两周金文中表示祈求义的动词计有&quot;祈、乞、、赐、、妥(绥)、降、求、、追&quot;十个。从出现频率看,除&quot;祈、、赐&quot;较多见外,其他各词出现频率都不高。从出现时间看,&quot;&quot;多见于西中和西晚,&quot;祈&quot;多见于西晚和春秋,两词有一定的先后承继关系;&quot;绥&quot;集中于西中,&quot;赐&quot;、&quot;降&quot;则多见于西晚。出现语境上表现出高度的共性,即基本均见于&quot;对扬……做器……动词+嘏词&quot;形式中,祈求的内容以长寿为主。句法形式上,均以带单宾语(嘏辞)为主。从词义来源看,此类中的一些词(","categories":["02_字词句考释"],"year":2008,"publication":"沈阳师范大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19496/j.cnki.ssxb.2008.04.039","pages":"131-133","volume":""},{"id":5512,"author":"李龙海","title":"对《周代金文中女子称谓类型研究》一文的补充","abstract":"曹定云先生在《周代金文中女子称谓类型的研究》一文中,依据青铜器铭文,对周代金文中女子称谓类型做了比较全面的总结。本文依据《殷周金文集成》等对周代女子称谓问题做了一次较全面的探索,发现周代对女的称谓除曹先生所列举者外,还有一些类型。","categories":["02_字词句考释"],"year":2008,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2008.02.003","pages":"141-143","volume":""},{"id":5516,"author":"杨荫冲","title":"“粪”字词义考释及其在古文献中的应用","abstract":"&quot;粪&quot;字词义的发生演变是个动态的过程。在&quot;打扫&quot;本义基础上向名词&quot;垃圾&quot;和动词&quot;丢弃&quot;两个方向引申,前者进一步引申为粪肥义。通过整理和分析该字在古文献中的应用,可以揭示它在不同时期的常用义项和通假字的使用情况。","categories":["02_字词句考释"],"year":2008,"publication":"湖北社会科学","link":"https://link.cnki.net/doi/10.13660/j.cnki.42-1112/c.009075","pages":"108-110","volume":""},{"id":5517,"author":"商艳涛","title":"金文“■”字补议","abstract":"在西周早期疐鼎铭文(5.2731)①中有字作■[1][p783],该字又见于春秋晚期庚壶铭(15.9733)及2003年陕西眉县杨家村出土的四十二年逨鼎铭,二器铭中均作■,此字通常隶定为&quot;■&quot;,王国","categories":["02_字词句考释"],"year":2008,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmR-yzrHknMw1v8jM_ZHpQVH6wcUDfgMJJ44Dnt1EsZa1ga4GqPPUtauMeKKsWa6mvL_6ohSxm3tSt1msabERFEprn_ti5LjnLo9if5vLdJGASi9dx-I0VBm1jz9SUctjr5nhwkBvMGPDq6PfoOqC7VenVFsEqtjLQNbB20o7P7A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-85","volume":""},{"id":5519,"author":"刘雨","title":"“杀人越货”和“夏鼎”——答罗琨先生","abstract":"《考古》2006年第9期发表了罗琨先生《利簋&quot;岁鼎&quot;析疑》一文(下简称&quot;罗文&quot;),针对我与何炳棣先生合写的《夏商周断代工程基本思路质疑》一文对利簋的解释,提出批评。罗文首先从分析&quot;岁&quot;字入手,指出甲骨","categories":["02_字词句考释"],"year":2008,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLNaUykyrsBY1rpB--UBOEqaQ69FJDptKGDdgXHfXHfwRQBZhrB40qeuVkhh9WyJHqIXLV3k1RfG4pQEEeWWvavykAUZW5McJIPKXhgRJjDNF74d_d0o6AL0EWXymuvv6oRNwm3k9LuyCHFWh8ATkwl8Km6-HZo-Y_brHS3kbf3ow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-104","volume":""},{"id":5520,"author":"覃觅","title":"“且”字本义补释","abstract":"文章就&quot;且&quot;字的本义进行总结,概括了学界的四种说法,认为各种观点都有其合理性,但均值得商榷。在前贤论断的基础上,文章通过对&quot;且、土、示、祖、俎、姐&quot;等古文字字形的分析,揭示它们之间彼此的关系,提出&quot;且&quot;是&quot;祖&quot;的初文,即&quot;且&quot;的本义是&quot;先祖,&quot;但并非是男性&quot;先祖,&quot;而是女性&quot;先祖&quot;的结论。","categories":["02_字词句考释"],"year":2008,"publication":"柳州职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJq22oa7pUkV8hEX7ukYhbSG8v5pQ0rBU5ThY2rejSXcujGyUYEDDIWAcUc6oWyMlo0hZebXuLrl9qfIIIRodakagKbpP7lxsKFAe0nc3NXwXHNiih9bVC6ejXIbSIUeCNSJGCgot3w1T3QBbIVNEAL49u4ACgXdn8r4th9hyZYbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-104","volume":""},{"id":5523,"author":"张玉金","title":"释甲骨金文中的“宜”字","abstract":"甲骨金文中的&quot;■&quot;应该释为&quot;宜&quot;,本义是陈肉之器。这种意义的&quot;宜&quot;用作动词,意思是把祭牲陈设到肉案上献给神灵,或把肉置放到肉案上献给尊贵的人。由动词的意义又引申有适宜、合适之义。它还有地名或国名、人名等用法。","categories":["02_字词句考释"],"year":2008,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2008.02.022","pages":"46215","volume":""},{"id":5524,"author":"赵立伟","title":"出土秦文献文字研究综述","abstract":"秦始皇统一中国后推行了书同文字的政策,规定以秦国文字作为全国的通行文字,这一政策的推行决定了此后汉字两千多年的历史,也奠定了秦文字在汉字发展史上的特殊地位,因此秦文字的研究一直是文字学界关注的焦点。近年来的秦文字研究在文字考释,文字编的撰集,文字理论研究等方面取得了很大的成就,但是也存在很大的缺撼与不足。","categories":["02_字词句考释"],"year":2008,"publication":"聊城大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16284/j.cnki.cn37-1401/c.2008.03.013","pages":"55-61","volume":""},{"id":5526,"author":"罗小华","title":"试论“就”字的演变过程","abstract":"笔者通过研究比较认为,在甲骨文、金文中,&quot;■&quot;即&quot;就&quot;,并叠加&quot;又&quot;或&quot;尤&quot;为声符,有声化趋势,后&quot;■&quot;废&quot;就&quot;存,为小篆所本。&quot;就&quot;字形体曾加&quot;定&quot;旁表意,然其形体并未保留下来。&quot;■&quot;字下从&quot;高&quot;之形体&quot;■&quot;亦未保留下来。","categories":["02_字词句考释"],"year":2008,"publication":"新西部（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWbH5KZvQNDu1E1qxvyv-md2eDP2HXLOPO7HGnNdNnXv8kZYioEkaw0oMlzRWF2x_ByAZV9lBlTneNZaVKNjmrHxvT75xL4tQxsQ6H5kCh7YJ02Lg4Y06ugAH-h-iW6cotx7iNz6X87mZ95lGd7o3C9q5WdUwON8fuO5FrPfXtzA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"115","volume":""},{"id":5527,"author":"井中伟","title":"由曲内戈形制辨祖父兄三戈的真伪","abstract":" 曲内戈是青铜戈中形制特殊、时代特征鲜明的一类兵器。考古资料显示,曲内戈最早出现于二里头文化三期,主要流行于商代,进入西周早期就急剧衰落了。曲内戈的分布地域比较广,主要见于河南、河北、陕西、山西、山东、湖北等地的商代墓葬中,其中在河南安阳殷墟出土的数量最多。近年来,随着考古资料的日益丰富,对曲内戈进","categories":["02_字词句考释"],"year":2008,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWbH5KZvQNDu1E1qxvyv-md2eDP2HXLOMSC8ay65yrdOSrEGTeAwSNGbGCvu_rv9h0E5WVAlbCc1R36iJl4Tbv_Nj2GYBXBqfEDaEZfknVQxD3Rwj16oruxI-12kJGa7TRQJjtPNLVf4OGjonK0V7Ob9ilhY-h0fRIRlho8fnrfQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-87","volume":""},{"id":5528,"author":"罗卫东","title":"读《五年琱生尊》铭文札记","abstract":"2006年11月8日,陕西扶风城关镇五郡西村六位农民为修水渠垫基础,在挖土时发现青铜文物27件(组),其中两件&quot;大口尊&quot;上铸有长篇铭文。《文博》2007年第1期在&quot;国宝新发现&quot;栏目公布了其中一件青铜尊的铭文拓片,《考古与文物》2007年第4期公布了《五年琱生尊》甲、乙两件铭文拓","categories":["02_字词句考释"],"year":2008,"publication":"北京师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJt2ntrlcrixfect1yJMgdDcmomhnwqNWvvbJBWQtRQB428bWxlIHiook4i2AT8o0Fp0CZTflgK_pOPz3xrLPwE3lxGflGvtlMNeLlyxzctOdO5kQUbc63J_VF6hUY-TNkPGS0nPDFynz5IxChRAhD9B3w32uSVKgeUaD5IDRgl9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-132","volume":""},{"id":5529,"author":"舒怀","title":"汉字考释必须兼顾字的本体认知和字用规律——从“臧”字说起","abstract":"&quot;臧&quot;有奴隶、褒奖、隐匿三个字义系统,三个字义系统各有本字,分别为臧、■、匨,因同音而互相假借。其中,臧字最有生命力:既是臧获本字,又借作臧否字,还借作匨匿字。借字借义行,而■否、匨匿本字废。通过对&quot;臧&quot;系字的观察,我们可以认识到:考释一个汉字,既要进行本体认知,又要注意字用规律,否则就不能全面认识这个字。","categories":["02_字词句考释"],"year":2008,"publication":"湖北大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13793/j.cnki.42-1020/c.2008.03.019","pages":"111-114","volume":""},{"id":5532,"author":"寇占民","title":"西周铜器铭文错铸札记","abstract":"青铜器虽为传世重器,但由于铸造时要经过制模、翻范和浇铸等工序,再加上铸造文字本身就是一个极其精细和复杂的过程,所以铭文错铸现象是在所难免的。本文从字形相近致误、笔画缺损致误和结构错乱致误三个方面,对西周铜器铭文错铸现象进行梳理,进而总结其规律,为金文研究者提供参考。","categories":["02_字词句考释"],"year":2008,"publication":"齐齐哈尔大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13971/j.cnki.cn23-1435/c.2008.03.030","pages":"102-105","volume":""},{"id":5533,"author":"彭适凡","title":"秦始皇十二年铜戈铭文考","abstract":"近年,笔者见到一件带纪年铭文的铜戈,现对其作一初步考释,以求教于方家。此戈长胡四穿,援细长上翘,中脊明显,凹刃锋利,内细长,上下有刃,内末斜刃成刀状,刃锋利,内中部有一长方穿。援与内相交处成一折角。通长25.8、援长16、胡长11.5、内长9.8厘米(图一)。戈内部背面刻有铭文两行,计15字,字的","categories":["02_字词句考释"],"year":2008,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2008.05.005","pages":"67-69","volume":""},{"id":5534,"author":"王伟","title":"从秦子簋盖词语说到秦子诸器——兼与董珊先生商榷","abstract":"在李学勤先生、董珊先生、王辉师等人对秦子姬簋盖铭文研究的基础上,从铭文本身出发,着重讨论&quot;畤&quot;、&quot;秦子&quot;、&quot;秦子姬&quot;、&quot;受命&quot;、&quot;士女&quot;、&quot;宫外&quot;等词语的含义,并由此申论有关&quot;秦子&quot;诸器的年代,认为秦子应指文公太子静公,&quot;秦子&quot;的称谓是其生前秦人对他的尊称;并对董珊先生《秦子姬簋盖初探》一文的相关说法提出质疑。","categories":["02_字词句考释"],"year":2008,"publication":"宁夏大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4n2uEoXLqLrH0tj5BLee8oYqQl7_AlbUGP5AgPJzimgz3oCPdkt_0-OA3AlFFyHjDx4rGcvXsbOYdpu-6sJbbnDKCRLDUH6St8Qr46MVvN74Vmt651QE0EmjuGpdkNXVWCyi6ffesm7CVxuFen0MeVO4G0ImlNqQRKnuC_pgCmQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-31","volume":""},{"id":5535,"author":"王进锋","title":"《保卣》铭剩义新探","abstract":"《保卣》铭是有关西周历史的重要材料。过去很多专家对其进行了考释,但争论仍然很大。本文在详细考证了铭中的几个字之后,认为其讲的是周成王让官员保到诸侯国收取贡品的事。《保卣》将成为研究西周贡纳制度的重要史料。《保卣》的作器者保不是召公奭,也不是明保,而是一个名叫保的负责收取贡品的普通官员。《保卣》带有商器的特点是文化的一种传承。","categories":["02_字词句考释"],"year":2008,"publication":"唐都学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKyMk1Vor_7mGrazog6fEUvbTs0ADTtD986LHvB1egswWFTIYEWPt9hq5mfI18LzEsK_sJgwdeU_sjN66mDx8bX1xVpbrpo1YUXCAV2EQdJdmMo6Nc40Sdnro5q6pc9FZ9aefluAb8_1nwmQWFRf_COe3Bi46jnCsElPNys3K3n0w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-60","volume":""},{"id":5536,"author":"白冰","title":"《金文编》附录后成字的图形文字再释","abstract":"依据商代甲骨文、西周金文对早期金文&quot;图形文字&quot;进行考察、辨析,可以认定某些图形为氏族徽号,某些图形表示一种生活场景,某些图形后来发展为文字。其中,■(何)、■(伐)、■(重)、■)(卿)、■(竝併並并)、■(虎)、■(豕)、■(牛)、■羊、■(崬)等便属于第三类。","categories":["02_字词句考释"],"year":2008,"publication":"五邑大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKyMk1Vor_7mGrazog6fEUvbTs0ADTtD988lX0NXldCyPBMUdjx7K3Ipc9992OEwOpVnnTWvSzhrGQMmNlUQVfzU0RJv50xuKezMEXCQt-K8FZXnU55MbuWHmgJwB65RYPMTEgLxo04PvkwJdlVUcxvxHvST32U6xDH-gpvYnWUEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-73","volume":""},{"id":5538,"author":"蒋文孝; 刘占成","title":"秦宜阳鼎铭文释录与考辨","abstract":"2006年陕西秦俑博物馆新入藏一件宜阳青铜鼎。本文对该鼎铭文进行了考释,并对铸造时代和国家及后来的使用情况进行了考证。认为宜阳鼎是战国晚期偏早阶段秦国所造。铭文分秦汉两次刻成,秦人的首刻仅有容量和地名,汉人的二次刻铭,则对该器进行了校正,说明了它的用途、容量、重量、编号以及此器转手流通所经历的地点。","categories":["02_字词句考释"],"year":2008,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHJtpsmS3Pzp3hNdhLsxI8Gj2AjsKUhia9G1KPmuYMJ1ps-nAFd9qrhrbZTJ5STp1Yu-RBZHJfWjuPcT1s4OX00H2uFCBnvrtEMlTvmXOt_jQrxTe5VQAr4gmFs3OVi1gZKtxnGafdFW-lxSvM23qsXVNtw2XCMBWBEoebld-U_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-83, 97","volume":""},{"id":5543,"author":"冯华","title":"从古文字材料看《释亲》及《尔雅》的时代","abstract":"《尔雅》是一部非常重要的儒家经典,它的成书时代一直是学术界比较感兴趣的问题,传统的方法是利用传世的先秦文献与《尔雅》相对照,从而判断《尔雅》的成书时代。目前,关于《尔","categories":["02_字词句考释"],"year":2008,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLQ1Mcc3Z-1irauJ0GTh6FtkMOTFKmdQEYosEx1j5d0yzSaxKONJc5xsWlj9tEwvuL0Qz4KwE1nYyY4kZol_dyR4_qVWrzxWaTKOhopMw3T86LIxWDpWzwn0iqXZrDWoDJ5XjMR5nZhPX_qFYSviLjjwvBPsPAzwwg3jVnR99uPMg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-46","volume":""},{"id":5548,"author":"张道升","title":"“春”字的释疑及启示","abstract":"于省吾先生释&quot;春&quot;是正确的。其阙疑和人们的质疑,还可用殷历法等知识给予解释。其考释过程给了我们许多启示。","categories":["02_字词句考释"],"year":2008,"publication":"成都大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVtX0v3vFJjZbR2lbqhy6hr7S39L1X9-856hg5StD4YZ2_vE7VWB7JNg7qNdW_QlmW5qzEpQOxSSiQgK1-Xs6AJkJD6kJntyfBqAuOLEMwgoVce3ytAhL8BvRuIB00IFy18-YEoX_OpKZv4QOhUJUEIinoNmYyRSl-wlEG6hXzqg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"116-119","volume":""},{"id":5549,"author":"张怀通","title":"“王若曰”新释","abstract":"","categories":["02_字词句考释"],"year":2008,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItazmbCCuGOoUVtz7Hv_kFgScDaAoogpEhOCROKEJBZoFrkhuA__y5ek3CvWw0dx3kmVhMv37d5Rr30Sjet-phvI4u5JB04bI_O0GS9nIihd9CUxEp1fvGqj56NAHJDxyP2S080APQXNFWbDvgSmh39Eb6ySWo9fe2faXHK732lw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"182-188","volume":""},{"id":5550,"author":"武振玉","title":"两周金文中的“偕同”类介词","abstract":"&quot;偕同&quot;类介词是指引进动作偕同对象的介词,这类介词普遍与并列连词有着密切的渊源关系,故针对传世文献的研究多很注重之。但此类词在出土文献中的应用情况如何,尚无系统的调查和阐述。通过调查,可知两周金文中此类介词有&quot;暨、及、以、与&quot;四词。虽然其总体出现频率还比较有限,用法上也表现为共性大于异性。但亦有足为传世文献提供佐证者,如&quot;暨&quot;字的相应用法在传世文献中就很少见到。同时,两周金文显示出的这些介词的具体用法亦可为探索其词义虚化过程提供重要参考。","categories":["02_字词句考释"],"year":2008,"publication":"吉林师范大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoaxd28Sm9Xc-1mVuvKsN3bdBIIHbJqVyl414pPgbJAfDV7FqkfrrfrVpFrc4TN4sJ0rUq6lSitzobY9tIGCTjFO5NlDjyZZ96Sh84BNDio1Dw4UE3STpnmH6_fgAGLuG-H0ptVKELPZ7d2ufKyp5d87SWk6hYHALUGrrGMnLxLw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-23, 68","volume":""},{"id":5552,"author":"陈隆文","title":"向寿戈再考","abstract":" 董珊先生曾发表《向寿戈考》一文,拜读之后受益良多。董先生认为戈铭第一字应为&quot;向&quot;,第二字应释为&quot;寿&quot;,戈铭中的&quot;向寿之岁&quot;就是以向寿出使于楚作为纪年。向寿其人见于《史记》和《战国策》的记载,他始任","categories":["02_字词句考释"],"year":2008,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIps28l1o7RPbqcUU4_i14utWEMMQmoxnpxpPbRfyYHBXRJ1vHDJHNzacDt9_jy41uJ0o-zCTuOFuRb7hs2UbpXD4PE6ZksA3qmipnF8XTGrA1QMfy6M_c1hwpqI8vhNQBX62SBYhiiOuvDACQjCCbwwC1cOzNWPcSWyDAToyteuA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81-85","volume":""},{"id":5554,"author":"王进锋","title":"从“降”字字义演变看先秦投降礼仪的形成","abstract":"先秦时期的战争中,经常会出现投降服输的行为,在其过程中也往往伴随一些礼仪活动。有专家将这样的礼仪活动称为投降礼。在先秦时期,投降礼仪的形成也经历了一定的过程。在对&quot;降&quot;字字义进行考证的过程中发现,&quot;降&quot;字在甲骨文、金文中还没有&quot;投降&quot;、&quot;降服&quot;之类的含义,其只有在进入春秋时代才真正具备了&quot;投降&quot;的含义。也就是在春秋时代才开始有了系统的投降礼仪。","categories":["02_字词句考释"],"year":2008,"publication":"云南社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdXwWsKI1a7fOG51C7iiz7CnjCj_9wJHP6hkr-itUyKaVAtokHFdHLVrXBGgn8opw-g8Zx2r6SH_PF-TYZCohhaTo-a3qkkEguok5ayps2rM4tzXmQ-mlc-65txNaNqMcmaGyDtOQhdnjuw_JUwtejoifaEYLn4P8Ka3UD56LvgQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"131-134","volume":""},{"id":5555,"author":"董珊","title":"越者(氵刀)钟铭新论","abstract":"自晚清以来,许多著名学者致力于越器者(氵刀)编钟铭文的研究,本文综合各家所说,对钟铭文义进行了新的理解,并对器主身份及年代问题进行了探讨。","categories":["02_字词句考释"],"year":2008,"publication":"东南文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKfPKqI05Wzp4I0Jf3SzMwcWHCmqqEYaaaAh2odO-IzV_NJRu_Eklcq7bhDtX3XNUDWtrAyYABovL4zHamLl3uSolpsKHSR5yH-64W-x7xWvYyEwH4hhUeKjfAFuieI_cQj6X6Uodix6fZfR7mM3ISyzY_ANPtXV1MlqF_ldUHiRg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-55","volume":""},{"id":5557,"author":"孙启康","title":"丹江口水库库区出土三起铜器铭文考释—读《尘封的瑰宝》觅王、侯之遗踪","abstract":"本文通过对丹江口水库库区出土的《彊王之孙叔姜簋》、《子中濒儿盘》和《蔡侯剑》等春秋时期铜器铭文的释读与考证,认为&quot;彊王&quot;乃&quot;羌戎之王&quot;;《■子中濒儿》应是&quot;伊雒之戎&quot;中的&quot;戎&quot;的首领,并曾是&quot;钖穴&quot;矿区的拥有者;《蔡侯干剑》上的蔡侯应是被楚文王俘虏并带回楚国囚禁达九年后,死于楚的蔡哀侯献舞。并根据出土文物和当地的采矿遗迹,结合文献考证,确定了古钖穴的具体地点;辨明了&quot;钖穴&quot;并非&quot;锡穴&quot;;&quot;彊王&quot;和&quot;■子&quot;显然都与当时","categories":["02_字词句考释"],"year":2008,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJlYNlgKD1BehFAdy_S1P2DuxUiGY6I4Ztbh245Cg8Y0O3f3Hn_FEZABmVLqi7eK_9r06N0E0xrvS7affiHcnhs4OtXyj_rce0LsgmOJfa6N7H0BYZPy-hTeQNllaubnEeqROCfUQP5Oq6xz0i4mE_2oqb7fBXOpGuOqXEBj6Ixxw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-125","volume":""},{"id":5558,"author":"程鹏万","title":"释朱家集铸客大鼎铭文中的“鸣腋”","abstract":"本文是对安徽寿县朱家集出土的大鼎上的铭文第八字与第九字的重新考释,认为此二字当释读为&quot;鸣腋&quot;。鸣腋应是当时负责饮食的机构的名称。","categories":["02_字词句考释"],"year":2008,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLy6bZUWZVIlRn81MqjsrKmN7FeBrXuPYaJFnYavt7l_kPWStBfzqx7WsekQcum-uKAq22Tp7ffTIFaPXIMbBjN-mmz7YQx_y6BpWIhIfCPDsv4kSjRWiKUsSWWpEMSb6oHhTxY2zRVkN86NfqWQi3a3vRKtbqyXtIpy7HyrUOQuQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"126-128","volume":""},{"id":5563,"author":"武振玉","title":"试论金文中“咸”的特殊用法","abstract":"传世文献中的&quot;咸&quot;,一般多据《说文》释为范围副词,其动词和时间副词用法很少见,也少见提及。但在金文中&quot;咸&quot;的动词和时间用法表现得很突出,本文即对&quot;咸&quot;的这两种特殊用法加以申论,并借此理清&quot;咸&quot;的词义发展规律,以补传世文献相关研究之不足。","categories":["02_字词句考释"],"year":2008,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhfgt3S0iYJSsIIKSqJvYBG5BMDH3-vQpgieSP1Tsj9CZ1VvqIH7bx2gXDILRXXwqpDzVQfKABBw6gU5roC_g5eDhq_ty7lLlz1Au29aQA9-ADAUGgXGQZisl6qQAPzThvC6CMpvGcqGMOBzJEuqpvclZPVThzs_ImfNkTmIQ4Fg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-35","volume":""},{"id":5567,"author":"陈絜","title":"浅谈荣仲方鼎的定名及其相关问题","abstract":"本文通过对方鼎铭文的重新解读,提出如下意见:1.保利艺术博物馆新近入藏的被学界称为荣仲方鼎的西周铜器,似应该定名为&quot;子作父丁方鼎&quot;或简称作&quot;子方鼎&quot;为妥,该鼎的器主是&quot;子&quot;而不是荣仲。2.铭文中的&quot;加&quot;应该读作&quot;贺&quot;;&quot;子&quot;确实可以训作&quot;宗子&quot;之义,但与荣氏及荣仲家族无关,&quot;子&quot;乃是任姓&quot;史&quot;族之长,而非荣氏之长;&quot;子赐白金钧&quot;,是讲&quot;子&quot;被荣仲赏赐。3.器主&quot;子&q","categories":["02_字词句考释"],"year":2008,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIeYPRYQqRGvGULr26ej2Y4MCxuRF933WoqZTR37hyeo-EWvdWe8kWBS304osQzWyDwEEjEf4mrRgu6pKB7Lu_HHJ_020v9CXcODXCap0V582JEDXb92QmOgY_NukUEAaR_k2EUP2FzwX1agE7n5AR-8aSEaqLTl3eweQDu4Q1Cmw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-68","volume":""},{"id":5568,"author":"赵平安","title":"唐子仲濒儿盘(匚也)“■”字考索","abstract":"湖北郧县五峰乡肖家河村春秋墓所出唐国铜器上的&quot;■&quot;,又见于齐国和楚国文物,从东周记月文化的大背景上看,是一个单字,表示月名。考虑到楚国已有具有特色的记月系统,推测唐、楚的这个月名很可能都是受齐国影响的产物。&quot;■&quot;应分析为从&quot;戌&quot;从&quot;日&quot;,与十二辰&quot;戌&quot;同源,又刻意加&quot;日&quot;相区别,可以看作&quot;戌&quot;的增累字。","categories":["02_字词句考释"],"year":2008,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKaMOCow63uj0qgwn_O4wawKJol_DyZovgOJPW4vZp2fcukbVDvT8ogiZoodNiC1jfpmDxdJiy_mNpiCuKfNeYR2BNZki21uy4fQ0PzAhoWytNT8cCxnKvGg-zdpEdeh2FBYHtI4NvpqFxg15GKZoHpkrKzjEjMMcnF6ZhRX9HVmg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-77","volume":""},{"id":5569,"author":"王进锋","title":"新出《五年琱生尊》与琱生诸器新释","abstract":"2006年底陕西扶风出土的《五年琱生尊》为理解生诸器提供了钥匙。生诸器中的生就是伯氏,召伯虎就是君氏;生是召伯虎的同族长兄。本文在对生三器的铭文进行了分析之后认为,生诸器的铭文反映的不是土地诉讼,也不是财产的分配,而是生与召伯虎分配依附于召氏宗族人口的事件。","categories":["02_字词句考释"],"year":2008,"publication":"历史教学（高校版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIST9v2jzUpa7whH1SC9RXqlZjAwCpVgk7YLrrd2h_3JKsIF61Y6mxgohKxLz3G0Ja364SEjd58YyDpK6C1ANQQDLx2kkv13zSNC6DZVgghe-oddoOtLZ8tMbrLGoi0oLR8drNPpf6KIwHxK8MPWjFR9hsf-2pg-jZX3bpyvv3Hsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-92","volume":""},{"id":5572,"author":"吴红松","title":"西周金文车饰二考","abstract":"According to the analysis of the inscriptions &quot;画■&quot;and&quot;金豙&quot;on two largess of Western Zhou dynasty, the former should be a crossrail,and the latter should be a bronze tach for linking horse bridle together on ancient carriages.","categories":["02_字词句考释"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjKzeCF5yPWPYpScXPFBbaOyfau7JH1lcIlzws5V5layXtJo9yNorcYWNsFjEtZXx5wcritFxXeKG9nnj9Rv6hZ5mLSBjFsQpVIih743I0TBiCYRpynkHnQ7e1_yDablstxdytENKJAK_O-vbsLL5ig8gMjIPbj_DTEpjwlzipdA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-86, 90","volume":""},{"id":5573,"author":"袁俊杰","title":"柞伯鼎铭补论","abstract":"根据古代贵族取名字的原则、礼俗与其他青铜器铭文及相关文献综合考虑,柞伯鼎铭中的遣氏应为虢仲的部下。幽叔就是胙国的始封君,亦即周公第七子胙伯,幽为其谥,叔是其字,当以行字称。","categories":["02_字词句考释"],"year":2008,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjKzeCF5yPWPYpScXPFBbaOyfau7JH1lcIlzws5V5layXtJo9yNorc7YMFilcLFb1EznYqAAM7OG37wTNkELgOk4HwFNrsQ2Ha1T6p6bfI7lvLRzAj6OeemkWSJvgG708laornkb0DnNJQ5eKDMDMSa4ZqyZENP8j_ePEFuAIfKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-90","volume":""},{"id":5574,"author":"张怀通","title":"小盂鼎与《世俘》新证","abstract":"&quot;武王俘玉&quot;一段文字,位于《世俘》的最后面,既不是文本错乱所致,也不是&quot;作者&quot;认为俘玉没有俘人重要而有意所为,而是&quot;作者&quot;依据西周时代献俘礼仪程序做出的必然安排,因此《世俘》是一篇主题明确、结构严谨的文献,它的文本是可靠的,所载史实是可信的。","categories":["02_字词句考释"],"year":2008,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoJ-ZkG2mS70PaeFXo5pAyGgyRUBAFYS8Uc2YArCvRO2FUT3RHZ8-OFs6FcztltJRs92xfisM3hgXoHMRwpSyD_gG_421WreBvZDt8af90tX8vegeKA54urFZLEwhJWK2Ku4IyTIheIMCb_WNzdgmawhf5SSQzBi0gBqSm0KGu6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-48","volume":""},{"id":5575,"author":"吴红松","title":"托鼎铭新释","abstract":"通过对上海博物馆馆藏托鼎铭中的&quot;寝&quot;和&quot;大具&quot;的重新分析,认为前者指人名而非旧释的&quot;寝宫&quot;,并对后者为&quot;丰厚的馔食&quot;的观点加以补充说明。","categories":["02_字词句考释"],"year":2008,"publication":"黄山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIU21Tr26hAW-A0xo3IY_X9Yk3xHzUSRmOWoqowJo1uIbHTp7qdIod6DSdhL7Lqio-1MsBK7uFsOCavU8CCE9I1qzNxdJAKhi0a-jZmbtdJ7yK9tA1AOX2khlFBGUGfZ0AarctOmDmxlSZ1kbYhs86TeDcMq9X3HFqj9oMZd1MtoA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79-80","volume":""},{"id":5576,"author":"张道升","title":"《行气玉铭》研究述评及新解","abstract":"《行气玉铭》研究者众多。文章从文字考释、年代国别、功用探讨等三方面对诸家研究进行述评,并进一步提出自己的看法:铭文中&quot;■&quot;读颠,&quot;■&quot;读&quot;撤&quot;,&quot;■&quot;直接释为&quot;本&quot;;其属战国时期的三晋物;其是一件杖首的装饰器物。","categories":["02_字词句考释"],"year":2008,"publication":"鸡西大学学报","link":"https://link.cnki.net/doi/10.16792/j.cnki.1672-6758.2008.01.056","pages":"146-148","volume":""},{"id":5579,"author":"吴红松","title":"金文兵器饰件考释二则","abstract":"本文在吸取和借鉴前人说法的基础上,结合考古实物资料,从形音义方面对西周金文中传统释读为&quot;彤欮&quot;、&quot;厚必&quot;的二物进行了讨论。将前者改释为&quot;彤杆&quot;,即&quot;涂红漆的箭杆&quot;;对释后者为&quot;緱必&quot;的观点加以补证说明。","categories":["02_字词句考释"],"year":2008,"publication":"宿州学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGASTvnQovbi4LNK4ixE06AzBIjlQqZThZUjIctLGOJMIR1aCyo41ZXb2HOHdN_SO27pk_JhSS4kVFH-4jm5c_9_Su7pRumsg8Q-9ChwwNmkD1x5V9_7U8xSYiZbHI1WkhpJ2o5UU7a-xxqKm_FxmUphotgLOnROpWb98m0g2b2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-27","volume":""},{"id":5580,"author":"余世诚","title":"国宝“遂公盨”的发现及其史学价值","abstract":"2002年5月保利艺术博物馆收藏的&quot;遂公盨&quot;具有很大的史学价值,&quot;遂公盨&quot;的铭文涉及&quot;大禹治水&quot;和&quot;为政以德&quot;这样重大的史学问题,证明了《尚书》记载的&quot;大禹治水&quot;是比较可靠的。我们应当发扬大禹精神,努力构建和谐社会。","categories":["02_字词句考释"],"year":2008,"publication":"中国石油大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKUypqeWJsdq2pB8BarJopKtngu0-FbH3TU8Sfy8VV-FXaOPthdnZgSXz8Y4m3GswqIU9FWT8DMcCP1_Z9VYwqkd4T6At5g-jpcURDw_SB74btzBW05vcoiKtrWzOI3ZOAAhg3MLHAFq1B2XVnAurEmN_78O8w8ecBgsFaJ0aeA3g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-61","volume":""},{"id":5581,"author":"马育良","title":"六安双墩汉墓铜壶“共府”铭文再解","abstract":"就目前所能了解到的墓葬情况分析,初步确定六安双墩汉墓为西汉六安国王陵大体上是可以接受的。但对墓主人身份的确定,不宜取铜壶&quot;共府&quot;铭文为核心证据,因为环绕双墩墓&quot;共府&quot;铭文的证据链基本上并不指向刘庆。事实上,&quot;六安飤丞&quot;封泥等物件在确定墓主身份时更应受到重视。","categories":["02_字词句考释"],"year":2008,"publication":"皖西学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJqE4k-SXZVb2N1wCEuMycn29q10FLoPIZPSoQVbQMPaj9HIezdXfUgqncRgNqxIrgE1lPr2-1-9bkclVuUuxzUrwGrpDG2rUjP0uHgnW9pNrGYoXjHck1MlSZxzbulV_nXXQhyPrAI-VA-h-a2MaLQtUudy0u1q6eFKpjhLwp_A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-81, 67","volume":""},{"id":5582,"author":"杨现昌","title":"■攸比鼎铭文浅释","abstract":"■攸比鼎是西周后期一件重要彝器,其铭文内容反映了西周后期有关法律、土地的一些情况,为研究西周后期法制、土地关系提供参考资料。","categories":["02_字词句考释"],"year":2008,"publication":"山东教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0lACWgk63Xi4PDAHUJkW7wXwzQNekd67YRPIIgPW3geJ_yK67S9rXxRxh2dnIQBGXJs0cnVzgEYcufmPXZTYdW2T3V70znDikUr3OIm1ZOphM9Js_y2PzhncO9QxpBfAxbxy7A2Tmys1qU_mJJD-dfCSyOlruMc-_6k3UxvW20A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-39","volume":""},{"id":5584,"author":"晁福林","title":"金文“蔑曆”与西周勉励制度","abstract":"习见于彝铭的&quot;蔑曆&quot;一语用若勖勉之意。这种意蕴,上古多有,在彝铭中习称&quot;蔑曆&quot;,而商周文献多以&quot;勖&quot;、&quot;励&quot;、&quot;懋&quot;等为称,战国以降则称&quot;勖勉&quot;、&quot;劝勉&quot;、&quot;勉力&quot;。彝铭&quot;蔑曆&quot;今所见者约五十例左右,多数是周天子权威的表现。从商末到西周后期,其意义虽然随时代发展而有所变化,但是其本质则没有改变。&quot;蔑曆&quot;实际上是上级对下级的勉励和下级的自勉,它以口头勉励的形式来保持和加强周王与臣下(或上下级贵族间)","categories":["02_字词句考释"],"year":2008,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJNOI_LAKtJp-qCyxKyVKpHnY4vwv9buDGtPZaGHzUcu2RoFcAvlcQwA9CI047Xvb0ttybWrI_ayX6uvDdmHt_IhPB7PbTQzGhMjwaS8YveOAn4TyASDD9qLuhroEJAIhyxPhSSkNrSw12eWo2Obc_-BESmWhgjGS0JOAKmRjWzmw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-42, 190","volume":""},{"id":5587,"author":"王辉","title":"琱生三器考释","abstract":" 目次一释文二器名三断代四字词、语句五译文六铭文反映的西周宗法与土地制度传世青铜器有五年琱生簋,或称五年召伯虎簋,原著录于《捃古》三之二·25,亦见《集成》4292,现藏美国耶鲁大学博物馆。又有六年琱生簋,或称六年召伯虎簋,原著录于《积古》6·17,亦见《集成》4293,现藏国家博物馆。二器内底各有铭文104字。二铭应可连读,其内容或以为&quot;记载了琱生与其同族召伯虎之间的财产权纠纷&quot;;或以为记述&quot;琱生这一支贵族扩大","categories":["02_字词句考释"],"year":2008,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZBJphbb9RxyvUsFUmJiSwQ5u1zyLxp5eyD7ozZVyJ0RqzAZ1XDbjGYZ2IgKrnkoM-c-QFb2mPrUzEkavSNU2Oe7YKCNRmljMxtGRzjBVHVdz0Syz70fnXI_VOqT0rS48IOQBU6nwxzzgp88Us6VQ8_gP0o7V4h3U6j8uGxtx-Rw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-64","volume":""},{"id":5592,"author":"戴文涛","title":"利簋铭文汇释","abstract":"本文汇集历年来关于利簋铭文考释的各家之言,其中主要内容按照各家对铭文&quot;岁鼎,克闻,夙有商&quot;的不同句读及释读,以&quot;岁祭&quot;说和&quot;岁星&quot;说两条线索展开讨论,并阐述自己所认同的观点。","categories":["02_字词句考释"],"year":2008,"publication":"安徽农业大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19747/j.cnki.1009-2463.2008.01.015","pages":"57-60","volume":""},{"id":5593,"author":"徐山","title":"释“录”","abstract":"&quot;录&quot;字的甲骨文形体义为宰鹿剥皮且带血状。&quot;录&quot;一词的本义为鹿皮。《说文》对&quot;录&quot;字的训释不确。","categories":["02_字词句考释"],"year":2008,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkXzPtDQ4RjELaqUsKoPekv1l6dmBvPBAVJjAueFlg_rT6pGLFQ00TLNDm7LrZe_sP-jShgg2SIFJE1Bozr0TyaAurem8v-zqM9VSnXm_ctxPJeeMoM4hdfnmi3yfD_tvj2R6OwyVSjEMVYnlo5UishHhtIP8AFiypcRiG7VwGyQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-82","volume":""},{"id":5595,"author":"陈英杰","title":"燹公盨铭文再考","abstract":"&quot;△&quot;公盨铭例特异,前所未见,文辞古奥,艰涩难读。文章在诸家考释的基础上,对△公盨的句读、语词、句子之缺省成分以及铭文性质提出了新的看法。文章指出,&quot;敷土、隓山、濬川&quot;是大禹治水的三种方法,对此句的理解,必须充分注意大禹的神性。&quot;■(擣)方&quot;指禹平定下土之后,对四方不服势力的征讨。&quot;降民、监德&quot;是两个并列的动宾结构。&quot;康亡不楙&quot;读为&quot;康娱丕懋&quot;,义即安乐勤勉。&quot;孝友■明&quot;指四种德行,即孝于父母,友于兄弟,忧恤贫病,明察是非;&quot;■&quot;释■,","categories":["02_字词句考释"],"year":2008,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIHCClOqj2CeUvtpiP4yIp1YchdOTL5L4NjFlTD5w3zCp4Hcu_5DL5R6ual3AFG_SDIcCZZ_3pWjrNGyVenCHoGKI0VrnS2azQaB6pQ75mYEI5xhuay4hNp6PY0EZtRS64rxUk_RQrC5zAtKe_8J-pwWWEFr93moCHP8NdwIOywg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-77","volume":""},{"id":6454,"author":"高文英; 陈双新","title":"古汉字形体讹变现象的考察与分析","abstract":"古汉字形体讹变现象是古文字形体演变过程中一种特殊而又并非偶然的现象。文章以对各个阶段的文字汇编性质的字书为考察对象,通过从历时与共时两个层面同时进行考察的方法来找出存在于古汉字演变中的讹变字,在对所考察的所有讹变字形进行全面分析的基础上,划分讹变的基本类型,阐述讹变的特点,分析造成讹变的原因,阐明讹变与汉字发展一般规律的关系,探讨讹变现象在汉字形体演变中的影响以及研究讹变现象的现实意义,从而对讹变现象得出较为全面的认识,使得学术界更加关注古汉字形体讹变现象,对古汉字形体演变规律及全貌有更加深入的认识。全文共分五章。第一章,介绍前人研究讹变现象的情况,对讹变的概念提出自己的界定标准,对于所选字书","categories":["02_字词句考释"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJrx9ziWAHRIlxscJhS45CMM6erMzEILHOOkrfgJN1CRqQYXFMDdflFZ26oPVD0A5NDTq6DIq6gjC4vxDer2_76kPLhF0gNBshKMFm-HyqRxc75XiLQeMnjErTSP794PXJK03kkiH1fuY9P1SGp_NxYV3N6xywCWvB_INwNnUsZFqzFGuDvFrCu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6457,"author":"周波; 裘锡圭","title":"战国时代各系文字间的用字差异现象研究","abstract":"戰國時代是中國古代社會發生重大變革的時期,經濟、社會、政治、軍事等各方面都有了長足的發展,文化上也空前繁榮。這一時期也是中國語言文字大分化、大發展的一個重要時期。諸侯各自爲政,必然會對文字的發展帶來不同的影響,文字因地而異的局面由此形成。同時由於各國間在地域、政治、經濟、文化等方面的聯繫,某些地區的文字比較一致,可以歸爲一系,不同系的文字彼此間也往往產生一定影響。這一時期的用字呈現出紛繁複雜的局面:同一字可以用表不同的詞,同一詞也可以用不同的字來表示。這些現象既存在於同一區系文字之中,也存在於不同區系的文字之間。而各系文字間的用字差異現象則是戰國“文字異形”現象中非常值得注意的一個方面。最近幾","categories":["02_字词句考释"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImzHH29z-xKcn_20PByAAK_EePDTm2j5MaxPBDlnsRECPRcuq-yf3w64RuBLCYy9glFBGjb6HQCJr5wHAq6TE3j6BpwH18z_eEI4dnq-1GBMAWxiiDuLBzu1YFpffnFfDko1BgRejRhA53eGdfNyuTvuakDXssBfe5xxUAyyv_edURHZIaed_D&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6461,"author":"柏亚东; 詹鄞鑫","title":"唐代墓誌词语通释","abstract":"唐代墓誌出土數量龐大,誌文断代明確,敍述完整、獨立且爲衆多時人各自著述,雖然格式常有雷同,但文體成熟,文辭浩繁,語料非常豐富。因此,封墓讀詞語進行懬泛深入的考釋是讀懂墓讀並進行各種相關研究的根本前提,也是中古詞彙研究重要的组成部分之一。墓誌庚泛爲語言文字學界所關注的時代剛剛開始,文字、詞彙、音韻等方面的成果都有一些,雖然不多,但已經是较好的發端。唐代墓誌,作爲斷代出土文獻語料,作窮盡性的整理不太現實,但是,我们可以相對封閉地就一定數量的墓誌詞語進行全面考釋,如果有一個较大的覆蓋面,那麽,在這個封羳範圍中通釋的詞語對所有唐代墓誌而言就能具有廣泛的代表性,這項工作應該是大有益處的,但至今還没有人做","categories":["02_字词句考释"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWXgKMq-rn6QFMPzGoZ4NuJvhoXeHx7wOGcu36bJcLb6AmB-Uz6vErJvJ2bfhuvgvFvbfrnItGQKitjjiJ9IpQ5nPw9MOkPhDxwM9w9mSuisTeTD-9VfNEZzZb4y9A-l9h8K4xnC1tMSHp0f3RnOgqblMfkN9wyxjteKPxzxQqHMwLX43tzaFo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6465,"author":"金河钟; 杨端志","title":"殷商金文词汇研究","abstract":"本文研究的课题是《殷商金文词汇研究》。对于金文何时出现这一问题,学者们意见不一。据笔者的初步调查研究显示,金文的出现时间可以追溯到商代早期。从商代早期到商代晚期的青铜器拓片共有4508片。尽管语料如此丰富,但是由于殷商金文本身构成简单,象形性强,除个别性研究外,几乎没有进行过体系性的研究。如果我们不研究殷商金文,不仅不能准确地把握殷商时期的语言,而且对西周金文的研究也会造成一定影响。殷商金文词汇研究不仅与上古汉语词汇及其系统、汉语词汇发展史有着密切关系,也是窥探殷商社会真实面貌的基础。本论文大体由两大部分构成。一是殷商金文词汇部分(论文的内容),二是殷商金文字形部分(附录)。4508片拓片按照","categories":["02_字词句考释"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaKlm8PmC1A3CCwCP9YMaPDC-f-pyd1kB57u6FkY0l9VhN8HCbT322eHDKZTIxMesk82lgXktNJJl6cfbmD2IRZuorjwRfL6Ugl5INykiEZss0xW67U4hDHTYbPyEJtoQ-x8ZuJVsLD2LIMdwY5YaNSt0lWY17LXSnk-mo_9W9JJv72zv6VPLx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6761,"author":"王秀丽","title":"浅析金文同义连用现象","abstract":"一、同义连用的判定同义连用是古汉语中的一种重要的词汇现象,古代的训诂学家已经注意到了这种现象,对此有各种不同的称呼,如&quot;重言&quot;、①&quot;连语&quot;、②&quot;词语复用&quot;③等。目前判定同义连用的标准并不是很统一,我们判定同义连用主要从形式和内容两方面考虑,从形式上看,连用的同义词之间紧密相连,中间不插入任何其他成分,如:谋虑、安宁;从内容上看,我们主张同义连用的基础是&quot;一义相同&quot;。正如王力先生在《同源字典》的前言中所说:&quot;所谓同","categories":["02_字词句考释"],"year":2008,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZiL_GslvQYlvrghICVCCN3R9_-0fl8wSQok7c9DZvkBzH0s692XNSOgRQJ6cWkSZTUoiW8al-3m4Phe9weIVKmSH2j0Sb1iN9odAFQ6N4S1Y3LuHbsLphra1nPM0F2r4lUQumeZccN8atxAYUZbNfit292uWbxkrel0pEo1-VNQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79-85","volume":""},{"id":6762,"author":"何家兴","title":"“小臣系”玉戚铭文补正","abstract":"《文物》2008年第1期刊有《陕西韩城梁带村遗址M26发掘简报》（以下简称《简报》,原刊第4-21页）①,该简报公布了很多精美的玉器。其中一件玉戚&quot;缘面上有对称刻文‘小臣奚□'&quot;（《简报》第16页）。仔细观察照片,我们认为第三字为&quot;系&quot;,而非&quot;奚&quot;;第四字为&quot;（?）&quot;。陕西韩城梁带村出土的玉戚铭文与河南三门峡虢国墓所出玉璧（M2009）铭文完全相","categories":["02_字词句考释"],"year":2008,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcztCD-ALo26ZN-Ts0JFVemcm_bqffpAwWWrpNnyOYLYSwW09P8l4v5h9DJrkSBztl6b9Qj7X4mtZoKxL0VlI65MGot0GJMMslY8ek8C2y069u5kYHA3TAvucfhnmfsQu1y6245ud8MNEYmcXLDNvDiwGKeV9pKVmyRb1UMXJsug==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-92","volume":""},{"id":6800,"author":"孟蓬生","title":"“瞻”字异构补释","abstract":"楚简中&quot;瞻&quot;字有一个异构,有人认为它的声符来源于&quot;詹&quot;,有人认为它的声符来源于&quot;权&quot;的一个异构。本文赞同陈剑先生提出的观点,即认为此字是由形符&quot;见&quot;和声符&quot;甚&quot;组成的,应当隶定为&quot;(?)&quot;。","categories":["02_字词句考释"],"year":2008,"publication":"励耘学刊（语言卷）","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2008.02.010","pages":"208-212","volume":""},{"id":6801,"author":"唐冶泽","title":"利簋铭文“朝岁鼎克”新解","abstract":"利簋出土以来,对于其铭文的解释,专家们各持高见。本文在重新断句的基础上提出新说,认为&quot;朝岁鼎克&quot;是一个完整的句子,否认了&quot;岁&quot;字为岁星或岁祀的说法,证明岁的本义为刿,甲、金文及西周史籍中仅有年岁与刿割二义。此处引申为杀伐,意思是经过一早上的战斗,打败了敌人。","categories":["02_字词句考释"],"year":2008,"publication":"长江文明","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKS0EWxAoTcNDSZVOY-C8kZH55sxZHKTN3l0jlX5d9maKqjohpFTY7mT7bW-VWXA9w2gvsz9xMJU_fh6XmeuO0oZXhbsx36XBz3tl7FJwsnj_jzki2cdGm7fB5QzTZsXFcg5UNTnwq-lHgxUS7X6S7NDozoxg4VX362-hGLkbJJBQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-45","volume":""},{"id":6802,"author":"刘志基","title":"战国出土文献字频的初步研究","abstract":"本文以郭店楚简为古书类文献代表,以睡虎地秦简为文书类文献代表,以战国金文为铭刻类文献代表,在全面完成其字频统计的基础上进行了三方面的研究:1.不同类型文献的字频比较研究;2.战国出土文献字频状况的断代特点研究;3.国别地域差异与字频状况关系的研究。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJs2qcXTCYtPNpprOYywyF1jp6hnf5_2QfWcsdm6EHk3wN5EhAMqPaMe_isX3a9lZKQlY-bUUL2N0c6uUnfJhm-seaqldA2SUenZT01zUoVYzi8FD8cg_lC0_7m56PpLTtzm4pvqmwdWa1wsy-qJrSgufliHapNdopP5KeeE16X8A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-86","volume":""},{"id":6803,"author":"李学勤","title":"论荣仲方鼎有关的几个问题","abstract":"西周早期青铜器荣仲方鼎,共发现两件,铭文相同。其开首&quot;王作荣仲序&quot;,记建立学校之事,&quot;序&quot;字与&quot;宫&quot;字有别。根据&quot;夏商周断代工程&quot;西周历谱推算,方鼎可能作于周康王二十一年(公元前1003年)。从铭文有&quot;史&quot;看,方鼎疑与滕州前掌大墓葬有关。","categories":["02_字词句考释"],"year":2008,"publication":"黄河文明与可持续发展（第1卷第1期）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8qm_01wsLXjwoosCwX8zQbeTCUY492gzHLAFcf7ZK_k-_1AHaTZMP0vyjNy_EFv2IdnSPKz1ui8xMd7KRiR4xUc15lOc9COcSw8A0tGxE0WCxm_wFPSGlqY4C1C_6o8R7foFLDezFXQLY79BS4Z-YJ4YxZq1DcWB4SPqkVLii-LIuypTgHsF0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-25","volume":""},{"id":6805,"author":"冯时","title":"郭沫若《金文所无考》补正","abstract":"郭沫若先生作为一代史学宗师,其史学研究在充分利用传世文献的同时,更注重全面系统地运用出土的先秦古文字资料,以期借出土文献校理传世文献,并最终重建商周古史。仅就甲骨文金文而论,其所著《甲骨文字研究》、《卜辞通纂》、《殷契粹编》、《两周金文辞大系图录考释》、《殷周青铜器铭文研究》、《金文丛考》等,都是具有巨大贡献的划时代经典之作。在这些著述中,郭老将甲骨","categories":["02_字词句考释"],"year":2008,"publication":"郭沫若研究三十年","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI9UFOQvMd52ox2DztRUxNxIvPnFan4215nigoAocAzfwON36DlBrLm6fkhqyqAc-F8002Zsq0wZk1aLxlXWCrrCToxIJJ5vxvRxgLlHkRrRJaMnAWLyXdlxaxcjCd-7ufhBSlwJc42ZbArG3uqsD7T4UU3d2PKuEYsaWgiXux_sdWIABPoi0ep&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-108","volume":""},{"id":6814,"author":"郭国权; 李守奎","title":"河南淅川县下寺春秋楚墓青铜器铭文集释","abstract":"1978年3月至1979年4月,河南省淅川縣下寺發現大中型春秋楚墓9座,出土了大量珍貴文物。1980年,淅川縣文管會和丹江庫區文物搶救發掘隊於發表了題為《河南淅川下寺春秋楚墓》的簡報，引起廣泛關注,相關的研究文章也相繼問世。1991年,《淅川下寺春秋楚墓》出版,對這一批墓葬的研究又進入了一個新階段。下寺楚墓出土的青銅器銘文為古文字研究提供了豐富的材料。李零、伍仕謙、李家浩、馮勝君和陳雙新先後發表了考釋下寺楚墓出土的青銅器銘文的文章,具有很高的學術價值。本文以下寺楚墓出土的青銅器銘文為研究對象，搜集各家之說,分器集釋,為研究者提供方便瑫r略陳己見,供研究者參考鸭馁Y料截至2008年1月。研","categories":["02_字词句考释"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIYcnqNSpIjLNUJifBgNAp-grs_37--RtfO7bQXpGj2K59UjFhwXT-p1HgkM9q0VhNqRAuf_dbdyk5a-tH_OLQ77pdfgOEkBnE8NidhvXdiQ-g_D83_MhLFBjmGlVRq5fpVZUOaIm1lG1kNFCfgTjw5j27-utJEOwdTzexVSzU4eZH1jFRVb_aN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6818,"author":"吴威; 陈五云","title":"《金文编》形声字构形系统研究","abstract":"本文以金文形声字为考察对象,以由容庚编著,张振林、马国权摹补的《金文编》第四版“正编”为考察范围,在分析金文形声字单字构形的基础上,力图客观、全面、穷尽性地描写金文形声字构形系统,进而揭示这一类型文字的构形规律。本文分为两大部分。第一部分为绪论,分别介绍了形声字的成因及特点、金文形声字的研究现状和我们的工作。第二部分为正文,分为五章:第一章为金文形声字的来源、结构类型与鉴别;第二章为金文形声字的字样整理,包括了异写字、异构字和字样整理的校补等三个小节;第三章为金文形声字的部件分类与组合,包括了基础部件与复合部件、成字部件与非字部件、平面组合与层次组合等三个小节;第四章为金文形声字的声符系统,包","categories":["02_字词句考释"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMJ2J28myZqavbzQDe3UFicOl9W6iDw9Ak8uYpQsYvyLGXBapT9Rb8MXoYi_3Nn27RZEFnfnCokYM14xzY6mYJ0mebLtWChmEXCJ04RX8cAYdvQhBdHC6E3dM-Lec6xf4Lt7agvJuwRh-6natFIlQARbPWiDkZAFxiQlWBwOjGboFPc1E4goN-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6994,"author":"寇占民","title":"金文释词二则","abstract":"戎生编钟铭文中的&quot;倝&quot;,读为&quot;榦&quot;;应训为&quot;防御&quot;义;史密簋铭文中的&quot;■&quot;,读为&quot;觀&quot;,应训为&quot;觀兵&quot;义。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsKpxMe7091DIP85oacps0304g4lcHLSSK3YHbINFYVu6xItjEYvtzCZ4Fv5rxTaEPP02KblXIZQwETYdWS4XiAQBU0bN8rJeb1ZESlRqidhXU7_D4spXGcJjP_gnQ2xNvDtfPf3EXvWLvaRfXc0X99MPC1Whu9lfiGDZmP3627A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-33","volume":""},{"id":6995,"author":"汤志彪","title":"金文考释三则","abstract":"本文对个别金文字词作出新的解释。伯■簋铭文中&quot;褱(怀)■&quot;一词应读作&quot;怀顾&quot;;十年陈侯午敦铭文中&quot;器&quot;字前面的字应该读作&quot;祰&quot;;王孙诰编钟铭文中&quot;不畏不差&quot;一词应理解为&quot;不随便、苟且,也没有差错、过失&quot;,&quot;■&quot;应读作&quot;壮武&quot;,指勇武、雄武,&quot;谋猷丕饬&quot;当指谋略的严谨。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsKpxMe7091DIP85oacps0304g4lcHLSSK3YHbINFYVu6xItjEYvtzubTsSloDLbPH1LZ3tTyl9RzBNWrPZMmsAqKdJcDgz9tYglVzsfPJ3_vwE_N-YBunoybSfZa4ehSBR7uXORLLS8FcaLvxx2wjRpQBWAJE5v2Izs4hpwagcg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-37","volume":""},{"id":6996,"author":"王晶","title":"金文中的“取■若干锊”与讯讼无关","abstract":"金文中的&quot;取■&quot;就是指&quot;取钱&quot;。那么所取之钱来自哪里?作何用?前辈学者对于这笔钱的来源和用途提出了诸多说法,多数学者倾向于认为这笔钱是诉讼费,但逐一考释铭文,似有欠妥之处。察看所有有&quot;取■若干锊&quot;字眼的铭文,我们发现这笔钱与诉讼没有直接关系,楚簋、番生簋盖、■簋盖和毛公鼎中都没有提到&quot;讯讼&quot;的问题,但依然出现了&quot;取■若干锊&quot;。这笔钱也不是一般的官禄,因为它只出现在少数的册命铭文中。通过对材料的梳理,我们认为&quot;取■&quot;之&quot;■&quot;来自大府,是大府征收上来的税款,用","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL9zZY9h4AiT7VxKaEEXrcDnNBcQDGnHlrX9BRV7MvDJQ4AscBzxs61emwk5QUUkxVLvcR2cNWZHSOxNtDh-3KYfj0rDPvx-JP3y9jXUFmhPX2pGFS44zjWmiCsthLpZKDhMXjzBsjrkaszQg-bv-_PNuLWe-y10KCAAhzUyMS6kQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-42","volume":""},{"id":6997,"author":"张再兴","title":"金文人名“某某父”中排行的计量考察","abstract":"本文对金文人名的主要形式&quot;某某父&quot;中有关排行的问题进行了计量考察。排行顺序与器铭数量的正比性反映了其社会地位的差异。&quot;伯&quot;、&quot;孟&quot;的区分并非传统学界认为的嫡庶之别,而是使用时代和性别的差异。考释金文人名中的■为&quot;孟&quot;,■即&quot;中&quot;。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL9zZY9h4AiT7VxKaEEXrcDnNBcQDGnHlrX9BRV7MvDJQ4AscBzxs61meaQ9NgQe0QGuqHMH1EUzgmHIpJ3dJ84u4pvQSPMkQOEJ6H55K1JnoWjGhl8EEs-vdy9xjL3ddQwmcnqfTRpmivQsY8dlrrtcG-gwz-xfo_IE7ENnkwMag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-52","volume":""},{"id":6998,"author":"陈英杰","title":"商代金文文例研究","abstract":"本文主要从作器动词、作器对象以及器物自名等几个方面对商代青铜器铭文文例问题作了一点总结和探讨。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJlMdoR0eMaxDgEP5WdYeREx6MIFLszv_7NRKJliAOBHgNrG-mjii23ink_y5C4vDrzmbery4Ki75qe_KHuiMWiltl5BGOFruXrloE2vBB5o1MxlWyuTuZPkNKgWZgJ5DgpiO3fVNrE13P8ajcVy1LgEk7IGQbmDL38y6JkMx16xg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-60","volume":""},{"id":7001,"author":"汤志彪","title":"包山遣册简补释一则","abstract":"包山257号简是遣册简,简文的第一句话是:食室所以△■①■,整理者认为:&quot;经与出土实物对照应是盛放食物的竹笥。&quot;②■作为盛物器,还见于信阳2-06号简、仰天湖13号简以及包山258号简。对于信阳简和仰天湖简的&quot;■&quot;字,朱德熙、裘锡圭先生认为:&quot;据文义推勘,■肯定是盛杯豆的容器的名称。我们认为■就是古籍的■。共、夅都是见系字,共在东部,■在中（冬）部,古音极近。《孟子·滕文公下》:‘书曰洚水警余。洚水者,洪水也。'又《告子下》:‘水逆性谓之洚水。洚水者,洪水也。'","categories":["02_字词句考释"],"year":2008,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgJIFS3eMaL3mbMPplT5Pc_uFluLfSC8gwrSNtm3eFPiysCjyYVa1B-3B1OcWuIxAkjNQETIJYBun6_wgiCZ3tvBwS2bu-pUS0cZEY_Glw05V3y_VPlrhkAHf5Jg5M7WskgWPyG3OMT-AUUQJEhheR4V8ly-QLWprKDxXl-tpRPw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46181","volume":""},{"id":7003,"author":"李学勤","title":"论荣仲方鼎有关的几个问题","abstract":"西周早期青铜器荣仲方鼎,共发现两件,铭文相同。其开首&quot;王作荣仲序&quot;,记建立学校之事,&quot;序&quot;字与&quot;宫&quot;字有别。根据&quot;夏商周断代工程&quot;西周历谱推算,方鼎可能作于周康王二十一年(公元前1003年)。从铭文有&quot;史&quot;看,方鼎疑与滕州前掌大墓葬有关。","categories":["02_字词句考释"],"year":2008,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL3mmeKOH4GKCopm5Plc045WhRL-Atx0vwaMeCx9gmFcgvIr_iYhl5Eq3E2Rrk1izKdQal3S81MkJkm906jb4Aq-jZxK0WDHPvomWVUvo9X6pk0DT4kTa-Wj2-3R4mWCYJPjiCKYT6oW6m5xVl-LASa6_SJFzlTPSSe0W4HYNuz8Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-19","volume":"1"},{"id":7010,"author":"王辉; 王伟","title":"《秦出土文献编年》续补(四)","abstract":"(2927)元年相邦疾戈秦昭襄王元年(前305年)铜质。仅见内部照片。内上一长方形穿,正面刻铭文3行14字,背面刻1字。[藏]珍秦斋[图]施谢捷《秦兵器铭刻零释·四》[文]同上元年相邦疾之造,西工师诚工戌疵(内正面)明(内正面)铭文中的&quot;疾&quot;即樗里子,惠文王弟严君疾。《史记·秦本纪》:&quot;昭襄王元年,严君疾为相。&quot;&quot;明&quot;为&quot;葭明&quot;之省,即","categories":["02_字词句考释"],"year":2008,"publication":"秦文化论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVlpuPFRjrNsmlE-HnAPNIRSAZ7ocPdghDaRkgZmrslORPyBcCdRR_9-0Yz5-cXUAfsfkAsThXSFqDCtyQ35gyTNqiAXE0mCxD9N8UgOAB8yU5ySoyGVGJOV1SvRlBPb8SyLPiGFl-x3z3M35uxtroKHkdZrcfSkiTbOkLO82vtg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"226-266","volume":""},{"id":7011,"author":"袁长会","title":"“若”字之考释","abstract":"在古代汉语中,&quot;若&quot;意义极为广泛。如何确定&quot;若&quot;的本义对其各义项之间的源流关系至关重要。本文在前人基础上拟从形、音、义三方面重新探求&quot;若&quot;这个字(词)的本义以及各义项之间的源流关系。","categories":["02_字词句考释"],"year":2008,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKatPJKDGQNaVXiMVyhcOa5I8gBPSYeex3cLKRBvF09O2kyQbbkvcUvhdXi81ShPuXIghcnJQgykdZ9cQM3JVmxZdyanaRvLxBCEGAl_P_oanz3j26GCqrIEESexXMnDcbavwQcfdekZgVydqs_oJj6qyX5Fhz7oaBtIxFNW3hjVXSuDgBxiTCn&amp;uniplatform=NZKPT&amp;language=CHS","pages":"146-147","volume":""},{"id":7012,"author":"武振玉","title":"两周金文宾语前置句释论","abstract":"两周金文中的宾语前置句有以&quot;是&quot;和&quot;唯&quot;为标志的两种,前者已具有一定的数量且形成了&quot;是&quot;字本身充当前置宾语和复指前置宾语两种不同的形式;后者虽数量有限,却体现了与甲骨文中同类句式的传承关系。","categories":["02_字词句考释"],"year":2008,"publication":"华夏文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKatPJKDGQNaVXiMVyhcOa5bJUFQWlXBH5LrvaAIELt1r4MEQHYvkI48X5O46Oc8e2fZ2elRVYC1-GIbM6kmUSR7mro4_wfJi7AKZNEjmJuLPe0rqHljvke2EDZuz9WgYTyO1qI1-2NZm7Um0LHLLqpbOUYyE6lUYqhRISGGKRRIA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-124","volume":""},{"id":7014,"author":"刘敬林","title":"古文“唯”“鸣”“谁”一字异体说商榷","abstract":"对&quot;唯&quot;&quot;鸣&quot;&quot;谁&quot;,古文字学界有一字异体的说法,文章从历时角度对此进行了考察,提出了与之不同的意见。","categories":["02_字词句考释"],"year":2008,"publication":"励耘学刊（语言卷）","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2008.01.007","pages":"106-109","volume":""},{"id":7016,"author":"吴国升","title":"春秋时期汉字字形分化现象的初步考察","abstract":"汉字是一个伴随着历史发展而次第产生和累积的系统,基于已有字的字形孳乳分化是汉字系统调整发展过程中构制新字的一种重要方式。本文以出土材料为依据,从字形关系出发,结合词例,对春秋时期发生的字形分化现象作了初步考察,清理出有明确线索的分化字28个,并分析探讨了其产生出现与流传存废的原因。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWiqkPpS394Thsdan3RIbUOAUqLO2y4wsfIqVOnEuzGa73tJDfe-m9RwBs2nRtRHYqQPhKOoITdDIgoaHKVOWhg9Qnsxo9jAzhzrCiGws_GefxwBU38w0LNO7cTldBojkBxvLtG_6YjZrhY0W_5B2bzIzp9yinqaaJpkggHebWzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"201-206","volume":""},{"id":7017,"author":"董莲池","title":"沬司徒疑簋“■”、“啚”释“徙”、释“图”说平议","abstract":"本文通过对&quot;徙&quot;、&quot;圖&quot;二字形体源流的考辨,从根本上否定了沬司徒疑簋铭中的&quot;■&quot;、&quot;啚&quot;释&quot;徙&quot;、释&quot;圖&quot;的可能,认为前者只能释为&quot;延&quot;,学者从前的认读没有错;后者只能释为&quot;鄙&quot;,和&quot;圖&quot;无关。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWiqkPpS394Thsdan3RIbUOAUqLO2y4wsfIqVOnEuzGa73tJDfe-m9ecIS7Jv6ZnWERcEKPX4-zB1ebH7klXGavpxIbs7bOqMhe9-3k3b2CfRu7jceRzIjJAa62QXzJIRvNIBhB8YK5W_13pgbhR7e818Yeub6tl-rHVFiTLAz2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-17, 9","volume":""},{"id":7018,"author":"潘玉坤","title":"从商周金文看文字孳乳","abstract":"《金文编》为探讨文字孳乳问题提供了一个很好的平台。书中列举的孳乳实例表明:字形上孳乳字须是在基源字基础上加旁而成,字义上基源字须曾一身二任地表示过孳乳字的意义。而由同音假借所形成的文字分化,则以不纳入孳乳的范畴为宜。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6aN9QQIvlrnR8AprTLtm0-Yhg79ixSttiNZlHAmvO3kbLk6mlBWqIwp1d9w6vF7eLSKRWlgvOIQhpUzBOlyggqeynmn9rVTJQ46bBLbwXHhfCFDsteDj9nFPS89qxVHhXCuxcz8eAV9pY3RbCQHjaQvCev8T6K16GOCfNGtcRgw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-22","volume":""},{"id":7019,"author":"王子扬","title":"“毕公左徒”玉戈小考","abstract":"本文对洛阳唐宫路小学战国墓出土玉戈的四字铭文作了重新释读,将整理者释读的&quot;毕公左徒&quot;改释为&quot;罼(毕)公左御&quot;,并且对&quot;毕公左御&quot;作了比较合理的解释。这件玉戈是毕公任周王&quot;左御&quot;时所作,死后随主人下葬墓中,墓主就是毕公本人。","categories":["02_字词句考释"],"year":2008,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI1dtEn9gaQQpHCyIF7SkgpvR-8DN5LDoschXs2jYOZc3NCBESINg24hij0SpuSj5VftZtTdc_5zOz-4p5uEtu9QuzjyqOJPyz6owuowcRcrpw3RgFCqPe_StgiZNCqloVcS6zBArriRQkrFHDF9L_bvBlHG3xliGLUGFX9FNF_sQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-61","volume":""},{"id":7021,"author":"张聪燕","title":"释“酉”","abstract":"许慎在《说文解字》中只是简单地用声训的方式对&quot;酉&quot;字作了解释,因此他没能释岀&quot;酉&quot;的本义,并且错误地认为&quot;丣&quot;是&quot;酉&quot;的古文。本文将对&quot;酉&quot;的甲骨文字形进行分析,并结合实物考察,得出&quot;酉&quot;的本义是盛酒器,&quot;酉&quot;是&quot;酒&quot;的本字,&quot;酉&quot;不是由&quot;丣&quot;演变过来的。","categories":["02_字词句考释"],"year":2008,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmwF9yLfxZl5h_zQH6_mQ5otILcowdzVhbM6VDAM2wpqRoM2_Cp7FlzsjbJcSn4sdV6Uvgg5AC2qe9ScgBKzhdwCTu8f396M7X0PkGvH0vmv97W0sPLUuyapTmw-VZVYQf_01lANTn2B_ZNeI_eIdNYdGLGHYtlDm3aRXTMG8kQ_xXLDomgPVq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-105","volume":""},{"id":4847,"author":"黄可佳","title":"殷墟刘家庄出土的有铭文玉器及玉器演变和定名的有关问题","abstract":"1999年9月中国社会科学院考古研究所安阳工作队为配合基本建设,在安阳市西2公里的刘家庄北部发现了1046号殷代贵族墓1。在该墓墓主人头部的铜簋内及右侧,出土了玉戈形器（报告称石璋）55件,均为长条形,多数上下有刃,一端似戈的内部,且有一穿孔,大部分出土时已残。其中18件玉戈上有墨书文字,绝大多数书写于戈的正面中部,书辞自上而下,自右而左。","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLrvwky6BKW48OAbZZjaOiGW6AIs7V3bzLI5aeQ18RlYl1Af6fhvKyD_iLW0vU80kVqoWCq1RYbqE5S8w2hwo-c9uOPQzSZz_IOjyBR_GZ7AuBb4MwI37MxtAkavRlo5JS2_ukCiM9d22ojFApn2t9Niwa81K8h7JRSRFgOD8KbCfv_sZZuF4Ir&amp;uniplatform=NZKPT&amp;language=CHS","pages":"209-213","volume":""},{"id":4848,"author":"严志斌","title":"?器铭文零释","abstract":"?器是新近从海外回流的一批重要西周青铜器1,铭文内容涉及西周中期的册命制度与周人以馨香享祀百神的实况。最近,吴镇烽先生撰文集中介绍了一鼎二簋一盘一盉一甗一壶共七件器的?器铭文与器形图相,并作了精湛的分析与考释2,文意、器主与时代已基本廓清。这组器铭除可为金文中册命与祭祀之典增加材料外,还新见多个字形与名物,笔者在学习铭文过程中,对以下二字的认识与吴先生稍有不同,现写出来,以供吴先生及学界同好参考,并请指正。","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6JPRS-7r_JJkc_v1AtyHeJyD7UlnENdfnk6Yd8s2AdZZFb6wHxFjRNiZTpm_1wohROuOz6FZXFKGKuWPXGhCQ2c9PX0yOIAlcSUJHPbCAbpIYL2Uc5mhoIrpton_nGSFuJMIasea3EFevM3C9nVrtx5xuZeoBy7Fz8cL99FzF25DwSA2PSkb5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"214-215","volume":""},{"id":4849,"author":"连劭名","title":"两周青铜器铭文新考","abstract":"一《邾君钟》铭文云:邾君求吉金,用自乍其和钟、和铃,用处大政。《殷周金文集成》(以下简称《集成》)1.50。“政”同正。《释名·释言语》云:“政,正也,下所取正也。”《论语·颜渊》云:“季康子问政于孔子,孔子对曰:政者,正也。子帅以正,孰敢不正?”西周青铜器《班簋》铭文云:“谥曰大政”。《梁其钟》铭文云:“梁其肇帅井皇祖考,秉明德,虔夙夕,辟天子,天子夷使梁其,身邦君大正。”(《集成》1.187)","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJUJVHayq56lv3LiZizHSOCqfH4DXuB4kjZcl2oM-a5ZbtJoIuhHhvnpbAddmHnyGaf-0h9Pe-Rl7h0aJaT1QkyackxYIlQR1eIEqeRdBdoSE6UIbEvRFM61LV-qACI-isNUOKNY4RUdRyv-IBwfhFW5O8vc6-f9ZyInz4EByDHNkEv1hhlCcP5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"219-226","volume":""},{"id":4850,"author":"陈英杰","title":"关于周代金文祭祀对象中的父、祖是否直系问题的一点商榷","abstract":"我在博士论文初稿（2004年6月）第二章中曾指出:为之作器的祖或父不一定就是作器者的直系祖父或父亲,而是指祖辈或父辈的某一杰出的人,如《铭文选》3·1741录■卣云“用作文考乙公宝尊彝”,3·175录簋云“用作文祖辛公宝将簋”,3·177■簋云“作祖庚尊簋”,3·178■方鼎又云“文祖乙公”（录、■、录■均为同一人的不同称呼）。","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxUcUozvK8pJ5t352KB_Z-UUC4jiGrPjQUlY6B4bFoRx0WXcVoesYtFMKtdwR4OP2O7EDJBaM9CJjRHnjd7rKcaVBju_Y_D7y1WIbdLVFYvDZ29DyQ9wOFBO2MV1ldDOMuEuF3LfDJxMlm2P5nxky7mPckMvTIjN93zbKKHPWnqsP2keh8eTSX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"227-228","volume":""},{"id":4851,"author":"邓佩玲","title":"金文“命”系嘏辞与近出楚简新证","abstract":"一、引言1925年,观堂先生于清华大学《古史新证》课上提出著名之“二重证据法”:“吾辈生于今日,幸于纸上之材料外更得地下之新材料。由此种材料,我辈固得据以补正纸上之材料,亦得证明古书之某部分全为实录,即百家一雅驯之言亦不无表示一面之事实。此二重证据法惟在今日始得为之。”1王氏倡议以“地下之材料”补证“纸上之材料”2,藉以验证古书之真伪及补苴其阙如。“二重证据法”影响甚巨,后世学者师法其意,以传世古书与新出土材料配合,作为相互之印证发明。","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0V_au33w-6UuPTWuvajaqxUjOVlyxO37sXqCzUSU-rKbKFN1cI2gmduXdWYAqbTv73Bm2EHo3VfoIxo_tDe0C0JN9wqRgNLmiUZQyz71DZ3NLjX5EtFQT2Q4NL7v2xQgcXHovZ1IBAoRSHpCiU_nsNCj7XIobB0PUyzHh3eDUK21g5RMzmIvG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"229-234","volume":""},{"id":5601,"author":"张玉金","title":"甲骨金文“尊”字补释","abstract":"甲骨金文中的&quot;踙&quot;应释为&quot;尊&quot;,&quot;踞&quot;和&quot;踙&quot;为一字异体。&quot;尊&quot;有两个义项,一是作动词,是置放、陈设之义;二是作名词,是指用来陈设的礼器。","categories":["02_字词句考释"],"year":2007,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJL8VqFn7evijcJpKreDyWgxAu1aLEsbriiiGAnkvAbEX5VcVBps-rcw-hUmmNa7Ss5qtGXnHshuTGIvuDCqxPNatopFcKJd2uiiO-6CnNQatqdhT_eBilaJj2mF5NKVJHACrnk-00lI3A7g_JQcvJs7arXwhhO3tNgWyGjrxZ3zQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-30","volume":""},{"id":5602,"author":"商艳涛","title":"金文中的巡省用语","abstract":"金文中表示巡省、出行的用语有省、遹、遹省、行、■、狩、征、遹征等,与传世文献有所不同,有的只见于金文。","categories":["02_字词句考释"],"year":2007,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2007.04.020","pages":"66-68","volume":""},{"id":5609,"author":"李憣","title":"■为贾证","abstract":" 关于西周金文&quot;&quot;字的考释,始终未得定论。赵诚先生称&quot;&quot;是20世纪金文文字考释&quot;争论得最激烈、最长久、参加的学者最多的&quot;,并介绍了其概况。彭裕商先生在《西周金文中的&quot;贾&quot;》一文注释中罗列了主要相关学术论著,高明先生则在《西周金文&quot;&quot;字资料整理和研究》一文中汇集了学者的大部分意见,兹不赘述。本文拟在前人研究的基础上,就有关&quot;&quot;在文字学方面悬而未决的三个基本问题,即&quot;&quot;为什么一定是&quot;贾&quot;、&quot;&quot;是什么,&quot;&quo","categories":["02_字词句考释"],"year":2007,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLACdcgVML1DzJYtitvG9afy7zOcLoPEb0mX0eLIKf0kErBL-30iRwbxiaVDWPuG8MDF52ofzOmrSEKQI4XdWK6ZkO0wOAkgMUaZngHgTsmrLt3qNCavjSCnVqFcj4FXxKtWlEPyAePY-6DNlGM5Rxkj4RhG-jcqHD5Gja2oRfRUw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-77","volume":""},{"id":5611,"author":"武振玉","title":"金文“在”字词性初探","abstract":"&quot;在&quot;是古今汉语中的一个常用词,且出现时间很早,甲骨文和金文中已经有大量&quot;在&quot;字出现,但关于其词性问题尚存在不同看法,或视为动词,或视为介词。对金文&quot;在&quot;字应用情况的详细考察,可以比较全面地了解金文中&quot;在&quot;的整体应用情况,理清关于&quot;在&quot;的词性问题存在的一些争议;另一方面可借此了解上古汉语早期&quot;在&quot;字应用的一个侧面,并藉此探讨&quot;在&quot;由动词向介词转变的原因、过程以及其中的规律。金文中&quot;在&quot;字的大量出现、用法上的变化以及相关的研究还可以使我们","categories":["02_字词句考释"],"year":2007,"publication":"社会科学辑刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEgDK5hSU4ng5W3imQVhrbik2E0A5DxlZeL9b3cnJQfjlqZCZbqH5qutvnh7-3Pl8u8Tq9G7rkg1TLyYF3E8NT5pGvbg8h6IRnM-mXSI17ic2O-iwNab735b2kX9KkXHIxhSC7NnCz2FucbPbeWHmXZIDgAYAkz0DDHnELhkmlTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"304-309","volume":""},{"id":5614,"author":"晁福林","title":"作册般鼋与商代厌胜","abstract":"作册般鼋载商王到洹水田弋事,铭文为了解古代弋射增加了一个新的例证。铭文所载&quot;奏于庸&quot;,其直接意思应当是献牲于庸,具体来说,就是用牲血衅钟鳙。这对于认识上古时代衅钟与厌胜之俗有重要意义。","categories":["02_字词句考释"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwpycx2E_u_wowpZRk4FDbdqfme3h6FoToJy3UPdsX-8bdav_7DRlGtl1-ULBsR6d9vQ3s5CtEkENQa7RJK_b9Lft-jeQSJmfKR6yGtNtXe-IfdvQ6_19NsjGbpwIxFAmIMUFxUCrLRrdG-BiuV34gN4E9qX_E1boQ3PuJrfO-8w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48-54","volume":""},{"id":5615,"author":"李清丽; 马伟峰","title":"梁姬壶铭文试析","abstract":"河南三门峡虢国博物馆藏梁姬青铜壶铭文后两字一直未成功释读,本文通过分析,对其做了进一步的考订,并提出新见解。","categories":["02_字词句考释"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZnsVKx_c41TCRYOnowYeZKayLs6I3XdgU1cVrql360RQID4ndwayRkyM_gTRz84zWK4ujaZd-UYmcUZ85mxg7KjQg2QuL0x8uvd7Muq8L-uEXkN1Ac7cMX-u485x1LZ1UoghAupLrDv0UnpC9Zxecm22X_0eM7DrhGxdf2Uhp-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-57","volume":""},{"id":5618,"author":"商艳涛","title":"金文中“征”值得注意的用法","abstract":"","categories":["02_字词句考释"],"year":2007,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxQi5MyoJ7lcznSGTNFO216dQTIwpoqPRabittSWiFdPyOUHY4LgRIosex5Qz2tovv1KsJ-QdNbjXlkt8a-jgW2Mzx-tBHk2KDGZ2WG13G8sSi5OgJEv9bBM7Kj8CjloDZyc7wwiIlsBkuiGzym9uiPlrQ-Kih27kJRxE0Y52Qig==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-145","volume":""},{"id":5622,"author":"吴镇烽","title":"琱生尊铭文的几点考释","abstract":"","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJlsASxjDi82G4peKIgEgPNv0yX55DViSMFOYHUq4AxShnWIu-dryPVT1Gf2y2NTx_OQvy6QXa7nSL1Tp0zdEkiyhD4VlXWhuUDbtCDGYaKQq7DkNSRJ9unl3BS_OSm17QBJuRHTID4N4G3k-FBCwsbBvlc9ERggHNT2QEXLwwLHQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"103-104, 111","volume":""},{"id":5623,"author":"王占奎","title":"琱生三器铭文考释","abstract":"","categories":["02_字词句考释"],"year":2007,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIdyJ33oBSXtNS8ZaCpg9dG0DmBcjHPkeXaP2hlZ6JZfFUvf0gGTSAE7r_3pKrlin19-B0WA55BHyPaRGseEBMTK0HHI-i6liuOkDW1eYfqVAd_qHJ2Eij5uzdssdGaPWOOk3vQMuL8J39L1iTQmfIfNaht4GVZY64cP30FFHOwbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-108","volume":""},{"id":5625,"author":"穆海亭","title":"周代金文中的妇名","abstract":"研究周代妇名,对判断古国之姓,进行金文断代具有重要意义。周代妇名的特点,是必称其姓。这是&quot;别婚姻&quot;的标识,也是与夏商妇名的显著区别。","categories":["02_字词句考释"],"year":2007,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6y1oPLYfhPQ0pErFzEZ5TpAAqkMykX9Tm14-Mab60kfffaEW57bmCLsaPkgrEyzAyu48GxiRCPpxjxeNPcxxtqPMQ8Hr3VakdtpHJbAVC9DwKGhZBAx9qTDygP0JV9GAngCsyfH_jhw2IgjikihgrqYeZ_cxj330oTXhjlKqXJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-55, 15","volume":""},{"id":5626,"author":"王龙正","title":"匍盉铭文补释并再论(兆见)聘礼","abstract":" 平顶山应国墓地出土的匍岙,不仅造型独具匠心,堪称一绝,而且铭文所载史料异常重要,价值更高。此前发表的简报,因作者水平所限,存在一些错误,需作更正与补充,加之当时因限于篇幅,诸多问题没能展开讨论,故而续写此文加以阐述,并试图对铭文反映的先秦覜聘礼进行考察研究。不妥之处,敬请读者批评指正。","categories":["02_字词句考释"],"year":2007,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJBrfAx9wdPNeI4sztMbldDmV_bYwSE6T_X9GOf8FGUh3xBoxISYsmMl9yBU4DZlMW64Y0p65K15U4xGR_4S9U5xKytTnqEPbIsZ1vfDv_H3Ib5M7xqkiKNp2mec7qAvyharTi1VNfs8vmuFiM0g7nJ7W6gPTND9ML3sSIa5AiQBg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"405-422","volume":""},{"id":5628,"author":"陈荣军","title":"西周金文辞例札记","abstract":"本文是对西周金文&quot;贶&quot;、&quot;遘于&quot;、&quot;亡尤&quot;、&quot;大采&quot;、&quot;昧爽&quot;等一组词汇的研究,主要从两方面进行讨论:一是西周早期金文词汇与甲骨文、晚商金文词汇的互证,明确这些词汇的传承与来源;二是金文材料与传世文献的互证,有助于对传世文献中这些词汇的理解。同时这些词汇的断代研究,对金文的断代也有辅助作用。","categories":["02_字词句考释"],"year":2007,"publication":"求索","link":"https://link.cnki.net/doi/10.16059/j.cnki.cn43-1008/c.2007.09.074","pages":"207-209","volume":""},{"id":5629,"author":"夏先培","title":"两周金文的第二人称代词及一些相关问题","abstract":"两周金文共有的第二人称代词有&quot;女&quot;、&quot;乃&quot;、&quot;尔&quot;,它们的语法功能一直比较稳定。&quot;余、朕、女、乃&quot;和&quot;我、尔&quot;在殷商以前可能属于不同方言,后者之进入前者所在方言,可能就是为了补前者不表复数之不足。第二人称代词在殷商西周时可通用于各种身份的人之间,到东周春秋时期逐渐有了限制。从殷商西周到春秋战国,随着称谓礼仪的发展,称谓系统也发展得愈益丰富完善。","categories":["02_字词句考释"],"year":2007,"publication":"长沙理工大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16573/j.cnki.1672-934x.2007.03.024","pages":"112-116","volume":""},{"id":5631,"author":"徐乡耕","title":"从吴语与吴国青铜器铭文释“吴”","abstract":"&quot;吴&quot;吴语读&quot;ng&quot;,&quot;鱼&quot;吴语亦读&quot;ng&quot;,两者同音;国语&quot;吴&quot;读&quot;wu&quot;,&quot;鱼&quot;读&quot;yu&quot;,发音迥异。吴国传世最早的青铜钟记载称&quot;工䱷&quot;,写作&quot;■■&quot;,吴王阖闾、夫差剑称&quot;工吾&quot;,写作&quot;■■&quot;,吴国青铜镜又简称&quot;吴&quot;,写作&quot;■&quot;;&quot;吾&quot;早期金文写作&quot;■&quot;,&quot;后省略为","categories":["02_字词句考释"],"year":2007,"publication":"苏州大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.19563/j.cnki.sdzs.2007.05.026","pages":"92-95","volume":""},{"id":5634,"author":"商艳涛","title":"金文札记二则","abstract":"金文中的是一个表示与祭祀活动有关的字,历来有多种理解,近来又有貉祭说。根据时间、祭祀对象及目的看,与貉当是两种不同性质的祭祀。《汉语大字典》中所收录的盠器铭中的&quot;盠&quot;是人名而非官职。","categories":["02_字词句考释"],"year":2007,"publication":"嘉兴学院学报","link":"","pages":"87-90","volume":""},{"id":5635,"author":"商艳涛","title":"金文中的俘获用语","abstract":"俘获用语是金文中军事用语的重要内容,主要有&quot;俘&quot;、&quot;捋&quot;、&quot;获&quot;、&quot;获馘&quot;、&quot;折首&quot;、&quot;执讯&quot;、&quot;有得&quot;、&quot;有檎&quot;、&quot;多擒&quot;、&quot;取&quot;、&quot;夺&quot;、&quot;捷&quot;等;论文联系甲骨文材料从字形和用法两方面对这类用语进行了较为全面的探讨,并对部分字词的功用作了细致的辨析。","categories":["02_字词句考释"],"year":2007,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLMR6mfS789vjNZrFbEZeydYsfLeoAH7Ij3GwUZLaQxLLQQoQ2u57QaLOkBdezzDFczoEzl2G2eGKZMRc9B3o1g3ZUlWAfRjxPypsIv8AQg1f0WPt3uSPuF3CLJHEY1Qnqa1A7Q6zZwW5_5HH0iJEEXMH6O9fUqffLfMV0sqzsJNg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-101","volume":""},{"id":5636,"author":"邓飞","title":"两周金文军事动词用字分析","abstract":"汉语用字研究一直是探讨汉语性质的一种有效手段.本文以两周金文军事动词用字为例,分析其内部用字的六书差异、用字的意义特点以及假借字的语音特点。以期为读者更进一步了解、认知上古汉语的特点作一些尝试。","categories":["02_字词句考释"],"year":2007,"publication":"绵阳师范学院学报","link":"https://link.cnki.net/doi/10.16276/j.cnki.cn51-1670/g.2007.09.014","pages":"33-35","volume":""},{"id":5638,"author":"单育辰","title":"再论沈子它簋","abstract":"沈子它簋铭文一直没有得到通读,本文在前人研究的基础上,对铭文作了进一步考订,并对一些字词的考释提出了自己的新见解。","categories":["02_字词句考释"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJtKFdTA_61UE5tHlBp6q2vvh07QskTKfxkebOIgTqhbgYem5Y0LTeIpBAqQMXq_3-xd-1WENFGpfI80hnKSMbtNzaPClVp4AZNcU8j7rCBh7wQqPDCZg5nQ8AhodEXiWbzfmT8gGEZXt-FMrjo0MZtjMhmCPBejItjk5AUNjp5BA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46245","volume":""},{"id":5640,"author":"王其秀","title":"成君鼎铭补正","abstract":"2007年第4期《中国历史文物》刊载蔡运章先生《战国成君鼎铭及相关问题》一文(原刊第44—48页,第65页)。该文著录洛阳新近征集的1件战国晚期铜鼎,铭文有4字,蔡先生释为&quot;成君七六六六&quot;。首2字,拓本不清,但从摹本看蔡先生释为&quot;成君&quot;,是正确的。后2字拓本清晰,作(?)。","categories":["02_字词句考释"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxn22Y_BqFNDPFiRM0twrEgaVeKvvuIy1CMEXHk2MpBXQDKYYhgjp6ba6-1gsBzlB0oK6Z9Jb5iUCLiOY3pE4WDGamjzKLiZGGvO7W8ojZpUYKdBM6kphvfYKk4xSoJ7rTFzwTKr-vMYeJh7UEGde5QmomRhBH2xframSTFMDidw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19","volume":""},{"id":5643,"author":"李学勤","title":"从柞伯鼎铭谈《世俘》文例","abstract":"新入藏国家博物馆的西周中期青铜器柞伯鼎上的铭文,记述了周王朝对南方蛮夷方国昏的战争,昏可能即《国语·郑语》的闽芈。由鼎铭文例知道,当时叙述征伐采取&quot;命&quot;、&quot;至&quot;和&quot;馘俘&quot;的格式,与《逸周书》记武王克商的《世俘》相似,其&quot;至&quot;均指抵达征伐的目的地,从而纠正了该篇注释诸家的误解。武王命人征伐的方国可能很远,如蜀即在今四川的蜀国。","categories":["02_字词句考释"],"year":2007,"publication":"江海学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIKsKYMk9SZfu3blqoEcRto48HcFDg2xObkHLf4uG0JHfNBCEdUAbbImM7j2jG5HOLfZBugTCyTvYSZUmnQHmL9g-phZfYDJxdLnxnbAf0CECRt4T8qudlf2R72GDaMYiajnVzK5kbbRDj6IfKjX8McqbiOdG_DbkP9UC3OYF6LA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-15","volume":""},{"id":5645,"author":"葛英会","title":"读郑州出土商代牛肋刻辞的几种原始资料与释文","abstract":"近年,因郑州二里岗牛肋骨刻辞的&quot;土&quot;字之上补释出一个&quot;乇&quot;字并连读为&quot;乇土&quot;(即亳社),从而牵涉到商史研究中有关&quot;商汤都亳&quot;的重要议题。通过二里岗牛肋骨刻辞几种早期资料的比对核校,过去的几度释文确实漏释了其间的&quot;乇&quot;字。此字的补释,对相关史实的研究将产生重要影响。","categories":["02_字词句考释"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLnRyz90EiOEZpgu5zDSFxc-d7WVPMPysH0AucynTJSq5SPi3uYdY9BGKiCZGUwOea2qhubBbzYco6Hwo5p6rq3ZuAa27Ff3qO3r-pK5RuPYSKmauykFUwl4rfrYu2J9G2RcmOFTe2IXzK4P7sEuEwzzI3PMLmOe2dEZM6X1EaTNA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-97","volume":""},{"id":5647,"author":"李学勤","title":"琱生诸器铭文联读研究","abstract":"陕西扶风五郡西村2006年11月发现的青铜器窖藏中一对大口尊形器,铭文可与过去著录的2件琱生簋联读,互相印证。铭文纪年应属于周厉王,内容记述了召伯虎宗族内部仆庸土田分配之事,对研究当时社会经济制度殊有价值。","categories":["02_字词句考释"],"year":2007,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2007.08.005","pages":"71-75, 1","volume":""},{"id":5648,"author":"辛怡华; 刘栋","title":"五年琱生尊铭文考释","abstract":"2006年11月,陕西省扶风县城关镇五郡西村发现一座西周时期的青铜器窖藏,出土器物27件(组)。其中两件带有铭文的五年琱生尊最为重要,它们与传世的五年琱生簋、六年琱生簋(又称召伯虎簋),是记述同一事件的不同阶段,为理解该事情的来龙去脉,提供了新的金文资料。本文在以往学者研究的基础上,试对铭文进行考释,不妥之处请指正。","categories":["02_字词句考释"],"year":2007,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2007.08.006","pages":"76-80","volume":""},{"id":5653,"author":"雷缙碚","title":"从西周金文用字看同词异字现象","abstract":"记录汉语的汉字系统,普遍存在着同词异字的现象,其中有共时的,也有历时的。就历时的同词异字而言,表现为不同历史时期可用不同的字(区别字、异体字、假借字等)来记录同一个词。本文在归纳出西周金文本身存在的同词异字的基础上,在将西周金文用字与现行汉字系统作对比,以观察历时的同词异字现象。","categories":["02_字词句考释"],"year":2007,"publication":"乐山师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYT1qERu1JLH9VLddVDevtfV3_Xu60ab0tsVgW8a6wnrPdrX6bdLimtbKUFQsuQ6eqnf9qyPKZDK66Cxp10WQLHZ-94UQQ-vR95bKNsam_YfVDSOI1lbG6BCu_ug1AuBDD-X9-r6T2xqIN0zeufkxL7d8Jc1__icRUtrEnYNWLCg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-74","volume":""},{"id":5657,"author":"蔡运章","title":"战国成君鼎铭及其相关问题","abstract":"洛阳发现战国晚期的成君鼎,作器者&quot;成君&quot;与《战国策》、《史记》所载周报王时的&quot;成君&quot;当是一人。鼎铭筮数《剥》卦是商周互体卦的珍贵资料.也是我国古代&quot;制器尚像&quot;习俗的产物。","categories":["02_字词句考释"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6xx9xYOV9NT9qJXcBU5HMBbNiNO4bdBaWzNTiCPax51RL879Khxz5zITn3uXZLWMfUkkZTualZpianXHEdjvoAjRpqYKRcy90Vz8fpiiC9u4_9A6ImGiJm_as0hbeN3x2vinDXPqIGqR4T3Gl06YXD-VpHyw0JH9IPu3nCLBzIQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-48, 65","volume":""},{"id":5662,"author":"师玉梅","title":"西周金文形声字的形成及构形特点考察","abstract":"本文通过对西周金文形声字的全面考察,得出了西周金文形声字的主要形成方式有增加义符、增加声符、形声相益、变形声化四种;构形上具有声符、义符位置不固定、形体不固定、数量不固定等特点,这些为认识早期形声字的面貌及理解后世形声字声符兼义现象提供了帮助。","categories":["02_字词句考释"],"year":2007,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2007.02.016","pages":"128-134","volume":""},{"id":5664,"author":"武振玉","title":"两周金文中“乃”字的词性和用法","abstract":"两周金文中&quot;乃&quot;字有代词和连词两种词性,代词&quot;乃&quot;主要用为人称代词,个别时候用为指示代词;连词&quot;乃&quot;主要表示承接关系,偶尔表示假设关系。对两周金文中&quot;乃&quot;字词性和用法的调查可以帮助人们了解其在上古汉语早期的应用情况,亦可为针对传世文献的相关研究提供重要的语料和有益的补证,弥补传世文献的不足。","categories":["02_字词句考释"],"year":2007,"publication":"延边大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16154/j.cnki.cn22-1025/c.2007.03.025","pages":"82-85","volume":""},{"id":5666,"author":"王晶","title":"卌三年来鼎铭中的“历人”即《周礼》中的“校人”","abstract":"新出土的卌三年来鼎铭中王命来“官司历人”,通过与传世文献的对比研究,我们发现“历人”即《周礼》中的“校人”。","categories":["02_字词句考释"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9gn1dZKMUqEyz_6Bn_oBiKYFyI2pEU8DIQyWYdGv_mT6zzjAJM-jOwyBU__XcCjIPI79JKnT0olVAMmVIb2LwzOaT3TYaiGBgp7InkKpAA7WdZSGXeFocS1zQtSRpP_tFQKqLJREb3qCr51cqrnW79AukfaGF9wMD9ftKTP9FQA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-52, 63","volume":""},{"id":5667,"author":"徐秀兵","title":"两周金文中“■”字的构意新解","abstract":"文章在前辈学者对“眉寿”的词义训释的基础上,运用构形系统分析法,对两周金文中的“■”字的构意进行了新的说解,认为“■”字是与后世传世文献中记录“眉寿”义的“眉”字记词功能相同的一个义音合成的异构字,但它打下了两周青铜文化的烙印,具有鲜明的时代特征。","categories":["02_字词句考释"],"year":2007,"publication":"成都大学学报（教育科学版）","link":"https://link.cnki.net/doi/10.13627/j.cnki.cdjy.2007.06.038","pages":"108-109","volume":""},{"id":5671,"author":"徐力","title":"春秋金文量词考析","abstract":"在对出土古文字的研究中,历来都是文字字形的研究重于相应词汇的研究。基于《春秋金文语料数据库》,在对现有春秋金文(可识部分)进行穷尽性的调查之后,离析出其中的量词,就其使用状况加以全面观照,并进行分类分析,归纳出其语法功能与语义特征,以显示量词这一词类在春秋时期的发展脉络,以及在先秦出土文字词汇发展中的重要地位。","categories":["02_字词句考释"],"year":2007,"publication":"浙江海洋学院学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKVTee1pSt_Jyn3P_Ox2Py6mwtmpEqkYm6A0laitffCAIuKVh8pVokFydmIERkn7QOozF7GIbfhYF2aaAIBv44WVX0IZVV4YRrKa1wzz_m80CwsCpYzf9M-7rxwBtaIdUIyHTdU6K0t8pCkv58F362PgSZ4OyRabiw9HqrT2RY3mg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-42","volume":""},{"id":5672,"author":"连劭名","title":"西周金文中的“眉敖”","abstract":"近读中国社会科学院考古研究所编《殷周金文集成》(以下简称《集成》),发现西周金文中的“眉敖”就是我国古代西南少数民族中的“微”,曾参加周武王领导的牧野之战,是著名的“牧誓八国”之一。西周青铜器《归芻簋》铭文云:唯五九月甲寅,王命益公征眉敖。益公至,","categories":["02_字词句考释"],"year":2007,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJI1yD1hW-XRL9KPL58gzUBCZMuWyjmXLC3oUNCwQVxRer4z4nVNxGM5LrJNJiPoNKRod2TwpjfGdtMP-VTmV9RNR6oT2AYZZtJtdIs_Xdlt2oJRgo37ugTfDAUwbdESEi0RsE8_bO6h9ch7-guuvNrca4dl7Ywji6EJmQhhZTNfA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66","volume":""},{"id":5673,"author":"张和平","title":"说“■”","abstract":"“中”字金文或作“■”。一般认为,“■”字写法有误,当作“■”,取旗帜之象,因为上古有立旗(即“立中”)聚众之传统。学界的这一普遍看法其实是错误的,因为通过对古代神话文本与哲学文本的综合分析,并结合对“中”字得以构形的经验原型的具体考察,便不难发现,“中”字在上古除了取象于旗帜之外,还取象于“旋转”,而这恰与金文中“中”作“■”形是相吻合的。“中”字之所以在取象于旗帜之外,复取象于“旋转”,这与它内含“世界本原”之意蕴有关。","categories":["02_字词句考释"],"year":2007,"publication":"厦门大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKjQYNQORoxJJk3rQSvQBifk3rpr-CNFM3NVhx81_eubWEsBOAlGsKCyOmyAQBFrn5pWkhayfMee-kbmE25ob3i3lqHEOD1bUD7lk879J6i_AAYcQALqr2r7rROOvSeo0hmy-EfcrO1298DsP6GIozqW-MGUlj3mu-7TgojNvCZQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-106","volume":""},{"id":5674,"author":"杨州","title":"金文“品”及“祼玉三品”梳析","abstract":"“品”字在商末、西周金文中用为量词,表示事物的种类。由此可以肯定《鲜盘》中的“祼玉三品”当指三种祼礼用玉。根据学界对“瓒”研究的最新成果,作者认为商末《子黄尊》中“黄瓒”应是祼礼用的玉“璜”,这种解释能为“祼玉三品”含义的正确理解提供新的思路。","categories":["02_字词句考释"],"year":2007,"publication":"山西师大学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLN10Js_9NOKDxXIhU4HzZwQ4vnyzY80RiGuz9FOeyjzhq4NI1oVQ4usAfcAwETAK-tCQk_MxczJ-DT0zNBEv9R5C0zap1xpzbB5TtLo1kHe7Ja0nHujyz3O0xbTWienS6MiHY4c5uNqIKYRzZFeXVD9F9u5E2IXennSD8X8tO9Yg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"130-132","volume":""},{"id":5676,"author":"武振玉","title":"两周金文“及”字用法试论","abstract":"“及”是古汉语中一个重要的兼类词,它兼有动词、介词、连词三种词性,探讨其词义演变规律对了解汉语实词虚化问题具有一定的参考作用,而探明其早期应用情况尤其如此。两周金文所代表的正是古代汉语早期的情况,其中“及”字的应用很具代表性:一是其三种词性并现,二是在出现时间上表现出较为明显的层次性。","categories":["02_字词句考释"],"year":2007,"publication":"东北师大学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16164/j.cnki.22-1062/c.2007.03.026","pages":"151-154","volume":""},{"id":5677,"author":"秦坚","title":"商代简牍文字刍议","abstract":"商代是汉字的成熟期。在商代汉字的三种字体中,简牍文字是核心字体,其风格面貌决定了汉字形体的基本特征;甲骨文、金文、陶文是软笔书写为特征的简牍文字在不同书写载体上的特殊形态。对简牍文字的研究有助于认识文字在商代社会文化中的作用,从而进一步了解汉字形体发展线索。","categories":["02_字词句考释"],"year":2007,"publication":"乌鲁木齐成人教育学院学报","link":"https://link.cnki.net/doi/10.16455/j.cnki.65-1281/g4.2007.02.012","pages":"40-43","volume":""},{"id":5681,"author":"程鹏万","title":"■半灷量新考","abstract":"本文对现藏中国国家博物馆的■半灷量器上的铭文重新考释,认为量铭&quot;半灷&quot;当读为&quot;半寸&quot;,半寸即半立方寸,为此量的容积。","categories":["02_字词句考释"],"year":2007,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPtkEsR3gsKEXKiNeLjsgGtEbN_qoJd71RCf01mf9qLx0Nexi4gSunfT7N3-Tr2JkuyB-j2CdTp9A-zZzjSdC-DH1TP1L-d6DjFYpXVKPFn7IVZd8TTHmmwFVkUdNZgY1ViAAiTmpwmnkMUyukHFjA0fk0ZiWNwmDPq21f6vZONQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-78","volume":""},{"id":5682,"author":"吴镇烽","title":"■鼎铭文考释","abstract":"1995年6月的一天,陕西省咸阳市渭城公安分局文物派出所收缴了一批文物,邀请省文物鉴定委员会派员鉴定,侯养民、呼林贵、王翰章、禚振西、刘合心和我等委员前往咸阳,对这批文物作了认真的鉴定。","categories":["02_字词句考释"],"year":2007,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_ijAOLM8kyGLp9yy3yQfP1AMA6XrMyPB_roSbQb2C15-D6q8YxrC7aeCjDTm55BisJw-R2K8a4FssO9JbohuTs0VSZXlzggfFRHTKtog_h7KwrXz0_3wnwMfzhOzkVbE-27Pj3LOxXD86NXTy8GMhP7y2SZI4s_5Mf7pF2E1G-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-19","volume":""},{"id":5685,"author":"王晶","title":"西周金文“讯”字解","abstract":"通过对西周铭文资料的整理和研究,我们认识到“讯”字在西周金文中作名词时,当“生俘”讲;作动词时,当“问”讲,又根据文例而译成“审问”或“询问”。","categories":["02_字词句考释"],"year":2007,"publication":"西南民族大学学报（人文社科版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtWw8sYCZF9BE1ZCdaYeiXljbZfpsgIYBQOIPRsSMRpbb1F7SKW_8t-XxMEYhBxgovJwu44kXzlJv8_GX7ypYzVT8Q35v7rnGsp1Wy4eEFGhBxtXczTd7YfBqCAKOh-4-Ku_dwNZxuyQmffAPOtqfdrloDIFz6bQHJZl020yOqHA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"206-207","volume":""},{"id":5690,"author":"徐山","title":"释“器”","abstract":"文章分析了“器”字的金文形体,其形体为犬从的会意字,表示犬吠之义。“器”一词在造字时采用了和本义相关的事件来表现。因为是有价值的器物,所以器物拥有者便养犬来看守,如遇外面生人接近或图谋不轨,则家犬就会狂吠。《说文》对“器”的形体分析不确。","categories":["02_字词句考释"],"year":2007,"publication":"黄石理工学院学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLObyzOkiQAKqLpT9C6qK5cFdNvDwWicQOEFHALmKnIwbUqz7DHuIrjY2KIxIXhsGHq_Pe-Zq9_f41Syq1KaWiS-iXuiGgrSrWaNdAb3EaU2HEpmSl6In4Z7Kk-JNyau4stQ6QFeuW2qxUvvmH-NdVr-lgL5Prp2qidSA2KwrLjEA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-44","volume":""},{"id":5691,"author":"董珊","title":"“弌日”解","abstract":"2001年3月,湖北郧县五峰乡肖家河村发现一座春秋墓,在出土的随葬器物中,铜盘、(?)的铭文有历日“唯正月成辛亥”、“唯正月成已未”。有学者已将这两个历日跟传世春秋齐器国差(缶詹)铭“国差立事岁成丁亥”(《殷周金文集成》10361,以下简称“《集成》”)相联系。不久,又看到李学勤先生指出郧县铜器历日“正月”等同于“正”,即“夏正”的意思。","categories":["02_字词句考释"],"year":2007,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2007.03.008","pages":"58-61","volume":""},{"id":5692,"author":"武振玉","title":"两周金文中连词“则”的用法研究","abstract":"“则”是古汉语中一个常用的虚词,然关于其词性、始见时间、具体用法等都还存在着下同程度的分歧。过去或认为连词“则”甲骨文中已见,但今天多数人已不同意这一看法。作为连词“则”应始见于两周金文中,其在两周金文中的用法代表了它早期的应用情况,对汉语史研究具有参考价值。两周金文中的虚词“则”均当视为承接连词,具体则有出现干具有顺承语义关系的语句中帮助表示时间上的承接、出现于假设复句中帮助表示事理上的承接、出现于具有对比关系的复句中帮助表示对待关系三种不同用法。","categories":["02_字词句考释"],"year":2007,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMKAJe7T_ZMlxv8Y1OFX-6IIpwuEPRh0cu4Sx-DLqIdY3C33Nuv_nPgEZFOczNVvBg74iN3KjHOwxcZpFMmMzhOS20WQwCwn6ww2PHAqQrB5z2UAPhTkrH2xUoM-3J3WlDhljnvnW-S79_jMs9_xIWHyRG2P1X8FLsJ1bQxhxOUw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-64","volume":""},{"id":5695,"author":"张素凤; 孙文莲","title":"论古汉字构形变化的规律","abstract":"“汉字构形学”是王宁创建的理论体系,它适合于分析各类汉字的构形模式,便于对不同形制的汉字进行比较。本文以汉字构形学理论为指导,利用计算机数据库技术,对古汉字构形变化做从定量到定性的研究,总结出汉字构形在古文字阶段的变化规律义化、音化、记号化。","categories":["02_字词句考释"],"year":2007,"publication":"河北学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfECRznnqvfE5OrDlsmfCHktFSavDA7YWBmZcITkObydNgr8Luh4kQ3LuyOj5ijbhpVcDYM5wNBKk6qete4j-Jfj4HNEBikBRgJOgXYkcGuuu-HU9QmZtlVfd2wFVtu4ndh4AmWqIBSlwe4HVg1u_vaFmjpDVboENFmAm4lNj-Wg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"206-209","volume":""},{"id":5696,"author":"张世超","title":"“肘”“肱”考辨","abstract":"文章结合新发现的文字材料,对甲骨文中与“肘”“肱”二字有关的字形材料和研究成果进行了梳理,纠正了错误的释法,并从语源上探讨了“肱”字的来源。","categories":["02_字词句考释"],"year":2007,"publication":"山西大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13451/j.cnki.shanxi.univ(phil.soc.).2007.02.015","pages":"73-74","volume":""},{"id":5697,"author":"吴红松","title":"西周金文考释二则","abstract":"本文在吸取前人说法的基础上,结合古文献的记载,从文字学角度对西周铜器铭文中的“■”■、“■”二字重新进行考释;认为“■”■仍释为“雍”,但应指枲麻,是明确古代服饰“巿”的质地之词;“■”即古文献中的“裼”字,指裼衣。后者在金文记载的服饰中为首见。此外,本文还对这些服饰所涉及的西周社会制度略作论述。","categories":["02_字词句考释"],"year":2007,"publication":"安徽农业大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19747/j.cnki.1009-2463.2007.02.028","pages":"108-111","volume":""},{"id":5698,"author":"张再兴","title":"金文构件形体的演变——基于字形属性库的类型学研究","abstract":"构件是文字系统中最本质、最底层的要素。在金文悠久的历史中,金文构件的形体变化有着明显的时代特征。本文探讨在金文字形属性库的支持下,研究金文构件形体的发展演变过程所关涉的方法、价值等若干问题。","categories":["02_字词句考释"],"year":2007,"publication":"华东师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16382/j.cnki.1000-5579.2007.02.010","pages":"57-61","volume":""},{"id":5699,"author":"李刚","title":"战国铜器铭文“厨”字论略","abstract":"战国时期的铜器铭文中有“厨”字,由于国别不同其写法也不同,不同写法可以作为判定铜器国别的标准。“厨”是当时的一种职官,其职掌可以通过铜器铭文略知,它是负责制造铜器的机构。","categories":["02_字词句考释"],"year":2007,"publication":"沈阳师范大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19496/j.cnki.ssxb.2007.02.043","pages":"165-167","volume":""},{"id":5700,"author":"李丰娟","title":"“無”形体考","abstract":"关于“無”的字形演变,历代学者都有不同的看法,笔者试图通过甲骨文、金文、简帛、碑刻等出土文献的文字资料,从字形、字义上对“無”追根溯源,期望能理出它的脉络,还“無”一个真实的面貌．","categories":["02_字词句考释"],"year":2007,"publication":"四川职业技术学院学报","link":"https://link.cnki.net/doi/10.13974/j.cnki.51-1645/z.2007.01.019","pages":"50-51","volume":""},{"id":5702,"author":"白冰","title":"论金文军礼系列字","abstract":"军礼是与军事有关的礼仪形式,是军队的行为规范和行动准则。金文中禾、秝、和、休4字与军门有关,追、取、聝三字与军战有关,穎、師2字与军祀有关。对上述9字的字形应作新的分析,对字义也应有新的解释,以冀澄清一些金文的初形、初义,纠正《说文解字》的某些疏失和此前研究的某些不足。","categories":["02_字词句考释"],"year":2007,"publication":"五邑大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEaBVUvvL6kts-PdsYr6YO1pocTW7qXPokoz8EozXTsA1sEtp0GQiIrP4qqux6eVO2Crq3neCs3tsXGi7M2SeFrueUR5e7qBFzW3P04Dcl49iOFPglN-A2LTC0KvFA_yg6_RD_6KPHsHNHMPbey7-1cnrcX5-B27qgYSE5ZjiAIg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-87","volume":""},{"id":5703,"author":"范常喜","title":"“曾姬无卹壶”器名补说","abstract":"“曾姬无卹壶”于上世纪30年代,出土于安徽寿县朱家集楚王墓中,共有两件。其形制为方口,有盖,盖有四“S”形纽,长颈,垂腹,方圈足。颈部附两虎形","categories":["02_字词句考释"],"year":2007,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxkvZ_YEjs74zY8MzzpV6kB0fc68yldVgZ0eEHZk4PDD0xplhhk39J6EvoclQVkB524o5Mr0fqc7bGf3twiA4iXzLTvfvCDCC1XtoRIIUWL2MAFpQ5u7-u-YUmKMfLxl9NTMmjkeQmhCh0pKdgBRhW8KMI54A45Y3AsSJME1YPpA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-85, 142","volume":""},{"id":5705,"author":"何琳仪","title":"鱼颠匕补释——兼说昆夷","abstract":"1923年在山西浑源李峪村出土了一件青铜匕铭文。新释“贻”,训“赠送”。新释“(虫虫)”,读“昆尸”。以李峪村另一件铜匕勺部、柄部交界之处的鱼形图案,印证此鱼颠匕铭文“述玉鱼颠”。新释“■”,训“复”。疏理“昆尸”诸多异称之间的音变关系,揭示其与鱼颠匕铭文的内在联系。援引“匈奴相邦”玺,推测鱼颠匕是代王赠送给匈奴的礼品。","categories":["02_字词句考释"],"year":2007,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIm7Fkkvb1ompFghUxVqX6va6b2eyRzY3Jtppj2XPtG7ahaiAv958MaGC_PwtSIWR2E67eFqB9bQKNMGkpeK0NCZdlXitIcZ6JF0Ucy8Z4Qe67_VGERwFAJyrnRehXHzqPpQ1kSqqJYsEsVDsiKETaXXrwgrAzCSC8GI0IOpAG0dQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-39","volume":""},{"id":5708,"author":"武振玉","title":"两周金文指代词“是”“兹”“之”用法之别","abstract":"“是”“兹”“之”是古汉语中最早出现的近指代词。“兹”“之”甲骨文中已见,“是”始见于西周金文中。甲骨文中“兹”“之”已表现出句法功能上的对立性,两周金文中,加上新出现的“是”,三者形成了严格的句法功能上的互补关系,即“是”主要充当前置宾语和复指前置宾语,“兹”主要充当定语,“之”主要充当一般宾语。与传世文献相比,两周金文在指代词的使用上存在着较为严格的“格位”倾向。","categories":["02_字词句考释"],"year":2007,"publication":"长春大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHCL2msu-LC3IwZWqInfnIx2iqUaAJ2tTbTlxUSzQbDQARm86mCxjSTQqt9sGN13FXd0HnbV7f7YOY4CISVeowN6kfBsKPbVRC9bShHg84ePw8QE01EnpRd8i5rKXm4JRVG-qnlu5xa_pwsZsc_Aq530wM5BV_Ho8nm5YyU1GawQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-43","volume":""},{"id":5709,"author":"俞绍宏","title":"说“才”","abstract":"汉字中的“才”字构字本义尚无定论。本文分析“才”字字形,把它与相关字如“余”、“舍”等相比较,认为“才”是“材”的初文,“材”是“才”的后起乳化字；“才”本表示房屋的一种支架。","categories":["02_字词句考释"],"year":2007,"publication":"巢湖学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEC2e9h_Ir-kF9k4vYAck4P8S6rNJgK0E8L86Xd-SuzJ1E4iptGnQ1JCSmHZOf8NlNsaGrYRo_gPvwgnOUM3ly_A90EGpB2WnF8D_gVolJnyUHDdWSrhx6ngM7r-e4GqETQoMpPn1wQjyVMjHi9High7dFVo4LI_57sedPDT2EhQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"162-164","volume":""},{"id":5711,"author":"何琳仪; 高玉平","title":"唐子仲濒儿匜铭文补释","abstract":" 2001年,在湖北省郧县五峰乡肖家河村出土一批青铜器,属春秋中期。黄旭初、黄凤春的《湖北郧县新出唐国铜器铭文考释》(下文简称《考释》),对其中有铭的盘、叵、鈚予以考证。不但确定铜器的国别,而且讨论铭文的内容,其中颇多精义。本文仅就叵铭补充两点不太成熟的意见,以供学界参","categories":["02_字词句考释"],"year":2007,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqK4O5YaX8gP1r1yg2mqjRdxYmnr9F3KGXJ9SFsvqf5V0lEiWOxDd1wvEPqDuRczXmkkJvYYMikC1c4P0K1J1JpvTln00X3GYTSsyD1-nNNwfNFamMvMlo4zqKGvQGjMHkNsiPNTEHYg2nRqBFhno7Bd-pv8kMT4FXj0xhzmXrjw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-69","volume":""},{"id":6469,"author":"刘影; 陈双新","title":"两周金文先王先祖修饰语及相关问题研究","abstract":"本文将修饰语作为一个词类来探讨。这个修饰语词类以两周先王先祖称谓,如王、祖、考、妣、母、父等为修饰对象,主要出现在追孝与颂扬先祖的铭文中。这些修饰语主要分作三大类：第一类为单音节修饰语,如文、皇、穆、烈、圣、帝、幽、光等；第二类为双音节修饰语,这类修饰语主要出自《墙盘铭文》,如(?)圉、(?)圣、宖鲁、祗(?)、青幽、(?)明等,另外还有诸如丕显、丕(?)、(?)等双音节修饰语；第三类多音节修饰语,多可作句子的谓语,如遽(?)、穆穆(穆穆翼翼)、克哲氒德、德屯无谏(敃)、(?)等。通过对铭文中的修饰语进行解释,兼及相关文字释读及通篇铭文的解释。同时阐释与修饰语相关的若干问题,如西周谥号问题及修","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhv91XOWtre4cgD5lmgfPpPvZStTrB-JPbd6T5IRTrWXp58s97TX7wNCeQWQQaEDKfIxO48s2xFsj_mUOipOBQkSzdq99whhxEUKdUegP_vflN7LNUpMn705x16YP32-gOzuklFcdiN7aPlfCPLcBEnFCLvy7g4Rpk2f_s3KDm2amup5iZhJE5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6470,"author":"魏常春; 陈双新","title":"两周金文形声字发展探析","abstract":"本文以容庚先生《金文编》为依托,参考董莲池先生《金文编校补》等著作,同时查阅近些年出土的金文资料,对两周金文形声字作了一次系统的梳理,得到金文形声字1114个。然后将其分为西周前期、西周后期、春秋、战国四个时期,形成两周金文形声字表。以此表为基本资料来进行研究,以发现两周金文形声字发展演变的规律,需要说明的是,本文并不着意于单字的分析,而是从总体上进行考察。论文可分为三部分,第一章是形声字的发展方式,我们归纳出了九种,分别是加注义符,加注声符,累增义符,累增声符,改换义符,改换声符,变形义符,变形声符,形声相益。每类之下,例字说明。第二章是义符系统、声符系统的发展考察。对义符系统进行考察时,主","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmyLS2Wny8T7QMUFKYabhp90qxDJJ1jSmbETbzcYCAD3JvzjQBMeXMN8KkFpuT3yswwPkVp53ldbF355NpGf120VONAEFxPqc7181MHc3lhvysbJITbEmTIoUXoBF42cgo63EcDjqPJOu1JYFEN3upqMLJjSpX9AKG40d0CXfyJS630ioOnlK6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6472,"author":"包诗林; 白兆麟","title":"于省吾《新证》训诂研究","abstract":"于省吾先生的系列《新证》，在二十世纪训诂学甚至整个训诂学史上都占有很重要的地位，但目前学界对此还缺乏具体而系统的专门研究。本文以于省吾先生的15部秦汉古书的《新证》为研究对象，考察其训诂体式、内容以及方法，并评判其在训诂学方面的成就与局限。《新证》属于考证札记体，涉及经书、子书等秦汉典籍15种，总共42卷，2309条(2518个句例)，其中考释类2046例，校勘类480例。考释类中分驳非、证是、直接考释、释疑和存疑类，校勘包括校正文和校注文两类。本文重点研究考释类的2046例。《新证》的训诂内容有三个方面：一是对于旧注的考察，二是对于词句的考释，三是对于古书文字的校勘。本文从哲学观念、逻辑方法","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL64A3ZeYjmGtDZKQOvY9QCvc5RXfTCit0_e3eWocfqgNB0ZLg7CeQZqHrkLS8yqYZCWMod9n1wMHtHMRwKMxPuG4YSPNZP3gBoDBOZXdvQwjbVMslmIwDww_2g-vSrHKKt6pcLq-QQrTMOF1FqQL4E1Q5V0F1O2CmmOmnSqZfMyoZev_zNf3BK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6477,"author":"杨州; 黄天樹","title":"甲骨金文中所见“玉”资料的初步研究","abstract":"商周時期是古玉發展的一個高峰,也是玉禮形成和發展的重要階段。本文對殷代甲骨文、殷周金文中與“玉”有關的資料進行系统的整理和較爲全面的剖析,進而就资料所見的用玉制度以及其他問题加以探討,以期拓展和推進商周(主要是殷代和西周)古玉及其相關禮制的研究。绪論中交代本题意義、研究方法等,並對前人相關的研究成果加以述評。本文主體以商、周分爲上下兩编,全文共設六章。第一章聯■殷器《亞■作祖丁簋》,對甲文中“玉”字進行了辨析;整理了甲骨文、商代金文中所見“玉”的卜辭铭文,亚就材料所見商代玉器的贡纳以及加工等問题進行了討論。第二章對玉類(如瑞、琮、璧、琡、玉壴、珥、琅、■、玗、瓒、磬等)的相關资料進行了歸納和剖","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgDlYS1LBLe4dGh4zTAZws6gS7y-r75-5iee6UyAChVvqs4dK-S9HDpZM8beZYIA_X9q_PNXrE7KB4EwUjRJ3CigOqiSi8WLq0qTCjnbZzyDOYA7KhzuDND4xYvtz914aY2lduusWyq2L7dyhRAqByXmMrIo_M4FhHtGYdLQgQbsYDA6bQQYzq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6479,"author":"田河; 吴振武","title":"出土战国遣册所记名物分类汇释","abstract":"遣冊一般認為是古人在喪葬活動中用來記錄隋葬物品的簡牘。上世紀五十年代迄今，考古工作者已發現十四批戰國時期的遣册，正式公佈的有七批，即：五里牌遣冊、仰天湖遣冊、信陽遣册、望山遣册、包山遣册、曾侯乙墓遣冊、曹家崗遣册。遣冊記錄的内容主要是車馬器、飲食器、樂器、武器、食品、服飾等随葬物品的數量和名稱。這些記錄對研究古器物命名、喪葬禮俗、名物制度具有很高的學術價值。本文以上述七批戰國遣册為研究對象，結合古文字學、考古學、名物學相關知識，采用分類研究的方法，對遣册所記名物依其功能分為食器、酒器、水器、樂器、車馬、旗幟、武具、服飾、几席、食品、雜物等十一個門類，分類加以整理。每條名物下面我們先收錄學界已有","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKO__fdYeteKg7guNTQIQgsYDa6KAYihplnVMZPyireUBFlMvLbuGcqtyauEqbpHqUJB8L3R-8O4FX3eI5FSjiiQsvC0Eq5tyFPPrg79TmOdMYrE3kkuIeUSAnVmZyiP9NSkpuxFG40EkDmEdpV_8xtYiJFvVqRzaXMV_G3mb-KAqsOsLtkwSCE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6481,"author":"王晓鹏; 杨端志","title":"甲骨刻辞义位归纳研究","abstract":"甲骨刻辞义位归纳是对甲骨刻辞中的义位变体进行周遍考察，概括、归并和划分义位的全部过程，是甲骨词汇语义研究的初步工作，也是基础工作。甲骨刻辞义位归纳研究则是对刻辞义位的性质、义位归纳的语义分析基础，以及义位归纳的原则、方法、特色和分类描写等问题所做的研究。本文着重从理论上探讨了甲骨刻辞义位归纳问题，并对已归纳的义位进行分类描写。论文主要内容如下：第一章“引论”，简要介绍课题研究目标和意义。对语料性质、时限、字数和选取使用等情况略做说明。阐述研究方法。第二章“甲骨刻辞义位”，界说甲骨刻辞义位，讨论义位与义项的区别，义位与词位的关系，以及刻辞义位的特性和甲骨刻辞词义系统的性质等问题。在归纳甲骨刻辞义","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlLqsC3NP1CjhVNRtv08_tuJC421gKYpgNWqpQ6vib6Zqc-ZkDuugfRDUNY5sXyKFe1cPKu63CLC0Hx4Qn45YL6-UswPygGHgsVEXgnlC8z4SOx9haovJg9yJWpiIKssqnNZy3onHgbFm9tkguvJeJ8CoVuTjLvhrXWa9d1_Ml9fBOv3Jn35-9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6820,"author":"杨建淼; 陆锡兴","title":"战国文字讹变现象初探","abstract":"本文以戰國文字的訛變現象為研究對象。在對戰國文字研究和文字訛變研究的基礎上,劃分了戰國文字訛變的主要類型,分析了造成戰國文字訛變的原因及訛變產生的主要影響,闡明了戰國文字的訛變與漢字發展演變的一般規律間的關係,探討了研究戰國文字訛變現象的實踐意義,以獲得對戰國文字訛變現象較為全面深入的認識。全文共分三章。第一章,介紹戰國文字的研究概況,重點介紹了戰國文字的分類和分域研究、戰國文字的形體研究,並界定了戰國文字的範圍。第二章,介紹了文字訛變的研究概況,界定了訛變的概念,並概括了戰國文字訛變的一些主要類型,闡明了對訛變的認識。第三章,從戰國文字承襲和自身之訛兩個角度探討了戰國文字訛變的主要類型:形近","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIdQ6i7aLSPtVs5V9tLHUxs0E8WvPO62QBq7__NdBm6ciHp4RyGhHhxjHMk83RyzdlSHYi9QlN2CajqeeDrIuYV-48JWLcMq9Zl3YhoUstZkI6fSevFSShoj9UfKY3qp0m3YUbt7aOKuulrGP8AY3Jglyrp_gWdnTzPllGExjTAPmazuZC2Z7WA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6828,"author":"吴艳娜; 张桂光","title":"金文常用双音词释义","abstract":"金文中双音词的正确释读，对金文以至整个古文字学的研究都有着重要意义。针对以往这一块的研究呈零散化、考释证据单一等缺陷与不足，我们搜集、筛选了近150个金文双音词并对其进行释义。为保证考释工作的系统性，我们首先从词性的角度进行分类，将金文中的双音词分为名词、动词、形容词、副词、虚词几大类别，之后在各类词下又按照内容进行二度整理划分，如分为祝嘏类，战争类等。为使词语的释读更加贴近原意，在具体考释过程中尽可能坚持二重证据法，兼顾典籍和出土文献两个方面。在整理、释义的过程中，除了吸收前辈的成果外，也有一些自己的发现和心得，如释“虩虩”为“显盛威武貌”，发现战争类中的“广伐”、“宕伐”等实际上是融入了周","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-dXMqhOynec-MFm_jpT-efW7WsBWwwxp1pzGApg1CqQSpR6BUwrOZ_EzoWJxrUZy8t7R__AnsU_2ZtuTKOcm5h-WFcxbVOwr9BLWVtv_LT_paN6nVSyjxoWGn3sF0EWl3IR26xpE50NSc54QoF09-DJKtWdlHhqtKIsNCMwBxZPM-GDhy9lZN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6832,"author":"徐力; 刘志基","title":"春秋金文词汇系统研究","abstract":"春秋金文處於金文這種出土文獻語料存在歷史時期的中後期，經歷了殷商和西周時期的發展，春秋金文材料無論是從文字系統還是從語言詞彙系統都趨向於成熟，同時，春秋時期作為中國歷史上一個特殊的轉型期，在政治、經濟、文化等多方面都有重大的變化。而作為從西周金文到戰國文字的一個過渡時期，春秋金文在語言詞彙上必然對這種變化有最直接的體現，其詞彙系統特徵也值得我們注意和研究。本文以目前已出土的春秋時期所有的青銅器銘文為材料範圍，並輔以同時期相關的傳世文獻材料為印證，依託《金文资料庫》等一手资料资料庫平臺，以數理統計的方法，對於春秋金文的語料進行窮盡性分析和研究，在此基礎上完成春秋金文詞彙系統，這一特定斷代時期内的","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIWaEW-GCgKfcCGzB5Gz930SrvZ3OqMNuZV41sORpcpUzh32stXwCbOFD-m_KzOe7XDil4Vb14AshBdcDb8z2jH8cRRukzhi9MVtRPQ57-XgjNHtJU5emKkdJvBW4NPCMu-kd_95MAxUta6eCAWG-i6-hqFB5BFaYi79vyzXKcHeQsis-dc64y&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6833,"author":"何雯霞; 刘志基","title":"西周金文文字系统補论","abstract":"以往傳統古文字研究主要是材料的著錄、整理、考釋,較少關注字形系統。近幾年,學者們逐漸重視起文字本體來,包括西周金文文字系統的研究。但是由於各方面的局限,這些研究佔據的材料不夠全面,且未能深入到構件層面,歷時比較也還欠缺,研究還存在著很大的空間。这就使得西周金文文字系統的再分析成為一種可能和必要。本文從中國社會科學院考古研究所编撰的《殷周金文集成》,中華書局出版的《近出殷周金文集錄》,以及《考古》《文物》《考古與文物》等專業期刊近年新刊論文中整理出文字材料,立足《西周金文文字系統論》的研究基础,以求進一步發展西周金文構形系統研究。本文共分六章。第一章,西周金文字數與字頻研究.主要目的是對已有研究","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIWaEW-GCgKfcCGzB5Gz930SrvZ3OqMNuZV41sORpcpdwrPp1rnx3f3k0QIZvZdWLU9_WlMx8AG6DDyVZhws0AoxTG-2bW2zEs8NgsPnXVoC4gUkeKihtPHvWiam5U3tUATq2VJ4Uf_H0kJsm5UlhqEC08fohoVZL5OveNm91YIS5G1OE4eMXp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6836,"author":"李山川; 张再兴","title":"西周金文虚词系统研究","abstract":"西周金文虛詞既是西周金文詞彙研究的重要内容又是西周金文語法研究的重要内容。對西周金文虛詞的研究有助於對銘文内容的正確解讀。傳統的研究方法往往只著重于從詞性上劃分虛詞的種類：這樣作的好處是能夠比較明確地說明不同虛詞在句中所表現出來的不同搭配情況；不足之處在於忽略了不同詞性的虛詞詞義之間的相互聯繫以及相同詞性虛詞搭配之間的細微差別。本文在具體分析了西周金文虛詞系統研究的必要性和可行性的基礎上，採用系統分類法、定量窮盡性分析法、比較分析法、歷時的分析法、語序分析法等系統研究手段對西周金文的虛詞進行考查。首先將所有西周金文虛詞分為對象虛詞系統、否定虛詞系統、連接虛詞系統、時間虛詞系統、語氣虛詞系統、方","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLY9HQm40KgU2tRQqJYQ7nXwYX8JZ0Zhvd3hu1-AEPbBiJDrarIzldAGa8-wMJ3HacnzFfEa2HhduK_dTr5x2MCJJzxkYjLs4pa-ZxGIoQeqKFvn-W-ms-QQPjf0MabjLOVcWKUd30MXzonf5aBPKXA1ZgG_XLkqA7688OU9maZxOzTFaqWZGNF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6837,"author":"苗利娟; 王蕴智","title":"河南出土商代金文的初步整理与研究","abstract":"本文在全面收集商代有铭铜器的基础上，运用殷墟考古学文化分期理论，对河南出土商代金文，尤其是建国后科学发掘所得的铜器铭文进行了初步整理。在整理工作的基础上，对商代金文字形进行梳理，共计归纳单字1291字，重文1、合文39字。同时，文中还尝试对族徽文字的书写风格进行论述，对部分商代金文及相关器名作了考订工作。最后，本文结合相关甲骨卜辞、陶文及西周金文材料，对部分出土于河南的常见族徽文字如“戈”、“(?)”、“(?)”、“(?)”、“息”等进行了必要的探讨。","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUlDeYjvat7GvL9HnDCUrwor6HCLArEhyNuiG6tWG220mshB_mm70LzhU86gpYcetvFOrM2Stpf9lhi_qDf8lUUst64p5HzSyXoCHfzyduVWbPLzMUtWeC-KaQ2YuDpHiHo7XlAgOVw-Fgh5_61IDEP5ocUCludoS64wDvJyJOxkH8_lzCUJxx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6838,"author":"彭吉思; 张桂光","title":"战国燕系文字地域特征研究","abstract":"战国文字不同于商代和西周的文字资料，不仅存在断代的问题，还有分域研究这个重点问题需要关注。由于春秋战国时期特殊的历史环境，使得文字的发展也随着国别和地域的不同呈现出各种差异。1989年何琳仪先生的《战国文字通论》以地区为单位将战国文字分为齐系文字、燕系文字、晋系文字、楚系文字和秦系文字五个大系。以古文字学的眼光，即主要以文字自身所体现的点画、结构、款式、风格诸方面的特点，考察战国文字资料，从而辨别其国别，确定其时代。但从冯胜君的《战国燕系古文字综述》来看，尚没有一篇从文字学的角度对燕系文字进行综合性研究的文章，因此展开本课题的研究很有意义。本文以战国时期的燕系文字资料为基础，通过分析单个文字的","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxgKzVDb9-xVnuWsbvsXGNnFadVd1IviTGdGB1RI6mMC_vGPKKJXKd1jaOFq86iuRSLwloF3Z9R4OWIQTiX3nRRBw5DXLlDpI1IsbGEm5wYxgULgnMDqfjKrxWJfUFdS4ZN2HQSCPF-rwcxsdkrf2FFRQvNz4SuofaDUbMqvIoL3ywLtmlgmht&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6839,"author":"王美杰; 张世超","title":"秦駰玉版研究","abstract":"本文共分三部分。第一部分主要介绍秦駰玉版的概况。包括玉版的定名依据、玉版的年代及相关器物研究、玉版的书体风格以及玉版的摹本。其中重点分析关于此玉版有出入的几个小问题:玉版的时代、相关器物研究及玉版的书体风格。第二部分是对玉版文字的集释与考证。先是将研究玉版的材料搜集到一起进行比勘,校正释文的正误,对玉版文字作具体梳理,各家所持观点一致者不作说明,分歧较大者作简要说明并作进一步考证。对于玉版文字中有争议而又不能确定的地方或存疑,或参以己见。第三部分为玉版铭文的再研究。包括玉版铭文的祭祀对象、玉版铭文的性质、用韵情况及铭文的分段情况。通过对玉版铭文的梳理,可以重新全面认识玉版的文字特点,以便得出结","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRyewSrRfLTNYnuKnWjllMpIAxmQnPHFqzcjMUYgQ2mZH3y5-SYgVzLpPTSP81EJ2vo7r8ny-hnJFcDXMiOtoVvvoqDLvG6qEhnZxBwWnS6QRVs4WSyfWPvUAMaJedLjYDDvoe6y1ZwU9BhsgwZ_GkVNmgOLPrlClo5CWfweOooWsUyIcCUibe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6840,"author":"朱晓雪; 吴良宝","title":"陈璋壶及郾王职壶综合研究","abstract":"本文以陈璋壶和郾王职壶为研究对象，对两件铜器的铭文进行了集释，并讨论了一些与陈璋壶、郾王职壶有关的问题。全文拟从两个方面进行论述。其一，铭文集释。其二，我们将铭文所记载的内容与传世文献联系起来，通过文献中的相关记载来研究壶铭中的历史事件和历史人物。在这一部分中，我们还对陈璋壶和郾王职壶的形制、国别、性质以及陈璋壶的容量进行了研究和讨论。","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJGrQbL234SjHsD5zA9KkkdMzAlSonwW8F_mdd9TgZslrY6dF7GVPvHIgSg63NMMrF0li0ypFJUjd4f5NvwFDzU2_zZkPhM1xyEEZ73tsdAnPeLNYiAuFBVN9uQuSleCHLySykZO_jChHDlTNQfxC5xDnmsS1c53eJHRDH-1eZGDHDY2PtHKm4P&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6842,"author":"郑春霞; 郑振峰","title":"西周金文有音合体字考察","abstract":"汉字本体的研究应该以字形为中心,并且在个体考证的基础上探讨其总体规律。本文运用王宁先生的结构——功能分析法对西周金文有音合体字进行考察。确定其可用的材料数量、分析构件的功能、讨论示音构件与所构字音义之间的联系、描述示音构件系统与非示音构件系统包含的内容,并通过与甲骨文和小篆有音合体字的比较,来考察西周金文有音合体字的特点。本文共分成五部分,第一部分绪论,介绍选题缘起,材料的确定,研究现状,研究思路与方法。第二部分对西周金文有音合体字的构件以及结构类型进行分析。第三部分描述示音构件系统,主要是分析示音构件与其所构成的字在音义上的关系。第四部分讨论非示音构件系统,分析表义构件的示意类别与功能分布。","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4h3NcL7Hi_gQHHmlIzxGfPlzHRV9dRLIkMJmPFc428Lrzgo6yypi5y326dn5f4Jh9gI88GN18j0I90iCEmxqAKR_VcNMWRNoqC0nZtfRnOoJ73lA5owySStwhN-JxVxhNCDdMoweEtU37zFIjB_xEpH2SsFM8DVGAkZ5DdrcdjUsBGH2a4Ubw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6843,"author":"洪莉; 刘志基","title":"殷周金文名物词研究","abstract":"殷周時期的文字材料在中國語言文字歷史上是較早的能夠反映社會形態早期語言狀況的文字材料，随著金文資料的豐富和考釋研究的積極開展，為系統地、完整地研究金文名物詞提供了堅實的基礎。本文選擇殷商至戰國時期的金文名物詞為研究對象，以数字平臺为基礎进行窮盡性調查和定量定性分析，研究確定名物詞的數量、構成及發展演變等問題。本文共分五個部分。緒論部分主要談到名物詞研究的現狀，根據現狀選取研究角度，從而確立研究的意義，並提出名物詞的判定標準；第一章主要是概說名物詞的基本情況及其内部意義的考釋說明，分析詞義和類別，提出需要注意的問題。金文中的名物詞共有499個，可分為十五類：舟、玉製禮器、水器、量器、食器、日用品","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQ5s-cRqXufRn3D30tsrSCIC_oNazNnzmRQuN2jMNR6ZhZOF6eaiX5G7QGEfAEJut314Y8BDqB4HVrv3t_TqSWNcWMGHQv3VZZux5NtzwvLcK8kZMz8MwENaJXyH53q_le1y29GLmOhOIrU4ELRASmvav9W3ThbYBahRVpOl44_VrLjZwLBcfm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6844,"author":"陈童; 阚景忠","title":"《名原》研究","abstract":"《名原》是清末著名文字学家孙诒让的遗作，从理论和实践两个方面总结了作者的古文字研究成果。孙诒让写作《名原》的目的是“推书契之初轨”，即将甲骨文、金文、石鼓文等古文字，与《说文解字》收录的小篆、古文、籀文相互比较，总结古汉字发展演变的规律，推求古汉字的原始面貌。《名原·叙录》是全书的理论纲领，全面阐述了孙诒让的文字观。《名原》上卷三篇分别阐述了数字、象形字的产生和演变，下卷四篇除探讨转注字的特点之外，还考释了大量古文奇字，补正了《说文》的失当之处。《古文大小篆沿革表》按照《说文》部首的次序，逐字收录了甲骨文、金文等各种古文字形，可惜已经亡佚。本文以《名原》的内容为线索，以《<名原>古文大小篆沿革","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJod5RkoVjWL_ce8WpOns-CQ2vRB_jneiL5qDBOA8BsV0EhaU04hQnunJ1f8SASynNZ2chHgkQDpMNsu77ekhFNmi24_HUpDZd_xO2D3t0gJJ_xKfwbp7kRmXpZralijhkpNYCVzvvS-nNe5ESG5Xb1UFTUMPasv5rCJllfL3JTM1PG5_EJSsrF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6846,"author":"肖辉; 徐在国","title":"青川木牍辑考","abstract":"1979年青川木牍出土于四川省青川县郝家坪的一座大型战国古墓群。共两件，其中一件已残损不清，不易辨识。另一件，字迹清晰，全文共一百二十一字。青川木牍反映了秦武王二年时执行的一项土地政策，与已有的秦代《田律》有较大不同，是研究战国时期秦国的土地制度和蜀地农业政策的重要实物资料。本文辑录了目前所能见到的有关《为田律》的文章。全文首先对《为田律》中相关诸字进行了考释，列举了各家看法，并在其后附注按语，对各家观点提出评述，分别结合自己理解谈了看法。全文上下共分为五个部分：一、概述；介绍青川木牍的形制、律名、年代及适用范围等。二、文字辑考：分别将藉家考释进行辑录。三、牍文通释：全文今释。四、史学价值：青","categories":["02_字词句考释"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJCXEoZLzOMVHufkTGcb2laYUvDgrnkxZHFkr1EHB_98FwssO0m9Fum-svKlcEjKGgTJLrZ58fbaWumVEO7LAnSRLiONPiio4bEzfrfCgA4n22Mo20xF5ThpM_ENVmlzIiiPMWDdDn1dflvJXU8haq2fcHX379Xi0j2kvv6NkNmeOpO6hsMoCmp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7025,"author":"孟蓬生","title":"说“橹”——兼论“古”字的构形本意","abstract":"商周古文字(甲骨文和金文)中有一个象盾形的字符,其读音众说纷纭,其中较有影响的是&quot;毌&quot;、&quot;盾&quot;两说。本文根据古文字中加&quot;口&quot;作装饰性和区别性偏旁的字符往往与本字读音相同或相近的通则,赞同前人释此字为&quot;橹&quot;的说法,认为这个盾形字符的上古音当与&quot;古&quot;相同,记录的是后代用&quot;橹&quot;字表示的那个语词(一种大盾)。文章认为&quot;古&quot;字的构形本意就是在盾形字符的基础上加了一个装饰性或区别性的&quot;口&quot;旁。《说文解字》解&quot;古&quot;的构形本意为&q","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFfyaBu0qH76nNBM8joa52CEfTaOzuPuk0v3tW5tvHx8UHyHhUDFqkoZ6041zrmDYWjw1LGf8PDxm7UE1VRpnZ5s64koeRVONolCpdzDC_h1n4H5PKomh8_kGucCvmFqSoib_iRr3vo3a-KQzAuu6SqU88pS_h6YYtfE_QkdICmQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-95","volume":""},{"id":7026,"author":"陈英杰","title":"谈金文中■、召、卲、邵等字的意义","abstract":"本文对两周金文中&quot;卲&quot;、&quot;邵&quot;、&quot;召&quot;、&quot;■&quot;等字的字形进行了梳理,对其意义和用法作了穷尽性的归纳和总结。&quot;■&quot;和&quot;召&quot;实际用法不同,字形也没有衍生关系,应作两个字看待,分立字头。&quot;邵&quot;的用法最复杂,除个别例子外,基本对应于文献中的&quot;昭&quot;。其中&quot;卲各&quot;自来没有确释,本文综合金文、文献及故训,认为其义就是向上天或先祖昭明精诚之心或昭明善德,使神来至受享。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKoeFxM4Xu8L5JNXpU3pJg3m_O1ceQC2f8_AcLsWB3U0oehWpHW7xPPQk8RcMooItIiI7LD_lxVd7qwkh9Y71TU5zQee-66tEhxdRgRI-qft_Rrn1raVue7YQua5gnay0IEW6ZHlc7GFPYwhmkiuQn6PUFkY62gVWZyMbKytaVsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-127","volume":""},{"id":7027,"author":"李轶","title":"说“旦”——兼说“庖丁”与“屠牛坦”","abstract":"先秦古文字中&quot;旦&quot;字的构形并非&quot;日出地面&quot;之象,而是从&quot;日&quot;、&quot;丁&quot;声的一个形声字。《庄子·养生主》中的&quot;庖丁&quot;与《管子·制分》中的&quot;屠牛坦&quot;是同一个人。&quot;丁&quot;、&quot;坦&quot;的基本声符相同,是同一个人名的文字异写。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKg4VdspdcgHSo6DFAsJ2G0ZfmdSIoxQkCtry67jdq8xpWwxgXfqrepFyMYfI0wY5vMSYIwBRgNHOB0GvKsN7MiCNbiDkJAfsXhVF6ST4yzsSCjBCLipdqomNiRDyuud3etByfvDsRT3LfMtT8vTCWo6D4Jh-8ov4t8Nocvz5ae9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"134-136, 140","volume":""},{"id":7028,"author":"刘新民","title":"“工”字字源新考","abstract":"&quot;工&quot;字的字源有十种说法,但是每种说法都有其局限性,本文对&quot;工&quot;字的字源进行了新的考释。&quot;工&quot;字最初是从打制土坯的石杵取象,本义表示一种&quot;建筑工具&quot;。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKg4VdspdcgHSo6DFAsJ2G0ZfmdSIoxQkCtry67jdq8xpWwxgXfqrepTntmcRbXwmBRhfGeQlS-rfqyh5uAShNxZrvLZ0olrgXyoELqFooVZDCCp2ruBKP-TFLhBmh7P2iug-CUP85KyqaqGLJM7vVrDXhijYsrrnkm-8I5lqDyYQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"137-140","volume":""},{"id":7029,"author":"潘玉坤","title":"西周铭文介宾结构补语考察","abstract":"西周铭文用作补语的介宾结构,介词有&quot;于、用、以、自、在、越、安、至于&quot;8个,其中使用频率最高、适用范围最广的是&quot;于&quot;,其他介词的适用范围均较窄。介宾补语可以表示处所、凭借、对象、主动者等意义。介宾结构表示时间,几乎都不做补语,而是做状语。当动词宾语和介宾补语同时出现时,主语、谓语中心语、动词宾语、介词宾语之间呈现出较为复杂的语义关系;语序上,以动宾在前、介宾在后为常。介宾补语的介词有时省略,省略的介词基本是引入处所、对象的&quot;于&quot;,引入凭借的&quot;以&quot;也偶有省略。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9rGXuEIgpt1fBPcG4ziiEL2CWDE7WH7xhbl1NzN7GYRKswt1Eh6mFXd9qCafTivXF49cOgclS383ZOmWXKwudsViY5pNBbJeOnh1JlTtxQ-S-h1D6xYnihoOeJffuiUilhJVVaqnU1X9CA5KXboZUrNbFWL5GZPb5f6JjCxwDXw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"243-250","volume":""},{"id":7031,"author":"张再兴","title":"“文”、“皇”考辨","abstract":"本文借鉴现代语义学方法,梳理&quot;皇&quot;、&quot;文&quot;两个词在西周金文中的语义搭配情况,探究了其作为修饰称呼语时面对不同中心词类型时的语义差异,并对传统金文词典相关字词的释义作出了若干修正。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItR5uGLIifJqdSVY-hu34N-rKkmuDo8hNjcdOBXNTjNpT4464JcIaiGX0VhPM_huc3ZW2cYnzlcRauBiPhpYcGDDc9Y1U5kiuPPooq5SgJIWNYllPBR4X5Uk2jxoMTSgNoPIreSy5AGlAu3i95gLxHK2q7b4wcXCyeklFoooeTdA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-107","volume":""},{"id":7032,"author":"李义海","title":"豫北出土商周青铜器铭文释读检讨","abstract":"该文从汉语言文字学与文献学的角度,对豫北出土的几件青铜器铭文释读进行了校订。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItR5uGLIifJqdSVY-hu34N-rKkmuDo8hNjcdOBXNTjNpT4464JcIaioKfGcC056rwuzJKzA50i1XEt8IVUoTTTRdRQJtcXMinGGCqPljebgvW90f6SKCDbA9Q6V4F7tOExLLLy5GMNV42MhvYLn-unGwWjSuYmUquS3khyGB5aXw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108-112","volume":""},{"id":7033,"author":"张富海","title":"金文“匍有”补说","abstract":"金文中屡见的&quot;匍有&quot;,目前主要有&quot;抚有&quot;和&quot;溥有&quot;两种读法,实际上都存在问题。本文从语言文字的各方面对两种读法作出分析,并提出了新的看法。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhyyF6POHvMPM7ZC5EbK4nX-R5RPhVMrrj4LdDH5a-auG_43D4DbHFaYgKay_3r2x4vTAg2polevA6sBSeQCGGLLqaOL-sIJLdS5w8K-bI9bnqQR315LlY-YaJOmQrjNBlNetYfBoLYM-G7MWJ78JwVFDwNTf57zaQugC0080hNg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-119, 40","volume":""},{"id":7039,"author":"闫华","title":"金文“用”字考察及释例","abstract":"&quot;用&quot;字在金文中的使用频率非常高,据《殷周金文集成引得》(中华书局2001年版)统计,&quot;用&quot;字共3244例,位列第四,这还不包括《殷周金文集成》(以下简称《集成》)以外金文中的用例。对&quot;用&quot;字的系统研究有助于解决一些铭文释读上的问题,也能够问答&quot;用&quot;是何时由动词虚化为介词的。&quot;用&quot;字的用法十分丰富,可作为介词、连词、动词使用,充当状语、谓语、定语、补语。前人已有专文论及金文中&quot;用&quot;字作为","categories":["02_字词句考释"],"year":2007,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5VENxNtMXJcC4Dbwu9rzuPcLxtnPhQ9x6m3gaAPcEl2LBUJU-nQHXtvAJyB5nGRzzADsyDFfUlJoKdomQY7SC_DCxaJcIzF1r87qXQp9Ac6VbuZVU8GTZcjPfslYaEi6s4gSS-UW3o2h544tU6LEmLBs-5CcRhHuDA3FxwBTg4Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"168-170","volume":""},{"id":7040,"author":"吴国升","title":"春秋文字义符替换现象的初步考察","abstract":"所谓&quot;义符替换&quot;,指的是古文字构形中用意义相近或相关的义符来代换合体字原有义符的现象。这是古文字形体发展演变中的一种重要现象,也是造成古文字异体众多的重要原因之一,因此,长期以来颇受学者们的关注。唐兰先生最早在《古文字学导论》一书中对之作了揭示,指出:&quot;凡义相近的字,在偏旁里可以通转。&quot;并举出了人与女、衣与巾、土与阜三组互为通用的形旁字例。①杨树达先生在《新识字之由来》一","categories":["02_字词句考释"],"year":2007,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5VENxNtMXJcC4Dbwu9rzuPcLxtnPhQ9x6m3gaAPcEl2LBUJU-nQHXd-avuL0Sm9he-2QQjxUIUxRfy76xTUbv6hWKbwzMmkb2Zfl3Nal9h0jbTC8CSMX8o5vNeUJUpYomQu-0jbfEc--GKz_9TT7GdrN1i6lARzlw_e0KBOlklw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"176-184","volume":""},{"id":7041,"author":"金河钟","title":"殷商非成篇金文整理研究——以商代职官名研究为基础","abstract":"殷商金文中非成篇金文占据的比重很大。殷商金文中职官名的构成很有规律,一般为&quot;某1+职官名+某2&quot;的形式,&quot;某1&quot;是地名,&quot;某2&quot;表示私名。在殷商金文中出现的职官名有保、师、牧、马、射、亚、戍、史、册、作册、作册友史、卿事(史)、卜、臣、宰、小臣、小子、犬、田、尹、一艹甪(箙)等,还有作职官名的可能性的正、朿、卫、友等4种。","categories":["02_字词句考释"],"year":2007,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIK4_MmAy7ZcVrp11NBfl9SXarivLZsZpZpfP83GQYabMhrJD_HC-gyPYDOwMMtUm9SPpc47E24RwvpnVJ07BNO-GjC1-nAWXvxSeH4iy8rk_lYk2A7saKPbZm_hOyawZY0X81LgNp3T2ZpeD0-W09MsiidsDorXv44Ahg9WWz94CaC3ElpXXgd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46087","volume":""},{"id":7044,"author":"罗卫东","title":"金文的“年”","abstract":"本文依据现存金文材料,描写了&quot;年&quot;的形体演变轨迹,进而分析&quot;年&quot;字呈现出多条演进序列的原因。依据&quot;年&quot;的构成成分及其位置,辨析&quot;年&quot;的形义关系。分别举例说明&quot;年&quot;在铭文中的各项意义。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLbKHJ9mjICuMNLO_Ugl2UCQ0KHyzEDk2UzTy_V4Fh5K5zMwzAHTEyGhqGfzHyZ44T8f80fHxNuBN3bPfXSqDFfSu0Wgr1H6LZVO9GHoxxCJeHJN2WINHPpRC0KBYvyGHqVckc_8yJ5K22gSM6gM5SEokf33waAnf119m_xzj9mg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-35","volume":""},{"id":7045,"author":"徐莉莉","title":"东汉器物铭文中的“工”","abstract":" 在东汉器物铭文中常出现&quot;工&quot;字,多见于东汉铜器洗和弩钱的铭文里。我们分析铭文里的&quot;工&quot;,发现其常见用法为物勒工名,即标明造作此器物的工匠。如:建初元年工杨吴造。四湅八石。(580.建初元年钱)汝南郡八石弩钱郭。永平十八年工李仲造。(581.永平十八年钱)","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJLbKHJ9mjICuMNLO_Ugl2UCQ0KHyzEDk2UzTy_V4Fh5K5zMwzAHTEyRDzrEtw47f8r2yMVlikhLl5a1tK61Ndylakpi6luvuTuh1ckJX1L2iif75GxURVURP4i97r-Hnc-xTfgYxXMqFjCGDbfzcm89PE2UMhL36GaRKhxfNPFEA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-83","volume":""},{"id":7046,"author":"王蕴智","title":"商代可释文字构形解说(一)","abstract":"随着以甲骨文为主体的商代文字研究的不断深化,如今所通行的一些甲骨文字书有待修订或重编,殷商文字的结体特征及其构形规律尚有待全面总结。据笔者的统计,迄今所见商代文字与后世字书中相对应的可释字形计约1250个,加上正在同源分化的字形和主要的通假用字,隶释字目可达1490多个。本文试对一部分笔者所整理出来的商代可释文字的结体特征加以解说,解说字目为:一元天丕*吏*上帝旁下示豊（禮）禄*祥祉福*祐*祗神*齐*祭祀祖*祰*祏祠#禘*祝祈禦（礻舌）社*祸*祟*三王皇玉灵*璞珏气乞*士中串°屮屯艸△芋△薛*萑苞艾荷*叶*蓺*兹*蕴蔡芟若芻薪*蒸*折艿蒿蓄*春藏*蓐莫暮*莽葬（艹害）。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImKy0fCZneEdZz3fmxqJSktcxfYdMvztv4Mh0g6PONfByvIDglYaaQRxjrHlvEympsppmR2KscTWxRPI4h1e1Gx2rfbBtqsljZ1vPzdy2_5QbPRzc1Jlpx191fOHf6np68PzKdCEkZ8QEcEuSObXjv4h7-bm4kaTHfl9bfLyWy_g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46186","volume":""},{"id":7047,"author":"赵诚","title":"金文的“臣”","abstract":"金文中的&quot;臣&quot;字与甲骨文构形相同,对这个字表示的基本意义学者们也大多不太生疏,因而一般的金文研究者对金文中的&quot;臣&quot;字所表示的词的用义不太在意,发现不多。本文将金文使用&quot;臣&quot;字的文句逐一观察、分析、排比,并结合传世文献和词义演化的一般规律,探索出&quot;臣&quot;字在金文中所使用的二十个义项。这些义项,有一些是新材料、新看法。从这些义项中可知金文中的&quot;臣&quot;字用义比较丰富。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImKy0fCZneEdZz3fmxqJSktcxfYdMvztv4Mh0g6PONfByvIDglYaaQcdhrPu7B6xQZxd1T94JY9e_FVDc04008dMI1ykigaiC1l31ipRiZx5w8MMNUUMrrNMNVU130sV3cAAanfkitek8HyK2IISN5UzKHID3zmpWpWcRVllX5Yg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-30","volume":""},{"id":7048,"author":"王晶","title":"西周金文“讯”字解","abstract":"通过对西周铭文资料的整理和研究,我们认识到&quot;讯&quot;字在西周金文中做名词时,当&quot;生俘&quot;讲;做动词时,当&quot;问&quot;讲,又根据文例而译成&quot;审问&quot;或&quot;询问&quot;。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkgur7zffArq65QA7XvJIVEdNb8Z9uOzNB3XkjWzBzhUQqZKonaOjhsFvCvgWPyY8WGVNP1VQjYqRDBLvsz_m7dDiGHun3nvWDXjFss6055PVdecTXom_6hakiQ4aZFPNBXJ7XaJ60HKZu2aA4TmpLBCxxQm3n_H_s8YGJgOhgOw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-38","volume":""},{"id":7049,"author":"潘玉坤","title":"铭文语言特点刍论","abstract":"本文尝试从语言表达角度对商周铭文作一些初步探讨。铭文语言以古朴雄重为常,其他风格同时存在;铭辞既有简古、单调、程式化的一面,也有繁富、富于变化、生动活泼的一面。","categories":["02_字词句考释"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLj4vuAjEf7OpA365EzvO0E6ii7roc321YZ5kcXRoTNRYnguitpmuiw_EVGjVvMlXn9ymuzcxOEQEa6TAL2Cs6IuUDmMoOFWhqafJp1RdRNlQ0_QNTuFfUP8iXX6y2K5A3IwUh5FYZIRSJtIGk9varI274C_Qz19aplJWfdiuu6eA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"148-153, 161","volume":""},{"id":7050,"author":"肖婭曼","title":"原初“是”的浑一性——沈子簋之“是”与代词说和形容词说","abstract":"最古一例&quot;是&quot;见于西周早期沈子簋&quot;懿父乃(乃)是子&quot;。对于此&quot;是&quot;,裘錫圭认为是指代词,唐蘭则认为&quot;是子&quot;舆&quot;懿父&quot;相对,&quot;是&quot;为形容词。代词说舆上下文不符,且&quot;是&quot;不能被&quot;此&quot;替换;形容词说虽舆上下文相符,但舆形容词&quot;是&quot;出现时代不符。本文认为:此&quot;是&quot;为肯定义素和指代义素统一于一体的肯定性指代词。它是后来各种&quot;是&quot;和系词&quot;是&quot;的源头。对原初&quot;是","categories":["02_字词句考释"],"year":2007,"publication":"汉语史研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLj4vuAjEf7OpA365EzvO0E6ii7roc321aEz79ecSgDbJugeB1TLz8Sa5z8b_TSTMdnWOty50NdjONRWbx4wXsZPUaH-HWFc-MV95js5iyFYEu1uW7zmorviQvhBJsLRlotEgGDT8uxK9kLpIPhLiJpEnhcIwLDg61xGt4HvYPxLA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"402-413","volume":""},{"id":7054,"author":"陈英杰; 陈双新","title":"戎生编钟铭文补议","abstract":"戎生编钟一组8件,153字(其中合文1,重文9),为保利艺术博物馆所购藏,著录于《保利藏金——保利艺术博物馆精品选》(岭南美术出版社1999年9月版),同书刊有王世民《戎生编钟》、马承源《戎生编钟铭文的探讨》、裘锡圭《戎生编钟铭文考释》、李学勤《戎生编钟论释》(该文又刊于《文物》1999年9期)、王子初《戎生编钟的音乐学研究》等先生的五篇论文,诸家从不同的角度对铭文作了深入探讨。就笔者所见,除此之外,只有胡长春先生《金文考释四则》(《学术界》2005年6期)涉及了此铭。","categories":["02_字词句考释"],"year":2007,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6J6ShsFGCDqxbGPcrOfUmY4j_peWW7pI_Ter9lAAYgZ1xs9KnjgC0nkCHAxx5-R1TWLQUZrg50jIlTEoxFGUpOdjQeTPeJH9kHOwV376HQtHVdDjg1qn-49oIqSg4Ld73rpVI-VDOil2ijNGU-7A_9qILvW2DGGm-CgxwKvf0cQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-87","volume":""},{"id":7056,"author":"刘志成","title":"两周金文韵读和《诗经》韵部之比较","abstract":"本文收集了两周时期有韵铜器铭文200篇,以董同龢上古汉语语音31韵部为准,进行了分类统计,并与《诗经》的押韵情况进行了比较。提出铭文冬部不独立,应该归东部;“邦”字有归入阳部、东部的方言分别;“命(令)”应归真部;从衣求声的“裘”应该归幽部,从衣又声的裘的金文异体字才应该归之部。","categories":["02_字词句考释"],"year":2007,"publication":"语言历史论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKqrAjMxvCGpJN8Y0XNdTVTs0uPw1UQxSZIzOAqt-uFJWgHQY7SO0a7LgYNhXWWUHI_JwNHX4vY45L1D5iK8FJI0ebfPl0am8AbA_M9aynEMmH3ACqrZbf387aHAyJWfJXd_etMif_KdaNXAcBkTr-hkJ86PI_xbxDr1PCXGhvIMQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-53","volume":""},{"id":7060,"author":"王红","title":"“东”字及其引申义新考","abstract":"“东”字本义自古至今有两种观点:一是许慎为代表的“日木说”,二是现代语言学家提出的“囊橐说”。本文考查文献,从中国汉字与中国古代文化的关系角度出发,认同《说文》中一说,并认为“东”字本义及其现代汉语中主要引申意义均和“日”有关。","categories":["02_字词句考释"],"year":2007,"publication":"文教资料","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwIm2ze9PGrVhd2mwdfmNX64QAO0bq76S7_XsfO5Q2JJCOpaumUWR4vZugvByJ12vCwhuuZvQSqtDXLx9Lv8UZa-ONNxBe_xHY2_Tclf6485565I_GgwuZspAdSHSlRN4ePTbLmiw-cG6Yq-MpFnrmOim0ceHhkxSSX-IbgyLBvsT3jAFb8GOr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-61","volume":""},{"id":5717,"author":"崔元","title":"金文玉部字考释和上古玉文化分析","abstract":"夏商周的玉文化是中国玉文化的最早开创时期,文章力求通过金文字中玉部字的本义分析,来证明这段时期尤其是周代是中国玉文化的奠基和初步繁荣时期。","categories":["02_字词句考释"],"year":2006,"publication":"北京理工大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15918/j.jbitss1009-3370.2006.05.006","pages":"22-25","volume":""},{"id":5719,"author":"丁身伟","title":"“为”是驯马","abstract":"该文用大量的金文(盤、鼎、钟、墩)、帛书中的为字作比较分析,同时亦与首、兄等字互相参照,从而认识马央毛与头发变成线段的相似之处,因此认定为字是驯马之意。否定许慎的为字是母猴说。","categories":["02_字词句考释"],"year":2006,"publication":"韩山师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzptf2nDSo7QnnslFHXHGtMZh_OnkGIzvXt9knhSPqR3UOx5tjWPeJTi-5vwUTWDGpsEh9oLkUSXioiVYJeE-TtZ-8wu7QxalW8EjxBZE6mQ8TNlvohS_FAjwvsH236YLmQ5sMQ1W4GzIuLZcOOuOJMBAwFaqUczC4elEwNW1l3Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-65","volume":""},{"id":5720,"author":"徐宝贵","title":"“孺”字考释","abstract":"~~","categories":["02_字词句考释"],"year":2006,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ54cH4b9gNYKe4GSRspjm0HpbKz3Jd3pzIiw1kU5rx4fgJGZYN3CWwqxkWPt99S68Nrf17kE-MVnlLpu7VecyAI3XEXAhbe7AAfnUdAhEv830RfSRZrqkVuCI9QUkrFr74Rh--RojlO89smiFKfI8tsEsqI13JChDuv0FqBHuRrw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-107","volume":""},{"id":5722,"author":"雷缙碚","title":"后起形声字与金文用字字形字义之比较","abstract":"词由引申可生新词,字经孳乳则成新字。由于文字与其所记录的词语之间没有必然联系,所以文字的孳乳与词汇的引申即不同步,也往往不一致。试将金文所用古字与后起形声字作比较,以分析后起形声字与金文用字的字形源流关系及形声字所记词义与金文用字本义的意义联系。","categories":["02_字词句考释"],"year":2006,"publication":"怀化学院学报（社会科学）","link":"https://link.cnki.net/doi/10.16074/j.cnki.cn43-1394/z.2006.09.038","pages":"127-128","volume":""},{"id":5723,"author":"罗琨","title":"利簋“岁鼎”析疑","abstract":" 读何炳棣、刘雨《夏商周断代工程基本思路质疑》(以下简称《质疑》),很受启发,却也感到有可商榷之处,例如对于&quot;岁鼎&quot;的释读,《质疑》说:利簋&quot;岁鼎&quot;之&quot;岁&quot;字,是否可以释为岁字,难以完全肯定,金文中岁字从无如利簋写作那样的。唐兰先生将此字释","categories":["02_字词句考释"],"year":2006,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYeYDnU93CEuB86tPAyrzqCUMy2ydqEnfVpsL_1G6i_MkqT8q6KnyX2oRqbNpE3plFNrsXI6tBsE-gO6vu1GM34ZV2Uv_a2wkTqbuB7xCLUkLVPU9B9xExYvmmil0MJpN8RVilto920pQu-tjYRhuhIaT7BPpErMiJwTFv_UJDaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"55-60","volume":""},{"id":5724,"author":"辛怡华","title":"“若”字初意试探","abstract":"汉语中的“若”字大致有十三四种词义,主要有选择、顺从、如此、好象等义。从《说文》：“若,择菜也”分析,“选择”是其初意。但在一些殷周金文及早期古文献里出现的“若”字,无论用上述哪一种词义解释,都很牵强。如果我们观察甲骨文、金文中的“若”字,此种解释也是值得商榷的。本文拟对早期汉语中的“若”字初意作一探索,恳请指正。一、“若”最初之意是为了探听神意进行祈祷的活动,或者仪式,“若”与神或上天有关汉字不仅是古代语言的形象化,具有同时性、同质性,而且它的文字体系是把创立文字以前的传承原封不动的集约在字形中。有时神话式的传说也被原封不动的字形化,如早骨文中般始祖王亥便是以鸟形神话的形式来表示的。“若”字","categories":["02_字词句考释"],"year":2006,"publication":"华夏文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYeYDnU93CEuB86tPAyrzqCUMy2ydqEnfBxtHMvNV3l5OmFTo8htnPu0_kUrOC8Vd600sjqe9qStueUSmzk6uku29x1zkomseSkMGzAP9Z6e3SjWC2napElPlCejL88QUE5ZS-hx5qSkALcwBnztX-VdxNGAHkurGXaSUOPkWdfg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-30","volume":""},{"id":5728,"author":"张昌平","title":"“择其吉金”金文辞例与楚文化因素的形成与传播","abstract":"“择其吉金”是春秋中晚期流行于楚国的金文辞例,春秋晚期传播至楚系国家以及吴、越等国。“择其吉金”与另一辞例“用其吉金”关系密切,它们最初可能都是起源于周文化中心区域,而后在豫南鄂北地区流行,并同时为楚国青铜器铭文所采用。这一文化现象说明,早期楚文化因素的形成并非只是通过楚国一个国家而是经由一个区域来完成的,而这个区域应当在豫南鄂北。","categories":["02_字词句考释"],"year":2006,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpy_QZMXv-kNCVk7EFEL5twz1xbXzDQYZy2EQsFgtV8JMxJc0tu5AeIwaL2_bTVd1X8jgiKRyN0QWvloUHjstt_y1XSI65J-XowpeSQc7Oond0Udv9apQ8klI0SiHle6ZkgZnf2-_g_xKNgkYtgiM2Wdb3IFm3YibfqU4h3KyzQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-47, 59","volume":""},{"id":5729,"author":"徐山","title":"释“憲”","abstract":"“”字的金文初文为上下结构,尚无后出形体中的部件“心”。“”字的金文初文为会意字,其字形义为观察用于执行法令的锐器之状。《说文》“,敏也”的解释非“”的本义所在,而“从心目,害省声”的形体分析亦不确。","categories":["02_字词句考释"],"year":2006,"publication":"江苏警官学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL8p3A37gLO2JfsKRnn-EBguoqFpPE2_4Wxk47M68Tle2S3Ww6-Pa6TGZFGx9ASUV4UC1It9GXVR6cPNdC5grGM4IJxYqR9JLiSANsGeANc5IiDQ5usUFzJX_l8WrDRP7JM5UiM7OPbDzOZL1FYni54QEVSYR7L10Mj5coKzpZRFw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-122","volume":""},{"id":5731,"author":"何琳仪","title":"逢逢渊渊释训","abstract":"本文讨论西周铜器铭文中习见词汇“逢逢渊渊”的释读。从字形、音韵、训诂、文献多种角度提出崭新的见解,以之与旧读“蓬蓬勃勃”相互比较,见其异同。指出“逢逢渊渊”本是形容钟鼓之声的象声词,引申为盛大之意。并顺便涉及与“渊渊”有关的铜器铭文“阗阗”的释读。","categories":["02_字词句考释"],"year":2006,"publication":"安徽大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL3mGYD_Zgaf4ggRMGWn36ZqSKutv9tCo9Iz_3pqjiKteloY9o1R2Upluv1RGtVUgu2NqE9TKnl7p_NDXWQR4fnDzHvWeIB-T9kCQxoiL-V_EKYGjZQpPGMJxrY4y29ihjmDOjQbuj8tXTXSmH1JJTgziIvaqlRRH10bE9klJOrZQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-87","volume":""},{"id":5732,"author":"刘雨","title":"金文中的王称","abstract":"金文王称的研究始于王国维《古诸侯称王说》,其后张政烺作《■王簋簋跋——评王国维古诸侯称王说》,对王氏理论加以修正。本文在两位前辈学者研究的基础上,全面检讨了金文中记录的殷代至战国各个时期的王称,将其归纳为“时王生称”、“时王美称”、“时王别称”、“在野王称”等四种。其中“时王别称”系由作者首次提出,该文具体考证了西周金文中的周王、成周王、豐王、畢王、幽王分别是文王、成王、西周早期某王、懿王、孝王的别称,它们都是以都城或重要驻地命名的。命名别称可能是西周诸王的一种普遍现象。","categories":["02_字词句考释"],"year":2006,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2006.04.001","pages":"6-29, 156","volume":""},{"id":5734,"author":"涂白奎","title":"《季姬方尊》铭文释读补正","abstract":"《文物》2003年9期载蔡运章、张应桥先生文《季姬方尊铭文及其重要价值》。文章报道了新近发现的《季姬方尊》,并对器铭进行了释读。由拓影看,器铭字相当恶劣,或清剔未精所致。笔者在细审铭拓和反复阅读该文后,觉得作者对铭文的释读还存在一些问题,有些问题还比较关键,因此不揣浅陋草成此文。","categories":["02_字词句考释"],"year":2006,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbEGCSnD-oQhpb-_bNRq2h2krNpeGT4j-Rj0VrCkzrMclutVC93eMzgnPvHcunQEpO7nhVcIe_L1Jk1pXKalw7rxiwyWhDQ_50SRS_QEj0RYWZqaZSHcp4G5O5Deh2g3S1RgAdsPYMsuC4_Get92-DFkYN1GjvzbHO5TzSYvh32A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-112","volume":""},{"id":5740,"author":"武振玉","title":"两周金文中的无指代词","abstract":"“无指代词”是古代汉语代词系统中特殊的一个小类,虽然其个体数量不多,但使用频率却比较高,关于其词性也存在着不同的意见。上古汉语中的无指代词,过去针对传世文献的研究主要涉及一个“莫”字。然而在两周金文中另有“亡”字亦可用为无指代词,且较“莫”字出现时间早,用例多。对两周金文中无指代词的调查可为研究上古汉语早期的此类词提供新的材料。","categories":["02_字词句考释"],"year":2006,"publication":"长江学术","link":"https://link.cnki.net/doi/10.19866/j.cnki.cjxs.2006.03.011","pages":"67-71","volume":""},{"id":5741,"author":"洪飏","title":"谈古文字考释中论证通假关系的语音标准问题","abstract":"古文字资料中有很多通假字。古文字考释中常常要遇到通假问题。本文具体讨论了古文字考释中确定通假关系的“律例兼备”的原则,并就其中存在的问题略作辨正。","categories":["02_字词句考释"],"year":2006,"publication":"渤海大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13831/j.cnki.issn.1672-8254.2006.04.009","pages":"32-35","volume":""},{"id":5743,"author":"陈仕益","title":"郭沫若两周金文韵读补论","abstract":"《郭沫若全集·考古编》4—8卷一共引录了442篇两周金文。郭沫若对它们的音韵情况的研究,仅限于标注了291篇入韵金文中的71篇的韵读。本文接力于此,进一步从若干方面对这442篇金文的押韵情况进行了归纳和分析。“归纳”是1.金文置韵的类型。有通篇置韵、片段置韵和通篇无韵三类,其比重依次为30%、36%和34%。2.句中韵。它们共有七、八十条。3.交韵和抱韵。31篇金文有交韵,6篇金文有抱韵。4.高频韵部。使用频率最高的韵部是幽、阳、之、鱼四个。“分析”紧随各类“归纳”之后。","categories":["02_字词句考释"],"year":2006,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2006.02.011","pages":"53-60","volume":""},{"id":5744,"author":"朱刚焄","title":"西周青铜器铭文复音词构词法","abstract":"在中国语法史、词汇史、文字学史的工作上,殷周时期的语言是首先值得注意的对象。因为就今可见的确实可靠的语文资料来说,殷周时期是中国语言文献历史当中我们能够追溯的最早的一个阶段。对于这个时期的语言事实有了明确的认识,才有可能知道此后各个时期语言在发展上的传承关系和新的现象。从西周开始历代复音词都有增加,构词的方法也由单音造词向复音词转变,所以我们通过对西周青铜器铭文的研究来了解西周汉语复音构词情况。","categories":["02_字词句考释"],"year":2006,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2006.02.015","pages":"84-88","volume":""},{"id":5748,"author":"张晓明; 马廷新","title":"春秋战国齐金文字体研究","abstract":"春秋战国是汉字字体由篆到隶的重要时期,齐金文素以其精严整饬的美化藻饰体著称,但这只是其字体演变中的一个环节。齐金文字体演变在书写便捷的原动力下,通过体势趋扁趋方打破篆体长圆体势,通过短直的笔画分解篆体圆转的笔画,与其他地域的金文字体一起推动了汉字字体的演变,并以其鲜明的地域个性丰富了汉字字体面貌。","categories":["02_字词句考释"],"year":2006,"publication":"管子学刊","link":"https://link.cnki.net/doi/10.19321/j.cnki.gzxk.2006.02.011","pages":"49-55","volume":""},{"id":5750,"author":"王长丰","title":"西周“■”土考——再释《中作父乙方鼎》之“■”土及其地望","abstract":"本文详尽地考证了《中作父乙方鼎》铭文所载之西周昭王伐虎方时,赐中之埰邑“(?)土”之“(?)”字。铭文宋时出土,“(?)”字未识。今考证其字亦即“(?)”字,亦是甲骨文之“(?)”地,古书所载之“潛(鬵、灊)地”,地望在今湖北省孝感市附近,地近古灊水。“(?)((?)、灊)”(水)在今湖北省潜江县境,非今嘉陵江上游之古潜水、安徽省安庆市潜山县境之古潜邑。","categories":["02_字词句考释"],"year":2006,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICMC3GuzjoAH4nMk2WvGuzbLghEMxSzSKObF-QubzjODPOPXdu2Qcxutm2z6WBBnS5zzIjmNq8Bz9UOJa0cIDsMKgPR0o211Q0TPCeqmZOeEtPNhCcN6Gufzzf6YpXoG5SUos4BicHuk3B5b_pAxXDCgR0Fgm_3pcOkHVbZdkdSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-72","volume":""},{"id":5752,"author":"李朝远","title":"西周金文中的“王&quot;与“王器”","abstract":"正如许多学者都指出的那样,金文研究不仅要仔细弄懂字词句、解读全文的意思,同时还要对金文的书写文本和书写格式进行研究和解读,究竟时人是在何时、何地、何背景的条件下使用了这种书写文本。近年来,断断续续地一直在考虑一个问","categories":["02_字词句考释"],"year":2006,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2006.05.006","pages":"74-79","volume":""},{"id":5753,"author":"程鹏万","title":"释东周金文中的“成日”","abstract":"本文将东周金文中的“”字释为“成日”合文。并将其与战国楚简《日书》、秦简《日书》相比较,认为“成日”是好日子的一种说法。","categories":["02_字词句考释"],"year":2006,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJashNv7QS0sJXoonwJmk2JytdXZ5QlJhIdIv6vbr-_rftmlygUBdfChIOxZgToLXhS1gB857Qr2DTWpT21zy_LBv__J4cNfxP4C8bmE_BfVrEzRatR7jAVPngx13HsF4-TYZQ_iZ2zXDysUb5V09I8R71Kg32X_krY_yMIP7hdTA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-37","volume":""},{"id":5757,"author":"白冰","title":"论金文刑罚系列字","abstract":"","categories":["02_字词句考释"],"year":2006,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeWMLuFWI-yaPVGWWLzdWL5JJ2CiMz47htaCX0lmaFV9dhrcPDMoCMZTAdibki-kBVrDLCbzE7XazJkQ1izu07E_1sytCpFqeLTUcmDTR38oOgyEFyUDXtBVdfcBaPSw51t_9cVO9cUzhwIz3AtHVteGoA5mDRIwxA3ol0olTFVg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-49","volume":""},{"id":5762,"author":"王辉; 萧春源","title":"珍秦斋藏秦铜器铭文选释","abstract":"澳门萧春源珍秦斋藏秦有铭青铜器有簋、鼎、盘、盉、(?)、壶、权及多件兵器。其铭文涉及秦的政治、军事、历史、文化,极为重要。本文选取其中10件铜器铭文进行考释,认为:十四年口平匽氏戟作于秦惠文王后元十四年(前311年),器主即四川青川县出土木牍所见的“内史匽”,时任上郡守;二十一年相邦冉戈作于昭襄王二十一年(前286年);三十年诏事戈时代有昭襄王三十年(前277年)及始皇三十年(前217年)两种可能性,而以前者的可能性为大;三十二年相邦冉戈作于昭襄王三十二年(前275年),该戈内上套一件鸟柲冒(帽),应是赵惠文王二十三年(前276年)赵国器物,秦人缴获后继续使用,西安市文物保护考古研究所藏同铭乌","categories":["02_字词句考释"],"year":2006,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2006.02.005","pages":"64-87, 155-156","volume":""},{"id":5763,"author":"严志斌","title":"商代金文句法研究","abstract":"本文是对商代金文的句法的初步探讨,主要从短语、句子成分、单句、复句及句类五方面进行分析。","categories":["02_字词句考释"],"year":2006,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2006.01.019","pages":"85-91","volume":""},{"id":5764,"author":"段立超","title":"“颂”字本义新考","abstract":"“颂”是会意字。本义为人屈膝低首恭顺地用语言与神灵沟通。指称范围扩大后,指一般的外表仪态。又因为同音假借,有了“容纳”的含义,基于此,东汉学者对“颂”字的解释与先秦相比有差异。后代有学者认为“颂”是“诵”的后起替代者,这不正确。“颂”字的基本内涵,是下对上的衷心称美赞扬,在上古文化背景下,其指向,是当时人们心目中的最高者:神明。","categories":["02_字词句考释"],"year":2006,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQ5NW7S5JDTj5FdEoO_GMV08ofojrmqT_4UySTjJaREYmISVj4C2gRuCKQc3trXfmn_UXrrO0qQsmdCm6uQCwm_7tAHtS1EUU1W0ZPbp2bwVFBVe_zmUuSbbEdj_MXasYpTGJcAGuR4r3ABCFSbDg6mH0p4RsMqPMdexzqvJy33w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-68","volume":""},{"id":5767,"author":"吴振武","title":"新见西周爯簋铭文释读","abstract":"首次刊布的这篇西周青铜簋铭,器主名“爯”,计49字,时代约在西周中期。铭文的主要内容虽为器主的祈愿之辞,然关系到西周思想文化、家族形态、语言文字等一系列有价值的课题。","categories":["02_字词句考释"],"year":2006,"publication":"史学集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKk0oYRhxLXIA8BBluMKbZi9LuxDziqRgqzi52yiHj-Tjyih5aSSFiJlNIyD3dwCxZgkHpOzeSk3EBevgb5XcURHyxDdsdNNn_iPz37R2FXwGTjVKYK4Gj04wIiozwB6u8iAYhH6Cyp1KLK98vnJV3aCLSM_JcmV1lBDrMDhQpgQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-88","volume":""},{"id":5768,"author":"赵鹏","title":"西周金文量词析论","abstract":"整理出西周金文中的量词39个,其中分为个体量词、集体量词、容器量诃、度量衡及货币单位量词和其他量词等五类。它们的语法功能主要是与数词组成数量短语,在句中作定语、谓语、宾语等句子成分,其语义特征主要体现在与名词的搭配选择关系小。通过对西周金文中的量词的使用情况的分析,可见西周处于量词产生的初级阶段。","categories":["02_字词句考释"],"year":2006,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLdeUkvUyPGyBu9LjnGoeam-5LyYLPgw7Hd2hHn_4msaSALQBlu3T7E2jIDdx6BRxmjcbGjKW_naIKFJ8M6EC50QIzkX2O2v-eiQXn-XuLnk7wUgg3XeJxlZCDP7BXC9tsc1m5IQLhOeudLY2wgKEuOjOl8SZNSmHoC0WLHxFLH8A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-62","volume":""},{"id":5769,"author":"陈双新","title":"乐器铭文“龢”、“協”、“鍚”、“雷”、“霝”释义","abstract":"研究青铜乐器自名之修饰语可以帮助我们从一个新的角度认识青铜乐器的用途、特征、价值等方面情况,前人较少注意及此。本文对其中的“龢”、“協”、“鍚”、“雷”、“霝”等词语进行综合考察和新的诠释, 如释“鍚”的“鍚”为形容乐音高扬等等。","categories":["02_字词句考释"],"year":2006,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJTbQtEPvK2d5qnDgmkncJ9pARKUoB05vAYsTFiouefDQVSS-uir8pYE_2vWkDSogg84UmJsDHcJTTH2a1cFNHqfOiBQcnDasfcIrJFr5IjRIx3fTwslE5Xb6DFAo6bcjWuDQiO-1PEI3OXCmlWEXSqdCKUFaODbp1IUB9T-5Sgzg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-44","volume":""},{"id":5781,"author":"武振玉","title":"两周金文中否定副词“毋”的特殊用法","abstract":"“毋”作为否定副词,甲骨文中已见,传世文献中出现频率亦较高。过去对它的研究结论基本是认为“毋”用于表示对主观意愿的否定,可以译为“不要”,是一个表示禁止性否定的副词。但是金文中“毋”有较为特殊的一种用法,即用于表示一般性的否定,这种“毋”不能译成“不要”,而是相当于“不、弗”。这种用法有特定的出现场合,即主要出现于修饰助动词“敢”的时候,相应的“敢”也不能理解为通常的含义,而是要理解为“可以”一类义。","categories":["02_字词句考释"],"year":2006,"publication":"长春师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5MJojaQg90ikZH0LwzcBPT6umRNeY0-4MLYlRrOfJ81cYY3_iKY10HMLQrlYB39p8MiE1pAUeJxZbzv8gzkC0umEsNcJnI6CtzEF0Mak6wtXB4JYnqoLYEyHJ6LhOFEy0RJDi0rk0ayK0dL0VdqTmM_bGpeVc0IJgoZS-ylS6pw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-61","volume":""},{"id":5783,"author":"陈英杰","title":"两周金文之“追、享、鄕、孝”正义","abstract":"依据迄今所能见到的两周金文材料,对器用铭辞中的“追、享、鄕、孝”等语词进行深入研究,发现金文中“追孝”意思就是“追养、继孝”,也即“追生时,这养继生时之孝”,是说祖考死后后人继续生时的供养。“享”是献食之祭,不是祭祀专名,而是一个泛化的表示祭祀义的动词,多用于神鬼,是“孝”之事死的一项重要内容。“鄕”则多用于生人,但它与“享”在整个两周时期均有混用现象。“孝”的内涵很广,它包括了后世“忠”、“友”、“悌”的内容,由此廓清了对两周时期“孝”的观念的错误理解。","categories":["02_字词句考释"],"year":2006,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_7UKPmACzIl75Q0e1sXPDVG50S9N_18P7ck2aZaUYCd3CuOzRu6bjVbud155XtdzYQXibHmBF-HyK9Uqir5Uw_p7BVbg_8r6q1U_q-M0Qvmwd0crh6hq71W_buSk0ahnajdkEIQqFxXCZsgYxWAdiw5VCjdZw_5qAWscLCpBxxQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46213","volume":""},{"id":5786,"author":"李山川","title":"金文介词“于”的语法功能","abstract":"介词是汉语中一个封闭的词类,它的绝对数量是有限的,但是它在语法中起到的作用却很大,被动式等很多特殊的语法现象都无法绕开介词。而上古汉语体系中,词的兼类现象是很常见的,像“于”字这样的一个单音节词既可能是动词,又可能是介词或是是助词。因此在铭文释读的过程中对于介词的把握是正确释读的一个难点。本文以最具典型性的介词“于”字为研究对象,在《金文今译》中收录的423篇铭文材料范围内作穷尽性的研究,将金文“于”字的介词性语法功能作比较全面的分析和归纳,并对前人的研究作一些必要的补充。","categories":["02_字词句考释"],"year":2006,"publication":"四川理工学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLCyl67RUfLmcpWCDBW0IPr8UyVwy-2OWFKcp3JAeZNlkYxcf6lHn4UnJqcBUn4cRo_g33Zm1VmZT3htF8hg_sTTnhyohNhM3wMmwUHDV7m7PXJDkchc75FpiY7Qo0JjOP_tC3olQnsL_-S54ySVPQKNJUCxugbPI_TQLwXa8OkGQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-109","volume":""},{"id":5788,"author":"朱其智","title":"西周金文研究札记两则","abstract":"沈子它(?)盖铭中“其丮衰乃沈子它唯福”之“其丮”为“其”字繁体“(?)”之分书,班(?)等铭中之“丮”为“其”之异体；师(?)盖铭中“淮夷(?)我(?)畮臣”之“(?)”当通“犹”,为准系词,兮甲盘中的“淮夷旧我(?)畮人”之“旧”通“(?)(犹)”,而非相反。","categories":["02_字词句考释"],"year":2006,"publication":"语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2vcPQqVNsamGK8PraIe3_60K9NSN1BUzNs7YgbWuvpXIIEup-hE2gvtTupN0ncOszz8GwOxz0TPaQCN2MW5A_sr1rHBYkHZKxkaEAL2UhkZVb9aBDEQJmEbMJC8NL4BRk-loZXZigeNIY-yJMiffZgm7JvDZbsUR-djyClV0C4Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-82","volume":""},{"id":5790,"author":"王云霞","title":"释“日”","abstract":"“日”字是象形字已成定论,但其中之点划表示什么却历来众说纷纭,有许多曲解。日中之点划只是为了与其他类似的文字易于区别,并无其他含义。本文就对这一问题谈一下自己的看法。","categories":["02_字词句考释"],"year":2006,"publication":"内蒙古师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJrCbVKt1wmiLry9EXTO3KWtupr5icFtdkrv6fAMcz1hh2IpmkIFlaYXh82nb9ENfb80DAQ4qS7JvByof4vsb36D7fl0pOICJpwu1gyB8GQGnBoB2KQceMin_cEhBBOX7h1NS1BD4UZK9xWPnoNDYH7MaJZOlLQy6MIzLSf8b7QsA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"284, 293","volume":""},{"id":5791,"author":"黄爱梅","title":"士山盘铭补义","abstract":"士山盘铭是一篇重要的西周金文材料,但争议之处尚多。笔者在综合各家意见的基础上,对铭文中的关键文字进行了重新释读。指出文中&quot;大虘服&quot;、&quot;履服&quot;、&quot;六孳服&quot;与兮甲盘所谓&quot;出其帛、其责(积)、其进人&quot;的记载相近,而内容更为具体,很可能是对祭祀所需藉田人员、所服之屦履及所用之粮食的征求。该盘铭很可能是迄今所见金文中对西周&quot;服&quot;制最直接的记载。它对理解西周&quot;服&quot;制的具体内容、内在标准以及周王与诸侯关系,都具有十分重要的意义。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK_ylfYIFljBHIGilt38svlveHJ38ayQdxsfQd1NQ6jstZwUkaJcgmejGDS8iOrSI9yd7OT_xsn1qdxRXqIN7BOmIkY-qK1XoRj2QjDCtOXl_TUeVYTp7vFzTqP-IVpqlv7JpHgrU3S7wi_TSXrjzR9pPiUZfOUSPem9gSkL3Rc-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-58","volume":""},{"id":5793,"author":"何景成","title":"关于《荣仲方鼎》的一点看法","abstract":"本文主要讨论了关于新近发表的《荣仲方鼎》铭文的几个问题。认为鼎铭中的&quot;子&quot;应该是贵族族长的称号,不是国子、王子或尚未逾年的新王。铭文末尾的&quot;史&quot;是表示荣仲族属的族氏铭文。族氏铭文是商人用以标识族属的主要方式,荣仲是商代遗族,&quot;荣仲&quot;这一称谓方式可能对于探讨族氏铭文在西周中期后逐渐消失的原因有所帮助。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJzBdHKMC_jpw2sra1KJE729htLUqfxJBkHDZ-TUxgbJKT9a_IBajlz7SgG-a56H-ZEVVolGCft5IJkmO_wKi5WgmyS36CQU2t1eX6LwK-I8Kk8wwFIEY9vBwG85k7UURWakyG3CtYo8WIC4I57vqVfuIM_ufpD3-E9-j1-mHS1Sg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-66","volume":""},{"id":5794,"author":"董珊","title":"晋侯墓出土楚公逆钟铭文新探","abstract":"本文论证楚公逆钟铭文的祭祀对象&quot;四方首&quot;指四方社、稷之神。钟铭记载了对楚国社稷、祖先的一次大祭祀,其中使用了战争掠夺的人牲作为祭祀品。文末对铭文中读为&quot;谐&quot;与&quot;肆&quot;的两个字做了解释。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIpF8wZa7pkWIumf-APKUR-kyvKI2H5JQpXLLKvPeyIoR1Kdwrk1uokSfoLVNrz1YMMaSX3W6bBSIaJ1s2kfZJXf9qlpxy2t1g61uUhXkJyDhy6b8Yq9YAJX48o2_ioyunsmF2fUMSHog4ZkLQTFuRL4ni7TcpjN-HKtn8OXuWisQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-74","volume":""},{"id":5799,"author":"吴镇烽","title":"高祖、亚祖、王父考","abstract":"高祖、亚祖、王父考通过对■鼎、■盘、墙盘等金文资料和文献资料分析研究,先秦时期的&quot;高祖&quot;和&quot;皇祖&quot;一样,只是对某一先祖的尊称,不是某一代先祖的专称。&quot;亚祖&quot;是在记述多位先祖时所使用的一个词语,是相对于前一位先祖的称谓,&quot;王父&quot;是祖父的另一称谓,不是&quot;祖父的昆弟&quot;。","categories":["02_字词句考释"],"year":2006,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzXHjiUEnNU7GLKqakpjZpJ1eYUnsqoZvJ5n9CxFCP5oFCeu85JzVxrSCBmdf9DVs_-cQnIZ5m7ueSuQushFs376fTAGfrwTiSdE6koxaswdm5XA7T9VxZdSrS-Mln04-kAZnyeKwce3ZPQr2gdnx8LPT8H8nzSwtYQK9ZMNOaLQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-77, 2","volume":""},{"id":5800,"author":"王恩田","title":"鹿邑微子墓补证——兼释相侯与子口寻(腯)","abstract":"鹿邑县太清宫镇即春秋相邑。微子即西周金文之相侯。鹿邑大墓铜器铭文中的子口寻,即微子启之孙脯。长字象拄杖形是商周文字,不应用经过讹变的战国楚简中的长字予以否定。","categories":["02_字词句考释"],"year":2006,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZUOvDsA8D1Gzj4F98VG5mlq0dspIU3pP6EmkaZSoFRaB5n90V7J96VKa97CeV94mmsDsTWC4CGYNVAaiLxZAU2jHmHTlYA9gzNvw8ny4X6BvjQLWFSJ3SmGQHtFBpKG8DCl2kTAVFfasy-1wX_s5zSsFUrAcFLNUCaA1fRwfSbQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-60","volume":""},{"id":5801,"author":"贺琼","title":"《殷墟书契补释》补正","abstract":"柯昌济先生《殷墟书契补释》一书对一些字的考释颇有见地,但书中也存在一些错误和缺陷。校读此书,有两方面的工作要做,一是尽可能考察注明其引器的出处,二是对其考释的字做全面的校正。","categories":["02_字词句考释"],"year":2006,"publication":"重庆工商大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6r2WR0sJucYYRcWyusHe5qUVNqwRq3pbiW5-rR23dR5UraV93xcSvqp0jF7tge-xyzM3i84tiUm3WABTlqtWzLaH0oXj75TYL7Aalv0yye1amq6QZ29gerXZ61onsR7HWMHpsVWAhjGtNudq-IqkLPgcInHDVFsidrDAL4oBBUQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"113-116","volume":""},{"id":5802,"author":"徐山","title":"释“進”","abstract":"“進”字的甲骨文形体,其字形为上从隹下从止的会意字,《说文》“从辵,閵省声”的形体分析不确。“進”字的形体义当为鸟在前方而人朝着鸟前进之状。","categories":["02_字词句考释"],"year":2006,"publication":"赤峰学院学报（汉文哲学社会科学版）","link":"https://link.cnki.net/doi/10.13398/j.cnki.issn1673-2596.2006.06.006","pages":"11, 102","volume":""},{"id":5804,"author":"吴镇烽","title":"■器铭文考释","abstract":"上海崇源艺术拍卖公司和诚源文化艺术公司,去年从海外购回一批商周青铜器,9月22日到25日聘请国内著名青铜器和占文字专家,在上海举办海外回流青铜器观摩研讨会,笔者有幸参加,饱享眼福。崇源公司和诚源公司为保护祖国文化遗产和弘扬中国传统文化做出了重要贡献。作为民营公司,他们的这一义举在全国也是","categories":["02_字词句考释"],"year":2006,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFr1GaSTB1nnbecWNEklqKgF8NiZ_AanbB7ntUFPbbaxbnqAI2dB15bOhzJqDcQcZE0njKsxoOuefOueCihJJYe-g3suWwtn6TFfOrD6jV5FxUHDfICF12PadvhaD-8vgHrVttoMD9hwpNZH_AA6FxdaSbO9epWPrE0qGZ_m-j8g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-65, 113","volume":""},{"id":5805,"author":"陈英杰","title":"商代铜器铭文作器对象的考察","abstract":"商代中后期开始出现少量有铭铜器,但铭文一般都很简略,多为一个字或两三个字,内容为族名、作器者名、作器对象名(即为谁作器。商代铭文中作器对象和祭祀对象通常是相同的,所以有的著作直接称之为“受祭者名”。但有的作器对象不一定是受祭祀者,所以综观整个铭文","categories":["02_字词句考释"],"year":2006,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4r7-kgfA5xSW0AXzSGWfW6IJSzacyhYa7pF6aJTPqbuVB3tX3LElfMgcVMaNlG-NilfoscLF5ShK_HrZONNufxtSpwoX54qsshy8YNMQH3x8E4AjmAJmpjErCcGnfPV2QqgdB3MrYtFoGG9Tpobd4L91HqdqxsEiXbpROxGR1ew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-77","volume":""},{"id":5806,"author":"董珊","title":"珍秦斋藏秦伯丧戈、矛考释","abstract":"珍秦斋收藏的四件伯丧戈、矛,是最近发现的重要秦国文物。本文在考察器物形制和解释铭文的基础上,认为这四件戈、矛属于春秋早期,并结合文献指出,四件戈、矛的器主“伯丧”应是文献所见的大庶长弗忌。铭文还记载了春秋时秦国最初向东方的发展,有特殊重要的历史意义。","categories":["02_字词句考释"],"year":2006,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2006.06.009","pages":"105-116, 158","volume":""},{"id":5809,"author":"禤健聪","title":"楚文字新读二则","abstract":"本文是关于战国楚文字材料的二则札记,对大府镐铭的第二句作了新的释读,把楚简中一般读为“冢”的字改读为“豬”。","categories":["02_字词句考释"],"year":2006,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXxnakXo4jprZLZl2OiaeuHptA0zsrIMdR95qmcmG2e9Emg6ZUD2k4WDdHBBXzeqNvSZjq1Fv0FtTvHGaEEhwdJqgEi-87hRpEi6qEJguUkA1QcVW98TlHJKSBCF1FbdWoSjJBSGZ5AJ07E2OYeZOKN7AW85ryqk7QBeMsQC1ajg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-84","volume":""},{"id":5810,"author":"俞绍宏","title":"二则金文考","abstract":"从字形分析入手,重新隶释出战国王命虎符铭文中的“虎”字以及九年戈铭文中的“■”字。","categories":["02_字词句考释"],"year":2006,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXxnakXo4jprZLZl2OiaeuHptA0zsrIMdR95qmcmG2e9Emg6ZUD2k4f7jAhmyCK5iO97ecFzdl9qxM7CPzP_a_b9bMXwGJQgcJZaYBB5KypyJJwIphB54D4y3ZdpQ2__sPIup1FZv2mLInkpzDZM7JpDHm-TFbmlkhCM0yFEdZxw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85, 54","volume":""},{"id":5811,"author":"徐山","title":"释“禽”","abstract":"“禽”字金文的早期形体上为部件,的含义为天盖状。“禽”的金文早期形体为用长柄上有网的工具在天空中擒鸟状。“禽”的金文后出形体将早期形体中的部件“”形变为“今”,从而将原来是会意字的“禽”改造成形声字。《说文》对“禽”字的训释和形体分析的不确之处。","categories":["02_字词句考释"],"year":2006,"publication":"安徽农业大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19747/j.cnki.1009-2463.2006.06.027","pages":"99-100","volume":""},{"id":5812,"author":"吴振武","title":"试释西周簋铭文中的“馨”字","abstract":"","categories":["02_字词句考释"],"year":2006,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2006.11.005","pages":"61-62","volume":""},{"id":5813,"author":"张振谦","title":"三年大将吏弩机补释","abstract":"","categories":["02_字词句考释"],"year":2006,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2006.11.006","pages":"62","volume":""},{"id":5814,"author":"刘余力; 蔡运章","title":"王太后左私室鼎铭考略","abstract":"","categories":["02_字词句考释"],"year":2006,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2006.11.007","pages":"63-67","volume":""},{"id":5824,"author":"孔令远","title":"读者来信:江苏邳州市九女墩六号墓出土青铜器铭文考","abstract":" 徐州市博物馆、邳州市博物馆等在1997年对九女墩六号墓进行了发掘(徐州博物馆、邳州博物馆:《江苏邳州市九女墩春秋墓发掘简报》,《考古》2003年第9期),出土了蓥具铭铜器残片(图一)。发掘简报发表了该器铭文拓片,铭文释为&quot;自作铸工□王之孙&quot;。笔者认为应释为&quot;工王之孙□□□□……作蓥&quot;。","categories":["02_字词句考释"],"year":2006,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKLXAjqf8QtmwYsXIXsz1aPfXWs0Et8WuqXiEeIzu4TvYdVIlXMLKl9f6JtJ9nikrNkA4y6uPt-VfNmdXck1PuUCdSsdgGtYzdmX-8mu289a227zy3wlXmgmAtbDuWCDjxVk_yVoYAUC_wFB2ZFP7KmASNTvo9zWIWnpD3dfDsOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96","volume":""},{"id":5826,"author":"冯时","title":"坂方鼎、荣仲方鼎及相关问题","abstract":" 保利艺术博物馆新藏殷末坂方鼎及西周荣仲方鼎资料近已刊布,二器铭文对研究商代周祭制度、商周历法和相关礼制具有十分重要的意义。学者于铭文内容已有详考,今不揣谫陋,就鼎铭及相关问题略陈剩义。","categories":["02_字词句考释"],"year":2006,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKWUzDGFhXcZDxV7cR-ax-eIgjlY_dqHgVdNm-01K1QNx8RBN7lJBPGkg59qggdwCKL9qE3YLhdXYjkbuoxVFjLo3RTMDYAQZ1MrbKKFN3TU7wQjjFXMDejGkPLvj5r8saADH27fX3m7YHkg1pmLtK-7Uuz2Q6jdsfwhZLPBgBHtQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-73","volume":""},{"id":5827,"author":"王冠英","title":"(录见)簋考释","abstract":"中国国家博物馆去年新藏一带支架形底座的长冠鸟形双耳无盖簋——(录见)簋。此簋铭文王年、月、月相、日(干支)四项要素俱全,是研究西周王年历谱和金文断代的重要资料。据原收藏者透露,此簋是解放前其祖父用一座小中药铺换来的,传清末或民初出土于陕西宝鸡。为了对税簋进行深入研究,《中国历史文物》编辑部特邀部分专家对(录见)簋的年代进行笔谈,希望能听到更多学者的意见。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJRfytsFVZCJH4RKgZ4tB4Xv7gJmWkTOYqN7BLxiLDFd5iN5IcQmjQAFmdX9l4YoPfggEEXxUWFDQ2QmjTjFq3PMVmhXfpL3TlMktrMGozEacRGmSVCSfwNWZ_WAvr6rZIXnXYOw-4rM6NPnbGhNBtoWRY2tVD5C9W-IaPMyEsLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"4-6, 1-2","volume":""},{"id":5830,"author":"冯沂","title":"临沂洗砚池晋墓出土正始二年弩机考议","abstract":"本文就山东临沂洗砚池晋墓中出土弩机所刻铭文内容进行了考释;结合考古资料,探讨了弩机的发展过程。并对已发表的弩机铭文,进行了比对研究。认为由于魏、蜀、吴三国兵器制作和监管制度不同,因此形成了各自弩机刻铭的特点。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeP1mPr6DgXSimPckn28TePTZ67eeptmAtdqti6sBwemmLcNLmefciUC4fadcBKUPmTksCk6zkhO1xVE2hNR_-G4wZ8pyo9CIjAUNR7n4xeFpgjd8NKRSjXr2FhTLb9kLEiSdp8ZzbTPWjMHS8FGxBOBx29qkEwq70rHb4yY-Y2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-22","volume":""},{"id":5831,"author":"赵平安","title":"山东泰安龙门口新出青铜器铭文考释","abstract":"本文对1993年山东泰安龙门口遗址出土的两件有铭青铜器进行了探讨,认为应分别定名为商丘叔■和■姬鬲。商丘叔■属于春秋早期卫国,是作者自作器,历史上曾有出土; ■姬鬲属于西周晚期,系姬姓铸(祝)国夫人为女儿所作,是首次发现。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWcCJtv9GxF8EhWhpF3CmXL3bFZpLUTwMA7e7tY50hlFAbML03qB2B7v0Myo920CY7NH2SlJ-2tPf6IptKsSOi4jxXHG0y2FyU40NJxyfnSsXEXqB9htBhYQMTigdh4JNck54idPmEGCNajOnvcTQS36BgwGZxyie1C7z44ZZSwg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-20","volume":""},{"id":5832,"author":"吴良宝","title":"战国金文考释两篇","abstract":"上海博物馆新入藏的&quot;二十三年&quot;鼎,提供了前所未知的魏国&quot;襄&quot;字资料,使得三晋文字中不同写法的&quot;襄&quot;字的国别得以区分开来,也证明过去将&quot;襄垣&quot;、&quot;壤阴&quot;方足小布定为韩币的意见是正确的,旧被定为赵器的《襄阴鼎》也是韩器。《集成》11338号的&quot;三年戈&quot;应为韩器,戈铭中的地名应是&quot;榆即&quot;的省变之体,其制作年代为韩釐王三年,即公元前293年。","categories":["02_字词句考释"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWcCJtv9GxF8EhWhpF3CmXL3bFZpLUTwMA7e7tY50hlFAbML03qB2BBOMrcTxqDyvw-pHjKKHVKevDHg41szvsr_7upBFMEcSbFD1N1PkHgYtDX3sbRj-3xtVFBxHSdN_v7eqBjM-ogpfxBnRLk4U5O6kThtrrdO42xHO0lN5EJQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-25","volume":""},{"id":5834,"author":"董珊","title":"向寿戈考","abstract":" 1987年,在江苏连云港市锦屏镇陶湾村岗嘴发现3件铜戈,现藏连云港市博物馆。其中1件戈的内上,由内端向栏刻有两行铭文共11字(图一;图二)。目前所见释文有以下三种。1.都寿之岁,襄城楚競(境)尹所造。2.都寿之岁,襄城公競(境)尹所造。3.□寿之岁,襄城公競脽所造。第一种是材料发表者周晓陆、纪达凯二位先生的释文。第二种是黄盛璋先生的释文,纠正了发表者误释&quot;公&quot;为&quot;楚&quot;的错误,认为&quot;襄城公&quot;是楚国的封君。第三种是李家浩先生的释文,他把&quot;競&quot;下一字改释为&quot;脽&quot;,右行首字则缺释。作者:董珊,北京市,","categories":["02_字词句考释"],"year":2006,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKNa_s9BVdinChn6MYY8U4NHyCoquy_rgrnWsaJaWSVPCe2LdgG_NRm0ym5am1s3rdcxHpPpCW2ZALmCXZBFN3D_x01EebcQiH3PWfRhA1z8HITAHG-i7QRPWOY3Fi-kt0dufw1y_hQxH65tdmtwUvhaqDLCRvehdA57pecYcL43A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-70","volume":""},{"id":5836,"author":"宋镇豪","title":"从新出甲骨金文考述晚商射礼","abstract":"射礼是按照一定的规程所举行的弓矢竞技行事,通常认为属于周代的礼制。然据近出甲骨文金文材料确知,逐渐脱离宗教权威支撑而用来体现贵族子弟矢射技能高下的射礼,早在晚商就已经流行,周代不过是继承而有所革替而已。晚商射礼,是商王暨各方贵族阶层成员参预的弓矢竞射札,通常习射于水泽原野处,泽畔建有与习射相关的建筑设施,又连天累日举行,以&quot;(?)弓&quot;、&quot;迟弓&quot;、&quot;疾弓&quot;三射作为竞技规则,注重用弓暨弓法,视射获猎物无废矢进行颁功贶赐,射后有享祭先祖之礼。周代射礼,实当源自殷礼。","categories":["02_字词句考释","03_政治经济"],"year":2006,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6kheqMBtvyzb2g1W9xT1qNUjRbkYdhclTeZG2vbaRcDYL7vX7OOuXLBCthottixtTbjgALWHHN0se88_Be7x5vqiCot1BzNrqg_EIXZ3t3DQpa-lLaRWXnNIwHxntB34zrhu1cPCVs4NnRDNLPnPAbykcbdEGRHl_bL6wrFVIEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46313","volume":""},{"id":6483,"author":"金信周; 吴金华","title":"两周颂扬铭文及其文化研究","abstract":"本文從漢語言文字學和文化學相結合的角度，討論了兩周時期的頌揚銘文，著重研究頌揚詞句的意義，並作了文化方面的專題研究。本文共分七章，主要內容如下：第一章緒論，主要介紹了本文的選題緣起及研究意義，回顧了相關頌揚銘文研究的現狀，說明了本文選定的語料和研究方法。第二章闡明了頌揚銘文的廣義和本文所探討的頌揚銘文的範圍，並將頌揚銘文的呈現方式分为用簡單詞句的頌揚銘文，單獨為頌揚而鑄造的頌揚銘文、其他格式銘文中的頌揚內容，考察了各種呈現方式中的主要用語、篇式、內容。第三章以銘文內容為準，對頌揚詞句進行分類，選取了政績類、謀猶類、威武類、恭敬謹慎類、明心類的主要頌揚詞句，通過相關文例的全盤分析和歸納，挖掘了新","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoArI4_KeTncZG5rd1xDD6uNB5D2QI6qslStNHVU3BrU1lEt541OJinrIBccWlbCjIQLxnH8LIFPBQZaEV1DVr4SIh-lCXIpVaPuhNj0UG5WkkXucZZ3jQfpJPFHERcwXxIB_P5bvzBPRRxXTlnKiFV94OUv21ef4LfHw2PhYblT3LIliwYNlS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6484,"author":"朱刚焄; 杨端志","title":"西周青铜器铭文复音词研究","abstract":"本文研究的课题是《西周青铜器铭文复音词研究》。古汉语词汇的研究是汉语词汇研究系统的一个极其重要的部分。因为古汉语词汇是现代汉语词汇的源头，古今汉语词汇虽然有各自不同的特点，但也有共同的基本规律。共同的东西体现了古今词汇的传承，而不同的东西体现了古今词汇的发展演变。正因为如此，古今汉语词汇才成为不可分割的整体。但值得注意的是：古汉语词汇以单音词为主，现代汉语词汇以复音词为主，这就是一个很大的不同点。那么，汉语词汇史当中复音词的源头到底是在哪一个时期呢?可以说是在甲骨文时期。因为在商代甲骨文时期出现的复音词数量并不多，从西周开始历代复音词都有所增加，构词的方法也由单音造词向复音词转变，所以我们通过","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhr3zNx0t5flm2SojE2hvycXz16sB2ZHn_T1VByqhCUtH8zG5Nmb-X_ASPvTqZ2PcOHzzqTZtfougOwYuys4gM4Uw-N9Am7gg2p6uiTFQN1u0vT1yujHzdWoa7craTO4b9WRi5oOmxO-tsYjjcMOnM03nGsdiOYAp66IF9NN40nJ_hunV8MUMa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6486,"author":"邵英; 王晖","title":"古文字形体考古研究","abstract":"甲骨文、金文等古文字形体是当时社会生活的真实反映，是上古社会历史文化的沉积物，具有“活化石”的特质。古文字形体蕴含着物质文化因素，亦为考古学研究内容，故其形体结构本身完全可以作为史料来运用。因此，由古文字的形象，可以推知初造文字时的一部分文化，更好地了解上古时期的部分历史和文化，例如：一、上古社会使用的渔猎工具与方法。古文字(?)(《合集》137)、(?)(《合集》9572)、(?)(《合集》8713)、(?)(北单爵)、(?)(单盉)：(?)(《合集》166)、(?)(《合集》7932)、(?)(《合集》20117)、(?)(商弓父庚卣)；(?)(《合集》23053)、(?)(《合集》230","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJR923eBSfoZnJ4oz8Wv4G4364JwsEGAQIB086TwL_zqUyF3YhxXQu71UpnVyuKKODKBgwa2083ZN1xro_TtBN0OxBWI_bkOtEcNlQ_MdT4-kLkxAUNqY-jrgs_osSGinEVlQBlLamksEsMVEkp3yogdhJQlx-XAHQEuzt8kQEQpB3b7mXwenFQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6489,"author":"冯华; 黄天树","title":"尔雅新证","abstract":"《爾雅》是一部重要的古代典籍，以前的學者多利用傳世文獻來研究《爾雅》。“爾雅新證”則是指利用出土的地下材料來校讀《爾雅》的研究方法。“爾雅新證”以甲骨文、金文、簡帛等古文字材料和一些非文字的考古材料來檢驗《爾雅》。“爾雅新證”一方面要訂正《爾雅》的訛誤，另一方面驗證《爾雅》的正確訓釋。通過新證，本文指出了《爾雅》的一些訛誤，同時也指出《爾雅》應該成書于戰國中晚期，並且《爾雅》的真實性是不容懷疑的。本文分為兩大部分，上編是爾雅新證的方法，即第一部分，有如下四章：第一章主要利用古文字字形進行新證，指出了《釋詁》“馘，獲也”、《釋訓》“暴虎，徒搏也”、《釋天》“何鼓謂之牽牛”等詞條的一些問題。第二章","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJGkK8x-UA11xCoeHmxkZVDbSwTzLTn3E1LaCP-6U7KoGN8A8NTXZPJYQ--WmR6MY4mzi87lkKj0kf8Lb3CYPpFzGLuUGHUwgmeP86-k92DvmBwj7CwNJK12bMekXqrlajS9zeArS3XQ4r9fLwee7YgwDU9RQrnrhUN_jaCv2nVk1cScSxtdqlg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6496,"author":"杨怀源; 彭裕商","title":"西周金文词汇研究","abstract":"出土文献研究中文字释读的研究非常深入与丰富，但是研究者很少把词义放进词义系统里来考察，这与语文学以解释经典为目的性质类似，与现代语言学的要求甚远。出土文献具有真实与稀有的特点，其中有不少不见于传世文献的语言现象。语言学家们对此有深刻的认识，但在实践上未能加以应有的利用，实践上语法研究成就最大，音韵次之，词汇方面则甚为薄弱，这种现状急待改变。金文研究发轫于宋，盛于清代，民国，已是古文字学四大分支学科之一，然而，现代语言学的介入，以语法和音韵为主，具有系统观念的金文词汇研究甚为少见，这也是急需解决的问题。自19世纪末甲骨文被发现以来，汉语词汇史的研究已经追溯到殷商晚期。由于汉语词汇史研究多以传世文","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLP7jRpttJlqjZi50mqrijzpf9_D-GKpxz0IEg9qbM_nPQ0BQcwUNMPaJKT-FgDOfiKvWKYOcMNOZeOiywW607RzLmgRu3DNuZcNuW_RIIQr2SWqouotnT4L6WvwZvspjF-LyzboG3iucR_qQqb-eqza23AM7RD8gIR5ojp5WBqh7txr1GlJ0lb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6498,"author":"武振玉; 吴振武","title":"两周金文词类研究（虚词篇）","abstract":"两周金文作为语料的价值被认识并且自觉运用到古汉语研究中是经过了一个较长的发展时期的。虽然早在二十世纪二十年代就已经有学者利用金文材料进行《尚书》的语言研究,此后亦不断有学者进行类似的研究,并且这些研究也多集中在虚词方面,但到目前为止,全面而系统的两周金文虚词研究尚付阙如。而随着《殷周金文集成》及其《引得》的编撰,对两周金文中的所有虚词进行全面而彻底的调查研究已成为可能,并且应是上古汉语虚词研究的当务之急。有鉴于此,本文选取两周金文中的虚词进行专门研究。研究范围包括两周金文中的代词、副词、介词、连词、叹词、语气词,共六类。其中对代词的词类归属考虑到了传统的看法及本文的体例。研究方法上则采用汉语史","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLByiII4k0pH0hm4Wj3SznrZ8yCxxpgz6MpGs6ZvQbIE8sKET2ZNib11P4WRcB0GtvQWYUBJFt7IaD_U5UgGCxZ_KcgWpiYP7yiT1UsbFY3-D7CTQwXloUJ0Q6QqHEB6Cdb3-L_1CCorBGVfJh9mW4PrUlCrt_MUxdq-C01l2NNiaL9w8cZ6JFE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6508,"author":"王颖; 臧克和","title":"战国中山国文字研究","abstract":"战国时期的中国是一个处于燕、赵、齐等大国夹缝中的中等国家,历史上关于它的记载很少。1979年河北省平山县发掘了几座战国墓葬,根据出土铜器上的铭文,证实为中山王的陵墓。此处出土了大批有铭器物,包括铜器、陶器、玉器和木器等,其中有几件铜器上的铭文篇幅很长,成为研究战国文字的重要资料。自这些文字材料发表以来,古文字研究者无不重视,各种考释类文章也陆续发表。但一直以来,国内对中山国文字的研究只停留在隶定与考释,尚无人从字形结构等方而作全面考察。中山国文字属于战国文字的范围,所以研究中山国文字就不能不以整个战国文字系统为背景。在战国时期的相当时间段落里,中山国作为方国之一,具有独特的战略地位,研究中山国","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLq-USFC-afTyE1HJqcKWY9uaNggCiQM5D4mQVucjAB1nvOX5JPmP_MKDcqBa2sMyGqw-MxB62dlBY5mz6FTf_N1njASsJVr1whB2Hxg8XU30P7xgOhqE5x3t9-jTe2dtu1ZpjGPuKDv2gToIhCTHMTKAiWDVKBRF9TwUVeNJ1HLpJyX5II4cGp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6848,"author":"葛力力","title":"字词辨析二题","abstract":"元·园·圆元、园、圆三字音相同,都读yuán,但是它们的意义相差很大。元,《说文解字》曰:&quot;始也&quot;。许慎著《说文》时尚未见甲骨文、金文等材料。从今天看到的甲骨文和金文可知,&quot;元&quot;的造字义应为人头。戴侗《六书故》曰:&quot;元,首也。从儿,从二。儿,古文人。二,古文上。人上为首。会意。&quot;高鸿缙在《中国字例》中说:&quot;元、兀一字,意为人之首也,名","categories":["02_字词句考释"],"year":2006,"publication":"江西省语言学会2006年年会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgXMEM0-uo8RewCb-iFe0B-0KwZOtKEYoheMnYsT8wh-WVyBz1e9j5XNE6kQecCFmp5RHu1jKnQ1QoZttFijPDKG-nPfEMznunDjwlp0003EXnDkL3_1SEDNXfbie8Lrgc90_3DMPhaUxKsOBbUHzRH9qWSG30DJEHJEJMrpPL7NhVec53ZSMB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-72","volume":""},{"id":6849,"author":"崔元; 杨端志","title":"金文本义正诂","abstract":"金文的研究是汉语史研究的重要方面，尤其在探求汉字的本义方面，研究者常以许慎《说文解字》为依据，但许慎没有甲骨文字和金文字的参照，分析的汉字字义有一些错讹之处，要追寻先民造字之初的本意，金文的字形起着重要的作用。历来对金文字义的研究都是零散的，本文试图以戴家祥的《金文大字典》为基础，用现代语义场理论研究金文本义。首先在第一章中探讨金文研究的意义和历史、现状；在第二章中，从《金文大字典》设定的273个部首入手，举例分析金文大字典中的部类构成的子语义场，并分析部分部首的更换情况；第三章则主要是两周汉语的总语义场分析，主要是对象(自然界、社会、人的精神世界)类语义场分析和运动(对象的运动、变化、行为、","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgzy2d1_FD6hN9KV5VUTpXF-je55E7LZ9E3fpfsM_opsSrjdU_mUqZ-elIIiNkBS64bi5IKm9eCsNhXj8D66cFtUwk4QTiErTQmB1cxJ11q2VKeombX62HAsmi8Satb8HnYDnM6-cgNMCT6_35HvDVMRs5QbNK9HclW5T4LRY-eLh1xAr9Wl1R&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6853,"author":"杨明明; 张希峰","title":"《殷周金文集成》所见叠音词的初步研究","abstract":"金文作為出土材料真實地記載了當時的語言，金文語言的研究是漢語史研究的一個重要部分。疊音詞作為漢語中一種特殊的語言現象，在金文中就已經出現了，為研究上古漢語詞彙提供了寶貴的資料。前人對金文的研究主要集中在對銘文的考釋上，對金文中疊音詞的專門研究卻很少，因此本文從原始材料出發，結合前人對文獻疊音詞研究的成果，就所收集的《殷周金文集成》中的疊音詞進行了初步的分析考察。通過對字形、字音、字義和文例的考察，引證文獻中疊音詞的用例，考釋每一個疊音詞在銘文中的意義，最後在對意義有一定認識的基礎上總結出金文疊音詞的部分特點。論文分為三個部分：一、緒論。闡述了本文的研究意義、研究歷史及現狀、研究範圍及方法，並對","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL1uPqoPNL7GvyeykVjQQG5pwCK7_TrsZLNYyiqJjkMhcEmRfCsrYPvVW_z5_0-9lyIsbBNPpX_GaBb215KxSKmJ-xeXG-7STQiNU5xPNkTCinwAw4dTtAXwS6g9xb48yXzJtyneypZPl_OHtE_OuVRtSjQ4z_ZQ4i7TPmacJHPABWy6URs2Lgj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6854,"author":"王伟; 黄天树","title":"两周金文中合成复音词及词组的初步研究","abstract":"詞彙是語法的重要組成部分。兩周金文詞彙上承甲骨文、商代金文，下啟秦漢，在語言史上具有重要的地位。兩周金文是一種同時材料，材料不僅豐富，而且真實可靠，是研究兩周時期語言與文化的理想語料。兩周詞彙研究對構建上古詞彙系統乃至整個漢語詞彙系統是必不可少的。本文以兩周時期的金文為研究物件，首先判定出其中的複合複音詞，然後再根據構詞方式的不同，從分類、例證、時間斷代、詞義、發展與傳承、語法特徵等方面進行討論。通過分析最後揭示兩周複合式複音詞的總體特徵，為以後漢語詞彙史作一些必要的基礎工作。","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxyMiXglh39T00Z6R7BDrGaXpoaeGLeORYlX2RRbCW2iSyX4XL9i8X61Mqet-PiQnlGjK3PPRBaOE2wL04cNAzIJeUTqkxcf27fIluIZ8g1L1FjtamSC-X1PI7KcT3rXiElMCcpWZuV2itleccQIFYb3Borocl51zE8XV84s2H5hifeuW8ymM2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6855,"author":"刘剑; 崔大庸","title":"洛庄汉墓五号坑铜器铭文初探","abstract":"铭文的研究一直是探究汉代铜器制造、使用和汉代手工业情况的重点。作为本文研究对象的洛庄汉墓5号坑出土的95件青铜器，包括鼎，钵，盆，匜，勺，釜，权，量等，其中有60件带有铭文，从数量上极大丰富了汉代铜器铭文的资料，虽然铭文篇幅很短，但是内容多是成组出现，有很强的规律性。本文简单介绍了5号陪葬坑出土铜器基本情况，依据铭文表面形态的类型对铭文的基本情况作了基本分析与分类。运用类型学的方法，将铭文分成不同组合，并在此基础上结合器型将铜器进行使用批次的区分，为进一步了解这批铜器的性质和使用情况奠定基础。由于铭文比较容易释读，结合《史记》《汉书》等文献，把这批铜器上的铭文同已经出土的封泥，简书，帛书，印章","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvEFBYzYi_xpB5e13AFJgv31DsWf8dr2_FthDOPdZgIUEWT086MNNyfTvpmHdrzYl96cTtTfKdZ-47slVOnko9KhHHQO-LprcLDPuHaDJ7KMja3LoSXXNsa_O0luR5j8k2jgKoRD6vd09Jar_oiM-0nhx5DdRjhaxYv1KTfp9wLK9zwSrBf-J7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6859,"author":"郭利芳; 张再兴","title":"春秋金文构件系统定量研究","abstract":"本論文主要是從構件的角度探討春秋金文的本體特徵和春秋金文在中國文字發展史上的地位與作用。對春秋金文構件的研究主要是以中國文字研究與應用中心開發的《金文資料庫》為平臺，對其中屬春秋的1250篇銘文進行系統研究。首先對春秋金文的字形作窮盡性的統計分析，確定所要選取的字形，而構件功能、文字本義等考釋基本有定論的字形是基本依據。全面分析，對文字系統各方面的特徵進行描述，從而對構件系統的研究提供可能。筆者對春秋金文中的構件做統計，排除未識構件和非基礎構件，得到基礎構件476個。根據構字能力不同，把構件分為四類，分別是構字能力強、次強、中、弱。按照這個順序，列表給出春秋金文構件的構字量，並標注其能否獨立構","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFEjF33gHwi7SZlcivYMyvgC3vcb9g01xY84hc1MzUGe24H0dfetqDuCjYU79mAy-iu1vc5XkK5Pn42NC2O_g9KP09MQgorK6W72U1rVMQiFNLHuaWPQW_R67Io6gpayE5MAW4KhcvMO6cSmfN-7N85Cri9zgNFMF43BGOBhNu1IWOhEotWJdT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6865,"author":"邱传亮; 李守奎","title":"楚玺文字集释","abstract":"楚璽文字是楚文字的重要組成部分之一。楚璽文字的研究對於楚國歷史地理、官制、姓氏文化、思想等方面的研究具有重要意義。但相對于楚系簡帛文字研究而言，楚璽文字的研究較為零散，尚未有人對此進行系統研究。本文擬對楚璽文字研究材料進行系統收集、整理。本文分為兩個部分：第一部分，楚璽文字研究綜述。這部分是對整個楚璽文字研究的歷史進程以及各階段的主要成果進行簡單地概括與回顧。第二部分是楚璽文字集釋。這部分是把目前所見到的楚璽文字按照《說文》次第排列，彙集各家對該字的考釋，最後依據自己的理解作出取捨。這是本文的主體部分，可分為十五卷，限於篇幅，本論文僅選擇卷一、卷二兩部分。","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmYMEiQ2cZnea_rd_ozjHSB8PnriSgXiT6VQbtkQ6CoqooYmXeWbL3dttfger_epKWfJF8qKbEA3vSNJiQ5NzttXAaMdk5iEeNqJAkfwmjKhmRpNnmjdZqYkMFZ5O2ERxLgTMocPdNSoRidN1Fc4lQ_E7vY_2VwXr-5yKoA-R2jqg8zHVBJIsV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6867,"author":"王卉; 詹鄞鑫","title":"汉代金文研究","abstract":"本论文以目前所能收集到的所有传世与出土的汉代金文(镜铭、印文、币文除外)为研究对象，在借鉴和吸收前人相关研究成果的基础上，运用综合分析及比较等方法从文字学等角度对汉代金文进行系统研究。本论文主要从以下几个角度展开研究：一，介绍汉代金文的书写特征、字体风格及规范程度，并分析讨论汉代金文字形特点研究。二，将汉代金文篆书与《说文解字》篆书做比较，分组列出所有构形与《说文》不同的篆书，讨论《说文》中实际存在问题的篆书。三，分析讨论汉代金文中的用字研究。","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIul4YRV7PeAccMH8zhTg_WV1mzaNKQvbjtUgNxQhvSWlzW7olwoxFSG2HGlGFebdpCtg7vPL6fHlywLL0pJr7G7wTGdlMHKMcdYWeIxlxrpCP5fCnl-Q7RSSbzZOnPI94_6PyOEDW3IyhG18_s5uPHcxo0FgBLRLiRIwqH8q2FV5qlmLBiuuLk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6870,"author":"张道升; 徐在国","title":"《行氣玉铭》辑考","abstract":"《行氣玉铭》现藏于天津历史博物馆，其形制为楞柱状，中空，顶端未透。器身琢为十二面，每面刻三个字，加重文符号，全文共四十五个字。《行氣玉铭》字数虽然不是很多，但是因为它是刻在玉器上，内容极为重要，是战国玉石文字最重要的资料之一。本文辑录了目前所能见到的所有研究《行氣玉铭》的文章，首列字形原拓，每个字形下按时间先后顺序排列各家的考释，各家的观点一目了然。最后是按语部分，对各家的观点进行评述，提出自己的看法。比如旧释为“(?)”的字，我们认为应该读为“撤”，训为“撤回”。本文分六个部分：一、概述；介绍《行氣玉铭》的形制等。二、文字辑考；分别将諸家考释进行辑录。三、铭文通释；全文今释。四、年代和国别；","categories":["02_字词句考释"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhEzQPCsu8-wb5GovAvaX2CoLxY2ZaFIvSKXoA_OB8il8Hg2Y1wk1A33AgHfE378o1jT8e8UjJA6arLsfG8ONKZtVPG6uWSN21OXxXyiBUyJ0gOnKJsw9q4c4SxLdUE1M3yF3N11bN9AAscsI6txJn76JoWkVXciNw3LjthO8foVLlayiZnbvw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7061,"author":"涂白奎","title":"对《舀鼎》铭文第二段的考释","abstract":"舀鼎铭拓自阮元著录于《积古斋钟鼎彝器款识》,至今已200年。由于其铭文内容关涉到对西周时期司法制度诸问题的研究,因此自铭拓问世以来,考释和研究者不啻十数家。舀鼎铭分三段,所记事类也不相同。第一段和第三段字句较为平实,各家考释基本无太大的分歧。考释分歧最严重的在第二段,由于该段所记人物较多,事件的进程也较复杂,又有一定数量的缺字,因此给考释带来相当的难度。其中,就该段铭文内容进行考释的,早期的研究以郭沫若先生为最著①。其后,姚孝遂、谭戒甫、孙常叙、晁福林、李学勤等先生也都撰文对此作了较为全面的研究②。笔者因教学之需,多次籀读各位先生的文章,觉得这些研究应是得失互见,而且还有一些问题似乎仍未得到解","categories":["02_字词句考释"],"year":2006,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIcL2cCkVMB6vomsIpuZzJGeAWZ71cO3C8n37q4lkYfbUUEFtHVBmSCDqM-UDaSg4cHguPIaKjZhQOnQ8ZGJKaVv3n2OfN48-DPSHy9DCxE5CoFA5D6bCSKBNtir79VFB7wQJEDP1ABO6Rec7Ol9t5ve1FYsGHEIivEaDDeD3VfKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"416-425","volume":""},{"id":7063,"author":"王恩田","title":"释■、■——兼论商代客馆与戍守制度","abstract":"武乙、文丁卜辞有:&quot;王作三■:右、中、左&quot;。(《粹》597)■,旧多释&quot;师&quot;,并以此作为商代已有常备军的证据。但武乙、文丁和帝乙、帝辛时期,有关战争的卜辞不少,却从来没见有使用&quot;三■&quot;或&quot;右■&quot;、&quot;中■&quot;、&quot;左■&quot;作战的记载。建立了军队而又不用来打仗,释&quot;师&quot;难以对此作出合理解释。此外,卜辞中■与寝对贞。而且还有&quot;大甲■&quot;辞例,大甲是殷人先王,释&quot;师&quot;则扦格难通。","categories":["02_字词句考释"],"year":2006,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKveQL8Mopu07K65JJxoqJYg-BKoSTHOkPwShwcq7tIqMLRUgxzygXIWaC56Q0YqobB4ogaNIFZqyFdZh9fIWm9o4ptaA868qFRmRWF_Be1exixTrlQZ3b0_v53LKSs0I6VZ-fTFh6igjkqrMAQLH7tgrV_86PWUX-Qp_MYYdUmhw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"308-324","volume":""},{"id":7068,"author":"罗泰","title":"西周铜器铭文的性质","abstract":"一铜器铭文作为礼仪信息及其作为史料的意义西周铜器铭文虽然不是当时唯一的文字材料,却是那个时代的直接证言。尽管铭文中的古文字有时很难读,但在几千年的流传过程中,铜器铭文未经窜改,而不像传世文献,几乎难逃此劫。铜器当然不是当时最常用的书写材料①:大部分西周文献当是写在竹木丝帛等易朽的材质上,而且西周早期还有甲骨文。即使按夏含夷的说法,铜器铭文是&quot;西周史料&quot;②,我们也有必要考虑铜器铭文在其他西周文字记录中的地位。铜器铭文究竟是什么性质的材料?它们是如何又是为何传达信息?前人研究,或着眼于文字考释,","categories":["02_字词句考释"],"year":2006,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmOWAf_GaMxaLwIYitp4CptysZvZsoTkKqkUlxk8ABTnsSwGvE-P-FhMXB5LQwJTavv-By6_PjA8_xkLOLDvZ_fdVFlM45eXz2-VTwi4-t74coqrON8LRP0iXEvCVVQ-fedZ-EE3zTOpslc_GI-kxZkOqRe9PJ997KLBtNHkNkvw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"343-374","volume":""},{"id":7070,"author":"李贤","title":"“(▉)孫”应为“弼孫”","abstract":"《保利藏金——保利艺术博物馆精品选》著录一鼎,有铭文六字,李零、董珊二位先生撰《（?）孙宋鼎》一文。根据作者描述,&quot;该鼎子母白,失盖。直腹,圆底,附耳,三兽首蹄足。器身饰蟠虺文及两道弦纹。附耳饰蟠龙纹。内壁有铭文2行6字:字体均匀修长,笔划精细而波曲,具有春秋时期南方诸侯国的字体特征。&quot;①该鼎铭文,李零、董珊二位先生隶定为&quot;（?）孫宋之飤鈑&quot;。其中第一个字（?）,作者认为从卩从人从攴,遂据《说文》&quot;色&quot;字从人从卩,隶定为&quot;（?）&quot;:又认为或从夕从丮省,隶定为&quot;（夕丮攴）&quot;,读&quot;宿孙&q","categories":["02_字词句考释"],"year":2006,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINfVl5gUBZvu717F_tLpiLeD7TW7PCRM_uNgofRz-8iuOORCZ10jOVi7QP2xIJoTG8b2w0KLLIjhUyjw7x1Ob34C9hGhjbEPbNCGSF9y7t_N-XGnfO4Wc5FNVFQX6VsH0DaIXhPoLR2m5OjH6NxusEaNUplORczhNuk_A3JqynIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59","volume":""},{"id":7071,"author":"吴红松","title":"释西周金文中的“裼”字","abstract":"西周铜器铭文中有一字作&quot;■&quot;或&quot;■&quot;形（为便于叙述,下文以△代之）,①见于西周中期的■盨和西周晚期的元年师■■,凡九见。其中,元年师■■的4279·2写法略异,现将诸形体列举如下:②A■4462■4463■4279·1■4280·1■4280·2■4281■4282·1■4282·2B■4279·2可以看出,A式的诸形体显然为一字。与A式相比,B式的形体在&quot;■&quot;部件旁少了一小半圆的笔画,但其与元年师■■中其他形体为同铭异器之文,所以B式与A式中的形体应为一字。","categories":["02_字词句考释"],"year":2006,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINfVl5gUBZvu717F_tLpiLeD7TW7PCRM_uNgofRz-8iuOORCZ10jOVc7oRQRtjEYxJt8MPB4MXYL-UVOIqmCVBSBLeFZZIKz9N1WKF98e_1aDXTMwMKjCmsQlK-QS9N3simlCcI9GNjynG5grGQMYottreMZOAvnzN54LwtckvZw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-62","volume":""},{"id":7072,"author":"李晓峰","title":"谈楚公逆钟中的“锡”字","abstract":"出土于M64的楚公逆钟有&quot;楚公逆用自作■△钟百■（肆）&quot;这一句话,其中△写作如下:■对于上揭这一字形,李学勤先生认为是&quot;燮&quot;、&quot;锡&quot;二字,但没有作出具体的解释。①黄锡全先生给这一形体做了分析,他认为:&quot;钟铭‘■'即和,‘锺'即钟。‘■'后一字隐约可见,作■。金文■、石鼓文■下列诸形:■■■■■■■很明显,钟铭之形当其省形,即■。《说文》:‘■,等也。从齐,妻声。'金文中鬲有称‘■鬲'（仲■父鬲）、鼎有称‘■鼎'（釐鼎）或‘■'（白六鼎、■鼎）、‘■■'（季无鼎）者。《周礼·司尊彝》有‘鬰齐',‘醴齐',‘盎齐',注云:‘故书","categories":["02_字词句考释"],"year":2006,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIIb-QbhSp8SGZgtnTVHjqqDiF2a433NSnMhX4ZDRYOP6tknHJWZbXr-UIXKcY7StT3eVYbzk2ScvtuxP1_PhjUMNz3J-rQzwAt-W2ytobtDKecyloN7szPAFYMwJgdwJWGCvAdLgDpHLyF4f6K5p2jRoc-We-IUUxIcp9Mp-WRg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":""},{"id":7073,"author":"俞绍宏","title":"兵器铭文释形(二则)","abstract":"一、释&quot;鋗&quot;焛令赵狈矛铭文(著录于《殷周金文集成》11561号)中有一字作A形(见文后附字形),《释文》与《引得》俱割裂字形,释此形为&quot;钴&quot;、&quot;户&quot;二字。按,此字左上的构字部件为&quot;金&quot;字,二家所释不误。而右边所从之形(见文后所附字形B),上从&quot;(?)&quot;,下从&quot;(?)&quot;;&quot;(?)&quot;又由两部分构成,即&quot;(?)&quot;、&quot;口&quot;。战国文字中的&quot;(?)&quot;多有用作装饰性构字部件的(如战国文字中的&quot;悁&qu","categories":["02_字词句考释"],"year":2006,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIIb-QbhSp8SGZgtnTVHjqqDiF2a433NSnMhX4ZDRYOP6tknHJWZbXrtjcKYZcsDeLN7zBBaw5FPveKul8q65mAzFWAD4RLTYb3DN9l6dw6kgESdCiXrksU9A0s4LhGnU7Fp8JDU6NhLCjLLOQZqL-_d_3SyxY9lzRyq7gd9_PLQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-67","volume":""},{"id":7075,"author":"许学仁","title":"出土文献中先秦儒家德目考辨二则","abstract":"本文根据金文、古玺、简帛等出土文献,整理&quot;仁&quot;、&quot;信&quot;两德目的构形字源及义蕴发展,并厘析&quot;仁&quot;、&quot;信&quot;偶见互讹之缘由。","categories":["02_字词句考释"],"year":2006,"publication":"传统中国研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0ZOVn7RXPzgPYJMvOsm2mgOyZHw70AhHYdBL-p3fau7-CcoWQfv5TcFU5CsuBizcrdUCw-j3ul_7Xzx6Zi9H-zLiWNAFQVVQCNgsriBbXDKtXGkjW8Xuu34Q3X_U59hTHOQYnKDtNohUYeh2hLtUkJfe8vpZp-hvbQBM__1wwEA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"288-293","volume":"1"},{"id":7076,"author":"王龙正","title":"金文“氏”字及其相关称谓(上篇)","abstract":"&quot;氏&quot;字,习见于两周金文,遍布于古代典籍。对其含义的正确解释,事关古代的称谓和宗法制度的理解问题。虽然学术界似有趋于某一说法的倾向,但事实并非如此。在多年收集资料的过程中,我们发现&quot;氏&quot;字在绝大多数情况下只是一个词缀,它联缀于某些名词的末尾,用以说明前者,表示第三人称单数,以显示对被称者的尊敬。它与前面的主词共同组成的新名词,近似于时下的&quot;某某先生&quot;、&quot;某某女士&quot;等称谓。而这种作为词缀(即&quot;词尾&quot;)使用的功能,应当是在单音节词向双音节词过渡时期才开始产生的。在少数情况下,只有当它单独、并且只能是","categories":["02_字词句考释"],"year":2006,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJPGZ2Wf8JnMj66c8ZCuxWkvjslKBOmuIDkrWsqyzWFZx8dVdvTK5FuD5FpkNFpGGdXIh7Iw4FJUf2W8VMViVH5zH-opHTwiE3MMjvqQIX9dgZDvIC4AVVJDDPp68J_MVr0bundEiCq_m9m9pd7LnssGu7sk0Xnb6AHQEcg50FieA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"165-190","volume":""},{"id":7081,"author":"董莲池","title":"古文字书编纂中应当注意的一个形体","abstract":"本文以小篆&quot;徙&quot;字为基础,上溯&quot;徙&quot;之源,下探&quot;徙&quot;之流,通过对&quot;徙&quot;字形体源流的梳理,否定了见于甲骨文、金文中那个从彳从止的形体是&quot;徒&quot;字的可能。认为只能释为延。","categories":["02_字词句考释"],"year":2006,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyBgkTmro8zVoE5A6t6PGgHcDQfq4pHxfTO5w2h-4S853bpJqY79wRZVgpXwRcZJEYBtCT2gq8ThUs_VAEPKSUhvR8mWe3Ltg0dM0NMmT5pbKLE0b9K5AN3xGCaswuECuwASvsKynvROcUNyuAJcojbShfdLUMt4pDwf-deRPKRQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46339","volume":""},{"id":7087,"author":"张再兴","title":"殷商西周金文中构件“鼎”的形体演变","abstract":"本文运用类型学的方法对殷商西周金文中的构件&quot;鼎&quot;的形体进行了分类,探讨了各类形体的存在时段,清理了其在殷商西周阶段的形体演变规律。在此基础上,还探讨了它与贝、鬲、甗等构件的关系。","categories":["02_字词句考释"],"year":2006,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKfxLJJ9xxgT0GJGiwaFOcufLUXjV0TYKNurdUp29MDkJzHjpcuQux9VhGmSTlVwiWAhUSPWYO-2-IkPFa8EaoiIlt9p8oJdxiu2KWcnKp7IJbHW_iYJIGEb_bsDi21pQw-e4_ucuUtD0i35lI4iREHXLPz05FNi1UKq76p0z72sg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"159-168","volume":""},{"id":7089,"author":"武振玉","title":"西周金文中“休”字的一种特殊用法","abstract":"&quot;休&quot;字甲骨文中已见,为地名用字。西周金文中,其词义词性已很丰富,如已有名词、动词、形容词等多种用法,其中用为形容词的一些&quot;休&quot;可以构成独词句,表示赞美等一类语义内容,带有明显的感叹色彩。&quot;休&quot;的这一用法,过去多被视为动词,本文通过对相关用例的重新梳理,认为其中的&quot;休&quot;都应单独断句,是由一个词构成的感叹句。","categories":["02_字词句考释"],"year":2006,"publication":"华夏文化论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKtqTMyvzOCy8tdesIazuiHGAxmxH4qNin1C-xe6rfgkuqC6tkZ-aGgvTszqpDGkpRTU-JxhGs8x6eXLSwFfY43JAix-334sN6LL5nc7DZlPJA2o2qbMQxbCubu4TL-uSyq_xPZ1EuiURiWQITF3cprFQo1DuNWEovC_L8FT8NSZA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-133","volume":""},{"id":7090,"author":"赵超; 杨寅庆","title":"“始”字考辨","abstract":"","categories":["02_字词句考释"],"year":2006,"publication":"现代语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKdxgmMtv4DcTENPpFKk8XcLNQ44q1qSk5R3XgdOx94NysOS9krNRV3_ycTJvcrXwzhgsaqsvRZbV2MfW1yD8VIX-nbSZfOjAFVLALhK7mblO9dhYlwtbYi4dXJgO8NJbGp6HzSEIyqeMMR7TpcQGTDtWANFW0LGExetEmOT9UsfLp8hP3lxp3b&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-125","volume":""},{"id":7091,"author":"崔元","title":"金文“言”部词义系统分","abstract":"","categories":["02_字词句考释"],"year":2006,"publication":"现代语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKdxgmMtv4DcTENPpFKk8XcLNQ44q1qSk5R3XgdOx94N7JVO6Dz6Wruwph7CIk6Vy2VaFUu5pMi05trpTlGGj9o59SkMV02rjESyRC9OncVYgikVxz9VeKHnbuxlopAkpXNQx311cyWbMMFM-tp9VvuIYD1lZ3d9hO095rVdn5Cty3i-gSC523l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"121-122","volume":""},{"id":7092,"author":"武振玉","title":"两周金文“亡”字用法初论","abstract":"&quot;亡&quot;字甲骨文中已见,关于其词性,各家一致肯定的是用为否定动词。如管燮初谓&quot;叙述征伐、田猎及日常生活的动词大部分是外动词,如正、伐、敦、逐、获、擒、令、乎、又（有）、亡&quot;;[1]陈梦家谓&quot;‘亡'义为‘无'或‘没有',乃是动词&quot;;[2]张玉金在《甲骨文语法学》中将&quot;亡&quot;与&quot;出、在、有、丧、死&quot;等一起列入了&quot;存现消失动词&quot;下;[3]沈培说&quot;现在我们还没有足够的证据能证明卜辞中有的‘亡'已通用为副词‘毋'。这样,像‘多祖亡害我'的句子结构就应当是……动宾结构‘害我'作动词","categories":["02_字词句考释"],"year":2006,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLpKIpPFDe3OwsXL1AlU278JA9aOOjgJolDlk3PN68q8M4rtnVNA-9N4eWlWGYVK2zy_xPZcKF-SrPLAn3E1A08VxLohy3-1T4UnxR9qIVkP3QfP3yD9EGR56PEuywH1qWpT-jSGpN7bjTH6WT1Clz0rmqyi9ca41uewNfJSfM95A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-117","volume":""},{"id":7096,"author":"凌知易; 朱祥林","title":"有关■公盨的几点看法","abstract":"2002年10月21日,《北京晚报》刊登记者丁肇文先生所作的考古学术研究动态报道——青铜器■公盨首展。据报道,这件■公盨是当年春天北京保利艺术博物馆专家在海外文物市场上偶然发现的。当时盨盖已失,只存器身,且大半为土锈所掩。显露部分的铭文,文辞古奥,难以释读,给人以无头无尾的感觉。由于器上有近百字的铭文,该博物馆专家意识到其中可能蕴含着重大的价值,故他与这件青铜器的持有者商","categories":["02_字词句考释"],"year":2006,"publication":"杭州文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJc9yyNMsW7UmeQfq8HiXJVrUyh-AFh30mbSuvlXKtk0ZdBN9Aof_brVpzZhtIxx-rkf-7dY8Nb6_PdknFhKSr5fdmegCyUJ3dPDu-bXrYvHi7IZecmQzXl7_gkKvOxkYpPt3g7DGhinoh818xD5nxn7e6XJ3NKVhXjOrup3sjQ6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-52","volume":""},{"id":4854,"author":"王长丰","title":"《静方鼎》的时代及其铭文书写者职官考","abstract":"静方鼎现藏日本出光美术馆,曾刊于出光美术馆《馆藏名品选》（东京,1996年版,图版67）。一九九五～一九九七年北大考古系徐天进先生曾对其实测和墨拓1。《静方鼎》释文如下:唯十月甲子,王在宗周。令师中暨静省南国,相埶位。八月初吉庚申至,告于成周。月暨望丁丑,王在成周大室,令静曰:“俾汝司在曾、鄂师。”王曰:“静,赐汝鬯、旂、市,采?,曰用事”。静扬天子休,用作父丁宝尊彝。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6Y56aF7x8DqPQqy89AiHlqrI8pPz5p6NRkvXAmwwWfzdOhdjUR5Ve90dhuKvmGtEWnKSZqFIyWsTR2vJ2-VGaNwe5cjwffCGLuEGItU7vu4rPmEmZruFTQJLMgi3epmkVASl5KsWAimCTptWJkeDiSFsCS2iv6mChUCrSR2bsVzUvO1SUmfNO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-63","volume":""},{"id":4856,"author":"连劭名","title":"商周青铜器铭文新证","abstract":"一晚商青铜器《乙亥簋》铭文云:乙亥,王赐■舟玉■十丰章,用作祖丁彝。《集成》3940“■舟”是人名。“玉”字之前的一字应是地名,如西周铜器《善鼎》铭文记善辅助■侯“监■师戌”,《静簋》铭文记“王以吴□、吕刚合■师邦周射于大池”。“丰”,王国维释为“珏”字,殷墟卜辞作丰（《后》上26）,金文作丰,皆古■字。1殷墟历组卜辞中有:庚午,贞秋大称,于帝五丰臣血,在祖乙宗卜。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUAFbll24lRYzwW85UJXooUMVjln0C1w6xcYjq7nl8Pd0C3Jvmayguv5F_2C7sOLUWWMsxJeaZZTSA07mEVFXGOOOmwlqQ8KIsHpyAhUl4rN7kDDQh0IdovnBFisIrW4eJ4xXzbA-u3fFHIPettHy1uuK9TFcpY-NoluTN0YqM_g6I6Evb-q_K&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-52","volume":""},{"id":4857,"author":"张玉金","title":"再论德方鼎铭文","abstract":"德方鼎铭的释文如下:隹（唯）三月,王才（在）成周,■（延）珷（武）祼自蒿（镐）。咸,王易（赐）■（德）贝廿朋,用乍（作）宝■（尊）彝。（《集成》5·2661）陈梦家（1955）1把“德方鼎”定为成王器,郭沫若（1958）2、唐兰（1986）3、王世民（1999）4、刘启益（2002）5、彭裕商（2003）6等皆从之。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRl3WraL6jl39g_IYW2X_IXVWE_bN4meaKNBplQg0lFOUnJrTUq-kHXCD4LzwYH4iAtw35MIPCbVto8BNXSWAWAg29XGIYWgt-69MmHHR5Yf2ZeAaDGELwM_SXvQ5kSqWR_hZGmkHhhcccOQIEIa6zx07glEmDvf39TCD79et3BOAgT_VQgy9g&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-56","volume":""},{"id":4858,"author":"刘桓","title":"师■鼎铭考释","abstract":"师■鼎系1974年12月5日在陕西省扶风县强家村出土1。该器铭文发表后,诸家论及该铭的论文已有数篇2。其中如王慎行先生《师■鼎铭文通释释论》一文对全铭作了通释、今译,并就有关问题有所探讨;于豪亮先生《陕西省扶风县强家村出土虢季家族铜器铭文考释》一文,对全铭重点作了释读。个人在该铭发表后亦写有考释文章,置之箧中。其后拜读以上两文及有关论文,又对拙作有所修改,删削所见略同的部分,而稍增益有新见和有补充意见的部分,发表于此。不当之处,敬希方家指正。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRl3WraL6jl39g_IYW2X_IXVWE_bN4meaKNBplQg0lFOUnJrTUq-kHwzcIQ8UVhQSgnFOuGw-YDQ8JPaXSwm5hifjq9t82kMp1cABUVZq0PTEALxZ9O_J2F8cB_86lnHMJjM3m3RSXMWcNpfwD-E5SlslWTQzoYcRm8g4wYCLRgCIHImccb15V&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-59, 63","volume":""},{"id":4859,"author":"张光裕","title":"新见老簋铭文及其年代","abstract":"丙子四月,气秉清和,以机缘获见老簋乙器（图一）。是器侈口附耳、方座,体饰直条瓦纹。通高27、至口高24、口径21、方座高10、底径20.7厘米。器内底铭文43字（图二）隹五月初吉王在■京鱼于大■,王蔑老■,易鱼百,老拜?首,皇扬王休,用乍且日乙■彝,其万年用夙夜于宗内容虽然简单,惟所涉事类则足资研读金文学者援引参证,兹摘要述释如下:壹、「王在■京,鱼于大■京一地,论者多家,自阮元释为邦字异文以来1,迄未有定说,然纭纭众说中,主要仍集中于“方”、“镐”、“丰”三说之讨论:一、方,方濬益:“当为方之繁文,……六月侵镐及方,……镐即镐京,方即此■京,方■古今字也。”","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHCg1P4KIxZwXKcEBYNwwvo0ur-mnChvVEf90GGC6z__IQFEvuOs2ajOVDZu76y5-O7pTiD9DDT2zxGDBEyRPnppqP7Hyf_DrhdtN78ZJxqROcPwR0MUe7lY_GiRO5DPSanG7dY-8nGbXngrRXSE_qRd7K8n7sdtflujKpKsmidM01lh8HzRNM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-68, 71","volume":""},{"id":4860,"author":"白光琦","title":"师酉鼎与师酉簋非一人器","abstract":"保利艺术博物馆所得师酉鼎,已由朱凤瀚先生著文予以介绍,并做了合理的的断代和考释1,在西周年代研究中提出了新的见解。但在相关铜器的讨论中,将师酉鼎与师酉簋断为一人之器,又以师訇为师酉之子,将訇簋与师訇簋断入西周晚期,不免引出许多矛盾。今略陈鄙见,就正于学者。师酉鼎的王世师酉鼎是附耳细柱足盆鼎,浅腹略外垂,与之形近者有伯唐父鼎、作册寓鼎、七年趞曹鼎和师父鼎。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDb7g25l5WXuwFmQcu0gbHM5PHsz8y3hyamz5L8pEJDDLAeG5gVy8awcU1bZ95PhSM1mOLqbOZLqpk2dTpGLkKzKY790q-ZlweRfOrBiNIKHoURh9m-vrZtdsXAI1_Aa8C25463wyWTK98G_B7nKtLTNCnLgBQtUYDaio8GL2AqjBF3U8pwBus&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-71","volume":""},{"id":4861,"author":"吴镇烽","title":"■鼎铭文考释","abstract":"1995年6月的一天,陕西省咸阳市渭城公安分局文物派出所收缴了一批文物,邀请省文物鉴定委员会派员鉴定,侯养民、呼林贵、王翰章、禚振西、刘合心和我等位委员前往咸阳,对这批文物作了认真的鉴定。这批文物有青铜器、陶俑、陶器、石刻等,从周秦汉唐到明清各个时代都有,当中有许多珍品。对于三级以上的珍贵文物王翰章先生都作了纪录,刘合心先生进行了拍照,青铜器有铭文者,我都一一作了拓印。时隔九年,近日整理自己收藏的拓本,发现当年的■鼎拓本至今仍未发表,现介绍如下,并对其铭文作以考释,以飨读者。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDb7g25l5WXuwFmQcu0gbHM5PHsz8y3hyamz5L8pEJDDLAeG5gVy8aIPsLlh5GIZvL-MWBSM3hTLeqSgT9exzyKxNX6nd1BjYuU12aOQp6s6klCKXnNp-yhKcVu6WuMjVKf9Q_HH7KCImbKomk-fmrP9S9XW3ON3u4WXUGN4rjaKYwy9XCr3Zm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-75","volume":""},{"id":4863,"author":"杨泽生","title":"西安丰镐遗址出土的当卢铭文“鼓师”","abstract":"在西安丰镐遗址出土的当卢中有所谓的“丰师”二字铭文:1原拓片为反文,为了方便,我们将它反正过来一并揭示如上。由于商周金文“师”前冠以地名称“某师”的情况比较普遍2,所以“丰师”铭文在丰镐遗址出现似乎是很自然的事情。但铭文第一字释“丰”并不可靠,试比较金文“壴”、“丰（豐）”二字:可见,此字实应释“壴”。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKybLIA7b6daqlsuE9fZb-EoqrNLeI72aiqLbVz42wocKSUJ6OqYHOekc8aZcP2zfKiKX7P4ju-fbRIwXq19zA41zq0s3ZZVaiC2idQRFiRLrYXmH_yC17zlWEYYqHyaJmc7FXVusOMjy7wDTsL4wN18RBsY26uoYc3gcNLdab0XyPB48aeXZ2p&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79, 78","volume":""},{"id":4865,"author":"郭莉","title":"金文中“■”、“师”、“帀”用法刍议","abstract":"金文中“自”、“师”“帀”都用“师”,《金文常用字典》认为:“于省吾先生认为:‘甲骨文和西周金文师旅之师均作自:而西周金文职官之名则多作师。’亦有迳作自者,如……训小自之自殆自之省变,与自（师）旅之自（师）当非一源。”师“或省自作帀”1。本文在对金文中“自”、“师”、“帀”用法进行穷尽式调查后,对此又有一些新的补充:“自”“师”“帀”分别流行于不同的时代,在先秦既互有通用,但又各有侧重（年代及义项的分布见文末附表）。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDzhbUXYmaln1uWid285OjINCtlA9fffG8ymQouHlRnk6Hpj9XXieZHAAi57m2SAYZOdiKWYe53UEVZvAYUOMySrtp0Fa66aZEOXNdRDEFciIuUVA64vWi_3iWPa342si8atXIZ78nmea53FJmGgFP_4Fa6NE8IMnQBO84qk9kRWbvjhot2Du5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-89","volume":""},{"id":4867,"author":"何琳仪; 胡长春","title":"释攀","abstract":"陕西省宝鸡市眉县新近发现一处完整的青铜器窖藏,计有27件铜器,均载铭文。其中逨盘和逨鼎是有明确记年的宣王标准器,已引起学界的高度重视1。盘、鼎铭文中“■司”一词,在已往发现的西周铜器铭文中曾多次出现,然而古文字学者对其释读迄今尚未取得共识。“■司”一词的再度出现,引起笔者对其重新推敲的兴趣。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWMZ3Oi9pDeO5KkhxE_xUp7SvN7E17XMb5YIyjID8G4O51ibIDaxChC19_74UKUv_EN5yd4Iz7E27uwCG2Fxmouz8EnSvFFBY-7WFkL3HeFLtgj3jvPvnXHHAKtSNklC0ebvHP8BeUluRKmYvMC3a4wygGq4UsIshh8NMLPT1hkUeVnakklj4D&amp;uniplatform=NZKPT&amp;language=CHS","pages":"103-109","volume":""},{"id":4868,"author":"涂白奎","title":"说西周金文中的“狐”字","abstract":"要说西周金文中的狐字,还得从战国文字中的狐字说起。战国文字中的“狐”字,旧时只见于古玺文。罗福颐先生主编的《古玺汇编》一书收录有三方,分别见于0646(■)、3986 (■)、3987(■)号。狐字之形皆作左犬右瓜,只是瓜字之形从人或反人,而于人的躯干处膨出作圆点状。瓜字的这种写法与《说文解字》所录篆文以及战国青铜器《令狐君壶》中被读作“狐”的“瓜”字的写法有相当的距离,因此给对它的识读带来一些困难。好在3986、3987的玺文分别为令狐佗、令狐买,令狐氏因为大家熟知,所以根据对玺文的推勘,对“狐”的识读也并不存在什么困难。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICBsdEJgFk3WdQ6luRf9hfSeYnDIdM6MkvJAp_1Zl3AAINU0tttP9p-Lx4tELx3zFZ_YbbtDq30VJhz1OIRcqyJT0Fr4UNTKGnJwVJS_b-T4W1BmxxqzZxDMRCsC-ReQ63Yzg6CzkXlTx8rsxTO51W3lfiI-e5zOwN5qKE_YRbSOeabUMDTrte&amp;uniplatform=NZKPT&amp;language=CHS","pages":"110-112","volume":""},{"id":4869,"author":"刘志基","title":"也说“严在上,翼在下”之“翼”","abstract":"“严在上,翼在下”为西周中晚期金文中习见套语,又见于最新出土的■盘铭文中1。王辉先生释此语曰:“严,威严。《诗·小雅·六月》:‘有严有翼,具武之服。’周人以为先祖皆威严地在上帝处,故曰‘在上’。廙读为翼,敬也。”2王人聪先生近年也对此语作过专题讨论3,他的意见与王辉先生之说有所不同,认为严、翼皆训敬:“严与翼互文见义,都是表示恭敬的意思。两句的意义互补,“严在上,翼在下’,即是‘严翼在上下’,句中的‘上下’为偏义复词,偏用上义,与‘文王陟降,在帝左右’句中的复词陟降偏用陟义相同。”比较两说,分歧只在“严”字上,对翼的认识是一致的。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9s38poEHMLoIXGjGk-MPllbt4XjA5fmUCZcZMp1itGZdtum-r8oaL_7czGQiPfOLCCLVcNVyxhrBBAd59a4m9-PO45iTvWeqWJZZehGN04XOsfJEI8l8NelglNiJ1L78srz-u5xwikMcLW2zc36y-zTFg3N0V5oFZ28yvuaGIS2UOD9yKLHWg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"113-114","volume":""},{"id":4870,"author":"黄爱梅","title":"士山盘铭补义","abstract":"2002年第1期《中国历史文物》上,朱凤瀚先生首次刊布了中国历史博物馆馆藏的士山盘。对于这篇非常重要的西周金文材料,此后黄锡全、董珊、杨坤、陈英杰、晃福林等先生都对其释文及意义发表了自己的看法1。综观以上各家观点,笔者感到尚有余义,就此提出一点拙见,以就正于方家。先将释文列下:唯王十又六年九月既生霸甲申,王在周新宫。王各大室,即位。","categories":["02_字词句考释"],"year":2005,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9s38poEHMLoIXGjGk-MPllbt4XjA5fmUCZcZMp1itGZdtum-r8oaLZPVdiI3kpGoSRBc8diJaFIJZBQdus5TGS8avbbtwL5JTExn8jnqRfvUB_s8_i6Kt1FcxoZPN_D6xQ-XDVFbZS7Mb89GSjoFuFN-pm1O7C5GS7li9eHIc6uwhrGgRWCfX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-123","volume":""},{"id":5840,"author":"彭曦","title":"作册艺鬲铭文简释","abstract":"《作册艺鬲》铭文之书法特点可证为西周晚期,时代约当厉、宣时期。作册职官于西周晚期非但未曾“消失”,而且权力尚重。此铭反映出西周晚期礼崩乐坏的某些情况。","categories":["02_字词句考释"],"year":2005,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2005.06.011","pages":"49-50","volume":""},{"id":5842,"author":"张玉金","title":"西周汉语第一人称代词称数问题研究","abstract":"根据称数的不同,可以把西周汉语中的“余(予)”“朕”“我”“”“吾”五个第一人称代词分为两类:一类是只指称单数的,如“余(予)”“朕”“”;一类是既可指称单数又可指称复数的,如“我”“吾”。对每一个第一人称代词的称数情况进行论证和统计,重点讨论“我”在称数方面的历史变化及原因。","categories":["02_字词句考释"],"year":2005,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKC3QygoPv_hca4TeK43cC33H8pNoGn2MTZGwhDzxwQJfsZK-sTbM2ilSwKLgv5nZgeo65OZXIjPMZ3spV5NA3BqnMP12KdbuKx6_c7LUZ8VQzwKNSt-anQ0x6F2PX98NCJ1D3AgTVJyQsUsYHesbS0DDgNLFHUxd9i1WUR5sGk2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-79, 106, 159","volume":""},{"id":5843,"author":"段德新","title":"国宝何尊与“中国”","abstract":"“中”和“国”两字在商周时代的甲骨文、金文中很多见。如在宝鸡山土的西周早期的何尊(图一)、大盂鼎,中期的卫簋,晚期的比鼎、毛公鼎等鸿宝重器的铭文中的,都有“(?)”、“(?)”和“或”、“彧”(图二)。依照汉字的造字规则,大多数学者都认为甲骨文“(?)”和金文“(?)”,就是象形字, 象征着居于军队中央,指挥士兵作战的旗帜,即旌旗。中间为旗,上下各飘着为旗游,这种由各种飘带","categories":["02_字词句考释"],"year":2005,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKC3QygoPv_hca4TeK43cC33H8pNoGn2MR8jFuebdG4ScNUQewn1_3BzzNOo-lpVkvyF0OS_B2-c4VJpYtDao51CJs1hgCTfJr21WZ6K1zeHOtIy96Rt-Rpvd_xJ6-CtFcWYl9awSo1Q5A23giHQylBiSWhoS4IZuUD8629vXSimA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-31","volume":""},{"id":5844,"author":"侯乃峰","title":"秦骃祷病玉版铭文集解","abstract":"秦骃祷病玉版是近些年来发现的重要的战国秦系文字材料, 传出土于华山地区,原藏私人手中,现归上海博物馆。自李零先生发表《秦骃祷病玉版的研究》 (以下简称李文),公布原物照片、铭文摹本及释文后,许多学者都对此物表示出很大的兴趣,先后发表了专门的研究文章,如李学勤先生的《秦玉牍索隐》(以下简称《索隐》),","categories":["02_字词句考释"],"year":2005,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIN2Es4xLUQu247dKtttGl30K8nX8ut4BFnhd3Th_2cmbKqnQDd6W3XlrTEAYcQCk9xnXlD6blGuqtXmRwrCWIA8K0vQfc-aS_kCdF4P-eadWew2pnXeFsUiUPB-z0CSrLeAl2O0dklqi9E7tvmYdrceQPXpB4GARbUfbTMJTyyDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-75","volume":""},{"id":5845,"author":"胡长春","title":"金文考释四则","abstract":"青铜器铭文习称金文。重视金文资料的搜集整理,一直是金文研究的优良传统。殷周金文在古文字学、上古史研究上占有重要地位。目前收录金文数量最多、最具权威性的著作无疑是《殷周金文集成》。该书共十八册,收录青铜器铭文11983器。该书出版后,又新出土了一批宝贵的殷周铜器铭文,涉及宗周王室、列国王室的世系、职官、礼制以及殷周古族等诸多方面内容。近年来本人搜集整理了新出土青铜器铭文成《新出殷周金文集成》一编,共得铭文1517器,其中有许多重器如晋侯苏钟、子犯编钟、吴虎鼎、史密簋、逨盘等,并就部分字词作了考释。","categories":["02_字词句考释"],"year":2005,"publication":"学术界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIN2Es4xLUQu247dKtttGl30K8nX8ut4BHryILFEpx8tYC4Ej0nllCwlglzdLIGh_Zr8oxTkOju38uL_5kD8FJ-N7z1q_k6jrP0LKBnT0QF3MbdBc32nu1GFdTtVyODva92IlxB8TFRNecQ0qQtLpNnXtzMLStaOFBHsAuQDoxUsA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"148-152","volume":""},{"id":5847,"author":"陈鸿","title":"战国形声字之异体与战国古音研究","abstract":"战国文字的谐声现象是研究战国语音的重要凭借。从异体字不同的声符入手来研究战国古音,也是比较值得肯定的 办法。战国形声字的异体字有三个种类:换用不同的声符、换用不同的形符、换用不同的声符和形符。在声母方面的特点是:以本 组声母自谐为主,舌上音本组之间的关系密切,尤其是余母、定母更为突出。唇音帮、滂、并关系密切。喉音见、溪、群及影、匣关系 密切。在韵母方面的特点是:以本母自谐为主,这种现象比声母更突出。","categories":["02_字词句考释"],"year":2005,"publication":"闽江学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI94VKqF03mtCpP6aCtlOl6xtspeC-A3aPhK9ipyDJhZ4AAslHoxQP1xsHkwHQ9InsZKxtXb2PY3d56fJ4UYZ27h0GHFkcZ39iMyjQzkw90ncBdNGckxAvX1c1em7ivIaDU9XN1w2Y6zH8N-ruYvlDF-4-Ft06hxfNvmrtaVxjKGg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-105","volume":""},{"id":5849,"author":"魏建震","title":"“王何立事”戈铭文及其相关问题","abstract":"本文对出土于山西临县窑头村的“王何立事”戈的铭文进行了研究,认为“王何立事”是古代一种纪年方法,王何并非此兵器的监造者,此戈的监造者为赵国某位地位较高的大臣,“王何立事”所记之年可能为赵武灵王去世之年。","categories":["02_字词句考释"],"year":2005,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKANjm_mML7XMSkDi_w-Qf956GGebzeND4JqgbyblapT3VdzG_Ys2qOqKPDN66JKz2gXiycsloMiJYsWTW5yD2V-KIcnOeYevoJdGMMz8MazuLrIaLCNbKncx9eYGQBBT_As3x_HfbXr-hy2lnD3GHWTkZj0wHyBPFybM-n6-tYOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-56, 68","volume":""},{"id":5853,"author":"董珊","title":"秦子姬簋盖初探","abstract":"珍秦斋藏秦子姬簋盖是新发现的春秋早期秦铭文材料。本文解释了铭文词句,又根据《史记·秦本纪》的有关记载,并参考宝鸡太公庙出土秦武公及王姬钟铭文的研究,认为铭文中的“秦子”是指秦出子,“秦子姬”乃是其生母“鲁姬子”。这对于讨论青铜器铭文研究中的“秦子”问题以及秦国早期历史的探索,有一定的参考价值。","categories":["02_字词句考释"],"year":2005,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2005.06.003","pages":"27-32, 155-156","volume":""},{"id":5854,"author":"武振玉","title":"试论“既”字在金文中的用法","abstract":"“既”是古代汉语中的常用词,不但出现频率高,应用时间长,且用法丰富。金文代表了其早期应用的一个重要方面,其中“既”有动词、时间副词、关联副词三种用法,对其进行调查分析不但可为了解该词的早期发展轨迹提供重要线索,亦可为传世文献相关研究提供佐证。","categories":["02_字词句考释"],"year":2005,"publication":"苏州科技学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPPc0UWmqC5jmvZNHKELdzcSYOfJlCs_X0d2tWLoSEFjVtGVOM4XC0yXRXG2aEZ963W9fJkyJI4Lhh4Yy2EsS_Jly2azjNzBObnlNo2-c-A1bYIEUkX80bAkR0zaCoPUo_oPnlVpwIPG-lnrwV5kZRPT4_GhLAmmKczr3nV1QzAQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-72","volume":""},{"id":5855,"author":"吴振武","title":"关于新见垣上官鼎铭文的释读","abstract":"洛阳大学所藏垣上官鼎是一件新公布的魏国记容铜器。据该鼎的铭文内容和实测容量,可以推算出战国时期“”的量值约合今53.5毫升。这一数值既可以用来重新考量传世的半灷量铭文之释读,同时也可以合理的解释《考工记》中所见的量名“”。","categories":["02_字词句考释"],"year":2005,"publication":"吉林大学社会科学学报","link":"","pages":"46152","volume":""},{"id":5858,"author":"裘锡圭","title":"商铜鼋铭补释","abstract":"《中国历史文物》2005年第1期发表了中国国家博物馆在2003年征集到的一件商代晚期铜鼋的器形和铭文。同期还发表了李学勤、朱凤瀚、王冠英三位先生的考释文章,即《作册般铜鼋考释》、《作册般鼋探析》和《作册般铜鼋三考》(以下简称&quot;李文&quot;、&quot;朱文&quot;、&quot;王文&quot;)。这三篇文章对铜鼋铭文作了很好的考释,读后获益甚多,现将可以补充三文或与三文不同的意见简述于下,以供参考。","categories":["02_字词句考释"],"year":2005,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIhPse4f9bVOISJSIV9SBTebfKoHzBF3TchEbXXu0OmuEPoxuzALlRT71Ay3DomF2r6xXr-99c8bntSkU5tsyovL9kpiIuViVVFLMB3o1c88Y2PEmIkoU_GWFErnsQ77QI2qxtACM4FXMqx0WPHQD_wIlnmUIw8sI64moMTWnWDMw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46117","volume":""},{"id":5859,"author":"严志斌","title":"季姬方尊补释","abstract":"本文对季姬方尊的铭文进行重新隶释,认为器主当是(?)季姬,铭文内容表明周王嫁女所赐是一个有一定规模的生产单位。","categories":["02_字词句考释"],"year":2005,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJE8QtJkoN7EeFqDWZP32M4To9pj3v9dzctR5nCuvTEcd1Skml7xl0Mn9qYVDWwCQRBqvft3aWyCaVxKpGe0ujQL5udQvHgUT2aDdiQ7MXuvNTNjhNuWl-MHuSrknMt59Z7LFzNezEg9G5HDD7ha3wxtP6jrzSMKveBCqCDHFPlOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-18","volume":""},{"id":5861,"author":"武振玉","title":"金文“于”并列连词用法辩正","abstract":"“于”可以表示并列关系,早期辞书多有论及,然所举例子多只限于《尚书》。甲骨文中“于”有用为并列连词的,各家所举多有不同,然能确定的只有一例。甲、金文中又均有两个“于”连用于一句中的形式,过去多谓其中的后一个“于”为并列连词,但陆续有学者提出反对意见。本文通过对金文中“于”字的调查以及与“雩”的对比,认为金文中“于”没有并列连词用法。","categories":["02_字词句考释"],"year":2005,"publication":"长春大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJE8QtJkoN7EeFqDWZP32M4To9pj3v9dzcDDJLieDg4aU4Ll-yIDIcd-dkI7C8wcqqZ4IEBPh0PLf-CGKef8C-juvRZOcORBt7uvU8TyWRFw1giMNOSbR7jn5_6axDE6kHZmaT4y0VNUZhas53aFGymIQUdDi625aUSKfDnYLFS_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-45","volume":""},{"id":5866,"author":"王俊","title":"榆次市猫儿岭墓地发现的两枚战国铜印考释","abstract":"1998年榆次东外环猫儿岭战国墓M139中出土了两枚铜印,发掘简报对其作了初步考释。由于猫儿岭墓的的族属、国别历来分歧较多,对出土的铜印研究无疑是解决这一问题的宝贵材料。本文力图通过对印文的考释在这一方面做出客观的探索。","categories":["02_字词句考释"],"year":2005,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2005.05.010","pages":"45-47, 60","volume":""},{"id":5867,"author":"武振玉","title":"金文中的连词“而”","abstract":"“而”是古汉语中一个重要的连词,不但出现频率高,延用时间长,且用法丰富。已往的研究多侧重于传世丈献中的连词“而”,对出土文献,如金文所反映的其早期应用情况尚缺少足够的了解。本文即对金文中的连词“而”予以相应的研究。佥文中“而”作为连词的出现频率虽不高,然却已经具备了后世其基本的用法,如可以分别见于具有并列、顺承、转折三种语义关系的复句中,起相应的连接作用。出现时间则限于东周时期。","categories":["02_字词句考释"],"year":2005,"publication":"湖南科技学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuK8OkhLCZslIEnV18bTu4G4oh5u1-9keRDj46bh-KPTHZV1RWdK0HPde5psOqa3tx7b9p7W-DnxNohxdfNP3aIBS43beJ3CMpb4wfVMyVfC104ggMIvPdYq9CfCz34Mw7pd3TIHm20QhUfiZL9NPf7jBbehrTNg-wEG2i-VihdQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"261-262","volume":""},{"id":5869,"author":"张艳","title":"考“后”","abstract":"《说文》曰:“后,继体君也。”经过采用形训的方法,结合古代文献,依据“后”字的甲骨文、金文字形,并寻找“后”字词义发展的线索,可以系统地解释“后”字的含义:“后”的本义为“妇女产子,”由此在母系社会被用作对最高首领的称呼,从而引申出“君”义及“继体君”义;由产子时的母前子後引申出“後”义,并造“後”字,因“后”的“继体君”义与“後”相通,加之音同,故常假借“后”为“後;”综合“妇女产子”义、“後”义、及“继体君”义,引申出“天子之妃曰后”。","categories":["02_字词句考释"],"year":2005,"publication":"浙江海洋学院学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTFjYyYZ9eTYhisJ6Uik4dFAYNPSDzmcyY2fnHDeqBMyQmiG75P7W2K44OZ0Ch200-saE0zZgkPcxL-R9gwjvcMOi83225S9oOV9IzAwRgeuzVAtW8_xlJdEAjxn9m-wcOyl-iaKvC_JS7p_bEIDAicK4K9xmozbPLt3neauLAsA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-17, 87","volume":""},{"id":5870,"author":"武振玉","title":"金文“于”字用法初探","abstract":"“于”是古代汉语中常见的虚词,其在传世文献中的用法已被揭示得比较清楚了,然其在早期汉语,如甲骨文、金文中的应用情况如何,尚未有全面的论述。殷周金文代表了早期汉语的发展情况,由于内容具有一定的程式性,其虚词的总体出现频率并不高,但“于”的用例却非常多。如既有用为动词的,又有用为介词的;用为介词时,不但可以引进处所、时间、对象,还可以引进施事者,构成一般所说的被动句。诸如此类都反映了金文中“于”字用法的丰富。故对其进行调查探讨,不但可以帮助我们了解“于”字的早期应用情况,且可为解释该字的虚化规律提供佐证。","categories":["02_字词句考释"],"year":2005,"publication":"吉林省教育学院学报","link":"https://link.cnki.net/doi/10.16083/j.cnki.1671-1580.2005.03.028","pages":"83-86","volume":""},{"id":5873,"author":"白冰","title":"白川静《金文之世界》校补(选辑)","abstract":"在日文原著翻译过程中,对白川静《金文之世界》一书所录130余件铜器铭文,从字形、词义、声韵,以及断代、考史诸方面,参照出土的新资料和研究的新成果深入探索,间或略陈己意。本文共校补32器。因篇幅所限,现重点选辑字形辨析之校补14器、词义考释之校补4器发表,另有白川静新释金文5字。","categories":["02_字词句考释"],"year":2005,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6N0P8RTj-UglvjYvYacWCziAAVFad_z4BDcvXY-ymujvYUz03NT3eSrQF9YYI-SRRqXdSlp_nf0ODJwwnh1Go3BWNbqlJiC4R0dHChkuohPA6bUFdgsdnvvj6PNvXwsoLV6Y-AHpDhJQxnnsA-hoAFAIchqcm-KA_kpjVu_l5AA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-63","volume":""},{"id":5877,"author":"潘玉坤","title":"试论西周铭文介词“于”、“以”的互补用法","abstract":"“于”、“以”是西周铜器铭文中使用最多的两个介词,“于”介引处所、时间、主动者、事情的用法是“以”所没有的,而“以”介引共事、原因的用法同样为“于”所不具备。“于”、“以”在句中的位置以及省略方面也有明显差异。尽管两者用法有少量重合之处,但总体说来,“于”和“以”的意义、功能在许多方面相互补足。这种相互补足十分鲜明而突出,是语言系统性的体现。","categories":["02_字词句考释"],"year":2005,"publication":"徐州师范大学学报","link":"https://link.cnki.net/doi/10.16095/j.cnki.cn32-1833/c.2005.04.013","pages":"55-59","volume":""},{"id":5878,"author":"蔡运章; 赵晓军","title":"三年垣上官鼎铭考略","abstract":"洛阳大学文物馆收藏有1件战国时期有铭铜鼎,传为解放前在洛阳市西工区一带出土。这件铜鼎的铭文,为研究战国晚期的量器制度等问题,提供了新的资料。一铜鼎为敛口,扁圆形深腹,腹上部附微向外撇的长方形双耳,腹下部收成平底,三蹄形短足。盖隆起呈弧形,上有三环形纽,纽上有乳状凸起。腹部饰粗弦纹一周。铸造工整精美,通","categories":["02_字词句考释"],"year":2005,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2005.08.010","pages":"90-93, 97","volume":""},{"id":5880,"author":"王长丰","title":"释“馘”、“■”及其相关字","abstract":"甲骨文、金文馘(■、■)字与其所从■字等的释读涉及相关甲骨文、金文数例。甲骨文、金文“■、■、■”等字即馘字,馘字所从“■、■、■、■”等字即■字。","categories":["02_字词句考释"],"year":2005,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK3KZFAleB85tOptxbu99RnFTD382fQCNIOOKX8TB6ihPRoynRpZCAk2p7iA3NykTos4-trPGMdElBlb1hEkO5lZECEPRgLo_cl_dvxlRK95tNqHl7xr810Enfvxa5Sd-dyknLQIpjE6-uS0ZmKlnm_OH7glPSgOuDaZbLL9SjZhg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-86, 94","volume":""},{"id":5885,"author":"刘桓","title":"大盂鼎铭文释读及其他","abstract":"西周重器大盂鼎铭文经前人释读后,已大致可读,然其中个别疑难字句仍值得商榷。鼎铭文的释读也有值得讨论之处。","categories":["02_字词句考释"],"year":2005,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLGzFcK6Uw0oPsqQ6Ms2aQOqn3P7Gy6kCgzC42JFYyD6GDXs9rb4hPl4ZvMLU63WXOZwa4MyqfUiysWHijYiHYZAjpcnm30aXGXLhcPZ1dmqzCrcTkntFuwILIVlzkfmcatNBlZHuSrZVrX25hIrImG53NA9AHY1CwQOTjf8MILAA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46025","volume":""},{"id":5886,"author":"陈秉新","title":"安徽出土子汤鼎铭文的再认识","abstract":" 子汤鼎1986年春出土于安徽省六安市北的九里沟村牛尾巴岗,现藏皖西博物馆。胡仁宜先生首次著文介绍该器,认为是春秋中、晚期之楚器,定名为子汤簋。器物肩部刻铭12字(图一),隶写为:子汤之子孙永保用之。此器铭文虽不长,但是其中器名一字为首见,器为春秋楚贵族子汤之器而出土于安","categories":["02_字词句考释"],"year":2005,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIAYMJx5f-SX2bxzBjXdtVzJ4NhtVLnkxkgkfOapVs-9g5pMPlE0u6DxrxfYIpzVvf6x6Icc6ZWsTiCpIBGcCVMtiir5x9HqzeC15GH-shsgcJJsKl8TsmUvQ03JQUmDaVr13QQRNYpBUzfUsyRGl4vkQdkxcXaKrcZAGLm2u0Q7g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-91","volume":""},{"id":5888,"author":"董艳艳","title":"商代金文中的同义词和反义词","abstract":"商代金文是与甲骨文共时的语料,与甲骨文有相同之处,也有不同之处。在详细考查商代金文资料的基础上,对商代金文中的同义词和反义词做了较为具体的分析和描述。","categories":["02_字词句考释"],"year":2005,"publication":"重庆交通学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4FvRkLKQ-oYk1QZF7TxZUrZlAuvTaW8XLq055q0OXGrB0mrU_ji_PVTXQS81uuJ9_rt_MKeWCkdYsTQWDurbOAkVb2uvfLxikAC5cfFpQ4OC1_G2HdGIQbcWiw8hkWHmALbsvSJa4UAmq7gTQEiIc8IJO7Xs_n2MZkIZqF2c6LA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-79","volume":""},{"id":5889,"author":"李运富","title":"论出土文本字词关系的考证与表述","abstract":"出土文本文字的考释有“完全考释”和“非完全考释”之别,完全考释应该对字的“形、音、义、用”都作出合理解释。考证时会涉及许多相关的字和词,对各种字词关系(含字际关系和词际关系)应该有科学的表述。在非完全考释中,有些字词关系不明确,表述时应注意实事求是。常有人仅仅根据异文就断言某字是某字的借字,仅仅根据形体相近就断言某字跟某字读音相同,甚至把出土文本中所有跟后代习用字不同而意义相当的字都看作通假字,这些判断或表述往往是不准确或靠不住的。","categories":["02_字词句考释"],"year":2005,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-dD79UMPJNONFpUDDiIbPrCul18qLME5nqBOWiJOltt49AI3KqBK9oAw-bthhVUNTM-1RO1ZK7Wcj5NYprvLgaWUs5sIl0aFucrFfq-zfQGoJpSVvugUoBEjSBNKKNpTHksnoGh3ijmdj7_GLcIKSH-kbZGEtOQP1twFm3OuFiQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-81","volume":""},{"id":5891,"author":"尹逊","title":"“集共”、“上林”铜鼎铭文考释商榷","abstract":"《中原文物》2004年第4期刊载《洛阳新发现的两件有铭铜鼎》一文,其中释为“康共”的“康”字当是“集”字,“上林”铜鼎铭文中“啬夫钦省”的“钦”应是人名。","categories":["02_字词句考释"],"year":2005,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXxxFxeGWe8dh6J7iAsgQq2mPhsMcmWIjuv0gZBo9u1crGUrcsDE-X7V8gPJHq8NyzlGzJCcWYMM4qeooBlmrCLDN3ZpxY1qGyyt_taJL4s1ItC4eO1ca5xG4kH7HCVKvLS6zg3C_0FQDZpEhATfcAHXDP5Z4pOqiR7oaXung2Ng==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"95-96","volume":""},{"id":5893,"author":"武振玉","title":"金文“以”字用法初探","abstract":"&quot;以&quot;是古汉语中常见的虚词,不但出现频率高,且用法复杂。然其发展的轨迹尚未被完全揭示,特别是由动词到介词的发展过程还有不明之处,这主要是因为在传世文献中&quot;以&quot;的动词用例相对较少,且一直不被注意。甲骨文、金文为我们提供了&quot;以&quot;字的早期用例,对其进行调查探讨不但可以帮助我们了解&quot;以&quot;字的早期应用情况,且可为探明该字的引申虚化过程提供佐证。","categories":["02_字词句考释"],"year":2005,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFXVpxI92q36BluTlfr1PVitAHubctRzjPG5gAScA1uwm_otSNgBwJmfjfKlE8QHT6SZO7Jk6JN7aWZeH2xmQR6gv3YYqgfy0nV2K2hGKHoafYvnxiT7xEvMWMmbew6KE28W8HOAh9AiixWk-5lPPO2AyLgwF5yxEEZ3tIkANV9A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46181","volume":""},{"id":5897,"author":"徐山","title":"释“叚”","abstract":"通过分析“叚”字的甲骨文形体, 认为“叚”为会意字, 其字形义为一人借给另一人从岩石上捶击下的碎块状。根据“叚”的同源词的情况,“叚”一词完整的发生背景可重构为 一人借给另一人从岩石中捶击下的赤色玉石。","categories":["02_字词句考释"],"year":2005,"publication":"安康师专学报","link":"https://link.cnki.net/doi/10.16858/j.issn.1674-0092.2005.02.016","pages":"50-51","volume":""},{"id":5898,"author":"董艳艳","title":"金文中的“亚”字考","abstract":"对于金文中的“亚”字,历来说法众多,莫衷一是。本文通过对《金文引得》中所有“亚”铭的整理和分析,探讨“亚”的准确含义及用法。","categories":["02_字词句考释"],"year":2005,"publication":"大理学院学报（社会科学）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoo4enj7XK86SfAjeVHGoknD1XAUHcDbY-O3UuScWmU6G8hNFkmt9u3-g3MD_vTVNI0eKfKxpHL4JvADzo_uJBQPzilq8uZkRJufdzagfkLulHFTJAV8Myg5Lnoi0f8Zs7H0Nkx3d0MDhyVliDEClcrH8gXbxREKH0KCzpTFR3EA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-43, 48","volume":""},{"id":5900,"author":"张道升","title":"甲金文修辞例释","abstract":"商周的甲骨文和金文中,运用了多种多样的修辞格,并有对修辞的详细论述。所以商周应是中国修辞思想的萌芽期。","categories":["02_字词句考释"],"year":2005,"publication":"宿州学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLRq2T7vISTXWhTYpIlvvZF3Iru94LfKVo8k-Jix9h6GjeypGFdKZZlTqvEyRPM_5m20m8FJab3L5AOHYFoD-oSDNLgK2nUqWFi1fwbaU4LJoyTQYgUGocYgXNyRS4U6lkzcXhVVgxBPGhgFba7rfWvaclkCkFyXj6H-710Q7RPxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-40","volume":""},{"id":5902,"author":"张玉金","title":"论西周汉语代词“厥”的性质","abstract":"目前西周汉语中代词“厥”的性质问题尚有争议。本文评述了学术界对这个问题的五种主要看法,运用现代语法学和语用学理论分析了所有有关的语料,得出了如下结论:“厥”主要是第三人称代词,它有本用,也有活用;有些“厥”已由第三人称代词转化为远指代词。","categories":["02_字词句考释"],"year":2005,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICvc2kNy5LG9U5mlJ_vNLgIdy83qjRObbM2XW-SlK8pOwNhj0mkjF5R6Yrd_N1qbjbYPq2VcYh77Z3esNpNCCpgqMzKPELI3ZJSOmgX_rhChNxAzb2YniNjUV6MaTpHQ1MR-1iWmrwccs-K3h-gvydblrO6V0o18AI11LdWrUnsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-62","volume":""},{"id":5903,"author":"潘玉坤","title":"西周金文中的同位语结构及其语序","abstract":"在穷尽调查西周金文语料的基础上,将其中的同位语短语按内部构成情况归纳为三类,从中发现,同位语内部基本是所指越具体的项位置越靠后。比较复杂的由三项构成的同位语、套叠使用的同位语,西周金文均已有使用,表明当时汉语的同位复指系统已经比较发达。同位语在句中可充当主语、宾语、间接宾语、定语、兼语等。本文系根据笔者博士学位论文《西周金文语序研究》相关部分改写而成。","categories":["02_字词句考释"],"year":2005,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICvc2kNy5LG9U5mlJ_vNLgIdy83qjRObbM2XW-SlK8pOwNhj0mkjF5L8TyLOzqdBaMh9YZKpsWnLuOTzZZclMICn0XaMez9KlQFeHItU2uCu7pecNkMocfHeYh1TD018-F8Kif4p4bOPy7OZ1Q7HHCeWQALrRcJt-vkX-KBKv__g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-68","volume":""},{"id":5904,"author":"梁华荣","title":"“曰”在西周金文中的一种特殊用法","abstract":"“曰”在古汉语中有三种用法, 一为“言”, 二为“谓”, 三为助词。在西周金文中“曰”可作介词, 相当于“对”、“于”。“曰”作介词, 为传世文献所少见。","categories":["02_字词句考释"],"year":2005,"publication":"社会科学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBt-Dv4O8m5qtt8rcc1aAbuVR-MRorSJuVu_Tdc8yYcABRqbU8dxzk4xk47htdIf-_m_2vO9VBtoMXg49KPcozQPFg-MPBlmVN5rhinj7JU-f2BxFOdUzsw-2yWfag6sQuuARDRFUY4fgrP7qRobtHEA7leiTCxndB5fO3nQPFpw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"154","volume":""},{"id":5906,"author":"贾海生","title":"论不其簋铭中的伯氏即南仲","abstract":"关于不其簋铭中的伯氏具体指谁, 学术界有不同的意见。其实不其簋铭与《诗经·小雅·出车》所记为一事, 铭中的伯氏即诗中的南仲。","categories":["02_字词句考释"],"year":2005,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOtUhxChzgrG3IgijYBx2QF2Rige9PCCQKNamJUz2yfwHPW7SLwI4QnnY5e53LIZePQot3BzmYHot7upX2TzNJYDw3kkdkeNgzEUhmKLtRYmQM7qRIXz5db0eiblq1_YYBhtqwy6kpsDRRUywiBg1gwF_V5vex7i6QVRsWU_baRQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46119","volume":""},{"id":5908,"author":"姜允玉","title":"中山王铜器铭文中的音韵现象初探","abstract":"中山王铜器铭文中有大量同源词、谐声词、通假字和方言词,是研究上古音有价值的材料。本文从声韵的角度,分别对其声母、韵母和声调三个方面进行考察,揭示出这些材料所反映的实际语音面貌,并对其语言现象作出音理上的解释说明。","categories":["02_字词句考释"],"year":2005,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2UYG4A0hPF-4roexYQ9KHVwhpuUv0zmJswJh3nvgWc6dlmF9hWQzKxDOexjsv9BwtdEj5r2L178GKEFZLw3dKya2o1lr0mZ3CJVFHwxbDyB3E_uExP9ebxJMKoVL2_Rvb2kGqUhyFRWyPPgnFjQm6GwKuUN-Wda5v7aVOy3ayCw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-23","volume":""},{"id":5909,"author":"徐在国","title":"东周兵器铭文中几个词语的训释","abstract":"一、卯(茆)&quot;卯&quot;字或作&quot;茆&quot;。见于下列戈铭:右卯(《集成》17·10944)昌城工佐□茆戈(同上17·11211)宋公差之所造茆戈(同上17·11281)昌城戈&quot;茆&quot;字或释为&quot;柳&quot;,不确。此字与宋公差戈&quot;茆&quot;字同,并从&quot;屮&quot;从&quot;卯&quot;。古文字中从&quot;艸&quot;之字或省从&quot;屮&quot;,如《侯马盟书》&quot;茀&quot;字即从&quot;屮&quot;从&quot;弗&quot;。","categories":["02_字词句考释"],"year":2005,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKx3gdzc2xdce66jAaK-UgrBoztYGzbqeUDxpn49mG6NQmCsyyHny6SU-01Ujx5fIFxc3gxqkcwPpBGgftMdDAxnJpdCowPfGeYqOaB1vdr1985NhfJ0Y9-CciLkzPJPSSKKERwVMfn2gECTVeRUwfeqV2CQvyMkdXDtIBKvAu4oA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-67","volume":""},{"id":5910,"author":"李守奎; 李轶","title":"表意字的表达功能与古文字考释","abstract":"表意字是字符表达一定意义的文字。它所表达的意义主要有字符所表达的字义, 文字所记录的相应语言单位 (词或语素) 的语义和字义与所记录的词义 (或语素义 ) 之间的关系———造字理据义。其中, 语义是表意字意义的核心, 是文字的本质。把文字与图符区别开来, 强调表意字的表达功能, 可以避免把文字当语言、把字义当词义、把末流当主流等不恰当释字, 进而正确进行古文字考释。","categories":["02_字词句考释"],"year":2005,"publication":"吉林大学社会科学学报","link":"https://link.cnki.net/doi/10.15939/j.jujsse.2005.02.020","pages":"139-144","volume":""},{"id":5911,"author":"曹兆兰","title":"保教的先驱——西周金文中的女“保”","abstract":"在西周金文中可以看到一种女性所从事的职业———保,她们是后世女保育员、女教师的先驱。西周的三篇铭文及相关资料揭示了“保”这一职业产生发展的演进过程。","categories":["02_字词句考释"],"year":2005,"publication":"教育理论与实践","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIpc48zYKsrcb-XddVnRJ4GKstiGXDXaiS90_ap74586_cTX8efh4W_J0hkbnBU6G-5-2bypBGfAJL-SZvJoRCS53s0j2b9Lznu3tzkenucPqL-R9xQGWRpTu8RhQ4aiYO--ubxaLy4_YinIjREbxRImQ9QMItiXx5J1lKiChnksQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":""},{"id":5913,"author":"邹芙都","title":"楚国铜器铭文札记七则","abstract":"作为两周铜器铭文研究重要组成部分的楚国铜器铭文研究,已经历了北宋至清初乾嘉、晚清、民国以及新中国以来至今4个时期,其中涉及的7件铜器铭文的相关问题仍有深入探讨的余地:《楚屈叔沱屈□之孙戈》的器主以往认为是屈叔沱,实应是其子之器;《楚屈子赤目》中的赤目一人或认为是屈瑕,实应作子朱看待为宜;对王孙其人的诸多考证,目前还暂时难与文献记载中的某人对应,应阙疑为是;《秦王卑命钟》的时代、铭文释读,学术界众说纷纭,通过铭文释读顺序的调整,并与吴入郢、秦援助、楚复国等大事联系起来,应将其铸作时代定在吴入郢之后数年;《王命铜龙节》铭文器主身份不是封君一级贵族所有,持有者可能是统领为楚国服役的苦力的小吏;《","categories":["02_字词句考释"],"year":2005,"publication":"云南民族大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13727/j.cnki.53-1191/c.2005.02.026","pages":"107-111","volume":""},{"id":5915,"author":"曹锦炎","title":"吴王寿梦之子剑铭文考释","abstract":"1997年，在浙江省绍兴市出土了一件春秋时期的青铜剑，剑身铸有铭文40字，是目前知出土青铜剑中铭文字数量多的一件。从铭文可知，器主是吴王寿之子，即后来继位为吴王的馀祭。该剑的铭文中带有两位吴王的名字，与《左传》的记载恰好可以互证。同时也为我们解决吴国王室的氏名演变问题提供了新线索。铭文中所记载的吴国与徐、楚两国的关系，亦可补史籍之不足。","categories":["02_字词句考释"],"year":2005,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2005.02.006","pages":"67-74, 1","volume":""},{"id":5916,"author":"王琪","title":"兼义造字“且”的认知研究","abstract":"汉字以形表义,甲骨文所呈现出的“兼义造字”,则是对这种造字原则的极致发挥。“且”以单个形体兼表“祖”与“俎”的本义“神主”与“薦”,成为一对二的古今字,这是同步的形成过程。从语言与认知的关系上来看,“且”以单个形体表示了含义丰富的概念,不仅反映了上古时期先民的思维特点,而且描绘了弥漫着礼教气息的生活图景,它是外部世界的映射,是先民高度的抽象能力与丰富的想象能力的体现。","categories":["02_字词句考释"],"year":2005,"publication":"咸阳师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSdzPNsehAhtTi4-ftr1O-baD5pS9UDoiOEUISbb_nHs35b6hcdF6R0oqYfrvDCT8MqrYPFCDCUMM6954FG0m1FJKeqkPidLI0t0u3m_t8l6o74vf8ArgofwInQpPPEOpnM35WTpW76ZXU7ggUUrc0b5DVnrmPTCY56eP7L7gbbw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"73-74","volume":""},{"id":5917,"author":"王长丰","title":"金文考释二则","abstract":"金文&quot;宇&quot;字不与&quot;■、禹&quot;相通,&quot;■&quot;在西周金文中作&quot;■居&quot;解。《中作父乙方鼎》铭文所载之&quot;■土&quot;之&quot;■&quot;字,亦即&quot;■&quot;字。","categories":["02_字词句考释"],"year":2005,"publication":"平顶山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_0KoJw1YF5k5qZN3bkXCAobtcWlLHUPVeB1SaJ6yszc_ic6AODQhr0oCQZ7WhVl3CrROB3LrhSVoueXmN-skMFu_gWQq3E43F9juDtHr7UIDFAAejimycuOcr_5CBRiOs31hdx2TMy_KOPybsUNETNl830DqzJNFTrGRD3Gk9Kg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-43","volume":""},{"id":5918,"author":"张新俊","title":"二年主父戈补释","abstract":"《殷周金文集成》17·11364所著录的赵国二年戈,最近由董珊先生考释为赵主父二年戈,十分正确。在戈的胡部有铭文二字,一直不能确释。认为此二字应该释作&quot;虎贲&quot;,表明该戈可能是属于赵主父二年的&quot;虎贲&quot;所有。","categories":["02_字词句考释"],"year":2005,"publication":"平顶山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI_0KoJw1YF5k5qZN3bkXCAobtcWlLHUPVeB1SaJ6yszc_ic6AODQhrKkjSuteBakdY3O1R6TT6J67puqnUCPSG4cjOVA0_k5Yu_6NHKjheU2tMKOueo0x7qKGKgiS8xeFEV14Mljs37I3ZccINlaKVMdF89D8l3H3NMU8OfBtSlQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-45","volume":""},{"id":5921,"author":"周向永","title":"辽宁开原建材村所出铜刀铭文涵义考","abstract":"开原建材村所出兄铭铜刀 ,其兄铭涵义应为春秋战国之际居于今辽北东部山地的土著貊人首领“兄”所佩带的标志身份的器物 ,其兄字是当时的职官名 ,是汉民族原始宗教中“祝”的身份的衍化 ,兄是祝的初文。作为一个官阶的称谓 ,被此后的高句丽族继承。","categories":["02_字词句考释"],"year":2005,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.2005.01.003","pages":"46340","volume":""},{"id":5923,"author":"梁华荣","title":"铭文叙述视角混乱与人称代词误用献疑","abstract":"作器者与作铭者的关系决定了铭文的叙述视角,也就决定铭中指称作器者代词的使用。本文认为,铭文的叙述视角与铭文指称作器者代词的使用具有一致关系,如果叙述视角混乱,必然导致人称代词使用的混乱。","categories":["02_字词句考释"],"year":2005,"publication":"求索","link":"https://link.cnki.net/doi/10.16059/j.cnki.cn43-1008/c.2005.01.067","pages":"180-181","volume":""},{"id":5925,"author":"李学勤","title":"作册般铜鼋考释","abstract":" 这里要讨论的是,中国国家博物馆2003年新入藏的一件十分珍奇的商代青铜器。器作鼋即大鳖形,首尾四足伸出,颈侧及盖上插有四箭,都","categories":["02_字词句考释"],"year":2005,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2ajPITsjojeIHa3VrpyNvZdZLXNT_9IsnNaDLukaiefZLhpITZ8ql_-uSPlFWxK9niXbd8AIAMz3-nQhzIETFCCJ7IQudBaQpjZJl6L9pXftQSfqqWhpRiR_Zb_E9wlUGckN1RSkhHikZusniQdS4Nm_8hm4IbvNPYm_PJEsKZw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46117","volume":""},{"id":5928,"author":"赵容俊","title":"文献资料中的“巫”考察","abstract":"本文从甲骨文、金文等古文字学的角度,试图考释&quot;巫&quot;字之义,并辅以先秦的古籍文献记录,观察中国古代的巫者有何种特色。经人类学与古籍文献的互相印证,证实&quot;巫&quot;为将附着患者身体的鬼魅驱逐除去时使用的道具。另外,先秦典籍所载巫者与自&quot;巫&quot;字引伸的一种人物&quot;巫&quot;基本含义亦无大差别,其活动可分为交通鬼神、医疗及救灾三方面。","categories":["02_字词句考释"],"year":2005,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJy7bEIqLcL8HzPTiI-e1nBWsyIAKpssnqL9pBW84gU-jReZNUGjjN8yDtxy7K4OlXyqjE--ZAIvfVcjEAYoCAlpCtTN6p1TbJpIjHMQYR7MTxLlesgAX9jnds4c0_VWQcKDU6hH7eKRiaHCIfz1eeiO3za4fl_HYWS7IHHvsQADA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-52","volume":""},{"id":6502,"author":"张晓明; 徐超","title":"春秋战国金文字体演变研究","abstract":"春秋战国时期是汉字字体演变的关键时期,金文字体演变是其中重要的内容。本文主要运用汉字字体研究的方法,借鉴汉字结构研究、书法学、历史学、考古学、古文字学等相关学科的研究成果,穷尽性地收集了春秋战国时期2440件有铭青铜器上的3025篇铭文,从中选择与整理出1293篇/幅作为研究对象,全面地考察了春秋战国时期金文字体的演变情况。通过对春秋战国时期金文字体演变现象分阶段、分地域的研究,通过与简牍文、帛书、玉石文字等其他载体形式字体的对比,理清了春秋战国时期金文字体演变的脉络,分析了其字体特征与字体性质的发展变化,对春秋战国金文字体演变的规律与原因、春秋战国金文字体演变在汉字字体发展史上的地位与作用等","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJkjUkZ0Av-R3-3HEwxkutYFPQfyDH9y-U11e7YLNs6Y4NB2J2f1nS9JcBZuOdJGoBE06iB1Vx-8ByJ8p3QYZ6ti_ZVjIzEo6pfxCvi9HFXF6YKGpiwmfCjb2QHdSiZjOqK2CvP088QnD_mEaP44pX3Uzx63gWoQBm5r70CSEu-tPfMEcWIAMfH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6507,"author":"吴国升; 黄德宽","title":"春秋文字研究","abstract":"本文以春秋文字为对象,从纯文字学的角度对其进行了综合研究。根据所收集的春秋文字材料,编成了《春秋文字分期分域字形表》和春秋早、中、晚三期及全期的隶定字表,并以此为基础统计出春秋早、中、晚三期及全期的字量,清理出各时期的沿用字和新增字,分析每个字的结构类型,考察汉字构形方式系统的演进状况。春秋文字材料中,共用汉字1194个,其中沿用字786个,新增字408个。结构类型总数为1236,其中象形类140,占总比例的11.33%;指事类43,占总比例的3.48%;会意类230,占总比例的18.61%;形声类769,占总比例的62.33%;未详54,占总比例的4.37%。与西周金文相比,各类型所占比例中","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIuCU8BG-OkQrefURiK83Rdg498iZjULkZTNQlm2Jl-4RLU0DPC6XNniEogrHAT3xn4YxLejo1kWyJ8vce4_8ch9tGLSEnXZ6pkTvm2ioFdsI6TQxWcvCB9E8XUPR5JwvYqSKprEBRqTD96sfjS5OQkkiK1MYIEZ9kWeAQKou08Lbq2m6lkMXAZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6512,"author":"梁华荣; 彭裕商","title":"西周金文虚词研究","abstract":"著名古文字学家李学勤先生指出:“前人考释金文,多侧重人地的考证、名物的训诂,而对文句的分析每有忽略,特别是金文中的虚词,很多学者未能予以注意。这种现象常常导致考释的错误,甚至文义颠倒,妨碍了金文的研究。”基于此,本文专以西周金文中的虚词作为研究对象,全面考察、分析、总结西周金文虚词的意义及用法。我们所说的虚词是指副词、介词、连词、助词、叹词,由于中国传统语言学尤其是一些有影响的文言虚词研究专著均将代词划归虚词之列,为了照顾传统习惯,我们将代词也一并归入虚词进行考察研究。本论文分为上下两编,上编在阐述金文虚词研究的重要性、回顾和总结虚词研究尤其是金文虚词研究的历史和现状后,重点是对西周金文语言系","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJESKVoYVrcGXmqA3qb-gyAAuqQZOCasu26MfNotsgV9oioislGa8NM_Nc2ucPA6HTvIX2Q5GPmA7o5yuNSKpMXqv5WBwRX7Jzx40WUaPPixY2FPubwj8aG8uCgWp7NyRrgG6s3mwUvAadFq7Mgsd7IZAFxk3SyVoOrE8dGHO7Znl4WBP7WF4U2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6514,"author":"陈鸿; 马重奇","title":"战国文字谐声系统与古音研究","abstract":"利用谐声来研究上古音或研究上古断代语音,是较科学的方法。随着战国文字出土材料的增加,对于研究战国语音的研究也有了更好的字形依凭。本文主要对于《战国文字编》所收的见于《说文》的谐声字进行研究。首先介绍了关于上古韵母、声母的研究以及谐声与上古音断代研究的相关成果,并对谐声进行新的定义。概括性地介绍了汉字谐声系统的历史层次。以实例分析的形式,对战国文字谐声的通例和变例进行了全面归纳。并且以声素为首,按上古韵母顺序排列,关联有关谐声字,对战国的谐声现象进行了全面的梳理。最后整理并构拟出战国语音的声类和韵类。拟测声类、韵类的同时,还采用“离析参照系”的观点,运用概率统计法,对谐声字的声母(韵母)频率和几","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJTCGIXpnFRgTox5qXWa_bAv-voTN0yVT54hcvBSKgS38zmfksNKx-v3xYnB6MDg-pwkyRXh3nIxb4Ouw2HTIipovi-9Y7-QR8GoZv3eYcDmP3wn-5QKM0tiG9iX64GqdjJYQZIFHXkeGo1Hkdf3UrOKqzmGXnrX2C_YN-WPSSgCJ0f41gaNylQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6872,"author":"许学仁","title":"出土文献中先秦儒家德目考辨二则","abstract":"本文根据金文、古玺、简帛等出土文献,整理“仁”、“信”两德目的构形字源及义蕴发展,并厘析“仁”、“信”偶见互讹之缘由。","categories":["02_字词句考释"],"year":2005,"publication":"传统中国研究集刊（第一辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxrXcWhudN8tCrHzZGpoPZikRfm2R-uwjeExdqKprlNfH42zkaAYy4tSMC84jen3MXJjkcIyrmjINcpsD8fIdRBHg2TEndJs7il9ruT8qxBuvKn-SNQiA4QWog5iCXvUzRhJ1a73g7_qyPL5xcN0ygjkSsR5Y4x-03BLXnDGC5d498Xi1FwSwx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"298-303","volume":""},{"id":6874,"author":"陈絜","title":"说“敢”","abstract":"&quot;敢&quot;字篆文作&quot;(?)&quot;,《说文》训作&quot;进取也&quot;,并视之为&quot;从受,古声&quot;的形声字。依据段玉裁《六书音韵表》,&quot;敢&quot;为八部字, &quot;古&quot;为五部字,音隔甚远,说&quot;敢&quot;从&quot;古&quot;得声,大概是讲不太通的。段氏为了调适许氏之误,谓&quot;当于双声合韵求之&quot;,实有强为","categories":["02_字词句考释"],"year":2005,"publication":"史海侦迹——庆祝孟世凯先生七十岁文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-SOhouoUl3FbrvaOt3aGCNRuSIUah3neJzxB60ACXbILTTk8KOvhfxYazM6_irYIuhX7BJldiZ6Bpsv3Mox6ku3yqsmFceO3U2p2HpLiv_IsZFZD1kCCysA25Ku478_lWccoGibn0nar9CQgR38CIlM0E00xKAj2BARD1ZNCArEiO66-qT4lN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-40","volume":""},{"id":6879,"author":"芮文浩; 方向东","title":"《庄子》语词考释","abstract":"《庄子》系先秦著作,其语言汪洋恣肆,其道理深奥宏阔。正因为如此,文献上能与之印证者不多,本文拟从文字和义理的角度,充分利用历代学者的研究成果,加以取舍,进行辨证,运用校勘学、文献学、训诂学、考据学的方法,结合相关文化知识,对《庄子》中分歧较大的语词进行考释,部分语词虽无多大歧解,但其中蕴涵的文化意蕴较隐晦者,也作适当考释,提出一得之见,揭示出深层的文化意蕴,以期对深入研究《庄子》之旨有所裨益。","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJQsYlzhgH43eJK2jY6aocTbhSLf93yGhUqYJ7viGyBrHsaZyzbReDoyqfuEt-oUw3eT76u4tNPj4VgACvqeHOQKVFKtsn4YAh8EXgp8wHnOKYe77U896-5JjmqW-phyWrobMassJDvIKGQxefX8QIKSW8wAxrZPYBQ9jrlTj5A_8jlLvgUVy8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6880,"author":"闫华; 冯良珍","title":"古文字中的讹变现象举要","abstract":"在目前的古文字研究中,古文字字形演变规律的研究还不够充分。讹变,作为古文字演变中一种普遍存在的现象,在商代甲骨文中就已经存在,到了战国文字时期,讹变的数量非常之多,变化也非常剧烈。它的存在并非偶然,反映了文字发展过程中的某些规律,也具有一定的积极意义。是文字发展过程中不可忽视的一个问题。本文试图澄清讹变的概念,以讹变的一些实例作为出发点和考察对象,探讨这些讹变现象形成的原因、并深入探寻支配这一现象的背后规律,最后对讹变的影响作出比较客观的评价。经过研究,我们得出:讹变的原因有:字形的相似、使用者对文字的整理、构形部件的位置变化、形声化、简化等。“西”字的讹变是由于字形的相似;《说文》所收形体从","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZVqf8yukoAVpwaFxA4VCvd5oSOI48d3buom46I3R7RrIwfjPoKWBsmtiWSCYY3tzHRQifxpSDnlWQ8achuZsTz79ybYkEPlre5ADgM62nGyMAtwS-MFvLQ4YCqFmvY5wsFtMilbS3a48rPJ7IDGM8yQYgzQNVuRjnQWLNYtjTlqqee5AtxOlG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6886,"author":"陈青峰; 刘志基","title":"殷商金文构形分析","abstract":"汉字的研究应该立足于汉字的本体即字形的研究。本文对殷商金文的构形系统进行描写,统计了构件的数量、频率、分布、功能等构形属性。并比较不同的汉字构形系统,确定处于早期汉字发展阶段的殷商金文构形系统的特点。","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLD_utgsi5pM2CGcyAlNu6JXyRzp2YyUNAfJafleGsYjKKHEeS-Ytm3ioqQ8aESoeawX72bPjgpk7FZSZhpoEK-78kw7gukqjHag4GuslRqIfOMhQy-E-zdTw6s-Pq-i-1qAM35jaG2jp3lt0s7de0f5B6VnmCF4yhuU4MBu1o1tdxqRtMde7ln&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6887,"author":"雷缙碚; 喻遂生","title":"西周金文与传世文献同词异字研究","abstract":"西周金文的文字研究,在前修時賢的努力下,已取得豐碩的成果。這些研究主要集中在以銘文釋讀為目的的靜態的形音義的考釋上,而將西周金文作為一個共時的文字系統的研究,一直是一個薄弱的環節。西周金文是一個相對統一的文字系統,不象六國文字那樣自成體系,它上承甲骨文,下啟小篆、秦隸、漢隸,進而與後世傳世文獻漢字系統有直接的傳承關係。本文將兩個漢字系統的同詞異字現象進行比較,以觀察此中所反映出的新字產生、舊字淘汰、字形改造及文字借用等問題。並儘量精確地歸納出古今不同漢字系統同詞異字的條例,以為將來漢字體系發展内在規律的研究作一些基礎工作。","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMrI53ZJK-8cw1pYS7qZKkBbSCif3-6ckV9vDQjC2pPws1J1uEQCMkS9h_W7f8bq4KjSKbTIjtv0m15-SH2IBZ9By4MlB8fAzGy4CfrvqXqxKODsVCFBaTKU5uZFii1T6QAO5e9nESBYaZ1UV_nL2AhmYOFdoyOziEPX9xDaUrtl1VSgrCRktR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6890,"author":"方勇; 吴振武; 冯胜君","title":"戰国楚文字中的偏旁形近混同现象释例","abstract":"關於戰國時期楚系文字的偏旁混同以及單字混同現象的討論,是非常重要的,特別是現在,隨着上海博物館收藏的戰國竹書材料的逐漸公佈,研究戰國楚文字的學術熱潮方興未艾。楚系文字以流麗紛繁見長,文字的訛變更是令人眼花繚亂,這其中就不免出現兩個或者更多的偏旁混同的現象甚至是單字混同的現象。因此就需要我們去整理一下其中混同的材料。我們正是基於此種目的來完成這篇論文的。文中用到了大量的楚系文字材料,如信陽楚簡、包山楚簡、郭店楚簡,九店楚簡、曾侯乙墓竹簡,還有最新公佈的上?┪镳^藏楚簡。另外,我們還借鑒了大量的楚系青銅器以及璽印材料等。我們將結合文字的演變過程來談文字偏旁混同的現象,具體運用甲骨文、金文、戰國楚系","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQCeDBLSwn-EE2TUFTcMpmzC7lxgCTofi7p84wpyVtF4-w6CQXQ3EZUsjrOl7MUbOS5WKNINFX1In8yZm6VUj-kvXnzzRJf7xXsXauax9ChsKB3BKKX7Jx8MchDD84H091cizmchUXmjI2IGxKNQjEBQPzgb6dpO5_MiwcXRi8KfKsSgUhNFBI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6892,"author":"姬娜; 胡安顺; 王辉","title":"战国郾君戈器铭考释平议","abstract":"在动荡的春秋战国时代,兵器的重要性是不言而喻。为数众多的兵器铭文对于研究春秋战国历史,尤其是燕国这种史籍记载相当简略且相互矛盾的历史,具有很高的学术价值。燕国的兵器铭文在燕国各种古文字材料之中是最为丰富,兵器铭文是研究燕系文字的重要资料。燕国的有铭兵器除几件属于西周时代外,大多数均为战国器物,而战国燕兵器材料又以戈为大宗,其中燕君监造的戈为数最多。因此,将战国郾君戈器铭作为—个重点来探讨,对于战国燕文籽的研究肯有十分重要的意义。本文选取66件相对真实和清晰的战国燕君戈器铭作为探讨对象,以《殷周金文集成》收录的铭文拓片为主要材料,兼涉其他相关资料,首先将战国燕君戈依形制划分为A、B两式共计八类,","categories":["02_字词句考释"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQSTDdBgSwioQYBedmnNbCLF4JU6iSwR_KcSkbwYrraE9t9jOk96iPH1ORujW8MyAQ0PTaWIpryDu8A2wnJyRaMkdzKn5Y_H2lD976XRfBFB_4g7vgtZbYTHVEqtlOTTkNMgwILYO6HEt9jXC-rgy_Vr0X3u91mfe_u006eldzouQObze5lxui&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7097,"author":"李朝遠","title":"(广倠)侯见工鼎","abstract":"上博新收侯见工鼎,为目前所知首件侯见工之鼎。器内腹铸有铭文六行六十字,记侯见工受王命征伐南夷建功事,亦是目前所见的唯一记録。所记之事,恐与抗击噩侯驭方的来犯有关。关于&quot;扑&quot;字,或根据楚简,释为翦伐之&quot;翦&quot;,本文仍倾向按传统读法,读为&quot;扑&quot;。关于&quot;见&quot;字,《老子》今本第三十五章有&quot;视之不足见&quot;句,据此,前贤十分正确地指出,郭店简中&quot;视&quot;与&quot;见&quot;的写法有明显不同,以前许多释为&quot;见&quot;的字其实都是&quot;视&quot;字。考之上博和郭店简《","categories":["02_字词句考释"],"year":2005,"publication":"上海博物馆集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJc9yyNMsW7UmeQfq8HiXJVrUyh-AFh30myXFFMiwHtqwnOIgDULFRYISejJmPvu1VE3N-0h3yFDXiK9766oQE4_wx7WJpJwILkJD2Ka5x6djp4Ju6HLFYU9oYDfm-bl1P-IbYrBKmzl8L6J5ey3C4_QKgAMJlrP9q8O5t0Yxzu6g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-113","volume":""},{"id":7099,"author":"劉紹剛","title":"古璽補釋三則","abstract":"&quot;連囂之四&quot;、&quot;公卒之四&quot;及&quot;西□□四&quot;三璽,均見於《古璽彙編》（以下簡稱《璽彙》）,以往研究戰國文字的學者對此多有論及,其中以李家浩《楚國官印考釋（四篇）》①、曹錦炎《古璽通論》②所論最詳。本文在上述學者研究的基礎上,試圖對春秋戰國時期&quot;連&quot;和&quot;卒&quot;的關係進行進一步的考證,對&quot;四&quot;的性質及&quot;西□□四&quot;的釋讀提出一點淺見,敬乞識者教正。","categories":["02_字词句考释"],"year":2005,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIf2yuV9bFMGxmtm1SltNuQG721Ug7TNn-aTLOdw3ccrJkIUKMLkX8tCUwBt-UCPBfeDr9SLJViH0RmjE2dQH6tGtYb0TCuNP1JXxFeVIaB-4io_orXudHDMoHBYvBJyu4YeQXQ2VPb7H55oPQ5Y4_T9CDyFyBxWROgKiiPxfyWqA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-49","volume":""},{"id":7100,"author":"张素凤","title":"中山王错方壶和鼎铭文字用研究","abstract":"汉字不断发展演变,汉字规范整理是一项长期任务。本文通过中山王错方壶和鼎铭文与小篆比较,分析研究铭文字用特点。认为:中山国文字与秦文字同源,诸侯力政造成各国文字异形;铭文用字规范,没有通假现象;各诸侯国缺乏统一规范的异体字、假借字以及文字发展演变的不均衡等,是战国时代文字异形的主要原因;异体字和各不相同的假借字没有扩大汉字的记录职能,只是增加识字负担,成为汉字规范整理时淘汰的对象。","categories":["02_字词句考释"],"year":2005,"publication":"励耘学刊（语言卷）","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2005.02.019","pages":"111-125","volume":""},{"id":7101,"author":"刘志基","title":"试说殷商金文中的非通用构件","abstract":"通常所谓汉字构件(偏旁、部首)具有通用性,即可以在诸多文字单位中充当结构成分。而在殷商铜器铭文中可以发现若干非通用构件,其特征是:1.它们被固定在个别文字或合体构件中,具有一见性;2.它们在传承中或迟或早被通用构件所替代,缺乏传承性;3.它们具有明显的图像来源,可以视为遗存于文字系统中的原始图画成分;4.在古文字考释研究中,对它们的研究通常意见分歧最大,因而具有考释不定性。非通用构件显然并不仅见于殷商铜器铭文,它们的存在足以引发对汉字构形学相关理论问题的思考:汉字构形系统对这种不通用构件的容忍度有多大?这种容忍度在不同断代的汉字构形系统中有没有差异?汉字构形系统为什么需要一部分非通用构件作为一","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLt82EeYZ5YEex8onJZjjLpwxZeNtJs_ck3wdxgmJ06pWJZGj1xnYx6ytq5_thxNdFPXJwTiir9_3QAzu0NSj2v3YgNAF_m2gTS9KpfIlp-zD7MdjI2tMIVQKaiD5JyIu43oUsEQsjXxfzvElg0vEzepo7e8JKqFzbq7SZcKepJRw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-16","volume":""},{"id":7102,"author":"张再兴","title":"西周金文构字元素同形关系浅析","abstract":"构字元素的同形关系是指两个构字元素的取象和功能毫无关涉,只是由于种种原因造成形体相同的关系。从动态的角度来看,西周金文的同形现象有几种情况:一是构字元素形体讹变而产生的同形;二是构字元素形体的发展演变而造成的同形;三是构字元素与缀加符号的同形;四是取象不同,但字形相同形成的同形。","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItbZzmop_ES-DZxYK2fiWUXuI4oF2ABj2E55w0IP_XuNqvFpiNgFYTRPACaZ5qpM8mkCtwDwuFw1lc4i-WUpnc4W1KXtGFf8TzvTrsqbYOZxcE7koe5Y62_JiwSscUhceo6JJMfqeWIL9RmvfLpOqUDfQ4tEaw8j8L6rcc4ECpIA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-36","volume":""},{"id":7103,"author":"李义海","title":"商周古文钲及从钲诸字考释","abstract":"商周古文■、■、■、■诸字,学界或缺释无说,或释为&quot;工&quot;&quot;贡&quot;若&quot;城&quot;,该文考释出它们都是乐器钲的象形字并发现了钲字的异体群落,释出钲及从钲构形的18个古文字形体,解读了&quot;钲典&quot;&quot;新钲&quot;&quot;■人&quot;和&quot;■者&quot;四个短语,解决了所见商周古文&quot;钲&quot;字以及从&quot;钲&quot;诸字的意义、取象和释读问题。","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItbZzmop_ES-DZxYK2fiWUXuI4oF2ABj2E55w0IP_XuNqvFpiNgFYTszcvY_0ybEVLu84amwlEO9UZsZpCA67ZcBg5Yh50I-yJ3CeSriQKv305O-baGFd8ZqZhIU4sf3i8J-GDxlQaDE6DjxqTpGCjl6hYndklf-OFyugAftkSpA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-41","volume":""},{"id":7104,"author":"师玉梅","title":"以古音释字五则","abstract":"古文字为研究上古音提供了可贵的材料,而上古音的研究也为古文字的考释提供了重要的语音依据。本文试从古音的角度对金文中的福、■等字进行了解释。","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIeucRldwdOECGfvCBHq0_5_HnycjgK7qY5eQF2jb1oiE4NVZe4WxrQEaLwT9PHhoe3pBdGo4f2yBWtUWoCOfmAN5Ear_RtR-JhfKcTsGNtbhezz_XYIauSvFNbJmAu77EF_XboHGz3SRNMbiTPr2hhCcyv5AZRrj3VN89dFipD_w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-55","volume":""},{"id":7105,"author":"王颖","title":"金文考释二则","abstract":"&quot;丌&quot;字一般被认为是&quot;其&quot;字的古文,或者是&quot;基&quot;的本字,但经过考察发现,&quot;丌&quot;字当有两个来源,一为族徽,一为&quot;其&quot;之简化异体字。&quot;不&quot;字与&quot;丕&quot;字本为一字之异体,汉代之后&quot;丕&quot;字由&quot;不&quot;字中分化出来,并承担了无实意语助词这一义项。","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIeucRldwdOECGfvCBHq0_5_HnycjgK7qY5eQF2jb1oiE4NVZe4WxrQqFrK_DbSvaJ3q2BVGdyxFIzRhV4F-aclctUo0MTc344ytcstyfRPyq_0KXsXfUwkFUM0q_MU6gFQKhF0hEPNSuPiBLzmSHjI76ZI2uf0IejQvSqOLQHTvQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-58","volume":""},{"id":7106,"author":"叶正渤; 王秀丽","title":"造磬铭文研究","abstract":"造磬铭文,是春秋早期的一篇重要史料,同时也具有一定的语言文字和音乐研究价值。","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKokpgn_2jpDyWclGe9yxHd043XpyV06IL5j-IvPc5GyxN80yTAb5c-cLBi295RCQ1DuDLncx6hC5_bcExHy6C3X8qt1YoN2RDEsBQN1A14ATt7JsnsjHf_utcf22Q4MmFxGcbBUDqu3IA5gNGzy9wHVgejC2E_25OVXb88PdnGOA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"23-25","volume":""},{"id":7107,"author":"周宝宏","title":"西周师询簋铭文汇释","abstract":"此文是对西周晚期重要青铜器师询簋铭文的汇释,汇集诸名家考释,间有自己的发现,特别注重词义的训诂与考证。","categories":["02_字词句考释"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhhO5Vxw_8_lLHG7oWE4ecdXcaTVfTRZ2EM9529Ze261NQppVXvMVTUCKxl78fAkjCT6f1ZREw9irxZHlOcRwxMalfqLh-CZhsNdy5mkQvP-VKdoPgZmDnCQDg5FkDtl-oDQDeYrfygAi97WlmV0yQrSrlzgB2rsrnWCHNvgYNrg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-31","volume":""},{"id":7112,"author":"潘玉坤","title":"西周铭文否定词的几种用法","abstract":"从殷商甲骨卜辞到西周青铜器铭文,否定词不仅数量有所增长(增加了&quot;无&quot;和&quot;亡&quot;),而且用法也趋于复杂。弄清这些变化和发展,是汉语史研究应当解决的问题。否定词包括否定副词、否定性无定代词和动词,主要构成部分是否定副词。这些不同类的词词形相同(表现为字形相同),彼此意义联系紧密,所以一般在讨论否定副词时会兼及无定代词和动词。否定副词是一个封闭的类,可以逐一加以研讨。据笔者调査,西周铭文共有10个","categories":["02_字词句考释"],"year":2005,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxzMM0uMCBdXiDKoaymEllBAnb6r80pgQWJ5rccHOlTMcAHhKSJdpjajHDDZ-lOmHuk6QldTSum9qk1fpwGxLygjGbPfrerXdqSwG_ZIkF9t3ohA7ZXvdHX8fRqMcAvj3r_VPETxSQ35rnZt6vHPsD2YeZIEtjuxKu6tZmJR9oXQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"133-142","volume":""},{"id":7113,"author":"蔡堂根","title":"“求”、“逑”小考","abstract":"在甲骨文和金文中,&quot;求&quot;是兽尾的象形,&quot;求&quot;的本义即指&quot;兽尾&quot;。兽尾与雄性生殖器近似,故尾常比喻生殖器,并与生育等相联系。因此,&quot;求&quot;可以喻指雄性生殖器,与生育行为相联系;&quot;逑&quot;也可以用来指称&quot;交配&quot;、&quot;配偶&quot;等相关的意象。","categories":["02_字词句考释"],"year":2005,"publication":"南开语言学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxzMM0uMCBdXiDKoaymEllBAnb6r80pgRwj9DZHYFgA8Yevqr38i7vefJII0nfRqk6f-5wukdW6381k9x4UCeSWJI4HlkAO_Y3Fsl3zsW87LTE69ZIFucgRJKSZ4BZEntFW6TRlTaz2AM1TXNK2wKYp7W58eeJ1TkM0-EHSRAKlw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"126-128, 229","volume":""},{"id":7114,"author":"程建功; 何茂活","title":"“五”、“午”考辨","abstract":"","categories":["02_字词句考释"],"year":2005,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpcqIxJH-K8BxFqt9BPDZnbBq1CM0PYfCLcsP9lE90oP6N8NEOYXkrSBCYbx2iC3lKy-NUhn4nm25QrLXokmwYBFAgBRFZj5c2n-iGrcXP92euUN3TxxYPN-dM3chk6UxQt1JJhBsPKActtVp_IzTZc-tXdJDRQTlxL4O8il0ZDS4YuHIbF7W9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"137-139","volume":""},{"id":5930,"author":"张正霞","title":"《毛公鼎》构词法研究","abstract":"本文以《毛公鼎》中的复音词为研究对象,通过定量、定性的研究,发现复音词的语义、词性构成比较甲骨文有进步,与同时期的《诗经》也有不同。偏正式是最能产的构词方式,述宾式、主谓式、动补式还没有产生。","categories":["02_字词句考释"],"year":2004,"publication":"大理学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIV6fM7Q3x57sE16dQBzvYu2BfyQtOE0eYqGAlF1e_-jSVB_KLwc7SqPlt-Jd2rkpooSdPhHeX2W_awCwJ__0nHhGZahLio3mRS0uRTWgR7Ga-xJsoerb0otRdb8wIdeGxVJWycwd2q2NPfCD2uuMV-6Y_BjouCUfJlfeDGKEi39g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-60","volume":""},{"id":5933,"author":"陈奇猷","title":"邿中簠当作止(邿)子中簠","abstract":"1986年4月山东省长清县万德镇石都庄发现2件邿国铜簠。《文物》2003年第4期载有铜簠(M1:3)器底、器盖铭文及铜簠(M1:4)铭文拓片。铭文相同,各17字。铭文的首字,M1:3器底铭文和M1:4铭文都从止从子。M1:3器盖也从止从子,但子字上下分开,不相连属。","categories":["02_字词句考释"],"year":2004,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2004.12.011","pages":"86","volume":""},{"id":5934,"author":"兰和群","title":"《班簋》铭文新释","abstract":"该文在前辈学者对《班簋》考释的基础上,通过对铭文的语言学审视,综合运用偏旁分析法、二重证据法和语法规则,发现“(?)人”即《诗经·小雅·采芑》“钲人伐鼓”之钲人,并结合训诂资料及《周礼·地官·鼓人》所记“鼓人”职责,探得“钲人”是在将帅指令下通过击打钲鼓向军队传递行止命令的官吏;“遣”是个表示“施”“舍”义的动词;通过《班簋》铭文、周人观念、《诗经》原文和孟子解诗的比较,求得“天畏否畀屯陟”中的“天畏”是一个定语后置式的名词短语;通过“天畏否畀屯陟”与《周书·多方》“惟天不畀纯”对勘,从语境与行文的角度,证成《班簋》铭“天畏否畀屯陟”之“否”当读为“丕”、训为大;“惟乍昭考爽谥曰大政”意为以被","categories":["02_字词句考释"],"year":2004,"publication":"郑州大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI8EmbS3A5yiDFiw8DTqziVanVc6N8VcbM-KCr4tJBulP5qNwJ47Qs2Bw0DvL2M2PlS9Gsx-Q6xiNwBHWgF1bm8bApaJBydz-oqNuPiZV75tfR4J8oLaE9OtMlM7TrF_IAlWrhUkCYjX8j_Fo1bmuliLgm-g8EP4ajSr-uutNBRCg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-108","volume":""},{"id":5938,"author":"潘峰","title":"释“白”","abstract":" 汉语中,有的把“白”训作“西方色”说和“米粒”说,这都有失其真。 《说文》云:“白,西方色也。阴用事,物色白。从入合二。二,阴数。”这种训释,仅从《说文》古文的符号得出结论,不可信。《说文》是一部信而有征的好辞书,但由于受到所处时代及作者世界观的","categories":["02_字词句考释"],"year":2004,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRUn2OZgGnn7gsZWHyBMtwshJukOzPbpUecw-dj_4Tem-LqS3sZ2RsX439lxFr4WdCUi2kgcjws9QIWnD69yh6gbvIpDjAnvZwVMWpWYKnVpcASdanzZday8zKD4wtOF7ajkivwCVgYgjpHDV6YxDGiIeU8GH8GaaGaTkpyBOcJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-24","volume":""},{"id":5939,"author":"赵鹏","title":"春秋战国金文量词析论","abstract":" 一、春秋战国金文中量词使用情况的描写 春秋战国金文中共有33个量词。可以分为个体量词、集体量词、容器量词、度量衡单位量词四大类。 (一)个体量词:指量词所计的是事物的单个个体的量。共4个。 1.邑:计城邑的单位。出现1次。例: (1)(素命)镈:侯氏赐之邑二百又九十又九邑。","categories":["02_字词句考释"],"year":2004,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRUn2OZgGnn7gsZWHyBMtwshJukOzPbpUecw-dj_4Tem-LqS3sZ2RsEm3EFFrXWK3d763VcgMoI6iZDIb0_5MogUzbHFbXv4o9kpDbdr8UiHQ-37DTR8kCibgwTyTajJ12D3BS304TBp8oIVzPuFdvnf0DbIBGdM1pGm82I-Wbmw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-28","volume":""},{"id":5943,"author":"陈英杰","title":"士山盘铭文再考","abstract":"本文对士山盘铭文中的一段册命文字重新做出考释,重点探讨了&quot;服&quot;、&quot;惩&quot;和&quot;宾&quot;三字,认为&quot;服&quot;乃采服之&quot;服&quot;,&quot;宾&quot;是宾礼,其在金文中用于东道主一方;&quot;惩&quot;义为惩毖、惩戒,铭中与巡守有关。盘铭册命内容与以往册命类铭文均不相同,是一种新见册命形式。此盘的重要性在于:一,提供了关于册命铭文的新材料;二,提供了西周分封服制的新材料;三,提供了西周方国的新材料,尤其鄀和六子非常可贵,因为目前关于鄀国的材料都是迁都以后的,&quot;六子&quot;则是在铭文中首次","categories":["02_字词句考释"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITXMn8FCqZIiU6fatvw4mxAHTdcUBg4kMkZP8QPzINNH4RC7zfnSiHRG3h9CjHBz4QcS1-xcZ4lVLFs5yNmMHweTmSXBbk-CLmh30UKC8H2KHE5_CK7VYpyI-3Ao1EQcysM7SV8gUkVoeFG2FXNrm5AagifcQzCLvsAui3E-zcSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46312","volume":""},{"id":5944,"author":"杨坤","title":"士山盘铭文正谊","abstract":"本文对士山盘铭文中&quot;于入&quot;、&quot;(?)&quot;、&quot;宾贝金&quot;三个关键词进行了释读与讨论。","categories":["02_字词句考释"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITXMn8FCqZIiU6fatvw4mxAHTdcUBg4kMkZP8QPzINNH4RC7zfnSiHBILqn9hgvOpUfi_RJT5ehgLkbyzT7lurBhqOXgbmHqv3dkQobk41giX3pssW5U9IWy3fHg31d0nxpKHokPtLpSzdPVmFmPrMuAzhW_0ShrLwK8RvG4y7kg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-19","volume":""},{"id":5946,"author":"俞允海","title":"中国古代校名考释","abstract":"中国古代学校的名称各异 ,古人的解释互有抵牾 ,特别是认为“庠、序、学、校”四语是时代不同而产生的词语。根据考古和民俗学研究 ,可以认为“庠、序、校”是地方学校 ,而“学”是古代国学。“明堂、辟雍、泮宫、灵台”等为国学的异名同实之称。","categories":["02_字词句考释"],"year":2004,"publication":"湖州师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKBUDgXh2G-We14qf1VWDRnpIT4sxLnb2h17BZihdzJNl7dDbucgcgH1sHDMDOoRZodnbYKY2UoeoO-JfbCkgOw6hOsXfSktJ2XY00N1gwCPxCvOI0JKl6Et4hCCayzmz_k25-CCQEmGcUSTHCcJropRhf9fGQ938fHYGgOFmKLAw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-27","volume":""},{"id":5948,"author":"张延俊","title":"“江”字音读的变迁及其原因","abstract":"“江”字最早见于金文 ,在上古共同语中属“见”母“东”部 ,音值为 [ku ]。南北朝后期 ,由于南部方言的地位提升和影响扩大 ,作为南部方言基本词汇“江”的方言读音“[ka ]”遂进入共同语 ,并最终取代了“[ku ]”音在共同语中的地位 ;后又受到来自北方民族发音习惯的影响 ,至明代 ,[ka ]被直接腭化为 [ ia ]。“江”字音读的变迁 ,反映了方言、外语等因素对语音变化的重要影响。前人关于“江”的 [ka ]音是由其 [ku ]音自然演变而形成和 [ ][ ‘][ ]是由于“ -i-”“ -y -”介音的影响而形成的观点还需要重新讨论","categories":["02_字词句考释"],"year":2004,"publication":"南京社会科学","link":"https://link.cnki.net/doi/10.15937/j.cnki.issn1001-8263.2004.10.014","pages":"71-76","volume":""},{"id":5950,"author":"张玉金","title":"德方鼎铭文续考","abstract":"德方鼎铭文中最难懂的一句话是“自蒿”,对此,郭沫若、马承源、白川静、唐兰四家都做过解释。本文认为,以往的解释都不能令人满意。本文对该句进行了新的阐释,并对全篇铭文做了今译。","categories":["02_字词句考释"],"year":2004,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2004.05.004","pages":"43-48, 155","volume":""},{"id":5953,"author":"蔡运章; 赵晓军; 戴霖","title":"论右孠鼎铭及其相关问题","abstract":"","categories":["02_字词句考释"],"year":2004,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2004.09.008","pages":"81-84","volume":""},{"id":5957,"author":"洪飏","title":"古文字考释中的古音伪证","abstract":"古文字考释中常常遇到通假问题。运用语音通假考释文字要注意“律例兼备”。本文对使用语音通假考释古文字进行检讨 ,揭示了其中存在的古音伪证现象。","categories":["02_字词句考释"],"year":2004,"publication":"长春师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHP_QTW0I-9sdN1e6-fKskmFKDffarq_XnnfcM_yw20Gd8w4Zgm-O0jnmAQ30AIZPd2ioWTOiP40RA5-wAGxxB8r_hpEQdzfiuy0qZ_Df-aFag729GN8Sq1JllNyDi-CmEPDG_MO3-XFcYxifzrx4sqE9qrWFyP0V7yxJfCRW9dg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"108-110","volume":""},{"id":5959,"author":"何琳仪","title":"说&quot;盘&quot;","abstract":"上海博物馆近年征集的西周青铜器晋韦父盘铭文中以&quot;舟&quot;为&quot;盘&quot;,十分罕见, 已有学者对此进行研究,本文做了补充考证。","categories":["02_字词句考释"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJidZanf2FnIk_rAShKrSNdPCYSstcewefCC0OhKs8c5apKr8N2xm4fdA3_tffTPM3v-wvimCt_RQQOnjElQu0OLmtVGiTwz8DscCw36Kn1ZF5vXYJXfRqSY7wV2aGjIfurJrurfYfGi1YBZvzOSFszHF1SYVqgrwuCaraie6WBbw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-32","volume":""},{"id":5960,"author":"张春龙; 胡铁南; 向开旺","title":"湖南出土的两件东周铜器铭文考释","abstract":"1993年4月湖南汨罗市高泉山墓地M1出土的盥盘铭文&quot;(?)&quot;当释为&quot;罗&quot;,该墓是罗子国国君之墓。辰溪县出土的越式矛铭文为楚国文字。","categories":["02_字词句考释"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKR-SqbdVFuLDFeawyfBXj50RZ-8gQyMzIUY-Yd4StMrdOaYei4pjYEpFpoGuhD-H_nARa2O6q8WN7t6_7_bUIiFemT5lP9m3QsjYeKhvMZgz-pBw-hf-QC_ng0c8iDNdX74NTHv-pADjx7EVfiyicNMpNWxVKEs8H1QfjcolNSBQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-35, 96","volume":""},{"id":5961,"author":"赵平安","title":"绍兴塔山甬钟的自名名称及相关问题","abstract":"本文对绍兴塔山甬钟的自名名称及相关问題进行了讨论,认为自名应释为&quot;镯&quot;, 甬钟应定名为&quot;之乘辰镯&quot;。","categories":["02_字词句考释"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKR-SqbdVFuLDFeawyfBXj50RZ-8gQyMzIUY-Yd4StMrdOaYei4pjYEdWiyjODCwepQ1jRLhVUZVxd8Oie5Xq-e38F0iwKrLwctZw3d4-ukWdzzrmPOg4vc67T-dat_RXbAyQEkIe75uTtH0l6hwXN5o7b9T5XW4YRMag6E2SZQCA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-38","volume":""},{"id":5966,"author":"李义海","title":"(泈皿)叔壶考释","abstract":"从铭文辞例和文字形体入手,运用语言学手段,依据书面文献资料,完全可以解决所谓不可施读的《叔壶》铭文释读问题。","categories":["02_字词句考释"],"year":2004,"publication":"天中学刊","link":"https://link.cnki.net/doi/10.14058/j.cnki.tzxk.2004.04.025","pages":"82-83","volume":""},{"id":5967,"author":"何琳仪","title":"司夜鼎考释","abstract":"传世司夜鼎以往不被金文研究者所重 ,本文则从中钩稽出“司夜”、“鬼门”等重要名词 ,并与典籍相互印证 ,探讨铭文与式盘的关系。","categories":["02_字词句考释"],"year":2004,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iInepT55pc1YX0Z3BlL9xTgHPanMhjRplAz_vbTGbhaag_TEhrvJCihdly2pOM4BFJ02oQdmgSdYrG_ThY5ig1LQLME9SUz9wqpmGv5vuTogiLmJFOTng4nhZXf60m4-xa0St8cwt5WqIXM94soL4-INhqDnNEBQL3C6lfKo9pIQQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46089","volume":""},{"id":5969,"author":"孙雪英","title":"试论古文字阶段形声字形符的演变","abstract":"甲骨文阶段形声字形符处于发展初期,数量较少。金文阶段形符增多,开始走向系统化,到了小篆阶段形符已形成严密的体系,形声字已成为汉字构形的主体。由甲骨文、金文到小篆的整个古文字阶段中,形符的发展反映了人类社会生活和文化生活的相关内容。","categories":["02_字词句考释"],"year":2004,"publication":"甘肃联合大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13805/j.cnki.2095-7009.2004.03.013","pages":"59-63","volume":""},{"id":5971,"author":"郑慧生","title":"释“关”","abstract":"甲骨文中的“　”等字 ,根据金文中此字的隶释 ,应为关字 ,与其相关的朕字 ,意为缝隙、征兆 ,关字的古音据相关字音 ,应读为t啨ｎｇ。","categories":["02_字词句考释"],"year":2004,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2004.02.002","pages":"46201","volume":""},{"id":5980,"author":"王颖","title":"西周金文及《尚书》中之“若曰”考","abstract":"&quot;若曰&quot;是《尚书》和西周金文中常见的词组,对于&quot;若&quot;的说解至今无定论,文章对西周金文和《尚书》中的用例进行了穷尽性考察,并参考前人观点,对&quot;若曰&quot;作出了新的解释。","categories":["02_字词句考释"],"year":2004,"publication":"廊坊师范学院学报","link":"https://link.cnki.net/doi/10.16124/j.cnki.cn13-1390/c.2004.01.022","pages":"94-96","volume":""},{"id":5984,"author":"彭占清","title":"“两周金文押韵方式”志疑","abstract":"本文以具体的现代论文为例,证明现代人研究金文押韵方式有三难:得古人初衷难,辨识语法文例难,处 理空围难。从而提出求是存疑的治学态度和立论原则。","categories":["02_字词句考释"],"year":2004,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWsyKajb8vLCYdV7-xbpP4T4u-0e6-PjPqBNKn6Fq2sV3m7wzuwx-Uw1420KBTNGugMvBGxLyDFq1alOf6Frum3VrDiQ_n667jopfJa8C9bUpO3nzmYOlvRm9xVCHBaGLAtz45PoG92i0a_L_Ml8htqZI8127NwYfu1FsAITvhJQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-29","volume":""},{"id":5985,"author":"江学旺","title":"浅谈古文字异体揉合","abstract":"本文对古文字中的异体字进行对比研究,揭示出一种特殊的构形方式,即“异体揉合”。在古文字发展过程中,有时会出现两个或几个异体字的不同部件揉合在一个构形单位之中。从而构成一个新的异体的现象。“异体揉合”现象的揭示,使我们对一些结构复杂的文字形体可以有新的认识。","categories":["02_字词句考释"],"year":2004,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWsyKajb8vLCYdV7-xbpP4T4u-0e6-PjPqBNKn6Fq2sV3m7wzuwx-U8fPIa76PKpdKPiyqi-NGhYY5irHNJj8Omcztzl-RTqLXoc5EZAjTOvtgdADG1P8po_6vx96pfhVTUxuzuVohNBRAIcoC9u_Q8K9uvsxO7eSWc_8Nd5BX2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-79","volume":""},{"id":5989,"author":"王冠英","title":"任鼎铭文考释","abstract":"本文对中国国家博物馆新藏任鼎铭文进行考释。任鼎铭文中有西周中期贵族买卖礼器的纪录,这使我们对周代&quot;工商食官&quot;有了新的认识。","categories":["02_字词句考释"],"year":2004,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcD-8smQ2XLc24KF9AUyNphzT9V04sKAPLGk7M5LpRNDzJXtetISYIV7igCWMZ0gtz0mTQALNUsTwyj-wrgRc3dQF9mkfdGMunbZ5nfVVLUMVbm1_ZqMeYoy-qFkvo5Lik7sw7NRcypW-3O4XEQkWBto2puHRLXU5jqYoIMQqkiA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-24, 2","volume":""},{"id":5990,"author":"曹锦炎","title":"自铎铭文考释","abstract":"2003年春 ,浙江省绍兴市出土一件50字铭的青铜甬钟。此器为典型的甬钟形式 ,却自铭为“铎”。西周甬钟源于南方商周时期的大铙 ,所以这件甬钟自铭为“铎”或许正是南方大铙的本来名称。此甬钟从铭文字体看 ,是典型的越国鸟虫书风格 ,铭文却注明是徐器 ,或可表明是徐人流亡越地后所作。因此 ,这件青铜甬钟的铸造地 ,当在越国故都绍兴 ,其具体年代约在越王勾践晚期或稍后。","categories":["02_字词句考释"],"year":2004,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2004.02.006","pages":"70-76, 1","volume":""},{"id":5993,"author":"张再兴","title":"从字频看西周金文文字系统的特点","abstract":"本文利用《金文资料库》对西周金文的文字频率进行了统计,探讨了西周金文的高频字特征等字频特点,以及金文传承率与字频的正比关系,字频角度的金文释读成果评价等西周金文文字系统特点的若干问题。","categories":["02_字词句考释"],"year":2004,"publication":"语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIOJfR8zWAXknjmja2qr3QdbjWsUZvCYgu5eP6TAnbtYWEcF9g_SCFg4aolSe--NJNBqDb4FgvDNOr8v6l4xD74Xkv7BxO1Xnko_729JtbpgiocNDbfOFgWJTlygPddBg27of44m75vr4re8sRZAzQr4MnxCe7MXD8g61R70aQTvQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-88","volume":""},{"id":5994,"author":"陈奇猷","title":"北赵晋侯墓出土叔矢方鼎铭文研究","abstract":"本文分四段:(1)叔方鼎铭文释文。(2)叔是第二代晋侯之名,(M114)之墓主即叔。(3)铭文所提示的历史事件。(4)附记:十四月。唐叔虞是武王之弟。","categories":["02_字词句考释"],"year":2004,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHWPVlEPOOv-5jJUcq38fhHS1QEPRpxzRad_4yZhVm0XwMoVw1sGmKPnLNjSgJGslmzp89urGgzilGMwqhY6dd4yC4DpF9QPAEK0zvR7na7-J6O3O9b9qbNN16Vjr1QoA50qk43E6wC_1qAPv_-DKZ-P2rTfBFdDoaUFBAhsiZww==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46025","volume":""},{"id":5995,"author":"秦建文","title":"金文“扬”字形义考","abstract":"金文“扬”字数量极多而变化纷繁 ,其在铭器金文中表现出的意义 ,与甲骨文不同 ,与今天的常用意义相差更远。就其变化纷繁的字体形状进行分析 ,可以把众多的形体归纳为四类 ,其主要意义为“称扬、颂扬” ,其次作人名。","categories":["02_字词句考释"],"year":2004,"publication":"曲靖师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHWPVlEPOOv-5jJUcq38fhHS1QEPRpxzQAv4S98pgCs0JNGjZ6t_9807IZxQAJ-tcoxqR5Wa3zQf3hADwgX8blvPykMR7wSwkgQqf9pDbgkcsJHMi0fQYiAIT9A1RVGXyKA_yJwAgNBrKC-dSQV4M8gf0lpPAAe6Mra2vOQWACxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-68","volume":""},{"id":5997,"author":"董珊","title":"谈士山盘铭文的“服”字义","abstract":"本文从唐兰先生旧说出发,讨论新见士山盘铭文“服”字含义,认为其相当于《左传》、《国语》中所见的“职贡”一词,具体包括职事与贡赋两个方面。另外提出士山盘铭之方国“履”应即金文所见的“眉敖”之“眉”。最后指出士山盘铭对于探讨西周恭王时期的政治和先秦服制都具有重要意义。","categories":["02_字词句考释"],"year":2004,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2004.01.008","pages":"78-85, 158","volume":""},{"id":5998,"author":"刘桓","title":"墙盘铭文札记","abstract":"墙盘铭文经诸家释读后,文意趋于明朗,但仍不无遗义。本文就铭文中的“达殷(田允)(畯)民”“亟狱”、”司夔”等语及(能攴)字的内涵加以探讨,提出了自己的看法。此外,作者还探讨了与墙盘铭相关的(?)钟铭“(?)五十颂处”的涵义。","categories":["02_字词句考释"],"year":2004,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2004.01.009","pages":"86-91, 159","volume":""},{"id":5999,"author":"李义海","title":"班簋补释","abstract":"在前辈学者对《班簋》考释的基础上,通过对铭文的语言学审视,综合运用偏旁分析法、二重证据法和语法规则,发现“铽人”即《诗经·小雅·采芑》“钲人伐鼓”之钲人,并结合训诂资料及《周礼·地官·鼓人》所记“鼓人”职责,探得“钲人”是在将帅指令下通过击打钲鼓向军队传递行止命令的官吏;通过《班簋》铭文、周人观念、《诗经》原文和孟子解诗的比较,求得“天畏否畀屯陟”中的“天畏”是一个定语后置式的名词短语;通过“天畏否畀屯陟”与《周书·多方》“惟天不畀纯”对勘,从语境与行文的角度,证成《班簋》铭“天畏否畀屯陟”之“否”当读为“丕”、训为大。","categories":["02_字词句考释"],"year":2004,"publication":"南阳师范学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIq_8RzVGDk-JoAzTe71oxuHG0zGd5I738vLnUHgki0yw3bz4on3DGavkyfBCqXfzdnIOR6HSWZdFGWtXJA-qYRZNIs9B43OYcKNQ2OZRkF2raVVVuNWzqv6lyoTFLovGN3LrvPo6fL-2UsrfkBOoKgtQu5Gfiacd-5XvGR16hvtA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-41","volume":""},{"id":6001,"author":"周世荣","title":"汉代漆器铭文“■工”考","abstract":" 一、概说笔者发现汉代漆器铭文中有关工种&quot;(氵冃)工&quot;的考释,一直是学者困惑的难题。虽然众说纷纭,但至今还没有一个为大多数学者可以接受、认可的观点。据笔者所知,对&quot;洞工&quot;大致有六种考释,分别为:彤、(氵月)、汩、羽、雕、&quot;洀&quot;。由于云梦西汉墓出土木方中的&quot;(氵冃)&quot;字写作&quot;(忄冃)&quot;(图一,1),明显从&quot;水&quot;旁,以上释文中的&quot;彤&quot;、&quot;羽&quot;、&quot;雕&quot;均不从&quot;氵(水)&quot;旁,从而可以认定其释文有误。而&q","categories":["02_字词句考释"],"year":2004,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZU9MK2_vjUoOv_o5xQ2TpPfJjCsBrYx4kDP2KUIPwCjn8L7a_gKu-qjQDKPmm8U2pJmJlX9eXSxRqfmlNxk7gReGXYGhguIPRDbWs0XxnY2Y4J4wWZHrjrqDKvcMqFqksGW-s-vfAFXVqyQxunOX-L0BQAEH3oU2-iKQhP5GeWg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-93","volume":""},{"id":6002,"author":"潘玉坤","title":"西周金文中几个与被动表述有关的句子","abstract":" 汉语的被动式由来已久,西周时期的青铜器铭文里肯定已经有了,但数量还很有限。讨论汉语语法史,谈到汉语被动式的早期发展,西周金文必不容绕过。而对于铭文中哪些句子是被动式,哪些不是,由于释读理解的不同,专家们往往意见不一。笔者曾参与《金文引得》(1)的编写,于此一问题尝稍加留意,趁便对西周铭文的被动式句作了一番全面检视。现就将那些争议较多的句子集聚起来,对各家见解及其根据略作平议,同时表明自己的观点。","categories":["02_字词句考释"],"year":2004,"publication":"中文自学指导","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEijQqu5XK-5qxBT-xN7F4ahTuaG20Yok91uoQFKZDDHhh3g2xtjC8-6t3_5xMrtLr27GcMfwNCp6gvF235RZ5N9JEPUeZeb3hTPNdt5h9H7vIEJUUxlRcn51kl1Kc3Kgcj9hmKLBFOcXn2bxCo6A2ccmEqjKMBeMes-c8fQa60A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-58","volume":""},{"id":6004,"author":"赵雨; 卢雪松","title":"西周单氏四器铭文写作特征研究","abstract":"眉县单氏四器铭文是一个完整的整体,累计共有1108字,是研究中国早期私家档案和私家文书的重要史料。铭文内容证明周厉王被流放后偏安于山西故地,仍以正统自居,&quot;共和&quot;可能没有独立纪年。铭文的写作特征包括史官的&quot;代言&quot;、格式的规范、叙事的恢弘和韵句的谐美。","categories":["02_字词句考释"],"year":2004,"publication":"黑龙江科技信息","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLLndB4q4q8RZEBQ-GtrPuHQ3zwCUYQ3rJEB7T30T68TIDTlDFaU57b1_M4t3iH27rUc2oUfTMkG_Clr-ZHQmtCGeATmyP26G7oJsYiNlSTvXBjuSn6flOcLAiKlbsNSxRxodnNKT514KiItLSBKy-wA0NtQllraJ4QJVysnIPM7Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104, 9","volume":""},{"id":6520,"author":"邹芙都; 彭裕商","title":"楚系铭文综合研究","abstract":"楚系铭文是指铸刻在楚国或深受楚文化影响的其它诸侯列国所铸造的青铜器上的文字，据现有出土资料，其起止时间上承西周中晚期，下迄秦灭楚之际，延续时间达六七百年之久。楚系铭文作为两周铜器铭文的一个重要组成部分，与中原北方铜器铭文相比较而言，因其自身特有的风格而成为中国南方文字的典型代表。在今天对先秦文化进行分区、分域研究曰益深化的学术热潮中，楚文化研究已被推向纵深领域，作为楚文化研究的重要分支楚系铭文研究也得到学术界的高度重视。本文以楚系铭文作为研究对象，对其作了较为系统的综合考订、研究工作，主要内容包括以下几个方面：一、在对以往有关楚系铭文研究情况总体把握的基础上，从铭文著录、文字考释、分期断代、铭","categories":["02_字词句考释"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIbdXF66Hlw1xSbXpb5NOEWSGdlVdG6jRMkfrw6B95pa4ezzI_GClYhP1iywF3rGzu11B4c6cAEeTDCZ1QKIhAT2uf2GWrBQSqHucbO3mKa966fzU-C962N9m8cKsbrPFkNouTEa8CzRZJLGbhe_o220vhTTBIkdjjDajuGV3RHnbVGud0clbF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6896,"author":"陈双新","title":"“祀、年、岁、载&quot;——上古记年词语的综合考察","abstract":"“祀、年、岁、载”四个词语在古文献中都有年岁义。今天在表达这个意义时,“年”依然是最通行的词语;“岁”很少用于指称具体的年月;“载”的年岁义还保留在一些成语中;“祀”的年岁义则完全不用了,许多人对它曾有过此义恐怕都未必知晓。同一个时间单位古人为什么会用四个声音和字形都完全不同的词语来表达呢?","categories":["02_字词句考释"],"year":2004,"publication":"语言文字应用研究论文集（Ⅱ）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJymJWcs6zBa0mQeaGqJAUSyRBRj7yLNf9_9TZT8kQP_dTaUvu1BykARx--HnmCrgyExk5y4Ibi0daNEM06U7Tcm3In7poNU5CjBS5HGzA3Yvtm3QW-S_M26XwUZuA4Pt9-e5ligQ6-Ara2ul1PciUgLFflk_c9AS6CFINYl9noQd_z5CveWG57&amp;uniplatform=NZKPT&amp;language=CHS","pages":"79-86","volume":""},{"id":6898,"author":"仉烁","title":"字海钩沉","abstract":"[舟] 舟就是船。古称独木为俞,集木为舟,行水为船。就是说,舟是船的一种,是由木板拼制而成的。甲骨文字形为?或?等,像纵向或斜向的船形,船头、船尾、船舱均清晰可辨,形象逼真。","categories":["02_字词句考释"],"year":2004,"publication":"语言学新思维","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLnYuS801WGzMIRs5-w71BQB9BmlvL24pJDRJW3WxMbZgc40CMG_F60A1Tgr5Ejns5tllw4C4vt_oHtPLyxwCBhERnfVpODsUIJ3st5rZ9pxxONrgxRdFsf52wSXAMMtCuWxZ3Q9OU4XJuob-Yv1XBc1nNx7ckJ-adrunaCjENuEarygvelf0sZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"223-233","volume":""},{"id":6899,"author":"韩祖伦","title":"秦始皇纪功刻石的文字学价值","abstract":"秦始皇统一六国后的纪功刻石,历来被奉为小篆的正宗。据《史记·秦始皇本纪》载,秦始皇的东巡刻石有六处共七种,分别为《峄山刻石》、《泰山刻石》、《琅琊台刻石》、《之罘刻石》、《东观刻石》、《碣石刻石》和《会稽刻石》。对这一批有着特殊意义的小篆文字资料,首先有必要对其原石和拓本流传情况做一考察。《峄山刻石》原石在后魏大武帝时毁佚,","categories":["02_字词句考释"],"year":2004,"publication":"秦文化论丛（第十一辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSEI387rTsIiMQ1ad7WRwc-pC43cChmU4ppXD8QZqjCiie3BmSDjQKRRtF5BBS_bc0Iarj8vGFbIJkvasaKuzbAb-hKFhAlMXVwEumLXtIkkuwouKtgm9YeTgt4Ns2CT9zzlQlg61eC744lkD27nE_zRIIy2sCoaBvq-5dZ7oL_0Tme1aeffxM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"137-147","volume":""},{"id":6900,"author":"郑慧生","title":"释“井”","abstract":"甲骨文、金文都有“井”字,其形四边四出,与今日之“井”字无异。《说文》曰:“井,八家为一井,象构韩形,瓮象也。古者伯益初作井。”段注:“韩,井上木(门东)也。其形四角或八角,又谓之银(丬木)。","categories":["02_字词句考释"],"year":2004,"publication":"夏商周文明研究·六——2004年安阳殷商文明国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSEI387rTsIiMQ1ad7WRwcctRxJ61gV6573j68ymuDmbcNoKbRx9kv1rlJWlVXKBcznvf4lfpFFvQnIKm9Vnzk8wuZWJ43bclR_oMb0eElL3XIFV3qMdV64VMsbTF-5_rn0lYD7KFMA_NeFBrX1tdsez84_R3DSyhd7_g2vzkbWnIFXRG_Town&amp;uniplatform=NZKPT&amp;language=CHS","pages":"40-41","volume":""},{"id":6901,"author":"何琳仪; 程燕","title":"释戹——兼释齐家村H90西周甲骨","abstract":"在《殷周金文集成》中,“戹”字凡五见,如下所示: 8.4302 录伯簋盖西周穆王8.4326 番生簋西周厉王8.4318 三年师兑簋西周厉王前后8.4319 三年师兑簋盖西周厉王前后5.2841 毛公鼎西周宣王1.271 齐侯鎛春秋吴大澂首先将毛公鼎此字释为“戹”,但对字形未做深入分析。孙诒让则详细地分析此字形体“当为轭,原始象形字,盖古乘车、兵车并以輈持衡,衡着两轭以扼两服马颈。上从一以象衡,中从以象軏。下从几以象轭。”按,这一半圆形孔,乃“衡上之键”,起固定衡与轭的作用。其位置本在衡与轭之间。从轭的正面观察很难见到。“戹”字的这一部位,金文在轭右,甲骨文在轭左(详见下文所引齐家村卜骨)。古","categories":["02_字词句考释"],"year":2004,"publication":"夏商周文明研究·六——2004年安阳殷商文明国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQo4vvvhTiZ6qkR0_ybQpXhepwxQIGOCNISCSVTHBBogvTfq0MdS3aRaOCLW2FZaUA9hMlw3BsAdDn_emj0Gv7s5X2GbA5NcaOuwicjlO74yhPbbFzteLA01leUfAkOLhkXO8mG1ROlcjkTgr0zR4awAG5MfRxPeleag-ggcXRU_4vk-lZqFDj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-84","volume":""},{"id":6902,"author":"胡云凤","title":"殷商金文动词研究","abstract":"殷商金文语法是目前古文字研究中尚未正视的层面,也是古汉语语法研究中的一个缺环。相对于同一时间的殷卜辞以及不同时间的西周金文,殷金文语法研究是远远落于二者之后的。殷金文语法研究未能开展的主要因素,在于殷金文缺少长篇铭文,其中字数最多的共48字,仅见于《小子(?)卣》(《殷周金文集成》5417)。这与一篇铭文动辄百言的西周金文来说,是不能相提并论的。我们知道“语料”是语法研究的基石,语料的可靠与充足是确保研究结论合乎实际的必备条件。在殷商语法的研究课题中,殷金文始终被视作辅助性的材料。除了缺少长篇铭文之外,另一个重要的因素就是内容的局限,殷金文的内容,据笔者对六字以上铭文的初步整理,归纳出两类主要","categories":["02_字词句考释"],"year":2004,"publication":"夏商周文明研究·六——2004年安阳殷商文明国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITk-P5RMRlhgCQMqucYerr8mHUxJxn8_UVlre4w7EkA9ioTN08nqDUF3EW_qNs0L3A4_UOYODa890tliOCwRBRoJle02rUyld5v_aZGiak3tc6_9yFAXcRlQvbQK-5y9_lWOi-lOC7w1mCxZ6c9dg7aD4-NQiY6oOerDCW2U1sLSpKEk524bfv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"138-159","volume":""},{"id":6903,"author":"陈絜","title":"关于商代妇名研究中的两个问题","abstract":"广义的“妇名”,应该是指所有女性的名号,诸如“妣癸”、“妣辛”之类的日干名亦当包括其中。但我们讨论商代妇名的目的,主要是想解决殷商时期的姓氏制度问题,所以本文所讲的“妇名”是狭义的,仅指那些学界通常称之为“诸妇”的像“雷妇”、“舟妇”、“妇好”、“妇井”之类的称名形式。","categories":["02_字词句考释"],"year":2004,"publication":"夏商周文明研究·六——2004年安阳殷商文明国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJn4UPHfRWVIl5U8s9V3V_lfxQTcuMKbowgA8krgP99a0-HYgaA47YEh4GAAwRTy3ogTizOSQIeN9gIWz3OAs4xqSRxVGlqItBuGMvBbLz99eBTBXleyP3_yt7KlxZ5bdtJApO78O_NDWtc-NyyTxUqPkGcvEhJNWHVFDTl9s5tvdht5jfzwJHH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"248-255","volume":""},{"id":6905,"author":"江林昌","title":"新出■公盨铭与夏禹问题","abstract":"2002年下半年,北京保利艺术博物馆从香港购藏了一件失盖的有铭铜器,曰“(?)公盨”。就器形与铭文的字体等方面考察,该器时代可定在西周中期偏晚。(?)公盨铭文对于我们认识夏代历史、研究先秦学术史、思想史、神话学、文献学、文体学等,都具有重要的学术意义,因此,器铭出现之后,立即引起了学术界的重视。在这里,我们先将铭文作隶定标点,并略作解释。","categories":["02_字词句考释"],"year":2004,"publication":"夏商周文明研究·六——2004年安阳殷商文明国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJcjlyxWndjTKFWTq4J4uhjugDwoIHkZC_YhaXZ77VWIV_JnU-sIItDgmFC6vtzHiz-WniBtMPfgy7z4Mrxjg2GTR05u3AmDQ0lRfgj_0BZYSW164PlbEVP5FqhlpOScJnzwWU3BvEf6qgMjoegFJYe-FcZDXFp9zzVqQloV1tshDqcotnsCgvh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"370-373","volume":""},{"id":6908,"author":"郭莉; 张桂光","title":"两周金文副词初探","abstract":"對兩周金文副詞進行系統深入的研究，至今鮮有學者涉獵，因此本文對現有兩周金文材料進行了窮盡式的調查，並在此基礎上，聯繫甲骨文及傳世文獻，對兩周金文副詞進行了系統而全面的研究，確定兩周金文副詞共有七十七個，其中西周有六十二個，東周新出現十五個，依據這些副詞的修飾限定功能，結合其分佈特徵，把它們分為：(一)否定副詞，(二)語氣副詞，(三)程度副詞，(四)情態方式副詞，(五)範圍副詞，(六)時間副詞，(七)謙敬副詞等七類，進而按類別對每個副詞的意義、用法都進行了詳細的描述，在此基礎上分析了金文副詞的來源、語法功能、語義指向及總的特徵。","categories":["02_字词句考释"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGh-BBf7lCe45AMMBYuTbedkRsWa4EQSs6-uV-QX8JCrTJ3vuj1hcq1PuO8e6fuFuph0qtMVBw2aDjW6FtKfAKtUSqBfMa3YjNaAFB1J5bslSLGUzKt4r1zeRMqWJwXL-4_r1qNljesx_S1O_YGh782hMLlT-hy-ttfqAFxZJCqEqQJrOXf9se&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6913,"author":"孙伟龙; 李守奎","title":"徐国铜器铭文研究","abstract":"徐国的铜器，可以将江淮下游，诸如江黄等小国的铜器与长江以南，时代上大致相近的一些铜器，在断代、花纹、形制等诸多方面联系起来,因此人们在探讨长江中下游地区青铜文化发展状况的时候，几乎言必及徐，但是徐国青铜器的文化面貌究竟如何，却始终不是那么清晰。徐国铜器多零散地出土于他国之墓中，故现在可以确认的徐国铜器，都是有铭文的。已经出土，但因为没有明确标志，而不能判定为徐器的，尚不知有多少。因而把握已知徐器的风格特征，再运用类型学等方法去鉴别未知的徐器，当是一条重要的途径。自 1963 年江西省靖安县出土庚儿鼎以来，在山西、湖北、浙江、江苏等省陆续都有徐器出土。这引起了许多专家学者的兴趣，发表的文章和著作","categories":["02_字词句考释"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKEUSK4SI7Cs49weVDpP2XpK-mqm-R3jlhmS_5VU9V0JOv2Cpr4Ato8KSIsNsJWarzIc7wOhN_vI-jGE09eraf87IN9a5Kj-2tH6LJiovUTcrIN4SZfTcKCX4K9aJLrbQ5rf5MMB2zzazbb2TIWPw9WkGt8BlWjPg4lGCbwhS-0tQhiOb1WxTCm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6914,"author":"韩卫斌; 李恩江","title":"重体字研究","abstract":"重体字是指那些由两个或两个以上相同的能独立表达一定意义的构件所组成的汉字。重体字的研究一直不为学界所关注，几乎见不到专门论述此类字的文章。但这一类字不仅能够反映出汉字发展演变的诸多规律，而且还有着自己鲜明的特点，不应该被我们忽视。笔者首先对重体字的定义进行了界定，然后按照数量的分类标准对二重字、三重字、四重字以及其他一些特殊的重体字进行了形音义的分析。在理解重体字时，应注意以下几点：一是所“重”之“体”必须能独立表达一定的意义；二是“体”可以成字也可以不成字；三是其外延包括曾经出现过的所有重体字；四是早期古文字形体的“反正无别”同样适用于重体字；五是重体字可以根据成字与否，分为真准两类，也可以","categories":["02_字词句考释"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIj2D5hwOeSM_JUz29oZX2vkD9ibSz8hOVkXrIOCAwKDRw1P8z5aEkf9FYHi_b3ybSHS3qfzHlQkdGn2IDJDc84V8oGiysdwv8tCkVgIMj71GracOMMPiPI2-qrGwKDWlPFHZPftkEUlP3o04BDXj0oHRuAIQ-4PpQTESi6SvV3BSP9rqYGIaXJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6920,"author":"邓章应; 喻遂生","title":"西周金文句法研究","abstract":"句法是语法的重要组成部分。西周金文的句法上承甲骨文、商代金文，下启东周秦汉。在语言史上具有重要的地位。全文共分五章。第一章绪论，综述了前人在金文及西周金文句法研究方面的成果，并对本文研究的意义、目的、范围等作了说明。第二章西周金文句法概述，概述了西周金文中的主语、谓语；动语、宾语；定语、状语、补语与中心语的构成与语义关系。第三章西周金文动宾结构考察，仔细考察了西周金文中的零宾语句、单宾语句、双宾语句及其转换形式。第四章西周金文介宾结构考察，考察了西周金文中介宾结构的类型及其语法功能，介词的消隐以及介宾短语的位置。第五章西周文几种句型的考察，研究了西周金文中的名词谓语句、主谓谓语句；连动句、兼语","categories":["02_字词句考释"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7oBQJqjkaivDgQcs8S6u5p27HxSH8AmbR_YBbGQCuAV_7D2FV_CYbUbWawNvc9MhnXJEtEl2KZJ0i4pIguvv42p60-DdC9Eyj5PSh7bpFqWVrwpBsgZOfELfebly60-uU3RmUEHYcCaVaP1jOMOLvJ-8XN-ZSOYk0CcblFfQtZf4Z0ylpM-xN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6924,"author":"刘黎; 白玉林","title":"先秦否定副词“不”、“弗”之比较","abstract":"过去对否定副词的研究取得成果最多的是对其起源和用法的研究，而对其演变的研究则比较薄弱，尤其对一些否定副词在历史上的消长交替情况研究得还不够。比如上古汉语否定副词共有十七个，它们在用法上存在着相互交叉的情况，但到了中古乃至现代，否定副词数量却大大减少，其中“弗”、“毋”等早已消失不见，而“不”、“未”等直至现代仍非常活跃，原因何在?为此，我选择其中关系较密切的“不”与“弗”为切入点，并将研究时间定在“先秦”，以甲骨文、金文及先秦时期的五部传世文献为研究对象，希望通过对“不”与“弗”的历时分析来探出一些否定副词用法上分合的脉络及由此而带来的一些发展变化。本文在对“不”、“弗”进行比较时采用语法、语","categories":["02_字词句考释"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVufq3LuQEdJFWMfUFN5Kc-oPLyag4cqad0QsYAU4Q5iRAuKBVc7IsEnb9CIP8YgVz3agaLEyedovdn1NbV-ODyYus-JiRSoFWAqH22CK32EdbaocelhS3Rv1S0sStiOrmn8J3uxglDgRpVzK3NHh7_R2uXdzSSN5uAgLcbXBr1hVsWwqukQom&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7115,"author":"刘雨","title":"商和西周金文中的玉","abstract":"早在新石器时代我国先民就广泛地制造和使用玉器,而过去我们对它们的了解却主要依赖后世流传的文献资料。商和西周金文是距今3000年左右的文字资料,它记录了那个时代人们对玉的使用和认识,将可以告诉我们一些更直接的有关古代玉器的知识。本文叙述了商周金文中记录的玉器种类和称谓量词,以及它们的产地、价值、功能和使用等方面。文后附录了引用的36件金文拓本及其铭文的释文和释意.期望能对玉器研究有所帮助。","categories":["02_字词句考释"],"year":2004,"publication":"故宫学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpcqIxJH-K8BxFqt9BPDZnRXUV8Or2je4ioLIl-iRjQHwpmxu40p5RWeMDT7zhLGxSza5Q84RHOSeIi001-p1CyOfjnLu95BXidClh_D5WKPCnPKZIlNwl1tc0o6chWAiVvSbsV-XTAhqvKXzZI8qSf7qtDFQ4G7WpDaQjdo_VoQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"171-195","volume":""},{"id":7123,"author":"袁金平","title":"关于兽叔盨铭文的一点补充","abstract":"《中国文物报》2003年9月19日发表了刘社刚先生《兽叔盨铭文及相关问题》一文。后程燕博士著《兽叔盨新释》（《古文字研究》第25辑,中华书局2004年10月）一文以作补释。二文对个别文字的分析仍有问题。今撰小文,以作补充。铭文&quot;用（?）(稻)（?）需（糯）(?)（梁）&quot;,乃金文习语。其中,（?）(下以A代替),二文均隶定为（?）,释为燋。伯公父（?）有（?）、（?）(以A1代替)字（见《金文编》第508页）,《金文编》将之分析为&quot;从米隹&quot;,径释为《说文》所收之&quot;燋&quot;字,可从。伯公父辞例作&quot;用盛A1","categories":["02_字词句考释"],"year":2004,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJJ838i1loAvWgK6zkgKX46IqHIFIdUB0551o8az58yjeUsq8cmtPiZtoqK9dYcOfL9OveUv2ST7yTvA8cS_pJTLJxYsTRWXjMIAGyERdIGUWsaAnHHnW96mUUn5fB8sSUGTlYgWy2KGlBBd2LjGyLCQ4r08ryw6_9isjv-fZkDcA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"315","volume":""},{"id":7124,"author":"李家浩","title":"戰國官印考釋三篇","abstract":"一、大■《璽彙》著録的0127號所謂的&quot;大府&quot;大印,傳安徽壽縣出土,①現藏故宫博物院,見《故宫》第7頁。此印白文二字,有邊欄,在二字之間有界畫,鈕爲長柱形。不論是從文字形體來看,還是從鈕式特點來看,都是一枚典型的楚印,所以人們在談論戰國","categories":["02_字词句考释"],"year":2004,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQjZBLDK-dYcQVuhsHmFCApFvDXSCCsny94XwyX2r6HS0j-bjdYSE28OzhkD6-mx8Npf7hpwvqk0c_Qlul7aaHIoJC2yC4nXGb4Ehz6PLVQ6hRzlRJUR-X8EhQE82v9CSZjSKxMmg-W-CmtbiL6YcROWYCXU17e_6hZqQBH9DVdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46379","volume":""},{"id":7128,"author":"潘玉坤","title":"金文语法札记五则","abstract":"(1)对&quot;受令册佩以出&quot;的断句作了辨析,认为其中的&quot;令册&quot;为名词性偏正结构,作宾语;&quot;佩&quot;为动词,作状语。(2)&quot;赤市朱黄&quot;句法结构不同于&quot;玄衣黹屯&quot;,为并列短语而非定语后置的偏正短语。(3)名词性后置定语多用于有限的几种变化很少的说法中,相同或相近说法反复出现。包含这类定语的偏正短语差不多都是称说赏赐物的,中心语表示事物的主体和全局,后置定语表示事物的局部、表示构成整体的部分的特征。(4)否定副词&quot;弗&quot;&quot;勿&quot;后面的动词常带宾语,与甲骨卜辞相似。(5)数目","categories":["02_字词句考释"],"year":2004,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoHOcljO8U8VSn0cbuTamcTUMxPD0avn4RQ53yfUu1tOGb9fv177oYaG-cMkeGnKTWHPVUwKFkU5RtQfeY0mTGwamEai3b7GT-FvunHr3ct-Qefny-iD6f27fDSjoK5J3548SmZuvORflmsAqjDVEwYPLqfMIXMBkUzZTNKWkDEA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"135-139","volume":""},{"id":7129,"author":"徐时仪","title":"“枪”和“抢”的衍变递嬗考探","abstract":"&quot;枪&quot;和&quot;抢&quot;是汉语中的常用词,本文考察了这两个词的字形及其词义的衍变递嬗,指出&quot;枪&quot;最初似为一头削尖的木棍,可能是由象形字或会意字演变而为形声字。枪、抢在表&quot;冲抵、碰撞&quot;义上同义而构成古今字,&quot;枪&quot;指火枪等兵器后,其&quot;冲抵、碰撞&quot;义为&quot;抢&quot;所替代,&quot;枪&quot;与&quot;抢&quot;也渐分化为表&quot;武器&quot;义和表&quot;抢先&quot;&quot;抢夺&quot;义的两个词。","categories":["02_字词句考释"],"year":2004,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLh58ozVBPWYgfBARUPHTVQ4GCwvozW6G8OX_R6XsITM_Eo59aWKyFdKDhh9qkU7eDnIfS7rOet0TRKnJkou9K8R_0wsyBOjXlR7gKvlvH_5vbN5nXcicB2srf9QOGFNSbVWWIjPkcYlMCNcSTBeRQ1Dxi6Zi7T7WN3PMG-DXlzzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"191-194","volume":""},{"id":7130,"author":"张玉金","title":"德方鼎铭文续考","abstract":"德方鼎铭文当中最难懂的一句话是&quot;■珷裸自蒿&quot;。对这句话,郭沫若(1958)、马承源(1963)、白川静(1965)、唐兰(1986)四家都做过解释。本文认为,以往的解释都不能令人满意。本文对这句话进行了新的阐释,并对全篇铭文做了今译。","categories":["02_字词句考释"],"year":2004,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLh58ozVBPWYgfBARUPHTVQ4GCwvozW6G8OX_R6XsITM_Eo59aWKyFdNMqOhELjsbg27eq-3DbNSNYgEwfabTCNYXqkd_ARA69eDtHokvcqZXXG_VLmvwUXA1CSvel0Y9PXTw9wrh67uQivPID7qPw3b5nN2bX9ynJqSbe3qNbRbw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"132-134","volume":""},{"id":7131,"author":"陈英杰","title":"金文释词二则","abstract":"本文考察了青铜器铭文中两个常用字&quot;尊&quot;和&quot;将&quot;的意义,指出&quot;将&quot;在金文中有四个意义:1.煮也;2.荐熟肉以祭;3.奉将、奉行;4.族氏名。第二义是常用义。本文对&quot;奠&quot;和&quot;尊&quot;的意义和用法作了釐正,指出二字由于后世写法的混同,导致字书、故训中二字的意义互有阑入。","categories":["02_字词句考释"],"year":2004,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3DZzDzjRrY_bVY8DiL2TyEXAO4_4f2Dgb_C8LCjvZpIvseZSbk6sVzp3QM2NUGBEZcN49aXcwrL71lqKtb9Uur6r8K2IcjAnFLBRYvaRUxPMTqqkb2aOhFU-4Ec_QSTBOmMBqkCsqEugXM1XlcdLGVjc34SivZGNgJXkKqcF8cA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"140-141","volume":""},{"id":7132,"author":"徐在国","title":"新蔡葛陵楚简札记","abstract":"对新蔡楚简释文作了补正,指出其误释之处,对部分缺释之字提出了自己的看法。","categories":["02_字词句考释"],"year":2004,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ3DZzDzjRrY_bVY8DiL2TyEXAO4_4f2Dgb_C8LCjvZpIvseZSbk6sVu-EE2-7rXn7XjlKF_KEDxsVcTj0S1JItJbIuW6ZKJxe4vozKK6qrSd8rEllmmIgZ1QQmlvUTvXJ0Igb6j6SSeCWIXN-8DwEcoqnynXs1G6jxolOKtiXF1w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"155-156","volume":""},{"id":7133,"author":"陈剑","title":"甲骨金文旧释“尤”之字及相关诸字新释","abstract":"殷墟甲骨文里有一个极为常见的“■”字,从“又”多一小斜笔或小横笔,写法变化不大。①它经常出现在跟祭祀有关的“王宾”卜辞的命辞中,说“王宾（某某）+祭祀名,亡■”。“亡■”没有问题是跟卜辞“亡■（忧）”、“亡■（害）”、“亡灾”一类说法意思相近的。","categories":["02_字词句考释"],"year":2004,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJa2j4nAfRvYOFen4UbgOTqiY-0KIPZKyp7UOjdpAPW07cp-KLeyzUMbq9PeOOta916B4J_1Y21FY13cbQrlGzzQ75lbanNNCzaBkC5V8kGCPIUTYLuqfp2EYmxYgWX-9qQU0w9RDjcEptYqTSREq2hM_c3Mfi5CTZFGyXMG7qjZg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-94","volume":""},{"id":7134,"author":"张富海","title":"说西周金文中的“■”字","abstract":"西周金文常见“■”字,《说文》以为训“讼”之“辞”的籀文。此字在西周金文中的用法大致可以归纳为以下两类:一、用在职官名中。有“■土”①、“■马”、“■工”、“■寇”和“■士”②,又有“有■”和“参有■”的称谓。有■是某些职官的泛称,参有■是■土、■马、■工的总称③。大盂鼎铭中的“邦■”和“夷■王臣”之“■”意义与有■相似。“邦■”即国之有■,“夷■王臣”即夷族有■之为王臣者。","categories":["02_字词句考释"],"year":2004,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHEv6sKm40YdzqWT5hjvFAtMa1Um88XWI-lJg2srKTIWEzqFDRxO5F0nnKNjLRmSfiK4GCj0JJcBsDNakE_VD_AdVGSM-QvOl7zLk00tp172Dz-motSMtPcQOWJXUC61l-wqaLfoY4DJl7uzH2BlRmL2Xpa0Z3S3fXBQSq30nGRg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"337-344","volume":""},{"id":7135,"author":"董珊","title":"中山国题铭考释拾遗(三则)","abstract":"20世纪70年代,河北省平山县三汲乡发现战国中山国君墓葬及中山都城灵寿遗址。有关发现曾一度引起学术界的热烈讨论,并取得了很丰硕的成果。笔者在学习中曾就中山国题铭写成一些札记,今选录三则,请师友们指教。","categories":["02_字词句考释"],"year":2004,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHEv6sKm40YdzqWT5hjvFAtMa1Um88XWI-lJg2srKTIWEzqFDRxO5FOtpJ7fZOmpwGgV4C_S_T6fOeGd_tGhrDumTiLtWt1irtPM9lS5DxskgKndENo5klC9aKWje2Y_5Y9MKWQ21_Us1QFO4cyk76aYOjKrwrn8qLZWDjc1pEhA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"345-354","volume":""},{"id":7137,"author":"严志斌","title":"关于商周“小子”的几点看法","abstract":"《文物》1998年9期刊发的《新发现的柞伯簋及其铭文考释》(以下简称《考释》)一文,对新出的柞伯簋作了较详细的解说。其中对铭文中出现的&quot;小子&quot;的论述较多,概括起来,似有以下认识:柞伯簋铭中小子是对未成年人的称谓,又称王多士,同时也是贵族大学的国子。另外,文中又认为&quot;作为职官的小子是主管小子的官&quot;。同时又认为小子又有表自谦者;又因柞伯是康王的堂弟,所以康王称之为小子。笔者拜读之后,觉得其观点有可商之处,兹作此小文,向作者及学界时彦请教。不当之处,请指正。","categories":["02_字词句考释"],"year":2004,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKs415tYI5gRPmA_CYwjLsQXNtMYYxUiHtLt5bT4iQytZwSb4nrdvRJ2YOaf_i3JQmRpcWYra5CYsbZqQwtZGGqyt4txJl1QIsO0_X4D6Pvg0IzdEVOsCQIAW7nLdwxrYtqW-vvrpTjEMMRKnw71Qo2I4HUyBRx17_xL0ajOXJilw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"383-390","volume":""},{"id":7139,"author":"韩祖伦","title":"秦始皇纪功刻石的文字学价值","abstract":" 秦始皇统一六国后的纪功刻石,历来被奉为小篆的正宗。据《史记·秦始皇本纪》载,秦始皇的东巡刻石有六处共七种,分别为《峄山刻石》、《泰山刻石》、《琅琊台刻石》、《之罘刻石》、《东观刻石》、《碣石刻石》和《会稽刻石》。对这一批有着特殊意义的小篆文字资料,首先有必要对其原石和拓本流传情况做一考察。《峄山刻石》原石在后魏大武帝时毁佚,","categories":["02_字词句考释"],"year":2004,"publication":"秦文化论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUFI4ZynPxC3_83ZXIodKDEnFlUnhD2pvqc4uFL0RBYV0SuaIHzaEhC0GWnCXehClMOqLs_hIF1kgKVfeO6aDOPF7QHk-ODgrcYqQ-EjQK_bHtEaGVFPUMRbfJL9otPg0kH6Wt2fILqUdCHKJVuky2ogDyzmVTmDDAv2qOpifF4g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"127-137","volume":""},{"id":7140,"author":"李朝远","title":"大盂鼎证补二三例","abstract":" 大盂鼎为国之重器,自道光初年出土之后,即成为学者争先探讨的对象。一个半世纪以来,大盂鼎的研究成果层出不穷,青铜器学和西周史学得以大大推进。大盂鼎可常读常新,此乃国之重器的魅力所在。值此&quot;百岁寿星潘达于捐赠大盂鼎·大克鼎回顾特展&quot;之际,兹不惴谫陋,将","categories":["02_字词句考释"],"year":2004,"publication":"上海文博论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUFI4ZynPxC3_83ZXIodKDEnFlUnhD2punTKj29D8jOeoewffz19F0MC1wpD2gJFQ4SPU_zRmoj6XrSMIZ65_fcUmypUvHc9VktT7g4C9IyNk5ARw4NsDwghFKs3p58dwnriRUoOpB9OfpKjy8MTp9OA3w-3Xb8MKKDZ7AoKo0IA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-30","volume":""},{"id":4873,"author":"曹玮","title":"“高祖”考","abstract":" 眉县铜器窖藏中出土的速盘,是新中国成立以后出土的铭文最长的西周青铜器。370余字的长篇铭文在叙述12代周王的同时,也详述了(?)自己家族的8代世袭。盘的器主(?)在阐述自己先祖的语句中,5次提到&quot;高祖&quot;这一称谓,使我们想到在以血缘为纽带、以宗法制度为特","categories":["02_字词句考释"],"year":2003,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL22KJZVeHTBlIQiOKpBkXf6x85puddIk63AmM3uxTb75q3F_HZBaS8nk81SXXcdMnEY-bSyltOd71gp6O4qQBQXUNzz9W8kO6-qwgvRfT8MV63b5htf3MV9y4TtIgFT7ROC5QI_OghZOKwrbhNDw9NpII2lnHHDqadwmB09udh7xMXjxqAxtqJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-34, 59","volume":""},{"id":4876,"author":"裘锡圭","title":"读逨器铭文札记三则","abstract":" 近日蒙&quot;陕西宝鸡眉县杨家村窖藏青铜器学术研讨会&quot;会务组寄赠《盛世吉金——陕西宝鸡眉县青铜器窖藏》,得以写成读铭文札记三则,谨供大家参考。这批铜器的器主之名一般释为&quot;逨&quot;,其实此字很可能从&quot;(卉本)&quot;的变体而不从&quot;來&quot;,为了排字方便姑书为&quot;逨&quot;。","categories":["02_字词句考释"],"year":2003,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKh--fogasEnFnxFZv0WTZBAbz_aKptN5cUf__Tgp4Z8qaPgimdXbijQKTh59waGZNhjqUSh2gBAtA1hTzt_4eqs0e-WjaQB46RzCDy1GXUmt4X5QSNjYvdd_h4xUB_DF6aBWEOsvRjsFyl2Z3RJUaubmsIfIM9hO0i1c6_MFrgTxwt0cENc4Sy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-77","volume":""},{"id":4878,"author":"刘怀君; 辛怡华; 刘栋","title":"四十二年、四十三年逨鼎铭文试释","abstract":" 陕西眉县杨家村发现的西周时期窖藏铜器,其中四十二年逨鼎有铭文280字;四十三年逨鼎有铭文316字。现分別试释如下. 四十二年逨鼎铭文: 唯(廿廿)又二年五月既生霸乙","categories":["02_字词句考释"],"year":2003,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJzGY93JI7yDBeoL8fKuoEY78G3CS3mprkwptLjNG1skOtdFk4Z2jJqgch9oq1LhXaniRiUSNaWzY68nhxMseKNmDHlDtEiK-IHcaV3ai5jJmfEXIJVgjZLlXHt0wJxFc1kyLdL6_lbzBYFqD_McXd52x77M3B8nYdU_hqpyE1-8HojWQan3vXp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-89","volume":""},{"id":4879,"author":"刘怀君; 辛怡华; 刘栋","title":"逨盘铭文试释","abstract":" 陕西眉县杨家村发现的西周时期的青铜器窖藏,出土铜器27件,其中逨盘铭文共21","categories":["02_字词句考释"],"year":2003,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKEv3YV0E6F2FvP4C9LIntIByLE8h30Iwito5HgPrNqKBHix9AfOeTGy5IyIEfdMgkiwD3Xy_IYbHJ-aGnHmD_8df5O95oFvyT0UHeHMggj54D01l_tyXvVV8QYwfHm7L3GLDVGUKbuJv8ohWlc5Mt1WRmhtetp3vjzlq02eZ9UciSbvngb_dfX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"90-93, 95","volume":""},{"id":6006,"author":"李学勤","title":"谈寝孪方鼎的所谓“惟王廿祀”","abstract":"商末卜辞金文中所谓“惟王廿祀”,在年代学研究上长期是疑难问题,特别是寝孪方鼎铭文的“”。经对原器仔细观察,证明“”本是“”即“曰”字。","categories":["02_字词句考释"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJJUMyDg9Ak4eJqnw09b_5L58WOZIDb0_9bCOEijl-qxg6xr80TiR8YVGAlj9oOD89grc56bqhQlIyTmRgtlcDyzJdapclShazBe-sne6oIq8BK7xK3WL5UOBqqreGnEMuk7Q_5dVRnzxQ0eXRoc4XfLpJGhMc0gi5PDG8eDeCpqA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46118","volume":""},{"id":6007,"author":"徐凤先","title":"以寝孪方鼎、肄簋为元祀的帝辛祀谱","abstract":"旧释为“廿祀”的寝孪方鼎和肄簋经重新考释当为“曰祀”,曾有学者认为系指元祀。商末周祭系统中,帝辛二祀到十一祀是材料最完备的一段,其间的祀谱和历谱基本确定。以寝孪方鼎和肄簋所载祀数为元祀,与帝辛祀谱相连接,结果恰与帝辛祀谱相合。","categories":["02_字词句考释"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmsZfG3VZKTUrI0UddfSiiA7y1m7Trd4b8pDONWiBF2j0tXC2gPAGHldb3wbVAduH2JSdbenfOoczsYhSrrhvaVQllIR19FSATeexbGBLjIKnRh_BxalU15_Degks4-AgOiLWVDhPgsQB-ZEXgsZxlmnIvnatPIJr2CD3ZTyC3fA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46212","volume":""},{"id":6008,"author":"师玉梅","title":"以西周铜器铭文研究西周音系的可行性","abstract":"西周铜器铭文能否作为研究西周音系的材料 ?回答这个问题的关键在于要弄清这一时期铭文的构字 (主要是形声字 )、用字 (主要是假借字 )是否含有方言因素。本文通过对西周时期的分封制、文字的传承与传播特点 ,以及这一时期的铜器和铭文特点、文字自身发展的阶段特点等几方面的分析 ,说明西周铜器铭文构字及用字很少有方言的体现 ,可以用来研究西周音系。","categories":["02_字词句考释"],"year":2003,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2003.04.021","pages":"102-104","volume":""},{"id":6009,"author":"李义海","title":"哀成叔鼎铭文续考","abstract":"在前辈学者对《哀成叔鼎》考释的基础上,该文从语言学的角度,重新解释了铭中“嘉”“是”“惟” “去”“乍”“安”“(?)”“(禾水皿)蒦”诸词的意义或用法。","categories":["02_字词句考释"],"year":2003,"publication":"漳州师范学院学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16007/j.cnki.issn2095-7114.2003.04.014","pages":"61-63","volume":""},{"id":6012,"author":"时兵","title":"两周金文的双宾语结构研究","abstract":"本文主要考察两周金文双宾语结构及替换结构和双宾语动词的使用情况,并且分别与先秦典籍和殷墟甲骨文作共时与历时的比较研究。","categories":["02_字词句考释"],"year":2003,"publication":"巢湖学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIMS4icnC47qmq7luXIp3Fg93S_w4XjHjki_YMqA722ZgVJg3WxbUfM4QpGfqsHi3od7GezPwljwAnH7WEw4GbV-VeZwGq4KBpZfQ3LesS0N3hkLKVv6gCh3eOJ1bjVqct81psFGlVGGkgbeQWMopqtZY9xDcpPgChSAuMmx4IqQA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-90","volume":""},{"id":6013,"author":"刘蕴璇","title":"日月异称考释","abstract":"","categories":["02_字词句考释"],"year":2003,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIMS4icnC47qmq7luXIp3Fg93S_w4XjHjl5Bz6IIqsBmxhK8TnHiUjHjqI5Kqdr-zltaAiDj_201mGlijiMGNe0cVPBYNV3JUdORm-g8HssGfFqotgjnvBWZkDWP3zZOViBJrIG_bXwXbyFqF3_ofdffmvOaZeHMvuxCmmW7sGg_Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-39","volume":""},{"id":6015,"author":"刘源","title":"■盘铭文考释","abstract":"2003年初,陕西省宝鸡市杨家村发现一处保存完好的西周铜器窖藏,共出土27件青铜器。其中的逐盘共铸有373字,是1949年后发现的铭文最长的西周铜器。该盘铸于西周宣王时期,其铭文记述了逐先祖考的事迹、历代王世的史事,及宣王对他的册命赏赐,具有十分重要的史料价值。本文对逐盘铭文作了考释,并初步讨论了该铭涉及的西周历史问题。","categories":["02_字词句考释"],"year":2003,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjEwT2bnTgfrRVQAfR-Ee28btf3D0IGTGIczNlVK5YTdwF4flD4ZorugBvfTJ7h96I2Vx1_CVQK0gSfFqDU56M7NM9q6zRQlk-YjwKieJU66Qj9DqFHcLH1-U-JNP_xQZu8e9BkdyxGC9TbUaKUzb3L3nBt5IFYVJ5kNvGUco2OQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-26","volume":""},{"id":6016,"author":"孙亚冰","title":"眉县杨家村卌二、卌三年■鼎考释","abstract":"眉县杨家村青铜器窖藏的出土,引起了国内外学术界的重视,其中(?)二年(?)鼎、(?)三年连鼎铭文对研究西周晚期册命制度、列鼎制度等都有重要意义。(?)二年逐鼎铭订正了文献中关于杨国始封者、始封时间的问题,(?)三年逐鼎铭中的“官司歷人”对研究《尚书》“歷人”问题也有启发作用。","categories":["02_字词句考释"],"year":2003,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjEwT2bnTgfrRVQAfR-Ee28btf3D0IGTGIczNlVK5YTdwF4flD4Zor-Z2blPoZP6wD6aNxOtwKifqkbkylIkX6IO8-C9qQBRN-eLGHLnIyFoMv7zXRIJTncQtl-BpAo0UkO4RB4ez3xEKcvZvt6S8Q0XYU4cSh3cHtKy7T6v4O8Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-34","volume":""},{"id":6022,"author":"潘玉坤","title":"金文“严在上,异在下”与“敬乃夙夜”试解","abstract":"(一)金文程式语“严在上,异在下”字面意思是“多多美言在上,休美在下”,前半句是对先人的祈求,后半句是先人“严在上”的目的及效用。(二)“敬乃夙夜”句法结构同“敬夙夜”,为“中心语+状语”短语,其中“乃”是一个起衬音作用的音节助词。","categories":["02_字词句考释"],"year":2003,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2003.05.011","pages":"70-75","volume":""},{"id":6024,"author":"徐宝贵","title":"金文考释两篇","abstract":"","categories":["02_字词句考释"],"year":2003,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFIpGN69RhmgGZu0v4etvOVm4e6PsEGzCmznTIfFHEEThyfmZHwgQLcp7zPjZx7clp_MLuIXJ5SuLxonbxueYuspp4bq8leXeVnoM5hjMHVy9ViV2uYLpuYpxXVZmXTD2JvQoGWxHJ7kdOaBJq6OXu7PTRNCmjd24y6wyZGzrkeQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-81","volume":""},{"id":6026,"author":"李学勤","title":"“秦子”新释","abstract":" 最近几年,秦国初期考古文物的研究受到学术界的普遍重视。其一个直接导因,是1993年春在甘肃礼县大堡子山发现了这一时期的秦国大墓,出土大量珍贵文物,不幸流散。现在已看到的若干青铜器,如鼎、簋、壶、钟、鎛等,多有“秦公”铭文,指明了大墓的性质。甘肃省文物考古研究所的学者根据","categories":["02_字词句考释"],"year":2003,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQi0TPbLGZMgdEyX6WKiSiQAJR8qH3hcGsa5tobfGk_afOOqbqCYpwe5lxFlyHQrIfddWKagNKuVPqKchR1C3mTMTs3yRYx7L8EbVo0e6kKKuLMdyMwHcPzlybY5BZCZGDYlv_xRFvF5GYgr5R3Rvc0cWeE-raOTCoXy1xRQfqUg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-40","volume":""},{"id":6027,"author":"李家浩","title":"包山遣册考释(四篇)","abstract":"本文主要讨论包山楚墓简牍遣册部分的几个问题:1一种兵器;2几种人马甲胄:3几种马具;4一种盛矢之器等。","categories":["02_字词句考释"],"year":2003,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIDTqoSZTtFB6ym8mLtvw90gjPO0XA9rQ8jI1PDOtJVV0Qk6PPa7XcVNedvi0RbIqpRy4OUsgxr_s7ey-PdMFrqLhO7ZRTG9S65R3MKNaucUmtmXK-9cwG9Wk-6tg27P1PVaZA1HZ20yOM_AFKBz9q1zUXHxcVaGuyS2NHp1STxdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46030","volume":""},{"id":6030,"author":"罗江文","title":"《诗经》与两周金文韵部比较","abstract":"在对已见著录的8000多条两周金文收集、整理的基础上,将两周金文韵部与《诗经》韵部作比较,可以进一步明确金文用韵与《诗经》用韵大体相似的结论。王力先生认为《诗经》韵部29部,冬侵为一部,冬部是在战国时期才分化出来。而金文冬、侵都未发现独用例,从二部的统计数字和冬部与东、阳、耕、侵诸部合韵的情况看,冬部似应独立,所以金文韵部应为30部。","categories":["02_字词句考释"],"year":2003,"publication":"思想战线","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmqKTxdPcGlEfXuqzEaQkMJ9DBcBI9upnDZMqmJtxynbPJDCnvuVboN6hGvSUChnCXHzGFIxRoL1MiMGREU95pzjVAKgLaLTn6nRFi1yrlJ43EJ9ZIgwo8tzOOcWaJlzQfyBmvs7XwGrCvM79YmbH7tRMuXo7X-ITTb1k8oIgRdg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"134-137","volume":""},{"id":6035,"author":"麻爱民","title":"墙盘与文献新证","abstract":"墙盘,西周共王时重要铜器,1976年出土于陕西扶风,墙盘出土后,学者在考古、历史、古文字方面进行了深入系统的研究,并取得了重大突破。本文从语言的角度,将墙盘中的词句与相关先秦文献进行比勘,并结合其它古文字材料纠正了《尚书》、《逸周书》、《诗经》中相关词句在传抄过程中的谬误以及由此而带来的训释方面的错误。","categories":["02_字词句考释"],"year":2003,"publication":"语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlRbNxpl2S3WNS8NpurTXigk9DC9VkHhm8eOB1WLTC6cwMzbUYjQZnVt3Joox7ziHEKP-RBaf5M8oO7arcb8UOu8iu-cIHFLoU_rnCVNgpW-aAqWvw3g8W9YBtGdicyHHZnN_8sXUQuBelE9XKGY7YpxP7dab828_Hnoe58-__Ew==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-74","volume":""},{"id":6038,"author":"许齐平","title":"许子妆簠考释","abstract":"许子妆(箐皿)是东周时期的许国青铜器,它为研究古代许国后期的历史,提供了最可靠和最具有说服力的实证。","categories":["02_字词句考释"],"year":2003,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHpa4XR4nX9ykS5We00ysrQrlbYxg_rBPpQqozRH3efhbGXyUMZsY2hjKpMYXhCqHvgv43fVO-Nr6M0mmPdL1A3lYzuKsMGUdZC9gyFN0tDU7o1s80X1q9pyZAPbyeyjeDAAj-jlYMgOhBzNeHO8cbNE3p9nc35vU0ChWIuQrtgw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-67","volume":""},{"id":6040,"author":"连劭名","title":"《(?)公盨》铭文考述","abstract":"本文肯定了保利博物馆新入藏青铜器《公盨》长篇铭文的价值,对铭文进行了详细考释。","categories":["02_字词句考释"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDyb5yQBHKx-F__iD-awCoB_2jUahcN0MOAwO4SSu_W2EzmhltV9NePDUmleSKwb8qE9_NzCA1zu-qkBzDi9g88GNf2Ev78Wmd8sp_jDXf0OkP_kHlAg4_M1wRPq70N0eHWk0BoAI8NjNAM8zQk5CIXd7nBE03iZZjQNXFoPbfCw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-56","volume":""},{"id":6046,"author":"程邦雄","title":"释“櫜”","abstract":"本文讨论殷周金文里的“”字。过去或隶释为“”“”,或释读为“韔”。本文通过形体、文字符号系统、语境、训诂、字词关系等多方面、多角度分析,认为该字应该释为“”字。本文提出,在古文字的考释中,当一个意义(词)不止一个字与之对应时,要综合考虑被释字本身的形、音、义和被释字之外的文字系统、词义系统、语境等多种因素。","categories":["02_字词句考释"],"year":2003,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLG6CI-kiHpPFsJliEo5CWCKtAq38y4F0Y9sOQGZ7kKl0QMGbaM5mYyvIZCrQqSo_exKYp2NFAHa_92wVgWj4zbhKcR7kxxiLf7x9ReTqGwFjxVE4SI5CboGAEY92nnuE6ZZQkK3i4G-qBItbapTmRcoOqDfgcnPwM41Dx7KxeAXg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-60","volume":""},{"id":6048,"author":"李香平","title":"“■”字补释","abstract":"本文在胡厚宣先生研究的基础上,通过对大量卜辞和铜器铭文的考察,重新探讨了商代卜辞中的“”字,指出它是第一人称代词“我”的异体形式,加“王”符以别于复数“我”所表示的殷商集体,是一个用于特定场合的异体专用字。","categories":["02_字词句考释"],"year":2003,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2003.02.013","pages":"94-96","volume":""},{"id":6049,"author":"刘宗汉","title":"《叔■方鼎》“王乎殷厥士赍叔■”解","abstract":"","categories":["02_字词句考释"],"year":2003,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIW32y_u9vueapD-vJv38SFwG5eyK2HDSNKjUAKMcGXBUS6dcXxgzn6qzWvuW1G7tfUmJWLNQU6bnaZafNIgUCJlC7DD6qaVwYKYTmgTHH7WIIm9rBz9FLRPotvfMnYXD7bA1foXbwUkK54i8Qoyr3cCef04PBnhqXTU8auVukSNw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"186-188","volume":""},{"id":6050,"author":"杜迺松","title":"金文“句鑃”、“左守”讨论","abstract":"金文中有自名“句鑃”的乐器,前人对其名的解释不尽完善,本文利用声韵训诂对“句鑃”一词的内涵意义和音读等多方面内容进行了研究和考证。“左守”一词是西周金文中新发现的,本文结合《三礼》等文献,从青铜礼器的性质、礼仪制度和语法结构、字义训释等方面论证了其含义,并阐明它对研究西周礼器制度的意义。","categories":["02_字词句考释"],"year":2003,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2003.03.005","pages":"43-47","volume":""},{"id":6051,"author":"刘桓","title":"五年琱生■、六年琱生■铭文补释","abstract":"本文在前人研究的基础上,就两铭的几处疑难字句及通篇大意作了新的释读。提出“伯氏”应指召伯虎,为涉讼的男一方。“宕其叁”、“宕其贰”,“宕其贰”、“宕其一”恰与《周礼·夏官·大司马》上地、中地计赋办法相合。两铭所反映的琱、召两家之土田纠纷,以碉氏赔偿贝和归还多占的土田(邑)做结。","categories":["02_字词句考释"],"year":2003,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2003.03.006","pages":"48-52","volume":""},{"id":6055,"author":"王辉","title":"■盘铭文笺释","abstract":" 2003年元月19日,陕西省眉县杨家村西周晚期窖藏出土青铜器27件,皆有铭文。其中盘铭21行,行16—19字,共372字(其中重文12,合文1),是研究西周历史文化的极其重要的资料。","categories":["02_字词句考释"],"year":2003,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQcIiEEM3qspwUUkQCxP77bNcihEUOGWSNLYyOyC2cOP-I0KSBGOnV6B9ApK2Fl4c_aFgRvRIXL8vex27cyIvP5qOyEdVxShFo_Yuyk9EgZAtdNSqGsXPTIzgRlSPH8HZX2euMtxSF2YUicz3HLT1RKwM1AcgbYDtxYtALbLwnBQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81-91","volume":""},{"id":6057,"author":"冯时","title":"■公盨铭文考释","abstract":" 北京保利艺术博物馆新近入藏西周中期青铜器公盨,铭10行98字(图一),内容十分重要。兹谨释写铭文,并做初步考释。天令(命)禹专土,隓(堕)山(濬) 川,乃(任)(地)(艺)征,降民监德,乃自乍(作)配乡(相)民,成父母,生我王。乍(则)臣(氏十)(厥)显唯德,民好明","categories":["02_字词句考释"],"year":2003,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKVcA0Jy3Tl--pLWY-G-UVn5TY_5i4iv841OliQqHGsxBp76UU3gCl7wh3Tmj3wzUfvMXFexFulESkE_YpqZ1h8GdYWo3CRBT2rEONGKfMOmRu-P5J8FbIhi88BzvWb5_I71zb2M_ncrxD0r6GxKy5O2Exn6kFwhjaJZ-0l-TRD3A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"447-456","volume":""},{"id":6060,"author":"刘志一","title":"贾湖龟甲刻符考释及其他","abstract":"贾湖龟甲刻符发表之后 ,学术界形成两种观点 :“准古彝文说”与“汉字滥觞说”。逐一对应释读 ,它们是路南古彝文。古彝文在巫术祭祀过程中应用 ,通常是一个字代表一件事、一个人物、一次法术 ,只有需要几个字连接时才出现短语或句子。汉族与甲骨文形成很晚 ,贾湖契刻不是“汉字的滥觞”。","categories":["02_字词句考释"],"year":2003,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKE8-j8GNUtM19heOlauRyXcZV_syM8PI6yFbD1k5AwfHJgIgj0PgA49K2NL9FwbNLL0BEwxe98kxzeZaYTVkc5hsyVysPOd2PYpR0KzRw6m2P08id4He8IUOi8v_HN64N6PRGw049svAmzCEFadw24gBPpDjrODm3Q6xMAQSLHGA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46308","volume":""},{"id":6062,"author":"王冠英","title":"再说金文套语“嚴在上,異在下”","abstract":"“严在上,异在下”是作器者祈求或颂扬先人的在天之灵在天帝面前多给自己多说好话、并施法给自己降下福祐的意思,其义略同于后世民间祭灶常说的“上天言好事,回宫降吉祥”,它体现的是周人凭借宗族血缘感情祈请先人为自己谋求天命。","categories":["02_字词句考释"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJo-kUnpDhW_vMT_tGhK3mRkNfQkdZitQv2qDSNSJc30tYyRLZmIbBqFfOaxwZxGUcA2cbdoq1UXp7LGKiflLHJtDSSxgKFd7XCP41-6TIOVzlZW27X9nBfzdYUYro1MfWRrnqVkQDfRuT1X3hjWgnrrmcI-T3_NeoMWtKj492J5Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-59","volume":""},{"id":6063,"author":"黄锡全","title":"士山盘铭文别议","abstract":"本文对中国历史博物馆馆藏士山盘铭文中王册命士山的一段文字提出了自己的解释,释出其中未识之字“方”,认为“徵(惩)”后的“服”字为治服或来服,“服”的对象均为方国或部族名。","categories":["02_字词句考释"],"year":2003,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJo-kUnpDhW_vMT_tGhK3mRkNfQkdZitQv2qDSNSJc30tYyRLZmIbBqQJ71VXhb814muTx5uX3Qrxa8AXUzgwvu2pW1w_u1g6sBPZtpNJ90Frl9x05posJMXleTy5hsinteoyVbvEtJQT_7pY1MSbWajEcBuv4jI2HamzLV_ChQng==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-65","volume":""},{"id":6069,"author":"黄旭初; 黄凤春","title":"湖北郧县新出唐国铜器铭文考释","abstract":"本文对2001年湖北省郧县五峰乡肖家河村出土的一批春秋青铜器上的铭文进行了考释。文中讨论了器名并提出御器说,同时兼及楚唐和楚麇关系。","categories":["02_字词句考释"],"year":2003,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLccC7wtDBYGtJ7ZWs_tN7hwpWa8jHMdUvT6TzShW3NJRLfmbf59I5aNAr1D8s2Bj-B5VSGefl_r61_YkrrFrrs4fkF-OTjxxpTkIULqb1Zt_9CSdOvleP4kJbt1P7G11wyq5HyzbqeaBXHa5fXxGciCPEuWSONzd0h2AYEyNDUPw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46280","volume":""},{"id":6073,"author":"江学旺","title":"从西周金文看汉字构形方式的演化","abstract":"不同时代各种结构类型字分布比例的不同,反映了文字构形方式的演化。殷商时期是以表意的构形方式为主。西周金文中,形声结构明显高于表意结构的比例,这表明西周时期汉字构形是以形声构形方式为主。如果就新增字来看,可以说西周时期形声构形方式几乎就是唯一能产的构形方式。","categories":["02_字词句考释"],"year":2003,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIH3qfNxePAlids3Eth0bG18XA9tTqvqV_ZZQqiifEUNlIGqgHRGXjoiEc1x-JURZhRlMj54MnUwF6FMVPKMVqMmlY-5Wtf-_UmwxB3olgTAXPr5nbkU2Z_gIIXZkzp1d4GFmUSCn5kOoobkJLrESmfZmLnllqE1MsEoh2M3-0W9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-33","volume":""},{"id":6076,"author":"高华平","title":"是“东宫之杯”还是“东宫之师”","abstract":" 1993年湖北荆门出土的郭店一号楚墓漆耳杯的四字铭文,最初发表时释为“东宫之杯”,后李学勤先生改释为“东宫之师”,[1]一般学者遂用李说。近李零先生又著文从墓主之身份及楚文字学角度,重新提出问题,认为应读释为“东宫之杯”。[2]笔者对楚简帛文字作了一些考察,觉该杯铭文释为“东宫之杯”,显系臆说,仍应以释为“东宫之师”为妥。理由如下: 首先,该杯四字铭文写作“(?)(?)止(?)”,前三字释为“东宫之”学界看法一致,第四字释为“师”还是“杯”,涉及到“币”、“不”二字字形的演变与区别问题。甲、金文和简帛文字中常以“币”为“师”,而“币”与“不”又字形相近,故易发生混淆。但笔者经过深入比较,发现","categories":["02_字词句考释"],"year":2003,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZGI24yXhtwhByXwA4b4jHVZuHZcTUQYUHIuIGWQYtgwHp5IOsbZcBhkOc87x0KZho_wSKVQS4LSgGQ2q4ZFIkdho3ZJlRjnO1eIV-R3zrXKJqFx2yb97hwTiCNFt_JwRjph-7cghPa89H2UC9qGitqvDg13O5L5thbkLtdIDOJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66","volume":""},{"id":6085,"author":"彭裕商","title":"西周金文中的“贾”","abstract":" 西周金文有字,学者或释贮,或释贾,至今未能取得一致的看法,而该字的释读,又直接关系到西周商业和一些重要制度的研究,因此有必要在已有研究成果的基础上,对该字再作进一步的深入辨析。笔者经过研究认为该字应释为贾。","categories":["02_字词句考释"],"year":2003,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_JjnmtY54KEUhwmSx-O0bswIfIuGzZsuD3JuMppPEtsHqlT-eMRgWsBTwCM5seVeL_SfBKNpFL9c5cZt7sSZ8Tp9JRs06WTEuwEnwuZz2DOtGBNxg5Wsd1_TG27QZtt5_QDHMkCGDxSFaMrgB7FmuK56F9gy_AjRLCYQZolJGsw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"153-157","volume":""},{"id":6087,"author":"陈双新","title":"子范编钟铭文补议","abstract":"","categories":["02_字词句考释"],"year":2003,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLLTntF1pUcR4MBMQ_a4LeOtuE_F00FokrvEyDJUDZhgXAIxpO92wtMl_OX7uS8sdHdfxdpVNkiHSsFLYDO0-DP5XX-0PCsj9ex4jqqqkwRFS81PqpQQplO86sY2ES4P8yFa4gTFeNUMmMfxdeC-FijmgIfZuJbyPrP44TlsYKUMQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-88","volume":""},{"id":6089,"author":"董艳艳","title":"商代金文语言概述","abstract":"金文是汉字发展史上的一个重要阶段,商代金文作为与甲骨文共时的语料,与甲骨文有相同之处,也有其特殊的意义,但研究者较少。 文章从语料数量、内容、词汇、语法等方面对商代金文语言的面貌作了概括性介绍。","categories":["02_字词句考释"],"year":2003,"publication":"宜宾学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgremmxh_9n4cIROWLxRkC8Ru73ZzktWwBMAljS_uTNtpj8yZGFbKWypLlRy98C6fO5bBwRYQXX_LyaegRTUZ10paFzc1ECdZh2F63fcUdSTSlgx12sEI3mwbKF0NXD7cN5CYH9Z16IY-sH17EzT-2ZWajH2zWmmo32H0I2ziP2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-73","volume":""},{"id":6927,"author":"潘玉坤","title":"西周铜器铭文被动表述与语序","abstract":"当一个句子的主语在语义上是谓语动词所表示的动作行为的受事时,我们称它为被动句。被动句有两种类型。无形式标志、与主动句同形的是一类,这类被动句与主动句语序无别,句法结构相同,但语义结构却很不一样。有形式标志、具有鲜明外部特征、明显不同于主动句的又是一类。为方便表述,下文把前者称作“语义被动句”,后者称作“被动句式”。西周青铜器铭文是汉语书面语的源头作品之一,语料可靠, 不存在辗转传抄、走样失真的问题。就被动句而言,弄清楚西周铭文的被动表述方式及其语序,对汉语史研究的意义不言而喻。","categories":["02_字词句考释"],"year":2003,"publication":"汉语被动表述问题研究新拓展——汉语被动表述问题国际学术研讨会论文集","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzOE5p0TnNqspzrs1hGiO1lMLJ60PqhsvrLNmrkFabpwA_fEBSkoYOsMmHm90c_vcomj-Ag0az8ygP_cHlLvi3oMz_lRC-2A3iUYWVo4BxVNqXMgLufKfgA7R98CJODxPZOIXOu_C4U7Wtlx5ABG_E5jhHG47eNC5kzXxI_O0ncS2k_HZqpwvq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"264-278","volume":""},{"id":6929,"author":"刘靖文; 张桂光","title":"先秦出土文献第一人称代词","abstract":"对於先秦传世文献典籍中的第一人称代词，一些学者已经从多个角度作了相当深入的研究，并取得了一些成果。以先秦出土文献为材料，对其中第一人称代词进行研究的工作大多是集中在某一时期上(主要是殷商时期)。本文分别对殷商、西周、东周三个时期的第一人称代词进行了考察，并尝试在此断代考察基础上进行历时研究，总结其中各个第一人称代词发展演变规律，作为传世典籍中较成熟可靠的关於第一人称代词探讨的一个补充，并为汉语语法史人称代词部分研究储备更丰富的材料。","categories":["02_字词句考释"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLW6CyazN2YyshjrQnjOxcfiRRpF_d44C4zlCjbRyl8WjGcBxSqFi_g-xBDMAJp2X6WPBGgkCgfFri8LlX2PFbkrgSGq_eDgoWeE-8KzDoyzpCKcquMmUjIVRHxqe7pUoxHeFr3KMLQlwURGfxcS4rjXL-4p9xHQPDuKQ_LSw68tHpYv2kgoEon&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6930,"author":"董艳艳; 喻遂生","title":"商代金文语言研究","abstract":"金文是汉字发展史上的一个重要阶段，对金文进行系统的研究始于宋代。自宋代以来金文研究取得了较为显著的成绩，但有关金文语言文字的研究，特别是词汇语法的研究还很薄弱，与甲骨文语言研究相比，还有较大差距。商代金文作为金文发展的初始阶段，其语言文字更是研究者甚少。本文对商代金文的语言情况作了初步的探讨。论文共分三章，分别是：词汇，对商代金文的词类做了划分并对每一类词的情况做了简述，描述并分析了商代金文的词义系统和词的聚合等现象。语法，分析了商代金文的词类、短语、句型及句子的构成材料。商代金文与其他材料的比较，将商代金文与甲骨文、西周金文及《尚书·商书》的部分内容做了简单的比较，找出它们之间的异同及关系。","categories":["02_字词句考释"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0lvssCfQ9L23sC9tMGTbLmA-OF7hAbGLnxQLhOF3uSs2cfp4K1diOIMz63ynW95lVpXyrjs3fgZTgCutAp6MoNcLMzH3jwpn4oANVWyy9t6jOgu8mPMBwUTGTNyMdGTLgQd1JyX2h0TrUehzAP0VXi0_DJEth2ezqZFQBAIqpQ2asOJIjdDQ4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6931,"author":"邓飞; 喻遂生","title":"两周金文军事动词研究","abstract":"上古时期的甲金文语言研究是汉语史研究的一个薄弱环节，在前修时贤的努力之下，甲骨文词汇的研究已经取得了突破性的进展，而两周金文的语言研究则进展缓慢，尤其是词汇研究一直少有人问津。两周金文是一种同时材料，材料不仅丰富而且真实可靠，应是研究两周时期语言和文化的理想资料。西周的词汇研究对构建上古词汇系统乃至整个汉语词汇系统是必不可少的。本文以两周的军事铭文为研究对象，清理出其中的军事动词，从这些动词的类别、词义、历史层次、时间断代、来源、新词的产生、发展与传承、语法特徵以及文字的构造、文化内涵等几个方面进行探讨，试图尽量多地揭示该类词的总体特徵，为以后编写完备的汉语词汇史作一点必要的基础工作。","categories":["02_字词句考释"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIp11DPYFR3omgAJwf893KpoEHQ0ZcknnjLsYZ2NpyJKPgTvbp1I-Kyu7xAWoAkxLd0cIDLE9wym587pHaYc9qssXXJk3B8x4E80oIMpC51H_b08BKv_d7y4NSGi3nBDa-8XTpQkxsLBdS93vQ0lb9napprDv8MDYsOcOwaPGVfEFRIjXetw2VC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6932,"author":"邵英; 胡安顺","title":"《段注》540部首“今正”义考辨","abstract":"东汉许慎的《说文解字》(以下简称《说文》)一书是我国第一部有系统的文字学著作，也是研究古文字的重要资料。因历经几个世纪的传抄刊刻，加之经唐朝李阳冰的随意篡改，造成了许多的遗脱讹误。宋朝的文字学家徐铉奉诏校订《说文》，南唐文字学家徐锴则在此前已著成《说文系传》。经过二徐的努力，使《说文》原貌基本恢复。到了清朝，著名音韵学家、文字学家段玉裁对《说文》进行了全面注释。他历经40年终于完成《说文解字注》(以下简称《段注》)这一巨著。他不仅旨在恢复其原貌，而且要揭示其体例。在全书的注释中，段玉裁一方面运用内证法，以许校许，以许注许，阐明其体例，贯通其条例；一方面运用外证法，引用诸子百家、传注字书、方言俗","categories":["02_字词句考释"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRgVtLTL2k9EEtvFiqusaMqckrH41KPjhdsA3oTrZyOvl50aX2j4T112m6Ipj9imebgx2DG7s8v_E0kxgTiAmLfp3syePJI6pxi9X_GxprMDHqdZAuj3sF-Tt6DgHVGAwYIYPvzQIkua0ZknZIDdE6AAi-owiIVZo78J2jqLvQjhs4B88LdLaI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6933,"author":"林亚红; 史佩信; 陈五云","title":"汉语早期“其”字考","abstract":"“其”是早期汉语中极其重要、出现频率极高的基本词汇之一。本文从三个历史时期对“其”作出历时性的考察，殷商甲骨文时期的“其”均为语气副词用法，没有指代词用法，西周中后期出现“其”的指代词及介词的用法，我们认为是从甲骨文时期的语气副词“其”发展出来的。“其”本身语气副词的性质功能和外在汉语句法结构的发展是促成“其”产生出指代词及介词用法的两大主要原因。先秦时期的指代词“其”由于是从甲骨文金文时期的语气副词“其”发展而来，故它的语意非常虚，并且随着语境的不同而改变。先秦文献中谓词前的位置仍保留着“其”的语气副词用法。介词用法的“其”逐渐少见。根据“其”的历史发展情况，我们发现汉语的历史发展还存在着另","categories":["02_字词句考释"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL5Ak2WkXxVO2Ep7lzjGe6Gqy0f7tld-4aPllxYmbq1NaxEzh7qVorXX_DBi6BPdsdxVCDqgTyscFw8pgvpcvJ3Jpwhgw9B2RXRHBBPtVutQVgYsyniBvS7c0qbkAmfETNtkFkvYSM55WotpuQUb6nHK0bm3p64gbUK4CZ-tDptuIAiItZr48LJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7142,"author":"趙平安","title":"商周时期金属稱量货幣的自名名稱及其嬗變","abstract":" 商周时期有一种按金属(青铜、白银、黄金等)质量来进行交易的货币,或称饼金、金饼、金版、版金等等,一般泛称称量货币。平心而论,称量货币这个名称既贴切又通俗,作为现代规范术语使用是完全可以的。但是,这个名称是后人赋予的,殊不知它在历史上有过自己的名称,只是不为人知而已。作","categories":["02_字词句考释"],"year":2003,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbol7naAYp6isw9oKi1fRxBWd5PSFpgtN78bvQxmwYRoqGhoQ5WUE6DI6CfYQVN9J6Dqr2HSBHBr26fYCrY_AQ9oosh5iZNqFU17UIs5SMknWy9TxzwdexYt-ucJY8cE1bLR6mHDDUMH1QqOIlqyIXpbqInNWLuggfvDfqh8Qq7Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"103-107","volume":""},{"id":7143,"author":"張再興","title":"西周金文字素表聲功能二题","abstract":" 一、西周金文的双声符组合表音现象裘锡圭先生曾经分析过多声的现象,并指出:&quot;真正的二声字是极少的,而且大概是由于在形声字上加注音符而形成的。&quot;裘先生同时认为二声字是由于在形声字上加注音符而形成的。我们在西周金文字素功能分析中发现了相当数量的多声现象。有这么","categories":["02_字词句考释"],"year":2003,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbol7naAYp6isw9oKi1fRxBWd5PSFpgtN78bvQxmwYRoqGhoQ5WUE6vtBaRyba7GnuCFukvhpgK-B3O3RuC9mRq-aA9Asw-g3W98oCpAUwEtC0ySpv5F2014gFWdj893sHAmX8dG2asfihMJUaWYLbR1rBK8fyKsouOPVwJoXlwA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-115","volume":""},{"id":7144,"author":"潘玉坤","title":"西周金文中的賓语前置句和主谓倒装句","abstract":" 传世典籍中,宾语前置句和主谓倒装句均不少见。出土文献情况如何呢?据笔者所知,西周青铜器铭文中的同类现象就还没有人做过系统清理——原因可能是材料太过分散。现在,全面覆盖2001年以前所有已公布的商周青铜器铭文的大型语料库《金文资料库》已经建成,这就使得清理工","categories":["02_字词句考释"],"year":2003,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJejau0EQAe0Bb-dO3ityU8SdAfJpz58Z0vEqEr9NZba-x5JmRRB85vveDJiElpqUp4qCdbta1H2wP8eVwxzQXOEfWcvT8YXifbPlFhexL7El5bAOMuFrEo4CpBtpwo_Yj9f2LvLBqsxH031ndQ6BJpEN38NcWWiYNOBJgO6GatGQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"116-120","volume":""},{"id":7145,"author":"黄德寬","title":"关於古代汉字字际关系的确定——以“顧”及相关字为例","abstract":" (一)字际关系指的是形、音、义某一方面相关联的一组字之间的关系。异体字、繁简字、古今字、同源字、通假字、同形字等,都是从字际关系角度提出的概念。汉字的整理、研究以及古代书面文献的训释,字际关系的确定是重要的基础性工作。在古代汉字的整理、研究过程中,字际关系的确定涉及到文字的考释、工","categories":["02_字词句考释"],"year":2003,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJejau0EQAe0Bb-dO3ityU8SdAfJpz58Z0vEqEr9NZba-x5JmRRB85v2Zamowq2RSbrnXYq3nWiAYm4vtjkZnZYopFBHNmlXjBaWTR7DZsmRiBVNk9l84YKzS1yJvlMkfsUoufJA2MUA67ExsbILpiDUi6Wt-orXbNefJVA3vIVtg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"275-280","volume":""},{"id":7147,"author":"史克禮","title":"《鱼鼎匕》铭文性质及“下民无智”的有关问题","abstract":" 一、《鱼鼎匕》铭文性质的有关考释《鱼鼎匕》为罗振玉旧藏,曾著录于罗氏《三代吉金文存》卷十八第30页(为罗氏摹刻本),现收录于《殷周金文集成》第三册第223、224页,内容包括考古所拓本、罗氏摹本和罗氏摹刻本三种。《集成》定为战国器。","categories":["02_字词句考释"],"year":2003,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkhyIm4Qi6aL7MqM5S6zoGeSTdYAzsazmWQj5or8oT2z5u3omPVMioECP5EpQVnR12_SZiYIzzZGjz0yQqRbQbVPwAAbbV2oNals3s_r6ByE_nNnhVZoG6vq7a5ACEGGujXCbfpLbzNIz8iCM_hw-EU3P_6dmjZlSBFBBdbqaDSw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"130-135","volume":""},{"id":7148,"author":"陶霞波","title":"关於商周金文中的“赐贝”及与货幣相关问题","abstract":" 赏赐是商周金文中重要的内容,在众多的赏赐物品中,贝是比较常见的。尤其是在商和西周早中期的金文中多见,西周晚期急剧减少,至东周时代的金文中已无一例。因此我们所要讨论的&quot;赐贝&quot;问题实际上只涉及商和西周时期的金文。通过对《金文语料库》中所收的金文资料进行了排查,贝字在商周金文","categories":["02_字词句考释"],"year":2003,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkhyIm4Qi6aL7MqM5S6zoGeSTdYAzsazmWQj5or8oT2z5u3omPVMiojb6Sx0g7si5dN4A4udw9RiMrbmE6PbNyn2bYUodg3nSdXPl4NZ9a3XEA3RG0p62M3CEAgB7-qlQLWLVc-Q7ACh2GWvDnjhzGbZA0-l5afa2tzyViCPZA6w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"136-140","volume":""},{"id":7149,"author":"夏渌","title":"释妇、事、家等古文字","abstract":"一、释妇附图(1)甲骨文、金文和小篆“妇”,《说文》释:“妇,服也。从女持帚洒扫也。”释:“服,用也。”反映了封建社会重男轻女的伦理道德观念,《大戴礼记》:“妇人伏于人也。”《白虎通义》:“服于家事,事人者也。”把妇女说成是“执箕帚”侍候丈夫的家庭奴隶。从甲骨文、金文的字形和记录语言的词例看,妇字并不是从女持帚的“扫把星”,而是女性俯身从事农艺,在田间插秧种植的形象。在母系氏族社会,锄耕农业主要由妇女来主持,男性分工则为渔猎及以后的畜牧业。“妇”字从女插秧实际上代表当时的先进生产力,从而在古汉语和古文字字形中,留下了历史和文化的“积淀”,反映了原始氏族社会的先进文化,“妇”字得名本源于女性首先","categories":["02_字词句考释"],"year":2003,"publication":"人文论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3O8z4P2FLfeAxbuLgb4pUkzPMPov-_kYynbxmWSF8jkeoYxYBvSd1T42Qlmeb2bXB78Pktutt9G8t073Hm8xca5LzZY3YwvJuPFXsFjeyLUkBlsAe0tWZfDvg67AFSZj3SCo1f3t8erc1vs-8B1TqKjpWM_LyWJn9GI43ITi9lQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"267-273","volume":""},{"id":7152,"author":"曹定云","title":"古文“夏”字再考——兼论夏夨、宜侯夨、乍册夨为一人","abstract":"一、&quot;夏&quot;字的类型及其衍变1995年,我在《中原文物》第3期上发表了《古文&quot;夏&quot;字考》一文。该文根据殷代甲骨文、周代金文、战国玺印、帛书等材料,共收录了15个不同的&quot;夏&quot;字,并根据字之结构、形状、分为不同的类型。在此基础上,该文又探讨了&quot;夏&quot;字的衍变和发展①。为说明问题,现将该文中的《&quot;夏&quot;字衍变源流表》重引如下。","categories":["02_字词句考释"],"year":2003,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLIrrtqm0WWKJ1fwVa2EF48JR8H--Fi7FDrOj-COrBcVX1iNImcl04BeWomycABh3I8so6Acyu8viRte5yD9xU938NTKYYfss3bZyMV3Bfh-_5bgDnfBZMTN5jZMLQyH_C3wVT8uajp5eN3vlOmdGdafj9M6wO5Aq_jFwpoqrLl2A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"482-492","volume":""},{"id":7153,"author":"陈炜湛","title":"碧落碑中之古文考","abstract":"碧落碑书体以小篆为主,其次为古文,二者交相为用、融为一体。书者为求美观,或篆或古,信笔为之,且一字多形,错综复杂,遂致艰深难读,令常人望而却步。1981年秋,我陪饶宗颐(选堂)先生游晋南,至新绛,伫立于此碑前良久,既叹其书艺之精湛,复恨其古文之难识。后得观中华书局《汗简·古文四声韵》(1983年)一书所附之碑文拓本及紫禁城出版社《唐代石刻篆文》(1987年)所载故宫所藏明拓本,二者相校,粗可通读。后又于《金石萃编》(卷五十七)得览有宋以来欧阳修、赵明诚、汪由敦、顾炎武、董迪、钱大昕、王昶……等诸家题跋品评,乃知郑承规之释文亦多有可商","categories":["02_字词句考释"],"year":2003,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2QrCf8WUbUBvnLCFiyK1S3x0TleV58gbjl_gXTSK2UmPwWuFpvC7nKuvGiY1prJYb_s63EjdTSd-W_y3DUED3ZBEFfRpsvYxCn83RsoSKUchzNbif10g7apO-3xPjEq14XUrqTvq0w7IUfGlUTFay4SkY1awu_t88lXvoWZJdDA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"979-989","volume":""},{"id":7154,"author":"曹玮","title":"也论金文中的“周”","abstract":"周是西周金文中常见的地名,研究西周史无论从什么角度入手,都无法回避这个地名的定位。但这项研究也是较为棘手的一个问题,其涉及面广,且学者多有论述,但观点分歧较大。本人在读书之中,偶尔受启示,有感而发。谬误之处,敬请各位方家哂正。一、文献表述的&quot;周&quot;文献中单提到&quot;周&quot;时,所表述的有二层意思:1.指建国前的周方国或周族,以及建国后的周王朝。如《尚书·大诰》:&quot;天休于宁","categories":["02_字词句考释"],"year":2003,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2QrCf8WUbUBvnLCFiyK1S3x0TleV58gbjl_gXTSK2UmPwWuFpvC7ncbjXBH88z6Cin18SX4jpOrcXy1tTo09cb9p2dxXUcO8iirrjWQDKWjr-ebsptaA2hbH7a7pR9X9oznndJABDFvvMbz3ma7aOHnjTtrVs8hCqk-63fccTRw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"581-603","volume":""},{"id":4882,"author":"辛怡华","title":"关于西周时期的铜饼","abstract":"一文献、金文中的铜饼在西周金文中,一般把铜称作金、吉金。《周礼·秋官·职金》云:“旅于上帝则共其金版,飨诸侯亦如之。”郑注:“饼金谓之版。”又《尔雅·释器》云:“饼金谓之钣。可见,金版,饼金,就是铜饼。1993年初,河南平顶山应国周墓地出土了一件柞柏簋,其铭文记录了康王在周都举行大射礼的过程。①。","categories":["02_字词句考释"],"year":2002,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLspcUbkjhNMbzgDZeb_6QkafxmeVm3HMcq_TAQNg14q634HrAPrj29Z6e-AQgU75NugWA74VGBxTsucEK58NXukUytYjbMHylDXtNTweqvhqQ_aAd-lxCazGW7BJDRzu4YGvM1v09tN8X2vAVCT4yI-jTZbx1L7K9gs32YDsU7Oc9_7mGTHC-T&amp;uniplatform=NZKPT&amp;language=CHS","pages":"238-239","volume":""},{"id":4884,"author":"王龙正; 王宏伟","title":"班簋及濮侯玉戈铭文补释","abstract":"我们曾在一篇小文中将甲骨文、金文中的■、（彳止）二字分别隶写为诞、延,并均释为信①。据此对班簋及濮侯玉戈（原称太保玉戈）铭文的相关文句作出新的解释,请学人指正。一、班簋（例句一）遣命曰:“以乃族从父征,诞城卫父身。”（例句二）公告厥事于上:“唯民亡（无）诞才（哉）!彝■（昧）天命,故亡。允才（哉）!显唯敬德,亡（无）逌违。”","categories":["02_字词句考释"],"year":2002,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJB1pfpNVpXwzngirlLDjFcQiucEyh9EYV8BBlVC8v85TCtMatj_E-RNQ5Fh-iXSJOai7E0UtJi7_4KRB8vYqBKKyE5O-nt_gS3JfAYW5KrblMSLqQFhWOVuOGrIaqy7VxwlNfTjxx5IyX6pXvSgQKibS1nhyNI5w-HhhTJj_axhX7Bhaq5Rxi6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"343-344","volume":""},{"id":4887,"author":"潘玉坤","title":"读铭札记二则","abstract":"一、“封”字别构《集成6.3518》首字为人名(下面以H代替),形体如(图一:1),铭辞“H乍父辛尊彝”。该字形《金文编》未收。《集成》的处理办法是,左旁照摹,右旁隶为丮——归入不识之字。《金文大字典》更只出原拓,不加隶定。但《集成释文》(香港中文大学中国文化研究所2001年版)隶作“對”。","categories":["02_字词句考释"],"year":2002,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIuNtWecYR5m0rosa0kFnYNCXMiGSUxeEfj-Dz_4s_f8wa7G0FK5gG5hTtNouNxaJtfVJ2WfvQYCJ3_7-qU_FxqneFPO7i_-ZjdRQWYI_x9GnudQPnidseUex0AKSW30cJKj-2GGN3I8Vk-MrRUkb2wogyFtgLmN8TO1HgxDj8WpqL9Mv773wWj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"356-357","volume":""},{"id":4889,"author":"裘锡圭","title":"应侯视工簋补释","abstract":" 新近出版的《保利藏金(续)》收有保利艺术博物馆新人藏的一对应侯视(旧释见)工簋。这对簋是有很高历史价值的西周中期重要铜器。上举书中已有朱凤瀚先生的说明文章和王世民先生的有关专论《应侯见工钟的组合与年代》,对它们作了很好的介绍与研究,我们在这里只想对簋铭的考释稍作补充。这对簋,两器同铭,都是器盖对铭,见上","categories":["02_字词句考释"],"year":2002,"publication":"文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPjhy6OAMLfqcGl3uftWVY2WO43QnworbLZuVCEi-ky-gJr8VEG16XWif1kL_rpTrR2y0p_vpfLyESSsYprvu5HqFH9Hy-OOcMZ6uzOuW5mGk3Q9icAkwxUyTB3tNAcSZIkvIHeU4F_pxV1OWGYhlG_He0WYz-f5EaL_0PVKisjfV1U9xHq_De&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-74","volume":""},{"id":6091,"author":"裘锡圭","title":"■公盨铭文考释","abstract":"保利艺术博物馆新近购藏一件失盖的有铭铜　。从器形和铭文字体看,其时代当属西周中期後段。铭文共十行,除最後一行为九字外,每行皆十字,共九十九字。铭文的格式和内容与一般西周铜器迥异,劈头就说天命禹治水,天为民立法立王,导民以德,接著以较多文字讲民之好德者应如何行事,最後以　公说民当用德的一句话作结。　公似即作器者,所以暂名此器为　公　。从这篇铭文可以知道,当时人的确把禹看作受天之命乎治水土的神人;并可据有关文字纠正后人对禹治水传说的一些误解。更为重要的","categories":["02_字词句考释"],"year":2002,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUl875E2PjmUwgXBSys34AHKbXOuImwY6nP56KYAbxyfsWOZcQ3noiVZnRFq5hol8Y6MK_uPd7wppZzXkM2Mz0WMx6Mb2JTsckO5Q0xALo4Qyn2EzsoAJkOE3aDBn4P5Ot2N87qRYVVdwLQLq0WSCDHuVYvRk4L3BrPdrCmtKffQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-27","volume":""},{"id":6092,"author":"朱凤瀚","title":"■公盨铭文初释","abstract":"　公　为保利艺术博物馆所徵集的西周青铜器。器横截面作椭方形,圆口缘,腹壁较直;圈足较矮,足跟外侈;两侧壁上部近口沿处有双兽首形小环耳。口沿下饰对称的长卷尾鸟纹纹饰带一周,腹部饰瓦纹。比较特殊的是,其腹内壁也随外壁的瓦纹凸凹而相应地作凹凸状,这在同类器型中是少见的。器内底有铭文十行九十八字。","categories":["02_字词句考释"],"year":2002,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGCGFOmUA5OhvaRkjEJmSYyO134V76CuWty_tOHBeOpwL8b4hRnPMzGDLoQfS0V2lMNAEO7ldSPKpeLPV7SiUKlKGKVbRb-3AsG3XqwKsshRkVuyz2sjWelvGoCZRTIqvJHnnZ8J7kLNRg8XLNChha0YELEmjM1GSK6CoM_oYwCw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-34","volume":""},{"id":6094,"author":"辛怡华","title":"试释金文中的“王若曰”","abstract":" “王若曰”是西周时期青铜器铭文中常见的一种格式,常常被译为“王如此说”或“王是这样说的”,或者认为“若”在这里没有实际意义。但笔者认为“王若曰”是一种固定格式,它的出现一定是涉及到王朝大事。“若”最初之意是为了探听神意进行祈祷的活动,或者仪式,“若”与神或上天有关。在君权神授的社会里,统治者的一言一行,当然是上帝意志的体现,而人们的一举一动必然听命于天,“王若曰”自然是统治者转述所谓的天帝旨意,以证明其行为的合法性。","categories":["02_字词句考释"],"year":2002,"publication":"华夏文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKth6P97vblGvxq7LY6YLn3vBQp3x4PhPiTtpv_9wUFXjeFp_Ovv9hpiS1naCT6MfIgGT55z88meBD6hOKF5AEkHsqhVGbJ2k5th8cbWsk1p9fBlyj1LfmqtOzvIh4Ue-e1i5_5oHXDb75Hh-MqrvjZ18YqsWkTm3UQHI2WuaNQ7g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46338","volume":""},{"id":6096,"author":"梁光华","title":"释“召”、“招”","abstract":"本文通过考察甲骨文、金文以及古今汉语文献资料 ,提出了一些新的观点 ,考释了“召”、“招”本为一字 ,并论证爬梳了“召、招”的本义及其引申发展的词义系统","categories":["02_字词句考释"],"year":2002,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2002.04.018","pages":"92-95","volume":""},{"id":6097,"author":"邓飞","title":"不其簋铭文“永追”考","abstract":"一直以来,学界都把“戎大同永追女”认定为是“戎大同从追女”之误,且是个偏正结构。笔者认为“永追”是个连动结构,其意义是向前行进而追杀。“永”的意义是与“追”紧密相连的。本文从“永”的字形、意义出发,讨论“永”和“从”的音义相关性,兼谈了“追”所涉及的结构。","categories":["02_字词句考释"],"year":2002,"publication":"伊犁师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_vUrHAYk8YMjyL1UA5po_yNgoV7ACt1rUKKRhE09Kp4xDbGzsuVAR4jwUj_JRChaNFMx74y2DhOwMBXW_9hgqUE05USd2VJjtc3cJJzbwcIzxE0SHX46DoD_CT1qghWEdvY9edrj_ouDIvFs3pB5fuQQs8J2EQ-v1RxrAYil0qA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-24","volume":""},{"id":6098,"author":"程邦雄","title":"释“*(籆)”","abstract":"本文讨论甲骨文、金文中的“*”字。从“*”字的取象构形、构字偏旁、辞例、实物形体等几个方面加以论述,认为“*”字就是“籆”字。","categories":["02_字词句考释"],"year":2002,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_vUrHAYk8YMjyL1UA5po_yNgoV7ACt1oowJq9H2p-nQUyon20mcK5MGvFF27r7oaqktjX6t7V4QE1Ar55BfIbDxK1VJGaCYwXbsHW1TjEChsUr3zfBRqq_yNoDYjjBe7ysRHTZkxP48e_m76fRW8C-QLgsUB--BxGlRFaEy_LcQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-79","volume":""},{"id":6102,"author":"李学勤","title":"韩国金海良洞出土西汉铜鼎续考","abstract":"韩国东义大学博物馆从1990年11月起,在庆尚南道金海市良洞里的伽（?）古墓群进行发掘。其第三次发掘系由1993年9月开始,至1994年1月结束,所掘332号土扩木椁墓,属于公元3世纪前半叶,却出有一件有铭文的西汉青铜鼎①。当时有韩国学者把鼎铭照片电传给我看,汉城的《东亚日报》也作了报道。据此我写了一篇小文②,文中鼎铭的释文曾有论作引用③。","categories":["02_字词句考释"],"year":2002,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3BKDsTbW6H5d2DZkoB61CQDQ-wj2V95zJuh051YprtZvTjVytZoKY9IjaznQaV1_OE4Ew_JmAZGgf4wAp9n6Ce8c3HSE8al31MFZUeBVFYOXaVDDLIOiAvA2y0hvFXecmz3t8VbJYGMM8P1eC8vinCof-Hm_J99J5itL-T0362w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-27","volume":""},{"id":6105,"author":"乔雅俊","title":"先秦典籍中“丽”字意义分析","abstract":"“丽”,繁体写作“（?）”。今人用“丽”,多取华美之意,具有审美之意,然考之在甲骨文、金文、先秦、两汉典籍中使用的情况,便可发现,“丽”字在先秦时期的使用情况是复杂的,含义也比较丰富。在甲骨文中,“丽”字写作“　”,在此基础上,金文略作变化,写作“　”、“　”。甲骨文与金文都作上下结构,上半部都是同形字重文,像两两相比之形。下半部即“鹿”字,像鹿形。对于“丽”之本义,诸家之说各异。汉许慎《说文解字》中说:“丽,旅行也。鹿之性见食急则必旅行。从鹿、丽声。……　,古文,　籀文。”清孙诒让在《名原》中对许慎的说法做了分析:据许说,则古文先有 、 字,丽为后来孳益字也,而","categories":["02_字词句考释"],"year":2002,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxEd4zcrmhfV9546uslOqAT17fP0d4cRTGl7LjlWL-GN0ywHY05FYsAJzOusudfwvyxHvDlOchaRyCsRL2um6GSr71cnbcdX8cl0GQ0d5GAaFg4fXs9fvqVAoT2ghcY8VlUVO3ZqVV9tu8zISPsNICv6PBcuhpCTj7cFlyMinZJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-46","volume":""},{"id":6106,"author":"过常职","title":"庐江出土吴王光剑铭文考辨","abstract":"庐江出土的吴王光剑铭文,诸家考释颇有歧见,本文着重考辨铭文后二句,在某些字的隶定和解释上对流行说法提出商榷。认为剑铭是吴王光扬武奋威的自赞之辞,其文义自应以直接关系征战和杀敌建功为宜。","categories":["02_字词句考释"],"year":2002,"publication":"巢湖学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxEd4zcrmhfV9546uslOqAT17fP0d4cRRb81DzeTaG78C8vo66OUkB8lAgAA4HxBh9qHfEiIWijxRLcG6w4TRw9zVlbP5m2nfSpf2ZTmsVR-jFhhN5GMLch4dGeuoGNFRZRkbR3I0fRqJLp_atUpNWPH5IGJkf9JqIVHCvr83DWA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-33","volume":""},{"id":6111,"author":"叶正渤","title":"《逸周书》语词研究","abstract":"《逸周书》不仅对研究西周早期的历史具有重要的史料价值,而且对研究先秦时期的语言也有着极重要的价值。本文着重探讨了文中成语俗语的意义、演变及其对后世语言的影响,还讨论了月相词语的含义和所指时间,认为月相词语都是定点的。","categories":["02_字词句考释"],"year":2002,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLo-9EbayHAvV4JYmSRXjZm6B4R1Oaa6iGJ1XGwjJzSSFUwidzrFkYABB0DFSx1G4_llh18Pgeuz0DSaq58KXZ5bVTiYefFeMb-mla0qkatuxESauMm7iZQyNzi2KhSkZHNEI4Zv_c0-O4W7JtfGCwJv_6mYgSkJ0iGxhU5UaBhQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-47","volume":""},{"id":6113,"author":"邓谷泉; 黄竹君","title":"白象拳头,本义为手","abstract":"甲骨文、金文、古文、篆文白字,虽字形有异,但都是大拇指在内的拳头侧面之形,外部笔画表示手掌和四指组成的形状,内部笔画表示在内的大拇指,是拳头的象形,其本义为手。","categories":["02_字词句考释"],"year":2002,"publication":"长沙大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTATtKZcJD3O3d_tGcQwCzfGZOhjh2xVDkGFREncGURVA38Out18q-P4yYY9TGGrUS4mKrN7FjFcRT3iCPIChIJH1ZOkM1SvAUNtVKPGRk92rzz9VZa0gQuN06VdLpSwgK0Txom_X0Exs-Jrs6rr8eOXUfxGtq3lKNq0cTRJ-OBw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-33","volume":""},{"id":6114,"author":"孙中运","title":"甲金文“朕”和“般”的真象——同游顺钊先生商榷","abstract":"《古汉语研究》2001年第三期有游顺钊先生的《甲金文“朕”字构形的历史取象》（以下简称《取象》）一文。读后感到新奇,同时觉得还有商榷的必要。《取象》认为“朕”是“双手持权杖”的“般庚”.但“朕”和“般”的形、音、义径渭分明,不可混淆,现就《取象》中的几个问题提出商榷。","categories":["02_字词句考释"],"year":2002,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTATtKZcJD3O3d_tGcQwCzfGZOhjh2xVB8rsyMIplqHnwIlTO9anSOnYysR756tPD1KLfsyVvdHdYKtsafwPEjo6eDyn1mMiO2pACMkjZ-H7UfFbAkseRmJfqQvJDUaJj6dmeefjrbbxsdW8a855gGm2k4OZ7lYU_sH9lLK9BhYQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37","volume":""},{"id":6119,"author":"李若晖","title":"“谣钟”小考","abstract":"清乾隆二十六年（1761）,江西临江（今江西省清江县）出土者减钟11件,藏于清西苑韵古堂,后散失于英法联军之役。今存世仅4件,分藏于北京故宫博物院、上海博物馆、台北中央博物院、台北故宫博物院。除最后1钟外,余各自全铭。其钟铭著录者甚众,①,今著录最为完备且较易觅得的,是《殷周金文集成》,见其1·193-202。其钟铭元论长短,均有句作:“勾吴王皮然之子者减择其吉金,自作　钟。”其中“　”字从“欠”,以一从“肉”、从“木”、从“佳”之字为声旁。诸家考释大体如下:郭沫若:当是鹞字之别构,从鸟榣省声,此读为瑶,瑶钟犹它器言宝钟。②董楚平从之。③陈梦家:此乃谣的假借字;谣钟犹歌钟。④施谢捷似乎是在不知","categories":["02_字词句考释"],"year":2002,"publication":"中国社会科学院研究生院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKj8wH_q8XU3HTrel8_3RQdeesJ8L9a-lXmqMgMeRXSoV4KqNxu_dP6gtNm0Rz5FdF2wGPrICGITQgsazhg1b6GM6T3i6gNyERpuzmnQ7yd98PvAP9dqXCZuG2FJ0spsQyUmBzps9vbQbWsC095tqb1eOKCUzF_SeUa-PiNyRUdDA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107","volume":""},{"id":6120,"author":"陈絜","title":"《■簋》铭文释读中的几个问题","abstract":"稗簋铭文虽经众多学者研究,但有些问题依然存在分歧。本文以为,铭文中的“赐　户、　”是指质赐　地的民户与　地之贝;器铭所涉及的王世与月份问题有待于进一步的推算,“遘于妣戊武乙 一”云云是当时的一种纪时形式,并不能说明器主与商王室有必然的血缘关系,而器主的真正族姓则为己姓。","categories":["02_字词句考释"],"year":2002,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKj8wH_q8XU3HTrel8_3RQdeesJ8L9a-lW1FxaoU2PUtlIlxt6X4lK-lQWHeQ5m0uZ6jzG2tfaeCuAEeTrcXf_lO7DbCxCLinfzgG-7YDia9fF1FFi6bDOhlW596cnaTfkoNQzIg5vBel37UjbSdlEtvuVPQhEvbSxWHO9zHo2ZuQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-73","volume":""},{"id":6123,"author":"张经","title":"曶鼎新释","abstract":"清代中叶出土的曶鼎是非常重要的器物,尤其是其铭文中所记述的两起案例,为研究西周社会历史提供了宝贵的资料。本文在前人研究的基础上,重新对该铭文进行考释,并讨论了西周金文中的众和臣的身份以及地贱人贵的现象。","categories":["02_字词句考释"],"year":2002,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2002.04.007","pages":"49-57","volume":""},{"id":6124,"author":"刘桓","title":"释颂鼎铭中册命之文——兼谈(宁贝)字的释读","abstract":"本文在前人研究的基础上,重新对颂鼎册命之文作了释读。通过铭文与《周礼》的对读,明确了颂的职官为成周的贾师(亦称贾正),周朝在成周设此专官管理贾人市肆,贾师还负责监管官府新进的为宫中所使用的货物。同时,笔者亦就宁与贾的关系有所阐释。","categories":["02_字词句考释"],"year":2002,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2002.04.008","pages":"58-61","volume":""},{"id":6125,"author":"叶正渤","title":"西周金文月相词语与静簋铭文的释读研究","abstract":"","categories":["02_字词句考释"],"year":2002,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKr23C3VKsWIWgbOWff6tvgp1r6FMpTM8FUM7Dd45jep9maEcshgjff_E99R8-kOy_1vh6yAxYav8HhR0duj3WOWjeLipLOHL3gS-NXykluojtMme2s4TsxtCiReK8kO8ODRP0ISRqDseSugDhbqGvW3gHV4TORGdTowInjfgBPdQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-23, 44","volume":""},{"id":6126,"author":"曹兆兰","title":"金文“女”、“母”的形义试析","abstract":"金文中有关“女”、“母”的字形 ,从文字的产生发展来看 ,应该是先有。由于所写词义太多 ,人们要求在字形上加以区别 ,于是产生了、二形。起初分工并不明确 ,其后发展路径各异","categories":["02_字词句考释"],"year":2002,"publication":"学术研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKr23C3VKsWIWgbOWff6tvgp1r6FMpTM8Hi71ACpAKX0dHe3D8X5sw_Zvkl146GZuZYabYEr_cErGXQoLTtNb2doaIsfiLRkRStDZxEHMRndR4qyItjIFXOXfhXktQ3dLbB04YDLLgMD7dbVskwVkp71-LV8oIBHHv1LpbyGv9Krg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"128-131","volume":""},{"id":6130,"author":"贾齐华","title":"也说“合体象形”","abstract":"“象形字只能是不可分割的独体之文”的观点具有代表性。而“独体为文,合体为字”之“独体”应视为一个相对的概念。象形字中确实存在一类为强化实物的区别性特征而在目的物上添加连带部件的准独体字,所谓“合体象形”是对这类象形字的传统叫法。这个名称中的“合体”容易与“合体为字”中的“合体”造成混淆,因而应拿“加体象形”取而代之。","categories":["02_字词句考释"],"year":2002,"publication":"河南社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJbwJQYy_DlimymBCGxb1cYBuy8QYQLXJv91o0pyj5XxWKZXKJBh3UM0qwV8ITw9YHv9nShAyeBmGmBZiNBeHovjBSMRndcnoWUrvUjWH1q8ibA6SifS1pMJa9KAYlgrK7MBM1f51CTU9XdH6yGwQ9sw9kfvOabQ1apWdVq1Z7Grg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-77","volume":""},{"id":6131,"author":"陈双新","title":"金文新释三则","abstract":"本文选取传世或新出的乐器铭文中三个重要词语,就前人所作的训释提出疑问并立新说,如释“遹省”为“天子五年一巡守”之“巡守”,释“偿”为“溃”等等。","categories":["02_字词句考释"],"year":2002,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIG6Cct8_M1AOMDMqukdOHtR02fBrZAkemPG6DN_kfaatV_xMLpt7ciAFj-M7Awne7WNZatzpgwJZ31FffR-N3RKlErJu_2k0B-QNDYQ0CFDQRmnis3b1FKDe-c8rvKjBtE7jnX8stKwKaDenzzE4XutB8jdcpk2JrG4A1uyP4H4g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-49","volume":""},{"id":6134,"author":"杜勇","title":"金文“生称谥”新解","abstract":"西周金文中的武、成、穆、共、懿等王号 ,因出现语境上的生称 ,致使不少学者认为西周或西周孝王以前犹无谥法。其实 ,只因这些铭文铸作于“生称谥”者谢世之后 ,才得以用其谥号追述前朝旧事。从金文中的多种文化现象和大量事例来看 ,谥法应创制于周初 ,且有一个从天子而下及诸侯等其他贵族的扩展过程。那种认为西周王号为生称而非死谥的看法可能是不符合历史实际的","categories":["02_字词句考释"],"year":2002,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfci7CSQrw3AvV4H-5qv2QlLUvhYczFvAVkltlScJjCkxtmmPF1VtGtkV25rxMagcqirwu5UofqSwfpChENxkMsp55TzMApiS7ufbtE9WDvM_16CAyQlOtgQZ2uzAfq2oBDRefk5vDkIFbXJFBrhGhRB00Z78JQPaaZ10jvSUppQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3-12, 190","volume":""},{"id":6138,"author":"臧克和","title":"基于《金文资料库》的《尚书》文献用字研究(二)","abstract":"殷周金文是地下出土文字材料,《尚书》语言是传世文献,二者大体可以认为是共时的语言材料。前者局限于格式,后者损失在历代流传抄写过程。将二者进行参互比较,对于降低两种语言材料的读解难度,认识该时段语言及用字特点、频率,建立专家数据库,具有不可替代的价值。华东师大中国文字研究与应用中心开发研制的《金文资料库》,所收青铜器铭文释文对应的青铜器囊括２００１年上半年以前所出土并发表者共１３２７１器,为以往任何金文著录形式所不及。本文是在对《尚书》历代传本基本用字调查的基础上,开展基于计算机《金文资料库》的《尚书》文献用字研究。本文所给出的有关数据,就目前而言都是穷尽性的。文章的第一部分刊于《中国文字研究》","categories":["02_字词句考释"],"year":2002,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIERdCURewtxF5YulIi5-iAamzbd-AiVd9teV_H0yWE0pvsJnJf34Lnw4J50nzSjSXtm7Z6-gnY16e9ohn9xMTlx5OXOTKozuw2h3R1KPOHnb5nMlIpyVsH9pQsUBGPmj-q-Jofi356i2UI6PSkX2JPb_WMif11umv7QTn_rMPwZQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-22","volume":""},{"id":6142,"author":"曹兆兰","title":"金文中方言“嬭”与雅言“母”的相因生义","abstract":"“母”的字形是“女而乳子者”的侧面象形;“(?)”的字形是“女而乳子者”的正面象形。“母”、“娴”在“母亲”这一词义条件下,是有雅言、方言之别的一对同义词。“母”在殷周金文中有“成年女性美称通称”一义,主要用于“×姓×母”的女子称谓结构模式中;“(?)”在春秋楚系金文中相因生义,也具有了“成年女性美称通称”一义。金文中(?)通女(母),是“古音娘日归泥说”金文一证。","categories":["02_字词句考释"],"year":2002,"publication":"方言","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKhkP1JytzIwBfGVAbSwtL5lA5_oB_xK3tUzrYWAm6sy1XegMsUTJ-Uexlb0Vlg90qu3l931_geffd6rNVgrQv9YYgsL9M4jWPegeoEPZGmfkBt1JILZVnKN7imsdowvc7HZgoIjLwyLWI5_GDC-PNgK-v6nvOOMyCP80qk_deBwQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"177-182","volume":""},{"id":6143,"author":"张懋镕","title":"“鱼伯己”觚应为“鱼祖己”觚","abstract":" 《考古》1999年第12期发表的《山东青州市发现&quot;鱼伯己&quot;铜觚》一文中,对铜器铭文的释读不确切,应更名为鱼且(祖)己觚。从字形分析,铭文第二字不是白(伯)字,而是且(祖)字。此且字写法见于商代晚期的","categories":["02_字词句考释"],"year":2002,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6cO2GW5aMyzbLrJhDKFGBHYC3EcvlXWmpUbBfDwxhCkFL8vmoXRI-mI42WgCHp_PTBfWjzA8MwgyzrHrPFNZABJr0beB0zyfDCO0AeUMScDNMS162Jl5flpcf3yjWTQwq_4vvaOtyCX8hEoovAbDOBMIbIs486YJwm_Z1g8TfWg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"93","volume":""},{"id":6145,"author":"施谢捷","title":"东周兵器铭文考释(三则)","abstract":"本文对见于《殷周金文集成》、《三代吉金文存》等收的三件东周时代的兵器铭文作了重新考析 ,纠正了过去的一些误释 ,并确认了“齐城造”戈铭字体是迄今尚未引起人们注意的另一种不同于楚、吴、越、宋等国的鸟虫篆","categories":["02_字词句考释"],"year":2002,"publication":"南京师大学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGWWm_jmAYFFFqFn69y6Q36sALGTKJu7ptoT21IG0S47sbohwgybrmP59_1RYrOu6CT9cPaPeB39C8sDV2O5B77chnMpyV91bUkhP9R5urMgf-CigGnHn47vuC1VD1QVxxEwVDe3FLE4BpQfCyRnPlnOb-mL8qObYC7N7El8D3sw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"155-160","volume":""},{"id":6146,"author":"王冠英","title":"作册封鬲铭文考释","abstract":"本文对中国历史博物馆新藏作册封鬲铭文进行考释,并说明该器作者与伊簋记载的“命册尹封”为一人,两器都是周厉王时器。","categories":["02_字词句考释"],"year":2002,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGWWm_jmAYFFFqFn69y6Q36sALGTKJu7pjjdl_uhXyTrWwQRMtZYPD3DZfzTC3nzSFINaFzW_wJRJ_xQRrxQJahnJD5BRfuz0DHwU8c061UPFs3GTexAVvsfoicWNit2MJ_HBvsPHpfXmyXILiNlpwZgWHvkuAb9U5ik3_aHAjBw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46118","volume":""},{"id":6149,"author":"贾燕子","title":"金文介词“于”用法补议","abstract":"甲骨文、金文中“于”字用法值得研究归纳,还有可补之处。本文主要对西周金文“于”的用法做以下补充:于带谓词宾语;于引进时间;于字结构的状语用法;于字结构的连用;另附于的动词用法。","categories":["02_字词句考释"],"year":2002,"publication":"大理学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKexha8H-UA_l37WPV35txBjKRVOxseTYjcADyZVO3S1G6nbBEGfDMyeHP7chKFKOFY2Y5TntYX-76QF89MiRD0vym8NEEW4WUMQV5Lh6J3ekIGM4zyKHAhI5V17666FylxIe1wEvaTFx95omuk0th7X8YpzfZtyMdp3S9M6TNo-w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-73","volume":""},{"id":6154,"author":"袁庆德","title":"古今字与古文字本义的考释","abstract":"有些已识的古文字的本义尚未得到考释或尚未得到正确的、明确的考释 ,在这些古文字当中 ,有许多都是在本义上被后起的今字代替了的古字 ,由于它们的本义很早就不使用了 ,而人们又往往习惯于从一个字在古文献里常用的意义中去寻找它的本义 ,结果不是找不到就是找错了。对于这类古文字 ,只有根据古今字的原理 ,找到它们的今字 ,才能确定它们的本义","categories":["02_字词句考释"],"year":2002,"publication":"大连教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKlmZ0yb-IP7uOFKiIgy5H8X36NxKZYO6igWdoSyR_Vec1DwbuGDD1Rd6kZ7r0FnCvzHr6KHuOjG5OlMq0z9OPM9A7hMBdrufg61LqNGrMQzP-cdKjcwXfnAdN7sotJIICQjyGdcgADk5CGu4gRgzekFy0bazYnHWpqE6oW5vAfVQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-48","volume":""},{"id":6156,"author":"施谢捷","title":"陈发乘戈跋","abstract":"《文物》2001 年第10期载山东沂水县博物馆《山东沂水县近年发现的几座战国墓》，发表了1999年5月出土于山东省沂水县城北25公里高桥镇马家方庄北部M7的一件铜戈，戈内近端处铸有铭文4字（附图一），原引李学勤先生说，释为“堕（陈）发裘（造）钻（戈）”","categories":["02_字词句考释"],"year":2002,"publication":"南京师范大学文学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDT-S0tSkdKMYAR6ZTusHjltpTdHXwBCoX6fHtQD95XF9ecAEr2fmjDmSvCHcTI6frYy-HbRFNLQXaOT1R6eP52cQm16ysWdgc2GRLCkLqA_J4czWCH4NEJNb_zALsvzDXIkcdt8s_7I8GSKQDS6Nb8XSBPI1t12oCLe8wRbPoYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"169-170","volume":""},{"id":6157,"author":"郑慧生","title":"释“毛”、“舞”","abstract":"先秦典籍中,“毛”字含义有三:毛发与兽毛之类;草类;五谷。金文和《说文》中的“毛”,字形像谷子。“毛”字的基本含义就是“五谷”。甲骨文中无“毛”字而有“舞”字,“舞”字中一人所执之物非一般所释的“牛尾”,而是倒执的“毛”,即五谷。“舞”是古人在谷物成熟后执禾而舞。","categories":["02_字词句考释"],"year":2002,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2002.01.004","pages":"16","volume":""},{"id":6159,"author":"曹兆兰","title":"金文女性称谓中的古姓","abstract":"","categories":["02_字词句考释"],"year":2002,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKCFB_CSYsW7d6t2r4D4u4opkteiPlZ09bLCA8oDRWT7_UR9R7Ch9zJM158fgsQDSF-d87yHLYmANYklSm3zeFDrw1XmvIKyQAGNi_Wt6-3RzY4ldf-Ro1H9vyjZ7hA8gODRh-aRYGlxyYGZzpU78tKaJhFYNIS2Bs3flGddIn2eQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-60","volume":""},{"id":6161,"author":"贾燕子","title":"金文介词“于”用法补议","abstract":"郭锡良先生《介词“于”的起源和发展》是对古汉语虚词进行个案研究的一篇力作,但文中对甲骨文、金文中“于”字用法的归纳还有可补之处。喻遂生师据此作《甲骨文介词“于”用法补议》,对甲骨文“于”字的用法做了详细的补充。此文对西周金文“于”的用法做以下补充:于带谓词宾语;于引进时间;于字结构的状语用法;于字结构的连用;另附于的动词用法。","categories":["02_字词句考释"],"year":2002,"publication":"黔西南民族师范高等专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLMJ3l-LbIvYBO7jTlm7ffob8KKjGz4ZcnYubluhTlF3NAmiQJXNmTYclPADtdIqWHhpuQasKbbfzGrkUbmbAS50DtCm2W9eFIAtLsUaZYpRGOe2w4g9TasdyaM3735fy8WKgcX2KsDFjiFPH2Q6xCfFr_64rsRlM_pF2AFKdMl8w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-32","volume":""},{"id":6163,"author":"程邦雄","title":"释“■((矍辶))”","abstract":"本文讨论殷周铭语文里的“(?)”字,过去释为“(来辶)”或“(?)”,没有定论。本文从字形分析切入,通过该字所在语境的探讨,结合相关字词的考释,在否定旧说的基础上,提出了新的见解,认为该字就是后来的“(矍辶)”字,在铭文里主要有三种用法:第一,用作人名;第二,用作动词“行往” “前去”;第三,借为“護”,表“辅佐”“辅助”。","categories":["02_字词句考释"],"year":2002,"publication":"华东师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16382/j.cnki.1000-5579.2002.02.013","pages":"88-91","volume":""},{"id":6165,"author":"朱凤瀚","title":"士山盘铭文初释","abstract":"本文对中国历史博物馆馆藏青铜器士山盘铭文进行考释。指出该盘为西周中期共王时器,铭文内容反映了西周中期王朝对下属侯国及附庸小国政治上的统治与经济上的依赖关系。","categories":["02_字词句考释"],"year":2002,"publication":"中国历史文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJm1K4_KGln6fM-XK9IlfqOUoN46WxABUU4ZRJ5E92C6tort1ytC9BqfKgbdvcEExX2YlzO5A-OSyQ_bw8hCq2bU6cf_dcfg58Er6DHf2gs-nOyJvhTXxA1Lg06tCMLxKHdSl37RSvUXhaIXXuk5GZ0Dbp9QjGD_Bk_2gANlLshcQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46119","volume":""},{"id":6166,"author":"梁光华","title":"释“召”、“招”","abstract":"本文通过考察甲骨文、金文以及古今汉语文献资料，提出了一些新的观点，考释了“召”、“招”本为一字，并论证爬梳了“召、招”的本义及其引申发展的词义系统。","categories":["02_字词句考释"],"year":2002,"publication":"黔南民族师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ41X8m9LqnSngvxNxUfDazcCdGewCcfxxIiiSWUWlcVAFM9R9Z1ArdEg-fBPMMyBaT5Brq9Ly_W6vMrQznLOUBrPi0louz_mnxnytAUqT-kgaeyUS8gWm1BzgcBfqW_8bK3rc56xhxMMW_gTPBDfF3JAYXoBFrr76epoILDEdvYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-18","volume":""},{"id":6167,"author":"贾燕子","title":"金文介词“于”用法补议","abstract":"郭锡良先生《介词“于”的起源和发展》是对古汉语虚词进行个案研究的一篇力作,但文中对甲骨文、金文中“于”字用法的归纳还有可补之处。喻遂生师据此做《甲骨文介词“于”用法补议》,对甲骨文“于”字的用法做了详细的补充。对西周金文“于”的用法尚可做以下补充:“于”带谓词宾语;“于”引进时间;“于”字结构的状语用法;“于”字结构的连用。另附“于”的动词用法。","categories":["02_字词句考释"],"year":2002,"publication":"南阳师范学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ41X8m9LqnSngvxNxUfDazcCdGewCcfxwIGAVGkDzTMRsvcYqimxf1_EFaeQAK17w0Jhrs_0Q65mK1E7jVj04yuqXLdqb2lhNX2oGqHb2_of8ay1kll_GzdD4pE1ReFn0X-yXaf4gV98T3xVDUnnMQ4bh_G_MAe6fkIzqVgRgXEw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-46, 80","volume":""},{"id":6168,"author":"张再兴","title":"西周金文构字元素的形体变化及其影响","abstract":"","categories":["02_字词句考释"],"year":2002,"publication":"琼州大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKLQmmLa40xOTwFKbSRRvAeCas3HTrmGm18Bn_Qi_E2E3HV97TruNTGRKGDWLA4UohOjJYLmniH_ELc_JecEgEXiTG2u3KJ5b_hDEeEEcTm1isaw4p-0WWbH2bnZchxVNInFgVRYoLLtkAFY_4QNpOrNxA9juke2WyvIf19eIm2Ug==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-46","volume":""},{"id":6170,"author":"张会","title":"“戹”本义考——辨“戹”和“厄”","abstract":"","categories":["02_字词句考释"],"year":2002,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKLQmmLa40xOTwFKbSRRvAeCas3HTrmGm2Xp4GOGb0UJHjrCKk_54F1478nM7hoTzd5mvCOPMuR_mLiast-jFHA6HEfPstRF_JmKA8DmDS5XtC8XvqMGwJeQMC5AITkf1v_ENukiBcPZRnc8Dg2i1cMJ1eeKb4Zf_B4QnYZiTpT9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-32","volume":""},{"id":6177,"author":"洪飏; 李薇薇","title":"金文中的“履”字及其演变发展","abstract":"本文就金文中所见到的“履”字 ,结合文献记载 ,说明履字的本来意义 ,并进一步指出许慎《说文解字》中关于“履”字说解的不妥。","categories":["02_字词句考释"],"year":2002,"publication":"锦州师范学院学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13831/j.cnki.issn.1672-8254.2002.01.009","pages":"37, 67","volume":""},{"id":6531,"author":"徐山; 王继如","title":"《潜夫论》词语考释","abstract":"本文以汪繼培箋、彭鐸校正的《潛夫論箋校正》作為研究对象,並充分利用諸版本中的異文材料,綜合運用文字學、詞義學、語法學、音韻學的語言學理論和訓詁學理論以及版本、校勘等古籍整理的研究手段,考釋了《潛夫論》一書中的130條詞語,對汪繼培箋和彭鐸校正中的疏誤之處提出自己的看法。考釋中涉及的問題和使用的方法有:梳理詞義系統中本義至引中義的演變脈胳來進行考釋;正確認識並列複词;利用對文、排比等修辭特徵進行考辨;指出汪箋、彭校中的非誤字問題:指出汪箋、彭校中誤用通假問題;指出汪箋、彭校中對異文取捨不當的問题;一些虛詞較為特殊的用法問题;徵引不確的問題;誤用句讀標點的問題;聲訓問題;《漢語大詞典》在處理《潛夫","categories":["02_字词句考释"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJPLs3h4g5yCp8rqfMq-JJPhfLqEmbs-G5JzuQQ92j7-lnC4dj4oJ1Tvl_JGcPlqxC38KaFwQft9GgdBmVtFRbSNXqu9YRU6vmyQkGizO0o1ihb35dLLaxpEhPOHGCDNgm1NLEbElL0C-FlTX4hzIdqNExNHNXXRKufs2CksY22p_fFR3VkqLwa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6938,"author":"黄锡全","title":"西周货币史料的重要发现——亢鼎铭文的再研究","abstract":"新发现的西周早期的亢鼎,明确记载用贝购买珠或玉,并另外付给有价值的物品,是研究西周货币的有关问题难得一见的重要材料。本文在报道者研究的基础之上,对难度较大的疑难文字重新进行深入研究,提出太保购买的这件珍品,很可能就是珍珠;另付的物品有调酒的郁(香料)一瓶,酒一坛,牛一头;卖者给予中间人红色铜二钧作为回报。推测这颗珍珠的总价值当在90朋贝左右。同时,对涉及的相关古文字及有关问题也作了深入的讨论。","categories":["02_字词句考释"],"year":2002,"publication":"中国钱币论文集第四辑","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKh0jwNWLxuOd9mX0379-I5ySPlhjPrBAHQnBdFlJsz5Kwj_4S60gcIPhdnAWvXQX5CMTdKZ8MwBFnjqOLxEzOFr6B3B-bPvp4NNzlR2YG9A-qFCMOInhSPuvtVDmyQ-zIG7iUmZpDBqmgQ2cmW4tbh6VEl5U8vlEVXixhJJyr-2sqBtk82y99B&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-76","volume":""},{"id":6942,"author":"谌于蓝; 张桂光","title":"金文同义词研究","abstract":"同义词，表达相同、相近的概念，是汉语词汇中一种特殊的聚合关系，广泛存在于典籍文献中。同义词的存在，是汉语词汇丰富的标志之一。金文中同义词的存在，是两周、春秋战国时期汉语词汇丰富的重要标志。考察铜器铭文中的同义词，参校传世文献典籍，既可看到汉语词汇自古及今一脉相承的继承性，亦能发现其具有时代的鲜明特性。对全文中的同义词现象进行探讨，上溯其源(甲骨文)，下推其流(文献典籍)，可以理清汉语词汇发展演变的线索，了解人们思维水平的进化，并为我们研究上古汉语的词汇面貌提供宝贵的资料。论文分为四部分：一、引言，简要介绍甲、金文同义词的研究概况，分析同义词的定义和判定标准。二、金文单音同义词考察。三、金文复音","categories":["02_字词句考释"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFWWczu8Ct8Qm4l7uKhqf2_O7_FRKXyEnpFNb6SuVeh51mee0icYPismMk8XUD3OW8LJJDwb0UENooi65YWX071JUjV4Ep1_b2-GtFAUZ1XjNxKlTyUrXD6gg6OGcjIXpapVPvnQpdhYGPyvolkhqxhz_gnrs_o8baE2IYvEKWXQ08sNJhj4Oc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6944,"author":"麻爱民; 张世超","title":"墙盘铭文集释与考证","abstract":"本文主体部分是对墙盘铭文的集释与考证。集释部分主要汇集了唐兰、裘锡圭等墙盘考释者的研究成果，对于诸家的文字考释和训解，比较简略的则直接称引，引证繁复的，则用简短的语言加以叙述，有些涉及孙诒让、徐同柏、郭沫若等前代学者之处，也作了简要的介绍。在集释的基础上，纠正文字的隶定、辨识及训解中的一些错误，并作了进一步的考证，提出了自己的拙见，对于有争议而又不能确定的地方或存疑或谈自己的思考，以便日后研究。本文第一部分介绍了墙盘的出土与形质，第二部分评述了有关墙盘的年代问题，支持墙盘为共王时器的观点，第三部分主要说明墙盘拓本问题，作了简单的校勘，并评定各本的优劣。本文的最后一部分是将墙盘铭文与传世文献互相","categories":["02_字词句考释"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK_fPZ0UQG-GCSpdiyAXOSSu-mDuMnkC30Y_yoFrxhyOBwIaYdADwlvfnHV5gIPfmV0lrQOUZP_CqKTzRtAg7uXiFNRCqub6WJ6LJPFdBFQssNBZiKJwYkSQEzl5wTVsl2oU8bPc4eDPvPYl09rs2aNWGgdIZhVXRJrsorC8iuHwmWE1AjoADFM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6945,"author":"杨慧真; 石定果","title":"《汗简》异部重文的再校订","abstract":"《汗简》是宋人郭忠恕根据传写的古文字资料辑成的一部字书。书中所辑古文字为战国时期的六国文字。《汗简》是仿照《说文》体例统系所收文字的，但与《说文》不同的是，《汗简》中存在著大量的异部重文。本文利用汉字形、音、义相结合的特点，对《汗简》异部重文进行了周遍性考察，基本廓清了《汗简》异部重文的真正面目。首先根据古文字形之间的对照，我们考察出一部分重出字；根据古文字形与楷体释文之间的关系，我们分别考察出了假借字、误释字、通用字；此外还分析出一些因编纂体例有误而导致的误归部字，由此得出了真正的异部重文。其次对析出的每类字，我们都列表进行了客观描写。最後通过上述考析，我们对比了《汗简》与《说文》体例的异同","categories":["02_字词句考释"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJOJfLSiO5ROH1ojU50d9IXAKNO-aZL0iXoOxmcd6oKXmZ8Ge_rv-ncqY4gy3SFAPRRH2Lue7Te5PYOEaVBeXznB5AXrgIU3QxMvGG-88fNEmow5psK6hRkvKmSuEaZc7Bq8jqezItPauN4lorh_vJmR1bfb-QwVdQRR1D_u_lSL8rGh06VCIIf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7150,"author":"裘锡圭","title":"释“衍”、“侃”","abstract":"在殷墟甲骨文中一般认为属于三、四期的无名组卜辞里,屡见&quot;■王&quot;之语,&quot;王&quot;上一字也可以写作■、■、■、■等形(参看《殷墟甲骨刻辞类纂》第872～873页,以下简称此书为《类纂》)。为了行文方便,下文以&quot;△&quot;作为它们共同的代表。此语在田猎卜辞中最为常见,下面举几条示例:","categories":["02_字词句考释"],"year":2002,"publication":"人文论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3O8z4P2FLfeAxbuLgb4pUkzPMPov-_kYynbxmWSF8jgWi6PSb66-2IFrm2Y3x4sDqF71kDO_UKpmABLJMBX_7_dGg3t0qRvluknVDVoghwMbMGLl2xgKOe22lCAsvnwlHc669N_6X1_M2OYbpvhnxtxvbS5vCMN3FiS2j8OQ4kg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"328-335","volume":""},{"id":7156,"author":"唐友波","title":"新见湏(月朱)鼎小识","abstract":"上海博物馆新进的一件战国铜鼎,盖上的铭文与陈介祺旧藏的&quot;眉(湏)(?)鼎&quot;铭文相同,在器口另有不同的容量铭刻。本文通过对其铭文、容量制度的分析,认为鼎盖与器口的铭文先后分别为韩国和魏国所计量和铭刻。","categories":["02_字词句考释"],"year":2002,"publication":"上海博物馆集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImA1IKlsKPoBvY6n17FlDXEeuUHWspRsiD9qeIvBKxvGvZSai2OL4qhJd7GvsHjUo_BH-dGANAz27P3EUW-FYD3GXeAn_Rw21libxiAZvo-aqZmt-k1dFFKkNlo63-Qozs28Bx0__KlIs-Rbak4rHYrzueSzqd6mAruEm2yHO17A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-60","volume":""},{"id":7157,"author":"饒宗頤","title":"由刑、德二柄谈“臸”字——经典异文探讨一例","abstract":"郭店楚简《缁衣》引《吕刑》作&quot;非甬臸制以刑&quot;,但此句在文献与出土资料中有五种不同写法,本文对五种异文进行了考证分析,得出四点结论:(1)上海博物馆本&quot;弗用霝&quot;,与今本《尚书》无异。(2)郭店本出於省略,删去了主词&quot;苗民&quot;二字。(3)臸字有多种异写,&quot;非甬臸&quot;就是&quot;不用晋&quot;,晋,进也,与齐通用,指齐礼、齐刑。(4)金文中还有以&quot;臸&quot;为声符的&quot;(?)&quot;字,读作&quot;箭&quot;;&quot;(?)&quot;字,读作&quot;煎&quot;。","categories":["02_字词句考释"],"year":2002,"publication":"上海博物馆集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzz5jIyCa8k_Q-Ihkc6H9nPRd7yMfHwBHgnoCRS59yhNKZlIX4Lp0hpjpEOfHmiOgyMZGogPX8E65ehZ-LlC4tHYgJBoh8xCky_axCb982waGqYkw_LOoe-3Jues7HuBEjvE5cw-7T1UdMniY-IitXeq11Vq1g8dQBcod49bVqJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"171-176","volume":""},{"id":7161,"author":"徐在國","title":"金文考释拾遗","abstract":" 一、释&quot;铸&quot;《殷周金文集成》(以下简称《集成》)4·2474铸司寇兽鼎铭文如下:■司寇兽肇乍(作)宝贞(鼎)其永宝用此鼎未见著录,拓片系商承祚先生藏。据张东寅先生《济南出土青铜器铭文研究》一文载,1978年","categories":["02_字词句考释"],"year":2002,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_qF82ps9XC12UBmd0Q9wWKeqY64pxB2tBQSxzImNdKff6L0ZRf1Dva0eOUyXOUCBwpsoSbDhZgxaB9-H4GRo5UaCx7gqZHA2_U_i403lofRsMsy1vZVbpF1sTBpeBN_Wptu2ssiZ1zM04p_ZyLZu2r2Q6YpuY36cXnN5T3S3yhQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"159-163","volume":""},{"id":7162,"author":"董珊; 陈剑","title":"郾王职壶铭文研究","abstract":"《上海博物馆集刊》第八期刊载周亚先生的文章《郾王职壶铭文初释》(以下简称“周文”),对上海博物馆新获郾王职壶及其铭文做了很好的介绍和考证,指出该器记载的乃是燕昭王伐齐这一战国史上的著名事件,创获颇多。我们学习了周先生的文章,有一些不成熟的想法,因此写成这篇小文,向周先生和学术界请教。","categories":["02_字词句考释"],"year":2002,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIz5fSQlec8dpWa5sfEuM6qQEcRsqtCj0EsHstLQncEAU8LZBspGyGxWMi8uQjDHxmdYmJ0s3ChSFef1qDmJOAZRAh5JpJqwHInz74EOoRa4mWe_G8nuJt05DUMIQHB_xH3h6FjBlfvedoFxmfyRsGabb4H7MBFIdm8NjuEphSzaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-54","volume":""},{"id":7167,"author":"王长丰","title":"《保卣》铭文再考与《召诰》、“改法度,制正朔”及召公世系等相关问题新证","abstract":"保卣盖器同铭《录遗》二百七十六。《商西周》一百三十三。释文乙卯,王令保及殷东或(国)五侯,版(延)兄(贶)六品,蔑历于保,易(赐)宾,用乍(作)文父癸宗宝尊彝。■(遘)于四方,■(合)王大祀,■(祐)于周,才(在)二月既■(望)。此器铭文传1948年河南洛阳出土,现藏上海博物馆。王令保及殷东或(国)五侯:此王实为周公,而托成王,详见下文。保即大保,召公奭的官名.《书序》:&quot;召公为保&quot;。及,《说文·又部》:&quot;及,逮也,从又从人&quot;,即逮捕也。殷东或(国)五侯即原殷东部","categories":["02_字词句考释"],"year":2002,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKO6MDS64Cw4lsoMJmbAGzqguNsMerflW-EKanHnYCfFx8htktbqpmAbeEdg8xifib603En4VMi3NpWI2wUHZCHHwuw6zT_tgRCwy9zsSwkV02avMflNp5s4SytsQb5D_17SchwHK-aUIVKZBn3_TAbkMSevvXyGQV2e2Sbcm7yWA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"45-48","volume":""},{"id":4893,"author":"孫斌來","title":"“中”組銅器銘文及年代攷——附論睘卣的年代及周武王在位年數","abstract":"北宋末重和戊戌歲,在湖北安陸孝感縣出土了六件器主爲“中”的銅器——安陸六器,我們稱之爲“中”組銅器。其中,圓鼎銘文僅有“中作寶鼎”四字,二、三號方鼎同銘,所以較長的銘文實際祇有四篇。郭沫若《兩周金文辭大係圖錄攷釋》、唐蘭《論周昭王時代的青銅器銘刻》和馬承源等《商周青銅器銘文選》都著錄了“中”組銅器這四篇較長的文。自宋代薛尚功著《歷代鍾鼎彝器款識法帖》以來,學者對“中”組銅器銘文多有考釋,但意見頗有分歧。僅就製作年代而言,郭沫若定“中”組銅器爲成時器[1],唐蘭定爲昭王時器[2],楊樹達在《積微居金文說》中定一號“中”方鼎爲武王時器[3]。馬承源等在《商周青銅器銘文選》中定爲昭王時器[4]。","categories":["02_字词句考释"],"year":2001,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIARfhsqOYlnj_bnUhndtatZcBMbpCImCHWZjeFMjjsSnOryseydc32CVy8Qymg07D4G693aN9qXN41kwEbWJFJSKorBX8isJAtVuJ0VP8TqB9DUJRL_nrNNy2UfAG1e-w3Hj8pLEgR6zH7fikvzOcFAzaYy7iI6TWavAgED-VtG6MWdeIwTV9P&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-52","volume":""},{"id":4899,"author":"金洋东; 叶欣; 罗静","title":"金文“唯”字考","abstract":"一论文提要殷商时代的青铜器是中国古代工艺艺术的顶峰,它上面所绘制的器形、纹饰及铭文反映了当时的历史、政治、经济、文化、宗教、军事、丧礼礼仪及科学技术等等,因此,可以说它是极具史料价值的。众所周知,这些青铜器主要是在祭祀时用的一种礼器,其纹饰所具有的艺术装饰性及造型美是现代技术也无法达到的。特别是铭文,作为当时的语言记录,是文字学、音韵学及训诂学方面的宝贵资料。也因此,在对青铜器的研究中,对铭文进行研究的人和所花费的时间是最多的,这方面的成果也较其他方面多一些。","categories":["02_字词句考释"],"year":2001,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJtTtWLbtGuDdVjhejxvaxrUSBBEgsD4_bcXlHoC2OK8C-s2w9PyTgCFyMfgsBSnV7TPZJJK3qcHHh2B_jzVTvyBxR2RNVP41e3vtjs242WmjDirSip9jp_suP187lT4WtuKV2fvKjEbPdYtaNlHMlbT2F06gonVOBJaAJFEeM1p_e8eN7b88Z&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-70","volume":""},{"id":6184,"author":"刘桓","title":"关于■敖簋铭文中“戎”的问题","abstract":"关于 敖簋铭文的释读，郭沫若先生认为“子牙父”即齐鲍叔牙，并根据该器器形、铭文字体等判定其制作年代应在春秋齐桓公时期，此说可从。刘丕烈先生认为“子牙父”为鲁叔牙，“ 敖”为鲁庆父之子公孙敖。其断代与郭说基本一致。本文以为“子牙父”应是齐鲍叔牙而非鲁叔牙，仍以郭说为是。但郭说以为铭文“戎献金（铜）百车”的“戎”指匈奴，则不可信。笔者根据铭文透露的齐、鲁关系，判定此“戎”应指山戎。齐桓公北伐山戎，曾谋之于鲁。“戎献金”作为贡纳，当是齐出兵征伐的结果。文中对前两说之误，有所考辨。","categories":["02_字词句考释"],"year":2001,"publication":"北方文物","link":"https://link.cnki.net/doi/10.16422/j.cnki.1001-0483.2001.04.011","pages":"81-83, 90","volume":""},{"id":6186,"author":"罗振跃","title":"“蔑历”一词在金文中的含义即赐食","abstract":"“蔑历”一词在西周金文中习见 ,关于此词的解释 ,众说纷纭 ,莫衷一是 ① 。西周有蔑历礼 ,从文献记载、出土材料、西周金文等方面综合考察 ,“蔑历”在铭文中的意义应即“赐食”。","categories":["02_字词句考释"],"year":2001,"publication":"贵州大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15958/j.cnki.gdxbshb.2001.05.012","pages":"69-72","volume":""},{"id":6188,"author":"王平","title":"《说支解字》训“词”例研究","abstract":" 一&quot;词&quot;字未见于出土的先秦古文字材料,西汉时期的《苍颉篇》19中始有&quot;词&quot;字。字形结构及构件与今之楷书繁体&quot;詞&quot;字相同。《说文·司部》:&quot;词,意内而言外也。从司,从言。似兹切。&quot;段玉裁《说文解字注》:&quot;词者,义内而言外。从司言,此为摹绘物状及发声助语之文字也。……司者,主也。意主于内而言发于外,故从司、言。……意即意内,词即言外。言意而词见,言词而意见。意者文字之义也,言者文字之声也,词者文字形声之合","categories":["02_字词句考释"],"year":2001,"publication":"中文自学指导","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxrFI3zG-KfiRvr7295IB77D_aRBnMDlO_pj4NXi65BbFBk5rzRLBzdkTCFUhY1QqjNiswEYbKwn6S0wDvNtvtJ-QkArheYf2yzjNJwOvxuglQ_xvrD-f4fjukUZqjTa4jfqqPelMSJRJ7z-Ws4Bcr0a9fo7xht0uK-KnIn-jbnQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-21, 16","volume":""},{"id":6190,"author":"朱方棡","title":"《易·师》考释及其他","abstract":"师 ,甲文取其半 ,象形字 ;金文合成今师字的字形 ,会意字。师字在甲文、金文时代都作军队、战争讲 ,也是军官、职官名并延及师长等义。《易·师》卦讲战争事 ,《周易》另外还有《同人》、《离》、《晋》、《革》四卦等讲军事。它们反映了商、周时期部族、方国之间的斗争 ,折射出那一历史时代人们对于战争这种社会现象的认识 ,理解和把握。","categories":["02_字词句考释"],"year":2001,"publication":"桂林师范高等专科学校学报（综合版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxrFI3zG-KfiRvr7295IB77D_aRBnMDlMJ0ULznYkGnEQBGBEtlO2B7h3NEcuF8N8eNjnkHuc2yv6pQbjYVT1DWdABPnu3VcuAukoY_x8iicOGibxtNJkGnjdulSo6oahr0fzHVuPuzkIQDEnxIW68kqhLA1H70TfnOLd6EfgkYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"53-59","volume":""},{"id":6191,"author":"朱方棡","title":"《易经》卦名等用字考","abstract":"《周易》经文的主要用字 ,是指卦名用字和主要术语用字 ,共 88个。用于通行本《周易》的这些字 ,考其本源 ,其中有一部分是见于甲文、金文 ,或甲文 ,或金文的 ;但亦有相当一部分不见于甲文、金文 ,尤其是形声字 ,明显后出。又与马王堆汉墓出土之帛书《易》相比较 ,由此确认通行本写定的年代是较晚的","categories":["02_字词句考释"],"year":2001,"publication":"广西师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16088/j.issn.1001-6597.2001.03.011","pages":"46-48","volume":""},{"id":6192,"author":"陈双新","title":"青铜乐器自名研究","abstract":"Based on his studies of the bronze musical instruments, the author analyses the inscriptions referring the self - named modifiers and tries to give them new explana- tions. The study is important to understand the function and values of the bronze musical instruments.","categories":["02_字词句考释"],"year":2001,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2001.03.014","pages":"96-104","volume":""},{"id":6194,"author":"游顺钊","title":"甲金文“朕”字构形的历史取象","abstract":"本文探讨甲金文朕字构形的历史取象，揭示它的象征意义。笔者于９０年代曾两度论述此字形的参照物，惜未能就其偏旁构件（舟）提出解说，逼得一再存疑。十年来此悬案一直耿耿于怀。现在借助古文献史籍与地下文字史料的深层信息，旧题新释，以就正于各方家。","categories":["02_字词句考释"],"year":2001,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKSWKwt-vNBJiCmWVlNNfCN6rU97QoHX6O-z_xc6H0LxnS5lU5L_zPT4bxbQGUeUTXmfXRXLNwovnyfYVEntzRabteYw-HUWRW-0GaG9PnCxAdq4rrF2otazSbrSGB1vG3XxH3vHXN-FumPI5Bhzc-VvXXJ00hkdEem5EfluVjsBw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-25","volume":""},{"id":6195,"author":"赵学清","title":"战国东方五国文字的构形系统","abstract":"战国东方五国文字是汉字发展史上的一个重要组成部分。通过对这些文字资料的研究 ,我们发现它们在构形上是成系统的。这种系统与汉字发展其他阶段上的系统有着密切的关系。战国东方五国文字的构形系统可以从三方面来看 ,第一 ,它们的基础构件及其构字比例和甲骨文、金文比较起来已经相当完善 ;第二 ,从构字模式上看 ,形声字的比例大幅度上升 ;第三 ,从汉字结构层次上看 ,层次结构占据绝大多数 ,平面结构很少。这些表明 ,战国东方五国文字的构形系统已经成熟","categories":["02_字词句考释"],"year":2001,"publication":"聊城师范学院学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16284/j.cnki.cn37-1401/c.2001.05.015","pages":"57-58, 66","volume":""},{"id":6196,"author":"周宝宏","title":"上古汉语词义是上古文献写成时代的重要依据──以产生时代分歧最多的《尧典》为例","abstract":"从上古汉语词义学角度研究上古文献的写成时代 ,同时用出土文献和传世文献的词语、词义作综合比较 ,会得出比较科学的结论。据此研究《尚书》中的《尧典》,其大部分词语和词义是春秋战国时期的 ,那么《尧典》也应该写成于春秋战国时期。","categories":["02_字词句考释"],"year":2001,"publication":"沈阳师范学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.19496/j.cnki.ssxb.2001.05.008","pages":"32-36","volume":""},{"id":6197,"author":"张永山","title":"利簋“岁鼎克闻”补证","abstract":"商周时将“岁星”称为“岁”,在卜辞和文献中都有明确记载。“鼎”为古“贞”字 ,同样能在卜辞和文献中找到对应的例证。先秦两汉文献中 ,“鼎”训为“当”,“贞”亦可训为“当”或“正”,故“岁鼎 (贞 )”就是“岁星正当其位”,“岁鼎 (贞 )克昏 (闻 )夙又 (有 )商”,是讲正当岁星悬在东北方时 ,武王得到了击败纣王伐灭商国的捷报。","categories":["02_字词句考释"],"year":2001,"publication":"清华大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13613/j.cnki.qhdz.000873","pages":"42-44","volume":""},{"id":6198,"author":"沙宗元","title":"杕氏壶铭文补释","abstract":"氏壶是春秋晚期燕国的著名铜器 ,现藏德国柏林博物馆。罗振玉《贞松堂集古遗文》最早著录了铭文摹本 ,后来的研究者对铭文多有考释 ,诸家之说 ,得失互见。本文对其中有代表性的几家略作评述 ,并对壶的年代与国别、壶铭的释读作一点补充论证。","categories":["02_字词句考释"],"year":2001,"publication":"安徽大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYsApqH-LI7TS9beo19eHc5qTYESGntYpN6MXl60il1HpavtYxPaUZI4FkeIN8BOFONf7xpvV4jZnxCJ3vwwaz5pvM2koRbddS4FMi8QZRq66P_lcD94QJ9UBXeEZW0__1072DVfO7xOKA43X7pf4OQ9tbfS-HCkyHg5EsdRctzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-54","volume":""},{"id":6199,"author":"张闻玉","title":"再谈金文之“初吉”","abstract":"","categories":["02_字词句考释"],"year":2001,"publication":"史学月刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYsApqH-LI7TS9beo19eHc5qTYESGntYqfDgqlo3t72y2bTS2vuljpcs-7ISVXf3vp02Fpel6dqygfhsiEbY2lVjVSOQtjCDbRLbYh_oy0hYQ60_88le50NF-Vm5RiuEd4p-maB_uK-cU6TS9AbEB636nKC5loD6T1CoK1bl7UXg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"147-149","volume":""},{"id":6200,"author":"曹林娣; 郭明友","title":"“文” 义辨证","abstract":"“初造书契”中其实有两个“文”,并且有各自独立的两组引申义项,但是,这没有被后人充分重视,古今学者,常常因为不明此中差别而误训其义,本文旨在辨明“文”之本义,并纠正几条经典中的误训。","categories":["02_字词句考释"],"year":2001,"publication":"苏州教育学院学报","link":"https://link.cnki.net/doi/10.16217/j.cnki.szxbsk.2001.03.001","pages":"1-4, 14","volume":""},{"id":6203,"author":"蔡升奕","title":"“商馈始于王”的“商”字作何解──兼论《逸周书·丰保》的成篇年代","abstract":"文章从甲、金文中“商”字多假借为“赏”（意为“赏赐”）的情况，悟出《逸周书·丰保》中“商馈始于王”的“商”也是通“赏”，全句的意思是赏赐从王开始。这样解释与上下文十分贴切。《丰保》与甲骨文、金文相同的用字现象，说明了《丰保》成篇的年代至少是在春秋中期或者远至西周的金文时期。","categories":["02_字词句考释"],"year":2001,"publication":"语文研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHlxa3c5uYWbEcsoISkqNscOiw_RINmmAmcmofscNE9hB5uzL4kHwXKn4vWpbTx0zkr-MkIlyKm8Y7tfXfDt8F_xhqqwpbXQdgttfvxpCf9l-0rPn7iqigFAPcn3Jt1eJX_nu9E0lviynROPspzg74LYKL9h0_YQ4wtMKmVoFbqg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-23","volume":""},{"id":6204,"author":"叶正渤","title":"略析金文中的“月”","abstract":"在金文中，月是一个具有多种意义的同形字，后来都写作月。作为合体字的部件，它所表示的意义有：（１）月或夕，（２）肉，（３）动物的嘴，（４）人的嘴。因此，在分析有月形的金文合体字时，应区别对待。","categories":["02_字词句考释"],"year":2001,"publication":"徐州师范大学学报","link":"https://link.cnki.net/doi/10.16095/j.cnki.cn32-1833/c.2001.02.007","pages":"49-51","volume":""},{"id":6207,"author":"潘玉坤","title":"铭文语言艺术管窥","abstract":" 典雅与风格殷周青铜器上的金文向以浑厚凝重、古雅端丽著称,其文辞——铭文的历史和考古价值,也恒为人所称道。铭文的语言风格如何呢?陆机说过&quot;铭博约而温润&quot;,(《文赋》)刘勰说过&quot;铭兼褒赞,故体贵弘润&quot;。(《文心雕龙·铭箴》)验之殷周青铜器铭文,不难得","categories":["02_字词句考释"],"year":2001,"publication":"中文自学指导","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIoChc5B3sYRyA79ZdTa2QPQC-efWNDPbX8itGCdk2IRRywpRPxrlEGoTi4-O9-ApMW000Sl9BJ6aNlVc2FcVWBcbl0ieuLt0iLzkgGXdBo_XZr6Zg7GMBXk54flsFk5oZTI8dHUPh66G7_ELn4T1jzsNsCNPX3O8Ra8HW1x49EcQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-40","volume":""},{"id":6208,"author":"姚垚","title":"民字本义试探","abstract":"“民”字的金文字形 ,或释为“以锥刺眼”,于是将民字的本义解释成“奴隶”。本文试图用金文字形 ,参证以周代的经传文献 ,来说明“民”的本义并非奴隶。从文字通假的关系来看 ,民应是萌的本字 ,后来假借为人民之民","categories":["02_字词句考释"],"year":2001,"publication":"学术论坛","link":"https://link.cnki.net/doi/10.16524/j.45-1002.2001.03.026","pages":"98-99","volume":""},{"id":6210,"author":"张涅","title":"“道”的原始义考释","abstract":"","categories":["02_字词句考释"],"year":2001,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwwnvYoBdhCPWz3e3WckrCa-PA-6RlLEsXTalSbloRmpIRZJ3-GXvtWwGDzXAPaI_iaItK3g-eJa_CDqBU1Qqu7IrblhJMU2tQkOXWk8Alg9YErirJiUR1CiKh3r2IxfcrOW7M_1ym4noFvmA54MJY853nnJ7spn2rnwgLzgRuRg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65","volume":""},{"id":6214,"author":"朱方棡","title":"《易·旅》考释及其他","abstract":"旅 ,甲、金文均用作军旅义 ,每旅五百人 ,形制旗下两人 (众、从 ) ,从“方人”,与旗帜有关。旅卦 ,主要是商旅卦 ,与军旅义无涉 ,是西周初人的一种观念反映 ,尤其重要的是旅行方位。《周·易》经文中多见“攸往”、“所往”的卦、爻辞 ,显示了西周初年人们活动的特点。“利西南得朋”、“东北凶”反映了周部族生存的地理环境以及周边民族态势 ,说明在周部族起始相当长的一段历史时期内其活动范围还是相当有限的。","categories":["02_字词句考释"],"year":2001,"publication":"桂林市教育学院学报（综合版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK99OwKTuYztQBb2aGKIscarjEItdVYjJtnEC_jYBrY-FnBN8oxrUm59skKG3SjbMUXoazWH2GfLOlfs_KCUNSU2wXd4r1-3lHRdjJPIKIoIj4pMp2msztGgbyDnN-qaA-nOJocwaefTV_50nORod_cuBlWuyHzF-jyWef9ppVsLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-67","volume":""},{"id":6215,"author":"张玉金","title":"甲骨金文中“其”字意义的研究","abstract":"关于甲骨文中“其”的意义，到目前为止主要有两种说法。第一种说法是，“其”的意义对占卜者这方面来说是不希望的；第二种说法是，“其”的主要语气是疑问、测度，还可以表示命令的语气和将要的意思。文章把甲骨文中的“其”字句进行了新的分类，并用现代语法学和训诂学的理论方法重新进行探究，得出的结论是，甲骨文中“其”的义项有两个，一是表示将要的意思，二是表示命令的语气；并无其他义项。文章还把甲骨文中的“其”和金文中的“其”进行了对比，认为两者的义项是相同的。","categories":["02_字词句考释"],"year":2001,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2001.01.004","pages":"46376","volume":""},{"id":6216,"author":"陈絜","title":"从商金文的“寝某”称名形式看殷人的称名习俗","abstract":"Based on the studies of qinmou in bronzeinscriptions of the Shang Dynasty, this paper discusses the appellative customs of the Shang people. Qinmouis composed of the official name and the family name, this kind of appellative customs was popular in the Sahang Dynasty and reflected the hereditary sys","categories":["02_字词句考释"],"year":2001,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2001.01.011","pages":"87-93, 109","volume":""},{"id":6218,"author":"唐生周; 杨庭硕","title":"利用共时性造字符码破译古文字","abstract":"《说文》释“单”字形义音皆误。依据共时性造字符码破译“单”字甲骨文形体，认伪“单”即捕兽索具。以此出发，甲骨文金文中一系列从单之字都可以得到解释。","categories":["02_字词句考释"],"year":2001,"publication":"吉首大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13438/j.cnki.jdxb.2001.01.019","pages":"94-99, 109","volume":""},{"id":6220,"author":"徐宝贵; 孙臣","title":"古文字考释四则","abstract":"","categories":["02_字词句考释"],"year":2001,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqYjw74jYSFpyGR5CjYTuuaS6KDe4iTwfneavYr_djWcvY3zHvzFjRMh2YLN0ynCjANd2FsRxv1WIJV1ENA9JfTILbaXe9q7ZE5xD3SbtnFmmgcdq2EbiPlQuQ2xqLYAIaHEKNAoH-I5VPGnGjWM7PLI0ph3dVDOVflpnxiVatGA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-82, 95","volume":""},{"id":6222,"author":"黄光武","title":"释“穆”──兼谈昭穆的礼乐涵义","abstract":"《说文》释“穆”为“禾”，义甚笼统；训“■”为声，又与《说文》训“■”从■得声不协。文章从钟鼎文中找出结构与“穆”相同的縣（懸）字为例，证明穆字义非禾属。穆为合体字，会悬钟和鸣之义，所从“禾”乃“木”之形讹。为何中国古代要用昭穆来命名祭祀秩序？文章指出：“穆”源于音乐的和美，而和美的乐声应该遵从音律的规则，故昭穆寓意古人效法有序的音律以规范人群的和睦。","categories":["02_字词句考释"],"year":2001,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbCq2EbXg1JdtQNL8xXDUhG_RnarhF1CJEuUKTr90EGV3y7A7LUcT-Rm24sJ84NL7cvb2R5PFhYi9A6sR0vSgM9gaDrfrcMxki8in2Tqd5PLmM3SHz5CUN9qM529bfmjP1ewhVI1cIc5Gq2DLyfvDD818OnBlKMes6GQq_vau4Nw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-46","volume":""},{"id":6535,"author":"尚秀妍","title":"兮甲盘铭汇释","abstract":"宋代出土的兮甲盘，是周宣王时器，铭文中涉及到周朝与北方 少数民族狁的战争，与南方淮夷的经济关系，以及周朝对周族人和淮夷人程度不同的贸易控制和管理。王国维说：“此种重器，其足羽翼经史，更在毛公鼎之上。”对此器许多文字学家都有过考释文字，本文参考各家说法加以汇释，又将铭文涉及的史实与古书对照，讨论一下盘铭所反映的当时的政治、军事、经济关系及兮甲盘的历史价值。","categories":["02_字词句考释"],"year":2001,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2001.04.020","pages":"89-94","volume":""},{"id":6536,"author":"杜廼松","title":"全国铜器鉴定所见金文考察","abstract":"本文作者结合历史文献和相关资料，对近几十年出土的青铜器铭文进行综合研究，论述了重要铭文的历史价值与意义。","categories":["02_字词句考释"],"year":2001,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPqFxgYHRjDupaZtp-LTPAX1aPl-FKzwGeX2U2a5RIHOLGLiAuJ_mn1a9yn1auJ7IXn1J3oIn0YVGaz713s1tePLar5O-jXzpeCr6-_HfkfmUmOALb_K2gVyDQkcjyp7JsKl3UxkR58SAhmErPJdEwg3FofnbyPPXCgMIh0CNISw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-69","volume":""},{"id":6538,"author":"李学勤","title":"长子、中子和别子","abstract":"河南鹿邑太清宫墓葬中,青铜器铭文显示,墓主自称“长子口”。作者由此次发掘的铜器铭文入手,结合历史文献,认为商末周初铭文中的“长子”为首子或元子,“中子”为支子,“北子”即“别子”,也指支子。","categories":["02_字词句考释"],"year":2001,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2001.06.001","pages":"46025","volume":""},{"id":6542,"author":"王兴才","title":"“者”字形义探微","abstract":"“者”的本义历来众说纷纭,本文认为“者”当表“附著”义,并对“者”的演嬗和用法进行了探讨。","categories":["02_字词句考释"],"year":2001,"publication":"牡丹江师范学院学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13815/j.cnki.jmtc(pss).2001.06.015","pages":"53-55","volume":""},{"id":6543,"author":"李杰群","title":"连词“则”的起源和发展","abstract":"本文考证了西周金文中&quot;则&quot;的本义应该是&quot;划分&quot;,而不是&quot;刻画&quot;。论述了&quot;则&quot;从&quot;按照等级划分&quot;引申为&quot;法则&quot;、&quot;效法&quot;,再虚化为承接连词的演变过程。","categories":["02_字词句考释"],"year":2001,"publication":"中国语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIE1JJv2_D1Fw_UlYsuO_ojklqctPj1csR_-mdpAEFOAQ9uz5xaYVIFTlpFPOJl1txakmx46NVUn1VONDtfDAQZzYrFMdoTNHM6-LMbWAdxLinYIwDMOCcwUwX9rIy8bokG7wTnin8_qfaSfLsSCTYa8Cr249h1xzXEgVGKZ2ceEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"525-530, 576","volume":""},{"id":6544,"author":"王建军","title":"殷周古文中所见的“省化”现象","abstract":"殷周古文中有一些字 ,实际上是截取“母字”的部分形体来充当“新字”或“新字”的部分形体 ,这种造字方法就是“省化”。被“省化”出能独立记录语言的“新字”不仅有利于汉语表达 ,而且还可以克服由宽泛的假借而引起的字义模糊现象 ,其功能完全有别于“六书”","categories":["02_字词句考释"],"year":2001,"publication":"株洲师范高等专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLnTxmdFiCSvncKIaLYa8s3e9uaR6h0OW-Inr0itwCB0BwR2pqZxVG-NZQ-4PdM_pLPEkugYbsFpIGxRQkovFQdEztsImYrRINK8KPzhLN7pnUE9Re2Eik2cl4lmyy4K9_DtC7h1byjY_6ftPEY4nXPv7Z-qx48kzFW73fkEdXyvw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-67","volume":""},{"id":6546,"author":"郭小武","title":"古文字考释五题","abstract":"本文以考证和诠释汉语古文字为主要目标。本文由以下五个分题组成：一、“临”“监”索解——兼示汉字的层级与网络；二、“鼓”“桴”索解——兼示汉字的形变与音变；三、“蝤”“秋”索解——兼示古代农俗；四、“公”“私”索解—──兼示古代哲理；五、“廪”字索解——兼示古代建筑。","categories":["02_字词句考释"],"year":2001,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2001.03.022","pages":"89-94","volume":""},{"id":6548,"author":"刘桓","title":"■攸比鼎铭新释","abstract":"西周(?)比鼎铭文反映了周代两个诸侯贵族之间关于田邑问题的讼诉。本文指出,史南、虢旅应分别为太史、大司寇之官;且应即助,亦读藉,乃指田税而言。攸卫牧的誓词应与当时的法典内容有关。从而对全铭作出了新的解释。","categories":["02_字词句考释"],"year":2001,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2001.04.004","pages":"14-16","volume":""},{"id":6549,"author":"李伯谦","title":"叔矢方鼎铭文考释","abstract":"晋侯墓地发掘清理的西周早期114号晋侯墓中出土了一件方鼎(M114∶217),上面有铭文8行48字。铭文讲述的是某年十四月,王在成周举行盛大祭典,礼毕,王会见与会臣下贵族,王对叔矢进行赏赐,叔矢为纪念铸造了这件铜鼎。铜鼎铭文中的王应是成王,叔矢则可能是晋国的始封君唐叔虞。这件方鼎是迄今所知惟一一件晋国第一代封君自作的铜器,具有重要的研究价值。","categories":["02_字词句考释"],"year":2001,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2001.08.004","pages":"39-42, 1","volume":""},{"id":6551,"author":"刘桓","title":"关于匍盉“柬”字考释","abstract":" 近时读了王龙正、姜涛、娄金山《匍鸭铜盉与(兆页)聘礼》一文,对读匍盉(即匍鸭铜盉)铭文,知该文考释解决了铭文中&quot;氐&quot;、&quot;青&quot;等不少问题,从中受到许多启发。反复研读铭文,感到该文似于&quot;柬&quot;字释读未获确诂,因而在该铭中间文字的贯串解释上不无窒碍之处。爱撰此文,聊抒浅见,不当之处,","categories":["02_字词句考释"],"year":2001,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2GUzfny703yGS9NyUgYcVIMSlEKhba_pxAv6DPTKBvpH2Rpp49PJty9-Qq0vN7g0obDnK-M_i7D7dSBJZKeCTY6W2t6YZYhm8VT8R5Sw4mRHOhW5kLL3JFi6gA90I8l2FGOgEVVx6cDYuxaowlon1aemW7zIOIRU9RYSMSVM--Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-62","volume":""},{"id":6552,"author":"陈双新","title":"“乐”义新探","abstract":"“乐”字的本义自东汉许慎至今已有很多人作过探讨,结论多样,但多不可取。本文结合甲骨文、金文及文献材料认为“乐”之本义当为“栎”。","categories":["02_字词句考释"],"year":2001,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2001.03.009","pages":"57-60","volume":""},{"id":6553,"author":"叶正渤","title":"我方鼎铭文今释","abstract":"我方鼎,旧名多异称,笔者据图始认为原器有二:一为方鼎,一为方盘。铭文字多未识,现重新考释,文义始通。器之时代;旧说为商代,日人林巳奈夫定为西周初,经考证,当以商末为是。","categories":["02_字词句考释"],"year":2001,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2001.03.010","pages":"61-64","volume":""},{"id":6555,"author":"蔡运章","title":"太子鼎铭考略","abstract":" 1998年10月,洛阳火车站西南金谷园村发现战国有铭铜鼎一件。本文谨就这件铜鼎铭文的释读及其相关问题,略作考述。这件铜鼎是金谷园村居民在村西南挖排水沟时,距地表约4.5米处发现的。同时出土","categories":["02_字词句考释"],"year":2001,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2001.06.007","pages":"69-71","volume":""},{"id":6556,"author":"赵诚","title":"金文的“者”","abstract":" &quot;者&quot;在金文中的用义比较丰富,有些用法表现了一些特殊性,对于上古汉语的研究相当有参考价值。陈初生编纂的《金文常用字典》(陕西人民出版社1987年),由于编写时间仓促,只收了5个义项,显然简略了一些;而某些特殊用法又未提及,也是一种不足。该字典出版于1987年,在当时的情况下,有这样一部工具书,可以说是相当不错的了。1998年,上海辞书出版社出版了一部《简明金文词典》,仅收了&quot;者(戈丮)臣&quot;一语(182页),相比之下就显得更简略。为","categories":["02_字词句考释"],"year":2001,"publication":"中国语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL5ignm3C0UXmoDB_84DshBSmTea8Zo0mcOf_SIn_0le1OLkOFFxAGjBAm_LDyLi7Rwfwv1CarC9McIkRnxm4IAM_KJPYbSATzY0T1xnMByuJuVBeLaAj5zQVOAA4g5BWVTd2Fbp5UsCEHkZWsWJA0xXqux5XU2s2dy2I9GamWNzQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"267-268","volume":""},{"id":6560,"author":"王国珍","title":"“形借”说辨","abstract":"段玉裁在《说文解字注》中提出了形借理论，并列举出五组例字，这五组字或本为一个字，或本为依声托事，或一字为另一字之义项，皆非因形近而相借。","categories":["02_字词句考释"],"year":2001,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2001.01.025","pages":"97-99","volume":""},{"id":6562,"author":"李学勤","title":"■簋铭文考释","abstract":"最近在新加坡东亚文明博物馆展出的(艹害)簋是西周穆王时器,有铭43字,记载戎人侵犯楷国,楷臣(艹害)抗敌获胜的事迹。楷国可能为毕公子所封,地在陕北志丹一带,其建立与抵御北方戎人有关,至西周中期仍存。西周晚期,王朝势衰,楷国也归于灭亡,以致在载籍中无其踪迹。","categories":["02_字词句考释"],"year":2001,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2001.01.001","pages":"1-3, 93","volume":""},{"id":6564,"author":"李学勤","title":"秦怀后磬研究","abstract":"怀后磬是春秋时秦国的一件石磬,刻有很长的铭文,在宋代发现,先后著录于吕大临《考古图》、薛尚功《历代钟鼎彝器款识法帖》,原器早已佚失。近年这件石磬受到学术界的重视,但磬的铭文一直存在未能通解之处。通过对石磬的进一步研究,作者认为石磬的器主应是春秋时期一代秦公的夫人,这件石磬有可能出自这位夫人的墓中。","categories":["02_字词句考释"],"year":2001,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2001.01.003","pages":"53-55, 101, 1","volume":""},{"id":6950,"author":"沙宗元; 黄德宽","title":"古汉字字形讹变现象初探","abstract":"本文以古汉字字形讹变现象为研究对象。在对古汉字各历史阶段讹变现象全面考察的基础上，划分讹变的基本类型，分析造成讹变的原因，阐明讹变与汉字发展演变一般规律间的关系，探讨研究讹变现象的实践意义，以获得对讹变现象较为全面深入的认识。全文共分六章。第一章，介绍讹变的概念和前人研究讹变现象的情况，说明研究讹变的原则、范围和目的。第二章，介绍讹变现象的主要类型。本章将讹变现象划分为有意讹变和无意讹变两大类，有意讹变包括变形声化和变形就义；无意讹变包括添加饰笔、笔划苟简、解散形体、合并形体和形近而讹五种类别。第三章，分别介绍了殷商、西周春秋、战国时期、秦汉之际字形讹变的主要类型和特点。第四章着重分析了造成字","categories":["02_字词句考释"],"year":2001,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIOOl8NBFiFVVXRteNNvrg8mUlhrBTmCBDb7fsOfuhkvixC42n_qvIZWcSYnrOrbgM6K5vZQFWoPQc_CEu0liFgUsShZsTSltOqCXqk5PqbTimgM2iIyoqKbZbaw73uX752D8q6SZ78-YheP1g6E2anfCXIuZetpIrXgi21MrCgkGcaVyFnmjOz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7169,"author":"羅衛東","title":"春秋金文中由“金”构成之字探析","abstract":" 研究汉字发展历史,必须通过断代的汉字测查,获得相关数据,然后进行历时比较,确立历代汉字在汉字发展史上地位,从而逐步了解汉字发展历史脉络。当然文字发展史的断代并不等同于历史的分期,文字变化是一个渐变的过程,但文字在一","categories":["02_字词句考释"],"year":2001,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXB5hdoNLxzWpqElIXLw_PEF1yuhif84jhphHiQT4wjU3sCYJ_afH1fO-_ynLKluelJlQiHKzx5AeU9JuH9cgd1V48XZSAA2KBGvV0SCIuJQYfFT109mWpkg7xvTW51Ujy74pxv15_mYd5QbLRnDo7qo7IcnGbhpAIq9aQQ1WsoQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"161-166","volume":""},{"id":7170,"author":"陳五雲","title":"古文字学雜志两篇","abstract":" 释义《说文》:&quot;义己之威仪也。从我从羊。&quot;段氏注:&quot;言己者,以字之从我也。……古者威仪字作义,今仁义字用之。仪者,度也。今威仪字用之。谊者,入所宜也,今情谊字用之。……义之本","categories":["02_字词句考释"],"year":2001,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXB5hdoNLxzWpqElIXLw_PEF1yuhif84jhphHiQT4wjU3sCYJ_afH1GRdzGQAC1r4hTAGbBtnXOelYLyitRc8Gi4GCelXkz_PFYGmnQ5IyMM2beGTpmo658VcfLnAJuJOEBu3Tx_jFqGF0juDcKcqRqAcQBud7ox0KDv3uSgiCQg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"185-190","volume":""},{"id":7171,"author":"張玉金","title":"释甲骨金文中的“西”和“囟”字","abstract":" 考释甲骨金文中的&quot;囟&quot;字,先要从卜辞中的&quot;西&quot;字谈起。卜辞中的&quot;西&quot;字,有下述几种形体:甲种是:■、■、■(以下用西_甲代表)乙种是:■、■、■(以下用西_乙代表)","categories":["02_字词句考释"],"year":2001,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZMmaa8LULeDHlaj9NA-0RULYI9JErUQ4YKOdYa1cL3DTp8QL3QfNsfEBg4zFb7VrJ0Q8NWvxkKXu6gpj3ecrTVpIdMJ6Ht5Eedx7zhfq5YanCFQSqMoAzxWYQaiWiCr_yvbotVVZzQnjwDGDLSJNffIigD8QCAc1KMY_7mZ6_jg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"139-151","volume":""},{"id":7172,"author":"詹鄞鑫","title":"《鱼鼎匕》考释","abstract":" 今春蒙李零兄赐赠大作《李零自选集》,其中《考古发现与神话传说》一文述及鱼鼎匕,阅后颇受启发。旧释似有可商之处,试作此文以求教。","categories":["02_字词句考释"],"year":2001,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZMmaa8LULeDHlaj9NA-0RULYI9JErUQ4YKOdYa1cL3DTp8QL3QfNsQ08tbbJfgV88kgotxKdEYzgq9tW9Tk1DfEYdxWoVUpSTeyy2cTPqMfctI2mnuUeb7f-23IrSBpEXZOz5-iZ4aY5KPccu6SW1A_hZLRWITNoWboBEE9ti8A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"175-179","volume":""},{"id":7173,"author":"陳雙新","title":"晋侯苏鐘铭文新释","abstract":"晋侯苏编钟16件355字,自发表以來虽历经讨论,但仍有一些文字的释定、事件的阐述存在较大分歧。本文在全面分析目前所见的各家观点基础上,对该钟铭文逐句重加梳理,提出了一些新的看法,如释&quot;遹省&quot;为&quot;天子五年一巡守&quot;之&quot;巡守&quot;,释&quot;■&quot;为&quot;溃&quot;,释&quot;■&quot;为《山海经》之&quot;臷国&quot;等,这样理解,全文的文意便畅达无碍。","categories":["02_字词句考释"],"year":2001,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxwgPA2-VN8Xl4Ia91UhXbT5NkbwBxhpeq4MxYLHQxlMMCWzI18YBhcfVXnSF0hS0NYrEUE-_D3SypOjC6l73iL75HaCvVaUozoYQYC90rRWhWEMZNXuLtiR_BVel-a0kLnDXHbbC3JT407EtudNtsoeBubDkYHzsLg7BnPrcqBw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"256-271","volume":""},{"id":7176,"author":"陈剑","title":"据郭店简释读西周金文一例","abstract":"郭店楚墓竹简对古代文史研究各个领域的深远影响,现在正随着研究的深入逐步显现。仅就古文字学研究而言,依靠郭店简提供的证据和线索,旧有的战国文字尤其是楚文字中的不少奇字难句已经得到了正确释读。同时,郭店简文字中还“蕴含着许多商周以来传袭的写法,为解读更早的文字充当了钥匙”①。利用郭店简释读更早的古文字,目前已经取得了一些成绩。但它所提供的“钥匙”,相信还有不少未被研究者注意到。所以本文想再举一个根据郭店简释读西周金文的例子,希望引起大家的注意。","categories":["02_字词句考释"],"year":2001,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJePHfWKf5hNjZgWpS6UbsxTA5S8QjVTfobK3n25tae5WGhTbYx0Bc8rBztoEHcfzTdhG9UdtdvGURj70Qf-0sMnXCl-LoGEl75SSsrJbfcJArJvRltrZSMmzb1owpIOm4f3Lso3Tx0M2l9osh0tEekse_0XoZK8n4CsUrekCnsQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"378-396","volume":""},{"id":7177,"author":"李家浩","title":"秦骃玉版铭文研究","abstract":"1999年10月,黄天树先生寄给我两件战国时期秦国的玉版铭文摹本复印件,并附言说:此摹本是故宫博物院刘雨先生赠送的,“此物传出自陕西华山,现在私人手中”。玉版为长方形,跟秦惠文王时的秦封宗邑瓦书形状相同①,文字风格也很相似,唯瓦书文字较大,显得粗犷一些。","categories":["02_字词句考释"],"year":2001,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLppm3lLqQlOqHJsMNaMKKAbUl3Az0oOoTkyNWDFn0xDMuenTtvcap5VA-uPgIxtrpikKYt9vfJjejxt8WNpvpryiLn82oWTdxxuVXL8vSAIwEnpli_mbsC5WNxpmErP_JMkycWerAxz3RBhKiC9dTcz4AF1H1UKN-RV4xKTouiWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"99-128","volume":""},{"id":7178,"author":"马月华","title":"《汝阴令戈小考》读后记","abstract":"1995年4月,上海博物馆新获一件战国有铭铜戈,最近李朝远先生在《汝阴令戈小考》（以下简称《小考》）一文中发表了有关资料①,同时还对戈的铭文进行了考释。我读到该文后有一些不同的意见,现在把它写出来,向李先生请教。","categories":["02_字词句考释"],"year":2001,"publication":"北京大学中国古文献研究中心集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLppm3lLqQlOqHJsMNaMKKAbUl3Az0oOoTkyNWDFn0xDMuenTtvcap5CgHwR9yF6v0k-7zreaKdy33UUt8He8JAdCewioy03EBQf0_R4gt8UxeFcgBZ_wJik_fP4Jcy4gBplDCHELbdlo9E4vcsBiWG0ZVQqag3qrWFbLbV-WS4Vw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"397-400","volume":""},{"id":3077,"author":"袁金平","title":"出土文献与古籍新诠","abstract":"本书收录作者所撰学术论文共计二十九篇，依据研究内容大体可分为文字考释、古书校读、历史地名考证以及字词关系辨析等几个研究类型。研究材料基本涵盖两周金文、战国竹简以及秦汉简帛。在研究旨趣上，作者致力于地下出土文字资料与传世古书的互证研究，力图有所创获，希望能为学界研究相关问题提供参考。","categories":["02_字词句考释"],"year":null,"publication":"","link":"","pages":"220","volume":""},{"id":3098,"author":"蔣書紅","title":"金文動詞性義項集註","abstract":"本书以金文中的动词性义项为主要研究对象，侧重于判定词性、归纳义项、列举例证、分析用字现象、描绘语法特征、统计频次、列引和比较诸家之说等，凡是有动词性义项用法的单音金文字词，皆纳入本书研究对象范围当中。本书首次以殷周时期金文文献中的主要动词性义项为专门研究对象进行了较为全面系统的梳理研究，较为细致地剖析描述了殷周时期金文的动词性义项详情。","categories":["02_字词句考释"],"year":null,"publication":"","link":"","pages":"303","volume":""},{"id":3105,"author":"吴毅强","title":"晉銅器銘文研究","abstract":"晋国青铜器是两周青铜器研究的重要方面，深受国内外学界的关注。当前的研究主要集中在晋侯墓地所出铭文上，由于所出铜器铭文的复杂性，以致对关键问题的认识尚存较大分歧，如晋侯名号与《史记》的对应，更是众说纷纭。同时，由于晋国青铜器铭文与史实联系较为紧密，如叔夨鼎、公簋、晋侯苏编钟等一批重要铭文，涉及诸多晋国史和西周史的关键问题，在学界引起较大争论，目前多数问题尚未解决。目前，研究多局限在单篇铜器铭文的考释上，全面系统的研究著作尚未出现，因此很有必要全面系统地梳理晋国青铜器铭文。该成果以晋国青铜器铭文为研究对象，首先对晋侯墓地进行综合考察，确定各组墓主的身份与年代；其次对青铜器铭文进行编年释义，并就其涉","categories":["02_字词句考释"],"year":null,"publication":"","link":"","pages":"510","volume":""}];